local PROFILE = TierProfiles[BUILD.Tier] or TierProfiles.FREE
getgenv().SliceHub.Profile = PROFILE

function SliceHubIsPremium()
    return BUILD and BUILD.IsPremium == true
end

function SliceHubFeatureEnabled(featureName)
    local features = PROFILE and PROFILE.Features or nil
    if type(features) == "table" then
        local value = features[tostring(featureName or "")]
        if type(value) == "boolean" then
            return value
        end
    end
    return true
end

function SliceHubPremiumOnlyValue(featureName, value, fallback)
    if SliceHubFeatureEnabled(featureName) then
        return value
    end
    return fallback
end

function SliceHubAutoSkipCutsceneAllowed()
    return SliceHubFeatureEnabled("AutoSkipCutscene")
end

function SliceHubWaveAutomationAllowed()
    return SliceHubFeatureEnabled("WaveAutomation")
        and SliceHubIsPremium()
        and BUILD
        and BUILD.Flags
        and BUILD.Flags.PremiumWave == true
end

function SliceHubClampAutoSkipCutscene(value)
    return SliceHubAutoSkipCutsceneAllowed() and value == true or false
end

function SliceHubRaidChoiceAllowed(raidChoice)
    raidChoice = tostring(raidChoice or "")
    if raidChoice == "Shiganshina (Col)" then return SliceHubFeatureEnabled("ColossalRaid") end
    if raidChoice == "Shiganshina (Arm)" then return SliceHubFeatureEnabled("ArmoredRaid") end
    if raidChoice == "Trost (Att)" then return SliceHubFeatureEnabled("AttackRaid") end
    if raidChoice == "Stohess (Female)" then return SliceHubFeatureEnabled("FemaleRaid") end
    return SliceHubFeatureEnabled("RaidAutomation")
end

function SliceHubRaidRuntimeAllowed(raidName)
    raidName = tostring(raidName or "")
    if raidName == "Colossal Raid" then return SliceHubFeatureEnabled("ColossalRaid") end
    if raidName == "Armored Raid" then return SliceHubFeatureEnabled("ArmoredRaid") end
    if raidName == "Attack Raid" then return SliceHubFeatureEnabled("AttackRaid") end
    if raidName == "Female Raid" then return SliceHubFeatureEnabled("FemaleRaid") end
    return true
end

function SliceHubRaidLockedReason(raidChoice)
    raidChoice = tostring(raidChoice or "")
    if raidChoice == "Shiganshina (Arm)" then return "Armored Raid is unsupported in the Free version. Free keeps Colossal Spears-only support." end
    if raidChoice == "Trost (Att)" then return "Attack Raid is unsupported in the Free version. Free keeps Colossal Spears-only support." end
    if raidChoice == "Stohess (Female)" then return "Female Raid is unsupported in the Free version. Free keeps Colossal Spears-only support." end
    if raidChoice == "Shiganshina (Col)" then return "Colossal Raid is supported in both builds, but it is Spears-only." end
    return "This raid is unsupported in the Free version."
end

function SliceHubRaidDisplayName(raidChoice)
    raidChoice = tostring(raidChoice or "")
    if raidChoice == "Shiganshina (Col)" then return raidChoice .. " • Spears Only" end
    if not SliceHubRaidChoiceAllowed(raidChoice) then return raidChoice .. " 🔒" end
    return raidChoice
end

function SliceHubColossalModeText()
    return "COLOSSAL • SPEARS ONLY"
end

function SliceHubTPSMin()
    local combat = PROFILE and PROFILE.Combat or nil
    local value = combat and tonumber(combat.TitansPerSwingMin) or 2
    value = math.floor(value + 0.5)
    if value < 1 then value = 1 end
    return value
end

function SliceHubTPSMax()
    local combat = PROFILE and PROFILE.Combat or nil
    local minimum = SliceHubTPSMin()
    local value = combat and tonumber(combat.TitansPerSwingMax) or 20
    value = math.floor(value + 0.5)
    if value < minimum then value = minimum end
    return value
end

function SliceHubClampTPS(value, fallback)
    local minimum = SliceHubTPSMin()
    local maximum = SliceHubTPSMax()
    local resolved = tonumber(value)
    if resolved == nil then
        resolved = tonumber(fallback) or maximum
    end
    return math.clamp(math.floor(resolved + 0.5), minimum, maximum)
end
