local function aotLooksLikeMainMenuGui()
    local okPlayers, Players = pcall(function() return game:GetService("Players") end)
    if not okPlayers or not Players or not Players.LocalPlayer then return false end
    local playerGui = Players.LocalPlayer:FindFirstChildOfClass("PlayerGui")
    if not playerGui then
        pcall(function() playerGui = Players.LocalPlayer:WaitForChild("PlayerGui", 0.8) end)
    end
    if not playerGui then return false end
    local score = 0
    local sawPlay, sawSlot, sawLobby = false, false, false
    for _, object in ipairs(playerGui:GetDescendants()) do
        if object:IsA("TextLabel") or object:IsA("TextButton") or object:IsA("TextBox") then
            if object.Visible and object.AbsoluteSize.X > 0 and object.AbsoluteSize.Y > 0 then
                local text = string.lower(tostring(object.Text or ""))
                text = string.gsub(text, "<.->", "")
                text = string.gsub(text, "%s+", " ")
                if text == "play" or string.find(text, " play ", 1, true) then sawPlay = true end
                if string.find(text, "slot a", 1, true) or string.find(text, "slot b", 1, true) or string.find(text, "slot c", 1, true) then sawSlot = true end
                if string.find(text, "lobby", 1, true) then sawLobby = true end
                if string.find(text, "main menu", 1, true) or string.find(text, "profile", 1, true) then score += 1 end
            end
        end
    end
    if sawPlay then score += 1 end
    if sawSlot then score += 2 end
    if sawLobby then score += 1 end
    return score >= 2
end

local isLikelyMainMenu = isMainMenu or aotLooksLikeMainMenuGui()

print("[AOT All-In-One V9] boot", "PlaceId=", placeId, "Lobby=", isLobby, "MainMenu=", isMainMenu, "LikelyMenu=", isLikelyMainMenu)

