local SLICEHUB_KEY_API_DEFAULT = "https://YOUR_RAILWAY_DOMAIN/api/validate"
local SLICEHUB_KEY_GATE_SOURCE = [====[

do
    local Environment =
        type(getgenv) == "function"
        and getgenv()
        or _G

    local Config =
        type(Environment.SliceHubKeyGateConfig) == "table"
        and Environment.SliceHubKeyGateConfig
        or {}

    local PendingSource = Config.Source
    local PendingName =
        tostring(Config.SourceName or "SliceHub")
    local RequestedTier =
        string.upper(
            tostring(Config.BuildTier or "FREE")
        )
    local DiscordInvite =
        tostring(
            Config.DiscordInvite
            or "https://discord.gg/Fg3tQG5CSA"
        )
    local DefaultApiUrl =
        tostring(
            Config.ApiUrl
            or "https://YOUR_RAILWAY_DOMAIN/api/validate"
        )

    if type(PendingSource) ~= "string"
        or PendingSource == "" then
        warn("[SliceHub Key Gate] Missing pending source.")
        return
    end

    local Players = game:GetService("Players")
    local TweenService = game:GetService("TweenService")
    local UserInputService =
        game:GetService("UserInputService")
    local HttpService =
        game:GetService("HttpService")
    local GuiService =
        game:GetService("GuiService")
    local CoreGui = game:GetService("CoreGui")

    local Player = Players.LocalPlayer
        or Players.PlayerAdded:Wait()
    local PlayerGui =
        Player:FindFirstChildOfClass("PlayerGui")
        or Player:WaitForChild("PlayerGui")

    local function trim(value)
        return (
            tostring(value or "")
            :gsub("^%s+", "")
            :gsub("%s+$", "")
        )
    end

    local function findFunction(...)
        local names = {...}

        for _, name in ipairs(names) do
            local value = Environment[name]

            if type(value) == "function" then
                return value
            end
        end

        return nil
    end

    local readFile =
        findFunction("readfile")
        or (
            type(readfile) == "function"
            and readfile
            or nil
        )
    local writeFile =
        findFunction("writefile")
        or (
            type(writefile) == "function"
            and writefile
            or nil
        )
    local isFile =
        findFunction("isfile")
        or (
            type(isfile) == "function"
            and isfile
            or nil
        )
    local makeFolder =
        findFunction("makefolder")
        or (
            type(makefolder) == "function"
            and makefolder
            or nil
        )
    local isFolder =
        findFunction("isfolder")
        or (
            type(isfolder) == "function"
            and isfolder
            or nil
        )
    local deleteFile =
        findFunction("delfile")
        or (
            type(delfile) == "function"
            and delfile
            or nil
        )

    local Request =
        (
            type(Environment.request) == "function"
            and Environment.request
        )
        or (
            type(Environment.http_request) == "function"
            and Environment.http_request
        )
        or (
            type(Environment.httprequest) == "function"
            and Environment.httprequest
        )
        or (
            type(syn) == "table"
            and type(syn.request) == "function"
            and syn.request
        )
        or (
            type(http) == "table"
            and type(http.request) == "function"
            and http.request
        )
        or (
            type(fluxus) == "table"
            and type(fluxus.request) == "function"
            and fluxus.request
        )

    local function ensureFolder()
        if type(makeFolder) ~= "function" then
            return false
        end

        local exists = false

        if type(isFolder) == "function" then
            local ok, result = pcall(
                isFolder,
                "SH"
            )
            exists = ok and result == true
        end

        if not exists then
            pcall(makeFolder, "SH")
        end

        return true
    end

    local function readTextFile(path)
        if type(readFile) ~= "function" then
            return nil
        end

        if type(isFile) == "function" then
            local okExists, exists =
                pcall(isFile, path)

            if not okExists or exists ~= true then
                return nil
            end
        end

        local ok, result =
            pcall(readFile, path)

        if ok and type(result) == "string" then
            return result
        end

        return nil
    end

    local function resolveApiUrl()
        local override = trim(
            Environment.SLICEHUB_KEY_API_URL
            or Environment.SliceHubKeyApiUrl
            or ""
        )

        if override ~= "" then
            return override
        end

        local savedApi =
            trim(
                readTextFile(
                    "SH/license_api.txt"
                )
                or ""
            )

        if savedApi ~= "" then
            return savedApi
        end

        return trim(DefaultApiUrl)
    end

    local function normalizeUrlCandidates(raw)
        raw = trim(raw)

        if raw == ""
            or string.find(
                raw,
                "YOUR_RAILWAY_DOMAIN",
                1,
                true
            ) then
            return {}
        end

        if not string.match(
            string.lower(raw),
            "^https?://"
        ) then
            raw = "https://" .. raw
        end

        raw = string.gsub(raw, "/+$", "")

        local candidates = {}
        local seen = {}

        local function push(url)
            if url ~= ""
                and not seen[url] then
                seen[url] = true
                candidates[#candidates + 1] = url
            end
        end

        if string.find(
            string.lower(raw),
            "/api/",
            1,
            true
        )
            or string.match(
                string.lower(raw),
                "/validate[%w%-%_]*$"
            ) then
            push(raw)
        else
            push(raw .. "/api/validate")
            push(raw .. "/validate")
        end

        return candidates
    end

    local function savedLicense()
        local content =
            readTextFile("SH/license.json")

        if not content or content == "" then
            return nil
        end

        local ok, decoded = pcall(
            HttpService.JSONDecode,
            HttpService,
            content
        )

        if ok and type(decoded) == "table" then
            return decoded
        end

        return nil
    end

    local function saveLicense(key, data)
        if type(writeFile) ~= "function" then
            return false
        end

        ensureFolder()

        local payload = {
            key = key,
            tier = data and (
                data.tier
                or data.plan
                or data.licenseType
            ) or nil,
            expiresAt = data
                and tonumber(
                    data.expiresAt
                    or data.expires
                    or data.expiry
                )
                or nil,
            savedAt = os.time(),
        }

        local okEncode, encoded = pcall(
            HttpService.JSONEncode,
            HttpService,
            payload
        )

        if not okEncode then
            return false
        end

        local okWrite = pcall(
            writeFile,
            "SH/license.json",
            encoded
        )

        return okWrite
    end

    local function clearSavedLicense()
        if type(deleteFile) == "function" then
            pcall(
                deleteFile,
                "SH/license.json"
            )
        elseif type(writeFile) == "function" then
            pcall(
                writeFile,
                "SH/license.json",
                ""
            )
        end
    end

    local function requestStatus(response)
        if type(response) ~= "table" then
            return nil
        end

        return tonumber(
            response.StatusCode
            or response.Status
            or response.status_code
        )
    end

    local function requestBody(response)
        if type(response) == "string" then
            return response
        end

        if type(response) ~= "table" then
            return nil
        end

        return response.Body
            or response.body
            or response.Response
            or response.response
    end

    local function decodeResponse(body)
        body = trim(body)

        if body == "" then
            return nil, "Empty response"
        end

        local ok, decoded = pcall(
            HttpService.JSONDecode,
            HttpService,
            body
        )

        if ok and type(decoded) == "table" then
            return decoded
        end

        if string.lower(body) == "true" then
            return {valid = true}
        end

        return nil, "Invalid JSON response"
    end

    local function urlEncode(value)
        local ok, result = pcall(
            HttpService.UrlEncode,
            HttpService,
            tostring(value or "")
        )

        return ok and result or tostring(value or "")
    end

    local function resolveDeviceId()
        local value = ""

        local environment =
            type(getgenv) == "function"
            and getgenv()
            or _G

        local getHwid =
            environment
            and environment.gethwid
            or gethwid

        if type(getHwid) == "function" then
            pcall(function()
                value = tostring(getHwid())
            end)
        end

        if value == "" then
            pcall(function()
                value = tostring(
                    game:GetService(
                        "RbxAnalyticsService"
                    ):GetClientId()
                )
            end)
        end

        if value == "" then
            -- Stable fallback so teleports between AOT:R places do not
            -- create false HWID mismatches on limited executors.
            value = "roblox-user:" .. tostring(Player.UserId)
        end

        return value
    end

    local function validateAtUrl(url, key)
        local deviceId = resolveDeviceId()
        local requestPayload = {
            key = key,
            scriptKey = key,
            userId = tostring(Player.UserId),
            username = tostring(Player.Name),
            displayName = tostring(
                Player.DisplayName
                or Player.Name
            ),
            placeId = tonumber(game.PlaceId) or 0,
            jobId = tostring(game.JobId or ""),
            requestedTier = RequestedTier,
            buildTier = RequestedTier,
            deviceId = deviceId,
            hwid = deviceId,
            clientId = deviceId,
            client = "SliceHub",
            version = tostring(
                Config.Version or "9.8.2.2"
            ),
        }

        local encodedPayload =
            HttpService:JSONEncode(
                requestPayload
            )

        if type(Request) == "function" then
            local okPost, response = pcall(
                Request,
                {
                    Url = url,
                    Method = "POST",
                    Headers = {
                        ["Content-Type"] =
                            "application/json",
                        ["Accept"] =
                            "application/json",
                    },
                    Body = encodedPayload,
                }
            )

            if okPost then
                local status =
                    requestStatus(response)
                local body =
                    requestBody(response)

                if status == nil
                    or (
                        status >= 200
                        and status < 300
                    ) then
                    local decoded, decodeError =
                        decodeResponse(body)

                    if decoded then
                        return true, decoded
                    end

                    if status ~= nil then
                        return false, nil, decodeError
                    end
                elseif status ~= 404
                    and status ~= 405 then
                    local decoded =
                        select(
                            1,
                            decodeResponse(body)
                        )

                    local message =
                        decoded
                        and (
                            decoded.message
                            or decoded.error
                            or decoded.reason
                        )

                    return false, nil,
                        tostring(
                            message
                            or ("HTTP " .. status)
                        )
                end
            end

            local joiner =
                string.find(url, "?", 1, true)
                and "&"
                or "?"

            local getUrl =
                url
                .. joiner
                .. "key="
                .. urlEncode(key)
                .. "&userId="
                .. urlEncode(Player.UserId)
                .. "&requestedTier="\n                .. urlEncode(RequestedTier)\n                .. "&deviceId="\n                .. urlEncode(deviceId)

            local okGet, getResponse = pcall(
                Request,
                {
                    Url = getUrl,
                    Method = "GET",
                    Headers = {
                        ["Accept"] =
                            "application/json",
                    },
                }
            )

            if okGet then
                local status =
                    requestStatus(getResponse)
                local body =
                    requestBody(getResponse)

                if status == nil
                    or (
                        status >= 200
                        and status < 300
                    ) then
                    local decoded, decodeError =
                        decodeResponse(body)

                    if decoded then
                        return true, decoded
                    end

                    return false, nil, decodeError
                end

                local decoded =
                    select(
                        1,
                        decodeResponse(body)
                    )

                return false, nil,
                    tostring(
                        decoded
                        and (
                            decoded.message
                            or decoded.error
                            or decoded.reason
                        )
                        or ("HTTP " .. tostring(status))
                    )
            end
        end

        local joiner =
            string.find(url, "?", 1, true)
            and "&"
            or "?"

        local getUrl =
            url
            .. joiner
            .. "key="
            .. urlEncode(key)
            .. "&userId="
            .. urlEncode(Player.UserId)
            .. "&requestedTier="\n            .. urlEncode(RequestedTier)\n            .. "&deviceId="\n            .. urlEncode(deviceId)

        local okHttp, body = pcall(
            game.HttpGet,
            game,
            getUrl
        )

        if okHttp then
            local decoded, decodeError =
                decodeResponse(body)

            if decoded then
                return true, decoded
            end

            return false, nil, decodeError
        end

        return false, nil,
            "No supported HTTP request method"
    end

    local function responseIsValid(data)
        if type(data) ~= "table" then
            return false, "Invalid server response"
        end

        local valid =
            data.valid == true
            or data.success == true
            or data.authorized == true
            or data.allowed == true

        if not valid then
            return false,
                tostring(
                    data.message
                    or data.error
                    or data.reason
                    or "Key rejected"
                )
        end

        local expiresAt = tonumber(
            data.expiresAt
            or data.expires
            or data.expiry
        )

        if expiresAt
            and expiresAt > 0
            and expiresAt <= os.time() then
            return false, "Key expired"
        end

        if RequestedTier == "PREMIUM" then
            local responseTier =
                string.upper(
                    tostring(
                        data.tier
                        or data.plan
                        or data.licenseType
                        or ""
                    )
                )

            local premium =
                data.premium == true
                or responseTier == "PREMIUM"
                or responseTier == "PAID"
                or responseTier == "LIFETIME"

            if not premium then
                return false,
                    "This key does not unlock Premium"
            end
        end

        return true
    end

    local function validateKey(key)
        key = trim(key)

        if key == "" then
            return false, nil, "Enter your key"
        end

        local candidates =
            normalizeUrlCandidates(
                resolveApiUrl()
            )

        if #candidates == 0 then
            return false, nil,
                "Key server is not configured"
        end

        local lastError =
            "Unable to contact key server"

        for _, url in ipairs(candidates) do
            local transportOk, data, errorMessage =
                validateAtUrl(url, key)

            if transportOk and data then
                local accepted, reason =
                    responseIsValid(data)

                if accepted then
                    return true, data, nil
                end

                return false, data, reason
            end

            lastError =
                tostring(
                    errorMessage
                    or lastError
                )
        end

        return false, nil, lastError
    end

