    local Scale = Instance.new("UIScale")
    Scale.Name = "ResponsiveScale"
    Scale.Parent = Window

    local function updateScale()
        local camera = workspace.CurrentCamera
        local viewport = camera
            and camera.ViewportSize
            or Vector2.new(1280, 720)
        local factor = math.min(
            1,
            math.max(
                0.70,
                math.min(
                    viewport.X / 520,
                    viewport.Y / 380
                )
            )
        )
        Scale.Scale = factor
    end

    updateScale()

    if workspace.CurrentCamera then
        workspace.CurrentCamera
            :GetPropertyChangedSignal(
                "ViewportSize"
            )
            :Connect(updateScale)
    end

    workspace:GetPropertyChangedSignal(
        "CurrentCamera"
    ):Connect(function()
        task.defer(updateScale)
    end)

    do
        local dragging = false
        local dragStart = nil
        local startPosition = nil

        Window.InputBegan:Connect(
            function(input)
                if input.UserInputType
                    == Enum.UserInputType.MouseButton1
                    or input.UserInputType
                    == Enum.UserInputType.Touch then

                    dragging = true
                    dragStart = input.Position
                    startPosition = Window.Position
                end
            end
        )

        Window.InputEnded:Connect(
            function(input)
                if input.UserInputType
                    == Enum.UserInputType.MouseButton1
                    or input.UserInputType
                    == Enum.UserInputType.Touch then
                    dragging = false
                end
            end
        )

        UserInputService.InputChanged:Connect(
            function(input)
                if not dragging
                    or (
                        input.UserInputType
                        ~= Enum.UserInputType.MouseMovement
                        and input.UserInputType
                        ~= Enum.UserInputType.Touch
                    ) then
                    return
                end

                local delta =
                    input.Position - dragStart

                Window.Position = UDim2.new(
                    startPosition.X.Scale,
                    startPosition.X.Offset
                        + delta.X / Scale.Scale,
                    startPosition.Y.Scale,
                    startPosition.Y.Offset
                        + delta.Y / Scale.Scale
                )
            end
        )
    end

    local function setStatus(message, kind)
        Status.Text = tostring(message or "")

        if kind == "success" then
            Status.TextColor3 =
                Color3.fromRGB(104, 229, 160)
            StatusCard.BackgroundColor3 =
                Color3.fromRGB(15, 31, 25)
        elseif kind == "error" then
            Status.TextColor3 =
                Color3.fromRGB(255, 123, 139)
            StatusCard.BackgroundColor3 =
                Color3.fromRGB(35, 17, 23)
        elseif kind == "working" then
            Status.TextColor3 =
                Color3.fromRGB(121, 186, 255)
            StatusCard.BackgroundColor3 =
                Color3.fromRGB(15, 24, 38)
        else
            Status.TextColor3 =
                Color3.fromRGB(157, 163, 184)
            StatusCard.BackgroundColor3 =
                Color3.fromRGB(16, 17, 26)
        end
    end

    local function attemptOpenDiscord()
        local openers = {
            Environment.openurl,
            Environment.open_url,
            Environment.launch_url,
            Environment.launchurl,
            Environment.openbrowser,
            type(syn) == "table"
                and syn.open_url
                or nil,
        }

        for _, opener in ipairs(openers) do
            if type(opener) == "function" then
                local ok = pcall(
                    opener,
                    DiscordInvite
                )

                if ok then
                    return true, "Discord opened"
                end
            end
        end

        local okBrowser = pcall(
            GuiService.OpenBrowserWindow,
            GuiService,
            DiscordInvite
        )

        if okBrowser then
            return true, "Discord opened"
        end

        local clipboard =
            Environment.setclipboard
            or Environment.toclipboard
            or (
                type(setclipboard) == "function"
                and setclipboard
                or nil
            )

        if type(clipboard) == "function" then
            local ok = pcall(
                clipboard,
                DiscordInvite
            )

            if ok then
                return true,
                    "Discord invite copied to clipboard"
            end
        end

        return false,
            "Open this invite: "
            .. DiscordInvite
    end

    GetKey.Activated:Connect(function()
        local ok, message =
            attemptOpenDiscord()

        setStatus(
            message,
            ok and "success" or "error"
        )
    end)

    local Busy = false
    local Launched = false

    local function launchSource(key, data)
        if Launched then
            return
        end

        Launched = true
        Busy = false

        Environment.SCRIPT_KEY = key
        Environment.SliceHubLicense = data
        Environment.SliceHubKeyValidated = true

        saveLicense(key, data)

        setStatus(
            "Key accepted. Launching "
            .. PendingName
            .. "...",
            "success"
        )

        Verify.Text = "ACCESS GRANTED"
        Verify.BackgroundColor3 =
            Color3.fromRGB(55, 183, 111)

        local onValidated = Config.OnValidated

        if type(onValidated) == "function" then
            pcall(onValidated, key, data)
        end

        task.wait(0.45)

        if Screen.Parent then
            Screen:Destroy()
        end

        local loader = loadstring or load

        if type(loader) ~= "function" then
            warn(
                "[SliceHub Key Gate] loadstring/load unavailable."
            )
            return
        end

        local chunk, compileError =
            loader(PendingSource)

        if type(chunk) ~= "function" then
            warn(
                "[SliceHub Key Gate] Compile failed for "
                .. PendingName
                .. ": "
                .. tostring(compileError)
            )
            return
        end

        print(
            "[SliceHub Key Gate] Access approved:",
            RequestedTier,
            PendingName
        )

        task.spawn(function()
            local ok, runtimeError =
                pcall(chunk)

            if not ok then
                warn(
                    "[SliceHub Key Gate] Runtime error in "
                    .. PendingName
                    .. ": "
                    .. tostring(runtimeError)
                )
            end
        end)
    end

    local function submit(key, automatic)
        if Busy or Launched then
            return
        end

        key = trim(key)

        if key == "" then
            setStatus("Enter your key first.", "error")
            return
        end

        Busy = true
        Verify.Text = "CHECKING..."
        Verify.BackgroundColor3 =
            Color3.fromRGB(48, 87, 164)

        setStatus(
            automatic
                and "Checking saved key..."
                or "Asking the SliceHub license server...",
            "working"
        )

        task.spawn(function()
            local ok, data, errorMessage =
                validateKey(key)

            Busy = false

            if ok then
                launchSource(key, data)
                return
            end

            Verify.Text = "VERIFY & LAUNCH"
            Verify.BackgroundColor3 =
                Color3.fromRGB(67, 133, 255)

            if automatic then
                clearSavedLicense()
            end

            setStatus(
                tostring(
                    errorMessage
                    or "Key rejected"
                ),
                "error"
            )
        end)
    end

    Verify.Activated:Connect(function()
        submit(KeyBox.Text, false)
    end)

    KeyBox.FocusLost:Connect(
        function(enterPressed)
            if enterPressed then
                submit(KeyBox.Text, false)
            end
        end
    )

    local initialKey =
        trim(Environment.SCRIPT_KEY or "")

    if initialKey == "" then
        local saved = savedLicense()

        if saved and type(saved.key) == "string" then
            initialKey = trim(saved.key)
        end
    end

    if initialKey ~= "" then
        KeyBox.Text = initialKey

        task.delay(0.15, function()
            if Screen.Parent then
                submit(initialKey, true)
            end
        end)
    else
        local candidates =
            normalizeUrlCandidates(
                resolveApiUrl()
            )

        if #candidates == 0 then
            setStatus(
                "Key server not configured yet. Add your Railway domain to SH/license_api.txt, then enter a key.",
                "error"
            )
        end
    end
end
