local function getEnv()
	local ok, env = pcall(function()
		if type(getgenv) == "function" then return getgenv() end
	end)
	return (ok and type(env) == "table") and env or _G
end

local Env = getEnv()

-- SliceHub build gates inside the lobby chunk. These read getgenv() directly so
-- Free/Premium behavior still works even when this lobby code is executed as a
-- separate loadstring chunk.
local function SliceHubLobbyIsPremium()
    local ok, env = pcall(function()
        if type(getgenv) == "function" then return getgenv() end
    end)
    env = (ok and type(env) == "table") and env or _G
    local hub = type(env.SliceHub) == "table" and env.SliceHub or nil
    return hub and hub.IsPremium == true
end

function SliceHubLobbyFeatureEnabled(featureName)
    local ok, env = pcall(function()
        if type(getgenv) == "function" then return getgenv() end
    end)
    env = (ok and type(env) == "table") and env or _G
    local hub = type(env.SliceHub) == "table" and env.SliceHub or nil
    local profile = hub and type(hub.Profile) == "table" and hub.Profile or nil
    local features = profile and type(profile.Features) == "table" and profile.Features or nil
    local value = features and features[tostring(featureName or "")] or nil
    if type(value) == "boolean" then return value end
    return SliceHubLobbyIsPremium()
end

function SliceHubLobbyPrestigeThresholdsAllowed()
    return SliceHubLobbyFeatureEnabled("PrestigeThresholds")
end

function SliceHubLobbyPrestigeBuffAllowed()
    return SliceHubLobbyFeatureEnabled("PrestigeBuffSelection")
end

function SliceHubLobbyWavesAllowed()
    return SliceHubLobbyFeatureEnabled("WaveAutomation")
        and SliceHubLobbyIsPremium()
end

function SliceHubRaidChoiceAllowed(raidChoice)
    raidChoice = tostring(raidChoice or "")
    if raidChoice == "Shiganshina (Col)" then return true end
    if SliceHubLobbyIsPremium() then return true end
    return false
end

function SliceHubRaidRuntimeAllowed(raidName)
    raidName = tostring(raidName or "")
    if raidName == "Colossal Raid" then return true end
    if SliceHubLobbyIsPremium() then return true end
    if raidName == "Armored Raid" or raidName == "Attack Raid" or raidName == "Female Raid" then return false end
    return true
end

function SliceHubRaidLockedReason(raidChoice)
    raidChoice = tostring(raidChoice or "")
    if raidChoice == "Shiganshina (Arm)" then return "Armored Raid is unsupported in the Free version. Free keeps Colossal Spears-only support." end
    if raidChoice == "Trost (Att)" then return "Attack Raid is unsupported in the Free version. Free keeps Colossal Spears-only support." end
    if raidChoice == "Stohess (Female)" then return "Female Raid is unsupported in the Free version. Free keeps Colossal Spears-only support." end
    if raidChoice == "Shiganshina (Col)" then return "Colossal Raid is supported in both builds, but it is Spears-only." end
    return "This raid is unsupported in the Free version."
end

function SliceHubRaidDisplayName(raidChoice)
    raidChoice = tostring(raidChoice or "")
    if raidChoice == "Shiganshina (Col)" then return raidChoice .. " • Spears Only" end
    if not SliceHubRaidChoiceAllowed(raidChoice) then return raidChoice .. " 🔒" end
    return raidChoice
end

function SliceHubClampAutoSkipCutscene(value)
    return SliceHubLobbyIsPremium() and value == true or false
end

local readfileFn = type(Env.readfile) == "function" and Env.readfile or nil
local writefileFn = type(Env.writefile) == "function" and Env.writefile or nil


-- V9.5 Colossal policy: the tested route is Spears-only. Lobby reads the same
-- persistent mission settings file before allowing a Colossal launch.
V95LobbyWeaponPolicy = V95LobbyWeaponPolicy or {}

function V95LobbyWeaponPolicy.Read()
    if type(readfileFn) ~= "function" then
        return false, false, "settings file access unavailable"
    end

    local okRead, raw = pcall(readfileFn, "TitanControlSettings_v101.json")
    if not okRead or type(raw) ~= "string" or raw == "" then
        return false, false, "mission settings not found"
    end

    local okDecode, document = pcall(function()
        return HttpService:JSONDecode(raw)
    end)
    if not okDecode or type(document) ~= "table" then
        return false, false, "mission settings unreadable"
    end

    local spears = type(document.Spears) == "table" and document.Spears or {}
    local toggles = type(document.Toggles) == "table" and document.Toggles or {}
    local spearReady = spears.SupportEnabled == true and spears.AutoFireEnabled ~= false
    local bladesSaved = toggles.BladesEnabled == true or toggles.FarmEnabled == true
    return spearReady, bladesSaved, spearReady and "ready" or "enable Spear Support + Auto Fire in the mission GUI"
end

function V95LobbyWeaponPolicy.ColossalReady()
    local spearReady, bladesSaved, reason = V95LobbyWeaponPolicy.Read()
    return spearReady == true, tostring(reason or "unknown"), bladesSaved == true
end

V5LobbyAutoExec = V5LobbyAutoExec or {}

function V5LobbyAutoExec.Enabled()
    if type(readfileFn) ~= "function" then return false end
    local okRead, raw = pcall(readfileFn, "TitanControlSettings_v101.json")
    if not okRead or type(raw) ~= "string" or raw == "" then return false end

    local okDecode, decoded = pcall(function() return HttpService:JSONDecode(raw) end)
    return okDecode
        and type(decoded) == "table"
        and type(decoded.Settings) == "table"
        and decoded.Settings.AutoExecuteOnTeleport == true
end

function V5LobbyAutoExec.Queue()
    if not V5LobbyAutoExec.Enabled() then return false end

    local queueFn = Env.queue_on_teleport
        or Env.queueonteleport
        or Env.queue_on_tp
        or (Env.syn and Env.syn.queue_on_teleport)

    if type(queueFn) ~= "function" then return false end

    local code = [[
local loader = loadstring or load
local source = nil
if type(readfile) == "function" then
    local ok, value = pcall(readfile, "SH/bootstrap.shc")
    if ok then source = value end
end
if type(source) == "string" and type(loader) == "function" then
    local chunk = loader(source)
    if type(chunk) == "function" then chunk() end
end
]]

    return pcall(queueFn, code)
end

if V5LobbyAutoExec.Connection then
    pcall(function() V5LobbyAutoExec.Connection:Disconnect() end)
end

V5LobbyAutoExec.Connection = player.OnTeleport:Connect(function(state)
    if state == Enum.TeleportState.RequestedFromServer
        or state == Enum.TeleportState.Started then
        pcall(V5LobbyAutoExec.Queue)
    end
end)

-- V5.5 persistent Auto Raid Queue. Colossal is supported by the dedicated
-- one-cannon P1 stall director and exact P2 Colossal boss lock.
V51RaidQueue = V51RaidQueue or {
    FileName = "AOT_RaidQueue_v51.json",
    RaidOrder = {"Shiganshina (Arm)", "Shiganshina (Col)", "Trost (Att)", "Stohess (Female)"},
    DifficultyOrder = {"Hard", "Severe", "Aberrant"},
    UI = {},
    AutoLaunchConsumed = false,
}

function V51RaidQueue.DefaultState()
    return {
        Version = 1,
        Enabled = false,
        RepeatQueue = false,
        FailurePolicy = "Retry",
        MaxRetries = 3,
        CurrentRetries = 0,
        Index = 1,
        EntryDone = 0,
        TotalCompleted = 0,
        TotalFailed = 0,
        LastResult = "None",
        Modifiers = {},
        Entries = {
            {RaidChoice = "Shiganshina (Arm)", Difficulty = "Aberrant", Runs = 3},
            {RaidChoice = "Trost (Att)", Difficulty = "Severe", Runs = 5},
            {RaidChoice = "Stohess (Female)", Difficulty = "Aberrant", Runs = 2},
        },
    }
end

function V51RaidQueue.Normalize(document)
    local base = V51RaidQueue.DefaultState()
    document = type(document) == "table" and document or {}
    base.Enabled = document.Enabled == true
    base.RepeatQueue = document.RepeatQueue == true
    local policy = tostring(document.FailurePolicy or "Retry")
    if policy ~= "Retry" and policy ~= "Skip" and policy ~= "Stop" then policy = "Retry" end
    base.FailurePolicy = policy
    base.MaxRetries = math.clamp(math.floor((tonumber(document.MaxRetries) or 3) + 0.5), 0, 10)
    base.CurrentRetries = math.clamp(math.floor((tonumber(document.CurrentRetries) or 0) + 0.5), 0, 99)
    base.Index = math.max(1, math.floor((tonumber(document.Index) or 1) + 0.5))
    base.EntryDone = math.max(0, math.floor((tonumber(document.EntryDone) or 0) + 0.5))
    base.TotalCompleted = math.max(0, math.floor((tonumber(document.TotalCompleted) or 0) + 0.5))
    base.TotalFailed = math.max(0, math.floor((tonumber(document.TotalFailed) or 0) + 0.5))
    base.LastResult = tostring(document.LastResult or "None")
    base.Modifiers = type(document.Modifiers) == "table" and document.Modifiers or {}

    if type(document.Entries) == "table" then
        for index = 1, 3 do
            local source = document.Entries[index]
            if type(source) == "table" then
                local raid = tostring(source.RaidChoice or base.Entries[index].RaidChoice)
                if not table.find(V51RaidQueue.RaidOrder, raid) then raid = base.Entries[index].RaidChoice end
                local difficulty = tostring(source.Difficulty or base.Entries[index].Difficulty)
                if not table.find(V51RaidQueue.DifficultyOrder, difficulty) then difficulty = "Aberrant" end
                if raid == "Shiganshina (Col)" then difficulty = "Aberrant" end
                base.Entries[index] = {
                    RaidChoice = raid,
                    Difficulty = difficulty,
                    Runs = math.clamp(math.floor((tonumber(source.Runs) or base.Entries[index].Runs) + 0.5), 1, 99),
                }
            end
        end
    end

    if base.Index > #base.Entries then base.Index = #base.Entries end

    if type(SliceHubFeatureEnabled) == "function"
        and not SliceHubFeatureEnabled("AutoRaidQueue") then
        base.Enabled = false
        base.RepeatQueue = false
        base.CurrentRetries = 0
        base.LastResult = "Premium Locked"
    end

    return base
end

function V51RaidQueue.Load()
    local document = nil
    if readfileFn then
        local ok, raw = pcall(readfileFn, V51RaidQueue.FileName)
        if ok and type(raw) == "string" and raw ~= "" then
            local decodedOk, decoded = pcall(function() return HttpService:JSONDecode(raw) end)
            if decodedOk then document = decoded end
        end
    end
    V51RaidQueue.State = V51RaidQueue.Normalize(document)
    return V51RaidQueue.State
end

function V51RaidQueue.Save()
    V51RaidQueue.State = V51RaidQueue.Normalize(V51RaidQueue.State)
    if writefileFn then
        local okEncode, encoded = pcall(function() return HttpService:JSONEncode(V51RaidQueue.State) end)
        if okEncode then pcall(writefileFn, V51RaidQueue.FileName, encoded) end
    end
    return V51RaidQueue.State
end

function V51RaidQueue.CurrentEntry()
    local state = V51RaidQueue.State or V51RaidQueue.Load()
    return state.Entries[state.Index], state
end

function V51RaidQueue.ApplyCurrentToLobbyState()
    local entry, queue = V51RaidQueue.CurrentEntry()
    if not entry or not queue.Enabled then return false end
    State.CreateMode = "Raid"
    State.RaidChoice = entry.RaidChoice
    State.Difficulty = entry.Difficulty
    State.Modifiers = {}
    if type(queue.Modifiers) == "table" then
        for _, modifier in ipairs(queue.Modifiers) do
            State.Modifiers[#State.Modifiers + 1] = tostring(modifier)
        end
    end
    State.AutoStart = false
    State.Delay = 0
    return true
end

V51RaidQueue.Load()
V51RaidQueue.AutoLaunchConsumed = false

local function copy(value)
	return HttpService:JSONDecode(HttpService:JSONEncode(value))
end

local function cleanName(value)
	local raw = tostring(value or "")
	local kept = {}
	for index = 1, #raw do
		local byte = string.byte(raw, index)
		if byte and byte >= 32 and byte ~= 127 then
			kept[#kept + 1] = string.sub(raw, index, index)
		end
	end
	local text = table.concat(kept)
	text = string.gsub(text, "^%s+", "")
	text = string.gsub(text, "%s+$", "")
	return string.sub(text, 1, 24)
end

local function diffInfo(name)
	for _, info in ipairs(Difficulties) do
		if info.Name == name then return info end
	end
	return Difficulties[1]
end

local function difficultyGradeForMode(mode, difficulty)
    if tostring(mode or "Mission") == "Raid" then
        return V43RaidDifficultyGrade[tostring(difficulty or "")] or "?"
    end
    return diffInfo(difficulty).Grade
end

local function modSet()
	local set = {}
	for _, name in ipairs(State.Modifiers) do set[name] = true end
	return set
end

local function modsText(mods)
	mods = mods or State.Modifiers
	if #mods == 0 then return "None" end
	return table.concat(mods, ", ")
end

local function normalizeConfig(data)
	data = type(data) == "table" and data or {}

	local createMode = tostring(data.CreateMode or data.Mode or "Mission")
	if createMode ~= "Raid" and createMode ~= "Waves" then
		createMode = "Mission"
	end

	local raidChoice = tostring(data.RaidChoice or "Shiganshina (Arm)")
	if not V401LobbyRaid.Data[raidChoice] then
		for choice, info in pairs(V401LobbyRaid.Data) do
			if tostring(data.Map or "") == info.Map
				and tostring(data.Objective or "") == info.Objective then
				raidChoice = choice
				break
			end
		end
	end
	if not V401LobbyRaid.Data[raidChoice] then raidChoice = "Shiganshina (Arm)" end

    if createMode == "Raid" and type(SliceHubRaidChoiceAllowed) == "function" and not SliceHubRaidChoiceAllowed(raidChoice) then
        raidChoice = "Shiganshina (Col)"
    end

	local map
	local objective

	if createMode == "Raid" then
		local raid = V401LobbyRaid.Data[raidChoice]
		map = raid.Map
		objective = raid.Objective
	elseif createMode == "Waves" then
		map = "Trost"
		objective = "Waves"
	else
		map = tostring(data.Map or "Shiganshina")
		if not MissionData[map] then map = "Shiganshina" end

		objective = tostring(data.Objective or MissionData[map][1])
		local okObjective = false
		for _, obj in ipairs(MissionData[map]) do
			if obj == objective then okObjective = true break end
		end
		if not okObjective then objective = MissionData[map][1] end
	end

	local difficulty = tostring(data.Difficulty or "Easy")
	local okDifficulty = false
	for _, d in ipairs(Difficulties) do if d.Name == difficulty then okDifficulty = true end end
	if not okDifficulty then difficulty = "Easy" end
	if createMode == "Waves" then difficulty = "Easy" end

	local minimum = nil
	if createMode == "Raid" then
		local raid = V401LobbyRaid.Data[raidChoice]
		minimum = raid and tonumber(raid.Minimum) or nil

        if not V43RaidDifficultyAllowed(raidChoice, difficulty) then
            difficulty = raidChoice == "Shiganshina (Col)" and "Aberrant" or "Hard"
        end
	end

	local allowed = {}
	for _, m in ipairs(Modifiers) do allowed[m] = true end
	local mods = {}
	if createMode ~= "Waves" and type(data.Modifiers) == "table" then
		for _, m in ipairs(data.Modifiers) do
			m = tostring(m)
			if allowed[m] then table.insert(mods, m) end
		end
	end

	return {
		CreateMode = createMode,
		RaidChoice = raidChoice,
		Map = map,
		Objective = objective,
		Difficulty = difficulty,
		Minimum = minimum,
		Modifiers = mods,
		AutoStart = data.AutoStart == true,
		Delay = math.clamp(math.floor((tonumber(data.Delay) or 0) + 0.5), 0, 30),
	}
end

local function captureConfig()
	return normalizeConfig(State)
end


---------------------------------------------------------------------
-- V2.2 LEARNED REMOTE FAST PATH
---------------------------------------------------------------------

local RemoteTraceStore = {Version = 1, Configs = {}}

local RemoteTrace = {
    Active = false,
    Replaying = false,
    Records = {},
    StartedAt = 0,
    CurrentSignature = nil,
    TeleportSeen = false,
    HookInstalled = false,
}

local function stableTraceConfig(config)
    local modifiers = {}
    for _, modifier in ipairs(config.Modifiers or {}) do
        modifiers[#modifiers + 1] = tostring(modifier)
    end
    table.sort(modifiers)

    return {
        CreateMode = tostring(config.CreateMode or "Mission"),
        RaidChoice = tostring(config.RaidChoice or ""),
        Map = tostring(config.Map or ""),
        Objective = tostring(config.Objective or ""),
        Difficulty = tostring(config.Difficulty or ""),
        Minimum = tonumber(config.Minimum),
        Modifiers = modifiers,
    }
end

local function traceConfigSignature(config)
    local ok, encoded = pcall(function()
        return HttpService:JSONEncode(stableTraceConfig(config))
    end)
    return ok and encoded or tostring(config.CreateMode) .. "|" .. tostring(config.Map) .. "|" .. tostring(config.Objective)
end

local function loadRemoteTraceStore()
    if not readfileFn then return end
    local okRead, raw = pcall(readfileFn, MissionRemoteTraceFileName)
    if not okRead or type(raw) ~= "string" or raw == "" then return end

    local okDecode, decoded = pcall(function()
        return HttpService:JSONDecode(raw)
    end)

    if okDecode and type(decoded) == "table" and type(decoded.Configs) == "table" then
        RemoteTraceStore = decoded
    end
end

local function saveRemoteTraceStore()
    if not writefileFn then return end

    local okEncode, encoded = pcall(function()
        return HttpService:JSONEncode(RemoteTraceStore)
    end)

    if okEncode and type(encoded) == "string" then
        pcall(writefileFn, MissionRemoteTraceFileName, encoded)
    end
end

local function serializeRemoteValue(value, depth)
    depth = depth or 0
    if depth > 6 then return nil, false end

    local kind = typeof(value)

    if value == nil then
        return {__type = "nil"}, true
    elseif kind == "boolean" or kind == "number" or kind == "string" then
        return value, true
    elseif kind == "Vector3" then
        return {__type = "Vector3", x = value.X, y = value.Y, z = value.Z}, true
    elseif kind == "Vector2" then
        return {__type = "Vector2", x = value.X, y = value.Y}, true
    elseif kind == "Color3" then
        return {__type = "Color3", r = value.R, g = value.G, b = value.B}, true
    elseif kind == "CFrame" then
        return {__type = "CFrame", components = {value:GetComponents()}}, true
    elseif kind == "table" then
        local output = {__type = "Table", values = {}}
        for key, child in pairs(value) do
            if type(key) ~= "string" and type(key) ~= "number" then
                return nil, false
            end

            local encoded, safe = serializeRemoteValue(child, depth + 1)
            if not safe then return nil, false end
            output.values[tostring(key)] = encoded
        end
        return output, true
    end

    return nil, false
end

local function deserializeRemoteValue(value)
    if type(value) ~= "table" or value.__type == nil then
        return value
    end

    if value.__type == "nil" then
        return nil
    elseif value.__type == "Vector3" then
        return Vector3.new(value.x or 0, value.y or 0, value.z or 0)
    elseif value.__type == "Vector2" then
        return Vector2.new(value.x or 0, value.y or 0)
    elseif value.__type == "Color3" then
        return Color3.new(value.r or 0, value.g or 0, value.b or 0)
    elseif value.__type == "CFrame" then
        return CFrame.new(table.unpack(value.components or {}))
    elseif value.__type == "Table" then
        local output = {}
        for key, child in pairs(value.values or {}) do
            local numericKey = tonumber(key)
            output[numericKey or key] = deserializeRemoteValue(child)
        end
        return output
    end

    return value
end

local function persistCurrentTrace()
    local signature = RemoteTrace.CurrentSignature
    if not signature or #RemoteTrace.Records == 0 then return end

    local safe = true
    for _, record in ipairs(RemoteTrace.Records) do
        if record.Safe ~= true then
            safe = false
            break
        end
    end

    RemoteTraceStore.Configs = RemoteTraceStore.Configs or {}
    RemoteTraceStore.Configs[signature] = {
        UpdatedAt = os.time(),
        Safe = safe,
        Records = copy(RemoteTrace.Records),
    }

    saveRemoteTraceStore()
end

local function beginRemoteTrace(config)
    RemoteTrace.Active = true
    RemoteTrace.Replaying = false
    RemoteTrace.Records = {}
    RemoteTrace.StartedAt = os.clock()
    RemoteTrace.CurrentSignature = traceConfigSignature(config)
    RemoteTrace.TeleportSeen = false
end

local function endRemoteTrace()
    RemoteTrace.Active = false
    persistCurrentTrace()
end

player.OnTeleport:Connect(function()
    RemoteTrace.TeleportSeen = true
    if RemoteTrace.Active then
        task.defer(persistCurrentTrace)
    end
end)

local function installMissionRemoteTraceHook()
    if RemoteTrace.HookInstalled then return true end

    local hookFn = Env.hookmetamethod or hookmetamethod
    local getMethodFn = Env.getnamecallmethod or getnamecallmethod
    local closureFn = Env.newcclosure or newcclosure

    if type(hookFn) ~= "function" or type(getMethodFn) ~= "function" then
        print("[LobbyCreator V2.2] Remote hook unavailable; Turbo UI only.")
        return false
    end

    local oldNamecall
    local okHook = pcall(function()
        local wrapper = function(self, ...)
            local method = getMethodFn()
            local shouldRecord =
                RemoteTrace.Active
                and not RemoteTrace.Replaying
                and (method == "FireServer" or method == "InvokeServer")
                and typeof(self) == "Instance"
                and (self.Name == "POST" or self.Name == "GET")
                and string.find(self:GetFullName(), "Assets.Remotes", 1, true) ~= nil

            if shouldRecord then
                local argumentCount = select("#", ...)
                local encodedArgs = {}
                local safe = true

                for index = 1, argumentCount do
                    local encoded, argSafe = serializeRemoteValue(select(index, ...), 0)
                    if not argSafe then
                        safe = false
                        break
                    end
                    encodedArgs[index] = encoded
                end

                RemoteTrace.Records[#RemoteTrace.Records + 1] = {
                    Remote = self.Name,
                    Method = method,
                    Delay = math.max(0, os.clock() - RemoteTrace.StartedAt),
                    ArgCount = argumentCount,
                    Args = encodedArgs,
                    Safe = safe,
                }

                task.defer(persistCurrentTrace)
            end

            return oldNamecall(self, ...)
        end

        if type(closureFn) == "function" then
            wrapper = closureFn(wrapper)
        end

        oldNamecall = hookFn(game, "__namecall", wrapper)
    end)

    RemoteTrace.HookInstalled = okHook

    if okHook then
        print("[LobbyCreator V2.2] Learned remote trace hook ready.")
    else
        warn("[LobbyCreator V2.2] Remote hook failed; Turbo UI only.")
    end

    return okHook
end

local function getMissionRemote(name)
    local replicatedStorage = game:GetService("ReplicatedStorage")
    local assets = replicatedStorage:FindFirstChild("Assets")
    local remotes = assets and assets:FindFirstChild("Remotes")
    return remotes and remotes:FindFirstChild(name)
end

local function tryLearnedRemoteLaunch(config)
    local signature = traceConfigSignature(config)
    local trace = RemoteTraceStore.Configs and RemoteTraceStore.Configs[signature]

    if type(trace) ~= "table"
        or trace.Safe ~= true
        or type(trace.Records) ~= "table"
        or #trace.Records == 0 then
        return false, "no safe learned trace"
    end

    RemoteTrace.Replaying = true
    RemoteTrace.TeleportSeen = false

    print("[LobbyCreator V2.2] Trying learned remote path:", #trace.Records, "calls")

    local previousDelay = 0
    local replayOk = true

    for _, record in ipairs(trace.Records) do
        local remote = getMissionRemote(record.Remote)
        if not remote then
            replayOk = false
            break
        end

        local originalDelay = tonumber(record.Delay) or previousDelay
        local delta = math.max(0, originalDelay - previousDelay)
        previousDelay = originalDelay

        task.wait(math.min(0.08, delta * 0.18))

        local args = {}
        local argCount = tonumber(record.ArgCount) or 0

        for index = 1, argCount do
            args[index] = deserializeRemoteValue((record.Args or {})[index])
        end

        local okCall = pcall(function()
            if record.Method == "InvokeServer" and remote:IsA("RemoteFunction") then
                remote:InvokeServer(table.unpack(args, 1, argCount))
            elseif record.Method == "FireServer" and remote:IsA("RemoteEvent") then
                remote:FireServer(table.unpack(args, 1, argCount))
            else
                error("remote method/class mismatch")
            end
        end)

        if not okCall then
            replayOk = false
            break
        end
    end

    RemoteTrace.Replaying = false

    if not replayOk then
        return false, "replay error"
    end

    local started = os.clock()
    while os.clock() - started < 1.35 do
        if RemoteTrace.TeleportSeen then
            return true, "teleport detected"
        end
        task.wait(0.04)
    end

    return false, "no teleport"
end

local function turboWaitUntil(predicate, timeout, interval)
    local started = os.clock()
    repeat
        local ok, result = pcall(predicate)
        if ok and result then return true end
        task.wait(interval or 0.025)
    until os.clock() - started >= (timeout or 0.6)

    return false
end


