-- V3 EXACT MISSION ENGINE
-- V3.0.1 register-pressure hotfix:
-- all Exact Engine helpers live on one namespace table rather than
-- consuming many top-level local registers in this already huge chunk.
---------------------------------------------------------------------

V3ExactMissionEngine = {
    Busy = false,
    TeleportSeen = false,
    LastStage = "Idle",
    LastError = nil,

    InternalMapNames = {
        ["Shiganshina"] = "Shiganshina",
        ["Trost"] = "Trost",
        ["Outskirts"] = "Outskirts",
        ["Giant Forest"] = "Forest",
        ["Utgard Castle"] = "Utgard",
        ["Loading Docks"] = "Docks",
        ["Stohess"] = "Stohess",
        ["Chapel"] = "Chapel",
    },
}

function V3ExactMissionEngine.Remote()
    local replicatedStorage = game:GetService("ReplicatedStorage")
    local assets = replicatedStorage:FindFirstChild("Assets")
    local remotes = assets and assets:FindFirstChild("Remotes")
    local remote = remotes and remotes:FindFirstChild("GET")

    if remote and remote:IsA("RemoteFunction") then
        return remote
    end

    return nil
end

function V3ExactMissionEngine.BuildPayload(config)
    config = type(config) == "table" and config or {}

    if tostring(config.CreateMode or "Mission") == "Waves" then
        return {
            Name = "Trost",
            Difficulty = "Easy",
            Type = "Waves",
            Objective = "Waves",
        }
    end

    if tostring(config.CreateMode or "Mission") == "Raid" then
        local raid = V401LobbyRaid.Data[tostring(config.RaidChoice or "")]
        local mapName = raid and raid.Map or tostring(config.Map or "Shiganshina")
        local objective = raid and raid.Objective or tostring(config.Objective or "Armored Titan")
        local minimum = raid and tonumber(raid.Minimum) or tonumber(config.Minimum)
        local difficulty = tostring(config.Difficulty or "Hard")

        if not V43RaidDifficultyAllowed(config.RaidChoice, difficulty) then
            difficulty = tostring(config.RaidChoice or "") == "Shiganshina (Col)"
                and "Aberrant"
                or "Hard"
        end

        return {
            Name = tostring(mapName),
            Difficulty = difficulty,
            Type = "Raids",
            Objective = tostring(objective),
            Minimum = minimum,
        }
    end

    return {
        Name = V3ExactMissionEngine.InternalMapNames[tostring(config.Map or "")]
            or tostring(config.Map or "Shiganshina"),
        Difficulty = tostring(config.Difficulty or "Easy"),
        Type = "Missions",
        Objective = tostring(config.Objective or "Skirmish"),
    }
end

function V3ExactMissionEngine.Invoke(action, ...)
    local remote = V3ExactMissionEngine.Remote()
    if not remote then
        return false, nil, "GET RemoteFunction missing"
    end

    local args = table.pack(...)
    local ok, result = pcall(function()
        return remote:InvokeServer(
            "S_Missions",
            action,
            table.unpack(args, 1, args.n)
        )
    end)

    if not ok then
        return false, nil, tostring(result)
    end

    return true, result, nil
end

player.OnTeleport:Connect(function()
    V3ExactMissionEngine.TeleportSeen = true
end)

function V3ExactMissionEngine.TeleportStarted()
    if V3ExactMissionEngine.TeleportSeen then
        return true
    end

    local value = player:GetAttribute("Teleporting")
    return value ~= nil and value ~= false
end

function V3ExactMissionEngine.Cleanup()
    pcall(function()
        V3ExactMissionEngine.Invoke("Leave")
    end)
end

function V3ExactMissionEngine.TryLaunch(config)
    config = type(config) == "table" and config or {}

    if tostring(config.CreateMode or "") == "Waves"
        and not SliceHubLobbyWavesAllowed() then
        return false, "This tab unlocks only when you have Premium."
    end

    if tostring(config.CreateMode or "") == "Raid"
        and type(SliceHubRaidChoiceAllowed) == "function"
        and not SliceHubRaidChoiceAllowed(config.RaidChoice) then
        local reason = type(SliceHubRaidLockedReason) == "function"
            and SliceHubRaidLockedReason(config.RaidChoice)
            or "This raid is unsupported in the Free version."
        warn("[SliceHub Free] " .. tostring(reason))
        return false, tostring(reason)
    end

    if V3ExactMissionEngine.Busy then
        return false, "exact engine busy"
    end

    V3ExactMissionEngine.Busy = true
    V3ExactMissionEngine.TeleportSeen = false
    V3ExactMissionEngine.LastError = nil
    V3ExactMissionEngine.LastStage = "Create"

    local function fail(reason, created)
        V3ExactMissionEngine.LastError = tostring(reason)
        V3ExactMissionEngine.LastStage = "Failed"

        if created then
            V3ExactMissionEngine.Cleanup()
        end

        V3ExactMissionEngine.Busy = false
        return false, tostring(reason)
    end

    local payload = V3ExactMissionEngine.BuildPayload(config)
    print("[Slice V4.2][EXACT] CREATE", HttpService:JSONEncode(payload))

    local createOk, createdMission, createErr =
        V3ExactMissionEngine.Invoke("Create", payload)

    if not createOk then
        return fail("Create invoke failed: " .. tostring(createErr), false)
    end

    local wavesMode = tostring(config.CreateMode or "") == "Waves"

    -- Waves Create is server-accepted even when the RemoteFunction returns nil
    -- or the map name. Missions/Raids keep their older strict validation.
    if not wavesMode then
        if createdMission == nil then
            return fail("Create returned nil", false)
        end

        if type(createdMission) == "string" then
            return fail("Create rejected: " .. tostring(createdMission), false)
        end
    end

    task.wait(0.045)

    V3ExactMissionEngine.LastStage = "Modifiers"

    for _, modifierName in ipairs(config.Modifiers or {}) do
        local modifyOk, enabled, modifyErr =
            V3ExactMissionEngine.Invoke("Modify", tostring(modifierName))

        if not modifyOk then
            return fail(
                "Modify failed for "
                    .. tostring(modifierName)
                    .. ": "
                    .. tostring(modifyErr),
                true
            )
        end

        if enabled == nil then
            return fail(
                "Modify returned nil for " .. tostring(modifierName),
                true
            )
        end

        print(
            "[Slice V4.2][EXACT] MODIFY",
            tostring(modifierName),
            "=>",
            tostring(enabled)
        )

        task.wait(0.018)
    end

    V3ExactMissionEngine.LastStage = "Start"

    local startOk, _, startErr = V3ExactMissionEngine.Invoke("Start")

    if not startOk then
        return fail("Start invoke failed: " .. tostring(startErr), true)
    end

    local startedAt = os.clock()

    while os.clock() - startedAt < 3.0 do
        if V3ExactMissionEngine.TeleportStarted() then
            V3ExactMissionEngine.LastStage = "Teleporting"
            V3ExactMissionEngine.Busy = false
            return true, "exact direct launch"
        end

        task.wait(0.035)
    end

    return fail("Start sent but teleport was not detected", true)
end

