local function applyConfig(config)
	local c = normalizeConfig(config)
	State.CreateMode = c.CreateMode
	State.RaidChoice = c.RaidChoice
	State.Map = c.Map
	State.Objective = c.Objective
	State.Difficulty = c.Difficulty
	State.Modifiers = c.Modifiers
	State.AutoStart = c.AutoStart
	State.Delay = c.Delay
end

local function saveConfigs()
	local doc = {Version = 11, Configs = SavedConfigs}
	if writefileFn then
		local okEncode, encoded = pcall(function() return HttpService:JSONEncode(doc) end)
		if not okEncode then return false, "JSON encode failed" end
		local okWrite = pcall(writefileFn, SaveFileName, encoded)
		if not okWrite then return false, "File write failed" end
		return true, "Saved to file"
	end
	Env.LobbyCreatorDebugConfigs_v11 = doc
	return true, "Saved for this session"
end

local function loadConfigs()
	local doc = nil
	if readfileFn then
		local okRead, raw = pcall(readfileFn, SaveFileName)
		if okRead and type(raw) == "string" and raw ~= "" then
			local okDecode, decoded = pcall(function() return HttpService:JSONDecode(raw) end)
			if okDecode and type(decoded) == "table" then doc = decoded end
		end
	elseif type(Env.LobbyCreatorDebugConfigs_v11) == "table" then
		doc = Env.LobbyCreatorDebugConfigs_v11
	end
	if type(doc) ~= "table" then return end
	SavedConfigs = {}
	local configs = type(doc.Configs) == "table" and doc.Configs or doc
	for name, config in pairs(configs) do
		local clean = cleanName(name)
		if clean ~= "" then SavedConfigs[clean] = normalizeConfig(config) end
	end
end

local function normalizeSettings(data)
	data = type(data) == "table" and data or {}

	local keyName = tostring(data.ToggleKeyName or Settings.ToggleKeyName or "RightShift")
	if not Enum.KeyCode[keyName] or keyName == "Unknown" then
		keyName = "RightShift"
	end

	local autoName = cleanName(data.AutoLoadConfigName or "")
	if autoName ~= "" and not SavedConfigs[autoName] then
		autoName = ""
	end

	return {
		ToggleKeyName = keyName,
		AutoLoadConfig = data.AutoLoadConfig == true,
		AutoLoadConfigName = autoName,
	}
end

local function saveSettings()
	local doc = {
		Version = 12,
		Settings = normalizeSettings(Settings),
	}

	if writefileFn then
		local okEncode, encoded = pcall(function() return HttpService:JSONEncode(doc) end)
		if not okEncode then return false, "JSON encode failed" end

		local okWrite = pcall(writefileFn, SettingsFileName, encoded)
		if not okWrite then return false, "File write failed" end
		return true, "Saved to file"
	end

	Env.LobbyCreatorStatusSettings_v12 = doc
	return true, "Saved for this session"
end

local function loadSettings()
	local doc = nil

	if readfileFn then
		local okRead, raw = pcall(readfileFn, SettingsFileName)
		if okRead and type(raw) == "string" and raw ~= "" then
			local okDecode, decoded = pcall(function() return HttpService:JSONDecode(raw) end)
			if okDecode and type(decoded) == "table" then doc = decoded end
		end
	elseif type(Env.LobbyCreatorStatusSettings_v12) == "table" then
		doc = Env.LobbyCreatorStatusSettings_v12
	end

	if type(doc) == "table" then
		Settings = normalizeSettings(type(doc.Settings) == "table" and doc.Settings or doc)
	else
		Settings = normalizeSettings(Settings)
	end
end

local function getToggleKeyCode()
	local keyName = tostring(Settings.ToggleKeyName or "RightShift")
	return Enum.KeyCode[keyName] or Enum.KeyCode.RightShift
end

