-- V9.7 mobile fit: the lobby creator uses a desktop-sized 920x650
-- shell. On mobile Roblox applies touch UI scaling, so force a lower
-- UIScale and keep the panel centered instead of letting it overflow.
function SliceHubLobbyCreatorMobileFit()
    local camera = Workspace.CurrentCamera
    if not camera then return end

    local viewport = camera.ViewportSize
    if viewport.X < 300 or viewport.Y < 240 then return end

    local touchLike = UserInputService.TouchEnabled or viewport.X < 900 or viewport.Y < 620
    local fit = math.min((viewport.X * 0.86) / 920, (viewport.Y * 0.82) / 650, 1)
    local scale = touchLike and math.clamp(fit, 0.36, 0.54) or math.clamp(fit, 0.72, 1)

    local windowFit = window:FindFirstChild("SliceHubLobbyFit")
    if not windowFit then
        windowFit = Instance.new("UIScale")
        windowFit.Name = "SliceHubLobbyFit"
        windowFit.Parent = window
    end
    windowFit.Scale = scale

    local shadowFit = shadow:FindFirstChild("SliceHubLobbyFit")
    if not shadowFit then
        shadowFit = Instance.new("UIScale")
        shadowFit.Name = "SliceHubLobbyFit"
        shadowFit.Parent = shadow
    end
    shadowFit.Scale = scale

    window.AnchorPoint = Vector2.new(0.5, 0.5)
    window.Position = UDim2.fromScale(0.5, 0.5)
    shadow.AnchorPoint = Vector2.new(0.5, 0.5)
    shadow.Position = UDim2.new(0.5, 6 * scale, 0.5, 8 * scale)
end

SliceHubLobbyCreatorMobileFit()
