local TabNames = {"Create", "Queue", "Configs", "Settings", "Auto Upgrade", "Auto Prestige", "Skill Tree", "Discord"}
tabSel.Size = UDim2.new(1, -6, 1/#TabNames, -5)
local TabButtons = {}
local PageFrames = {}
local ActiveTab = "Create"

local function makeTab(name, index)
	local b = Instance.new("TextButton")
	b.Position = UDim2.new(0, 0, (index - 1)/#TabNames, 0)
	b.Size = UDim2.new(1, 0, 1/#TabNames, 0)
	b.BackgroundTransparency = 1
	b.AutoButtonColor = false
	b.Font = Enum.Font.GothamBold
	b.Text = "   " .. string.upper(name)
	b.TextSize = 12
	b.TextColor3 = index == 1 and Theme.Text or Theme.Dim
	b.TextXAlignment = Enum.TextXAlignment.Left
	b.ZIndex = 3
	b.Parent = tabBar
	TabButtons[name] = b

	local page = Instance.new("Frame")
	page.Name = name .. "Page"
	page.Size = UDim2.fromScale(1, 1)
	page.BackgroundTransparency = 1
	page.Visible = index == 1
	page.Parent = pages
	PageFrames[name] = page

	local function switchLobbyTab()
		ActiveTab = name
		for i, tabName in ipairs(TabNames) do
			local page = PageFrames[tabName]
			local tabButton = TabButtons[tabName]
			if page then page.Visible = tabName == name end
			if tabButton then tabButton.TextColor3 = tabName == name and Theme.Text or Theme.Dim end
			if tabName == name and tabSel then
				tw(tabSel, {Position = UDim2.new(0, 3, (i - 1)/#TabNames, 3)}, 0.12)
			end
		end
		print("[LobbyCreator] tab ->", tostring(name))
	end

	b.Active = true
	b.Selectable = true
	b.Activated:Connect(switchLobbyTab)
	b.MouseButton1Click:Connect(switchLobbyTab)
	b.InputBegan:Connect(function(input)
		if input.UserInputType == Enum.UserInputType.MouseButton1 or input.UserInputType == Enum.UserInputType.Touch then
			switchLobbyTab()
		end
	end)
end

for i, name in ipairs(TabNames) do makeTab(name, i) end

-- v61: lobby tab fallback. Some clients swallow TextButton.Activated in the lobby UI.
UserInputService.InputBegan:Connect(function(input, gameProcessed)
	if not MenuOpen or not window.Visible or not tabBar.Visible then return end
	local kind = input.UserInputType
	if kind ~= Enum.UserInputType.MouseButton1 and kind ~= Enum.UserInputType.Touch then return end
	local p = input.Position
	local x = tonumber(p.X) or 0
	local y = tonumber(p.Y) or 0
	for i, tabName in ipairs(TabNames) do
		local b = TabButtons[tabName]
		if b and b.Visible then
			local pos = b.AbsolutePosition
			local size = b.AbsoluteSize
			if x >= pos.X and x <= pos.X + size.X and y >= pos.Y and y <= pos.Y + size.Y then
				ActiveTab = tabName
				for j, name2 in ipairs(TabNames) do
					local page = PageFrames[name2]
					local tabButton = TabButtons[name2]
					if page then page.Visible = name2 == tabName end
					if tabButton then tabButton.TextColor3 = name2 == tabName and Theme.Text or Theme.Dim end
					if name2 == tabName and tabSel then
						tw(tabSel, {Position = UDim2.new(0, 3, (j - 1)/#TabNames, 3)}, 0.12)
					end
				end
				print("[LobbyCreator] fallback tab ->", tostring(tabName))
				return
			end
		end
	end
end)

