-- Mode detector.
local function cleanText(value)
	local t = tostring(value or "")
	t = string.gsub(t, "<.->", "")
	t = string.gsub(t, "%s+", " ")
	return string.lower(t)
end

local function visibleTextObject(obj)
	if not (obj:IsA("TextLabel") or obj:IsA("TextButton") or obj:IsA("TextBox")) then return false end
	if not obj.Visible or obj.AbsoluteSize.X <= 0 or obj.AbsoluteSize.Y <= 0 then return false end
	local node = obj.Parent
	while node and node ~= playerGui do
		if node:IsA("GuiObject") and not node.Visible then return false end
		if node:IsA("LayerCollector") and not node.Enabled then return false end
		node = node.Parent
	end
	return true
end

local function scanKeywords(keywords)
	for _, obj in ipairs(playerGui:GetDescendants()) do
		if obj:IsDescendantOf(gui) then continue end
		if visibleTextObject(obj) then
			local text = cleanText(obj.Text)
			for _, kw in ipairs(keywords) do
				if string.find(text, kw, 1, true) then return true, text end
			end
		end
	end
	return false, nil
end

local function detectMode()
	if scanKeywords({"mission completed", "mission complete", "mission failed"}) then return "Result" end
	local titans = Workspace:FindFirstChild("Titans")
	if titans and #titans:GetChildren() > 0 then return "Mission/Raid" end
	if scanKeywords({"titans killed", "damage dealt", "wave", "objective"}) then return "Mission/Raid" end
	if scanKeywords({"create mission", "start mission", "mission board", "ready", "deploy", "lobby"}) then return "Lobby" end
	if scanKeywords({"main menu", "play", "credits"}) then return "MainMenu" end
	return "Unknown"
end

local function modeColor(mode)
	if mode == "Lobby" then return Theme.Success end
	if mode == "Mission/Raid" then return Theme.Accent2 end
	if mode == "Result" then return Theme.Warn end
	if mode == "MainMenu" then return Color3.fromRGB(180, 135, 255) end
	return Color3.fromRGB(150, 158, 180)
end

