local function refreshPreview()
    local d = diffInfo(State.Difficulty)
    local mode = State.CreateMode
    local grade = difficultyGradeForMode(mode, State.Difficulty)

    if mode == "Waves" then
        local allowed = SliceHubLobbyWavesAllowed()
        preview.Text =
            "Type: Waves"
            .. "\nMap: Trost"
            .. "\nDifficulty: Easy [E-]"
            .. "\nObjective: Fixed Wave Route"
            .. "\nModifiers: None"
            .. "\nAuto Start: " .. (V98WavesUI.AutoStart and "ON" or "OFF")
            .. "\nLaunch: " .. (allowed and "Direct Create → Start" or "Premium only")

        V401CreateModeUI.EngineHint.Text = allowed
            and "Direct S_Missions Create → Start. Waves accepts a nil Create return when the server creates the lobby."
            or "This tab unlocks only when you have Premium."
        autoBtn.Text = V98WavesUI.AutoStart and "Auto Start Waves: ON" or "Auto Start Waves: OFF"
        createBtn.Text = allowed and "LAUNCH WAVES DIRECT" or "WAVES • PREMIUM ONLY"
        createBtn.BackgroundColor3 = allowed and Theme.Accent or Theme.Danger
    elseif mode == "Raid" then
        local colossalSelected = State.RaidChoice == "Shiganshina (Col)"
        local colossalReady, colossalReason, bladesSaved = true, "", false
        if colossalSelected then
            colossalReady, colossalReason, bladesSaved = V95LobbyWeaponPolicy.ColossalReady()
        end

        preview.Text =
            "Type: Raid"
            .. "\nRaid: " .. tostring(State.RaidChoice)
            .. "\nMap: " .. tostring(State.Map)
            .. "\nBoss: " .. tostring(State.Objective)
            .. "\nDifficulty: " .. State.Difficulty .. " [" .. grade .. "]"
            .. "\nModifiers: " .. modsText()
            .. (colossalSelected and ("\nRoute: " .. (type(SliceHubColossalModeText) == "function" and SliceHubColossalModeText() or "COLOSSAL • SPEARS ONLY")) or "")
            .. "\nAuto Create: " .. (State.AutoStart and "ON" or "OFF")
            .. " • Delay: " .. State.Delay .. " sec"

        if colossalSelected then
            if colossalReady then
                V401CreateModeUI.EngineHint.Text = bladesSaved
                    and ((type(SliceHubColossalModeText) == "function" and SliceHubColossalModeText() or "COLOSSAL • SPEARS ONLY") .. " • Saved Blades are ignored for this raid.")
                    or ((type(SliceHubColossalModeText) == "function" and SliceHubColossalModeText() or "COLOSSAL • SPEARS ONLY") .. " • Spear Support + Auto Fire verified.")
                createBtn.Text = "LAUNCH COLOSSAL • SPEARS ONLY"
                createBtn.BackgroundColor3 = Theme.Accent
            else
                V401CreateModeUI.EngineHint.Text = "COLOSSAL BLOCKED • " .. tostring(colossalReason)
                createBtn.Text = "ENABLE SPEARS FOR COLOSSAL"
                createBtn.BackgroundColor3 = Theme.Danger
            end
        else
            V401CreateModeUI.EngineHint.Text =
                "Direct S_Missions Raid Create → Modify → Start. UI/trace remain fallback only."
            createBtn.Text = "LAUNCH RAID DIRECT"
            createBtn.BackgroundColor3 = Theme.Accent
        end
    else
        preview.Text =
            "Type: Mission"
            .. "\nMap: " .. State.Map
            .. "\nObjective: " .. State.Objective
            .. "\nDifficulty: " .. State.Difficulty .. " [" .. grade .. "]"
            .. "\nModifiers: " .. modsText()
            .. "\nEngine: Exact Direct → Turbo UI"
            .. "\nAuto Create: " .. (State.AutoStart and "ON" or "OFF")
            .. " • Delay: " .. State.Delay .. " sec"

        V401CreateModeUI.EngineHint.Text =
            "Direct S_Missions launch first. Turbo UI is the automatic fallback."
        createBtn.Text = "LAUNCH EXACT ENGINE"
        createBtn.BackgroundColor3 = Theme.Accent
    end

    if mode ~= "Waves" then
        autoBtn.Text = State.AutoStart and "Auto Create: ON" or "Auto Create: OFF"
    end
    delayLabel.Text = "Delay: " .. State.Delay .. " sec"
    local pct = math.clamp(State.Delay / 30, 0, 1)
    fill.Size = UDim2.fromScale(pct, 1)
    knob.Position = UDim2.fromScale(pct, 0.5)
end

local refreshAll

local function V43LayoutDifficultyButtons()
    local allowed = {}

    if State.CreateMode == "Raid" then
        local raid = V401LobbyRaid.Data[State.RaidChoice]
        for _, name in ipairs(raid and raid.Difficulties or {"Hard", "Severe", "Aberrant"}) do
            allowed[#allowed + 1] = name
        end
    elseif State.CreateMode == "Waves" then
        allowed[1] = "Easy"
    else
        for _, info in ipairs(Difficulties) do
            allowed[#allowed + 1] = info.Name
        end
    end

    local visibleSet = {}
    for _, name in ipairs(allowed) do visibleSet[name] = true end

    local count = math.max(1, #allowed)
    local index = 0

    for _, info in ipairs(Difficulties) do
        local b = diffButtons[info.Name]
        if b then
            local visible = visibleSet[info.Name] == true
            b.Visible = visible

            if visible then
                index += 1
                local grade = difficultyGradeForMode(State.CreateMode, info.Name)
                b.Text = info.Name .. "\n" .. grade
                b.Position = UDim2.new((index - 1) / count, 2, 0, 0)
                b.Size = UDim2.new(1 / count, -5, 1, 0)
            end
        end
    end
end

function V401RebuildCreateChoices()
	for _, child in ipairs(mapList:GetChildren()) do
		if child:IsA("TextButton") then child:Destroy() end
	end
	mapButtons = {}

	if State.CreateMode == "Raid" then
		V401CreateModeUI.MapLabel.Text = "Raid"
		for i, raidChoice in ipairs(V401LobbyRaid.Order) do
			local b = button(mapList, (type(SliceHubRaidDisplayName) == "function" and SliceHubRaidDisplayName(raidChoice) or raidChoice), UDim2.new(), UDim2.new(1, -8, 0, 26), ((type(SliceHubRaidChoiceAllowed) ~= "function" or SliceHubRaidChoiceAllowed(raidChoice)) and Theme.Card or Theme.Panel2))
			b.LayoutOrder = i
			mapButtons[raidChoice] = b
			b.Activated:Connect(function()
                if type(SliceHubRaidChoiceAllowed) == "function" and not SliceHubRaidChoiceAllowed(raidChoice) then
                    warn("[SliceHub Free] " .. (type(SliceHubRaidLockedReason) == "function" and SliceHubRaidLockedReason(raidChoice) or "This raid is unsupported in Free."))
                    return
                end
				local raid = V401LobbyRaid.Data[raidChoice]
				State.RaidChoice = raidChoice
				State.Map = raid.Map
				State.Objective = raid.Objective
				refreshAll()
			end)
		end
	elseif State.CreateMode == "Waves" then
		V401CreateModeUI.MapLabel.Text = "Map"
		local b = button(mapList, "Trost • Fixed", UDim2.new(), UDim2.new(1, -8, 0, 26), Theme.Accent)
		b.LayoutOrder = 1
		b.Active = false
		b.AutoButtonColor = false
		mapButtons.Trost = b
	else
		V401CreateModeUI.MapLabel.Text = "Map"
		for i, map in ipairs(MapOrder) do
			local b = button(mapList, map, UDim2.new(), UDim2.new(1, -8, 0, 26), Theme.Card)
			b.LayoutOrder = i
			mapButtons[map] = b
			b.Activated:Connect(function()
				State.Map = map
				State.Objective = MissionData[map][1]
				refreshAll()
			end)
		end
	end
end

local function rebuildObjectives()
	for _, child in ipairs(objList:GetChildren()) do
		if child:IsA("TextButton") then child:Destroy() end
	end
	objButtons = {}

	local missionMode = State.CreateMode == "Mission"
	V401CreateModeUI.ObjectiveLabel.Visible = missionMode
	objList.Visible = missionMode

	if not missionMode then return end

	for i, obj in ipairs(MissionData[State.Map]) do
		local b = button(objList, obj, UDim2.new(), UDim2.new(1, -8, 0, 26), Theme.Card)
		b.LayoutOrder = i
		objButtons[obj] = b
		b.Activated:Connect(function()
			State.Objective = obj
			refreshAll()
		end)
	end
end

refreshAll = function()
	if State.CreateMode == "Waves" then
		State.Map = "Trost"
		State.Objective = "Waves"
		State.Difficulty = "Easy"
		State.Modifiers = {}
	elseif State.CreateMode == "Raid" then
        if type(SliceHubRaidChoiceAllowed) == "function" and not SliceHubRaidChoiceAllowed(State.RaidChoice) then
            State.RaidChoice = "Shiganshina (Col)"
        end
		local raid = V401LobbyRaid.Data[State.RaidChoice] or V401LobbyRaid.Data["Shiganshina (Col)"] or V401LobbyRaid.Data["Shiganshina (Arm)"]
		State.RaidChoice = V401LobbyRaid.Data[State.RaidChoice] and State.RaidChoice or "Shiganshina (Col)"
		State.Map = raid.Map
		State.Objective = raid.Objective

        if not V43RaidDifficultyAllowed(State.RaidChoice, State.Difficulty) then
            State.Difficulty = State.RaidChoice == "Shiganshina (Col)"
                and "Aberrant"
                or "Hard"
        end
	elseif not MissionData[State.Map] then
		State.Map = "Shiganshina"
		State.Objective = MissionData[State.Map][1]
	else
		local validObjective = false
		for _, objective in ipairs(MissionData[State.Map]) do
			if objective == State.Objective then validObjective = true break end
		end
		if not validObjective then State.Objective = MissionData[State.Map][1] end
	end

	V401RebuildCreateChoices()
	rebuildObjectives()
    V43LayoutDifficultyButtons()

	setSelected(V401CreateModeUI.Mission, State.CreateMode == "Mission", Theme.Accent)
	setSelected(V401CreateModeUI.Waves, State.CreateMode == "Waves", Theme.Accent)
	setSelected(V401CreateModeUI.Raid, State.CreateMode == "Raid", Theme.Accent)
    V401CreateModeUI.Waves.Text = SliceHubLobbyWavesAllowed() and "WAVES" or "WAVES 🔒"

	local wavesMode = State.CreateMode == "Waves"
	V401CreateModeUI.DifficultyLabel.Visible = true
	diffHolder.Visible = true
	V401CreateModeUI.ModifiersLabel.Visible = not wavesMode
	modHolder.Visible = not wavesMode

	local selectedChoice = State.CreateMode == "Raid" and State.RaidChoice or State.Map
	for name, b in pairs(mapButtons) do
		setSelected(b, selectedChoice == name, Theme.Accent)
	end
	for name, b in pairs(objButtons) do
		setSelected(b, State.Objective == name, Theme.Accent)
	end
	for name, b in pairs(diffButtons) do
		setSelected(b, State.Difficulty == name, diffInfo(name).Color)
	end

	local set = modSet()
	for name, b in pairs(modButtons) do
		setSelected(b, set[name] == true, Theme.Accent)
	end

	refreshPreview()
end

