	State.RaidChoice = V401LobbyRaid.Data[State.RaidChoice] and State.RaidChoice or "Shiganshina (Col)"
	State.Map = raid.Map
	State.Objective = raid.Objective
	refreshAll()
end)

for i, d in ipairs(Difficulties) do
	local w = 1 / #Difficulties
	local b = button(diffHolder, d.Name .. "\n" .. d.Grade, UDim2.new(w*(i-1), 2, 0, 0), UDim2.new(w, -5, 1, 0), Theme.Card)
	b.TextSize = 9
	diffButtons[d.Name] = b
	b.Activated:Connect(function()
        if State.CreateMode == "Raid"
            and not V43RaidDifficultyAllowed(State.RaidChoice, d.Name) then
            return
        end
        if State.CreateMode == "Waves" and d.Name ~= "Easy" then
            return
        end

		State.Difficulty = d.Name
		refreshAll()
	end)
end

for i, m in ipairs(Modifiers) do
	local b = button(modHolder, m, UDim2.new(), UDim2.new(1, 0, 0, 25), Theme.Card)
	b.LayoutOrder = i
	b.TextSize = 9
	b.TextWrapped = true
	modButtons[m] = b
	b.Activated:Connect(function()
		if State.CreateMode == "Waves" then return end
		local set = modSet()
		if set[m] then
			local nextMods = {}
			for _, old in ipairs(State.Modifiers) do
				if old ~= m then table.insert(nextMods, old) end
			end
			State.Modifiers = nextMods
		else
			table.insert(State.Modifiers, m)
		end
		refreshAll()
	end)
end

autoBtn.Activated:Connect(function()
	if State.CreateMode == "Waves" then
		V98WavesUI.AutoStart = not V98WavesUI.AutoStart
	else
		State.AutoStart = not State.AutoStart
	end
	refreshPreview()
end)

local draggingSlider = false
local function setDelayFromX(x)
	local pct = math.clamp((x - track.AbsolutePosition.X) / math.max(1, track.AbsoluteSize.X), 0, 1)
	State.Delay = math.clamp(math.floor(pct * 30 + 0.5), 0, 30)
	refreshPreview()
end

track.InputBegan:Connect(function(input)
	if input.UserInputType == Enum.UserInputType.MouseButton1
		or input.UserInputType == Enum.UserInputType.Touch then
		draggingSlider = true
		setDelayFromX(input.Position.X)
	end
end)

knob.InputBegan:Connect(function(input)
	if input.UserInputType == Enum.UserInputType.MouseButton1
		or input.UserInputType == Enum.UserInputType.Touch then
		draggingSlider = true
	end
end)

UserInputService.InputChanged:Connect(function(input)
	if draggingSlider
		and (input.UserInputType == Enum.UserInputType.MouseMovement
			or input.UserInputType == Enum.UserInputType.Touch) then
		setDelayFromX(input.Position.X)
	end
end)

UserInputService.InputEnded:Connect(function(input)
	if input.UserInputType == Enum.UserInputType.MouseButton1
		or input.UserInputType == Enum.UserInputType.Touch then
		draggingSlider = false
	end
end)

local function summary()
	if State.CreateMode == "Raid" then
		return "Raid / " .. tostring(State.RaidChoice) .. " / " .. difficultyGradeForMode("Raid", State.Difficulty) .. " / Mods: " .. modsText()
	end
	if State.CreateMode == "Waves" then
		return "Waves / Trost / Easy / No modifiers"
	end
	return "Mission / " .. State.Map .. " / " .. State.Objective .. " / " .. diffInfo(State.Difficulty).Grade .. " / Mods: " .. modsText()
end

local function saveLastMissionInfo()
	local config = captureConfig()
	local doc = {
		Version = 1,
		Source = "LobbyCreator",
		UpdatedAt = os.time(),
		PlaceId = tonumber(game.PlaceId) or 0,
		CreateMode = config.CreateMode,
		RaidChoice = config.RaidChoice,
		Map = config.Map,
		Objective = config.Objective,
		Difficulty = config.Difficulty,
		Minimum = config.Minimum,
		DifficultyGrade = difficultyGradeForMode(config.CreateMode, config.Difficulty),
		Modifiers = config.Modifiers,
	}

	pcall(function()
		Env.AOT_LastMissionInfo = doc
		if type(getgenv) == "function" then
			getgenv().AOT_LastMissionInfo = doc
		end
	end)

	if writefileFn then
		local okEncode, encoded = pcall(function()
			return HttpService:JSONEncode(doc)
		end)
		if okEncode and type(encoded) == "string" then
			pcall(writefileFn, LastMissionInfoFileName, encoded)
		end
	end

	print("[LobbyCreator] Saved last run info:", tostring(config.CreateMode), tostring(config.Map), tostring(config.Objective), tostring(config.Difficulty))
	return doc
end

local FlowRunning = false

local MapAliases = {
	["Shiganshina"] = {"shiganshina"},
	["Trost"] = {"trost"},
	["Outskirts"] = {"outskirts"},
	["Giant Forest"] = {"forest", "giant forest"},
	["Utgard Castle"] = {"utgard", "utgard castle"},
	["Loading Docks"] = {"loading docks", "docks"},
	["Stohess"] = {"stohess"},
	["Chapel"] = {"chapel"},
}

local ObjectiveAliases = {
	["Skirmish"] = {"skirmish"},
	["Breach"] = {"breach"},
	["Protect"] = {"protect"},
	["Escort"] = {"escort"},
	["Guard"] = {"guard"},
	["Defend"] = {"defend"},
	["Stall"] = {"stall"},
	["Raid"] = {"raid"},
	["Random"] = {"random"},
}

local ModifierAliases = {
	["No Perks"] = {"no perks"},
	["No Skills"] = {"no skills"},
	["No Memories"] = {"no memories", "no talents"},
	["Nightmare"] = {"nightmare"},
	["Oddball"] = {"oddball"},
	["Injury Prone"] = {"injury prone"},
	["Chronic Injuries"] = {"chronic injuries", "cronic injuries"},
	["Fog"] = {"fog"},
	["Glass Cannon"] = {"glass cannon", "glasscannon"},
	["Time Trial"] = {"time trial", "timetrial"},
	["Simple"] = {"simple"},
	["Boring"] = {"boring"},
}

local function allTextMatches(textValue, aliases, exact)
	local cleaned = cleanText(textValue)
	for _, alias in ipairs(aliases) do
		alias = cleanText(alias)
		if exact then
			if cleaned == alias then return true end
		elseif string.find(cleaned, alias, 1, true) then
			return true
		end
	end
	return false
end

local function safeText(obj)
	if obj and (obj:IsA("TextLabel") or obj:IsA("TextButton") or obj:IsA("TextBox")) then
		return tostring(obj.Text or "")
	end
	return ""
end

local function visibleGameTextObjects()
	local result = {}
	for _, obj in ipairs(playerGui:GetDescendants()) do
		if obj:IsDescendantOf(gui) then
			continue
		end
		if visibleTextObject(obj) then
			table.insert(result, obj)
		end
	end
	return result
end

local function getAllVisibleGameText()
	local lines = {}
	for _, obj in ipairs(visibleGameTextObjects()) do
		table.insert(lines, cleanText(obj.Text))
	end
	return table.concat(lines, "\n")
end

local function findTextObject(aliases, exact, preferLowest)
	local best = nil
	for _, obj in ipairs(visibleGameTextObjects()) do
		if allTextMatches(obj.Text, aliases, exact) then
			if not best then
				best = obj
			elseif preferLowest and obj.AbsolutePosition.Y > best.AbsolutePosition.Y then
				best = obj
			elseif not preferLowest and obj.AbsolutePosition.Y < best.AbsolutePosition.Y then
				best = obj
			end
		end
	end
	return best
end

local function clickAt(x, y)
	x = math.floor(x + 0.5)
	y = math.floor(y + 0.5)

	local inset = Vector2.new(0, 0)
	pcall(function()
		inset = GuiService:GetGuiInset()
	end)

	local clickX = x + inset.X
	local clickY = y + inset.Y

	print(string.format("[LobbyCreator] Screen click raw=(%d,%d) inset=(%d,%d) final=(%d,%d)", x, y, inset.X, inset.Y, clickX, clickY))

	-- Some custom Roblox UI only reacts properly after the cursor is moved/hovered first.
	pcall(function()
		VirtualInputManager:SendMouseMoveEvent(clickX, clickY, game)
	end)
	task.wait(0.02)

	VirtualInputManager:SendMouseButtonEvent(clickX, clickY, 0, true, game, 0)
	task.wait(0.035)
	VirtualInputManager:SendMouseButtonEvent(clickX, clickY, 0, false, game, 0)
	task.wait(0.09)
end

local function findClickTarget(obj)
	if not obj then return nil end
	if obj:IsA("GuiButton") then return obj end

	local objectSize = obj.AbsoluteSize
	local best = obj
	local node = obj.Parent

	for _ = 1, 8 do
		if not node or node == playerGui then break end
		if node:IsDescendantOf(gui) then break end

		if node:IsA("GuiButton") then
			return node
		end

		if node:IsA("GuiObject") and node.Visible then
			local size = node.AbsoluteSize
			local biggerThanText = size.X >= objectSize.X + 18 and size.Y >= objectSize.Y + 18
			local notWholeScreen = size.X <= 760 and size.Y <= 680
			local clickableCardSize = size.X >= 60 and size.Y >= 35

			if biggerThanText and notWholeScreen and clickableCardSize then
				best = node
				break
			end
		end

		node = node.Parent
	end

	return best
end

local function activateButtonIfPossible(target)
	local node = target
	for _ = 1, 6 do
		if not node or node == playerGui then break end
		if node:IsA("GuiButton") then
			pcall(function()
				node:Activate()
			end)
			return true
		end
		node = node.Parent
	end
	return false
end

local function clickGuiObject(obj, xOffset, yOffset, direct)
	if not obj then return false end

	local target = direct and obj or findClickTarget(obj)
	if not target then return false end

	local pos = target.AbsolutePosition
	local size = target.AbsoluteSize
	local x = pos.X + size.X / 2 + (xOffset or 0)
	local y = pos.Y + size.Y / 2 + (yOffset or 0)

	print("[LobbyCreator] Click target:", target:GetFullName(), "from:", obj:GetFullName())
	clickAt(x, y)
	activateButtonIfPossible(target)
	task.wait(0.03)
	return true
end

local function setOwnMenuVisible(open)
	MenuOpen = open == true
	window.Visible = MenuOpen
	shadow.Visible = MenuOpen
end

-- Mobile SH floating button for the Lobby Creator.
if UserInputService.TouchEnabled and gui and not gui:FindFirstChild("SliceHubLobbyMobileToggle") then
    State.SliceHubLobbyMobileToggle = Instance.new("TextButton")
    State.SliceHubLobbyMobileToggle.Name = "SliceHubLobbyMobileToggle"
    State.SliceHubLobbyMobileToggle.AnchorPoint = Vector2.new(1, 0)
    State.SliceHubLobbyMobileToggle.Position = UDim2.new(1, -14, 0, 92)
    State.SliceHubLobbyMobileToggle.Size = UDim2.fromOffset(54, 54)
    State.SliceHubLobbyMobileToggle.BackgroundColor3 = Theme.Accent or Color3.fromRGB(89, 169, 255)
    State.SliceHubLobbyMobileToggle.BorderSizePixel = 0
    State.SliceHubLobbyMobileToggle.AutoButtonColor = true
    State.SliceHubLobbyMobileToggle.Text = "SH"
    State.SliceHubLobbyMobileToggle.TextColor3 = Color3.fromRGB(255, 255, 255)
    State.SliceHubLobbyMobileToggle.TextSize = 18
    State.SliceHubLobbyMobileToggle.Font = Enum.Font.GothamBlack
    State.SliceHubLobbyMobileToggle.ZIndex = 10000
    State.SliceHubLobbyMobileToggle.Parent = gui
