local function sprayClickGuiObject(obj, labelName)
	if not obj then return false end

	local target = findClickTarget(obj) or obj
	if not target then return false end

	local size = target.AbsoluteSize
	local offsets = {
		Vector2.new(0, 0),
		Vector2.new(-math.min(55, size.X * 0.25), 0),
		Vector2.new(math.min(55, size.X * 0.25), 0),
		Vector2.new(0, -math.min(18, size.Y * 0.22)),
		Vector2.new(0, math.min(18, size.Y * 0.22)),
	}

	print("[LobbyCreator] Spray click:", tostring(labelName or "object"), target:GetFullName())

	for _, offset in ipairs(offsets) do
		clickGuiObject(target, offset.X, offset.Y, true)
		task.wait(0.02)
	end

	return true
end

local function clickBottomButtonByText(labelText)
	local obj = findTextObject({labelText}, true, true) or findTextObject({labelText}, false, true)
	if obj then
		return sprayClickGuiObject(obj, labelText)
	end
	return false
end

local function scrollObjectIntoView(obj)
	local node = obj and obj.Parent
	while node and node ~= playerGui do
		if node:IsA("ScrollingFrame") and not node:IsDescendantOf(gui) then
			local desiredY = node.CanvasPosition.Y + (obj.AbsolutePosition.Y - node.AbsolutePosition.Y) - 40
			node.CanvasPosition = Vector2.new(node.CanvasPosition.X, math.max(0, desiredY))
			task.wait(0.08)
			return true
		end
		node = node.Parent
	end
	return false
end

local function scrollGameLists(amount)
	for _, obj in ipairs(playerGui:GetDescendants()) do
		if obj:IsA("ScrollingFrame") and not obj:IsDescendantOf(gui) and obj.Visible then
			obj.CanvasPosition = Vector2.new(obj.CanvasPosition.X, math.max(0, obj.CanvasPosition.Y + amount))
		end
	end
	task.wait(0.12)
end

local function clickText(aliases, exact, timeout, stepName, preferLowest)
	local started = os.clock()
	while os.clock() - started <= (timeout or 4) do
		local obj = findTextObject(aliases, exact, preferLowest)
		if obj then
			scrollObjectIntoView(obj)
			print("[LobbyCreator] Click:", stepName or table.concat(aliases, "/"), "->", tostring(obj.Text))
			return clickGuiObject(obj)
		end
		task.wait(0.12)
	end

	warn("[LobbyCreator] Could not find text for step:", stepName or table.concat(aliases, "/"))
	return false
end

local function waitForText(aliases, exact, timeout)
	local started = os.clock()
	while os.clock() - started <= (timeout or 4) do
		if findTextObject(aliases, exact, false) then
			return true
		end
		task.wait(0.12)
	end
	return false
end

local function currentDifficultyMatches()
	local d = diffInfo(State.Difficulty)
	local visible = getAllVisibleGameText()
	local difficultyName = cleanText(State.Difficulty)
	local grade = cleanText(d.Grade)

	return string.find(visible, difficultyName, 1, true) ~= nil
		or string.find(visible, grade .. " grade", 1, true) ~= nil
		or string.find(visible, "(" .. grade, 1, true) ~= nil
end

local function clickDifficultyArrow()
	local arrow = findTextObject({">"}, true, false) or findTextObject({"<"}, true, false)
	if arrow then
		return clickGuiObject(arrow, 0, 0, true)
	end

	-- Fallback: click slightly left of the visible difficulty label.
	local difficultyLabel = findTextObject({"difficulty"}, false, false)
	if difficultyLabel then
		clickAt(difficultyLabel.AbsolutePosition.X + 20, difficultyLabel.AbsolutePosition.Y + 58)
		return true
	end

	return false
end

local clickDifficultyDirection

local function setDifficultyByCycling()
	if currentDifficultyMatches() then
		print("[LobbyCreator] Difficulty already set:", State.Difficulty)
		return true
	end

	for attempt = 1, 8 do
		local clickedDifficulty = false
		if clickDifficultyDirection then
			clickedDifficulty = clickDifficultyDirection("backward")
		else
			clickedDifficulty = clickDifficultyArrow()
		end

		if not clickedDifficulty then
			warn("[LobbyCreator] Difficulty arrow not found.")
			return false
		end
		task.wait(0.28)
		if currentDifficultyMatches() then
			print("[LobbyCreator] Difficulty set:", State.Difficulty)
			return true
		end
	end

	warn("[LobbyCreator] Could not verify difficulty:", State.Difficulty)
	return false
end

local function clickModifier(modifierName)
	local aliases = ModifierAliases[modifierName] or {modifierName}

	for attempt = 1, 8 do
		local obj = findTextObject(aliases, true, false) or findTextObject(aliases, false, false)
		if obj then
			scrollObjectIntoView(obj)
			task.wait(0.05)

			-- The checkbox is left of the modifier title in the game's modifier panel.
			local x = math.max(4, obj.AbsolutePosition.X - 38)
			local y = obj.AbsolutePosition.Y + obj.AbsoluteSize.Y / 2
			print("[LobbyCreator] Toggle modifier:", modifierName)
			clickAt(x, y)
			return true
		end

		scrollGameLists(130)
	end

	warn("[LobbyCreator] Modifier not found:", modifierName)
	return false
end

local function objectivePageLooksOpen(selectedAliases)
	if findTextObject(selectedAliases, true, false) or findTextObject(selectedAliases, false, false) then
		return true
	end
	if findTextObject({"skirmish"}, true, false) and findTextObject({"random"}, true, false) then
		return true
	end
	return false
end

local function clickObjectAndAncestors(obj, labelName)
	if not obj then return false end

	local clicked = false
	local node = obj
	for depth = 0, 5 do
		if not node or node == playerGui then break end
		if node:IsA("GuiObject") and not node:IsDescendantOf(gui) then
			local size = node.AbsoluteSize
			if size.X > 20 and size.Y > 12 and size.X < 900 and size.Y < 750 then
				print("[LobbyCreator] Aggressive click " .. tostring(labelName or "object") .. " depth " .. tostring(depth) .. ":", node:GetFullName())
				if depth <= 2 then
					sprayClickGuiObject(node, tostring(labelName or "object") .. " depth " .. tostring(depth))
				else
					clickGuiObject(node, 0, 0, true)
				end
				clicked = true
			end
		end
		node = node.Parent
	end

	return clicked
end

local function clickObjectivesButtonUntilOpen(objectiveAliases)
	for attempt = 1, 5 do
		if objectivePageLooksOpen(objectiveAliases) then
			return true
		end

		local obj = findTextObject({"objectives"}, true, true) or findTextObject({"objectives"}, false, true)
		if obj then
			scrollObjectIntoView(obj)
			clickObjectAndAncestors(obj, "OBJECTIVES")
			sprayClickGuiObject(obj, "OBJECTIVES label")
		else
			warn("[LobbyCreator] OBJECTIVES text not found during aggressive retry.")
			clickBottomButtonByText("objectives")
		end

		task.wait(0.95)
	end

	return objectivePageLooksOpen(objectiveAliases)
end

local function clickObjectiveCard(objectiveAliases, objectiveName)
	for attempt = 1, 5 do
		local obj = findTextObject(objectiveAliases, true, false) or findTextObject(objectiveAliases, false, false)
		if obj then
			scrollObjectIntoView(obj)
			clickObjectAndAncestors(obj, objectiveName or "objective")
			sprayClickGuiObject(obj, objectiveName or "objective")
			task.wait(0.45)
			return true
		end

		scrollGameLists(120)
	end

	return false
end

local function getPath(root, path)
	local node = root
	for _, name in ipairs(path) do
		if not node then return nil end
		node = node:FindFirstChild(name)
	end
	return node
end

local function fireGuiButtonSignals(button)
	if not button or not button:IsA("GuiButton") then return false end

	local ok = false

	pcall(function()
		button:Activate()
		ok = true
	end)

	if type(firesignal) == "function" then
		pcall(function()
			firesignal(button.MouseButton1Down)
			ok = true
		end)
		pcall(function()
			firesignal(button.MouseButton1Click)
			ok = true
		end)
		pcall(function()
			firesignal(button.Activated)
			ok = true
		end)
	end

	return ok
end

local function findGuiButtonAncestor(obj)
	local node = obj
	for _ = 1, 8 do
		if not node or node == playerGui then break end
		if node:IsA("GuiButton") then
			return node
		end
		node = node.Parent
	end
	return nil
end

local function exactClickObject(obj, stepName)
	if not obj then
		return false
	end

	local buttonObject = obj:IsA("GuiButton") and obj or findGuiButtonAncestor(obj)
	if buttonObject then
		print("[LobbyCreator] Exact signal:", tostring(stepName or buttonObject.Name), "->", buttonObject:GetFullName())
		fireGuiButtonSignals(buttonObject)
		task.wait(0.07)
		clickGuiObject(buttonObject, 0, 0, true)
		return true
	end

	if obj:IsA("GuiObject") then
		print("[LobbyCreator] Exact object click:", tostring(stepName or obj.Name), "->", obj:GetFullName())
		clickGuiObject(obj, 0, 0, true)
		return true
	end

	return false
end

local function getMissionMain()
	return getPath(playerGui, {"Interface", "Missions", "Missions", "Main"})
end

local function getMissionInfoRoot()
	return getPath(playerGui, {"Interface", "Missions", "Info"})
end

local function clickMissionMainButton(buttonName, stepName)
	local main = getMissionMain()
	local path = {"Info", "Main", "Buttons", buttonName}
	local obj = main and getPath(main, path)

	if obj and exactClickObject(obj, stepName or buttonName) then
		return true
	end

	-- Fallback to visible text.
	local textMap = {
		Objectives_Missions = "objectives",
		Creation_Missions = "create",
		Back_Missions = "back",
	}
	local labelText = textMap[buttonName]
	if labelText then
		return clickText({labelText}, true, 2, stepName or buttonName, true)
	end

	return false
end

clickDifficultyDirection = function(directionName)
	local main = getMissionMain()
	if not main then
		return clickDifficultyArrow()
	end

	local objectName = directionName == "forward" and "Forward_Missions" or "Backward_Missions"
	local obj = getPath(main, {"Info", "Main", "Difficulty", objectName})
	if obj then
		return exactClickObject(obj, "Difficulty " .. directionName)
	end

	return clickDifficultyArrow()
end

local function searchUnder(root, aliases, exact)
	if not root then return nil end

	for _, obj in ipairs(root:GetDescendants()) do
		local candidate = tostring(obj.Name or "") .. " " .. safeText(obj)
		if allTextMatches(candidate, aliases, exact) then
			return obj
		end
	end

	return nil
end

local function pointInsideGuiObject(x, y, boundsRoot)
	if not boundsRoot or not boundsRoot:IsA("GuiObject") then
		return false
	end

	local rootPos = boundsRoot.AbsolutePosition
	local rootSize = boundsRoot.AbsoluteSize

	return x >= rootPos.X
		and x <= rootPos.X + rootSize.X
		and y >= rootPos.Y
		and y <= rootPos.Y + rootSize.Y
end

local function objectInsideBounds(obj, boundsRoot)
	if not obj or not boundsRoot or not obj:IsA("GuiObject") or not boundsRoot:IsA("GuiObject") then
		return false
	end

	local pos = obj.AbsolutePosition
	local size = obj.AbsoluteSize
	local centerX = pos.X + size.X / 2
	local centerY = pos.Y + size.Y / 2

	return pointInsideGuiObject(centerX, centerY, boundsRoot)
end

local function objectInsideClippedAncestors(obj, stopAt)
	if not obj or not obj:IsA("GuiObject") then
		return false
	end

	local pos = obj.AbsolutePosition
	local size = obj.AbsoluteSize
	local centerX = pos.X + size.X / 2
	local centerY = pos.Y + size.Y / 2

	local node = obj
	while node and node ~= stopAt do
		if node:IsA("GuiObject") and (node:IsA("ScrollingFrame") or node.ClipsDescendants) then
			if not pointInsideGuiObject(centerX, centerY, node) then
				return false
			end
		end
		node = node.Parent
	end

	return true
end

local function objectVisibleInTree(obj, stopAt)
	if not obj then return false end

	local node = obj
	while node and node ~= stopAt do
		if node:IsA("GuiObject") and not node.Visible then
			return false
		end
		if node:IsA("LayerCollector") and not node.Enabled then
			return false
		end
		node = node.Parent
	end

	return true
end

local function searchVisibleUnder(root, aliases, exact)
	if not root then return nil end

	local function usable(obj)
		return obj:IsA("GuiObject")
			and objectVisibleInTree(obj, root)
			and objectInsideBounds(obj, root)
			and objectInsideClippedAncestors(obj, root)
	end

	-- Prefer real visible text labels/buttons. Matching by instance name first can
	-- return a row container instead of the modifier title, which makes checkbox
	-- offsets much less reliable.
	for _, obj in ipairs(root:GetDescendants()) do
		if usable(obj) and (obj:IsA("TextLabel") or obj:IsA("TextButton") or obj:IsA("TextBox")) then
			local text = safeText(obj)
			if text ~= "" and allTextMatches(text, aliases, exact) then
				return obj
			end
		end
	end

	for _, obj in ipairs(root:GetDescendants()) do
		if usable(obj) then
			local candidate = tostring(obj.Name or "") .. " " .. safeText(obj)
			if allTextMatches(candidate, aliases, exact) then
				return obj
			end
		end
	end

	return nil
end

local function addUnique(list, value)
	if not value then return end
	for _, existing in ipairs(list) do
		if existing == value then return end
	end
	table.insert(list, value)
end

local function getModifierScrollers(root)
	local scrollers = {}

	if root and root:IsA("ScrollingFrame") and objectVisibleInTree(root, nil) then
		addUnique(scrollers, root)
	end

	if root then
		for _, obj in ipairs(root:GetDescendants()) do
			if obj:IsA("ScrollingFrame") and objectVisibleInTree(obj, root) then
				addUnique(scrollers, obj)
			end
		end
	end

	table.sort(scrollers, function(a, b)
		local aCanvas = 0
		local bCanvas = 0
		pcall(function() aCanvas = a.AbsoluteCanvasSize.Y end)
		pcall(function() bCanvas = b.AbsoluteCanvasSize.Y end)
		return aCanvas > bCanvas
	end)

	return scrollers
end

local function getMaxCanvasY(scroller)
	local canvasY = scroller.AbsoluteSize.Y
	local windowY = scroller.AbsoluteSize.Y

	pcall(function()
		canvasY = scroller.AbsoluteCanvasSize.Y
	end)

	pcall(function()
		windowY = scroller.AbsoluteWindowSize.Y
	end)

	return math.max(0, canvasY - math.max(1, windowY))
end

local function clampCanvasY(scroller, y)
	return math.clamp(y, 0, getMaxCanvasY(scroller))
end

local function modifierPanelScroll(root, amount)
	if not root or not root:IsA("GuiObject") then return false end

	local moved = false
	local scrollers = getModifierScrollers(root)

	for _, obj in ipairs(scrollers) do
		local before = obj.CanvasPosition.Y
		local after = clampCanvasY(obj, before + amount)
		obj.CanvasPosition = Vector2.new(obj.CanvasPosition.X, after)
		if math.abs(after - before) > 0.5 then
			moved = true
		end
	end

	-- Some mission panels use a custom wheel listener instead of a normal ScrollingFrame.
	-- Keep the wheel fallback, but send it at the visible center of the modifier panel.
	if not moved then
		local pos = root.AbsolutePosition
		local size = root.AbsoluteSize
		local x = math.floor(pos.X + size.X / 2)
		local y = math.floor(pos.Y + size.Y / 2)

		local inset = Vector2.new(0, 0)
		pcall(function()
			inset = GuiService:GetGuiInset()
		end)

		pcall(function()
			VirtualInputManager:SendMouseMoveEvent(x + inset.X, y + inset.Y, game)
		end)

		for _ = 1, 5 do
			pcall(function()
				VirtualInputManager:SendMouseWheelEvent(x + inset.X, y + inset.Y, amount < 0, game)
			end)
			task.wait(0.02)
		end
	end

	task.wait(0.07)
	return true
end

local function resetModifierPanelScroll(root)
	if not root then return end

	for _, obj in ipairs(getModifierScrollers(root)) do
		obj.CanvasPosition = Vector2.new(obj.CanvasPosition.X, 0)
	end

	task.wait(0.06)
end


local function clickObjectiveExact(objectiveName)
	local aliases = ObjectiveAliases[objectiveName] or {objectiveName}
	local main = getMissionMain()
	local objectiveRoot = main and getPath(main, {"Info", "Objectives"})

	local obj = searchUnder(objectiveRoot, aliases, true) or searchUnder(objectiveRoot, aliases, false)
	if obj then
		return exactClickObject(obj, "Objective " .. objectiveName)
	end

	return clickObjectiveCard(aliases, objectiveName)
end

local function clickObjectiveReturnExact()
	local main = getMissionMain()
	local obj = main and getPath(main, {"Info", "Objectives", "Objectives_Buttons", "Objectives_Return"})
	if obj then
		return exactClickObject(obj, "Back from Objectives")
	end

	return clickMissionMainButton("Back_Missions", "Back from Objectives fallback")
end

local function clickCreateExact()
	return clickMissionMainButton("Creation_Missions", "Create lobby")
end

local function clickLobbyInfoButton(buttonName, textName, stepName)
	local info = getMissionInfoRoot()
	local candidates = {}

	if info then
		table.insert(candidates, getPath(info, {"Main", "Info", "Main", "Info_Buttons", buttonName}))
		table.insert(candidates, getPath(info, {"Main", "Info", "Main", "Info_Buttons", buttonName, "Title"}))
		table.insert(candidates, searchUnder(info, {textName}, true))
		table.insert(candidates, searchUnder(info, {textName}, false))
	end

	for _, obj in ipairs(candidates) do
		if obj and exactClickObject(obj, stepName or textName) then
			return true
		end
	end

	return clickText({textName}, true, 3, stepName or textName, true)
end

local function modifierPanelLooksOpen()
	local info = getMissionInfoRoot()
	local modifierRoot = info and getPath(info, {"Main", "Info", "Modifiers"})
	if modifierRoot and modifierRoot:IsA("GuiObject") and objectVisibleInTree(modifierRoot, info) then
		local size = modifierRoot.AbsoluteSize
		if modifierRoot.Visible and size.X > 30 and size.Y > 30 then
			return true, modifierRoot
		end
	end

	return false, modifierRoot
end

local function waitForModifierPanel(timeout)
	local started = os.clock()
	while os.clock() - started <= (timeout or 1.2) do
		local open, root = modifierPanelLooksOpen()
		if open then
			return true, root
		end
		task.wait(0.06)
	end
	return false, nil
end

local function clickModifiersExact()
	local alreadyOpen = modifierPanelLooksOpen()
	if alreadyOpen then
		return true
	end

	local info = getMissionInfoRoot()
	local candidates = {}

	if info then
		addUnique(candidates, getPath(info, {"Main", "Info", "Main", "Info_Buttons", "Modify"}))
		addUnique(candidates, getPath(info, {"Main", "Info", "Main", "Info_Buttons", "Modify", "Title"}))
		addUnique(candidates, searchUnder(info, {"modifiers"}, true))
		addUnique(candidates, searchUnder(info, {"modify"}, true))
		addUnique(candidates, searchUnder(info, {"modifiers"}, false))
	end

	for attempt = 1, 4 do
		for _, obj in ipairs(candidates) do
			if obj and obj:IsA("GuiObject") and not obj:IsDescendantOf(gui) then
				print("[LobbyCreator] Open Modifiers attempt", attempt, "->", obj:GetFullName())
				if attempt == 1 then
					exactClickObject(obj, "Open Modifiers")
				else
					clickObjectAndAncestors(obj, "Open Modifiers")
				end

				if waitForModifierPanel(0.45) then
					return true
				end
			end
		end

		-- Last-resort visible text click. This catches layouts where the path changed.
		clickText({"modifiers"}, true, 0.8, "Open Modifiers fallback", true)
		if waitForModifierPanel(0.45) then
			return true
		end
	end

	return false
end

local function clickStartExact()
	return clickLobbyInfoButton("Begin", "start", "Start mission")
end

local function clickModifierReturnExact()
	local info = getMissionInfoRoot()
	local obj = info and getPath(info, {"Main", "Info", "Modifiers", "Modifiers_Buttons", "Modifiers_Return"})
	if obj then
		return exactClickObject(obj, "Back from Modifiers")
	end
	return clickText({"back"}, true, 3, "Back from Modifiers", true)
end

local function closeModifierPanelHard()
	local info = getMissionInfoRoot()
	local modifierRoot = info and getPath(info, {"Main", "Info", "Modifiers"})
	if modifierRoot then resetModifierPanelScroll(modifierRoot) end
	task.wait(0.08)

	for attempt = 1, 5 do
		if not modifierPanelLooksOpen() then
			return true
		end

		print("[LobbyCreator] Close Modifiers hard attempt", attempt)
		if not clickModifierReturnExact() then
			clickBottomButtonByText("back")
		end

		task.wait(0.22)
	end

	return not modifierPanelLooksOpen()
end

local function findModifierRowRoot(titleObj, modifierRoot)
	if not titleObj or not titleObj:IsA("GuiObject") then return nil end

	local titlePos = titleObj.AbsolutePosition
	local titleSize = titleObj.AbsoluteSize
	local titleCenterX = titlePos.X + titleSize.X / 2
	local titleCenterY = titlePos.Y + titleSize.Y / 2

	local best = nil
	local node = titleObj.Parent

	for _ = 1, 10 do
		if not node or node == playerGui then break end
		if node:IsA("GuiObject") and node ~= modifierRoot and objectVisibleInTree(node, modifierRoot) and objectInsideBounds(node, modifierRoot) and objectInsideClippedAncestors(node, modifierRoot) then
			local size = node.AbsoluteSize
			local rowLike = size.X >= titleSize.X + 34
				and size.Y >= math.max(18, titleSize.Y)
				and size.Y <= 92
				and pointInsideGuiObject(titleCenterX, titleCenterY, node)

			if rowLike then
				best = node
			end
		end

		if node == modifierRoot then break end
		node = node.Parent
	end

	return best
end

local function findModifierCheckboxObject(titleObj, modifierRoot)
	if not titleObj or not titleObj:IsA("GuiObject") or not modifierRoot then return nil end

	local titlePos = titleObj.AbsolutePosition
	local titleSize = titleObj.AbsoluteSize
	local titleY = titlePos.Y + titleSize.Y / 2
	local titleX = titlePos.X

	local rowRoot = findModifierRowRoot(titleObj, modifierRoot)
	local best = nil
	local bestScore = math.huge

	local function scan(root, rowBonus)
		if not root then return end

		for _, obj in ipairs(root:GetDescendants()) do
			if obj:IsA("GuiObject")
				and obj ~= titleObj
				and objectVisibleInTree(obj, modifierRoot)
				and objectInsideBounds(obj, modifierRoot)
				and objectInsideClippedAncestors(obj, modifierRoot)
			then
				local pos = obj.AbsolutePosition
				local size = obj.AbsoluteSize
				local centerX = pos.X + size.X / 2
				local centerY = pos.Y + size.Y / 2

				local leftOfTitle = centerX < titleX - 8
				local closeY = math.abs(centerY - titleY) <= math.max(20, titleSize.Y * 1.4)
				local smallSquareish = size.X >= 8 and size.Y >= 8 and size.X <= 46 and size.Y <= 46 and math.abs(size.X - size.Y) <= 18

				if leftOfTitle and closeY and smallSquareish then
					local expectedX = math.max(modifierRoot.AbsolutePosition.X + 24, titleX - 34)
					local score = math.abs(centerX - expectedX) + math.abs(centerY - titleY) * 2 + math.abs(size.X - size.Y) + rowBonus
					if obj:IsA("GuiButton") then
						score -= 12
					end
					if score < bestScore then
						bestScore = score
						best = obj
					end
				end
			end
		end
	end

	-- Prefer checkbox-looking objects in the same row/card as the modifier title.
	scan(rowRoot, -16)
	scan(modifierRoot, 0)

	return best, rowRoot
end

local function clickModifierCheckboxForTitle(titleObj, modifierRoot, modifierName)
	local checkbox, rowRoot = findModifierCheckboxObject(titleObj, modifierRoot)

	if checkbox and checkbox:IsA("GuiObject") then
		local pos = checkbox.AbsolutePosition
		local size = checkbox.AbsoluteSize
		local x = pos.X + size.X / 2
		local y = pos.Y + size.Y / 2

		print("[LobbyCreator] Modifier checkbox object:", modifierName, "->", checkbox:GetFullName())
		clickAt(x, y)
		return true
	end

	-- Fallback: one physical click at the most likely checkbox column.
	-- Do NOT double-click the row; a second hit can turn the modifier back off.
	local y = titleObj.AbsolutePosition.Y + titleObj.AbsoluteSize.Y / 2
	local rootPos = modifierRoot.AbsolutePosition
	local rootSize = modifierRoot.AbsoluteSize
	local rowX = rowRoot and rowRoot.AbsolutePosition.X or rootPos.X
	local rowWidth = rowRoot and rowRoot.AbsoluteSize.X or rootSize.X

	local x = math.min(titleObj.AbsolutePosition.X - 34, rowX + 28)
	x = math.clamp(x, math.max(rootPos.X + 10, rowX + 8), math.min(rootPos.X + rootSize.X - 10, rowX + rowWidth - 8))

	print("[LobbyCreator] Modifier checkbox fallback:", modifierName, "x=", x, "y=", y)
	clickAt(x, y)
	return true
end


local function clickModifierExact(modifierName, keepCurrentScroll)
	local aliases = ModifierAliases[modifierName] or {modifierName}
	local info = getMissionInfoRoot()
	local modifierRoot = info and getPath(info, {"Main", "Info", "Modifiers"})

	if not modifierRoot then
		return clickModifier(modifierName)
	end

	if not keepCurrentScroll then
		resetModifierPanelScroll(modifierRoot)
	end

	for attempt = 1, 10 do
		local obj = searchVisibleUnder(modifierRoot, aliases, true) or searchVisibleUnder(modifierRoot, aliases, false)

		if obj and obj:IsA("GuiObject") then
			print("[LobbyCreator] Visible modifier:", modifierName, "attempt", attempt, "title=", obj:GetFullName())
			local ok = clickModifierCheckboxForTitle(obj, modifierRoot, modifierName)
			task.wait(0.06)
			return ok
		end

		modifierPanelScroll(modifierRoot, 108)
	end

	warn("[LobbyCreator] Visible modifier not found after panel scrolling:", modifierName)
	return clickModifier(modifierName)
end

local function waitForManualObjectiveOpen(objectiveAliases)
	notify("Manual assist needed", "Click OBJECTIVES once. I will continue after the objective page opens.", "info")
	print("[LobbyCreator] Manual assist: waiting for objective page to open.")

	local started = os.clock()
	while os.clock() - started <= 18 do
		if objectivePageLooksOpen(objectiveAliases) then
			print("[LobbyCreator] Manual assist detected objective page.")
			return true
		end
		task.wait(0.2)
	end

	return false
end

local function selectedModifiersInPanelOrder()
	local selected = modSet()
	local ordered = {}

	for _, name in ipairs(Modifiers) do
		if selected[name] then
			table.insert(ordered, name)
		end
	end

	return ordered
end

local function waitForManualCreatePage()
	notify("Manual assist needed", "Click BACK once if still on objectives. I will continue when CREATE is visible.", "info")
	print("[LobbyCreator] Manual assist: waiting for CREATE button/map page.")

	local started = os.clock()
	while os.clock() - started <= 18 do
		if findTextObject({"create"}, true, true) then
			print("[LobbyCreator] Manual assist detected CREATE button.")
			return true
		end
		task.wait(0.2)
	end

	return false
end

local function runMissionFlow()
	if FlowRunning then
		notify("Already running", "Mission flow is already in progress.", "error")
		return
	end

    if State.CreateMode == "Raid" then
        if type(SliceHubRaidChoiceAllowed) == "function" and not SliceHubRaidChoiceAllowed(State.RaidChoice) then
            warn("[SliceHub Free] " .. (type(SliceHubRaidLockedReason) == "function" and SliceHubRaidLockedReason(State.RaidChoice) or "This raid is unsupported in Free."))
            setOwnMenuVisible(true)
            refreshPreview()
            return
        end
        if State.RaidChoice == "Shiganshina (Col)" then
            notify("Colossal Spears-only", type(SliceHubColossalModeText) == "function" and SliceHubColossalModeText() or "COLOSSAL • SPEARS ONLY", "info")
            local ready, reason = V95LobbyWeaponPolicy.ColossalReady()
            if not ready then
                notify("Colossal is Spears-only", tostring(reason) .. ". Blades are unsupported for Colossal in V9.5.", "error")
                setOwnMenuVisible(true)
                refreshPreview()
                return
            end
        end
    end

	if CurrentMode ~= "Lobby" and CurrentMode ~= "MainMenu" and CurrentMode ~= "Unknown" then
		notify("Blocked by mode", "Current mode is " .. CurrentMode .. ".", "error")
		return
	end

	FlowRunning = true
	setOwnMenuVisible(false)

	local ok, err = pcall(function()
        local launchConfig = captureConfig()

		-----------------------------------------------------------------
		-- V4.2.0 RAID LOBBY FLOW
		-- Exact S_Missions direct path first; learned trace and visible UI are fallbacks.
		-----------------------------------------------------------------
		if launchConfig.CreateMode == "Raid" then
            if type(SliceHubRaidChoiceAllowed) == "function" and not SliceHubRaidChoiceAllowed(launchConfig.RaidChoice) then
                error(type(SliceHubRaidLockedReason) == "function" and SliceHubRaidLockedReason(launchConfig.RaidChoice) or "This raid is unsupported in Free.")
            end

			local raidInfo = V401LobbyRaid.Data[launchConfig.RaidChoice]
			if not raidInfo then error("Unknown raid choice: " .. tostring(launchConfig.RaidChoice)) end

			print("[LobbyCreator V4.3.0] Starting exact raid flow:", HttpService:JSONEncode(launchConfig))
			notify("Raid flow started", summary(), "info")
			saveLastMissionInfo()

			notify("V4.2 Raid Direct", "Trying exact Create → Modify → Start.", "info")
			local exactOk, exactReason = V3ExactMissionEngine.TryLaunch(launchConfig)
			if exactOk then
				notify("Raid direct launch", "Exact S_Missions raid launch triggered teleport.", "success")
				return
			end

			warn("[Slice V4.2][RAID] exact path failed:", tostring(exactReason))

			local fastOk, fastReason = tryLearnedRemoteLaunch(launchConfig)
			if fastOk then
				saveLastMissionInfo()
				notify("Raid trace fallback", "Learned raid path triggered teleport.", "success")
				return
			end

			print("[LobbyCreator V4.3.0] Exact:", tostring(exactReason), "| Trace:", tostring(fastReason), "-> visible Raid UI")
			notify("Raid UI fallback", "Direct and learned paths failed; using visible Raid UI.", "info")
			beginRemoteTrace(launchConfig)

			if not waitForText({"raids"}, true, 0.6) then
				clickText({"play"}, true, 3, "Open Play")
				turboWaitUntil(function()
					return findTextObject({"raids"}, true, true) ~= nil
						or findTextObject({"raid"}, false, true) ~= nil
				end, 0.65)
			end

			if not clickText({"raids"}, true, 4, "Open Raids") then
				if not clickText({"raid"}, false, 3, "Open Raid fallback") then
					error("Could not click RAIDS")
				end
			end

			turboWaitUntil(function()
				return findTextObject(raidInfo.Aliases, false, true) ~= nil
					or findTextObject({"create"}, true, true) ~= nil
			end, 0.85)

			if not clickText(raidInfo.Aliases, false, 5, "Select raid: " .. launchConfig.RaidChoice) then
				error("Could not select raid: " .. launchConfig.RaidChoice)
			end
			task.wait(0.06)

			setDifficultyByCycling()
			task.wait(0.03)

			turboWaitUntil(function()
				return findTextObject({"create"}, true, true) ~= nil
			end, 0.70)

			if not clickCreateExact() then
				error("Could not click CREATE for raid")
			end

			turboWaitUntil(function()
				return getMissionInfoRoot() ~= nil
			end, 0.85)

			if #State.Modifiers > 0 then
				if clickModifiersExact() then
					task.wait(0.025)

					do
						local info = getMissionInfoRoot()
						local modifierRoot = info and getPath(info, {"Main", "Info", "Modifiers"})
						resetModifierPanelScroll(modifierRoot)
					end

					for _, modifierName in ipairs(selectedModifiersInPanelOrder()) do
						clickModifierExact(modifierName, true)
						task.wait(0.018)
					end

					if not closeModifierPanelHard() then
						warn("[LobbyCreator V4.3.0] Raid modifiers stayed open; trying START fallback.")
					end
					task.wait(0.18)
				else
					warn("[LobbyCreator V4.3.0] Raid modifiers button not found; continuing.")
				end
			end

			if modifierPanelLooksOpen() then
				closeModifierPanelHard()
				task.wait(0.16)
			end

			saveLastMissionInfo()
			task.wait(0.01)

			if not clickStartExact() then
				if modifierPanelLooksOpen() then
					closeModifierPanelHard()
					task.wait(0.05)
				end
				if not clickStartExact() then
					error("Could not click START for raid")
				end
			end

			task.wait(0.12)
			endRemoteTrace()
			notify("Raid UI fallback sent", "Raid START clicked; fallback trace saved.", "success")
			return
		end

		print("[LobbyCreator] Starting mission flow:", HttpService:JSONEncode(launchConfig))
		notify("Mission flow started", summary(), "info")

        -- Save before START so mission runtime can read exact planned identity even on instant teleport.
        saveLastMissionInfo()

        notify("V4.2 Exact Engine", "Trying direct Create → Modify → Start.", "info")
        local exactOk, exactReason = V3ExactMissionEngine.TryLaunch(launchConfig)

        if exactOk then
            notify("Exact launch", "Direct mission engine triggered teleport.", "success")
            return
        end

        warn("[Slice V4.2][EXACT] direct path failed:", tostring(exactReason))

        local fastOk, fastReason = tryLearnedRemoteLaunch(launchConfig)
        if fastOk then
            saveLastMissionInfo()
            notify("Trace fallback", "Learned remote path triggered teleport.", "success")
            return
        end

        print("[Slice V3] Exact:", tostring(exactReason), "| Trace:", tostring(fastReason), "-> Turbo UI")
        notify("Turbo fallback", "Exact path unavailable; using visible UI fallback.", "info")
        beginRemoteTrace(launchConfig)

		-- Open the game mode selection if needed.
		if not waitForText({"missions"}, true, 0.6) then
			clickText({"play"}, true, 3, "Open Play")
            turboWaitUntil(function() return findTextObject({"missions"}, true, true) ~= nil end, 0.55)
		end

		if not clickText({"missions"}, true, 4, "Open Missions") then error("Could not click MISSIONS") end
        turboWaitUntil(function() return findTextObject({"maps", "shiganshina", "trost", "outskirts"}, false, true) ~= nil end, 0.70)

		if not waitForText({"maps"}, true, 0.75) and not waitForText({"shiganshina", "trost", "outskirts"}, true, 0.75) then
			warn("[LobbyCreator] Missions clicked, but map page was not detected yet. Retrying card-style click once.")
			clickText({"missions"}, true, 1.5, "Open Missions retry")
			task.wait(0.32)
		end

		local mapAliases = MapAliases[State.Map] or {State.Map}
		if not clickText(mapAliases, true, 5, "Select map: " .. State.Map) then
			if not clickText(mapAliases, false, 3, "Select map fallback: " .. State.Map) then
				error("Could not select map: " .. State.Map)
			end
		end
		task.wait(0.045)

		setDifficultyByCycling()
		task.wait(0.025)

		local objectiveAliases = ObjectiveAliases[State.Objective] or {State.Objective}

		if not clickMissionMainButton("Objectives_Missions", "Open Objectives") then
			error("Could not open OBJECTIVES")
		end
		turboWaitUntil(function() return objectivePageLooksOpen(objectiveAliases) end, 0.60)

		if not objectivePageLooksOpen(objectiveAliases) then
			if not clickObjectivesButtonUntilOpen(objectiveAliases) then
				warn("[LobbyCreator] Auto OBJECTIVES click failed. Entering manual assist.")
				if not waitForManualObjectiveOpen(objectiveAliases) then
					error("OBJECTIVES button clicked, but objective page did not open.")
				end
			end
		end

		if not clickObjectiveExact(State.Objective) then
			error("Could not select objective: " .. State.Objective)
		end
		task.wait(0.025)

		-- In this game, selecting an objective leaves you on the objective page.
		-- Go back to the map/difficulty page before pressing CREATE.
		clickObjectiveReturnExact()
        turboWaitUntil(function() return findTextObject({"create"}, true, true) ~= nil end, 0.65)

		if not findTextObject({"create"}, true, true) then
			waitForManualCreatePage()
		end

		if not clickCreateExact() then error("Could not click CREATE") end
        turboWaitUntil(function() return getMissionInfoRoot() ~= nil end, 0.75)

		if #State.Modifiers > 0 then
			if clickModifiersExact() then
				task.wait(0.025)

				-- Reset once, then toggle selected modifiers in the panel's top-to-bottom order.
				-- This is much faster than jumping back to the top for every modifier.
				do
					local info = getMissionInfoRoot()
					local modifierRoot = info and getPath(info, {"Main", "Info", "Modifiers"})
					resetModifierPanelScroll(modifierRoot)
				end

				for _, modifierName in ipairs(selectedModifiersInPanelOrder()) do
					clickModifierExact(modifierName, true)
					task.wait(0.018)
				end

				if not closeModifierPanelHard() then
					warn("[LobbyCreator] Modifiers stayed open after toggles; trying START fallback anyway.")
				end
				task.wait(0.18)
			else
				warn("[LobbyCreator] Modifiers button not found; skipping modifiers.")
			end
		end

		if modifierPanelLooksOpen() then
			closeModifierPanelHard()
			task.wait(0.16)
		end

		saveLastMissionInfo()
		task.wait(0.01)

		if not clickStartExact() then
			if modifierPanelLooksOpen() then closeModifierPanelHard(); task.wait(0.05) end
			if not clickStartExact() then error("Could not click START") end
		end

        task.wait(0.12)
        endRemoteTrace()
		notify("V3 fallback launch", "Turbo UI START clicked; trace saved.", "success")
	end)

    if RemoteTrace.Active then
        endRemoteTrace()
    end

	FlowRunning = false

	if not ok then
		warn("[LobbyCreator] Mission flow failed:", err)
		setOwnMenuVisible(true)
		notify("Mission flow failed", tostring(err), "error")
	end
end

local function startCountdown()
    if State.CreateMode == "Waves" and not SliceHubLobbyWavesAllowed() then
        notify("Premium only", "This tab unlocks only when you have Premium.", "info")
        return
    end

	CountdownToken += 1
	local token = CountdownToken

    if State.CreateMode == "Waves" then
        local function launchWaves()
            if FlowRunning then
                notify("Already running", "A lobby launch is already in progress.", "info")
                return
            end

            FlowRunning = true
            setOwnMenuVisible(false)
            saveLastMissionInfo()
            notify("Waves launch", "Direct Trost / Easy Create → Start.", "info")

            task.spawn(function()
                local ok, reason = V3ExactMissionEngine.TryLaunch({
                    CreateMode = "Waves",
                    Map = "Trost",
                    Objective = "Waves",
                    Difficulty = "Easy",
                    Modifiers = {},
                })

                FlowRunning = false
                if ok then
                    notify("Waves started", "Direct Waves launch triggered teleport.", "success")
                else
                    setOwnMenuVisible(true)
                    warn("[SliceHub Waves] direct launch failed:", reason)
                    notify("Waves launch failed", tostring(reason), "error")
                end
            end)
        end

        if not V98WavesUI.AutoStart or State.Delay <= 0 then
            launchWaves()
            return
        end

        notify("Countdown started", "Waves flow in " .. State.Delay .. " seconds.", "info")
        task.spawn(function()
            for remain = State.Delay, 1, -1 do
                if token ~= CountdownToken then
                    countdownLabel.Text = "Countdown: cancelled"
                    return
                end
                countdownLabel.Text = "Countdown: " .. remain .. " sec"
                task.wait(1)
            end
            if token == CountdownToken then
                countdownLabel.Text = "Countdown: launching Waves"
                launchWaves()
            end
        end)
        return
    end

	if not State.AutoStart or State.Delay <= 0 then runMissionFlow(); return end
	notify("Countdown started", State.CreateMode .. " flow in " .. State.Delay .. " seconds.", "info")
	task.spawn(function()
		for remain = State.Delay, 1, -1 do
			if token ~= CountdownToken then countdownLabel.Text = "Countdown: cancelled"; return end
			countdownLabel.Text = "Countdown: " .. remain .. " sec"
			task.wait(1)
		end
		if token == CountdownToken then
			countdownLabel.Text = "Countdown: launching flow"
			runMissionFlow()
			task.wait(0.8)
			if token == CountdownToken then countdownLabel.Text = "Countdown: idle" end
		end
	end)
end
createBtn.Activated:Connect(startCountdown)
cancelBtn.Activated:Connect(function() CountdownToken += 1; countdownLabel.Text = "Countdown: cancelled"; notify("Countdown cancelled", "Timer stopped.", "info") end)

-- V5.1 queue resume: after Auto Execute returns to Lobby, continue exactly one queued run.
task.spawn(function()
    task.wait(1.0)
    while gui.Parent do
        task.wait(0.45)
        local queue = V51RaidQueue.State or V51RaidQueue.Load()
        if queue.Enabled
            and not V51RaidQueue.AutoLaunchConsumed
            and not FlowRunning
            and detectMode() == "Lobby" then
            V51RaidQueue.AutoLaunchConsumed = true
            V51RaidQueue.ApplyCurrentToLobbyState()
            refreshAll()
            if V51RaidQueue.RefreshUI then V51RaidQueue.RefreshUI() end
            notify("Raid queue resume", "Launching queue entry " .. tostring(queue.Index) .. "/" .. tostring(#queue.Entries), "success")
            task.wait(0.35)
            runMissionFlow()
        end
    end
end)

