}

V96LobbyAutoUpgrade.BladeStats = {
    {Key = "ODMDamage", RemoteKey = "ODM_Damage", Label = "ODM Damage", Aliases = {"odm damage", "odm dmg"}},
    {Key = "BladeDurability", RemoteKey = "Blade_Durability", Label = "Blade Durability", Aliases = {"blade durability", "durability"}},
    {Key = "ODMGas", RemoteKey = "ODM_Gas", Label = "ODM Gas", Aliases = {"odm gas", "gas capacity"}},
