    {Key = "ODMRange", RemoteKey = "ODM_Range", Label = "ODM Range", Aliases = {"odm range"}},
    {Key = "CritDamage", RemoteKey = "Crit_Damage", Label = "Crit Damage", Aliases = {"crit damage", "critical damage"}},
    {Key = "ODMControl", RemoteKey = "ODM_Control", Label = "ODM Control", Aliases = {"odm control"}},
    {Key = "ODMSpeed", RemoteKey = "ODM_Speed", Label = "ODM Speed", Aliases = {"odm speed"}},
}

V96LobbyAutoUpgrade.SpearStats = {
    {Key = "TSDamage", RemoteKey = "TS_Damage", Label = "TS Damage", Aliases = {"ts damage", "thunder spear damage", "spear damage"}},
    {Key = "BlastRadius", RemoteKey = "Blast_Radius", Label = "Blast Radius", Aliases = {"blast radius", "explosion radius"}},
    {Key = "CritChance", RemoteKey = "Crit_Chance", Label = "Crit Chance", Aliases = {"crit chance", "critical chance"}},
    {Key = "TSGas", RemoteKey = "TS_Gas", Label = "TS Gas", Aliases = {"ts gas", "thunder spear gas", "spear gas"}},
    {Key = "TSRange", RemoteKey = "TS_Range", Label = "TS Range", Aliases = {"ts range", "thunder spear range", "spear range"}},
    {Key = "TSSpeed", RemoteKey = "TS_Speed", Label = "TS Speed", Aliases = {"ts speed", "thunder spear speed", "spear speed"}},
    {Key = "TSControl", RemoteKey = "TS_Control", Label = "TS Control", Aliases = {"ts control", "thunder spear control", "spear control"}},
    {Key = "CritDamage", RemoteKey = "Crit_Damage", Label = "Crit Damage", Aliases = {"crit damage", "critical damage"}},
}

function V96LobbyAutoUpgrade.StatsForWeapon(weapon)
    if weapon == "Spears" then return V96LobbyAutoUpgrade.SpearStats end
    if weapon == "Blades" then return V96LobbyAutoUpgrade.BladeStats end
    return {}
end

function V96LobbyAutoUpgrade.IsSelected(key)
    if V96LobbyAutoUpgrade.Selected[key] == nil then
        V96LobbyAutoUpgrade.Selected[key] = true
    end
    return V96LobbyAutoUpgrade.Selected[key] == true
end

function V96LobbyAutoUpgrade.Match(text, aliases)
    local value = cleanText(text)
    for _, alias in ipairs(aliases or {}) do
        alias = cleanText(alias)
        if value == alias then return true end
        if string.find(value, alias, 1, true) and #value <= #alias + 18 then return true end
    end
    return false
end

function V96LobbyAutoUpgrade.DetectWeapon()
    local spearScore, bladeScore = 0, 0

    local function scoreText(raw, weight)
        local value = string.lower(tostring(raw or ""))
        if value == "" then return end

        if string.find(value, "thunder spear", 1, true)
            or string.find(value, "thunderspear", 1, true)
            or string.find(value, "spear", 1, true) then
            spearScore += weight
        end

        if string.find(value, "blade", 1, true)
            or string.find(value, "sword", 1, true) then
            bladeScore += weight
        end
    end

    local liveCharacter = player.Character
    local liveBackpack = player:FindFirstChildOfClass("Backpack")

    for _, root in ipairs({liveCharacter, liveBackpack}) do
        if root then
            scoreText(root.Name, 1)
            for _, object in ipairs(root:GetDescendants()) do
                scoreText(object.Name, object:IsA("Tool") and 8 or 2)
                if object:IsA("StringValue") then scoreText(object.Value, 5) end
            end
        end
    end

    if liveCharacter then
        if liveCharacter:GetAttribute("Spears") ~= nil then spearScore += 12 end
        if liveCharacter:GetAttribute("Max_Spears") ~= nil then spearScore += 12 end
        if liveCharacter:GetAttribute("BladeDurability") ~= nil then bladeScore += 8 end
        if liveCharacter:GetAttribute("Blades") ~= nil then bladeScore += 8 end
    end

    for key, value in pairs(player:GetAttributes()) do
        scoreText(key, 4)
        scoreText(value, 4)
    end

    -- Native lobby equipment text is strong evidence only when it actually says
    -- equipped/loadout/current, so our own Auto Upgrade labels cannot bias detection.
    for _, object in ipairs(visibleGameTextObjects()) do
        local value = cleanText(object.Text)
        if string.find(value, "equipped", 1, true)
            or string.find(value, "loadout", 1, true)
            or string.find(value, "current gear", 1, true) then
            scoreText(value, 10)
        end
    end

    if spearScore >= bladeScore + 3 and spearScore >= 6 then
        return "Spears", spearScore, bladeScore
    end
    if bladeScore >= spearScore + 3 and bladeScore >= 6 then
        return "Blades", spearScore, bladeScore
    end

    -- Mission settings are only a last-resort hint; live equipment evidence above wins.
    local spearReady, bladesSaved = V95LobbyWeaponPolicy.Read()
    if spearReady == true and bladesSaved ~= true then return "Spears", spearScore, bladeScore end
    if bladesSaved == true and spearReady ~= true then return "Blades", spearScore, bladeScore end

    return V96LobbyAutoUpgrade.LastWeapon ~= "Unknown" and V96LobbyAutoUpgrade.LastWeapon or "Unknown", spearScore, bladeScore
end

function V96LobbyAutoUpgrade.Remote()
    local replicatedStorage = game:GetService("ReplicatedStorage")
    local assets = replicatedStorage:FindFirstChild("Assets")
    local remotes = assets and assets:FindFirstChild("Remotes")
    local remote = remotes and remotes:FindFirstChild("GET")
    if remote and remote:IsA("RemoteFunction") then return remote end
    return nil
end

function V96LobbyAutoUpgrade.SelectedRemoteKeys(weapon)
    local keys = {}
    for _, stat in ipairs(V96LobbyAutoUpgrade.StatsForWeapon(weapon)) do
        if V96LobbyAutoUpgrade.IsSelected(stat.Key) and stat.RemoteKey then
            keys[#keys + 1] = stat.RemoteKey
        end
    end
    return keys
end

function V96LobbyAutoUpgrade.CopyLevels(source)
    local output = {}
    if type(source) == "table" then
        for key, value in pairs(source) do
            if type(value) == "number" then output[tostring(key)] = value end
        end
    end
    return output
end

function V96LobbyAutoUpgrade.ParseProfile(result, weapon)
    if type(result) ~= "table" then return nil, nil, nil end

    local currentSlot = tostring(result.Current_Slot or "")
    local slots = type(result.Slots) == "table" and result.Slots or nil
    local slot = slots and slots[currentSlot] or nil
    if type(slot) ~= "table" then return nil, nil, nil end

    local upgrades = type(slot.Upgrades) == "table" and slot.Upgrades or nil
    local weaponLevels = upgrades and upgrades[weapon] or nil
    local levels = V96LobbyAutoUpgrade.CopyLevels(weaponLevels)

    local currency = type(slot.Currency) == "table" and slot.Currency or nil
    local progression = type(slot.Progression) == "table" and slot.Progression or nil
    local gold = currency and tonumber(currency.Gold) or nil
    local prestige = progression and tonumber(progression.Prestige) or nil

    return levels, gold, prestige
end

function V96LobbyAutoUpgrade.LevelGain(beforeLevels, afterLevels, keys)
    if type(beforeLevels) ~= "table" or type(afterLevels) ~= "table" then return nil end
    local gain = 0
    for _, key in ipairs(keys or {}) do
        local before = tonumber(beforeLevels[key])
        local after = tonumber(afterLevels[key])
        if before ~= nil and after ~= nil and after > before then
            gain += after - before
        end
    end
    return gain
end

function V96LobbyAutoUpgrade.NotifySuccess(weapon, gain, gold, manual)
    local now = os.clock()
    if not manual and now - (V96LobbyAutoUpgrade.SuccessToastAt or 0) < 2.25 then return end
    V96LobbyAutoUpgrade.SuccessToastAt = now

    local detail
    if type(gain) == "number" and gain > 0 then
        detail = tostring(weapon) .. " • " .. tostring(gain) .. " confirmed level gain"
    else
        detail = tostring(weapon) .. " • server confirmed upgrade pass"
    end
    if gold ~= nil then detail ..= " • Gold " .. tostring(math.floor(gold)) end
    notify("Gear successfully upgraded", detail, "success")
end

function V96LobbyAutoUpgrade.ClassifyResponse(result)
    if type(result) == "table" then return "SUCCESS" end
    if type(result) == "string" then
        local value = string.lower(result)
        if string.find(value, "max", 1, true) then return "MAXED" end
        if string.find(value, "gold", 1, true)
            or string.find(value, "fund", 1, true)
            or string.find(value, "currency", 1, true)
            or string.find(value, "afford", 1, true) then
            return "NO_GOLD"
        end
        return "REJECTED"
    end
    if result == false then return "REJECTED" end
    return "NO_PROGRESS"
end

function V96LobbyAutoUpgrade.InvokeBatch(keys)
    local remote = V96LobbyAutoUpgrade.Remote()
    if not remote then return false, nil, "GET RemoteFunction missing" end

    local ok, result = pcall(function()
        return remote:InvokeServer(
            "S_Equipment",
            "Upgrade",
            keys
        )
    end)

    if not ok then return false, nil, tostring(result) end
    return true, result, nil
end

function V96LobbyAutoUpgrade.StopAuto(reason)
    V96LobbyAutoUpgrade.Enabled = false
    V96LobbyAutoUpgrade.LastResultType = tostring(reason or "STOPPED")
end

function V96LobbyAutoUpgrade.RunPass(manual)
    if V96LobbyAutoUpgrade.Busy then return 0, "busy" end
    V96LobbyAutoUpgrade.Busy = true

    local weapon = V96LobbyAutoUpgrade.DetectWeapon()
    V96LobbyAutoUpgrade.Weapon = weapon
    if weapon ~= "Unknown" then V96LobbyAutoUpgrade.LastWeapon = weapon end

    if weapon == "Unknown" then
        V96LobbyAutoUpgrade.LastAction = "Waiting for equipped loadout detection"
        V96LobbyAutoUpgrade.Busy = false
        return 0, "unknown loadout"
    end

    local keys = V96LobbyAutoUpgrade.SelectedRemoteKeys(weapon)
    if #keys == 0 then
        V96LobbyAutoUpgrade.LastAction = "No stats selected"
        V96LobbyAutoUpgrade.Busy = false
        return 0, "no stats selected"
    end

    V96LobbyAutoUpgrade.Passes += 1
    V96LobbyAutoUpgrade.LastAction = "Sending " .. tostring(#keys) .. " selected " .. tostring(weapon) .. " stats"

    local ok, result, remoteError = V96LobbyAutoUpgrade.InvokeBatch(keys)
    if not ok then
        V96LobbyAutoUpgrade.LastAction = "Remote error • " .. tostring(remoteError)
        V96LobbyAutoUpgrade.LastResultType = "ERROR"
        V96LobbyAutoUpgrade.StopAuto("ERROR")
        notify("Auto Upgrade error", tostring(remoteError), "error")
        V96LobbyAutoUpgrade.Busy = false
        return 0, V96LobbyAutoUpgrade.LastAction
    end

    local resultType = V96LobbyAutoUpgrade.ClassifyResponse(result)
    V96LobbyAutoUpgrade.LastResultType = resultType

    if resultType == "SUCCESS" then
        local levels, gold, prestige = V96LobbyAutoUpgrade.ParseProfile(result, weapon)
        local before = V96LobbyAutoUpgrade.LastLevels[weapon]
        local gain = V96LobbyAutoUpgrade.LevelGain(before, levels, keys)

        if type(levels) == "table" then
            V96LobbyAutoUpgrade.LastLevels[weapon] = levels
        end
        if gold ~= nil then V96LobbyAutoUpgrade.LastGold = gold end
        if prestige ~= nil then V96LobbyAutoUpgrade.LastPrestige = prestige end

        local confirmed = (type(gain) == "number" and gain > 0) and gain or 1
        V96LobbyAutoUpgrade.Clicks += confirmed

        if type(gain) == "number" and gain > 0 then
            V96LobbyAutoUpgrade.LastAction = string.format(
                "Pass %d • +%d confirmed level%s",
                V96LobbyAutoUpgrade.Passes,
                gain,
                gain == 1 and "" or "s"
            )
        else
            V96LobbyAutoUpgrade.LastAction = "Pass " .. tostring(V96LobbyAutoUpgrade.Passes) .. " • server confirmed upgrade"
        end

        V96LobbyAutoUpgrade.NotifySuccess(weapon, gain, gold, manual == true)
        V96LobbyAutoUpgrade.Busy = false
        return confirmed, V96LobbyAutoUpgrade.LastAction
    end

    V96LobbyAutoUpgrade.StopAuto(resultType)

    if resultType == "MAXED" then
        V96LobbyAutoUpgrade.LastAction = "Selected gear stats MAXED"
        notify("Selected gear stats maxed", tostring(weapon) .. " • no further selected upgrades available", "success")
    elseif resultType == "NO_GOLD" then
        V96LobbyAutoUpgrade.LastAction = "Upgrade stopped • insufficient currency"
        notify("Upgrade stopped", "Insufficient currency for the next selected upgrade.", "error")
    elseif resultType == "REJECTED" then
        V96LobbyAutoUpgrade.LastAction = "Upgrade request rejected"
        notify("Upgrade stopped", tostring(result), "error")
    else
        local goldText = V96LobbyAutoUpgrade.LastGold ~= nil
            and (" • Last known Gold " .. tostring(math.floor(V96LobbyAutoUpgrade.LastGold)))
            or ""
        V96LobbyAutoUpgrade.LastAction = "No upgrade accepted • MAXED or unaffordable" .. goldText
        notify(
            "Upgrade stopped",
            "Server accepted no upgrade. Selected stats are maxed or current Gold cannot afford the next level.",
            "info"
        )
    end

    V96LobbyAutoUpgrade.Busy = false
    return 0, V96LobbyAutoUpgrade.LastAction
end

