-- Auto Prestige tab.
-- V9.7.3.3: Free = one manual button + dynamic confirmation; Premium = full automatic controls.
;(function()
local prestigePage = PageFrames["Auto Prestige"]
local prestigePanel = panel(prestigePage, UDim2.fromOffset(0, 0), UDim2.fromScale(1, 1))
local PrestigeReplicatedStorage = game:GetService("ReplicatedStorage")

V962LobbyAutoPrestige = V962LobbyAutoPrestige or {
    FileName = "SliceHub_AutoPrestige_v962.json",
    Enabled = false,
    Busy = false,
    Buff = "Luck",
    DropdownOpen = false,
    Thresholds = {
        [0] = 200000000,
        [1] = 300000000,
        [2] = 400000000,
        [3] = 500000000,
        [4] = 800000000,
        [5] = 1000000000,
    },
    Caps = {
        [0] = 200000000,
        [1] = 300000000,
        [2] = 400000000,
        [3] = 500000000,
        [4] = 800000000,
        [5] = 1000000000,
    },
    -- FREE only: prestige readiness is level-based, never Gold-based.
    -- Keys are the current Prestige. P4 -> P5 remains level 200.
    FreeLevelRequirements = {
        [0] = 100,
        [1] = 150,
        [2] = 175,
        [3] = 200,
        [4] = 200,
    },
    Minimum = 1000000,
    LastGold = nil,
    LastPrestige = nil,
    LastAction = "Idle",
    LastProbeAt = 0,
    ProbeInterval = 4.0,
    PendingOffers = nil,
    PendingProfile = nil,
    ConfirmationOpen = false,
    UI = {},
}
V962LobbyAutoPrestige.UI = type(V962LobbyAutoPrestige.UI) == "table" and V962LobbyAutoPrestige.UI or {}
V962LobbyAutoPrestige.ConfirmationOpen = false

function V962LobbyAutoPrestige.NormalizeBuff(value)
    if not SliceHubLobbyPrestigeBuffAllowed() then return "Luck" end
    value = tostring(value or "Luck")
    if value == "EXP" or value == "Gold" then return value end
    return "Luck"
end

function V962LobbyAutoPrestige.NormalizeThreshold(prestige, value)
    prestige = tonumber(prestige) or 0
    local cap = V962LobbyAutoPrestige.Caps[prestige]
    if cap == nil then return nil end
    if not SliceHubLobbyPrestigeThresholdsAllowed() then return cap end
    value = tonumber(value) or cap
    value = math.clamp(value, V962LobbyAutoPrestige.Minimum, cap)
    return math.floor(value / 1000000 + 0.5) * 1000000
end

function V962LobbyAutoPrestige.ApplyTierLimits()
    V962LobbyAutoPrestige.Buff = V962LobbyAutoPrestige.NormalizeBuff(V962LobbyAutoPrestige.Buff)
    if not SliceHubLobbyIsPremium() then
        -- Free is manual-confirm only. Never restore an old saved ON state.
        V962LobbyAutoPrestige.Enabled = false
    end
    for prestige = 0, 5 do
        V962LobbyAutoPrestige.Thresholds[prestige] =
            V962LobbyAutoPrestige.NormalizeThreshold(
                prestige,
                V962LobbyAutoPrestige.Thresholds[prestige]
            )
    end
end

function V962LobbyAutoPrestige.Load()
    if type(readfileFn) ~= "function" then return end
    local okRead, raw = pcall(readfileFn, V962LobbyAutoPrestige.FileName)
    if not okRead or type(raw) ~= "string" or raw == "" then return end

    local okDecode, decoded = pcall(function() return HttpService:JSONDecode(raw) end)
    if not okDecode or type(decoded) ~= "table" then return end

    V962LobbyAutoPrestige.Enabled = SliceHubLobbyIsPremium() and decoded.Enabled == true or false
    V962LobbyAutoPrestige.Buff = V962LobbyAutoPrestige.NormalizeBuff(decoded.Buff)

    if type(decoded.Thresholds) == "table" then
        for prestige = 0, 5 do
            local rawValue = decoded.Thresholds[tostring(prestige)]
                or decoded.Thresholds[prestige]
            local normalized = V962LobbyAutoPrestige.NormalizeThreshold(prestige, rawValue)
            if normalized then
                V962LobbyAutoPrestige.Thresholds[prestige] = normalized
            end
        end
    end

    V962LobbyAutoPrestige.ApplyTierLimits()
end

function V962LobbyAutoPrestige.Save()
    V962LobbyAutoPrestige.ApplyTierLimits()
    if type(writefileFn) ~= "function" then return false end

    local thresholds = {}
    for prestige = 0, 5 do
        thresholds[tostring(prestige)] = V962LobbyAutoPrestige.Thresholds[prestige]
    end

    local document = {
        Version = 1,
        Enabled = V962LobbyAutoPrestige.Enabled == true,
        Buff = V962LobbyAutoPrestige.Buff,
        Thresholds = thresholds,
    }

    local okEncode, encoded = pcall(function() return HttpService:JSONEncode(document) end)
    if not okEncode then return false end
    return pcall(writefileFn, V962LobbyAutoPrestige.FileName, encoded)
end

function V962LobbyAutoPrestige.Remote()
    if V96LobbyAutoUpgrade and type(V96LobbyAutoUpgrade.Remote) == "function" then
        return V96LobbyAutoUpgrade.Remote()
    end

    local assets = PrestigeReplicatedStorage:FindFirstChild("Assets")
    local remotes = assets and assets:FindFirstChild("Remotes")
    local remote = remotes and remotes:FindFirstChild("GET")
    if remote and remote:IsA("RemoteFunction") then return remote end
    return nil
end

function V962LobbyAutoPrestige.ParseProfile(profile)
    if type(profile) ~= "table" then return nil, nil, nil end

    local currentSlot = tostring(profile.Current_Slot or "")
    local slots = type(profile.Slots) == "table" and profile.Slots or nil
    local slot = slots and slots[currentSlot] or nil
    if type(slot) ~= "table" then return nil, nil, nil end

    local progression = type(slot.Progression) == "table" and slot.Progression or nil
    local currency = type(slot.Currency) == "table" and slot.Currency or nil

    local prestige = progression and tonumber(progression.Prestige) or nil
    local gold = currency and tonumber(currency.Gold) or nil
    local level = nil
    if progression then
        level = tonumber(progression.Level)
            or tonumber(progression.Current_Level)
            or tonumber(progression.CurrentLevel)
            or tonumber(progression.Player_Level)
            or tonumber(progression.PlayerLevel)
            or tonumber(progression.Lvl)
    end
    level = level
        or tonumber(slot.Level)
        or tonumber(slot.Current_Level)
        or tonumber(slot.CurrentLevel)
        or tonumber(profile.Level)
        or tonumber(profile.Current_Level)
        or tonumber(profile.CurrentLevel)

    return prestige, gold, slot, level
end

function V962LobbyAutoPrestige.ParseNumberText(value)
    local text = string.lower(tostring(value or ""))
    text = string.gsub(text, ",", "")
    text = string.gsub(text, "%s+", "")

    local numberText, suffix = string.match(text, "([%d%.]+)([kmb]?)")
    local numberValue = tonumber(numberText)
    if not numberValue then return nil end

    if suffix == "k" then numberValue *= 1000 end
    if suffix == "m" then numberValue *= 1000000 end
    if suffix == "b" then numberValue *= 1000000000 end
    return numberValue
end

function V962LobbyAutoPrestige.ReadNamedValue(nameNeedle)
    nameNeedle = string.lower(tostring(nameNeedle or ""))

    local attributeNames = {
        nameNeedle,
        string.upper(nameNeedle),
        string.sub(nameNeedle, 1, 1):upper() .. string.sub(nameNeedle, 2),
    }

    for _, attributeName in ipairs(attributeNames) do
        local value = player:GetAttribute(attributeName)
        if tonumber(value) ~= nil then return tonumber(value) end
    end

    for _, object in ipairs(player:GetDescendants()) do
        if (object:IsA("IntValue") or object:IsA("NumberValue"))
            and string.find(string.lower(object.Name), nameNeedle, 1, true) then
            return tonumber(object.Value)
        end
    end

    for _, object in ipairs(playerGui:GetDescendants()) do
        if object:IsDescendantOf(gui) then continue end
        if object:IsA("TextLabel") or object:IsA("TextButton") or object:IsA("TextBox") then
            local path = string.lower(object:GetFullName())
            local objectName = string.lower(object.Name)
            if string.find(path, nameNeedle, 1, true)
                or string.find(objectName, nameNeedle, 1, true) then
                local parsed = V962LobbyAutoPrestige.ParseNumberText(object.Text)
                if parsed ~= nil then return parsed end
            end
        end
    end

    return nil
end

function V962LobbyAutoPrestige.ReadLocalState()
    local prestige = V962LobbyAutoPrestige.ReadNamedValue("prestige")
    local gold = V962LobbyAutoPrestige.ReadNamedValue("gold")

    if prestige == nil and V96LobbyAutoUpgrade then
        prestige = tonumber(V96LobbyAutoUpgrade.LastPrestige)
    end
    if gold == nil and V96LobbyAutoUpgrade then
        gold = tonumber(V96LobbyAutoUpgrade.LastGold)
    end

    if prestige == nil then prestige = tonumber(V962LobbyAutoPrestige.LastPrestige) end
    if gold == nil then gold = tonumber(V962LobbyAutoPrestige.LastGold) end

    return prestige, gold
end

function V962LobbyAutoPrestige.FreeRequiredLevel(prestige)
    prestige = math.floor((tonumber(prestige) or -1) + 0.5)
    return V962LobbyAutoPrestige.FreeLevelRequirements[prestige]
end

function V962LobbyAutoPrestige.ReadLocalLevel()
    local _, _, _, profileLevel = V962LobbyAutoPrestige.ParseProfile(
        V962LobbyAutoPrestige.PendingProfile
    )
    if tonumber(profileLevel) ~= nil then return tonumber(profileLevel) end

    local level = V962LobbyAutoPrestige.ReadNamedValue("level")
    if level == nil then level = V962LobbyAutoPrestige.ReadNamedValue("lvl") end
    return tonumber(level)
end

function V962LobbyAutoPrestige.ProbeProfile(force)
    local now = os.clock()
    if not force
        and now - (V962LobbyAutoPrestige.LastProbeAt or 0) < V962LobbyAutoPrestige.ProbeInterval then
        return V962LobbyAutoPrestige.PendingProfile, V962LobbyAutoPrestige.PendingOffers
    end

    local remote = V962LobbyAutoPrestige.Remote()
    if not remote then return nil, nil, "GET RemoteFunction missing" end

    V962LobbyAutoPrestige.LastProbeAt = now

    local ok, profile, offers, aux = pcall(function()
        return remote:InvokeServer("S_Equipment", "Talents")
    end)

    if not ok then return nil, nil, tostring(profile) end

    if type(profile) == "table" then
        V962LobbyAutoPrestige.PendingProfile = profile
        local prestige, gold = V962LobbyAutoPrestige.ParseProfile(profile)
        if prestige ~= nil then V962LobbyAutoPrestige.LastPrestige = prestige end
        if gold ~= nil then V962LobbyAutoPrestige.LastGold = gold end
    end

    if type(offers) == "table" then
        V962LobbyAutoPrestige.PendingOffers = offers
    end

    return profile, offers, aux
end

function V962LobbyAutoPrestige.Memories()
    if V962LobbyAutoPrestige.MemoryData ~= nil then
        return V962LobbyAutoPrestige.MemoryData
    end

    local modules = PrestigeReplicatedStorage:FindFirstChild("Modules")
    local storage = modules and modules:FindFirstChild("Storage")
    local memoryModule = storage and storage:FindFirstChild("Memories")
    if not memoryModule or not memoryModule:IsA("ModuleScript") then return nil end

    local ok, data = pcall(require, memoryModule)
    if ok and type(data) == "table" then
        V962LobbyAutoPrestige.MemoryData = data
        return data
    end

    return nil
end

function V962LobbyAutoPrestige.FindTalentTagById(target)
    local memories = V962LobbyAutoPrestige.Memories()
    local talents = memories and memories.Talents
    if type(talents) ~= "table" then return nil end

    local targetText = tostring(target)

    local function search(node, depth)
        if type(node) ~= "table" or depth > 5 then return nil end

        for key, value in pairs(node) do
            if tostring(key) == targetText
                and type(value) == "table"
                and type(value.Tag) == "string"
                and value.Tag ~= "" then
                return value.Tag
            end
        end

        for _, value in pairs(node) do
            if type(value) == "table" then
                local found = search(value, depth + 1)
                if found then return found end
            end
        end

        return nil
    end

    return search(talents, 0)
end

function V962LobbyAutoPrestige.ResolveTalent(offers)
    if type(offers) ~= "table" then return nil end

    local ordered = {}
    for index = 1, #offers do ordered[#ordered + 1] = offers[index] end
    if #ordered == 0 then
        for _, value in pairs(offers) do ordered[#ordered + 1] = value end
    end

    for _, offer in ipairs(ordered) do
        if type(offer) == "string" or type(offer) == "number" then
            if tostring(offer) ~= "99" and tostring(offer) ~= "" then
                local mapped = V962LobbyAutoPrestige.FindTalentTagById(offer)
                if mapped then return mapped end

                if type(offer) == "string" and tonumber(offer) == nil then
                    return offer
                end
            end
        elseif type(offer) == "table" then
            if type(offer.Tag) == "string" and offer.Tag ~= "" then
                return offer.Tag
            end

            local nested = V962LobbyAutoPrestige.ResolveTalent(offer)
            if nested then return nested end
        end
    end

    return nil
end

function V962LobbyAutoPrestige.BuffTag()
    if V962LobbyAutoPrestige.Buff == "EXP" then return "EXP Boost" end
    if V962LobbyAutoPrestige.Buff == "Gold" then return "Gold Boost" end
    return "Luck Boost"
end

function V962LobbyAutoPrestige.FormatGold(value)
    value = tonumber(value) or 0
    if value >= 1000000000 then
        local scaled = value / 1000000000
        return (scaled % 1 == 0 and string.format("%.0fB", scaled) or string.format("%.2fB", scaled))
    end
    if value >= 1000000 then
        local scaled = value / 1000000
        return (scaled % 1 == 0 and string.format("%.0fM", scaled) or string.format("%.1fM", scaled))
    end
    return tostring(math.floor(value))
end

function V962LobbyAutoPrestige.ReadVerifiedState()
    local prestige, gold = V962LobbyAutoPrestige.ReadLocalState()
    local localLevel = V962LobbyAutoPrestige.ReadLocalLevel()
    local profile = V962LobbyAutoPrestige.ProbeProfile(true)
    local serverPrestige, serverGold, _, serverLevel = V962LobbyAutoPrestige.ParseProfile(profile)

    prestige = tonumber(serverPrestige) or tonumber(prestige)
    gold = tonumber(serverGold) or tonumber(gold)
    local level = tonumber(serverLevel) or tonumber(localLevel)
    if prestige ~= nil then prestige = math.floor(prestige + 0.5) end
    if level ~= nil then level = math.floor(level + 0.5) end

    if prestige ~= nil then V962LobbyAutoPrestige.LastPrestige = prestige end
    if gold ~= nil then V962LobbyAutoPrestige.LastGold = gold end
    return prestige, gold, level
end

function V962LobbyAutoPrestige.RequestFreePrestige()
    if SliceHubLobbyIsPremium() then
        return V962LobbyAutoPrestige.RunCheck(true)
    end
    if V962LobbyAutoPrestige.Busy then return false, "busy" end
    if V962LobbyAutoPrestige.ConfirmationOpen then return false, "confirmation open" end

    V962LobbyAutoPrestige.ApplyTierLimits()
    V962LobbyAutoPrestige.LastAction = "Checking level requirement..."
    if V962LobbyAutoPrestige.Refresh then V962LobbyAutoPrestige.Refresh() end

    local prestige, _, level = V962LobbyAutoPrestige.ReadVerifiedState()
    if prestige == nil or level == nil then
        V962LobbyAutoPrestige.LastAction = "Could not read current Prestige or Level"
        notify("Auto Prestige", V962LobbyAutoPrestige.LastAction .. ". Try again in a moment.", "error")
        return false, V962LobbyAutoPrestige.LastAction
    end

    local requiredLevel = V962LobbyAutoPrestige.FreeRequiredLevel(prestige)
    if requiredLevel == nil then
        V962LobbyAutoPrestige.LastAction =
            "P" .. tostring(prestige) .. " cannot prestige through the configured Free route"
        notify("Auto Prestige", V962LobbyAutoPrestige.LastAction, "info")
        return false, V962LobbyAutoPrestige.LastAction
    end

    if level < requiredLevel then
        V962LobbyAutoPrestige.LastAction =
            "P" .. tostring(prestige) .. " → P" .. tostring(prestige + 1)
            .. " requires Level " .. tostring(requiredLevel)
            .. " • You are Level " .. tostring(level)
        notify("Level requirement not reached", V962LobbyAutoPrestige.LastAction, "info")
        return false, V962LobbyAutoPrestige.LastAction
    end

    V962LobbyAutoPrestige.LastAction =
        "Ready to prestige P" .. tostring(prestige) .. " → P" .. tostring(prestige + 1)

    if type(V962LobbyAutoPrestige.ShowConfirmation) == "function" then
        V962LobbyAutoPrestige.ShowConfirmation(prestige, level, requiredLevel)
        return true, "confirmation shown"
    end

    notify("Auto Prestige", "Confirmation window is unavailable.", "error")
    return false, "confirmation unavailable"
end

function V962LobbyAutoPrestige.RunCheck(manual, freeConfirmed)
    local premiumMode = SliceHubLobbyIsPremium()
    if not premiumMode and freeConfirmed ~= true then
        return false, "free confirmation required"
    end
    if V962LobbyAutoPrestige.Busy then return false, "busy" end
    V962LobbyAutoPrestige.ApplyTierLimits()
    V962LobbyAutoPrestige.Busy = true

    local prestige, gold = V962LobbyAutoPrestige.ReadLocalState()
    local level = premiumMode and nil or V962LobbyAutoPrestige.ReadLocalLevel()

    if prestige == nil
        or (premiumMode and gold == nil)
        or (not premiumMode and level == nil) then
        local profile = V962LobbyAutoPrestige.ProbeProfile(true)
        local probedPrestige, probedGold, _, probedLevel =
            V962LobbyAutoPrestige.ParseProfile(profile)
        prestige = probedPrestige or prestige
        gold = probedGold or gold
        level = probedLevel or level
    end

    prestige = tonumber(prestige)
    gold = tonumber(gold)
    level = tonumber(level)

    if prestige == nil
        or (premiumMode and gold == nil)
        or (not premiumMode and level == nil) then
        V962LobbyAutoPrestige.LastAction = premiumMode
            and "Waiting for Prestige / Gold state"
            or "Waiting for Prestige / Level state"
        V962LobbyAutoPrestige.Busy = false
        if manual then
            notify(
                "Auto Prestige",
                premiumMode
                    and "Could not read current Prestige or Gold yet."
                    or "Could not read current Prestige or Level yet.",
                "info"
            )
        end
        return false, V962LobbyAutoPrestige.LastAction
    end

    prestige = math.floor(prestige + 0.5)
    if level ~= nil then level = math.floor(level + 0.5) end
    V962LobbyAutoPrestige.LastPrestige = prestige
    if gold ~= nil then V962LobbyAutoPrestige.LastGold = gold end

    local threshold = nil
    local requiredLevel = nil

    if premiumMode then
        threshold = V962LobbyAutoPrestige.Thresholds[prestige]
        if threshold == nil then
            V962LobbyAutoPrestige.LastAction =
                "Prestige " .. tostring(prestige) .. " is outside configured P0-P5"
            V962LobbyAutoPrestige.Busy = false
            if manual then notify("Auto Prestige", V962LobbyAutoPrestige.LastAction, "info") end
            return false, V962LobbyAutoPrestige.LastAction
        end

        if gold < threshold then
            V962LobbyAutoPrestige.LastAction =
                "P" .. tostring(prestige) .. " • "
                .. V962LobbyAutoPrestige.FormatGold(gold) .. " / "
                .. V962LobbyAutoPrestige.FormatGold(threshold)
            V962LobbyAutoPrestige.Busy = false
            if manual then
                notify("Prestige threshold not reached", V962LobbyAutoPrestige.LastAction, "info")
            end
            return false, V962LobbyAutoPrestige.LastAction
        end

        V962LobbyAutoPrestige.LastAction = "Threshold reached • preparing Talent choices"
    else
        requiredLevel = V962LobbyAutoPrestige.FreeRequiredLevel(prestige)
        if requiredLevel == nil then
            V962LobbyAutoPrestige.LastAction =
                "Prestige " .. tostring(prestige) .. " is outside the Free prestige route"
            V962LobbyAutoPrestige.Busy = false
            if manual then notify("Auto Prestige", V962LobbyAutoPrestige.LastAction, "info") end
            return false, V962LobbyAutoPrestige.LastAction
        end

        if level < requiredLevel then
            V962LobbyAutoPrestige.LastAction =
                "P" .. tostring(prestige) .. " → P" .. tostring(prestige + 1)
                .. " requires Level " .. tostring(requiredLevel)
                .. " • You are Level " .. tostring(level)
            V962LobbyAutoPrestige.Busy = false
            if manual then
                notify("Level requirement not reached", V962LobbyAutoPrestige.LastAction, "info")
            end
            return false, V962LobbyAutoPrestige.LastAction
        end

        V962LobbyAutoPrestige.LastAction = "Level reached • preparing Talent choices"
    end

    local profile, offers, probeError = V962LobbyAutoPrestige.ProbeProfile(true)
    if type(profile) ~= "table" then
        V962LobbyAutoPrestige.LastAction =
            "Talent preparation failed • " .. tostring(probeError or "no profile")
        V962LobbyAutoPrestige.Busy = false
        if manual then notify("Auto Prestige error", V962LobbyAutoPrestige.LastAction, "error") end
        return false, V962LobbyAutoPrestige.LastAction
    end

    local verifiedPrestige, verifiedGold, slot, verifiedLevel =
        V962LobbyAutoPrestige.ParseProfile(profile)
    if verifiedPrestige ~= nil then prestige = math.floor(verifiedPrestige + 0.5) end
    if verifiedGold ~= nil then gold = verifiedGold end
    if verifiedLevel ~= nil then level = math.floor(verifiedLevel + 0.5) end

    if premiumMode then
        threshold = V962LobbyAutoPrestige.Thresholds[prestige]
        if threshold == nil or gold == nil or gold < threshold then
            V962LobbyAutoPrestige.LastAction = "Server profile is below configured threshold"
            V962LobbyAutoPrestige.Busy = false
            return false, V962LobbyAutoPrestige.LastAction
        end
    else
        requiredLevel = V962LobbyAutoPrestige.FreeRequiredLevel(prestige)
        if requiredLevel == nil or level == nil or level < requiredLevel then
            V962LobbyAutoPrestige.LastAction = "Server profile is below the required level"
            V962LobbyAutoPrestige.Busy = false
            return false, V962LobbyAutoPrestige.LastAction
        end
    end

    if type(offers) ~= "table" and type(slot) == "table" then
        offers = slot.Next_Talents
    end
    if type(offers) ~= "table" then
        offers = V962LobbyAutoPrestige.PendingOffers
    end

    local talent = V962LobbyAutoPrestige.ResolveTalent(offers)
    if not talent then
        V962LobbyAutoPrestige.LastAction = "No valid offered Talent could be resolved"
        V962LobbyAutoPrestige.Busy = false
        if manual then
            notify(
                "Auto Prestige stopped",
                "No valid offered Talent could be resolved from S_Equipment/Talents.",
                "error"
            )
        end
        return false, V962LobbyAutoPrestige.LastAction
    end

    local selection = {
        Boosts = V962LobbyAutoPrestige.BuffTag(),
        Talents = talent,
    }

    V962LobbyAutoPrestige.LastAction =
        "Prestiging P" .. tostring(prestige)
        .. " • " .. tostring(selection.Boosts)
        .. " • " .. tostring(talent)

    local remote = V962LobbyAutoPrestige.Remote()
    if not remote then
        V962LobbyAutoPrestige.LastAction = "GET RemoteFunction missing"
        V962LobbyAutoPrestige.Busy = false
        return false, V962LobbyAutoPrestige.LastAction
    end

    local ok, newProfile, extraA, extraB = pcall(function()
        return remote:InvokeServer(
            "S_Equipment",
            "Prestige",
            selection
        )
    end)

    if not ok then
        V962LobbyAutoPrestige.LastAction = "Prestige remote error • " .. tostring(newProfile)
        V962LobbyAutoPrestige.Busy = false
        if manual then notify("Auto Prestige error", tostring(newProfile), "error") end
        return false, V962LobbyAutoPrestige.LastAction
    end

    local newPrestige, newGold = V962LobbyAutoPrestige.ParseProfile(newProfile)
    if newPrestige ~= nil and newPrestige > prestige then
        V962LobbyAutoPrestige.LastPrestige = newPrestige
        V962LobbyAutoPrestige.LastGold = newGold
        V962LobbyAutoPrestige.PendingOffers = nil
        V962LobbyAutoPrestige.PendingProfile = newProfile
        V962LobbyAutoPrestige.LastAction =
            "SUCCESS • P" .. tostring(prestige) .. " → P" .. tostring(newPrestige)
            .. " • " .. tostring(selection.Boosts)

        if V96LobbyAutoUpgrade then
            V96LobbyAutoUpgrade.LastPrestige = newPrestige
            V96LobbyAutoUpgrade.LastGold = newGold
            V96LobbyAutoUpgrade.LastLevels = {}
        end

        notify(
            "Prestige successful",
            "P" .. tostring(prestige) .. " → P" .. tostring(newPrestige)
                .. " • " .. tostring(selection.Boosts)
                .. " • Talent: " .. tostring(talent),
            "success"
        )

        V962LobbyAutoPrestige.Save()
        V962LobbyAutoPrestige.Busy = false
        return true, V962LobbyAutoPrestige.LastAction
    end

    local rejection = type(newProfile) == "string"
        and tostring(newProfile)
        or "Server did not confirm a Prestige increase"
    V962LobbyAutoPrestige.LastAction = "Prestige not confirmed • " .. rejection

    if V962LobbyAutoPrestige.Enabled then
        V962LobbyAutoPrestige.Enabled = false
        V962LobbyAutoPrestige.Save()
    end

    notify("Auto Prestige stopped", V962LobbyAutoPrestige.LastAction, "error")
    V962LobbyAutoPrestige.Busy = false
    return false, V962LobbyAutoPrestige.LastAction
end

