local function makePrestigeSlider(prestige, y)
    local cap = V962LobbyAutoPrestige.Caps[prestige]
    local row = Instance.new("Frame")
    row.Position = UDim2.fromOffset(14, y)
    row.Size = UDim2.new(1, -28, 0, 42)
    row.BackgroundTransparency = 1
    row.Parent = prestigePanel

    local rowLabel = label(row, "", UDim2.fromOffset(0, 0), UDim2.new(1, 0, 0, 18), true)
    rowLabel.TextSize = 10

    local track = Instance.new("Frame")
    track.Position = UDim2.fromOffset(0, 23)
    track.Size = UDim2.new(1, 0, 0, 10)
    track.BackgroundColor3 = Theme.Panel2
    track.BorderSizePixel = 0
    track.Parent = row
    corner(track, 10)
    stroke(track, Theme.Stroke, 0.5)

    local fill = Instance.new("Frame")
    fill.Size = UDim2.new(0, 0, 1, 0)
    fill.BackgroundColor3 = Theme.Accent
    fill.BorderSizePixel = 0
    fill.Parent = track
    corner(fill, 10)

    local knob = Instance.new("Frame")
    knob.AnchorPoint = Vector2.new(0.5, 0.5)
    knob.Position = UDim2.new(0, 0, 0.5, 0)
    knob.Size = UDim2.fromOffset(16, 16)
    knob.BackgroundColor3 = Theme.Text
    knob.BorderSizePixel = 0
    knob.ZIndex = 5
    knob.Parent = track
    corner(knob, 16)

    local dragging = false

    local function refresh()
        local minimum = V962LobbyAutoPrestige.Minimum
        local value = V962LobbyAutoPrestige.Thresholds[prestige]
        local ratio = math.clamp((value - minimum) / math.max(1, cap - minimum), 0, 1)
        fill.Size = UDim2.new(ratio, 0, 1, 0)
        knob.Position = UDim2.new(ratio, 0, 0.5, 0)
        rowLabel.Text =
            "PRESTIGE " .. tostring(prestige)
            .. "   •   " .. V962LobbyAutoPrestige.FormatGold(value)
            .. "   [" .. V962LobbyAutoPrestige.FormatGold(minimum)
            .. " → " .. V962LobbyAutoPrestige.FormatGold(cap) .. "]"
            .. (SliceHubLobbyPrestigeThresholdsAllowed() and "" or "  🔒")
    end

    local function setFromX(screenX)
        if not SliceHubLobbyPrestigeThresholdsAllowed() then return end
        local x = track.AbsolutePosition.X
        local width = math.max(1, track.AbsoluteSize.X)
        local ratio = math.clamp((screenX - x) / width, 0, 1)
        local raw = V962LobbyAutoPrestige.Minimum
            + (cap - V962LobbyAutoPrestige.Minimum) * ratio
        local rounded = math.floor(raw / 1000000 + 0.5) * 1000000
        V962LobbyAutoPrestige.Thresholds[prestige] =
            V962LobbyAutoPrestige.NormalizeThreshold(prestige, rounded)
        refresh()
    end

    track.InputBegan:Connect(function(input)
        if input.UserInputType == Enum.UserInputType.MouseButton1
            or input.UserInputType == Enum.UserInputType.Touch then
            if not SliceHubLobbyPrestigeThresholdsAllowed() then
                notify("Premium locked", "Gold Threshold Per Prestige is available in SliceHub Premium.", "error")
                return
            end
            dragging = true
            setFromX(input.Position.X)
        end
    end)

    track.InputEnded:Connect(function(input)
        if input.UserInputType == Enum.UserInputType.MouseButton1
            or input.UserInputType == Enum.UserInputType.Touch then
            dragging = false
            V962LobbyAutoPrestige.Save()
        end
    end)

    UserInputService.InputChanged:Connect(function(input)
        if dragging
            and (input.UserInputType == Enum.UserInputType.MouseMovement
                or input.UserInputType == Enum.UserInputType.Touch) then
            setFromX(input.Position.X)
        end
    end)

    UserInputService.InputEnded:Connect(function(input)
        if dragging
            and (input.UserInputType == Enum.UserInputType.MouseButton1
                or input.UserInputType == Enum.UserInputType.Touch) then
            dragging = false
            V962LobbyAutoPrestige.Save()
        end
    end)

    sliderRows[prestige] = {
        Refresh = refresh,
        Row = row,
    }

    refresh()
end

