function V962LobbyAutoPrestige.ShowConfirmation(prestige, level, requiredLevel)
    if SliceHubLobbyIsPremium() then return false end
    prestige = math.floor((tonumber(prestige) or 0) + 0.5)
    level = math.floor((tonumber(level) or 0) + 0.5)
    requiredLevel = math.floor((tonumber(requiredLevel) or 0) + 0.5)
    V962LobbyAutoPrestige.ConfirmationOpen = true
    V962LobbyAutoPrestige.UI.ConfirmTitle.Text =
        "Prestige to P" .. tostring(prestige + 1) .. "?"
    V962LobbyAutoPrestige.UI.ConfirmMessage.Text =
        "Current Prestige: P" .. tostring(prestige)
        .. "\nRequired Level: " .. tostring(requiredLevel)
        .. "   •   Your Level: " .. tostring(level)
        .. "\n\nAre you sure you want to prestige to P" .. tostring(prestige + 1) .. "?"
    V962LobbyAutoPrestige.UI.ConfirmOverlay.Visible = true
    return true
end

