V962LobbyAutoPrestige.Refresh = function()
    V962LobbyAutoPrestige.ApplyTierLimits()

    local premiumMode = SliceHubLobbyIsPremium()
    if not premiumMode then V962LobbyAutoPrestige.DropdownOpen = false end

    chooseBuffButton.Visible = premiumMode
    chooseBuffButton.Text =
        "CHOOSE BUFF  "
        .. (V962LobbyAutoPrestige.DropdownOpen and "▼" or ">")
        .. "   " .. string.upper(V962LobbyAutoPrestige.Buff)
    chooseBuffButton.BackgroundColor3 = Theme.CardOn

    buffHolder.Visible = premiumMode and V962LobbyAutoPrestige.DropdownOpen
    prestigeInfo.Text = premiumMode
        and "Premium automatically prestiges when your selected threshold is reached, using the chosen permanent boost."
        or "Free checks your current Prestige and required Level. When ready, it asks you to confirm before prestiging."

    for buffName, buffButton in pairs(buffButtons) do
        local selected = buffName == V962LobbyAutoPrestige.Buff
        buffButton.BackgroundColor3 = selected and Theme.Accent or Theme.Card
        buffButton.TextColor3 = selected and Theme.Text or Theme.Muted
        buffButton.Text = string.upper(buffName)
    end

    for prestige = 0, 5 do
        local row = sliderRows[prestige]
        if row and row.Row then row.Row.Visible = premiumMode end
        if row and row.Refresh then row.Refresh() end
    end

    checkPrestigeButton.Visible = premiumMode
    if premiumMode then
        autoPrestigeButton.Position = UDim2.fromOffset(14, 444)
        autoPrestigeButton.Size = UDim2.new(0.5, -18, 0, 34)
        autoPrestigeButton.Text =
            "AUTO PRESTIGE: " .. (V962LobbyAutoPrestige.Enabled and "ON" or "OFF")
        autoPrestigeButton.BackgroundColor3 =
            V962LobbyAutoPrestige.Enabled and Theme.Accent or Theme.Card
        checkPrestigeButton.Text =
            V962LobbyAutoPrestige.Busy and "WORKING..." or "CHECK NOW"
        prestigeStatus.Position = UDim2.fromOffset(14, 486)
    else
        autoPrestigeButton.Position = UDim2.fromOffset(14, 88)
        autoPrestigeButton.Size = UDim2.new(1, -28, 0, 40)
        autoPrestigeButton.Text =
            V962LobbyAutoPrestige.Busy and "PRESTIGING..." or "AUTO PRESTIGE"
        autoPrestigeButton.BackgroundColor3 = Theme.Accent
        prestigeStatus.Position = UDim2.fromOffset(14, 142)
    end

    local prestige, gold = V962LobbyAutoPrestige.ReadLocalState()
    if premiumMode then
        if prestige ~= nil and gold ~= nil then
            prestige = math.floor(prestige + 0.5)
            local threshold = V962LobbyAutoPrestige.Thresholds[prestige]
            local thresholdText = threshold
                and V962LobbyAutoPrestige.FormatGold(threshold)
                or "N/A"
            prestigeStatus.Text =
                "P" .. tostring(prestige)
                .. " • Gold " .. V962LobbyAutoPrestige.FormatGold(gold)
                .. " • Required " .. thresholdText
                .. " • " .. V962LobbyAutoPrestige.LastAction
        else
            prestigeStatus.Text = V962LobbyAutoPrestige.LastAction
        end
    else
        local level = V962LobbyAutoPrestige.ReadLocalLevel()
        if prestige ~= nil and level ~= nil then
            prestige = math.floor(prestige + 0.5)
            level = math.floor(level + 0.5)
            local requiredLevel = V962LobbyAutoPrestige.FreeRequiredLevel(prestige)
            prestigeStatus.Text =
                "P" .. tostring(prestige)
                .. " • Level " .. tostring(level)
                .. " • Required Level " .. tostring(requiredLevel or "N/A")
                .. " • " .. V962LobbyAutoPrestige.LastAction
        else
            prestigeStatus.Text = V962LobbyAutoPrestige.LastAction
        end
    end
end

chooseBuffButton.Activated:Connect(function()
    if not SliceHubLobbyPrestigeBuffAllowed() then
        notify("Premium locked", "Prestige Buff Selection is available in SliceHub Premium.", "error")
        return
    end
    V962LobbyAutoPrestige.DropdownOpen = not V962LobbyAutoPrestige.DropdownOpen
    V962LobbyAutoPrestige.Refresh()
end)

autoPrestigeButton.Activated:Connect(function()
    if SliceHubLobbyIsPremium() then
        V962LobbyAutoPrestige.Enabled = not V962LobbyAutoPrestige.Enabled
        V962LobbyAutoPrestige.LastAction =
            V962LobbyAutoPrestige.Enabled and "Auto Prestige armed" or "Auto Prestige stopped"
        V962LobbyAutoPrestige.Save()
        V962LobbyAutoPrestige.Refresh()
        return
    end

    task.spawn(function()
        V962LobbyAutoPrestige.RequestFreePrestige()
        V962LobbyAutoPrestige.Refresh()
    end)
end)

checkPrestigeButton.Activated:Connect(function()
    if not SliceHubLobbyIsPremium() then return end
    task.spawn(function()
        V962LobbyAutoPrestige.RunCheck(true)
        V962LobbyAutoPrestige.Refresh()
    end)
end)

V962LobbyAutoPrestige.Refresh()

task.spawn(function()
    while gui.Parent do
        task.wait(0.75)

        if SliceHubLobbyIsPremium()
            and V962LobbyAutoPrestige.Enabled
            and not V962LobbyAutoPrestige.Busy then
            V962LobbyAutoPrestige.RunCheck(false)
        end

        if ActiveTab == "Auto Prestige" and V962LobbyAutoPrestige.Refresh then
            V962LobbyAutoPrestige.Refresh()
        end
    end
end)

end)()



