function V97LobbySkillTree.NormalizeChoice(group, value)
    local options = V97LobbySkillTree.Options[group]
    if type(options) ~= "table" then return value end
    value = tostring(value or "")
    for _, option in ipairs(options) do
        if option == value then return value end
    end
    return options[1]
end

function V97LobbySkillTree.Load()
    if type(readfileFn) ~= "function" then return end
    local okRead, raw = pcall(readfileFn, V97LobbySkillTree.FileName)
    if not okRead or type(raw) ~= "string" or raw == "" then return end
    local okDecode, decoded = pcall(function() return HttpService:JSONDecode(raw) end)
    if not okDecode or type(decoded) ~= "table" then return end

    V97LobbySkillTree.Enabled = decoded.Enabled == true
    V97LobbySkillTree.Middle = V97LobbySkillTree.NormalizeChoice("Middle", decoded.Middle)
    V97LobbySkillTree.Left = V97LobbySkillTree.NormalizeChoice("Left", decoded.Left)
    V97LobbySkillTree.Right = V97LobbySkillTree.NormalizeChoice("Right", decoded.Right)
    if type(decoded.Priority) == "table" then
        for index = 1, 3 do
            V97LobbySkillTree.Priority[index] =
                V97LobbySkillTree.NormalizeChoice("Priority", decoded.Priority[index])
        end
    end
end

function V97LobbySkillTree.Save()
    if type(writefileFn) ~= "function" then return false end
    local doc = {
        Version = 1,
        Enabled = V97LobbySkillTree.Enabled == true,
        Middle = V97LobbySkillTree.Middle,
        Left = V97LobbySkillTree.Left,
        Right = V97LobbySkillTree.Right,
        Priority = {
            V97LobbySkillTree.Priority[1],
            V97LobbySkillTree.Priority[2],
            V97LobbySkillTree.Priority[3],
        },
    }
    local okEncode, encoded = pcall(function() return HttpService:JSONEncode(doc) end)
    if not okEncode then return false end
    return pcall(writefileFn, V97LobbySkillTree.FileName, encoded)
end

function V97LobbySkillTree.Remote()
    if V96LobbyAutoUpgrade and type(V96LobbyAutoUpgrade.Remote) == "function" then
        return V96LobbyAutoUpgrade.Remote()
    end

    local replicatedStorage = game:GetService("ReplicatedStorage")
    local assets = replicatedStorage:FindFirstChild("Assets")
    local remotes = assets and assets:FindFirstChild("Remotes")
    local remote = remotes and remotes:FindFirstChild("GET")

    if remote and remote:IsA("RemoteFunction") then
        return remote
    end

    return nil
end

function V97LobbySkillTree.ResolveSlot(profile)
    if type(profile) ~= "table" then return nil, nil end

    local slots = type(profile.Slots) == "table" and profile.Slots or nil
    if not slots then return nil, nil end

    -- Exact game behavior from Modules.Core.Update.Get_Data:
    -- Current slot is cached from Player:GetAttribute("Slot"), not required from Data.Current_Slot.
    local slotKey = player:GetAttribute("Slot")
    if slotKey == nil then
        slotKey = profile.Current_Slot
    end

    if slotKey ~= nil then
        local direct = slots[slotKey]
        if type(direct) == "table" then
            return slotKey, direct
        end

        local textKey = tostring(slotKey)
        local textSlot = slots[textKey]
        if type(textSlot) == "table" then
            return textKey, textSlot
        end
    end

    -- Last-resort single-slot fallback for executors that hide the Slot attribute briefly.
    local onlyKey, onlySlot, count = nil, nil, 0
    for key, value in pairs(slots) do
        if type(value) == "table" then
            count += 1
            onlyKey, onlySlot = key, value
            if count > 1 then break end
        end
    end

    if count == 1 then
        return onlyKey, onlySlot
    end

    return nil, nil
end

function V97LobbySkillTree.ParseProfile(profile)
    if type(profile) ~= "table" then return nil end

    local currentSlot, slot = V97LobbySkillTree.ResolveSlot(profile)
    if type(slot) ~= "table" then return nil end

    local weapon = tostring(slot.Weapon or "")
    if weapon ~= "Blades" and weapon ~= "Spears" then
        weapon = V96LobbyAutoUpgrade
            and V96LobbyAutoUpgrade.DetectWeapon
            and V96LobbyAutoUpgrade.DetectWeapon()
            or "Unknown"
    end

    local skills = type(slot.Skills) == "table" and slot.Skills or {}
    local unlocked = type(skills.Unlocked) == "table" and skills.Unlocked or {}
    local unlockedSet = {}
    for _, id in ipairs(unlocked) do unlockedSet[tostring(id)] = true end

    local sp = tonumber(skills.SP)
        or tonumber(skills.Skill_Points)
        or tonumber(skills.Points)
        or tonumber(slot.Skill_Points)
        or (type(slot.Progression) == "table" and tonumber(slot.Progression.Skill_Points))
        or (V97LobbySkillTree.ReadSPFromGui and V97LobbySkillTree.ReadSPFromGui())
        or nil

    return {
        Profile = profile,
        Slot = slot,
        Weapon = weapon,
        Unlocked = unlocked,
        UnlockedSet = unlockedSet,
        SP = sp,
    }
end

function V97LobbySkillTree.IsProfile(profile)
    if type(profile) ~= "table" then return false end

    local slots = rawget(profile, "Slots")
    if type(slots) ~= "table" then return false end

    local _, slot = V97LobbySkillTree.ResolveSlot(profile)
    if type(slot) ~= "table" then return false end

    local skills = rawget(slot, "Skills")
    return type(skills) == "table"
        and type(rawget(skills, "Unlocked")) == "table"
end

function V97LobbySkillTree.ReadSPFromGui()
    local best = nil
    for _, object in ipairs(playerGui:GetDescendants()) do
        if object:IsDescendantOf(gui) then continue end
        if object:IsA("TextLabel") or object:IsA("TextButton") then
            local number = string.match(string.upper(tostring(object.Text or "")), "SKILLS%s*%[%s*(%d+)%s*SP%s*%]")
            if number then best = tonumber(number) or best end
        end
    end
    return best
end

function V97LobbySkillTree.GetFunctionUpvalues(fn)
    if debug and type(debug.getupvalues) == "function" then
        local ok, values = pcall(debug.getupvalues, fn)
        if ok and type(values) == "table" then return values end
    end

    if type(getupvalues) == "function" then
        local ok, values = pcall(getupvalues, fn)
        if ok and type(values) == "table" then return values end
    end

    return nil
end

function V97LobbySkillTree.ProfileFromController(candidate)
    if type(candidate) ~= "table" then return nil end

    local cache = rawget(candidate, "Cache")
    local modules = rawget(candidate, "Modules")

    if type(cache) ~= "table" or type(modules) ~= "table" then
        return nil
    end

    local data = rawget(cache, "Data")
    if V97LobbySkillTree.IsProfile(data) then
        local cachedPlayer = rawget(cache, "Player")

        if cachedPlayer == nil or cachedPlayer == player then
            return data
        end
    end

    return nil
end

function V97LobbySkillTree.FindClientCacheProfile()
    local now = os.clock()

    if V97LobbySkillTree.ControllerProfile
        and now - (V97LobbySkillTree.ControllerProfileAt or 0) < 1.0
        and V97LobbySkillTree.IsProfile(V97LobbySkillTree.ControllerProfile) then
        return V97LobbySkillTree.ControllerProfile, "Cache.Data"
    end

    if type(getgc) ~= "function" then
        return nil, nil
    end

    local ok, objects = pcall(getgc, true)
    if not ok or type(objects) ~= "table" then
        return nil, nil
    end

    -- First pass: the normal client controller table itself.
    for _, object in ipairs(objects) do
        local profile = V97LobbySkillTree.ProfileFromController(object)
        if profile then
            V97LobbySkillTree.ControllerProfile = profile
            V97LobbySkillTree.ControllerProfileAt = now
            return profile, "Cache.Data"
        end
    end

    -- Some executors expose the controller only through Lua closure upvalues.
    for _, object in ipairs(objects) do
        if type(object) == "function" then
            local upvalues = V97LobbySkillTree.GetFunctionUpvalues(object)

            if type(upvalues) == "table" then
                for _, value in pairs(upvalues) do
                    local profile = V97LobbySkillTree.ProfileFromController(value)
                    if profile then
                        V97LobbySkillTree.ControllerProfile = profile
                        V97LobbySkillTree.ControllerProfileAt = now
                        return profile, "Cache.Data via upvalue"
                    end
                end
            end
        end
    end

    return nil, nil
end

function V97LobbySkillTree.FindCachedProfile()
    if V97LobbySkillTree.IsProfile(V97LobbySkillTree.LastProfile) then
        return V97LobbySkillTree.LastProfile, "last response"
    end

    if V962LobbyAutoPrestige
        and V97LobbySkillTree.IsProfile(V962LobbyAutoPrestige.PendingProfile) then
        return V962LobbyAutoPrestige.PendingProfile, "prestige cache"
    end

    local exactProfile, exactSource = V97LobbySkillTree.FindClientCacheProfile()
    if exactProfile then
        return exactProfile, exactSource
    end

    local now = os.clock()
    if V97LobbySkillTree.CachedScanProfile
        and now - (V97LobbySkillTree.CachedScanAt or 0) < 1.0
        and V97LobbySkillTree.IsProfile(V97LobbySkillTree.CachedScanProfile) then
        return V97LobbySkillTree.CachedScanProfile, "recent raw cache scan"
    end

    if type(getgc) ~= "function" then return nil, nil end

    local ok, objects = pcall(getgc, true)
    if not ok or type(objects) ~= "table" then return nil, nil end

    local detectedWeapon = V96LobbyAutoUpgrade
        and V96LobbyAutoUpgrade.DetectWeapon
        and V96LobbyAutoUpgrade.DetectWeapon()
        or "Unknown"

    local bestProfile, bestScore = nil, -math.huge

    for _, object in ipairs(objects) do
        if V97LobbySkillTree.IsProfile(object) then
            local state = V97LobbySkillTree.ParseProfile(object)

            if state then
                local score = 0
                if state.Weapon == detectedWeapon then score += 1000 end
                if state.Weapon == "Blades" or state.Weapon == "Spears" then score += 100 end
                score += math.min(500, #(state.Unlocked or {}))

                if score > bestScore then
                    bestScore, bestProfile = score, object
                end
            end
        end
    end

    V97LobbySkillTree.CachedScanAt = now
    V97LobbySkillTree.CachedScanProfile = bestProfile

    if bestProfile then
        return bestProfile, "raw profile cache"
    end

    return nil, nil
end

function V97LobbySkillTree.ProbeProfile()
    local cached, source = V97LobbySkillTree.FindCachedProfile()
    if cached then
        V97LobbySkillTree.LastProfile = cached
        V97LobbySkillTree.ProfileSource = source
        return cached, nil
    end
    local remote = V97LobbySkillTree.Remote()
    if not remote then return nil, "GET RemoteFunction missing" end
    local ok, profile = pcall(function()
        return remote:InvokeServer("S_Equipment", "Talents")
    end)
    if ok and V97LobbySkillTree.IsProfile(profile) then
        V97LobbySkillTree.LastProfile = profile
        V97LobbySkillTree.ProfileSource = "Talents response"
        return profile, nil
    end
    return nil, ok and "no live profile found" or tostring(profile)
end

function V97LobbySkillTree.SkillDefinitions()
    if V97LobbySkillTree.Definitions ~= nil then
        return V97LobbySkillTree.Definitions or nil
    end

    local replicatedStorage = game:GetService("ReplicatedStorage")
    local modules = replicatedStorage:FindFirstChild("Modules")
    local storage = modules and modules:FindFirstChild("Storage")
    local skillModule = storage and storage:FindFirstChild("Skills")

    if not skillModule and modules then
        for _, object in ipairs(modules:GetDescendants()) do
            if object:IsA("ModuleScript")
                and string.lower(object.Name) == "skills" then
                skillModule = object
                break
            end
        end
    end

    if not skillModule or not skillModule:IsA("ModuleScript") then
        V97LobbySkillTree.Definitions = false
        return nil
    end

    local ok, defs = pcall(require, skillModule)

    if ok and type(defs) == "table" then
        V97LobbySkillTree.Definitions = defs
        return defs
    end

    V97LobbySkillTree.Definitions = false
    return nil
end

function V97LobbySkillTree.SkillLabel(skillId)
    local defs = V97LobbySkillTree.SkillDefinitions()
    local data = defs and (defs[tostring(skillId)] or defs[tonumber(skillId)])
    if type(data) == "table" and type(data.Tag) == "string" then return data.Tag end
    return "Skill " .. tostring(skillId)
end

function V97LobbySkillTree.BranchChoice(lane)
    if lane == "Middle" then return V97LobbySkillTree.Middle end
    if lane == "Left" then return V97LobbySkillTree.Left end
    if lane == "Right" then return V97LobbySkillTree.Right end
    return nil
end

function V97LobbySkillTree.GetPath(weapon, lane)
    local wp = V97LobbySkillTree.Paths[weapon]
    local lp = wp and wp[lane]
    local choice = V97LobbySkillTree.BranchChoice(lane)
    return lp and lp[choice] or nil, choice
end

function V97LobbySkillTree.SequenceFor(pathData)
    local output = {}
    if type(pathData) ~= "table" then return output end
    for _, id in ipairs(pathData.Common or {}) do output[#output + 1] = tostring(id) end
    for _, id in ipairs(pathData.Branch or {}) do output[#output + 1] = tostring(id) end
    return output
end


function V97LobbySkillTree.TreeRoot()
    local interface = playerGui:FindFirstChild("Interface")
    local equipment = interface and interface:FindFirstChild("Equipment")
    local tree = equipment and equipment:FindFirstChild("Tree")
    local skills = tree and tree:FindFirstChild("Skills")

    if skills then
        return skills
    end

    -- Conservative fallback: exact ancestry/name pattern only.
    for _, object in ipairs(playerGui:GetDescendants()) do
        if object.Name == "Skills"
            and object.Parent
            and object.Parent.Name == "Tree"
            and object.Parent.Parent
            and object.Parent.Parent.Name == "Equipment" then
            return object
        end
    end

    return nil
end

function V97LobbySkillTree.NodeVisuals(node)
    if not node then return nil, nil, nil end

    local main = node:FindFirstChild("Main")
    local inner = main and main:FindFirstChild("Inner")
    local background = inner or main or node
    local icon = inner and inner:FindFirstChild("Icon")
    local stroke = inner and inner:FindFirstChild("Stroke")

    return background, icon, stroke
end

function V97LobbySkillTree.ColorAverage(color)
    if typeof(color) ~= "Color3" then return nil end
    return ((color.R + color.G + color.B) / 3) * 255
end

function V97LobbySkillTree.GuiNodeState(skillId)
    local root = V97LobbySkillTree.TreeRoot()
    if not root then return "MISSING", nil end

    local node = root:FindFirstChild("Skill_" .. tostring(skillId))
    if not node or not node:IsA("GuiObject") then
        return "MISSING", nil
    end

    local background, icon, stroke = V97LobbySkillTree.NodeVisuals(node)
    if not background or not background:IsA("GuiObject") then
        return "UNKNOWN", node
    end

    local bg = V97LobbySkillTree.ColorAverage(background.BackgroundColor3)
    local iconAvg = nil
    local strokeAvg = nil

    if icon and (icon:IsA("ImageLabel") or icon:IsA("ImageButton")) then
        iconAvg = V97LobbySkillTree.ColorAverage(icon.ImageColor3)
    end

    if stroke and stroke:IsA("UIStroke") then
        strokeAvg = V97LobbySkillTree.ColorAverage(stroke.Color)
    end

    local unlockedAttribute = node:GetAttribute("Unlocked") == true

    -- Confirmed from the user's live GUI state dump.
    if bg and bg >= 42
        and (strokeAvg == nil or strokeAvg >= 220)
        and (iconAvg == nil or iconAvg >= 220) then
        return "PURCHASED", node
    end

    if unlockedAttribute
        or (
            bg and bg >= 18 and bg <= 34
            and (strokeAvg == nil or (strokeAvg >= 90 and strokeAvg <= 170))
        ) then
        return "AVAILABLE", node
    end

    if bg and bg <= 10
        and (strokeAvg == nil or strokeAvg <= 45)
        and (iconAvg == nil or iconAvg <= 45) then
        return "LOCKED", node
    end

    -- Tween/transition state after an unlock animation.
    return "TRANSITION", node
end

function V97LobbySkillTree.GuiPathStatus(weapon, lane)
    local pathData, choice = V97LobbySkillTree.GetPath(weapon, lane)
    if not pathData then
        return "INVALID", nil, choice
    end

    local starter = pathData.Branch and tostring(pathData.Branch[1]) or nil
    local blockedBy = pathData.BlockedBy and tostring(pathData.BlockedBy) or nil

    if blockedBy then
        local oppositeState = V97LobbySkillTree.GuiNodeState(blockedBy)
        local starterState = starter and V97LobbySkillTree.GuiNodeState(starter) or nil

        if oppositeState == "PURCHASED" and starterState ~= "PURCHASED" then
            return "LOCKED", nil, choice
        end
    end

    local sawTransition = false

    for _, skillId in ipairs(V97LobbySkillTree.SequenceFor(pathData)) do
        local nodeState = V97LobbySkillTree.GuiNodeState(skillId)

        if nodeState == "PURCHASED" then
            -- Continue through already-owned trunk/branch nodes.
        elseif nodeState == "AVAILABLE" then
            return "READY", tostring(skillId), choice
        elseif nodeState == "TRANSITION" then
            sawTransition = true
            return "WAIT", nil, choice
        elseif nodeState == "LOCKED" then
            return "BLOCKED", nil, choice
        elseif nodeState == "MISSING" then
            return "MISSING", nil, choice
        else
            return "WAIT", nil, choice
        end
    end

    if sawTransition then
        return "WAIT", nil, choice
    end

    return "COMPLETE", nil, choice
end

function V97LobbySkillTree.SelectGuiTarget(weapon)
    local notes = {}
    local visited = {}

    for priorityIndex = 1, 3 do
        local lane = tostring(V97LobbySkillTree.Priority[priorityIndex] or "None")

        if lane ~= "None" and not visited[lane] then
            visited[lane] = true

            local status, skillId, branch =
                V97LobbySkillTree.GuiPathStatus(weapon, lane)

            if status == "READY" then
                return lane, skillId, branch, notes
            elseif status == "LOCKED" then
                notes[#notes + 1] = lane .. "/" .. tostring(branch) .. " locked"
            elseif status == "COMPLETE" then
                notes[#notes + 1] = lane .. "/" .. tostring(branch) .. " complete"
            elseif status == "BLOCKED" then
                notes[#notes + 1] = lane .. "/" .. tostring(branch) .. " waiting on prerequisite"
            elseif status == "WAIT" then
                notes[#notes + 1] = lane .. "/" .. tostring(branch) .. " transitioning"
            elseif status == "MISSING" then
                notes[#notes + 1] = lane .. "/" .. tostring(branch) .. " GUI node missing"
            end
        end
    end

    return nil, nil, nil, notes
end

function V97LobbySkillTree.PathStatus(state, lane)
    local pathData, choice = V97LobbySkillTree.GetPath(state.Weapon, lane)
    if not pathData then return "INVALID", nil, choice end

    local starter = pathData.Branch and tostring(pathData.Branch[1]) or nil
    local blockedBy = pathData.BlockedBy and tostring(pathData.BlockedBy) or nil
    if blockedBy and state.UnlockedSet[blockedBy]
        and (not starter or not state.UnlockedSet[starter]) then
        return "LOCKED", nil, choice
    end

    for _, id in ipairs(V97LobbySkillTree.SequenceFor(pathData)) do
        if not state.UnlockedSet[id] then return "READY", id, choice end
    end
    return "COMPLETE", nil, choice
end

function V97LobbySkillTree.InvokeUnlock(skillId)
    local remote = V97LobbySkillTree.Remote()
    if not remote then return false, nil, nil, "GET RemoteFunction missing" end
    local ok, profile, sp, message = pcall(function()
        return remote:InvokeServer("S_Equipment", "Unlock", {tostring(skillId)})
    end)
    if not ok then return false, nil, nil, tostring(profile) end
    return true, profile, sp, message
end

function V97LobbySkillTree.StopAuto(reason)
    V97LobbySkillTree.Enabled = false
    V97LobbySkillTree.LastAction = tostring(reason or "Auto Skill Tree stopped")
    V97LobbySkillTree.Save()
end

function V97LobbySkillTree.RunStep(manual)
    if V97LobbySkillTree.Busy then return false, "busy" end
    V97LobbySkillTree.Busy = true

    local state = nil
    local profile = V97LobbySkillTree.LastProfile
    local mode = "GUI bootstrap"

    if V97LobbySkillTree.IsProfile(profile) then
        state = V97LobbySkillTree.ParseProfile(profile)

        if state then
            mode = "server profile"
            V97LobbySkillTree.ProfileSource = "unlock response"
        end
    end

    local weapon =
        (state and state.Weapon)
        or (
            V96LobbyAutoUpgrade
            and V96LobbyAutoUpgrade.DetectWeapon
            and V96LobbyAutoUpgrade.DetectWeapon()
        )
        or V97LobbySkillTree.LastWeapon
        or "Unknown"

    if weapon ~= "Blades" and weapon ~= "Spears" then
        V97LobbySkillTree.LastAction = "Waiting for Blades / Spears detection"
        V97LobbySkillTree.Busy = false
        return false, V97LobbySkillTree.LastAction
    end

    V97LobbySkillTree.LastWeapon = weapon

    if not state then
        local guiSP = V97LobbySkillTree.ReadSPFromGui()
        if guiSP ~= nil then
            V97LobbySkillTree.LastSP = guiSP
        end

        if guiSP ~= nil and guiSP <= 0 then
            V97LobbySkillTree.StopAuto("No SP remaining")
            V97LobbySkillTree.Busy = false

            if manual then
                notify("Auto Skill Tree", "No Skill Points remaining.", "info")
            end

            return false, "No SP remaining"
        end
    elseif state.SP ~= nil then
        V97LobbySkillTree.LastSP = state.SP
    end

    local chosenLane, targetSkill, chosenBranch
    local notes = {}

    if state then
        local visited = {}

        for priorityIndex = 1, 3 do
            local lane = tostring(V97LobbySkillTree.Priority[priorityIndex] or "None")

            if lane ~= "None" and not visited[lane] then
                visited[lane] = true

                local status, skillId, branch =
                    V97LobbySkillTree.PathStatus(state, lane)

                if status == "READY" then
                    chosenLane, targetSkill, chosenBranch =
                        lane, skillId, branch
                    break
                elseif status == "LOCKED" then
                    notes[#notes + 1] =
                        lane .. "/" .. tostring(branch) .. " locked"
                elseif status == "COMPLETE" then
                    notes[#notes + 1] =
                        lane .. "/" .. tostring(branch) .. " complete"
                end
            end
        end
    else
        chosenLane, targetSkill, chosenBranch, notes =
            V97LobbySkillTree.SelectGuiTarget(weapon)
    end

    if not targetSkill then
        local detail =
            #notes > 0
            and table.concat(notes, " • ")
            or "No active priority can progress"

        -- During GUI animation, do not permanently disable Auto.
        local lowerDetail = string.lower(detail)
        local temporary =
            string.find(lowerDetail, "transition", 1, true)
            or string.find(lowerDetail, "waiting on prerequisite", 1, true)

        if temporary then
            V97LobbySkillTree.LastAction = detail
        else
            V97LobbySkillTree.StopAuto(detail)
        end

        V97LobbySkillTree.Busy = false

        if manual then
            notify(
                "Auto Skill Tree",
                detail,
                temporary and "info" or "success"
            )
        end

        return false, detail
    end

    local targetLabel = V97LobbySkillTree.SkillLabel(targetSkill)

    V97LobbySkillTree.LastAction =
        tostring(mode)
        .. " • "
        .. tostring(chosenLane)
        .. "/"
        .. tostring(chosenBranch)
        .. " • unlocking "
        .. targetLabel
        .. " ["
        .. tostring(targetSkill)
        .. "]"

    local ok, newProfile, remainingSP, message =
        V97LobbySkillTree.InvokeUnlock(targetSkill)

    if not ok then
        V97LobbySkillTree.StopAuto(
            "Unlock remote error • " .. tostring(message)
        )
        V97LobbySkillTree.Busy = false
        notify("Auto Skill Tree error", tostring(message), "error")
        return false, V97LobbySkillTree.LastAction
    end

    if type(newProfile) ~= "table" then
        local reason = tostring(message or "server rejected unlock")
        local low = string.lower(reason)

        if string.find(low, "skill point", 1, true)
            or string.find(low, "insufficient", 1, true)
            or string.find(low, "not enough", 1, true) then

            V97LobbySkillTree.StopAuto("No SP • " .. reason)
            notify(
                "Auto Skill Tree stopped",
                "No Skill Points available for the next selected path.",
                "info"
            )
        elseif string.find(low, "lock", 1, true)
            or string.find(low, "path", 1, true) then

            V97LobbySkillTree.StopAuto("Path rejected • " .. reason)
            notify("Auto Skill Tree stopped", reason, "error")
        else
            V97LobbySkillTree.StopAuto("Unlock rejected • " .. reason)
            notify("Auto Skill Tree stopped", reason, "error")
        end

        V97LobbySkillTree.Busy = false
        return false, V97LobbySkillTree.LastAction
    end

    local newState = V97LobbySkillTree.ParseProfile(newProfile)

    if not newState
        or not newState.UnlockedSet[tostring(targetSkill)] then

        V97LobbySkillTree.StopAuto(
            "Server response did not confirm " .. targetLabel
        )
        V97LobbySkillTree.Busy = false

        notify(
            "Auto Skill Tree stopped",
            V97LobbySkillTree.LastAction,
            "error"
        )

        return false, V97LobbySkillTree.LastAction
    end

    -- First successful GUI-bootstrap unlock switches the engine into
    -- authoritative server-profile mode for all following nodes.
    V97LobbySkillTree.LastProfile = newProfile
    V97LobbySkillTree.ProfileSource = "unlock response"
    V97LobbySkillTree.LastWeapon = newState.Weapon

    local numericSP = tonumber(remainingSP)

    if numericSP ~= nil then
        V97LobbySkillTree.LastSP = numericSP
    elseif newState.SP ~= nil then
        V97LobbySkillTree.LastSP = newState.SP
    end

    V97LobbySkillTree.Successes += 1

    V97LobbySkillTree.LastAction =
        tostring(chosenLane)
        .. "/"
        .. tostring(chosenBranch)
        .. " • unlocked "
        .. targetLabel
        .. (V97LobbySkillTree.LastSP ~= nil
            and (" • SP " .. tostring(V97LobbySkillTree.LastSP))
            or "")

    if manual then
        notify(
            "Skill unlocked",
            V97LobbySkillTree.LastAction,
            "success"
        )
    end

    V97LobbySkillTree.Busy = false
    return true, V97LobbySkillTree.LastAction
end

