local function makeTreeDropdown(key, titleText, subtitleText, y, options, getter, setter)
    local titleLabel = label(treePanel, titleText, UDim2.fromOffset(14, y), UDim2.new(0.52, -18, 0, 18), true)
    local subtitleLabel = label(treePanel, subtitleText, UDim2.fromOffset(14, y + 18), UDim2.new(0.52, -18, 0, 16), false)
    subtitleLabel.TextSize = 9
    local selectButton = button(treePanel, "", UDim2.new(0.56, 0, 0, y), UDim2.new(0.44, -14, 0, 34), Theme.Panel2)
    selectButton.TextXAlignment = Enum.TextXAlignment.Left
    selectButton.ZIndex = 30
    local menu = Instance.new("Frame")
    menu.Position = UDim2.new(0.56, 0, 0, y + 36)
    menu.Size = UDim2.new(0.44, -14, 0, #options * 30)
    menu.BackgroundColor3 = Theme.Panel2
    menu.BorderSizePixel = 0
    menu.Visible = false
    menu.ZIndex = 40
    menu.Parent = treePanel
    corner(menu, 7)
    stroke(menu, Theme.Stroke, 0.2)
    local menuLayout = Instance.new("UIListLayout")
    menuLayout.SortOrder = Enum.SortOrder.LayoutOrder
    menuLayout.Padding = UDim.new(0, 1)
    menuLayout.Parent = menu
    local optionButtons = {}
    for index, option in ipairs(options) do
        local optionButton = Instance.new("TextButton")
        optionButton.Size = UDim2.new(1, 0, 0, 29)
        optionButton.BackgroundColor3 = Theme.Panel2
        optionButton.BorderSizePixel = 0
        optionButton.AutoButtonColor = false
        optionButton.Font = Enum.Font.GothamMedium
        optionButton.TextSize = 10
        optionButton.TextXAlignment = Enum.TextXAlignment.Left
        optionButton.Text = "   " .. tostring(option)
        optionButton.TextColor3 = Theme.Muted
        optionButton.LayoutOrder = index
        optionButton.ZIndex = 41
        optionButton.Parent = menu
        optionButtons[option] = optionButton
        optionButton.Activated:Connect(function()
            setter(option)
            V97LobbySkillTree.OpenDropdown = nil
            menu.Visible = false
            V97LobbySkillTree.Save()
            if V97LobbySkillTree.Refresh then V97LobbySkillTree.Refresh() end
        end)
    end
    selectButton.Activated:Connect(function()
        local opening = V97LobbySkillTree.OpenDropdown ~= key
        V97LobbySkillTree.OpenDropdown = opening and key or nil
        menu.Visible = opening
        if V97LobbySkillTree.Refresh then V97LobbySkillTree.Refresh() end
    end)
    dropdownRows[key] = {Button = selectButton, Menu = menu, OptionButtons = optionButtons, Getter = getter}
    return titleLabel, subtitleLabel
end

