local function pointInside(guiObject, point)
    if not guiObject or not guiObject.Visible then return false end
    local position, size = guiObject.AbsolutePosition, guiObject.AbsoluteSize
    return point.X >= position.X and point.X <= position.X + size.X and point.Y >= position.Y and point.Y <= position.Y + size.Y
end
UserInputService.InputBegan:Connect(function(input)
    local key = V97LobbySkillTree.OpenDropdown
    if not key then return end
    if input.UserInputType ~= Enum.UserInputType.MouseButton1 and input.UserInputType ~= Enum.UserInputType.Touch then return end
    local row = dropdownRows[key]
    if not row then return end
    local point = input.Position
    if not pointInside(row.Button, point) and not pointInside(row.Menu, point) then
        V97LobbySkillTree.OpenDropdown = nil
        row.Menu.Visible = false
        task.defer(function()
            if V97LobbySkillTree.Refresh then V97LobbySkillTree.Refresh() end
        end)
    end
end)

V97LobbySkillTree.Refresh = function()
    local weapon = V97LobbySkillTree.LastWeapon
    if V96LobbyAutoUpgrade and V96LobbyAutoUpgrade.DetectWeapon then
        local detected = V96LobbyAutoUpgrade.DetectWeapon()
        if detected == "Blades" or detected == "Spears" then
            weapon = detected
            V97LobbySkillTree.LastWeapon = detected
        end
    end

    treeStateTitle.Text = "Detected equipment: " .. string.upper(tostring(weapon))
    treeStateTitle.TextColor3 =
        (weapon == "Blades" or weapon == "Spears") and Theme.Text or Theme.Warn

    treeStateText.Text =
        V97LobbySkillTree.LastAction
        .. "  •  Confirmed " .. tostring(V97LobbySkillTree.Successes)
        .. (V97LobbySkillTree.LastSP ~= nil and ("  •  SP " .. tostring(V97LobbySkillTree.LastSP)) or "")
        .. (V97LobbySkillTree.ProfileSource and ("  •  " .. tostring(V97LobbySkillTree.ProfileSource)) or "")

    treeAutoButton.Text =
        "AUTO SKILL TREE: " .. (V97LobbySkillTree.Enabled and "ON" or "OFF")
    treeAutoButton.BackgroundColor3 =
        V97LobbySkillTree.Enabled and Theme.Accent or Theme.Card
    treeStepButton.Text = V97LobbySkillTree.Busy and "WORKING..." or "RUN ONE STEP"

    for key, row in pairs(dropdownRows) do
        local current = tostring(row.Getter())
        row.Button.Text = "   " .. current .. "   " .. (V97LobbySkillTree.OpenDropdown == key and "▲" or "▼")
        row.Menu.Visible = V97LobbySkillTree.OpenDropdown == key
        row.Button.ZIndex = 30
        row.Menu.ZIndex = 40
        for option, optionButton in pairs(row.OptionButtons) do
            local selected = tostring(option) == current
            optionButton.TextColor3 = selected and Theme.Accent or Theme.Muted
            optionButton.BackgroundColor3 = selected and Theme.CardOn or Theme.Panel2
        end
    end

    treeFooter.Text =
        "Middle " .. tostring(V97LobbySkillTree.Middle)
        .. " • Left " .. tostring(V97LobbySkillTree.Left)
        .. " • Right " .. tostring(V97LobbySkillTree.Right)
        .. " • Order " .. tostring(V97LobbySkillTree.Priority[1])
        .. " → " .. tostring(V97LobbySkillTree.Priority[2])
        .. " → " .. tostring(V97LobbySkillTree.Priority[3])
end

treeAutoButton.Activated:Connect(function()
    V97LobbySkillTree.Enabled = not V97LobbySkillTree.Enabled
    V97LobbySkillTree.LastAction =
        V97LobbySkillTree.Enabled and "Auto Skill Tree armed" or "Auto Skill Tree stopped"
    if V97LobbySkillTree.Enabled then V97LobbySkillTree.LastProfile = nil end
    V97LobbySkillTree.Save()
    V97LobbySkillTree.Refresh()
end)

