	if V94LobbyRefresh.Configs then V94LobbyRefresh.Configs() end
	notify(ok and "Auto-load cleared" or "Save failed", ok and "No config will auto-load on startup." or msg, ok and "success" or "error")
end)

if V94LobbyRefresh.Settings then V94LobbyRefresh.Settings() end

-- Drag and menu toggle.
local dragging, dragStart, startPos = false, nil, nil
local function startDrag(input)
	dragging = true
	dragStart = input.Position
	startPos = window.Position
end

title.InputBegan:Connect(function(input)
	if input.UserInputType == Enum.UserInputType.MouseButton1 or input.UserInputType == Enum.UserInputType.Touch then startDrag(input) end
end)
UserInputService.InputChanged:Connect(function(input)
	if dragging and (input.UserInputType == Enum.UserInputType.MouseMovement or input.UserInputType == Enum.UserInputType.Touch) then
		local delta = input.Position - dragStart
		local pos = UDim2.new(startPos.X.Scale, startPos.X.Offset + delta.X, startPos.Y.Scale, startPos.Y.Offset + delta.Y)
		window.Position = pos
		shadow.Position = UDim2.new(pos.X.Scale, pos.X.Offset + 6, pos.Y.Scale, pos.Y.Offset + 8)
	end
end)
UserInputService.InputEnded:Connect(function(input)
	if input.UserInputType == Enum.UserInputType.MouseButton1 or input.UserInputType == Enum.UserInputType.Touch then dragging = false end
end)
UserInputService.InputBegan:Connect(function(input, processed)
	if bindingKey then
		if input.KeyCode and input.KeyCode ~= Enum.KeyCode.Unknown then
			Settings.ToggleKeyName = input.KeyCode.Name
			bindingKey = false
			local ok, msg = saveSettings()
			if V94LobbyRefresh.Settings then V94LobbyRefresh.Settings() end
			notify(ok and "Keybind saved" or "Save failed", ok and ("Menu key is now " .. Settings.ToggleKeyName) or msg, ok and "success" or "error")
		end
		return
	end

	if input.UserInputType == Enum.UserInputType.Keyboard
		and input.KeyCode == getToggleKeyCode() then
		MenuOpen = not MenuOpen
		window.Visible = MenuOpen
		shadow.Visible = MenuOpen
		return
	end

	if processed then return end
end)

end)()

refreshAll()
if V94LobbyRefresh.Configs then V94LobbyRefresh.Configs() end
if V94LobbyRefresh.AutoUpgrade then V94LobbyRefresh.AutoUpgrade() end
if V94LobbyRefresh.Settings then V94LobbyRefresh.Settings() end
if Settings.AutoLoadConfig and Settings.AutoLoadConfigName ~= "" and SavedConfigs[Settings.AutoLoadConfigName] then
	notify("Auto-loaded config", Settings.AutoLoadConfigName .. " loaded into Create tab.", "success")
else
	notify("V9.6.1 Lobby ready", "Remote Auto Upgrade is armed for testing; V9.5 mission behavior remains unchanged.", "success")
end

task.spawn(function()
	while gui.Parent do
		task.wait(0.35)
		CurrentMode = detectMode()
		statusDot.BackgroundColor3 = modeColor(CurrentMode)
		local runName
		if State.CreateMode == "Raid" then
			runName = State.RaidChoice
		elseif State.CreateMode == "Waves" then
			runName = "Trost / Waves"
		else
			runName = State.Map .. " / " .. State.Objective
		end
		statusLabel.Text = "Mode: " .. CurrentMode .. " • " .. State.CreateMode .. " • " .. runName .. " / " .. difficultyGradeForMode(State.CreateMode, State.Difficulty)
		if CurrentMode ~= LastMode then
			LastMode = CurrentMode
			refreshPreview()
			notify("Mode changed", "Detected: " .. CurrentMode, "info")
		end
		if ActiveTab == "Auto Upgrade" and V94LobbyRefresh.AutoUpgrade then V94LobbyRefresh.AutoUpgrade() end
	end
end)


