-- Mobile fit: the family-spinner/main-menu panel was designed for desktop.
-- Keep desktop unchanged, but scale and vertically center it on phones/tablets.
local function updateMainMenuMobileFit()
    local camera = workspace.CurrentCamera
    if not camera then return end

    local viewport = camera.ViewportSize
    if viewport.X < 260 or viewport.Y < 220 then return end

    local scaleObject = root:FindFirstChild("SliceHubMainMenuMobileFit")
    if not scaleObject then
        scaleObject = Instance.new("UIScale")
        scaleObject.Name = "SliceHubMainMenuMobileFit"
        scaleObject.Parent = root
    end

    local touchLike = UserInputService.TouchEnabled or viewport.Y < 560 or viewport.X < 760
    local fit = math.min((viewport.X * 0.94) / 330, (viewport.Y * 0.92) / 688, 1)

    if touchLike then
        scaleObject.Scale = math.clamp(fit, 0.48, 0.82)
        root.AnchorPoint = Vector2.new(1, 0.5)
        root.Position = UDim2.new(1, -8, 0.5, 0)
    else
        scaleObject.Scale = 1
        root.AnchorPoint = Vector2.new(1, 1)
        root.Position = UDim2.new(1, -12, 1, -92)
    end
end

