local function cleanText(value)
	local text = tostring(value or "")
	text = string.gsub(text, "<.->", "")
	text = string.gsub(text, "%s+", " ")
	text = string.gsub(text, "^%s+", "")
	text = string.gsub(text, "%s+$", "")
	return string.lower(text)
end

local function visibleTextObject(object)
	if not object or not (object:IsA("TextLabel") or object:IsA("TextButton") or object:IsA("TextBox")) then return false end
	if not object.Visible or object.AbsoluteSize.X <= 0 or object.AbsoluteSize.Y <= 0 then return false end
	local node = object.Parent
	while node and node ~= playerGui do
		if node:IsA("GuiObject") and not node.Visible then return false end
		if node:IsA("LayerCollector") and not node.Enabled then return false end
		node = node.Parent
	end
	return true
end

local function clickAt(x, y)
	local inset = Vector2.new(0, 0)
	pcall(function() inset = GuiService:GetGuiInset() end)
	local cx = math.floor(x + inset.X + 0.5)
	local cy = math.floor(y + inset.Y + 0.5)
	pcall(function() VirtualInputManager:SendMouseMoveEvent(cx, cy, game) end)
	task.wait(0.03)
	pcall(function() VirtualInputManager:SendMouseButtonEvent(cx, cy, 0, true, game, 0) end)
	task.wait(0.05)
	pcall(function() VirtualInputManager:SendMouseButtonEvent(cx, cy, 0, false, game, 0) end)
end

local function buttonAncestor(object)
	local node = object
	for _ = 1, 9 do
		if not node or node == playerGui then break end
		if node:IsA("GuiButton") then return node end
		node = node.Parent
	end
	return nil
end

local function cardRoot(object)
	if not object or not object:IsA("GuiObject") then return nil end
	local best = object
	local node = object.Parent
	for _ = 1, 10 do
		if not node or node == playerGui then break end
		if node:IsA("GuiObject") then
			local size = node.AbsoluteSize
			if size.X >= 110 and size.Y >= 70 and size.X <= 620 and size.Y <= 520 then
				best = node
			end
		end
		node = node.Parent
	end
	return best
end

local function clickGuiObject(object, preferCard)
	if not object or not object:IsA("GuiObject") then return false end
	local target = preferCard and (cardRoot(object) or object) or (buttonAncestor(object) or object)
	pcall(function() if target:IsA("GuiButton") then target:Activate() end end)
	local pos = target.AbsolutePosition
	local size = target.AbsoluteSize
	clickAt(pos.X + size.X / 2, pos.Y + size.Y / 2)
	return true
end

local function findText(wanted)
	local needle = cleanText(wanted)
	for _, object in ipairs(playerGui:GetDescendants()) do
		if helperGui and object:IsDescendantOf(helperGui) then continue end
		if visibleTextObject(object) then
			local hay = cleanText(object.Text)
			if hay == needle or string.find(hay, needle, 1, true) then
				return object
			end
		end
	end
	return nil
end

local function clickText(wanted, preferCard)
	local object = findText(wanted)
	if object then return clickGuiObject(object, preferCard) end
	return false
end

local function clickSlot(slotName)
	local slotTitle = findText(slotName)
	if not slotTitle then return false end
	local card = cardRoot(slotTitle)
	local selectObj = nil
	if card then
		for _, object in ipairs(card:GetDescendants()) do
			if visibleTextObject(object) and string.find(cleanText(object.Text), "select", 1, true) then
				selectObj = object
				break
			end
		end
	end
	if selectObj then return clickGuiObject(selectObj, false) end
	if card then
		local pos = card.AbsolutePosition
		local size = card.AbsoluteSize
		clickAt(pos.X + size.X / 2, pos.Y + size.Y * 0.86)
		return true
	end
	return clickGuiObject(slotTitle, false)
end

local function queueV5BootstrapIfEnabled()
    local env = type(getgenv) == "function" and getgenv() or _G
    local readFn = env.readfile or readfile
    local queueFn = env.queue_on_teleport
        or env.queueonteleport
        or env.queue_on_tp
        or (env.syn and env.syn.queue_on_teleport)

    if type(readFn) ~= "function" or type(queueFn) ~= "function" then
        return false
    end

    local okRead, raw = pcall(readFn, "TitanControlSettings_v101.json")
    if not okRead or type(raw) ~= "string" then return false end

    local okDecode, decoded = pcall(function() return HttpService:JSONDecode(raw) end)
    if not okDecode
        or type(decoded) ~= "table"
        or type(decoded.Settings) ~= "table"
        or decoded.Settings.AutoExecuteOnTeleport ~= true then
        return false
    end

    local code = [[
local loader = loadstring or load
if type(readfile) == "function" and type(loader) == "function" then
    local ok, source = pcall(readfile, "SH/bootstrap.shc")
    if ok and type(source) == "string" then
        local chunk = loader(source)
        if type(chunk) == "function" then chunk() end
    end
end
]]

    return pcall(queueFn, code)
end

local DestinationPlaces = {
    [4658598196] = {
        Town = 14916516914,
        Trade = 14932214603,
    },
    [5310627045] = {
        Town = 15393230099,
        Trade = 108309021405580,
    },
}

local SelectedDestination = "Town"
local DestinationButtons = {}

local function destinationPlaceId(destination)
    local byGame = DestinationPlaces[tonumber(game.GameId) or 0]
    return byGame and byGame[destination] or nil
end

local function directDestination(destination)
    local placeId = destinationPlaceId(destination)
    if not placeId then
        warn("[AOT MainMenu V5] no grounded destination PlaceId for GameId", game.GameId)
        return false
    end

    pcall(queueV5BootstrapIfEnabled)

    local ok, err = pcall(function()
        TeleportService:Teleport(placeId, player)
    end)

    if not ok then
        warn("[AOT MainMenu V5] direct destination failed", destination, err)
    end
    return ok
end

local function refreshDestinationButtons()
    for name, button in pairs(DestinationButtons) do
