---------------------------------------------------------------------
-- V5.7.3 MAIN MENU MULTI-RARITY SAFE FAMILY SPINNER
---------------------------------------------------------------------
local FamilySpin = {
    Running = false,
    Armed = false, -- NEVER persisted. Every fresh script execution starts safe/off.
    Serial = 0,
    Rolls = 0,
    TargetRarities = {
        Epic = false,
        Legendary = false,
        Mythic = true,
    },
    Delay = 0.10,
    AutoStop = true,
    WebhookEnabled = true,
    PingEnabled = true,
    WebhookUrl = "",
    WebhookUserID = "",
    StartedAt = 0,
    Status = "Idle",
    DangerConfirmFamily = nil,
    DangerConfirmUntil = 0,
}

local SpinableFamilies = {
    Epic = {
        Zoe = true,
        Galliard = true,
        Finger = true,
        Tybur = true,
        Ksaver = true,
        Braun = true,
        Leonhart = true,
        Arlert = true,
    },
    Legendary = {
        Ackerman = true,
        Yeager = true,
        Reiss = true,
    },
    Mythic = {
        Fritz = true,
        Helos = true,
    },
}

local RarityOrder = {"Epic", "Legendary", "Mythic"}
local familySettingsFile = "AOT_MainMenuFamilySpinner_v3.json"
local env = type(getgenv) == "function" and getgenv() or _G
local readFileFn = env.readfile or readfile
local writeFileFn = env.writefile or writefile

local function familySpinnerIsPremium()
    local hub = type(env.SliceHub) == "table" and env.SliceHub or nil
    return hub and hub.IsPremium == true
end

local function familySpinnerMinDelay()
    return familySpinnerIsPremium() and 0.03 or 0.30
end

local function familySpinnerMaxDelay()
    return 1.00
end

local function familySpinnerDefaultDelay()
    return familySpinnerIsPremium() and 0.03 or 0.50
end

local function familySpinnerClampDelay(value)
    local minValue = familySpinnerMinDelay()
    local maxValue = familySpinnerMaxDelay()
    return math.clamp(tonumber(value) or familySpinnerDefaultDelay(), minValue, maxValue)
end

local function familySpinnerWebhooksAllowed()
    return familySpinnerIsPremium()
end

FamilySpin.Delay = familySpinnerClampDelay(FamilySpin.Delay)
if not familySpinnerWebhooksAllowed() then
    FamilySpin.WebhookEnabled = false
    FamilySpin.PingEnabled = false
end

local function trimText(value)
    local textValue = tostring(value or "")
    textValue = string.gsub(textValue, "^%s+", "")
    textValue = string.gsub(textValue, "%s+$", "")
    return textValue
end

local function normalizeFamily(value)
    return string.lower(trimText(value))
end

local function canonicalRarity(value)
    local normalized = string.lower(trimText(value))
    if normalized == "epic" then return "Epic" end
    if normalized == "legendary" or normalized == "leg" then return "Legendary" end
    if normalized == "mythic" or normalized == "myth" then return "Mythic" end
    return nil
end

local function rarityForFamily(familyName)
    local wanted = normalizeFamily(familyName)
    for rarity, families in pairs(SpinableFamilies) do
        for family in pairs(families) do
            if normalizeFamily(family) == wanted then
                return rarity
            end
        end
    end
    return nil
end

local function selectedRarityCount()
    local count = 0
    for _, rarity in ipairs(RarityOrder) do
        if FamilySpin.TargetRarities[rarity] == true then
            count += 1
        end
    end
    return count
end

local function selectedRarityText()
    local selected = {}
    for _, rarity in ipairs(RarityOrder) do
        if FamilySpin.TargetRarities[rarity] == true then
            selected[#selected + 1] = rarity
        end
    end
    return #selected > 0 and table.concat(selected, " + ") or "NONE"
end

local function isTargetRarity(rarity)
    return rarity ~= nil and FamilySpin.TargetRarities[rarity] == true
end

local function loadFamilySettings()
    if type(readFileFn) ~= "function" then return end
    local okRead, raw = pcall(readFileFn, familySettingsFile)
    if not okRead or type(raw) ~= "string" or raw == "" then
        -- Migrate V2 spinner settings if available.
        local okOld, oldRaw = pcall(readFileFn, "AOT_MainMenuFamilySpinner_v2.json")
        if okOld and type(oldRaw) == "string" and oldRaw ~= "" then
            raw = oldRaw
        else
            return
        end
    end

    local okDecode, doc = pcall(function() return HttpService:JSONDecode(raw) end)
    if not okDecode or type(doc) ~= "table" then return end

    if type(doc.TargetRarities) == "table" then
        for _, rarity in ipairs(RarityOrder) do
            if type(doc.TargetRarities[rarity]) == "boolean" then
                FamilySpin.TargetRarities[rarity] = doc.TargetRarities[rarity]
            end
        end
    else
        local oldRarity = canonicalRarity(doc.TargetRarity)
        if oldRarity then
            FamilySpin.TargetRarities.Epic = false
            FamilySpin.TargetRarities.Legendary = false
            FamilySpin.TargetRarities.Mythic = false
            FamilySpin.TargetRarities[oldRarity] = true
        end
    end

    if tonumber(doc.Delay) then
        FamilySpin.Delay = familySpinnerClampDelay(doc.Delay)
    else
        FamilySpin.Delay = familySpinnerClampDelay(FamilySpin.Delay)
    end
    if type(doc.AutoStop) == "boolean" then FamilySpin.AutoStop = doc.AutoStop end

    if type(doc.WebhookEnabled) == "boolean" then
        FamilySpin.WebhookEnabled = doc.WebhookEnabled
    elseif type(doc.WebhookPing) == "boolean" then
        -- Old setting meant “send/ping”. Preserve useful behavior during migration.
        FamilySpin.WebhookEnabled = doc.WebhookPing
    end

    if type(doc.PingEnabled) == "boolean" then
        FamilySpin.PingEnabled = doc.PingEnabled
    elseif type(doc.WebhookPing) == "boolean" then
        FamilySpin.PingEnabled = doc.WebhookPing
    end

    if type(doc.WebhookUrl) == "string" then FamilySpin.WebhookUrl = doc.WebhookUrl end
    if type(doc.WebhookUserID) == "string" then FamilySpin.WebhookUserID = doc.WebhookUserID end
end

local function saveFamilySettings()
    if not familySpinnerWebhooksAllowed() then
        FamilySpin.WebhookEnabled = false
        FamilySpin.PingEnabled = false
    end
    FamilySpin.Delay = familySpinnerClampDelay(FamilySpin.Delay)
    if type(writeFileFn) ~= "function" then return end
    local okEncode, encoded = pcall(function()
        return HttpService:JSONEncode({
            Version = 3,
            TargetRarities = FamilySpin.TargetRarities,
            Delay = FamilySpin.Delay,
            AutoStop = FamilySpin.AutoStop,
            WebhookEnabled = FamilySpin.WebhookEnabled,
            PingEnabled = FamilySpin.PingEnabled,
            WebhookUrl = FamilySpin.WebhookUrl,
            WebhookUserID = FamilySpin.WebhookUserID,
            -- Intentionally NOT saving Running or Armed.
        })
    end)
    if okEncode and type(encoded) == "string" then
        pcall(writeFileFn, familySettingsFile, encoded)
    end
end

