local function refreshDelaySlider()
    FamilySpin.Delay = familySpinnerClampDelay(FamilySpin.Delay)
    local ratio = math.clamp((FamilySpin.Delay - minDelay) / (maxDelay - minDelay), 0, 1)
    delayFill.Size = UDim2.new(ratio, 0, 1, 0)
    delayKnob.Position = UDim2.new(ratio, 0, 0.5, 0)
    if familySpinnerIsPremium() then
        delayLabel.Text = string.format("SPIN DELAY: %.2fs   •   PREMIUM TURBO 0.03s  →  SAFE 1.00s", FamilySpin.Delay)
    else
        delayLabel.Text = string.format("SPIN DELAY: %.2fs   •   FREE MIN 0.30s  →  Premium 0.03s", FamilySpin.Delay)
    end
end

local function setDelayFromX(screenX)
    local x = delayTrack.AbsolutePosition.X
    local w = math.max(1, delayTrack.AbsoluteSize.X)
    local ratio = math.clamp((screenX - x) / w, 0, 1)
    FamilySpin.Delay = familySpinnerClampDelay(math.floor((minDelay + (maxDelay - minDelay) * ratio) * 100 + 0.5) / 100)
    refreshDelaySlider()
    saveFamilySettings()
end

