local function loadMainWebhook()
    if type(readFileFn) ~= "function" then return nil end
    local okRead, raw = pcall(readFileFn, "TitanControlSettings_v101.json")
    if not okRead or type(raw) ~= "string" or raw == "" then return nil end
    local okDecode, doc = pcall(function() return HttpService:JSONDecode(raw) end)
    if not okDecode or type(doc) ~= "table" then return nil end
    local cfg = type(doc.Webhook) == "table" and doc.Webhook or nil
    if not cfg then return nil end
    return cfg
end

local function resolveSpinnerWebhook()
    local mainCfg = loadMainWebhook() or {}
    local url = trimText(FamilySpin.WebhookUrl)
    local userID = trimText(FamilySpin.WebhookUserID)

    if url == "" and type(mainCfg.url) == "string" then
        url = trimText(mainCfg.url)
    end
    if userID == "" and type(mainCfg.userID) == "string" then
        userID = trimText(mainCfg.userID)
    end

    if url == "" then return nil end
    return {
        url = url,
        userID = userID,
    }
end

local function sendFamilyFoundWebhook(familyName, rarity, rolls, elapsed)
    if not familySpinnerWebhooksAllowed() then return false, "Family spinner webhooks are Premium only" end
    if not FamilySpin.WebhookEnabled then return false, "Webhook disabled" end

    local cfg = resolveSpinnerWebhook()
    if not cfg then
        return false, "No spin webhook URL and no main SliceHub webhook fallback"
    end

    local requestFunction = nil
    pcall(function()
        if syn and type(syn.request) == "function" then requestFunction = syn.request
        elseif type(http_request) == "function" then requestFunction = http_request
        elseif type(request) == "function" then requestFunction = request
        elseif http and type(http.request) == "function" then requestFunction = http.request end
    end)
    if type(requestFunction) ~= "function" then return false, "No supported HTTP request function" end

    local content = ""
    if FamilySpin.PingEnabled and type(cfg.userID) == "string" and cfg.userID ~= "" then
        content = "<@" .. cfg.userID .. ">"
    end

    local body = HttpService:JSONEncode({
        content = content,
        embeds = {{
            title = "🎯 Target Rarity Rolled",
            description = "Family Spinner detected a family in one of the selected rarities.",
            color = rarity == "Mythic" and 15735864 or (rarity == "Legendary" and 16766720 or 11162880),
            fields = {
                {name = "Family", value = tostring(familyName), inline = true},
                {name = "Rarity", value = tostring(rarity), inline = true},
                {name = "Selected targets", value = selectedRarityText(), inline = false},
                {name = "Rolls this session", value = tostring(rolls), inline = true},
                {name = "Elapsed", value = string.format("%.1fs", elapsed), inline = true},
                {name = "Spin delay", value = string.format("%.2fs", FamilySpin.Delay), inline = true},
            },
            footer = {text = "SliceHub AOT:R • Multi-Rarity Safe Spinner"},
            timestamp = os.date("!%Y-%m-%dT%H:%M:%SZ"),
        }},
    })

    local ok, result = pcall(function()
        return requestFunction({
            Url = cfg.url,
            Method = "POST",
            Headers = {["Content-Type"] = "application/json"},
            Body = body,
        })
    end)
    if not ok then return false, tostring(result) end
    local status = type(result) == "table" and tonumber(result.StatusCode or result.Status or result.status_code) or nil
    if status and (status < 200 or status >= 300) then return false, "HTTP " .. tostring(status) end
    return true
end

local function resolveFamilyRemote()
    local replicatedStorage = game:GetService("ReplicatedStorage")
    local assets = replicatedStorage:FindFirstChild("Assets")
    local remotes = assets and assets:FindFirstChild("Remotes")
    local getRemote = remotes and remotes:FindFirstChild("GET")
    if getRemote and getRemote:IsA("RemoteFunction") then
        return getRemote
    end
    return nil
end

local function rollFamilyRemote()
    local getRemote = resolveFamilyRemote()
    if not getRemote then
        return false, "GET remote missing"
    end

    local ok, spins, extra, family, pity, sequence = pcall(function()
        return getRemote:InvokeServer("Family", "Roll")
    end)
    if not ok then
        return false, tostring(spins)
    end
    if family == nil then
        return false, "Roll rejected or no spins left"
    end

    local rarity = rarityForFamily(family)
    if rarity == nil and type(sequence) == "table" then
        local final = sequence[#sequence]
        if type(final) == "table" and normalizeFamily(final.Family) == normalizeFamily(family) then
            rarity = canonicalRarity(final.Rarity)
        end
    end

    return true, {
        Spins = spins,
        Extra = extra,
        Family = tostring(family),
        Rarity = rarity or "Unknown",
        Pity = pity,
        Sequence = sequence,
    }
end

local function detectCurrentFamilyFromAttributes()
    local candidates = {player, player.Character}
    for _, object in ipairs(candidates) do
        if object then
            for _, key in ipairs({"Family", "family", "CurrentFamily", "Current_Family"}) do
                local ok, value = pcall(function() return object:GetAttribute(key) end)
                if ok and type(value) == "string" and value ~= "" then
                    local rarity = rarityForFamily(value)
                    if rarity then return value, rarity end
                end
            end
        end
    end
    return nil, nil
end

local function detectCurrentFamilyFromUI()
    local bestFamily, bestRarity = nil, nil
    for _, object in ipairs(playerGui:GetDescendants()) do
        if helperGui and object:IsDescendantOf(helperGui) then continue end
        if visibleTextObject(object) then
            local rawText = tostring(object.Text or "")
            local lowered = string.lower(rawText)
            for rarity, families in pairs(SpinableFamilies) do
                for family in pairs(families) do
                    local familyLower = string.lower(family)
                    local exact = normalizeFamily(rawText) == familyLower
                    local titlePattern = string.find(lowered, familyLower .. " (", 1, true) ~= nil
                    if exact or titlePattern then
                        return family, rarity
                    end
                end
            end
        end
    end
    return bestFamily, bestRarity
end

local function detectCurrentHighRarityFamily()
    local family, rarity = detectCurrentFamilyFromAttributes()
    if family then return family, rarity end
    return detectCurrentFamilyFromUI()
end

local function disarmSpinner()
    FamilySpin.Armed = false
    FamilySpin.DangerConfirmFamily = nil
    FamilySpin.DangerConfirmUntil = 0
    refreshFamilyToggles()
    refreshSpinButton()
end

local function stopFamilySpin(reason, result)
    if not FamilySpin.Running and not result then return end
    FamilySpin.Running = false
    FamilySpin.Serial += 1
    local elapsed = math.max(0, os.clock() - (FamilySpin.StartedAt or os.clock()))

    if result then
        FamilySpin.Status = "FOUND " .. tostring(result.Family)
        familyStatus.Text = string.format(
            "FOUND %s (%s) • %d rolls • %.1fs\nTargets: %s",
            tostring(result.Family), tostring(result.Rarity), FamilySpin.Rolls, elapsed, selectedRarityText()
        )
        if FamilySpin.WebhookEnabled then
            local ok, err = sendFamilyFoundWebhook(result.Family, result.Rarity, FamilySpin.Rolls, elapsed)
            if ok then
                familyStatus.Text ..= " • webhook sent"
            else
                familyStatus.Text ..= " • webhook: " .. tostring(err)
            end
        end
    else
        FamilySpin.Status = tostring(reason or "Stopped")
        familyStatus.Text = string.format("%s • %d rolls", FamilySpin.Status, FamilySpin.Rolls)
    end

    -- Every stop requires manual re-arming before another roll session.
    disarmSpinner()
end

local function familySpinLoop(serial)
    while FamilySpin.Running and FamilySpin.Serial == serial and helperGui.Parent do
        -- HARD MYTHIC GUARD. This is checked before every Family/Roll remote call,
        -- not only once when START is pressed. A Mythic can never be the family
        -- that gets consumed by the next roll in this spinner loop.
        local heldFamily, heldRarity = detectCurrentHighRarityFamily()
        if canonicalRarity(heldRarity) == "Mythic" then
            FamilySpin.Status = "MYTHIC PROTECTED"
            familyStatus.Text = string.format(
                "MYTHIC PROTECTED • %s will NOT be rerolled.\nSpinner stopped and disarmed.",
                tostring(heldFamily or "current Mythic family")
            )
            stopFamilySpin("MYTHIC PROTECTED")
            return
        end

        local ok, resultOrError = rollFamilyRemote()
        if not ok then
            stopFamilySpin(tostring(resultOrError))
            return
        end

        local result = resultOrError
        FamilySpin.Rolls += 1
        familyStatus.Text = string.format(
            "SPINNING • targets %s\nroll %d • %s (%s)",
            selectedRarityText(),
            FamilySpin.Rolls,
            tostring(result.Family),
            tostring(result.Rarity)
        )

        -- A newly rolled Mythic is ALWAYS terminal, even when Mythic is not one of
        -- the selected target rarities and even when AUTO STOP is disabled.
        if canonicalRarity(result.Rarity) == "Mythic" then
            stopFamilySpin("MYTHIC PROTECTED", result)
            return
        end

        if isTargetRarity(result.Rarity) then
            local elapsed = math.max(0, os.clock() - FamilySpin.StartedAt)
            if FamilySpin.AutoStop then
                stopFamilySpin("Found", result)
                return
            elseif FamilySpin.WebhookEnabled then
                task.spawn(sendFamilyFoundWebhook, result.Family, result.Rarity, FamilySpin.Rolls, elapsed)
            end
        end

        local deadline = os.clock() + math.max(0.03, FamilySpin.Delay)
        repeat
            if not FamilySpin.Running or FamilySpin.Serial ~= serial then return end
            task.wait(0.01)
        until os.clock() >= deadline
    end
end

spinButton.Activated:Connect(function()
    if FamilySpin.Running then
        stopFamilySpin("Stopped manually")
        return
    end

    if not FamilySpin.Armed then
        familyStatus.Text = "LOCKED • turn SPINNER ARMED ON first. This resets OFF on every script load."
        return
    end

    if selectedRarityCount() <= 0 then
        familyStatus.Text = "Select at least one target rarity before starting."
        return
    end

    -- Recreate the native game's valuable-family warning that direct remote calls bypass.
    local currentFamily, currentRarity = detectCurrentHighRarityFamily()
    if canonicalRarity(currentRarity) == "Mythic" then
        familyStatus.Text = string.format(
            "MYTHIC PROTECTED: %s will never be rerolled by this script.",
            tostring(currentFamily or "current Mythic family")
        )
        disarmSpinner()
        return
    end
    if currentFamily and currentRarity then
        local now = os.clock()
        local alreadyConfirmed = FamilySpin.DangerConfirmFamily == currentFamily
            and now <= (FamilySpin.DangerConfirmUntil or 0)

        if not alreadyConfirmed then
            FamilySpin.DangerConfirmFamily = currentFamily
            FamilySpin.DangerConfirmUntil = now + 8
            familyStatus.Text = string.format(
                "SAFETY BLOCK: current family %s (%s).\nPress START again within 8s to CONFIRM rerolling it.",
                tostring(currentFamily), tostring(currentRarity)
            )
            return
        end
    end

    FamilySpin.DangerConfirmFamily = nil
    FamilySpin.DangerConfirmUntil = 0
    FamilySpin.Running = true
    FamilySpin.Serial += 1
    FamilySpin.Rolls = 0
    FamilySpin.StartedAt = os.clock()
    FamilySpin.Status = "Starting"
    saveFamilySettings()
    refreshSpinButton()
    refreshRarityButtons()
    local serial = FamilySpin.Serial
    familyStatus.Text = "Starting direct remote spinner • targets " .. selectedRarityText()
    task.spawn(familySpinLoop, serial)
end)

refreshSpinButton()

local mini = Instance.new("TextButton")
mini.Name = "Reopen"
