-- The mission runtime is a separate loadstring chunk, so outer locals are
-- not inherited. Use a short scoped block and assign PROFILE globally. This
-- avoids adding long-lived top-level locals to this register-heavy chunk.
do
    local environment = _G
    pcall(function()
        if type(getgenv) == "function" then
            environment = getgenv()
        end
    end)

    local hub = type(environment) == "table" and environment.SliceHub or nil
    local resolvedProfile = type(hub) == "table" and hub.Profile or nil
    if type(resolvedProfile) ~= "table" then
        resolvedProfile = {}
    end
    if type(resolvedProfile.Spears) ~= "table" then
        resolvedProfile.Spears = {}
    end
    PROFILE = resolvedProfile
end

-- Mission-local tier helpers. These read the generated profile directly so
-- Free always exposes/uses 8 and Premium always exposes/uses up to 20.
function SliceHubMissionTPSMin()
    local combat = PROFILE and PROFILE.Combat or nil
    local value = combat and tonumber(combat.TitansPerSwingMin) or 2
    value = math.floor(value + 0.5)
    if value < 1 then value = 1 end
    return value
end

function SliceHubMissionTPSMax()
    local blade = PROFILE and PROFILE.Blade or nil
    local combat = PROFILE and PROFILE.Combat or nil
    local minimum = SliceHubMissionTPSMin()
    local value = blade and tonumber(blade.MaxTitansPerSwing)
        or (combat and tonumber(combat.TitansPerSwingMax))
        or 20
    value = math.floor(value + 0.5)
    if value < minimum then value = minimum end
    return value
end

function SliceHubMissionClampTPS(value, fallback)
    local minimum = SliceHubMissionTPSMin()
    local maximum = SliceHubMissionTPSMax()
    local resolved = tonumber(value)
    if resolved == nil then
        resolved = tonumber(fallback) or maximum
    end
    return math.clamp(math.floor(resolved + 0.5), minimum, maximum)
end

