local saveAllSettings
local settingsSaveReady = false

local PersistentSettings = {
	FileName = "TitanControlSettings_v101.json",
	Store = {},
	StorageMode = "Session",
	StorageDetail = "Settings reset when this script stops.",
	AutoSave = true,
	RestoreFarmOnStart = false,
	AutoLoadProfile = false,
	AutoLoadProfileName = "",
}

do
	local function getGlobalEnvironment()
		local environment = nil
		pcall(function()
			if type(getgenv) == "function" then
				environment = getgenv()
			end
		end)
		if type(environment) ~= "table" then
			environment = _G
		end
		return environment
	end

	function PersistentSettings:GetExecutorFunction(name)
		local environment = getGlobalEnvironment()
		if type(environment) == "table" and type(environment[name]) == "function" then
			return environment[name]
		end
		if type(_G) == "table" and type(_G[name]) == "function" then
			return _G[name]
		end
		return nil
	end

	function PersistentSettings:GetSection(sectionName)
		local section = self.Store and self.Store[sectionName]
		if type(section) == "table" then
			return section
		end
		return {}
	end

	function PersistentSettings:GetBoolean(sectionName, key, fallback)
		local value = self:GetSection(sectionName)[key]
		if type(value) == "boolean" then
			return value
		end
		return fallback == true
	end

	function PersistentSettings:GetString(sectionName, key, fallback)
		local value = self:GetSection(sectionName)[key]
		if type(value) == "string" then
			return value
		end
		return tostring(fallback or "")
	end

	function PersistentSettings:GetNumber(sectionName, key, fallback, minimum, maximum)
		local value = tonumber(self:GetSection(sectionName)[key]) or tonumber(fallback) or 0
		if minimum then value = math.max(minimum, value) end
		if maximum then value = math.min(maximum, value) end
		return value
	end

	function PersistentSettings:Load()
print("[SliceHub V1 V2/PERFORMANCE] settings loaded")
		self.ReadFile = self:GetExecutorFunction("readfile")
		self.WriteFile = self:GetExecutorFunction("writefile")

		if self.ReadFile and self.WriteFile then
			self.StorageMode = "File"
			self.StorageDetail = "Settings auto-save to " .. self.FileName
		end

		local loaded = nil
		if self.ReadFile then
			local readOk, encoded = pcall(self.ReadFile, self.FileName)
			if readOk and type(encoded) == "string" and encoded ~= "" then
				local decodeOk, document = pcall(function()
					return HttpService:JSONDecode(encoded)
				end)
				if decodeOk and type(document) == "table" then
					loaded = document
				end
			end
		end

		if not loaded then
			local environment = getGlobalEnvironment()
			if type(environment) == "table" and type(environment.TitanControlPersistentSettings) == "table" then
				loaded = environment.TitanControlPersistentSettings
			end
		end

		self.Store = type(loaded) == "table" and loaded or {}
		self.AutoSave = self:GetBoolean("Settings", "AutoSave", true)
		self.RestoreFarmOnStart = self:GetBoolean("Settings", "RestoreFarmOnStart", false)
		self.AutoExecuteOnTeleport = self:GetBoolean("Settings", "AutoExecuteOnTeleport", false)
		self.AutoHideGuiOnLaunch = self:GetBoolean("Settings", "AutoHideGuiOnLaunch", true)
		self.AutoLoadProfile = self:GetBoolean("Settings", "AutoLoadProfile", false)
		self.AutoLoadProfileName = self:GetString("Settings", "AutoLoadProfileName", "")
		self.MenuScale = self:GetNumber("Settings", "MenuScale", 100, 80, 120)
		self.ThemeName = self:GetString("Settings", "ThemeName", "Blue")
		self.GuiCursorEnabled = self:GetBoolean("Settings", "GuiCursorEnabled", true)
		self.MenuToggleKeyName = self:GetString("Settings", "MenuToggleKeyName", "RightShift")
		if not Enum.KeyCode[self.MenuToggleKeyName] or self.MenuToggleKeyName == "Unknown" then
			self.MenuToggleKeyName = "RightShift"
		end
	end

	function PersistentSettings:WriteDocument(document)
		document = type(document) == "table" and document or {}
		self.Store = document
		self.AutoSave = self:GetBoolean("Settings", "AutoSave", self.AutoSave ~= false)
		self.RestoreFarmOnStart = self:GetBoolean("Settings", "RestoreFarmOnStart", self.RestoreFarmOnStart == true)
		self.AutoExecuteOnTeleport = self:GetBoolean("Settings", "AutoExecuteOnTeleport", self.AutoExecuteOnTeleport == true)
		self.AutoHideGuiOnLaunch = self:GetBoolean("Settings", "AutoHideGuiOnLaunch", self.AutoHideGuiOnLaunch ~= false)
		self.AutoLoadProfile = self:GetBoolean("Settings", "AutoLoadProfile", self.AutoLoadProfile == true)
		self.AutoLoadProfileName = self:GetString("Settings", "AutoLoadProfileName", self.AutoLoadProfileName or "")
		self.MenuScale = self:GetNumber("Settings", "MenuScale", self.MenuScale or 100, 80, 120)
		self.ThemeName = self:GetString("Settings", "ThemeName", self.ThemeName or "Blue")
		self.GuiCursorEnabled = self:GetBoolean("Settings", "GuiCursorEnabled", self.GuiCursorEnabled ~= false)
		self.MenuToggleKeyName = self:GetString("Settings", "MenuToggleKeyName", self.MenuToggleKeyName or "RightShift")
		if not Enum.KeyCode[self.MenuToggleKeyName] or self.MenuToggleKeyName == "Unknown" then
			self.MenuToggleKeyName = "RightShift"
		end

		local environment = getGlobalEnvironment()
		if type(environment) == "table" then
			environment.TitanControlPersistentSettings = document
		end

		if not self.WriteFile then
			return true, "Saved for this session only"
		end

		local encodeOk, encoded = pcall(function()
			return HttpService:JSONEncode(document)
		end)
		if not encodeOk then
			return false, "Settings JSON encode failed"
		end

		local writeOk, writeError = pcall(self.WriteFile, self.FileName, encoded)
		if not writeOk then
			return false, "Settings file write failed: " .. tostring(writeError)
		end
		return true, "Saved to " .. self.FileName
	end
end

