local function sendWebhook(embed)
	if not WebhookConfig.url or WebhookConfig.url == "" then
		return false, "No webhook URL set"
	end

	embed = embed or {}

	local payload = {
		content = "",
		embeds = {embed}
	}

	if WebhookConfig.enableRarePing and embed.pingRare and WebhookConfig.userID ~= "" then
		payload.content = "<@" .. WebhookConfig.userID .. ">"
	end
	embed.pingRare = nil

	local requestFunction = nil
	pcall(function()
		if syn and type(syn.request) == "function" then
			requestFunction = syn.request
		elseif type(http_request) == "function" then
			requestFunction = http_request
		elseif type(request) == "function" then
			requestFunction = request
		elseif http and type(http.request) == "function" then
			requestFunction = http.request
		end
	end)

	if type(requestFunction) ~= "function" then
		return false, "No supported HTTP request function found"
	end

	local body = HttpService:JSONEncode(payload)
	local ok, result = pcall(function()
		return requestFunction({
			Url = WebhookConfig.url,
			Method = "POST",
			Headers = {["Content-Type"] = "application/json"},
			Body = body,
		})
	end)

	if not ok then
		return false, tostring(result)
	end

	local statusCode = nil
	if type(result) == "table" then
		statusCode = tonumber(result.StatusCode or result.Status or result.status_code)
	end

	if statusCode and (statusCode < 200 or statusCode >= 300) then
		return false, "HTTP " .. tostring(statusCode)
	end

	return true, result
end

-- V9.4 lightweight run recorder. It stores only bounded, high-signal state
-- transitions so diagnostics remain useful without spamming the developer console.
V94RunRecorder = {
	MaxEvents = 100,
	Events = {},
	RunSerial = 0,
	RunStartedAt = os.clock(),
	Status = "IDLE",
}

function V94RunRecorder.Record(kind, message, data)
	local event = {
		At = os.clock(),
		Elapsed = math.max(0, os.clock() - (tonumber(V94RunRecorder.RunStartedAt) or os.clock())),
		Kind = tostring(kind or "EVENT"),
		Message = tostring(message or ""),
		Data = {},
	}

	if type(data) == "table" then
		for key, value in pairs(data) do
			local valueType = type(value)
			if valueType == "string" or valueType == "number" or valueType == "boolean" then
				event.Data[tostring(key)] = value
			end
		end
	end

	table.insert(V94RunRecorder.Events, event)
	while #V94RunRecorder.Events > V94RunRecorder.MaxEvents do
		table.remove(V94RunRecorder.Events, 1)
	end
	V94RunRecorder.Status = event.Kind .. " • " .. event.Message
	return event
end

function V94RunRecorder.Begin(meta)
	V94RunRecorder.Events = {}
	V94RunRecorder.RunSerial += 1
	V94RunRecorder.RunStartedAt = os.clock()
	V94RunRecorder.Status = "RUNNING"
	V94RunRecorder.Record("RUN_START", "Mission evidence armed", meta)
end

function V94RunRecorder.Finish(data)
	V94RunRecorder.Record("RUN_RESULT", tostring(data and data.resultType or "result"), {
		runType = data and data.runType or "Mission",
		time = data and data.timeTaken or "Unknown",
		kills = data and data.titanKills or 0,
		damage = data and data.damageDealt or 0,
	})
	V94RunRecorder.Status = "COMPLETE"
end

function V94RunRecorder.Summary(limit)
	local lines = {}
	local count = math.clamp(math.floor(tonumber(limit) or 10), 1, 25)
	local first = math.max(1, #V94RunRecorder.Events - count + 1)
	for index = first, #V94RunRecorder.Events do
		local event = V94RunRecorder.Events[index]
		lines[#lines + 1] = string.format(
			"+%.2fs [%s] %s",
			tonumber(event.Elapsed) or 0,
			tostring(event.Kind or "EVENT"),
			tostring(event.Message or "")
		)
	end
	return #lines > 0 and table.concat(lines, "\n") or "No run events recorded"
end

