-- v114 objective runtime tuning. Uses globals to avoid adding more top-level locals near Luau's local-register limit.
ObjectiveRuntimeActive = false
ObjectiveRuntimeBase = nil
function applyObjectiveRuntimeTuning(active)
	if not Config or Config.ObjectiveRuntimeEnabled ~= true then return end
	active = active == true
	if active then
		if not ObjectiveRuntimeBase then
			ObjectiveRuntimeBase = {
				SkyHeight = Config.SkyHeight,
				TitansPerHit = Config.TitansPerHit,
				KillSpeed = Config.KillSpeed,
				SpeedPulseDistance = Config.SpeedPulseDistance,
				TargetStallTimeout = Config.TargetStallTimeout,
			}
		end
		ObjectiveRuntimeActive = true
		Config.SkyHeight = Config.ObjectiveSkyHeight or Config.SkyHeight
		Config.TitansPerHit = SliceHubMissionClampTPS(math.max(tonumber(Config.TitansPerHit) or SliceHubMissionTPSMin(), tonumber(Config.ObjectiveTitansPerHit) or SliceHubMissionTPSMax()))
		Config.KillSpeed = math.max(tonumber(Config.KillSpeed) or 0, tonumber(Config.ObjectiveKillSpeed) or 720)
		Config.SpeedPulseDistance = math.max(tonumber(Config.SpeedPulseDistance) or 0, tonumber(Config.ObjectiveSpeedPulseDistance) or 8)
		Config.TargetStallTimeout = math.min(tonumber(Config.TargetStallTimeout) or 3.5, tonumber(Config.ObjectiveTargetStallTimeout) or 1.35)
	elseif ObjectiveRuntimeActive and ObjectiveRuntimeBase then
		ObjectiveRuntimeActive = false
		Config.SkyHeight = ObjectiveRuntimeBase.SkyHeight or Config.SkyHeight
		Config.TitansPerHit = SliceHubMissionClampTPS(ObjectiveRuntimeBase.TitansPerHit or Config.TitansPerHit)
		Config.KillSpeed = ObjectiveRuntimeBase.KillSpeed or Config.KillSpeed
		Config.SpeedPulseDistance = ObjectiveRuntimeBase.SpeedPulseDistance or Config.SpeedPulseDistance
		Config.TargetStallTimeout = ObjectiveRuntimeBase.TargetStallTimeout or Config.TargetStallTimeout
	end
end

function objectiveModeActiveNow()
	if not State or not State.ObjectiveBrainEnabled or not updateObjectiveBrain then return false end
	local ok, data = pcall(updateObjectiveBrain, false)
	return ok and type(data) == "table" and (State.CombatPreset == "Objective" or data.Mode == "Objective")
end

-- v116 adaptive combat tuning. Kept global on purpose to avoid another top-level local-register spike.
AdaptiveCombatMode = "Unknown"
BladeOnlyRuntimeActive = false
BladeOnlyRuntimeBase = nil
function titanControlRipperAvailableNow()
	if not State or State.TitanRipperEnabled ~= true then return false end
	if type(TitanControlRipperAvailable) == "function" then
		local ok, any = pcall(TitanControlRipperAvailable)
		return ok and any == true
	end
	return true
end
function applyBladeOnlyRuntime(active)
	if not Config then return end
	active = active == true
	if active then
		if not BladeOnlyRuntimeBase then
			BladeOnlyRuntimeBase = {
				SkyHeight = Config.SkyHeight,
				TitansPerHit = Config.TitansPerHit,
				KillSpeed = Config.KillSpeed,
				SpeedPulseDistance = Config.SpeedPulseDistance,
				TargetStallTimeout = Config.TargetStallTimeout,
				BladeCooldown = Config.BladeCooldown,
				MultiTargetRemoteSpacing = Config.MultiTargetRemoteSpacing,
				BladeOnlyBurstRounds = Config.BladeOnlyBurstRounds,
				BladeOnlyClickRepeats = Config.BladeOnlyClickRepeats,
			}
		end
		BladeOnlyRuntimeActive = true
		Config.SkyHeight = math.min(tonumber(Config.SkyHeight) or 300, tonumber(Config.BladeOnlySkyHeight) or 215)
		Config.TitansPerHit = SliceHubMissionClampTPS(math.min(tonumber(Config.TitansPerHit) or SliceHubMissionTPSMax(), tonumber(Config.BladeOnlyTitansPerHit) or SliceHubMissionTPSMax()))
		Config.KillSpeed = math.max(tonumber(Config.KillSpeed) or 0, tonumber(Config.BladeOnlyKillSpeed) or 770)
		Config.SpeedPulseDistance = math.max(tonumber(Config.SpeedPulseDistance) or 0, tonumber(Config.BladeOnlySpeedPulseDistance) or 9)
		Config.TargetStallTimeout = math.min(tonumber(Config.TargetStallTimeout) or 3.5, tonumber(Config.BladeOnlyTargetStallTimeout) or 1.15)
		Config.BladeCooldown = math.min(tonumber(Config.BladeCooldown) or 0.075, tonumber(Config.BladeOnlyBladeCooldown) or 0.062)
		Config.MultiTargetRemoteSpacing = math.min(tonumber(Config.MultiTargetRemoteSpacing) or 0.014, tonumber(Config.BladeOnlyRemoteSpacing) or 0.010)
		Config.BladeOnlyBurstRounds = math.clamp(math.floor((tonumber(Config.BladeOnlyBurstRounds) or 2) + 0.5), 1, 3)
		Config.BladeOnlyClickRepeats = math.clamp(math.floor((tonumber(Config.BladeOnlyClickRepeats) or 2) + 0.5), 1, 3)
	elseif BladeOnlyRuntimeActive and BladeOnlyRuntimeBase then
		BladeOnlyRuntimeActive = false
		Config.SkyHeight = BladeOnlyRuntimeBase.SkyHeight or Config.SkyHeight
		Config.TitansPerHit = SliceHubMissionClampTPS(BladeOnlyRuntimeBase.TitansPerHit or Config.TitansPerHit)
		Config.KillSpeed = BladeOnlyRuntimeBase.KillSpeed or Config.KillSpeed
		Config.SpeedPulseDistance = BladeOnlyRuntimeBase.SpeedPulseDistance or Config.SpeedPulseDistance
		Config.TargetStallTimeout = BladeOnlyRuntimeBase.TargetStallTimeout or Config.TargetStallTimeout
		Config.BladeCooldown = BladeOnlyRuntimeBase.BladeCooldown or Config.BladeCooldown
		Config.MultiTargetRemoteSpacing = BladeOnlyRuntimeBase.MultiTargetRemoteSpacing or Config.MultiTargetRemoteSpacing
		Config.BladeOnlyBurstRounds = BladeOnlyRuntimeBase.BladeOnlyBurstRounds or Config.BladeOnlyBurstRounds
		Config.BladeOnlyClickRepeats = BladeOnlyRuntimeBase.BladeOnlyClickRepeats or Config.BladeOnlyClickRepeats
		BladeOnlyRuntimeBase = nil
	end
end
function updateAdaptiveCombatMode()
	local wantsRipper = State and State.TitanRipperEnabled == true
	local hasRipper = wantsRipper and titanControlRipperAvailableNow()
	AdaptiveCombatMode = hasRipper and "Ripper" or (wantsRipper and "BladeOnlyMissingRipper" or "BladeOnly")
	applyBladeOnlyRuntime(not hasRipper)
	return AdaptiveCombatMode
end

