function V5FarmRouter.Sync(reason)
    local spearActive = State.SpearSupportEnabled == true
        and State.SpearAutoFireEnabled ~= false
    local active = State.BladesEnabled == true or spearActive

    State.FarmEnabled = active
    V5FarmRouter.LastReason = tostring(reason or "sync")

    return active
end

