V5AutoExecute = V5AutoExecute or {
    BootstrapFile = "SH/bootstrap.shc",
    LastQueueAt = 0,
    LastStatus = "Idle",
}

function V5AutoExecute.GetQueueFunction()
    local environment = nil
    pcall(function()
        if type(getgenv) == "function" then
            environment = getgenv()
        end
    end)

    local candidates = {
        environment and environment.queue_on_teleport,
        environment and environment.queueonteleport,
        type(syn) == "table" and syn.queue_on_teleport or nil,
        type(fluxus) == "table" and fluxus.queue_on_teleport or nil,
        type(_G) == "table" and _G.queue_on_teleport or nil,
        type(_G) == "table" and _G.queueonteleport or nil,
    }

    for _, fn in ipairs(candidates) do
        if type(fn) == "function" then
            return fn
        end
    end

    return nil
end

function V5AutoExecute.QueueNow()
    if PersistentSettings.AutoExecuteOnTeleport ~= true then
        V5AutoExecute.LastStatus = "Disabled"
        return false, "disabled"
    end

    if os.clock() - (V5AutoExecute.LastQueueAt or 0) < 0.75 then
        return true, "already queued"
    end

    local queueFn = V5AutoExecute.GetQueueFunction()
    if not queueFn then
        V5AutoExecute.LastStatus = "queue_on_teleport unavailable"
        return false, V5AutoExecute.LastStatus
    end

    local bootstrap = V5AutoExecute.BootstrapFile
    local queuedCode = string.format([[
local p = %q
local ok = false
if type(loadfile) == "function" then
    local good, chunk = pcall(loadfile, p)
    if good and type(chunk) == "function" then
        ok = pcall(chunk)
    end
end
if not ok and type(readfile) == "function" then
    local loader = loadstring or load
    if type(loader) == "function" then
        local goodRead, source = pcall(readfile, p)
        if goodRead and type(source) == "string" then
            local chunk = loader(source)
            if type(chunk) == "function" then pcall(chunk) end
        end
    end
end
]], bootstrap)

    local ok, err = pcall(queueFn, queuedCode)
    if ok then
        V5AutoExecute.LastQueueAt = os.clock()
        V5AutoExecute.LastStatus = "Queued encrypted SH cache"
        return true, V5AutoExecute.LastStatus
    end

    V5AutoExecute.LastStatus = tostring(err)
    return false, V5AutoExecute.LastStatus
end

player.OnTeleport:Connect(function(state)
    if PersistentSettings.AutoExecuteOnTeleport ~= true then return end

    local stateText = tostring(state)
    if string.find(stateText, "RequestedFromServer", 1, true)
        or string.find(stateText, "Started", 1, true) then
        local ok, message = V5AutoExecute.QueueNow()
        print("[SliceHub V5][AUTO-EXEC]", ok, message)
    end
end)

V51QueueRuntime = V51QueueRuntime or {
    FileName = "AOT_RaidQueue_v51.json",
    LastHandledSignature = nil,
    LastHandledAt = 0,
}

function V51QueueRuntime.FileFunctions()
    local env = nil
    pcall(function() if type(getgenv) == "function" then env = getgenv() end end)
    env = type(env) == "table" and env or _G
    return env and env.readfile or nil, env and env.writefile or nil
end

function V51QueueRuntime.Load()
    local readFn = select(1, V51QueueRuntime.FileFunctions())
    if type(readFn) ~= "function" then return nil end
    local ok, raw = pcall(readFn, V51QueueRuntime.FileName)
    if not ok or type(raw) ~= "string" or raw == "" then return nil end
    local decodeOk, decoded = pcall(function() return HttpService:JSONDecode(raw) end)
    return decodeOk and type(decoded) == "table" and decoded or nil
end

function V51QueueRuntime.Save(document)
    local _, writeFn = V51QueueRuntime.FileFunctions()
    if type(writeFn) ~= "function" or type(document) ~= "table" then return false end
    local okEncode, encoded = pcall(function() return HttpService:JSONEncode(document) end)
    if not okEncode then return false end
    return pcall(writeFn, V51QueueRuntime.FileName, encoded)
end

function V51QueueRuntime.IsActive()
    local q = V51QueueRuntime.Load()
    return type(q) == "table" and q.Enabled == true, q
end

function V51QueueRuntime.AdvanceEntry(queue)
    local entries = type(queue.Entries) == "table" and queue.Entries or {}
    queue.EntryDone = 0
    queue.CurrentRetries = 0
    queue.Index = (tonumber(queue.Index) or 1) + 1
    if queue.Index > #entries then
        if queue.RepeatQueue == true and #entries > 0 then
            queue.Index = 1
        else
            queue.Enabled = false
            queue.Index = math.max(1, #entries)
        end
    end
end

function V51QueueRuntime.HandleResult(data)
    local active, queue = V51QueueRuntime.IsActive()
    if not active or type(data) ~= "table" then return false end
    if tostring(data.runType or "Mission") ~= "Raid" then return false end

    local signature = table.concat({tostring(data.resultType), tostring(data.timeTaken), tostring(data.raidName), tostring(queue.Index), tostring(queue.EntryDone)}, "|")
    if V51QueueRuntime.LastHandledSignature == signature and os.clock() - (V51QueueRuntime.LastHandledAt or 0) < 30 then
        return true
    end
    V51QueueRuntime.LastHandledSignature = signature
    V51QueueRuntime.LastHandledAt = os.clock()

    local failed = tostring(data.resultType) == "failed"
    queue.TotalCompleted = tonumber(queue.TotalCompleted) or 0
    queue.TotalFailed = tonumber(queue.TotalFailed) or 0
    queue.CurrentRetries = tonumber(queue.CurrentRetries) or 0
    queue.EntryDone = tonumber(queue.EntryDone) or 0
    queue.Index = math.max(1, tonumber(queue.Index) or 1)
    queue.LastResult = failed and "FAILED" or "COMPLETED"

    if failed then
        queue.TotalFailed += 1
        queue.CurrentRetries += 1
        local policy = tostring(queue.FailurePolicy or "Retry")
        local maxRetries = math.max(0, tonumber(queue.MaxRetries) or 3)
        if policy == "Stop" then
            queue.Enabled = false
        elseif policy == "Skip" or queue.CurrentRetries > maxRetries then
            V51QueueRuntime.AdvanceEntry(queue)
        end
    else
        queue.TotalCompleted += 1
        queue.CurrentRetries = 0
        queue.EntryDone += 1
        local entry = type(queue.Entries) == "table" and queue.Entries[queue.Index] or nil
        local required = entry and math.max(1, tonumber(entry.Runs) or 1) or 1
        if queue.EntryDone >= required then
            V51QueueRuntime.AdvanceEntry(queue)
        end
    end

    queue.LastRunTime = tostring(data.timeTaken or "Unknown")
    queue.SessionStats = type(queue.SessionStats) == "table" and queue.SessionStats or {Completed = 0, Failed = 0, TotalSeconds = 0, FastestSeconds = nil}
    if failed then queue.SessionStats.Failed = (tonumber(queue.SessionStats.Failed) or 0) + 1 else queue.SessionStats.Completed = (tonumber(queue.SessionStats.Completed) or 0) + 1 end
    local mm, ss = string.match(tostring(data.timeTaken or ""), "(%d+):(%d+)")
    local seconds = mm and ss and (tonumber(mm) * 60 + tonumber(ss)) or 0
    if seconds > 0 then
        queue.SessionStats.TotalSeconds = (tonumber(queue.SessionStats.TotalSeconds) or 0) + seconds
        if not queue.SessionStats.FastestSeconds or seconds < tonumber(queue.SessionStats.FastestSeconds) then queue.SessionStats.FastestSeconds = seconds end
    end
    queue.LastRaidName = tostring(data.raidName or "Unknown")
    queue.LastDifficulty = tostring(data.difficulty or "Unknown")
    V51QueueRuntime.Save(queue)
    return true, queue
end

