	lastBladeBurstCount = 1

	CombatSafetyBoostUntil = 0
	CombatSafetyBoostHeight = 0
	RipperOpportunityReadySince = nil
	BladeToolMissingSince = nil
	BladeZeroObservedAt = nil

	if HealthGuardConnection then
		HealthGuardConnection:Disconnect()
		HealthGuardConnection = nil
	end

	local previousHealth = humanoid.Health
	HealthGuardConnection = humanoid.HealthChanged:Connect(function(newHealth)
		if State.FarmEnabled and newHealth < previousHealth - 0.5 then
			CombatSafetyBoostUntil = os.clock() + (tonumber(Config.DamageSafetyBoostDuration) or 0.45)
			CombatSafetyBoostHeight = math.max(
				CombatSafetyBoostHeight,
				tonumber(Config.DamageSafetyBoostHeight) or 32
			)
		end
		previousHealth = newHealth
	end)
	nextBladeAttack = 0
	cachedTitanCandidates = {}
	cachedTitanCandidatesAt = 0
	CombatAnchorRuntime.Position = nil
	CombatAnchorRuntime.GroundCenter = nil
	CombatAnchorRuntime.AimPosition = nil
	CombatAnchorRuntime.TargetCount = 0
	CombatAnchorRuntime.LastRefresh = 0
	CombatAnchorRuntime.LastCommit = 0
	CombatAnchorRuntime.PulseUntil = 0
	CombatAnchorRuntime.PulseSerial += 1
	BladeBurstFailureCounts = setmetatable({}, {__mode = "k"})
	BladeEngineNoProgressBursts = 0
end

