---------------------------------------------------------------------
-- HARDWARE INPUT & EMULATION UTILITIES
---------------------------------------------------------------------

local function resolvePath(root, path)
	local current = root
	for _, name in ipairs(path) do
		current = current:FindFirstChild(name)
		if not current then return nil end
	end
	return current
end

local function scanNetworkForRemote(keywords)
	for _, item in ipairs(ReplicatedStorage:GetDescendants()) do
		if item:IsA("RemoteEvent") or item:IsA("RemoteFunction") then
			local lowerName = string.lower(item.Name)
			for _, keyword in ipairs(keywords) do
				if string.find(lowerName, keyword, 1, true) then
					return item
				end
			end
		end
	end
	return nil
end

local function simulateHumanKeyPress(keyCode)
	task.wait(0.02) 
	VirtualInputManager:SendKeyEvent(true, keyCode, false, game)
	task.wait(0.04) 
	VirtualInputManager:SendKeyEvent(false, keyCode, false, game)
end

local function simulateCenterMouseClick(targetPart)
	local camera = Workspace.CurrentCamera
	if not camera then return end

	local aimTarget = targetPart or currentTargetPart
	local aimPosition = nil
	if typeof(aimTarget) == "Vector3" then
		aimPosition = aimTarget
	elseif aimTarget and aimTarget.Parent then
		aimPosition = aimTarget.Position
	end

	if aimPosition then
		pcall(function()
			local cameraPosition = camera.CFrame.Position
			if (aimPosition - cameraPosition).Magnitude > 0.1 then
				camera.CFrame = CFrame.lookAt(cameraPosition, aimPosition)
			end
		end)
		task.wait(0.01)
	end
	
	local x = camera.ViewportSize.X / 2
	local y = camera.ViewportSize.Y / 2

	VirtualInputManager:SendMouseButtonEvent(x, y, 0, true, game, 0)
	task.wait(0.012)
	VirtualInputManager:SendMouseButtonEvent(x, y, 0, false, game, 0)
end

local function nameContainsKeyword(name, keywords)
	local lowerName = string.lower(name)
	for _, keyword in ipairs(keywords) do
		if string.find(lowerName, string.lower(keyword), 1, true) then return true end
	end
	return false
end

local function findMatchingTool(keywords)
	if character then
		for _, item in ipairs(character:GetChildren()) do
			if item:IsA("Tool") and nameContainsKeyword(item.Name, keywords) then return item end
		end
	end
	for _, item in ipairs(backpack:GetChildren()) do
		if item:IsA("Tool") and nameContainsKeyword(item.Name, keywords) then return item end
	end
	return nil
end

local function bladeToolScore(tool)
	if not tool or not tool:IsA("Tool") then return -math.huge end
	local name = string.lower(tostring(tool.Name or ""))
	if string.find(name, "ripper", 1, true)
		or string.find(name, "skill", 1, true)
		or string.find(name, "ability", 1, true) then
		return -math.huge
	end

	local score = 0
	if string.find(name, "blade", 1, true) then score += 120 end
	if string.find(name, "sword", 1, true) then score += 100 end
	if string.find(name, "katana", 1, true) then score += 100 end
	if string.find(name, "odm", 1, true) then score += 35 end
	if string.find(name, "gear", 1, true) then score += 12 end
	if string.find(name, "weapon", 1, true) then score += 6 end
	if character and tool:IsDescendantOf(character) then score += 10 end
	return score
end

local function findBladeTool(forceRescan)
	if not forceRescan and CachedBladeTool and CachedBladeTool.Parent and (
		CachedBladeTool:IsDescendantOf(backpack) or
		(character and CachedBladeTool:IsDescendantOf(character))
	) and bladeToolScore(CachedBladeTool) > 0 then
		return CachedBladeTool
	end

	local bestTool, bestScore = nil, -math.huge
	local function consider(container)
		if not container then return end
		for _, item in ipairs(container:GetChildren()) do
			local score = bladeToolScore(item)
			if score > bestScore then
				bestTool, bestScore = item, score
			end
		end
	end
	consider(character)
	consider(backpack)

	CachedBladeTool = bestScore > 0 and bestTool or nil
	return CachedBladeTool
end

-- Fixed Grip Logic: Prevents constant un-equipping glitches
local function equipTool(tool)
	if not humanoid or humanoid.Health <= 0 then return false end
	if not tool or not tool.Parent then return false end
	if tool.Parent ~= character then 
		humanoid:EquipTool(tool) 
	end
	return tool.Parent == character
end

local function tryFastReloadOnBladeToolMiss()
    -- V2.1.1: intentionally disabled.
    -- A missing Tool is not proof of empty blade segments.
    BladeToolMissingSince = nil
    return false
end

local function prepareBladeWaveTool()
    local tool = findBladeTool(false)

    if not tool then
        CachedBladeTool = nil
        tool = findBladeTool(true)
    end

    BladeToolMissingSince = nil
    BladeDiag.LastTool = tool and tool:GetFullName() or "nil"

    if not tool then
        BladeDiag.Reason = "NO_BLADE_TOOL"
        return nil
    end

    if not equipTool(tool) then
        task.wait(0.012)
        CachedBladeTool = nil
        tool = findBladeTool(true)

        if not tool or not equipTool(tool) then
            return nil
        end
    end

    pcall(function()
        tool:Activate()
    end)
    return tool
end


---------------------------------------------------------------------
-- AUTO BLADE REFILL (EXACT 0/6 EDGE TRIGGER)
---------------------------------------------------------------------

local BladeCounterKeywords = {
	"blade", "blades", "segment", "segments", "durability", "ammo", "sword", "weapon"
}

local function normalizeCounterText(value)
	local textValue = tostring(value or "")
	textValue = string.gsub(textValue, "<.->", "") -- Remove RichText tags.
	textValue = string.gsub(textValue, "%s+", "")
	return textValue
end

local function parseCounterTextForMaximum(value, expectedMaximum)
    local normalized = normalizeCounterText(value)
    local currentText, maximumText = string.match(normalized, "(%d+)/(%d+)")
    if not currentText or not maximumText then return nil, nil end

    local current = tonumber(currentText)
    local maximum = tonumber(maximumText)
    if current == nil or maximum ~= expectedMaximum then return nil, nil end
    if current < 0 or current > maximum then return nil, nil end
    return current, maximum
end

local function parseBladeCounterText(value)
    return parseCounterTextForMaximum(value, Config.BladeSegmentMaximum)
end

local function parseBladeSetCounterText(value)
    return parseCounterTextForMaximum(value, Config.BladeSetMaximum)
end

local function getCounterObjectText(object)
	if object:IsA("TextLabel") or object:IsA("TextButton") or object:IsA("TextBox") then
		return object.Text
	end
	return nil
end

local function bladeCounterCandidateScore(object, current, maximum)
	local score = 0
	local normalized = normalizeCounterText(getCounterObjectText(object))
	if normalized == string.format("%d/%d", current, maximum) then
		score += 8
	end

	if object:IsA("GuiObject") then
		if object.Visible then score += 2 end
		if object.AbsoluteSize.X > 0 and object.AbsoluteSize.Y > 0 then score += 2 end
	end

	local node = object
	for _ = 1, 5 do
		if not node then break end
		local lowerName = string.lower(node.Name)
		for _, keyword in ipairs(BladeCounterKeywords) do
			if string.find(lowerName, keyword, 1, true) then
				score += 5
				break
			end
		end
		node = node.Parent
	end

	return score
end


local function bladeCounterInsideSliceHub(object)
    local node = object
    while node do
        if node.Name == "TitanControlMenu" then
            return true
        end
        node = node.Parent
    end
    return false
end

local function bladeCounterActuallyVisible(object)
    if not object or not object:IsA("GuiObject") then
        return false
    end
    if not object.Visible or object.AbsoluteSize.X <= 0 or object.AbsoluteSize.Y <= 0 then
        return false
    end

    local node = object.Parent
    while node and node ~= playerGui do
        if node:IsA("GuiObject") and not node.Visible then
            return false
        end
        if node:IsA("LayerCollector") and not node.Enabled then
            return false
        end
        node = node.Parent
    end
    return true
end

local function getTrustedBladesHudRoot()
    return resolvePath(playerGui, {"Interface", "HUD", "Main", "Top", "7", "Blades"})
end

local function findBladeCounter()
    -- V2: only trust the game's actual Blades HUD subtree.
    -- Never scan all of PlayerGui, because mission objectives can contain values like 0/6.
    local bladesRoot = getTrustedBladesHudRoot()
    if not bladesRoot then
        BladeDiag.LastNoCounterPrintAt = BladeDiag.LastNoCounterPrintAt or 0
        if os.clock() - BladeDiag.LastNoCounterPrintAt >= 4 then
            BladeDiag.LastNoCounterPrintAt = os.clock()
            print("[SliceHub V3][BLADE-COUNTER] trusted Blades HUD root missing; combat not ammo-gated")
        end
        return nil
    end

    local bestObject = nil
    local bestScore = -math.huge

    local function consider(object)
        local textValue = getCounterObjectText(object)
        if textValue == nil then return end

        local current, maximum = parseBladeCounterText(textValue)
        if current == nil or maximum ~= Config.BladeSegmentMaximum then return end

        local score = bladeCounterCandidateScore(object, current, maximum)

        local lowerName = string.lower(tostring(object.Name or ""))
        if string.find(lowerName, "segment", 1, true) then score += 25 end
        if string.find(lowerName, "durability", 1, true) then score += 20 end
        if string.find(lowerName, "blade", 1, true) then score += 10 end

        if score > bestScore then
            bestScore = score
            bestObject = object
        end
    end

    consider(bladesRoot)
    for _, object in ipairs(bladesRoot:GetDescendants()) do
        consider(object)
    end

    if bestObject then
        local path = bestObject:GetFullName()
        if BladeDiag.LastSegmentSource ~= path then
            BladeDiag.LastSegmentSource = path
            print("[SliceHub V3][AMMO] segment source ->", path)
        end
    else
        BladeDiag.LastNoCounterPrintAt = BladeDiag.LastNoCounterPrintAt or 0
        if os.clock() - BladeDiag.LastNoCounterPrintAt >= 8 then
            BladeDiag.LastNoCounterPrintAt = os.clock()
            print("[SliceHub V3][AMMO] trusted segment counter missing; combat not ammo-gated")
        end
    end

    return bestObject
end

local function readBladeSegments()
    local bladesRoot = getTrustedBladesHudRoot()

    if cachedBladeCounter
        and cachedBladeCounter:IsDescendantOf(playerGui)
        and bladesRoot
        and cachedBladeCounter:IsDescendantOf(bladesRoot) then

        local current, maximum = parseBladeCounterText(getCounterObjectText(cachedBladeCounter))
        if current ~= nil then
            return current, maximum
        end
    end

    cachedBladeCounter = nil
    cachedBladeCounter = findBladeCounter()
    if not cachedBladeCounter then
        return nil, nil
    end

    return parseBladeCounterText(getCounterObjectText(cachedBladeCounter))
end

local function readBladeSets()
    local bladesRoot = getTrustedBladesHudRoot()
    if not bladesRoot then
        return nil, nil
    end

    if cachedBladeSetCounter
        and cachedBladeSetCounter:IsDescendantOf(playerGui)
        and cachedBladeSetCounter:IsDescendantOf(bladesRoot) then

        local current, maximum = parseBladeSetCounterText(getCounterObjectText(cachedBladeSetCounter))
        if current ~= nil then
            return current, maximum
        end
    end

    cachedBladeSetCounter = nil

    local bestObject = nil
    local bestScore = -math.huge

    local function consider(object)
        local textValue = getCounterObjectText(object)
        if textValue == nil then return end

        local current, maximum = parseBladeSetCounterText(textValue)
        if current == nil then return end

        local score = 0
        local lowerName = string.lower(tostring(object.Name or ""))
        if string.find(lowerName, "set", 1, true) then score += 40 end
        if string.find(lowerName, "stock", 1, true) then score += 30 end
        if string.find(lowerName, "blade", 1, true) then score += 10 end

        local node = object.Parent
        for _ = 1, 5 do
            if not node or node == bladesRoot.Parent then break end
            local lower = string.lower(tostring(node.Name or ""))
            if string.find(lower, "set", 1, true) then score += 25 end
            if string.find(lower, "blade", 1, true) then score += 8 end
            node = node.Parent
        end

        if score > bestScore then
            bestScore = score
            bestObject = object
        end
    end

    -- Prefer the known Sets subtree, whether it is itself text or contains a text child.
    local directSets = bladesRoot:FindFirstChild("Sets", true)
    if directSets then
        consider(directSets)
        for _, object in ipairs(directSets:GetDescendants()) do
            consider(object)
        end
    end

    if not bestObject then
        consider(bladesRoot)
        for _, object in ipairs(bladesRoot:GetDescendants()) do
            consider(object)
        end
    end

    if not bestObject then
        return nil, nil
    end

    cachedBladeSetCounter = bestObject
    local path = bestObject:GetFullName()
    if BladeDiag.LastSetSource ~= path then
        BladeDiag.LastSetSource = path
        print("[SliceHub V3][AMMO] set source ->", path)
    end

    return parseBladeSetCounterText(getCounterObjectText(bestObject))
end

local function findGasStationPart()
	-- v102: use the confirmed AOT refill path first. The old scorer could pick a random "Refill" part.
	local direct = resolvePath(Workspace, {"Climbable", "_Walls", "Gate", "GasTanks", "Refill"})
	if direct and direct:IsA("BasePart") then
		StationRefill.LastStationPart = direct
		return direct
	end

	if StationRefill.LastStationPart and StationRefill.LastStationPart.Parent then return StationRefill.LastStationPart end
	local bestPart, bestScore = nil, -math.huge
	for _, object in ipairs(Workspace:GetDescendants()) do
		if object:IsA("BasePart") then
			local lowerName = string.lower(object.Name)
			local score = lowerName == "refill" and 60 or 0
			local node = object.Parent
			for _ = 1, 8 do
				if not node then break end
				local lower = string.lower(tostring(node.Name or ""))
				if string.find(lower, "gastank", 1, true) or string.find(lower, "gas", 1, true) then score += 18 end
				if string.find(lower, "station", 1, true) or string.find(lower, "supply", 1, true) then score += 10 end
				node = node.Parent
			end
			if score > bestScore then bestScore = score; bestPart = object end
		end
	end
	StationRefill.LastStationPart = bestPart
	return bestPart
end

function stationRefillKeyHold()
	local key = Config.AutoRefillKey or Enum.KeyCode.R
	local holdTime = math.max(0.08, tonumber(Config.StationRefillHoldTime) or 0.42)

	pcall(function() VirtualInputManager:SendKeyEvent(true, key, false, game) end)
	pcall(function()
		if type(keypress) == "function" then keypress(key.Value or key) end
	end)
	task.wait(holdTime)
	pcall(function() VirtualInputManager:SendKeyEvent(false, key, false, game) end)
	pcall(function()
		if type(keyrelease) == "function" then keyrelease(key.Value or key) end
	end)
end

V51AdaptiveRefill = V51AdaptiveRefill or {
    RemoteFailures = 0,
    StationCyclesSinceTest = 0,
    SkipRemoteUntilCycle = 0,
    Status = "Learning",
}

function V51AdaptiveRefill.ShouldTestRemote()
    if V51AdaptiveRefill.RemoteFailures < 2 then return true end
    return V51AdaptiveRefill.StationCyclesSinceTest >= 3
end

function V51AdaptiveRefill.MarkRemoteSuccess()
    V51AdaptiveRefill.RemoteFailures = 0
    V51AdaptiveRefill.StationCyclesSinceTest = 0
    V51AdaptiveRefill.Status = "Remote refill learned: working"
end

function V51AdaptiveRefill.MarkRemoteFailure()
    V51AdaptiveRefill.RemoteFailures += 1
    V51AdaptiveRefill.StationCyclesSinceTest = 0
    V51AdaptiveRefill.Status = V51AdaptiveRefill.RemoteFailures >= 2
        and "Skipping remote preflight for 3 station cycles"
        or "Remote preflight failed once"
end

V52RefillSafety = V52RefillSafety or {
    Phase = "Idle",
    HoldCFrame = nil,
    Active = false,
    StartedAt = 0,
}

function V52RefillSafety.SetPhase(phase)
    V52RefillSafety.Phase = tostring(phase or "Idle")
    if V51AdaptiveRefill then
        V51AdaptiveRefill.Status = "Refill hold: " .. V52RefillSafety.Phase
    end
end

local function beginStationRefill(reason, manual, refillMode, targetAmmo)
    local requestedMode = tostring(refillMode or "Blades")
	if StationRefill.Running then return false end
    if requestedMode == "Blades"
        and Config.V93BladeAmmoDirectorEnabled == true
        and V93BladeAmmoDirector.StationExhausted == true then
        local now = os.clock()
        local retryAt = tonumber(V93BladeAmmoDirector.StationRetryAfter) or 0
        if now < retryAt then
            V93BladeAmmoDirector.BladelessHold = true
            V93BladeAmmoDirector.Status = string.format("STATION RETRY HOLD • %.1fs", math.max(0, retryAt - now))
            statusText = V93BladeAmmoDirector.Status
            return false
        end

        -- V9.5: station failure is no longer a permanent mission-long death sentence.
        V93BladeAmmoDirector.StationExhausted = false
        V93BladeAmmoDirector.BladelessHold = false
        bladeRefillArmed = true
        V93BladeAmmoDirector.Status = "STATION RETRY REARMED"
    end
	local station = findGasStationPart()
	if not station then
		if manual then showNotification("Refill failed", "No GasTanks.Refill part found.", "error") end
		return false
	end
	if not character or not character.Parent or not rootPart then
		if manual then showNotification("Refill failed", "Character/root not ready.", "error") end
		return false
	end
	StationRefill.Running = true
	StationRefill.LastReason = tostring(reason or "station refill")
    StationRefill.Mode = requestedMode
    StationRefill.TargetAmmo = tonumber(targetAmmo)
	task.spawn(function()
		local resumeFarm = State.FarmEnabled == true
        local preRefillCFrame = nil
        local preRefillCameraSubject = nil
        local preRefillCameraType = nil

        pcall(function()
            preRefillCFrame = rootPart and rootPart.CFrame or nil
        end)

        pcall(function()
            local camera = Workspace.CurrentCamera
            if camera then
                preRefillCameraSubject = camera.CameraSubject
                preRefillCameraType = camera.CameraType
            end
        end)

        local spearHoldCFrame = preRefillCFrame
        local spearHoverActive = StationRefill.Mode == "Spears" and typeof(spearHoldCFrame) == "CFrame"

        if spearHoverActive then
            -- V5.2: the refill pipeline owns the character from trigger until combat has
            -- resumed. Gravity never gets a free frame between PRELIGHT/RELOAD/RETURN.
            V52RefillSafety.Active = true
            V52RefillSafety.StartedAt = os.clock()
            V52RefillSafety.HoldCFrame = spearHoldCFrame
            V52RefillSafety.SetPhase("HOVER HOLD")

            pcall(function()
                if rootPart and rootPart.Parent then
                    rootPart.Anchored = true
                    rootPart.AssemblyLinearVelocity = Vector3.zero
                    rootPart.AssemblyAngularVelocity = Vector3.zero
                end
            end)

            task.spawn(function()
                while spearHoverActive and StationRefill.Running do
                    pcall(function()
                        if character and character.Parent
                            and rootPart and rootPart.Parent
                            and typeof(spearHoldCFrame) == "CFrame" then

                            character:PivotTo(spearHoldCFrame)
                            rootPart.Anchored = true
                            rootPart.AssemblyLinearVelocity = Vector3.zero
                            rootPart.AssemblyAngularVelocity = Vector3.zero
                            V52RefillSafety.HoldCFrame = spearHoldCFrame
                        end
                    end)
                    task.wait(0.02)
                end
            end)
        end

		State.FarmEnabled = false
        if StationRefill.Mode == "Spears" then
            clearCurrentTarget(false)
            speedPulseForward = false
            CombatAnchorRuntime.Position = nil
            CombatAnchorRuntime.GroundCenter = nil
            CombatAnchorRuntime.AimPosition = nil
            CombatAnchorRuntime.TargetCount = 0
            CombatAnchorRuntime.PulseUntil = 0
            CombatAnchorRuntime.PulseSerial += 1
        else
		    releaseCombatLock()
        end
		statusText = "Gas station refill: " .. StationRefill.LastReason


		local function readAnyAmmo()
            if StationRefill.Mode == "Spears" then
                local spearValue = nil
                pcall(function()
                    spearValue = V35Spears and V35Spears.ReadAmmo and V35Spears.ReadAmmo() or nil
                end)
                return tonumber(spearValue)
            end

			local bladeValue = nil
			pcall(function() bladeValue = select(1, readBladeSets()) end)
			return bladeValue
		end

        local function targetReached(value)
            if StationRefill.Mode ~= "Spears" then
                return false
            end

            local target = math.max(1, math.floor(tonumber(StationRefill.TargetAmmo) or 8))
            return tonumber(value) ~= nil and tonumber(value) >= target
        end

        local function returnFromSpearRefill()
            if StationRefill.Mode ~= "Spears" then
                return true
            end

            if not character or not character.Parent or not rootPart or not rootPart.Parent then
                return false
            end

            local returnCFrame = preRefillCFrame
            local targetPosition = nil
            local targetPart = nil
            local packCount = 0

            pcall(function()
                if V35Spears and V35Spears.GetBestCluster then
                    targetPosition, targetPart, packCount = V35Spears.GetBestCluster()
                end
            end)

            if typeof(targetPosition) == "Vector3" then
                local height = tonumber(Config.SpearSkyHeight) or 430
                local returnPosition = targetPosition + Vector3.new(0, height, 0)
                local lookAt = targetPosition

                if (lookAt - returnPosition).Magnitude > 0.1 then
                    returnCFrame = CFrame.lookAt(returnPosition, lookAt)
                else
                    returnCFrame = CFrame.new(returnPosition)
                end

                print(
                    "[SliceHub V3.6][TS-RETURN]",
                    "fresh pack=" .. tostring(packCount),
                    "height=" .. tostring(height)
                )
            else
                print(
                    "[SliceHub V3.6][TS-RETURN]",
                    "no fresh pack; using pre-refill position"
                )
            end

            if typeof(returnCFrame) ~= "CFrame" then
                return false
            end

            local okReturn = pcall(function()
                character:PivotTo(returnCFrame)

                rootPart.Anchored = true
                rootPart.AssemblyLinearVelocity = Vector3.zero
                rootPart.AssemblyAngularVelocity = Vector3.zero

                if humanoid then
                    humanoid.PlatformStand = false
                    humanoid.Sit = false
                    humanoid.AutoRotate = true
                end

                spearHoldCFrame = returnCFrame
                V52RefillSafety.SetPhase("RETURN HOLD")
            end)

            task.wait(0.12)

            pcall(function()
                local camera = Workspace.CurrentCamera
                if camera then
                    camera.CameraType = Enum.CameraType.Custom

                    if humanoid and humanoid.Parent then
                        camera.CameraSubject = humanoid
                    elseif preRefillCameraSubject then
                        camera.CameraSubject = preRefillCameraSubject
                    end
                end
            end)

            pcall(function()
                clearCurrentTarget(false)

                CombatAnchorRuntime.Position = nil
                CombatAnchorRuntime.GroundCenter = nil
                CombatAnchorRuntime.AimPosition = nil
                CombatAnchorRuntime.TargetCount = 0
                CombatAnchorRuntime.LastRefresh = 0
                CombatAnchorRuntime.PulseUntil = 0
                CombatAnchorRuntime.PulseSerial += 1
            end)

            return okReturn == true
        end

		local beforeAmmo = readAnyAmmo()
        if StationRefill.Mode == "Blades" and Config.V93BladeAmmoDirectorEnabled == true then
            V93BladeAmmoDirector.LastStationBeforeSets = beforeAmmo
            V93BladeAmmoDirector.Status = "STATION VERIFY • BEFORE " .. tostring(beforeAmmo) .. "/" .. tostring(Config.BladeSetMaximum)
        end

		pcall(function()
			if rootPart then
                rootPart.Anchored = StationRefill.Mode == "Spears"
				rootPart.AssemblyLinearVelocity = Vector3.zero
				rootPart.AssemblyAngularVelocity = Vector3.zero
			end
			if humanoid then
				humanoid.PlatformStand = false
				humanoid.Sit = false
				humanoid.AutoRotate = true
                if StationRefill.Mode ~= "Spears" then
                    humanoid:ChangeState(Enum.HumanoidStateType.Running)
                end
			end
		end)

		local function groundAt(pos)
			local params = RaycastParams.new()
			params.FilterType = Enum.RaycastFilterType.Blacklist
			params.FilterDescendantsInstances = character and {character} or {}
			local result = Workspace:Raycast(pos + Vector3.new(0, 35, 0), Vector3.new(0, -90, 0), params)
			if result and result.Position then
				return result.Position + Vector3.new(0, 3.1, 0)
			end
			return pos
		end

		local function spotList()
			local dist = math.max(0.75, tonumber(Config.StationRefillSpotDistance) or 1.8)
			local sx, sz = 2, 2
			pcall(function()
				sx = math.max(1.5, station.Size.X * 0.5)
				sz = math.max(1.5, station.Size.Z * 0.5)
			end)
			local raw = {
				-- close edge spots: prompt range without burying inside the tank
				(station.CFrame * CFrame.new(0, 0, -(sz + dist))).Position,
				(station.CFrame * CFrame.new(0, 0, sz + dist)).Position,
				(station.CFrame * CFrame.new(-(sx + dist), 0, 0)).Position,
				(station.CFrame * CFrame.new(sx + dist, 0, 0)).Position,
				-- touch-zone fallbacks: some servers only show [R] when the root is basically touching
				(station.CFrame * CFrame.new(0, 1.5, -(sz + 0.35))).Position,
				(station.CFrame * CFrame.new(0, 1.5, sz + 0.35)).Position,
				(station.CFrame * CFrame.new(-(sx + 0.35), 1.5, 0)).Position,
				(station.CFrame * CFrame.new(sx + 0.35, 1.5, 0)).Position,
				station.Position + Vector3.new(0, 2.8, 0),
			}
			local list = {}
			for _, pos in ipairs(raw) do
				table.insert(list, groundAt(pos))
			end
			return list
		end

		local function faceStation()
			pcall(function()
				if rootPart then
					local p = rootPart.Position
					local look = Vector3.new(station.Position.X, p.Y, station.Position.Z)
					if (look - p).Magnitude > 0.1 then
						rootPart.CFrame = CFrame.lookAt(p, look)
					end
				end
			end)
		end

		local function moveToSpot(pos)
			if not humanoid or not rootPart then return false end

            if StationRefill.Mode == "Spears" then
                V52RefillSafety.SetPhase("STATION APPROACH")
                local hoverOffset = Vector3.new(0, 7.5, 0)
                local holdPosition = pos + hoverOffset
                local look = Vector3.new(station.Position.X, holdPosition.Y, station.Position.Z)
                spearHoldCFrame = (look - holdPosition).Magnitude > 0.1
                    and CFrame.lookAt(holdPosition, look)
                    or CFrame.new(holdPosition)

                pcall(function()
                    character:PivotTo(spearHoldCFrame)
                    rootPart.Anchored = true
                    rootPart.AssemblyLinearVelocity = Vector3.zero
                    rootPart.AssemblyAngularVelocity = Vector3.zero
                end)

                task.wait(0.10)
                return rootPart and rootPart.Parent and (rootPart.Position - holdPosition).Magnitude <= 3.5
            end

			pcall(function()
				rootPart.Anchored = false
				rootPart.AssemblyLinearVelocity = Vector3.zero
				rootPart.AssemblyAngularVelocity = Vector3.zero
			end)
			pcall(function() humanoid:MoveTo(pos) end)
			local started = os.clock()
			local timeout = tonumber(Config.StationRefillMoveTimeout) or 2.6
			while os.clock() - started < timeout do
				if not rootPart or not rootPart.Parent then return false end
				faceStation()
				if (rootPart.Position - pos).Magnitude <= 5.5 then return true end
				task.wait(0.05)
			end

            -- V3.5.4: Spear farming often leaves the character far above/away from
            -- the station. Normal MoveTo can never finish from those combat anchors.
            -- Use a station snap only after normal movement has failed.
            if StationRefill.Mode == "Spears"
                and character
                and character.Parent
                and rootPart
                and rootPart.Parent then

                pcall(function()
                    local look = Vector3.new(
                        station.Position.X,
                        pos.Y,
                        station.Position.Z
                    )

                    character:PivotTo(CFrame.lookAt(pos, look))
                    rootPart.AssemblyLinearVelocity = Vector3.zero
                    rootPart.AssemblyAngularVelocity = Vector3.zero
                end)

                task.wait(0.16)

                if rootPart and rootPart.Parent then
                    faceStation()
                    return (rootPart.Position - pos).Magnitude <= 8.5
                end
            end

			return false
		end

        local skipStationMovement = false

        if StationRefill.Mode == "Spears" and V51AdaptiveRefill.ShouldTestRemote() then
            local preflightBefore = readAnyAmmo()

            statusText = "TS safety refill: adaptive remote preflight"

            if V35Spears and V35Spears.DirectReload then
                V35Spears.DirectReload(station)
            end

            local preflightStarted = os.clock()
            local lastSeenAmmo = preflightBefore

            repeat
                task.wait(0.06)

                local liveAmmo = readAnyAmmo()

                if liveAmmo ~= nil then
                    lastSeenAmmo = liveAmmo
                end

                print(
                    "[SliceHub V3.6.1][TS-PREFLIGHT]",
                    "ammo=" .. tostring(liveAmmo),
                    "target=" .. tostring(math.floor(tonumber(StationRefill.TargetAmmo) or 8))
                )

                if targetReached(liveAmmo) then
                    skipStationMovement = true
                    break
                end

                if preflightBefore ~= nil
                    and liveAmmo ~= nil
                    and liveAmmo > preflightBefore then

                    -- Reload was accepted remotely. Keep polling without moving the character.
                    local restoreStarted = os.clock()

                    repeat
                        task.wait(0.06)
                        liveAmmo = readAnyAmmo()

                        if targetReached(liveAmmo) then
                            skipStationMovement = true
                            break
                        end
                    until os.clock() - restoreStarted >= 2.2

                    if not skipStationMovement
                        and V35Spears
                        and V35Spears.DirectReload then

                        V35Spears.DirectReload(station)

                        local retryStarted = os.clock()
                        repeat
                            task.wait(0.06)
                            liveAmmo = readAnyAmmo()

                            if targetReached(liveAmmo) then
                                skipStationMovement = true
                                break
                            end
                        until os.clock() - retryStarted >= 1.6
                    end

                    break
                end
            until os.clock() - preflightStarted >= 0.55

            if skipStationMovement then
                V51AdaptiveRefill.MarkRemoteSuccess()
                statusText = "TS refill complete without station travel"
                print(
                    "[SliceHub V3.6.1][TS-PREFLIGHT]",
                    "remote refill succeeded; station movement skipped"
                )
            else
                V51AdaptiveRefill.MarkRemoteFailure()
                print(
                    "[SliceHub V3.6.1][TS-PREFLIGHT]",
                    "no remote ammo increase; using station fallback"
                )
            end
        elseif StationRefill.Mode == "Spears" then
            V51AdaptiveRefill.Status = "Adaptive skip: direct station fallback"
            V51AdaptiveRefill.StationCyclesSinceTest += 1
            print("[SliceHub V5.1][TS-ADAPTIVE] skipping remote preflight; station cycle", V51AdaptiveRefill.StationCyclesSinceTest, "/3")
        end

		local spots = spotList()
        if not skipStationMovement then
            if StationRefill.Mode == "Spears" then
                V52RefillSafety.SetPhase("STATION FALLBACK")
            end
            task.wait(0.04)
		for index, pos in ipairs(spots) do
			statusText = "Gas station refill: spot " .. tostring(index)
			moveToSpot(pos)
			faceStation()
			task.wait(Config.StationRefillPressDelay or 0.16)

            local reachedTarget = false

            if StationRefill.Mode == "Spears" then
                V52RefillSafety.SetPhase("RELOAD POLLING")
                for reloadAttempt = 1, 3 do
                    if V35Spears and V35Spears.DirectReload then
                        V35Spears.DirectReload(station)
                    end

                    local pollStarted = os.clock()

                    repeat
                        task.wait(0.06)

                        local liveAmmo = readAnyAmmo()

                        print(
                            "[SliceHub V3.6][TS-RELOAD]",
                            "attempt=" .. tostring(reloadAttempt),
                            "ammo=" .. tostring(liveAmmo),
                            "target=" .. tostring(math.floor(tonumber(StationRefill.TargetAmmo) or 8))
                        )

                        if targetReached(liveAmmo) then
                            reachedTarget = true
                            statusText = "Gas station refill: Spears "
                                .. tostring(liveAmmo)
                                .. "/"
                                .. tostring(math.floor(tonumber(StationRefill.TargetAmmo) or 8))
                            break
                        end
                    until os.clock() - pollStarted >= 1.6

                    if reachedTarget then
                        break
                    end
                end
            else
                local refillPresses = math.clamp(
                    math.floor((tonumber(Config.StationRefillKeyPresses) or 12) + 0.5),
                    3,
                    18
                )

                for _ = 1, refillPresses do
                    stationRefillKeyHold()
                    task.wait(0.08)
                end
            end

			local afterAmmo = readAnyAmmo()

            if reachedTarget then
                break
            end

            if StationRefill.Mode == "Spears" then
                if targetReached(afterAmmo) then
                    break
                end
            elseif beforeAmmo ~= nil and afterAmmo ~= nil and afterAmmo > beforeAmmo then
				break
			end

			-- V3.5.5: Spear mode uses exact Attacks/Reload remote; blades keep normal R input.
		end
        end

        if StationRefill.Mode == "Spears" then
            task.wait(0.15)
        else
		    task.wait(Config.StationRefillVerifyDelay or 1.2)
        end

        if StationRefill.Mode == "Blades" and Config.V93BladeAmmoDirectorEnabled == true then
            local verifyDeadline = os.clock() + math.max(0.60, tonumber(Config.V93StationVerifySeconds) or 2.20)
            local observedSets = nil
            local observedSegments = nil

            repeat
                cachedBladeCounter = nil
                cachedBladeSetCounter = nil
                observedSegments = select(1, readBladeSegments())
                observedSets = select(1, readBladeSets())

                local setsRestored = observedSets ~= nil
                    and ((beforeAmmo ~= nil and observedSets > beforeAmmo)
                        or (beforeAmmo == nil and observedSets > 0))
                if setsRestored then
                    break
                end
                task.wait(0.08)
            until os.clock() >= verifyDeadline

            V93BladeAmmoDirector.LastStationAfterSets = observedSets

            local stationSetsRestored = observedSets ~= nil
                and ((beforeAmmo ~= nil and observedSets > beforeAmmo)
                    or (beforeAmmo == nil and observedSets > 0))

            if stationSetsRestored then
                V93BladeAmmoDirector.StationExhausted = false
                V93BladeAmmoDirector.BladelessHold = false
                V93BladeAmmoDirector.StationFailures = 0
                V93BladeAmmoDirector.StationRetryAfter = 0
                bladeRefillArmed = true
                V93BladeAmmoDirector.Status = "STATION REFILL VERIFIED • " .. tostring(observedSets) .. "/" .. tostring(Config.BladeSetMaximum)
                V94RunRecorder.Record("BLADE_STATION", V93BladeAmmoDirector.Status, {
                    segments = observedSegments,
                    sets = observedSets,
                })
                print("[SliceHub V9.3][AMMO]", V93BladeAmmoDirector.Status)
            elseif observedSets ~= nil then
                V93BladeAmmoDirector.StationFailures += 1
                local threshold = math.max(2, math.floor(tonumber(Config.V95StationFailureThreshold) or 3))
                local reachedThreshold = V93BladeAmmoDirector.StationFailures >= threshold

                V93BladeAmmoDirector.StationExhausted = reachedThreshold
                V93BladeAmmoDirector.StationRetryAfter = reachedThreshold
                    and (os.clock() + math.max(1.0, tonumber(Config.V95StationRetryCooldown) or 2.50))
                    or 0
                V93BladeAmmoDirector.BladelessHold = (observedSegments == nil or observedSegments <= 0)
                bladeRefillArmed = true

                if reachedThreshold then
                    V93BladeAmmoDirector.Status = "STATION RETRY COOLDOWN • "
                        .. tostring(V93BladeAmmoDirector.StationFailures) .. "/" .. tostring(threshold)
                else
                    V93BladeAmmoDirector.Status = "STATION REFILL UNCONFIRMED • RETRY "
                        .. tostring(V93BladeAmmoDirector.StationFailures) .. "/" .. tostring(threshold)
                end

                V94RunRecorder.Record("BLADE_STATION", V93BladeAmmoDirector.Status, {
                    segments = observedSegments,
                    sets = observedSets,
                })
                statusText = V93BladeAmmoDirector.Status
                print(
                    "[SliceHub V9.5][AMMO] station refill unconfirmed; bounded retry policy",
                    "sets=" .. tostring(observedSets),
                    "segments=" .. tostring(observedSegments),
                    "failures=" .. tostring(V93BladeAmmoDirector.StationFailures)
                )
            else
                -- Counter vanished entirely: do not permanently condemn the station, but
                -- also do not immediately loop movement again from this same attempt.
                V93BladeAmmoDirector.Status = "STATION VERIFY UNKNOWN • HOLD"
                statusText = V93BladeAmmoDirector.Status
                V93BladeAmmoDirector.BladelessHold = observedSegments == nil or observedSegments <= 0
                print("[SliceHub V9.3][AMMO] station verification unknown; repeated loop suppressed by hold state")
            end
        end

		cachedBladeCounter = nil
		cachedBladeSetCounter = nil
		if manual then
            if StationRefill.Mode == "Spears" then
                showNotification(
                    "Spear refill attempted",
                    "Used direct Attacks/Reload calls and stopped once learned capacity was restored.",
                    "info"
                )
            else
			    showNotification("Refill attempted", "Moved to GasTanks.Refill and used normal R holds.", "info")
            end
		end
        local returnedToFarm = true

        if StationRefill.Mode == "Spears" then
            if skipStationMovement then
                statusText = "TS refill complete: resuming in place"

                pcall(function()
                    if rootPart and rootPart.Parent then
                        rootPart.AssemblyLinearVelocity = Vector3.zero
                        rootPart.AssemblyAngularVelocity = Vector3.zero
                    end

                    local camera = Workspace.CurrentCamera
                    if camera and humanoid and humanoid.Parent then
                        camera.CameraType = Enum.CameraType.Custom
                        camera.CameraSubject = humanoid
                    end
                end)
            else
                statusText = "TS refill complete: returning to combat"
                returnedToFarm = returnFromSpearRefill()
            end
        end

        -- V5.2 release order: combat becomes live while the refill owner still holds
        -- the character, then gravity is released only after the farm has had a chance
        -- to rebuild its sky anchor.
        if StationRefill.Mode == "Spears" then
            V52RefillSafety.SetPhase("COMBAT HANDOFF")
        end

		StationRefill.Running = false

		if resumeFarm then
			State.FarmEnabled = true
			clearCurrentTarget(false)
            cachedTitanCandidatesAt = 0

            if StationRefill.Mode == "Spears" then
                statusText = returnedToFarm
                    and "TS refill complete: Farm resumed"
                    or "TS refill complete: Farm resumed from fallback position"
            end
		end

        if StationRefill.Mode == "Spears" then
            task.wait(0.10)
            spearHoverActive = false
            pcall(function()
                if rootPart and rootPart.Parent then
                    rootPart.AssemblyLinearVelocity = Vector3.zero
                    rootPart.AssemblyAngularVelocity = Vector3.zero
                    rootPart.Anchored = false
                end
            end)
            V52RefillSafety.Active = false
            V52RefillSafety.HoldCFrame = nil
            V52RefillSafety.SetPhase("Idle")
        else
            spearHoverActive = false
        end
	end)
	return true
end

local function fireDirectBladeReload()
    -- V6 trace-grounded primary path.
    local get = resolvePath(ReplicatedStorage, {"Assets", "Remotes", "GET"})
    if get and get:IsA("RemoteFunction") then
        local ok, result = pcall(function()
            return get:InvokeServer("Blades", "Reload")
        end)
        if ok then
            print("[SliceHub V6][BLADE-RELOAD] GET Blades/Reload accepted", tostring(result))
            return true
        end
        warn("[SliceHub V6][BLADE-RELOAD] GET reload failed:", tostring(result))
    end

    -- Legacy fallback retained for executor/game variants where GET is unavailable.
    local post = resolvePath(ReplicatedStorage, {"Assets", "Remotes", "POST"})
    if post and post:IsA("RemoteEvent") then
        local ok, err = pcall(function()
            post:FireServer("Attacks", "Reload")
        end)
        if ok then return true end
        warn("[SliceHub V6][BLADE-RELOAD] POST fallback failed:", tostring(err))
    end
    return false
end

V95BladeReloadCore = V95BladeReloadCore or {}

function V95BladeReloadCore.ReadFresh()
    cachedBladeCounter = nil
    cachedBladeSetCounter = nil
    return select(1, readBladeSegments()), select(1, readBladeSets())
end

function V95BladeReloadCore.Progressed(beforeSegments, beforeSets, afterSegments, afterSets)
    if afterSegments ~= nil and afterSegments > 0 then
        return true
    end
    if beforeSets ~= nil and afterSets ~= nil and afterSets < beforeSets then
        return true
    end
    return false
end

function V95BladeReloadCore.WaitForProgress(beforeSegments, beforeSets, seconds)
    local deadline = os.clock() + math.max(0.10, tonumber(seconds) or 0.35)
    local afterSegments, afterSets = nil, nil
    repeat
        afterSegments, afterSets = V95BladeReloadCore.ReadFresh()
        if V95BladeReloadCore.Progressed(beforeSegments, beforeSets, afterSegments, afterSets) then
            return true, afterSegments, afterSets
        end
        task.wait(0.04)
    until os.clock() >= deadline
    return false, afterSegments, afterSets
end

function V95BladeReloadCore.FirePostFallback()
    local post = resolvePath(ReplicatedStorage, {"Assets", "Remotes", "POST"})
    if not post or not post:IsA("RemoteEvent") then return false end
    local ok, err = pcall(function()
        post:FireServer("Attacks", "Reload")
    end)
    if not ok then
        warn("[SliceHub V9.5][BLADE-RELOAD] POST fallback failed:", tostring(err))
    end
    return ok
end

local function beginBladeRefill(reason, allowMissingHudProbe)
    if not State.AutoRefillEnabled or not bladeRefillArmed or refillSequenceRunning then return false end
    if not character or not character.Parent or not humanoid or humanoid.Health <= 0 then return false end

    local gateSegments, gateMaximum = readBladeSegments()
    local gateSets, gateSetMaximum = readBladeSets()

    if Config.V93BladeAmmoDirectorEnabled == true then
        -- Core V9.3 invariant: visible usable blade segments always beat inferred stall signals.
        if gateSegments ~= nil
            and gateMaximum == Config.BladeSegmentMaximum
            and gateSegments > 0 then
            V93BladeAmmoDirector.Status = "EARLY RELOAD BLOCKED • " .. tostring(gateSegments) .. "/" .. tostring(gateMaximum)
            V91BladeRefillGuard.Status = V93BladeAmmoDirector.Status
            print("[SliceHub V9.3][AMMO]", V93BladeAmmoDirector.Status, "reason=" .. tostring(reason or "unknown"))
            return false
        end

        if gateSegments == nil and allowMissingHudProbe ~= true then
            V93BladeAmmoDirector.Status = "HUD UNKNOWN • RELOAD BLOCKED"
            return false
        end

        if os.clock() < (tonumber(V93BladeAmmoDirector.DirectRetryAfter) or 0) then
            return false
        end

        if gateSets ~= nil
            and gateSetMaximum == Config.BladeSetMaximum
            and gateSets <= 0 then
            if V93BladeAmmoDirector.StationExhausted == true then
                V93BladeAmmoDirector.BladelessHold = gateSegments == nil or gateSegments <= 0
                V93BladeAmmoDirector.Status = V93BladeAmmoDirector.BladelessHold
                    and "BLADELESS HOLD • 0/3 • STATION EXHAUSTED"
                    or "0/3 SETS • USING CURRENT BLADE"
                statusText = V93BladeAmmoDirector.Status
                return false
            end

            if gateSegments == 0 or (gateSegments == nil and allowMissingHudProbe == true) then
                bladeRefillArmed = false
                V93BladeAmmoDirector.Status = "STATION REFILL REQUEST • EMPTY CURRENT BLADE"
                return beginStationRefill("V9.3 confirmed empty current blade + 0/" .. tostring(Config.BladeSetMaximum), false) == true
            end
        end
    end

    bladeRefillArmed = false
    refillSequenceRunning = true
    V93BladeAmmoDirector.DirectSequenceStartedAt = os.clock()

    task.spawn(function()
        local routeStation = false
        local sequenceOk, sequenceError = xpcall(function()
        local waitStarted = os.clock()
        while StationRefill.Running and os.clock() - waitStarted < 5 do
            task.wait(0.05)
        end
        waitStarted = os.clock()
        while ripperSequenceRunning and os.clock() - waitStarted < 1 do
            task.wait(0.01)
        end

        if not State.AutoRefillEnabled or not character or not character.Parent then
            refillSequenceRunning = false
            return
        end

        cachedBladeCounter = nil
        cachedBladeSetCounter = nil
        local beforeSegments, beforeMaximum = readBladeSegments()
        local beforeSets, beforeSetMaximum = readBladeSets()

        if Config.V93BladeAmmoDirectorEnabled == true
            and beforeSegments ~= nil
            and beforeMaximum == Config.BladeSegmentMaximum
            and beforeSegments > 0 then
            V93BladeAmmoDirector.Status = "LATE EARLY-RELOAD BLOCK • " .. tostring(beforeSegments) .. "/" .. tostring(beforeMaximum)
            bladeRefillArmed = true
            refillSequenceRunning = false
            print("[SliceHub V9.3][AMMO] aborting reload after fresh counter read", beforeSegments, "/", beforeMaximum)
            return
        end

        V93BladeAmmoDirector.LastDirectBeforeSegments = beforeSegments
        V93BladeAmmoDirector.LastDirectBeforeSets = beforeSets
        V93BladeAmmoDirector.Status = "DIRECT RELOAD • VERIFYING"
        V94RunRecorder.Record("BLADE_RELOAD", V93BladeAmmoDirector.Status, {
            reason = tostring(reason or "confirmed empty"),
            segments = beforeSegments,
            sets = beforeSets,
        })

        local bladeTool = findBladeTool()
        if bladeTool then
            equipTool(bladeTool)
            task.wait(Config.AutoRefillEquipDelay)
        end

        -- V9.5: a successful InvokeServer call only proves transport, not an accepted reload.
        -- Verify each stage and escalate: GET remote -> physical R -> POST + physical R.
        V93BladeAmmoDirector.ReloadAttempts += 1
        V93BladeAmmoDirector.LastReloadMethod = "GET Blades/Reload"
        fireDirectBladeReload()

        local verified, afterSegments, afterSets = V95BladeReloadCore.WaitForProgress(
            beforeSegments,
            beforeSets,
            Config.V95BladeReloadRemoteProbeSeconds
        )

        if not verified then
            V93BladeAmmoDirector.LastReloadMethod = "PHYSICAL R"
            simulateHumanKeyPress(Config.AutoRefillKey)
            verified, afterSegments, afterSets = V95BladeReloadCore.WaitForProgress(
                beforeSegments,
                beforeSets,
                Config.V95BladeReloadPhysicalProbeSeconds
            )
        end

        if not verified then
            V93BladeAmmoDirector.LastReloadMethod = "POST + PHYSICAL R"
            V95BladeReloadCore.FirePostFallback()
            task.wait(0.04)
            simulateHumanKeyPress(Config.AutoRefillKey)
            verified, afterSegments, afterSets = V95BladeReloadCore.WaitForProgress(
                beforeSegments,
                beforeSets,
                Config.V95BladeReloadFinalProbeSeconds
            )
        end

        V93BladeAmmoDirector.LastDirectAfterSegments = afterSegments
        V93BladeAmmoDirector.LastDirectAfterSets = afterSets

        cachedBladeCounter = nil
        CachedBladeTool = nil
        BladeToolMissingSince = nil
        BladeZeroObservedAt = nil

        if verified then
            V93BladeAmmoDirector.DirectFailures = 0
            V93BladeAmmoDirector.BladelessHold = false
            V93BladeAmmoDirector.Status = "DIRECT RELOAD VERIFIED • "
                .. tostring(afterSegments) .. "/" .. tostring(Config.BladeSegmentMaximum)
                .. " • " .. tostring(V93BladeAmmoDirector.LastReloadMethod or "verified")
            V94RunRecorder.Record("BLADE_RELOAD", V93BladeAmmoDirector.Status, {
                segments = afterSegments,
                sets = afterSets,
            })
            print("[SliceHub V9.3][AMMO]", V93BladeAmmoDirector.Status, "sets=" .. tostring(afterSets))
        else
            V93BladeAmmoDirector.DirectFailures += 1
            V93BladeAmmoDirector.DirectRetryAfter = os.clock()
                + math.max(0.20, tonumber(Config.V93DirectReloadRetryDelay) or 0.25)
            V93BladeAmmoDirector.Status = "DIRECT RELOAD UNCONFIRMED • RETRY SOON • "
                .. tostring(V93BladeAmmoDirector.LastReloadMethod or "unknown")
            V94RunRecorder.Record("BLADE_RELOAD", V93BladeAmmoDirector.Status, {
                segments = afterSegments,
                sets = afterSets,
            })
            print(
                "[SliceHub V9.3][AMMO] direct reload unconfirmed",
                "before=" .. tostring(beforeSegments) .. "/" .. tostring(beforeSets),
                "after=" .. tostring(afterSegments) .. "/" .. tostring(afterSets)
            )

            if (afterSegments == nil or afterSegments <= 0)
                and afterSets ~= nil
                and afterSets <= 0 then
                if V93BladeAmmoDirector.StationExhausted == true then
                    V93BladeAmmoDirector.BladelessHold = true
                    V93BladeAmmoDirector.Status = "BLADELESS HOLD • DIRECT EMPTY + STATION EXHAUSTED"
                    statusText = V93BladeAmmoDirector.Status
                else
                    routeStation = true
                end
            else
                bladeRefillArmed = true
            end
        end

        task.wait(math.max(0.02, tonumber(Config.AutoRefillPostPressDelay) or 0.18))
        end, function(err)
            return tostring(err)
        end)

        refillSequenceRunning = false
        V93BladeAmmoDirector.DirectSequenceStartedAt = 0

        if not sequenceOk then
            bladeRefillArmed = true
            V93BladeAmmoDirector.DirectFailures += 1
            V93BladeAmmoDirector.DirectRetryAfter = os.clock()
                + math.max(0.20, tonumber(Config.V93DirectReloadRetryDelay) or 0.25)
            V93BladeAmmoDirector.Status = "DIRECT RELOAD ERROR • REARMED"
            V91BladeRefillGuard.Status = V93BladeAmmoDirector.Status
            warn("[SliceHub V9.3.1][AMMO] direct reload task recovered:", tostring(sequenceError))
            return
        end

        if routeStation then
            task.defer(function()
                beginStationRefill("V9.3 direct reload ended at 0/3", false)
            end)
        end
    end)

    return true
end

-- V9.1 Blade refill ownership. The exact queue can stay alive even when the trusted
-- segment HUD disappears, so refill is driven by two safe signals:
--   1) trusted 0/3 set count -> station refill
--   2) recent exact Slash activity + sustained no-damage progress -> direct reload probe
V91BladeRefillGuard = V91BladeRefillGuard or {
    LastBreakAt = 0,
    LastProgressAt = os.clock(),
    LastTriggerAt = 0,
    HoldUntil = 0,
    Connection = nil,
    Status = "Idle",
}

function V91BladeRefillGuard.Trigger(reason)
    if Config.V91BladeBreakReloadEnabled ~= true then return false end
    if not State.AutoRefillEnabled then return false end
    if refillSequenceRunning or (StationRefill and StationRefill.Running) then return false end

    local now = os.clock()
    if now - (tonumber(V91BladeRefillGuard.LastTriggerAt) or 0)
        < math.max(0.50, tonumber(Config.V91BladeBreakReloadCooldown) or 0.45) then
        return false
    end

    local segments, segmentMaximum = readBladeSegments()
    local bladeSets, setMaximum = readBladeSets()

    if Config.V93BladeAmmoDirectorEnabled == true then
        if segments ~= nil and segmentMaximum == Config.BladeSegmentMaximum then
            -- Never spend or seek ammo while the current blade still has usable segments.
            if segments > 0 then
                V91BladeRefillGuard.LastTriggerAt = now
                V91BladeRefillGuard.HoldUntil = now + 0.18
                V93BladeAmmoDirector.Status = "NO-PROGRESS IGNORED • " .. tostring(segments) .. "/" .. tostring(segmentMaximum)
                V91BladeRefillGuard.Status = V93BladeAmmoDirector.Status
                return false
            end

            V91BladeRefillGuard.LastTriggerAt = now
            V91BladeRefillGuard.HoldUntil = now + 1.20

            if bladeSets ~= nil
                and setMaximum == Config.BladeSetMaximum
                and bladeSets <= 0 then
                bladeRefillArmed = false

                if V93BladeAmmoDirector.StationExhausted == true then
                    V93BladeAmmoDirector.BladelessHold = true
                    V93BladeAmmoDirector.Status = "BLADELESS HOLD • 0/6 + 0/3"
                    V91BladeRefillGuard.Status = V93BladeAmmoDirector.Status
                    statusText = V93BladeAmmoDirector.Status
                    return false
                end

                V93BladeAmmoDirector.Status = "STATION REFILL • CONFIRMED 0/6 + 0/3"
                V91BladeRefillGuard.Status = V93BladeAmmoDirector.Status
                return beginStationRefill("V9.3 confirmed 0/6 + 0/" .. tostring(Config.BladeSetMaximum), false) == true
            end

            bladeRefillArmed = true
            V93BladeAmmoDirector.Status = "DIRECT RELOAD • CONFIRMED 0/6"
            V91BladeRefillGuard.Status = V93BladeAmmoDirector.Status
            return beginBladeRefill(reason or "confirmed 0/6", false) == true
        end

        -- Segment HUD missing: require both a recent Break hint and a longer no-progress window.
        local breakRecent = now - (tonumber(V91BladeRefillGuard.LastBreakAt) or 0)
            <= math.max(0.35, tonumber(Config.V93MissingHudBreakWindow) or 1.10)
        local noProgressFor = now - (tonumber(V91BladeRefillGuard.LastProgressAt) or now)
        local enoughNoProgress = noProgressFor
            >= math.max(1.20, tonumber(Config.V93MissingHudNoProgressSeconds) or 1.80)

        V91BladeRefillGuard.LastTriggerAt = now

        if not breakRecent or not enoughNoProgress then
            V93BladeAmmoDirector.Status = "HUD UNKNOWN • HOLDING AMMO"
            V91BladeRefillGuard.Status = V93BladeAmmoDirector.Status
            return false
        end

        V91BladeRefillGuard.HoldUntil = now + 1.20

        if bladeSets ~= nil
            and setMaximum == Config.BladeSetMaximum
            and bladeSets <= 0 then
            bladeRefillArmed = false

            if V93BladeAmmoDirector.StationExhausted == true then
                V93BladeAmmoDirector.BladelessHold = true
                V93BladeAmmoDirector.Status = "BLADELESS HOLD • HUD MISSING + 0/3"
                V91BladeRefillGuard.Status = V93BladeAmmoDirector.Status
                statusText = V93BladeAmmoDirector.Status
                return false
            end

            V93BladeAmmoDirector.Status = "STATION REFILL • HUD MISSING + BREAK + STALL"
            V91BladeRefillGuard.Status = V93BladeAmmoDirector.Status
            return beginStationRefill("V9.3 HUD-missing empty evidence", false) == true
        end

        bladeRefillArmed = true
        V93BladeAmmoDirector.Status = "CAUTIOUS DIRECT RELOAD • HUD MISSING"
        V91BladeRefillGuard.Status = V93BladeAmmoDirector.Status
        return beginBladeRefill(reason or "HUD-missing evidence", true) == true
    end

    -- Legacy V9.1 behavior when the V9.3 director is explicitly disabled.
    V91BladeRefillGuard.LastTriggerAt = now
    V91BladeRefillGuard.HoldUntil = now + 1.20

    if bladeSets ~= nil
        and setMaximum == Config.BladeSetMaximum
        and bladeSets <= 0 then
        bladeRefillArmed = false
        V91BladeRefillGuard.Status = "STATION REFILL • " .. tostring(reason or "empty sets")
        return beginStationRefill("V9.1 refill guard 0/" .. tostring(Config.BladeSetMaximum), false) == true
    end

    bladeRefillArmed = true
    V91BladeRefillGuard.Status = "DIRECT RELOAD PROBE • " .. tostring(reason or "no progress")
    return beginBladeRefill(reason or "legacy probe", true) == true
end

do
    local post = resolvePath(ReplicatedStorage, {"Assets", "Remotes", "POST"})
    if post and post:IsA("RemoteEvent") then
        V91BladeRefillGuard.Connection = post.OnClientEvent:Connect(function(category, action, arg3, arg4)
            local cat = tostring(category or "")
            local act = tostring(action or "")

            if cat == "Zones" and act == "Damage_Check" and (tonumber(arg3) or 0) > 0 then
                V91BladeRefillGuard.LastProgressAt = os.clock()
                return
            end

            if cat == "Effects" then
                if act == "Hit" or act == "Blood" then
                    V91BladeRefillGuard.LastProgressAt = os.clock()
                elseif act == "Sound" and tostring(arg3 or "") == "Break" then
                    -- Break is only a hint; it is too noisy to reload from by itself.
                    V91BladeRefillGuard.LastBreakAt = os.clock()
                end
            end
        end)
    end
end

task.spawn(function()
    while true do
        task.wait(0.12)

        if Config.V91BladeBreakReloadEnabled ~= true
            or not State.AutoRefillEnabled
            or not State.BladesEnabled
            or not State.FarmEnabled
            or refillSequenceRunning
            or (StationRefill and StationRefill.Running) then
            continue
        end

        if V91RaidBossGuard and V91RaidBossGuard.Blocked and V91RaidBossGuard.Blocked() then
            continue
        end

        local now = os.clock()
        local exactActive = V6ExactBlade
            and now - (tonumber(V6ExactBlade.LastSlashAt) or 0) <= 0.75
        local noProgressFor = now - (tonumber(V91BladeRefillGuard.LastProgressAt) or now)

        if exactActive
            and noProgressFor >= 1.15
            and now - (tonumber(V91BladeRefillGuard.LastTriggerAt) or 0) >= 2.25 then
            pcall(V91BladeRefillGuard.Trigger, "1.15s exact queue no-progress")
        end
    end
end)

task.spawn(function()
    local lastPrintedAmmoState = nil

    while true do
        task.wait(Config.AutoRefillCheckDelay)

        if not State.AutoRefillEnabled then
            continue
        end

        local current, maximum = readBladeSegments()
        local bladeSets, setMaximum = readBladeSets()

        lastBladeSegments = current
        lastBladeSets = bladeSets

        -- V9.3.1: the one-shot latch must never strand a freshly confirmed empty
        -- current blade while trusted spare sets still exist. This does not infer
        -- emptiness: only the real 0/6 HUD counter can arm recovery.
        local confirmedEmptyWithSpare = Config.V93BladeAmmoDirectorEnabled == true
            and current == 0
            and maximum == Config.BladeSegmentMaximum
            and bladeSets ~= nil
            and setMaximum == Config.BladeSetMaximum
            and bladeSets > 0

        if confirmedEmptyWithSpare then
            local now = os.clock()
            V93BladeAmmoDirector.ConfirmedEmptyWithSpareSince =
                V93BladeAmmoDirector.ConfirmedEmptyWithSpareSince or now

            local emptyFor = now - V93BladeAmmoDirector.ConfirmedEmptyWithSpareSince
            local recoveryDelay = math.max(
                0.25,
                tonumber(Config.V931ConfirmedEmptyRecoverySeconds) or 0.35
            )

            if emptyFor >= recoveryDelay
                and not refillSequenceRunning
                and not (StationRefill and StationRefill.Running)
                and now >= (tonumber(V93BladeAmmoDirector.DirectRetryAfter) or 0) then

                if not bladeRefillArmed then
                    bladeRefillArmed = true
                    BladeZeroObservedAt = nil
                    V93BladeAmmoDirector.ReloadLatchRecoveries += 1
                    V93BladeAmmoDirector.LastReloadLatchRecoveryAt = now
                end

                V93BladeAmmoDirector.BladelessHold = false
                V93BladeAmmoDirector.ConfirmedEmptyWithSpareSince = now
                V93BladeAmmoDirector.Status = "CONFIRMED EMPTY RECOVERY • START DIRECT RELOAD • 0/6 + "
                    .. tostring(bladeSets) .. "/" .. tostring(Config.BladeSetMaximum)
                V91BladeRefillGuard.Status = V93BladeAmmoDirector.Status
                print("[SliceHub V9.5][AMMO]", V93BladeAmmoDirector.Status)

                -- Trusted 0/6 is authoritative. Start recovery directly instead of
                -- relying on a later latch pass that can be starved by raid routing.
                beginBladeRefill("V9.4.2 trusted 0/6 watchdog", false)
            end
        else
            V93BladeAmmoDirector.ConfirmedEmptyWithSpareSince = nil
        end

        local ammoState = tostring(current) .. "/" .. tostring(maximum)
            .. "|" .. tostring(bladeSets) .. "/" .. tostring(setMaximum)
        if ammoState ~= lastPrintedAmmoState then
            lastPrintedAmmoState = ammoState
            V94RunRecorder.Record("BLADE_AMMO", ammoState, {
                segments = current,
                sets = bladeSets,
            })
            print(
                "[SliceHub V3][AMMO]",
                "segments=" .. tostring(current) .. "/" .. tostring(maximum),
                "sets=" .. tostring(bladeSets) .. "/" .. tostring(setMaximum)
            )
        end

        -- V9.1: if the segment counter is unavailable, still honor a trusted empty
        -- Blade-set counter. The old branch ignored 0/3 completely and could leave
        -- Exact Blade spamming forever with no way for station refill to take ownership.
        if current == nil then
            if Config.V93BladeAmmoDirectorEnabled == true then
                local now = os.clock()
                local exactActive = V6ExactBlade
                    and now - (tonumber(V6ExactBlade.LastSlashAt) or 0) <= 0.75
                local breakRecent = now - (tonumber(V91BladeRefillGuard.LastBreakAt) or 0)
                    <= math.max(0.35, tonumber(Config.V93MissingHudBreakWindow) or 1.10)
                local noProgressFor = now - (tonumber(V91BladeRefillGuard.LastProgressAt) or now)
                local enoughNoProgress = noProgressFor
                    >= math.max(1.20, tonumber(Config.V93MissingHudNoProgressSeconds) or 1.80)

                if bladeSets ~= nil
                    and setMaximum == Config.BladeSetMaximum
                    and bladeSets <= 0
                    and exactActive
                    and breakRecent
                    and enoughNoProgress
                    and not refillSequenceRunning
                    and not (StationRefill and StationRefill.Running) then
                    bladeRefillArmed = false
                    V91BladeRefillGuard.HoldUntil = now + 2.0

                    if V93BladeAmmoDirector.StationExhausted == true then
                        V93BladeAmmoDirector.BladelessHold = true
                        V93BladeAmmoDirector.Status = "BLADELESS HOLD • HUD UNKNOWN + 0/3"
                        statusText = V93BladeAmmoDirector.Status
                    else
                        print("[SliceHub V9.3][REFILL] HUD missing + Break + stall + 0/3 -> station")
                        beginStationRefill("V9.3 HUD-missing confirmed empty evidence", false)
                    end
                else
                    V93BladeAmmoDirector.Status = "HUD UNKNOWN • HOLDING AMMO"
                end
            else
                if bladeSets ~= nil
                    and setMaximum == Config.BladeSetMaximum
                    and bladeSets <= 0
                    and not refillSequenceRunning
                    and not (StationRefill and StationRefill.Running) then
                    bladeRefillArmed = false
                    V91BladeRefillGuard.HoldUntil = os.clock() + 2.0
                    beginStationRefill("V9.1 trusted sets 0/" .. tostring(Config.BladeSetMaximum), false)
                end
            end
            continue
        end

        if current > 0 then
            BladeZeroObservedAt = nil

            if Config.V93BladeAmmoDirectorEnabled == true then
                V93BladeAmmoDirector.BladelessHold = false
                if bladeSets ~= nil and bladeSets > 0 and V93BladeAmmoDirector.StationExhausted == true then
                    V93BladeAmmoDirector.StationExhausted = false
                    V93BladeAmmoDirector.StationFailures = 0
                    V93BladeAmmoDirector.Status = "AMMO RESTORED • STATION REARMED"
                elseif not refillSequenceRunning and not StationRefill.Running then
                    V93BladeAmmoDirector.Status = "READY • " .. tostring(current) .. "/" .. tostring(maximum)
                end
            end

            if not bladeCounterPositiveSince then
                bladeCounterPositiveSince = os.clock()
            end

            if not bladeRefillArmed
                and os.clock() - bladeCounterPositiveSince >= Config.AutoRefillRearmDelay then
                bladeRefillArmed = true
            end
        else
            bladeCounterPositiveSince = nil

            if current == 0
                and maximum == Config.BladeSegmentMaximum
                and bladeRefillArmed then

                BladeZeroObservedAt = BladeZeroObservedAt or os.clock()

                local zeroStableFor = os.clock() - BladeZeroObservedAt
                if zeroStableFor >= (tonumber(Config.BladeZeroConfirmDuration) or 0.14) then
                    local verifyCurrent, verifyMaximum = readBladeSegments()

                    if verifyCurrent == 0
                        and verifyMaximum == Config.BladeSegmentMaximum then

                        BladeZeroObservedAt = nil

                        if bladeSets ~= nil
                            and setMaximum == Config.BladeSetMaximum
                            and bladeSets <= 0 then

                            bladeRefillArmed = false

                            if Config.V93BladeAmmoDirectorEnabled == true
                                and V93BladeAmmoDirector.StationExhausted == true then
                                V93BladeAmmoDirector.BladelessHold = true
                                V93BladeAmmoDirector.Status = "BLADELESS HOLD • 0/6 + 0/3 + STATION EXHAUSTED"
                                statusText = V93BladeAmmoDirector.Status
                                print("[SliceHub V9.3][AMMO] bladeless hold armed; no repeated station route")
                            else
                                print("[SliceHub V9.3][REFILL] confirmed 0/6 + 0/3 -> station")
                                beginStationRefill(
                                    "V9.3 confirmed 0/6 + 0/" .. tostring(Config.BladeSetMaximum),
                                    false
                                )
                            end
                        else
                            print(
                                "[SliceHub V9.3][REFILL] confirmed 0/6 -> direct reload",
                                "sets=" .. tostring(bladeSets)
                            )
                            beginBladeRefill("ammo loop confirmed 0/6", false)
                        end
                    else
                        -- transient / stale zero reading: cancel instead of wasting a blade set
                        BladeZeroObservedAt = nil
                    end
                end
            else
                BladeZeroObservedAt = nil
            end
        end
    end
end)

---------------------------------------------------------------------
-- AUTO CUTSCENE SKIP (DETECTED + ONE E PRESS PER CUTSCENE)
---------------------------------------------------------------------

local CutsceneKeywords = {
	"cutscene", "cinematic", "sequence", "story", "dialogue", "dialog", "skip"
}

local function guiObjectIsActuallyVisible(object)
	if not object:IsA("GuiObject") or not object.Visible then return false end
	if object.AbsoluteSize.X <= 0 or object.AbsoluteSize.Y <= 0 then return false end

	local ancestor = object.Parent
	while ancestor and ancestor ~= playerGui do
		if ancestor:IsA("GuiObject") and not ancestor.Visible then
			return false
		end
		if ancestor:IsA("LayerCollector") and not ancestor.Enabled then
			return false
		end
		ancestor = ancestor.Parent
	end
	return true
end

local function containsCutsceneKeyword(value)
	local lower = string.lower(tostring(value or ""))
	for _, keyword in ipairs(CutsceneKeywords) do
		if string.find(lower, keyword, 1, true) then
			return true
		end
	end
	return false
end

local function getVisibleGuiText(object)
	if not guiObjectIsActuallyVisible(object) then return nil end
	if object:IsA("TextLabel") or object:IsA("TextButton") or object:IsA("TextBox") then
		local text = tostring(object.Text or "")
		text = string.gsub(text, "<.->", "")
		return string.lower(text)
	end
	return nil
end

local function hasCutsceneNamedAncestor(object)
	local node = object
	for _ = 1, 7 do
		if not node or node == playerGui then break end
		if containsCutsceneKeyword(node.Name) then return true end
		node = node.Parent
	end
	return false
end

local function detectCutsceneActiveRaw()
	local camera = Workspace.CurrentCamera
	local score = 0
	if camera and camera.CameraType == Enum.CameraType.Scriptable then
		score += 2
	end

	local controlGui = playerGui:FindFirstChild("TitanControlMenu")
	for _, object in ipairs(playerGui:GetDescendants()) do
		-- Never treat this script's own "Auto Skip Cutscene" toggle as a game cutscene.
		if controlGui and object:IsDescendantOf(controlGui) then
			continue
		end

		if object:IsA("GuiObject") and guiObjectIsActuallyVisible(object) then
			local compactName = string.gsub(string.lower(object.Name), "%s+", "")
			if (compactName == "e" or compactName == "ekey" or string.find(compactName, "skip", 1, true))
				and ((camera and camera.CameraType == Enum.CameraType.Scriptable) or hasCutsceneNamedAncestor(object)) then
				return true
			end
		end

		local text = getVisibleGuiText(object)
		if text then
			local compact = string.gsub(text, "%s+", " ")
			local exact = string.gsub(text, "%s+", "")

			-- A visible skip instruction is strong enough by itself.
			if string.find(compact, "press e", 1, true)
				or string.find(compact, "hold e", 1, true)
				or (string.find(compact, "skip", 1, true) and string.find(compact, "e", 1, true)) then
				return true
			end

			-- A lone E is accepted inside a cutscene-named UI tree, or while the
			-- camera is Scriptable (the usual state during a cinematic).
			if exact == "e" and (hasCutsceneNamedAncestor(object)
				or (camera and camera.CameraType == Enum.CameraType.Scriptable)) then
				return true
			end

			if hasCutsceneNamedAncestor(object) then
				score += 1
				if string.find(compact, "skip", 1, true) then
					score += 2
				end
			end
		elseif object:IsA("GuiObject") and guiObjectIsActuallyVisible(object) and hasCutsceneNamedAncestor(object) then
			score += 1
		end

		if score >= 3 then
			return true
		end
	end

	return score >= 3
end

local cutsceneDetectCacheAt = 0
local cutsceneDetectCacheValue = false

local function detectCutsceneActive(force)
    local now = os.clock()
    if not force and now - cutsceneDetectCacheAt < 0.20 then
        return cutsceneDetectCacheValue
    end

    local active = false
    local ok = pcall(function()
        active = detectCutsceneActiveRaw() == true
    end)

    cutsceneDetectCacheAt = now
    cutsceneDetectCacheValue = ok and active or false
    return cutsceneDetectCacheValue
end

V91CutsceneRemoteSkip = V91CutsceneRemoteSkip or {
    LastSentAt = 0,
    LastTarget = nil,
    Status = "Idle",
    Attempts = 0,
}

V94CutsceneDirector = {
    State = "IDLE",
    StateAt = os.clock(),
    EvidenceSince = nil,
    InactiveSince = nil,
    Attempts = 0,
    LastAttemptAt = 0,
    Status = "Waiting for live cutscene evidence",
}

-- Waves initializes Workspace.Waves before its Crates folder. Finishing the
-- cutscene during that small gap makes the game's own Zones module index
-- Workspace.Waves.Crates too early and permanently error for that session.
-- Never manufacture a client-side Crates folder; wait for the server-owned
-- folder and use the game's normal E-key route instead of double-sending the
-- generic Finished remote plus E.
local wavesCratesReadySince = nil

local function wavesCutsceneSetupState()
    local waves = Workspace:FindFirstChild("Waves")
    if not waves then
        wavesCratesReadySince = nil
        return false, true, "Not a Waves runtime"
    end

    -- Workspace.Waves alone is enough to classify this as Waves. The game can
    -- create that folder before Objective.Waves and Crates, which is exactly
    -- the unsafe initialization window we must not skip through.
    local unclimbable = Workspace:FindFirstChild("Unclimbable")
    local objective = unclimbable and unclimbable:FindFirstChild("Objective")
    local waveObjective = objective and objective:FindFirstChild("Waves")
    if not waveObjective then
        wavesCratesReadySince = nil
        return true, false, "Waiting for Waves objective setup"
    end

    local crates = waves:FindFirstChild("Crates")
    if not crates or not crates:IsA("Folder") then
        wavesCratesReadySince = nil
        return true, false, "Waiting for server Waves.Crates setup"
    end

    local now = os.clock()
    wavesCratesReadySince = wavesCratesReadySince or now
    if now - wavesCratesReadySince < 0.75 then
        return true, false, "Waves.Crates found; stabilizing setup"
    end

    return true, true, "Waves setup ready"
end

function V91CutsceneRemoteSkip.Target()
    local unclimbable = Workspace:FindFirstChild("Unclimbable")
    local cutscene = unclimbable and unclimbable:FindFirstChild("Cutscene")
    if not cutscene then return nil end

    local useMiddle = V4RaidDirector
        and V4RaidDirector.RaidName == "Colossal Raid"
        and V55ColossalDirector
        and (
            V55ColossalDirector.TransitionActive == true
            or V55ColossalDirector.P2Confirmed == true
            or V55ColossalDirector.Stage == "P2 BOSS"
        )

    if useMiddle then
        return cutscene:FindFirstChild("Middle") or cutscene:FindFirstChild("Start")
    end
    return cutscene:FindFirstChild("Start") or cutscene:FindFirstChild("Middle")
end

function V91CutsceneRemoteSkip.Try(reason)
    if Config.V91CutsceneRemoteBurstEnabled ~= true then return false end

    local inWaves, wavesReady, wavesReason = wavesCutsceneSetupState()
    if inWaves then
        -- Waves uses one safe input path only. Sending both the generic
        -- Finished remote and E can complete initialization twice.
        V91CutsceneRemoteSkip.Status = wavesReady
            and "Waves safe key-only skip"
            or tostring(wavesReason or "Waiting for Waves setup")
        return false
    end

    local target = V91CutsceneRemoteSkip.Target()
    if not target then return false end

    local now = os.clock()
    if target == V91CutsceneRemoteSkip.LastTarget
        and now - (tonumber(V91CutsceneRemoteSkip.LastSentAt) or 0)
            < math.max(0.18, (tonumber(Config.V94CutsceneRetryGap) or 0.55) * 0.65) then
        return false
    end

    local post = resolvePath(ReplicatedStorage, {"Assets", "Remotes", "POST"})
    if not post or not post:IsA("RemoteEvent") then return false end

    V91CutsceneRemoteSkip.LastTarget = target
    V91CutsceneRemoteSkip.LastSentAt = now
    local sent = pcall(function()
        post:FireServer("Functions", "Finished", target)
    end)

    if sent then
        V91CutsceneRemoteSkip.Attempts += 1
    end
    V91CutsceneRemoteSkip.Status = string.format(
        "%s attempt %d • %s",
        tostring(target.Name),
        tonumber(V91CutsceneRemoteSkip.Attempts) or 0,
        tostring(reason or "verified")
    )
    V94RunRecorder.Record("CUTSCENE_REMOTE", V91CutsceneRemoteSkip.Status)
    print("[SliceHub V9.4][CUTSCENE]", V91CutsceneRemoteSkip.Status)
    return sent == true
end

task.spawn(function()
    local function setState(nextState)
        if V94CutsceneDirector.State ~= nextState then
            V94RunRecorder.Record(
                "CUTSCENE_STATE",
                tostring(V94CutsceneDirector.State) .. " -> " .. tostring(nextState),
                {attempts = V94CutsceneDirector.Attempts}
            )
        end
        V94CutsceneDirector.State = nextState
        V94CutsceneDirector.StateAt = os.clock()
    end

    while true do
        task.wait(Config.CutsceneCheckDelay)

        local enabled = State.AutoSkipCutsceneEnabled
            or (V4RaidDirector and V4RaidDirector.Enabled and State.RaidAutoSkipEnabled)

        if type(SliceHubClampAutoSkipCutscene) == "function" then
            enabled = SliceHubClampAutoSkipCutscene(enabled)
        end

        if not enabled then
            cutsceneDetectedSince = nil
            cutsceneInactiveSince = nil
            cutsceneSkipSent = false
            V94CutsceneDirector.EvidenceSince = nil
            V94CutsceneDirector.InactiveSince = nil
            V94CutsceneDirector.Attempts = 0
            V94CutsceneDirector.LastAttemptAt = 0
            V94CutsceneDirector.Status = "Disabled"
            V91CutsceneRemoteSkip.Attempts = 0
            setState("IDLE")
            continue
        end

        local active = false
        local ok = pcall(function()
            active = detectCutsceneActive(V94CutsceneDirector.State ~= "IDLE")
        end)
        if not ok then active = false end

        local now = os.clock()
        local state = V94CutsceneDirector.State

        if state == "IDLE" then
            if active then
                cutsceneDetectedSince = now
                V94CutsceneDirector.EvidenceSince = now
                V94CutsceneDirector.Status = "Verifying live cutscene evidence"
                setState("DETECTING")
            end

        elseif state == "DETECTING" then
            if not active then
                cutsceneDetectedSince = nil
                V94CutsceneDirector.EvidenceSince = nil
                V94CutsceneDirector.Status = "Evidence vanished before confirmation"
                setState("IDLE")
            elseif now - (V94CutsceneDirector.EvidenceSince or now)
                >= math.max(0.25, tonumber(Config.CutsceneStableTime) or 0.40) then
                cutsceneSkipSent = true
                V94CutsceneDirector.Attempts = 0
                V94CutsceneDirector.LastAttemptAt = 0
                V91CutsceneRemoteSkip.Attempts = 0
                V94CutsceneDirector.Status = "Live evidence confirmed"
                setState("ACTIVE_CONFIRMED")
            end

        elseif state == "ACTIVE_CONFIRMED" then
            if not active then
                cutsceneInactiveSince = now
                V94CutsceneDirector.InactiveSince = now
                V94CutsceneDirector.Status = "Release detected"
                setState("VERIFY_RELEASE")
            else
                local inWaves, wavesReady, wavesReason = wavesCutsceneSetupState()
                local maxAttempts = inWaves
                    and 2
                    or math.max(1, math.floor(tonumber(Config.V94CutsceneMaxAttempts) or 4))
                local retryGap = inWaves
                    and 0.90
                    or math.max(0.30, tonumber(Config.V94CutsceneRetryGap) or 0.55)

                if inWaves and not wavesReady then
                    -- Do not spend attempts while the server is still creating
                    -- the Crates folder required by the game's Zones module.
                    V94CutsceneDirector.Status = tostring(
                        wavesReason or "Waiting for Waves setup"
                    )
                elseif V94CutsceneDirector.Attempts < maxAttempts
                    and now - (tonumber(V94CutsceneDirector.LastAttemptAt) or 0)
                        >= retryGap then

                    V94CutsceneDirector.Attempts += 1
                    V94CutsceneDirector.LastAttemptAt = now

                    if not inWaves then
                        pcall(
                            V91CutsceneRemoteSkip.Try,
                            "verified attempt " .. tostring(V94CutsceneDirector.Attempts)
                        )
                    end

                    -- Waves intentionally uses only the native E-key route.
                    simulateHumanKeyPress(Config.CutsceneKey)
                    V94CutsceneDirector.Status = (inWaves and "Waves safe skip attempt " or "Skip attempt ")
                        .. tostring(V94CutsceneDirector.Attempts)
                        .. "/" .. tostring(maxAttempts)

                    if V94CutsceneDirector.Attempts == 1 then
                        showNotification(
                            "Cutscene Director",
                            inWaves
                                and "Waves setup is ready; safe cutscene skip sent."
                                or "Live cutscene confirmed; bounded skip started.",
                            "info"
                        )
                    end
                elseif V94CutsceneDirector.Attempts >= maxAttempts
                    and now - (tonumber(V94CutsceneDirector.LastAttemptAt) or now)
                        >= math.max(0.50, tonumber(Config.V94CutsceneRecoveryDelay) or 0.85) then
                    V94CutsceneDirector.Status = "Attempts exhausted; restoring control"
                    setState("RECOVER")
                end
            end

        elseif state == "RECOVER" then
            -- Restore local control once after all spaced attempts. Do not spam E.
            pcall(function()
                if V55ColossalDirector and V55ColossalDirector.RestoreControl then
                    V55ColossalDirector.RestoreControl()
                end
            end)
            V94RunRecorder.Record("CUTSCENE_RECOVERY", "Bounded attempts exhausted")
            setState("WAIT_CLEAR")

        elseif state == "WAIT_CLEAR" then
            if not active then
                cutsceneInactiveSince = now
                V94CutsceneDirector.InactiveSince = now
                V94CutsceneDirector.Status = "Release detected after recovery"
                setState("VERIFY_RELEASE")
            end

        elseif state == "VERIFY_RELEASE" then
            if active then
                V94CutsceneDirector.InactiveSince = nil
                setState("WAIT_CLEAR")
            elseif now - (V94CutsceneDirector.InactiveSince or cutsceneInactiveSince or now)
                >= math.max(0.30, tonumber(Config.CutsceneReleaseDelay) or 0.45) then
                cutsceneDetectedSince = nil
                cutsceneInactiveSince = nil
                cutsceneSkipSent = false
                V94CutsceneDirector.EvidenceSince = nil
                V94CutsceneDirector.InactiveSince = nil
                V94CutsceneDirector.Attempts = 0
                V94CutsceneDirector.LastAttemptAt = 0
                V94CutsceneDirector.Status = "Released and rearmed"
                V91CutsceneRemoteSkip.Attempts = 0
                setState("IDLE")
            end
        end
    end
end)


---------------------------------------------------------------------
-- OBJECTIVE BRAIN + COMBAT PRESETS
---------------------------------------------------------------------

local MissionObjectiveHistory = {
    Order = {},
    LatestByKey = {},
    LastUpdatedAt = 0,
    SelectedObjective = nil,
    SelectedMap = nil,
    MetadataUpdatedAt = 0,
}

local function readLastMissionInfoForWebhook()
    local document = nil

    pcall(function()
        local environment = nil
        if type(getgenv) == "function" then
            environment = getgenv()
        end

        if type(environment) == "table"
            and type(environment.AOT_LastMissionInfo) == "table" then
            document = environment.AOT_LastMissionInfo
        elseif type(_G) == "table"
            and type(_G.AOT_LastMissionInfo) == "table" then
            document = _G.AOT_LastMissionInfo
        end
    end)

    if type(document) ~= "table" then
        local readFile = nil

        pcall(function()
            if type(getgenv) == "function" then
                local environment = getgenv()
                if type(environment) == "table"
                    and type(environment.readfile) == "function" then
                    readFile = environment.readfile
                end
            end
        end)

        if not readFile and type(_G) == "table" and type(_G.readfile) == "function" then
            readFile = _G.readfile
        end

        if readFile then
            local okRead, raw = pcall(readFile, "AOT_LastMissionInfo_v1.json")
            if okRead and type(raw) == "string" and raw ~= "" then
                local okDecode, decoded = pcall(function()
                    return HttpService:JSONDecode(raw)
                end)

                if okDecode and type(decoded) == "table" then
                    document = decoded
                end
            end
        end
    end

    if type(document) == "table" then
        local objective = tostring(document.Objective or "")
        local mapName = tostring(document.Map or "")
        MissionObjectiveHistory.SelectedCreateMode = tostring(document.CreateMode or document.Mode or "Mission")
        MissionObjectiveHistory.SelectedRaidChoice = tostring(document.RaidChoice or "")
        MissionObjectiveHistory.SelectedDifficulty = tostring(document.Difficulty or "")

        if objective ~= "" then
            MissionObjectiveHistory.SelectedObjective = objective
        end

        if mapName ~= "" then
            MissionObjectiveHistory.SelectedMap = mapName
        end

        MissionObjectiveHistory.MetadataUpdatedAt = tonumber(document.UpdatedAt) or 0
    end

    return document
end

V3MissionIdentity = V3MissionIdentity or {}

function V3MissionIdentity.CombinedTasksLower()
    local lines = {}
    for _, key in ipairs(MissionObjectiveHistory.Order) do
        local value = MissionObjectiveHistory.LatestByKey[key]
        if value then
            lines[#lines + 1] = string.lower(tostring(value))
        end
    end
    return table.concat(lines, " | ")
end

function V3MissionIdentity.InferSpecialMissionTypeFromTasks()
    local value = V3MissionIdentity.CombinedTasksLower()

    local function has(word)
        return string.find(value, string.lower(word), 1, true) ~= nil
    end

    if has("escort convoy") or has("escort supplies") then return "Escort" end
    if has("breach") or has("barricade") then return "Breach" end
    if has("stall") then return "Stall" end
    if has("protect") then return "Protect" end
    if has("guard") then return "Guard" end
    if has("defend hq") or has("defend headquarters") or has("beacon") then return "Defend" end
    if has("raid") then return "Raid" end

    return nil
end

function V3MissionIdentity.TasksLookLikeNormalSkirmish()
    local value = V3MissionIdentity.CombinedTasksLower()
    local generic = {
        "slay titans",
        "most kills",
        "avoid damage",
        "heal injuries",
        "escape grabs",
        "blind titans",
        "no refills",
        "no grabs",
        "injure titans",
    }

    for _, phrase in ipairs(generic) do
        if string.find(value, phrase, 1, true) then
            return true
        end
    end

    return false
end

function V3MissionIdentity.GetSpecialMissionTypeForWebhook()
    local liveSpecial = V3MissionIdentity.InferSpecialMissionTypeFromTasks()
    if liveSpecial then
        return liveSpecial
    end

    if V3MissionIdentity.TasksLookLikeNormalSkirmish() then
        return nil
    end

    if not MissionObjectiveHistory.SelectedObjective then
        readLastMissionInfoForWebhook()
    end

    local selected = tostring(MissionObjectiveHistory.SelectedObjective or "")
    local lowerSelected = string.lower(selected)

    local updatedAt = tonumber(MissionObjectiveHistory.MetadataUpdatedAt) or 0
    local age = updatedAt > 0 and math.max(0, os.time() - updatedAt) or math.huge

    if age <= 900
        and selected ~= ""
        and lowerSelected ~= "skirmish"
        and lowerSelected ~= "random"
        and lowerSelected ~= "general"
        and lowerSelected ~= "objective" then
        return selected
    end

    return nil
end

V3MissionIdentity.KnownMapAliases = {
    ["Shiganshina"] = {"shiganshina"},
    ["Trost"] = {"trost"},
    ["Outskirts"] = {"outskirts"},
    ["Giant Forest"] = {"giant forest", "giantforest", "forest"},
    ["Utgard Castle"] = {"utgard castle", "utgardcastle", "utgard"},
    ["Loading Docks"] = {"loading docks", "loadingdocks", "docks"},
    ["Stohess"] = {"stohess"},
    ["Chapel"] = {"chapel"},
}

V3MissionIdentity.MapTracker = {
    ObservedMap = nil,
    ObservedAt = 0,
    PendingConsumed = false,
}

V3MissionIdentity.PlaceIdMaps = {
    -- Primary universe map places
    [13379349730] = "Shiganshina",
    [14012874501] = "Trost",
    [14638336319] = "Giant Forest",
    [13904207646] = "Outskirts",
    [15220308770] = "Utgard Castle",
    [17688739434] = "Loading Docks",
    [15824912319] = "Stohess",
    [126678335159530] = "Chapel",

    -- Alternate universe/place set
    [17373821193] = "Shiganshina",
    [15393230324] = "Trost",
    [17373828240] = "Giant Forest",
    [17373824844] = "Outskirts",
    [18182863694] = "Utgard Castle",
    [110415968652032] = "Loading Docks",
    [139092911630535] = "Stohess",
    [133979984250876] = "Chapel",
}

function V3MissionIdentity.CanonicalMapFromText(value)
    local lowerValue = string.lower(tostring(value or ""))
    if lowerValue == "" then return nil end

    for mapName, aliases in pairs(V3MissionIdentity.KnownMapAliases) do
        for _, alias in ipairs(aliases) do
            local lowerAlias = string.lower(alias)
            if lowerValue == lowerAlias
                or string.find(lowerValue, lowerAlias, 1, true) then
                return mapName
            end
        end
    end

    return nil
end

function V3MissionIdentity.ExactWorkspaceMap()
    local rawMap = Workspace:GetAttribute("Map")
    local canonical = V3MissionIdentity.CanonicalMapFromText(rawMap)

    if not canonical then
        canonical = V3MissionIdentity.PlaceIdMaps[game.PlaceId]
    end

    if canonical then
        V3MissionIdentity.MapTracker.ObservedMap = canonical
        V3MissionIdentity.MapTracker.ObservedAt = os.clock()
        return canonical
    end

    return nil
end

function V3MissionIdentity.ObserveMapFromVisibleGui()
    local best = nil

    for _, object in ipairs(playerGui:GetDescendants()) do
        if object:IsA("TextLabel")
            or object:IsA("TextButton")
            or object:IsA("TextBox") then

            local visible = object.Visible
                and object.AbsoluteSize.X > 0
                and object.AbsoluteSize.Y > 0

            if visible then
                local textValue = tostring(object.Text or "")
                local canonical = V3MissionIdentity.CanonicalMapFromText(textValue)

                if canonical then
                    -- Prefer labels whose entire text is the map name.
                    local cleaned = string.lower(string.gsub(textValue, "^%s*(.-)%s*$", "%1"))
                    local exact = false
                    for _, alias in ipairs(V3MissionIdentity.KnownMapAliases[canonical] or {}) do
                        if cleaned == string.lower(alias) then
                            exact = true
                            break
                        end
                    end

                    if exact then
                        return canonical
                    end

                    best = best or canonical
                end
            end
        end
    end

    return best
end

function V3MissionIdentity.ObserveMapFromExplicitMetadata()
    local candidateObjects = {
        Workspace,
        game:GetService("ReplicatedStorage"),
    }

    local attributeNames = {
        "Map",
        "MapName",
        "MissionMap",
        "CurrentMap",
        "LevelName",
    }

    for _, root in ipairs(candidateObjects) do
        for _, attributeName in ipairs(attributeNames) do
            local value = nil
            pcall(function()
                value = root:GetAttribute(attributeName)
            end)

            local canonical = V3MissionIdentity.CanonicalMapFromText(value)
            if canonical then
                return canonical
            end
        end

        local checked = 0
        for _, object in ipairs(root:GetDescendants()) do
            checked += 1
            if checked > 3500 then break end

            local lowerName = string.lower(tostring(object.Name or ""))
            local looksLikeMapMetadata =
                lowerName == "map"
                or lowerName == "mapname"
                or lowerName == "missionmap"
                or lowerName == "currentmap"
                or lowerName == "levelname"

            if looksLikeMapMetadata and object:IsA("StringValue") then
                local canonical = V3MissionIdentity.CanonicalMapFromText(object.Value)
                if canonical then
                    return canonical
                end
            end
        end
    end

    return nil
end

task.spawn(function()
    while true do
        task.wait(0.35)

        if not isMissionRuntimePlace() then
            continue
        end

        local observed = V3MissionIdentity.ExactWorkspaceMap()
            or V3MissionIdentity.ObserveMapFromVisibleGui()
            or V3MissionIdentity.ObserveMapFromExplicitMetadata()

        if observed then
            V3MissionIdentity.MapTracker.ObservedMap = observed
            V3MissionIdentity.MapTracker.ObservedAt = os.clock()
        end
    end
end)

function V3MissionIdentity.GetTrackedMissionMap()
    if V3MissionIdentity.MapTracker.ObservedMap then
        return V3MissionIdentity.MapTracker.ObservedMap
    end

    local guiMap = V3MissionIdentity.ObserveMapFromVisibleGui()
    if guiMap then
        V3MissionIdentity.MapTracker.ObservedMap = guiMap
        V3MissionIdentity.MapTracker.ObservedAt = os.clock()
        return guiMap
    end

    local metadataMap = V3MissionIdentity.ObserveMapFromExplicitMetadata()
    if metadataMap then
        V3MissionIdentity.MapTracker.ObservedMap = metadataMap
        V3MissionIdentity.MapTracker.ObservedAt = os.clock()
        return metadataMap
    end

    return nil
end

function V3MissionIdentity.GetMissionMapForWebhook()
    -- V3: the game's Host reads Workspace:GetAttribute("Map").
    -- This is authoritative and beats GUI text or saved lobby metadata.
    local exactMap = V3MissionIdentity.ExactWorkspaceMap()
    if exactMap then
        return exactMap
    end

    -- Secondary current-run evidence.
    local tracked = V3MissionIdentity.GetTrackedMissionMap()
    if tracked then
        return tracked
    end

    -- 2. Fresh launcher metadata is consumed once for this mission runtime.
    if not MissionObjectiveHistory.SelectedMap then
        readLastMissionInfoForWebhook()
    end

    local updatedAt = tonumber(MissionObjectiveHistory.MetadataUpdatedAt) or 0
    local age = updatedAt > 0 and math.max(0, os.time() - updatedAt) or math.huge
    local selectedMap = V3MissionIdentity.CanonicalMapFromText(MissionObjectiveHistory.SelectedMap)

    if not V3MissionIdentity.MapTracker.PendingConsumed
        and age <= 300
        and selectedMap then

        V3MissionIdentity.MapTracker.PendingConsumed = true
        V3MissionIdentity.MapTracker.ObservedMap = selectedMap
        V3MissionIdentity.MapTracker.ObservedAt = os.clock()
        return selectedMap
    end

    -- Never guess from arbitrary Workspace object names.
    return nil
end

function V3MissionIdentity.GetRunMetadataForWebhook()
    local document = readLastMissionInfoForWebhook()
    local createMode = tostring(MissionObjectiveHistory.SelectedCreateMode or (document and document.CreateMode) or "Mission")
    local objective = tostring(MissionObjectiveHistory.SelectedObjective or (document and document.Objective) or "")
    local raidChoice = tostring(MissionObjectiveHistory.SelectedRaidChoice or (document and document.RaidChoice) or "")
    local difficulty = tostring(MissionObjectiveHistory.SelectedDifficulty or (document and document.Difficulty) or "Unknown")

    local liveRaid = V4RaidDirector and V4RaidDirector.Enabled and tostring(V4RaidDirector.RaidName or "") or ""
    local liveMap = V3MissionIdentity.ExactWorkspaceMap and V3MissionIdentity.ExactWorkspaceMap() or nil
    local liveSpecial = V3MissionIdentity.InferSpecialMissionTypeFromTasks and V3MissionIdentity.InferSpecialMissionTypeFromTasks() or nil
    local explicitLiveMission = liveMap == "Loading Docks" and liveSpecial == "Stall" and liveRaid == ""

    -- Live runtime evidence is authoritative. Saved lobby selection is only fallback
    -- while the live run has not identified itself yet.
    local isRaid = not explicitLiveMission and (
        liveRaid ~= ""
        or (createMode == "Raid" and liveSpecial == nil)
        or (raidChoice ~= "" and liveSpecial == nil)
    )

    local raidName = liveRaid ~= "" and liveRaid or objective
    if raidName == "" then raidName = raidChoice end
    raidName = string.gsub(raidName, " Raid$", "")

    return {
        RunType = isRaid and "Raid" or "Mission",
        RaidName = isRaid and (raidName ~= "" and raidName or nil) or nil,
        Difficulty = difficulty,
        RaidChoice = isRaid and raidChoice or "",
    }
end

function V3MissionIdentity.GetMissionDisplayForWebhook()
    local specialType = V3MissionIdentity.GetSpecialMissionTypeForWebhook()
    local mapName = V3MissionIdentity.GetMissionMapForWebhook()

    if specialType and mapName then
        return specialType .. "\n" .. mapName
    elseif specialType then
        return specialType
    elseif mapName then
        return mapName
    end

    return "Unknown mission"
end

function V3MissionIdentity.CleanMissionObjectiveLine(raw)
    local textValue = tostring(raw or "")
    textValue = string.gsub(textValue, "<.->", "")
    textValue = string.gsub(textValue, "^%s+", "")
    textValue = string.gsub(textValue, "%s+$", "")
    textValue = string.gsub(textValue, "%s+", " ")

    if textValue == "" then
        return nil, nil
    end

    local lower = string.lower(textValue)

    -- Skip headers/status noise and keep actual mission objective rows.
    if lower == "objectives"
        or string.find(lower, "reward boost", 1, true)
        or string.find(lower, "mission completed", 1, true)
        or string.find(lower, "mission failed", 1, true)
        or string.find(lower, "brain:", 1, true)
        or string.find(lower, "webhook + perf", 1, true)
        or string.find(lower, "settings reload automatically", 1, true) then
        return nil, nil
    end

    local objectiveWords = {
        "escort convoy",
        "escort supplies",
        "titan assists",
        "injure titans",
        "slay titans",
        "avoid damage",
        "most kills",
        "heal injuries",
        "escape grabs",
        "execute",
        "blind titans",
        "no refills",
        "no grabs",
        "defend",
        "protect",
        "stall",
        "capture",
        "repair",
        "breach",
    }

    local matched = false
    for _, word in ipairs(objectiveWords) do
        if string.find(lower, word, 1, true) then
            matched = true
            break
        end
    end

    if not matched then
        return nil, nil
    end

    -- Key ignores progress so [0/2] updates replace earlier [0/2]/[1/2] entries.
    local key = string.gsub(lower, "%s*%[%s*%d+%s*/%s*%d+%s*%]", "")
    key = string.gsub(key, "%s+", " ")
    key = string.gsub(key, "^%s+", "")
    key = string.gsub(key, "%s+$", "")

    return key, textValue
end

function V3MissionIdentity.RememberMissionObjectiveLine(raw)
    local key, cleaned = V3MissionIdentity.CleanMissionObjectiveLine(raw)
    if not key or not cleaned then return end

    if MissionObjectiveHistory.LatestByKey[key] == nil then
        table.insert(MissionObjectiveHistory.Order, key)
    end

    MissionObjectiveHistory.LatestByKey[key] = cleaned
    MissionObjectiveHistory.LastUpdatedAt = os.clock()
end

function V3MissionIdentity.GetMissionObjectiveSummary()
    local lines = {}

    for _, key in ipairs(MissionObjectiveHistory.Order) do
        local value = MissionObjectiveHistory.LatestByKey[key]
        if value and value ~= "" then
            table.insert(lines, "• " .. value)
        end
    end

    if #lines == 0 then
        return "No objectives detected"
    end

    return table.concat(lines, "\n")
end

;(function() -- scoped objective/preset helpers
	local objectiveState = {
		LastScan = 0,
		LastPositionScan = 0,
		Text = "",
		Mode = "General",
		Position = nil,
	}

	local objectiveKeywords = {"objective", "objectives", "defend", "guard", "protect", "escort", "stall", "castle", "cart", "gate", "wall", "tower", "point", "base", "hq", "headquarters", "beacon", "supply", "supplies", "breach", "barricade", "district", "door"}
	local protectedObjectiveWords = {"titan", "titans", "nape", "humanoid", "root", "player", "character", "camera", "remote", "debris", "effect", "hitbox"}

	local function lowerText(value)
		local text = tostring(value or "")
		text = string.gsub(text, "<.->", "")
		text = string.gsub(text, "%s+", " ")
		return string.lower(text)
	end

	local function containsAny(text, words)
		text = lowerText(text)
		for _, word in ipairs(words) do
			if string.find(text, string.lower(word), 1, true) then return true end
		end
		return false
	end

	local function visibleTextObject(object)
		if not (object:IsA("TextLabel") or object:IsA("TextButton") or object:IsA("TextBox")) then return false end
		if not object.Visible or object.AbsoluteSize.X <= 0 or object.AbsoluteSize.Y <= 0 then return false end
		local node = object.Parent
		while node and node ~= playerGui do
			if node:IsA("GuiObject") and not node.Visible then return false end
			if node:IsA("LayerCollector") and not node.Enabled then return false end
			node = node.Parent
		end
		return true
	end

	local function readObjectiveText()
		local lines = {}
		for _, object in ipairs(playerGui:GetDescendants()) do
            if screenGui and object:IsDescendantOf(screenGui) then
                continue
            end

			if visibleTextObject(object) then
				local raw = tostring(object.Text or "")
				local lower = lowerText(raw)
				if containsAny(lower, {"objectives", "objective", "defend", "guard", "protect", "escort", "stall", "breach", "hq", "headquarters", "beacon", "supply", "supplies", "repair", "capture", "slay", "execute", "blind", "grabs", "assist", "injure", "damage", "kills", "refills"}) then
					table.insert(lines, raw)
                    V3MissionIdentity.RememberMissionObjectiveLine(raw)
				end
			end
		end
		return table.concat(lines, " | ")
	end

	local function detectModeFromText(text)
		local lower = lowerText(text)
		if string.find(lower, "defend", 1, true) or string.find(lower, "guard", 1, true) or string.find(lower, "protect", 1, true) or string.find(lower, "escort", 1, true) or string.find(lower, "stall", 1, true) or string.find(lower, "breach", 1, true) or string.find(lower, "hq", 1, true) or string.find(lower, "headquarters", 1, true) or string.find(lower, "beacon", 1, true) or string.find(lower, "supply", 1, true) then return "Objective" end
		if string.find(lower, "slay", 1, true) or string.find(lower, "kill", 1, true) then return "Slay" end
		return "General"
	end

	local function objectLooksProtected(object)
		local node = object
		for _ = 1, 6 do
			if not node then break end
			if containsAny(node.Name, protectedObjectiveWords) then return true end
			node = node.Parent
		end
		return false
	end

	local function getObjectPosition(object)
		if object:IsA("BasePart") then return object.Position end
		if object:IsA("Model") then
			local ok, pivot = pcall(function() return object:GetPivot() end)
			if ok and pivot then return pivot.Position end
		end
		return nil
	end

	local function findObjectivePosition()
		local now = os.clock()
		if now - objectiveState.LastPositionScan < 2.0 then return objectiveState.Position end
		objectiveState.LastPositionScan = now
		local bestPosition, bestScore = nil, -math.huge
		local origin = rootPart and rootPart.Position or Vector3.zero
		for _, object in ipairs(Workspace:GetDescendants()) do
			if (object:IsA("BasePart") or object:IsA("Model")) and not objectLooksProtected(object) and containsAny(object.Name, objectiveKeywords) then
				local position = getObjectPosition(object)
				if position then
					local score = 0
					local name = lowerText(object.Name)
					if string.find(name, "headquarters", 1, true) or string.find(name, "hq", 1, true) or string.find(name, "beacon", 1, true) then score += 55 end
					if string.find(name, "breach", 1, true) or string.find(name, "gate", 1, true) or string.find(name, "wall", 1, true) then score += 42 end
					if string.find(name, "supply", 1, true) or string.find(name, "supplies", 1, true) then score += 40 end
					if string.find(name, "castle", 1, true) then score += 35 end
					if string.find(name, "objective", 1, true) then score += 30 end
					if string.find(name, "defend", 1, true) or string.find(name, "guard", 1, true) or string.find(name, "protect", 1, true) then score += 22 end
					if string.find(name, "cart", 1, true) or string.find(name, "escort", 1, true) then score += 18 end
					score -= math.min(120, (position - origin).Magnitude / 12)
					if score > bestScore then bestScore, bestPosition = score, position end
				end
			end
		end
		objectiveState.Position = bestPosition
		return bestPosition
	end

	updateObjectiveBrain = function(force)
		local now = os.clock()
		if not force and now - objectiveState.LastScan < 0.35 then return objectiveState end
		objectiveState.LastScan = now
		objectiveState.Text = readObjectiveText()
		objectiveState.Mode = detectModeFromText(objectiveState.Text)
		local objectiveActive = State.ObjectiveBrainEnabled and (State.CombatPreset == "Objective" or objectiveState.Mode == "Objective")
		if objectiveActive then findObjectivePosition() end
		if applyObjectiveRuntimeTuning then pcall(applyObjectiveRuntimeTuning, objectiveActive) end
		if objectiveBrainStatusLabel then
			local text = objectiveState.Text ~= "" and objectiveState.Text or "No objective text detected"
			objectiveBrainStatusLabel.Text = string.format("Brain: %s  •  %s", objectiveState.Mode or "General", string.sub(text, 1, 70))
		end
		return objectiveState
	end

	getObjectiveMode = function()
		return (updateObjectiveBrain(false).Mode or "General")
	end

	getObjectiveTargetScore = function(entry)
		if not entry then return math.huge end
		local score = tonumber(entry.DistanceSquared) or math.huge
		if State.ObjectiveBrainEnabled then
			local state = updateObjectiveBrain(false)
			local useObjective = State.CombatPreset == "Objective" or state.Mode == "Objective"
			if useObjective and state.Position and entry.Part then
				local distanceToObjective = (entry.Part.Position - state.Position).Magnitude
				local distanceToPlayer = math.sqrt(tonumber(entry.DistanceSquared) or 0)
				score = distanceToObjective * distanceToObjective + distanceToPlayer * 0.45
			end
		end
		return score
	end

	local function setToggle(control, value)
		if control and control.Set then pcall(function() control:Set(value, true) end) end
	end

	applyCombatPreset = function(name, silent)
		name = tostring(name or "Sonic")
		if name ~= "Sonic" and name ~= "Safe" and name ~= "Objective" then name = "Sonic" end
		local maxTitansPerSwing = SliceHubMissionTPSMax()
		local savedTitansPerHit = SliceHubMissionClampTPS(Config.TitansPerHit, maxTitansPerSwing)
		State.CombatPreset = name
		if name == "Sonic" then
			Config.TitansPerHit = maxTitansPerSwing; Config.SkyHeight = 300; Config.SpeedPulseDistance = 20; Config.TargetStallTimeout = 0.75
		elseif name == "Safe" then
			Config.TitansPerHit = maxTitansPerSwing; Config.SkyHeight = 260; Config.SpeedPulseDistance = 18; Config.TargetStallTimeout = 0.90
		else
			Config.TitansPerHit = maxTitansPerSwing; Config.SkyHeight = 230; Config.SpeedPulseDistance = 20; Config.TargetStallTimeout = 0.75
		end
		-- Boot-time silent restore should apply the saved preset behavior without
		-- overwriting the user's saved Titans Per Swing value.
		if silent == true then
			Config.TitansPerHit = savedTitansPerHit
		end
		State.TitanRipperEnabled = true
		State.ObjectiveBrainEnabled = true
		lastBladeBurstCount = math.min(lastBladeBurstCount or 1, Config.TitansPerHit)
		setToggle(Controls and Controls.TitanRipper, State.TitanRipperEnabled)
		if Controls and Controls.TitansPerHit and Controls.TitansPerHit.Set then pcall(function() Controls.TitansPerHit:Set(Config.TitansPerHit, true) end) end
		if combatPresetLabel then combatPresetLabel.Text = "Preset: " .. name end
		updateObjectiveBrain(true)
		saveSettingsIfReady()
		if not silent then showNotification("Combat preset", name .. " preset applied.", "success") end
	end
end)()

