                if containsAny(raw, textKeywords) then
                    lines[#lines + 1] = raw
                end
            end
        end

        table.sort(lines)
        return table.concat(lines, " | ")
    end

    local function getPosition(object)
        if object:IsA("BasePart") then
            return object.Position
        end

        if object:IsA("Model") then
            local ok, pivot = pcall(function()
                return object:GetPivot()
            end)
            if ok and pivot then
                return pivot.Position
            end
        end

        return nil
    end

    local function getCandidateRoot(object)
        if object:IsA("Model") then
            return object
        end

        local model = object:FindFirstAncestorOfClass("Model")
        if model and model.Parent ~= nil and not containsAny(model:GetFullName(), excludeWords) then
            return model
        end

        return object
    end

    local function getInteractionFlags(root)
        local hasPrompt = false
        local hasClick = false
        local hasTouch = false
        local promptNames = {}

        local function inspect(object)
            if object:IsA("ProximityPrompt") then
                hasPrompt = true
                promptNames[#promptNames + 1] =
                    tostring(object.ObjectText or "") .. "/" .. tostring(object.ActionText or "")
            elseif object:IsA("ClickDetector") then
                hasClick = true
            elseif object:IsA("TouchTransmitter") then
                hasTouch = true
            end
        end

        inspect(root)
        for _, object in ipairs(root:GetDescendants()) do
            inspect(object)
        end

        return hasPrompt, hasClick, hasTouch, table.concat(promptNames, ",")
    end

    local function keywordScore(name)
        local l = lower(name)
        local score = 0

        for word, value in pairs(objectKeywords) do
            if string.find(l, word, 1, true) then
                score += value
            end
        end

        return score
    end

    local function getMotionScore(root, position, now)
        local previous = Probe.Motion[root]
        Probe.Motion[root] = {
            Position = position,
            Time = now,
        }

        if not previous or not previous.Position or not previous.Time then
            return 0, 0
        end

        local dt = math.max(0.01, now - previous.Time)
        local moved = (position - previous.Position).Magnitude
        local speed = moved / dt

        local score = 0
        if moved >= 2 then score += 20 end
        if moved >= 8 then score += 25 end
        if speed >= 5 then score += 20 end

        return score, moved
    end

    local function collectCandidates()
        local now = os.clock()
        local seen = {}
        local candidates = {}
        local origin = rootPart and rootPart.Position or Vector3.zero

        for _, object in ipairs(Workspace:GetDescendants()) do
            if object:IsA("Model")
                or object:IsA("BasePart")
                or object:IsA("ProximityPrompt")
                or object:IsA("ClickDetector")
                or object:IsA("TouchTransmitter") then

                local root = getCandidateRoot(object)
                if root
                    and not seen[root]
                    and root.Parent
                    and not containsAny(root:GetFullName(), excludeWords) then

                    seen[root] = true

                    local position = getPosition(root)
                    if position then
                        local nameScore = keywordScore(root:GetFullName())
                        local hasPrompt, hasClick, hasTouch, promptText = getInteractionFlags(root)

                        local interactionScore = 0
                        if hasPrompt then interactionScore += 65 end
                        if hasClick then interactionScore += 45 end
                        if hasTouch then interactionScore += 25 end

                        if nameScore > 0 or interactionScore > 0 then
                            local motionScore, moved = getMotionScore(root, position, now)
                            local distance = (position - origin).Magnitude
                            local distancePenalty = math.min(50, distance / 70)

                            local score = nameScore + interactionScore + motionScore - distancePenalty

                            candidates[#candidates + 1] = {
                                Object = root,
                                Position = position,
                                Score = score,
                                Distance = distance,
                                Moved = moved,
                                HasPrompt = hasPrompt,
                                HasClick = hasClick,
                                HasTouch = hasTouch,
                                PromptText = promptText,
                            }
                        end
                    end
                end
            end
        end

        table.sort(candidates, function(a, b)
            return a.Score > b.Score
        end)

        return candidates
    end

    local function printProbe(snapshot, reason)
        local candidates = collectCandidates()

        print(
            "[SliceHub V2.1.1][OBJECTIVE-PROBE]",
            "reason=" .. tostring(reason),
            "objective=" .. tostring(snapshot ~= "" and snapshot or "none"),
            "candidateCount=" .. tostring(#candidates)
        )

        for index = 1, math.min(#candidates, Probe.MaxResults) do
            local c = candidates[index]

            print(
                "[SliceHub V2.1.1][OBJECTIVE-CANDIDATE]",
                "#" .. tostring(index),
                "score=" .. string.format("%.1f", c.Score),
                "dist=" .. string.format("%.1f", c.Distance),
                "moved=" .. string.format("%.1f", c.Moved),
                "prompt=" .. tostring(c.HasPrompt),
                "click=" .. tostring(c.HasClick),
                "touch=" .. tostring(c.HasTouch),
                "promptText=" .. tostring(c.PromptText),
                "path=" .. c.Object:GetFullName()
            )
        end
    end

    task.spawn(function()
        while true do
            task.wait(0.75)

            if not State or not State.FarmEnabled then
                continue
            end

            local snapshot = readObjectiveSnapshot()
            local lowerSnapshot = lower(snapshot)
            local relevant =
                string.find(lowerSnapshot, "escort", 1, true)
                or string.find(lowerSnapshot, "convoy", 1, true)
                or string.find(lowerSnapshot, "suppl", 1, true)
                or string.find(lowerSnapshot, "cart", 1, true)

            if not relevant then
                continue
            end

            local now = os.clock()
            local signatureChanged = snapshot ~= Probe.LastObjectiveSignature
            local intervalElapsed = now - Probe.LastFullScanAt >= Probe.PrintInterval

            if signatureChanged or intervalElapsed then
                Probe.LastObjectiveSignature = snapshot
                Probe.LastFullScanAt = now
                printProbe(snapshot, signatureChanged and "objective changed" or "periodic")
            end
        end
    end)
end)()

---------------------------------------------------------------------
-- COLOSSAL HITBOX EXPANDER (1000x1000x1000 STUD OVERRIDE)
---------------------------------------------------------------------

local function processHitboxExpansion()
	if not State.ExpandHitboxesEnabled then return end
	local titansFolder = Workspace:FindFirstChild(Config.TitansFolderName)
	if not titansFolder then return end

	for _, titan in ipairs(titansFolder:GetChildren()) do
		local nape = titan:FindFirstChild("Nape", true)
		if nape and nape:IsA("BasePart") then
			if nape.Size ~= Config.HitboxSize then
				nape.Size = Config.HitboxSize
			end
			nape.CanCollide = false
			nape.Transparency = Config.HitboxTransparency
			nape.CastShadow = false
			nape.Massless = true
			nape.Color = Color3.fromRGB(255, 255, 255)
		end
	end
end

task.spawn(function()
	while true do
		task.wait(Config.HitboxRefreshDelay)
		pcall(processHitboxExpansion)
	end
end)

---------------------------------------------------------------------
-- TARGET ACQUISITION & SKY-LOCK NAVIGATION
---------------------------------------------------------------------

local function getTitanTargetPart(titan)
	local nape = titan:FindFirstChild("Nape", true)
	if nape and nape:IsA("BasePart") then return nape end
	local titanRoot = titan:FindFirstChild("HumanoidRootPart")
	if titanRoot and titanRoot:IsA("BasePart") then return titanRoot end
	return nil
end

local function isTitanAlive(titan)
	if not titan:IsA("Model") then return false end
	local titanHumanoid = titan:FindFirstChildOfClass("Humanoid")
	return titanHumanoid ~= nil and titanHumanoid.Health > 0
end

local function isTitanBlacklisted(titan)
	local expiry = targetBlacklistedUntil[titan]
	if not expiry then return false end
	if os.clock() >= expiry then
		targetBlacklistedUntil[titan] = nil
		return false
	end
	return true
end


---------------------------------------------------------------------
-- V4 RAID DIRECTOR
---------------------------------------------------------------------

V4RaidDirector = V4RaidDirector or {
    Enabled = false,
    RaidName = "Unknown",
    Phase = "Idle",
    CombatPaused = false,
    BossTitan = nil,
    BossPart = nil,
    RawBossTitan = nil,
    RawBossPart = nil,
    BossName = nil,
    BossVulnerable = false,
    ShieldActive = false,
    ObjectiveAnchors = {},
    ObjectiveAnchorsAt = 0,
    ObjectiveRadius = 260,
    Phase2Latched = false,
    LastRaidName = "Unknown",
    LastTransitionAt = 0,
    LastBossSeenAt = 0,
    LockedBossTitan = nil,
    LockedBossPart = nil,
    WeakPointText = "Waiting for boss",
    Status = "Waiting for raid",
}

function V4RaidDirector.Lower(value)
    return string.lower(tostring(value or ""))
end

function V4RaidDirector.Contains(text, token)
    return string.find(
        V4RaidDirector.Lower(text),
        V4RaidDirector.Lower(token),
        1,
        true
    ) ~= nil
end

function V4RaidDirector.NameLooksBoss(value)
    local name = V4RaidDirector.Lower(value)

    return
        string.find(name, "armored", 1, true) ~= nil
        or string.find(name, "female", 1, true) ~= nil
        or string.find(name, "colossal", 1, true) ~= nil
        or string.find(name, "attack", 1, true) ~= nil
        or string.find(name, "reiner", 1, true) ~= nil
        or string.find(name, "eren", 1, true) ~= nil
        or string.find(name, "annie", 1, true) ~= nil
        or string.find(name, "bertholdt", 1, true) ~= nil
        or string.find(name, "bertolt", 1, true) ~= nil
        or string.find(name, "boss", 1, true) ~= nil
end

function V4RaidDirector.IsBossTitan(titan)
    if not titan then return false end

    if V4RaidDirector.NameLooksBoss(titan.Name) then
        return true
    end

    local bossAttribute = nil
    local titanType = nil

    pcall(function()
        bossAttribute = titan:GetAttribute("Boss")
        titanType = titan:GetAttribute("Type")
            or titan:GetAttribute("TitanType")
            or titan:GetAttribute("Variant")
    end)

    if bossAttribute == true then
        return true
    end

    return V4RaidDirector.NameLooksBoss(titanType)
end

function V4RaidDirector.ResolveObjectiveBossReference()
    local names = {
        ["Armored Raid"] = "Armored_Boss",
        ["Attack Raid"] = "Attack_Boss",
        ["Female Raid"] = "Female_Boss",
        ["Colossal Raid"] = "Colossal_Boss",
    }

    local objectiveName = names[V4RaidDirector.RaidName]
    local objective = objectiveName and Workspace:FindFirstChild(objectiveName, true) or nil
    local titansFolder = Workspace:FindFirstChild(Config.TitansFolderName)
    if not objective or not titansFolder then return nil, nil end

    for _, object in ipairs(objective:GetDescendants()) do
        if object:IsA("ObjectValue") then
            local value = object.Value
            if value and value:IsDescendantOf(titansFolder) then
                local titan = value
                while titan and titan.Parent ~= titansFolder do titan = titan.Parent end
                if titan and titan.Parent == titansFolder and isTitanAlive(titan) then
                    local part = getTitanTargetPart(titan)
                    if part then return titan, part end
                end
            end
        end
    end

    return nil, nil
end

function V4RaidDirector.RaidIdentityScore(titan)
    if not titan then return -math.huge end

    local pieces = {tostring(titan.Name or "")}
    pcall(function()
        pieces[#pieces + 1] = tostring(titan:GetAttribute("Type") or "")
        pieces[#pieces + 1] = tostring(titan:GetAttribute("TitanType") or "")
        pieces[#pieces + 1] = tostring(titan:GetAttribute("Variant") or "")
        pieces[#pieces + 1] = tostring(titan:GetAttribute("BossName") or "")
        pieces[#pieces + 1] = tostring(titan:GetAttribute("Character") or "")
    end)
    local identity = V4RaidDirector.Lower(table.concat(pieces, " "))

    local tokens = {}
    if V4RaidDirector.RaidName == "Armored Raid" then
        tokens = {"reiner", "armored"}
    elseif V4RaidDirector.RaidName == "Attack Raid" then
        tokens = {"eren", "attack"}
    elseif V4RaidDirector.RaidName == "Female Raid" then
        tokens = {"annie", "female"}
    elseif V4RaidDirector.RaidName == "Colossal Raid" then
        tokens = {"bertholdt", "bertolt", "colossal"}
    end

    local score = 0
    for _, token in ipairs(tokens) do
        if string.find(identity, token, 1, true) then
            score += 100000
        end
    end

    pcall(function()
        if titan:GetAttribute("Boss") == true then score += 80000 end
        if titan:GetAttribute("Shifter") == true then score += 60000 end
    end)

    local scale = 1
    pcall(function() scale = tonumber(titan:GetScale()) or 1 end)
    score += math.max(0, scale - 1) * 550

    local humanoid = titan:FindFirstChildOfClass("Humanoid")
    if humanoid then
        score += math.log(math.max(1, tonumber(humanoid.MaxHealth) or 1)) * 35
    end

    return score
end

function V4RaidDirector.TitanIdentityText(titan)
    if not titan then return "" end
    local pieces = {tostring(titan.Name or "")}
    pcall(function()
        pieces[#pieces + 1] = tostring(titan:GetAttribute("Type") or "")
        pieces[#pieces + 1] = tostring(titan:GetAttribute("TitanType") or "")
        pieces[#pieces + 1] = tostring(titan:GetAttribute("Variant") or "")
        pieces[#pieces + 1] = tostring(titan:GetAttribute("BossName") or "")
        pieces[#pieces + 1] = tostring(titan:GetAttribute("Character") or "")
        pieces[#pieces + 1] = tostring(titan:GetAttribute("ShifterName") or "")
    end)
    return V4RaidDirector.Lower(table.concat(pieces, " "))
end

function V4RaidDirector.FindTitanByIdentityTokens(tokens)
    local titansFolder = Workspace:FindFirstChild(Config.TitansFolderName)
    if not titansFolder then return nil, nil end

    local bestTitan, bestPart, bestScore = nil, nil, -math.huge

    for _, titan in ipairs(titansFolder:GetChildren()) do
        if isTitanAlive(titan) then
            local part = getTitanTargetPart(titan)
            if part and part.Parent then
                local identity = V4RaidDirector.TitanIdentityText(titan)
                local score = 0
                local hits = 0

                for index, token in ipairs(tokens or {}) do
                    if string.find(identity, V4RaidDirector.Lower(token), 1, true) then
                        hits += 1
                        score += index == 1 and 240000 or 150000
                    end
                end

                if hits > 0 then
                    pcall(function()
                        if titan:GetAttribute("Boss") == true then score += 80000 end
                        if titan:GetAttribute("Shifter") == true then score += 60000 end
                    end)

                    local humanoid = titan:FindFirstChildOfClass("Humanoid")
                    if humanoid then
                        score += math.log(math.max(1, tonumber(humanoid.MaxHealth) or 1)) * 30
                    end

                    if score > bestScore then
                        bestTitan, bestPart, bestScore = titan, part, score
                    end
                end
            end
        end
    end

    return bestTitan, bestPart
end

function V4RaidDirector.FemaleObjectiveStage()
    local stage = V521FemaleDirector and V521FemaleDirector.ComputeStage
        and V521FemaleDirector.ComputeStage()
        or "ANNIE P1"

    if V521FemaleDirector then
        V521FemaleDirector.Stage = stage
    end

    return stage
end

function V4RaidDirector.FindFemaleBossTitan()
    local stage = V4RaidDirector.FemaleObjectiveStage()

    if V4RaidDirector.FemaleStage ~= stage then
        V4RaidDirector.FemaleStage = stage
        V4RaidDirector.LockedBossTitan = nil
        V4RaidDirector.LockedBossPart = nil
        if clearCurrentTarget then clearCurrentTarget(false) end
        cachedTitanCandidatesAt = 0
    end

    if stage == "DONE" then
        return nil, nil
    end

    local tokens = stage == "EREN P2"
        and {"eren", "attack"}
        or {"annie", "female"}

    if V4RaidDirector.LockedBossTitan
        and isTitanAlive(V4RaidDirector.LockedBossTitan) then
        local identity = V4RaidDirector.TitanIdentityText(V4RaidDirector.LockedBossTitan)
        local matches = false
        for _, token in ipairs(tokens) do
            if string.find(identity, token, 1, true) then
                matches = true
                break
            end
        end
        if matches then
            local part = getTitanTargetPart(V4RaidDirector.LockedBossTitan)
            if part then return V4RaidDirector.LockedBossTitan, part end
        end
    end

    local titan, part = V4RaidDirector.FindTitanByIdentityTokens(tokens)
    if titan and part then
        V4RaidDirector.LockedBossTitan = titan
        V4RaidDirector.LockedBossPart = part
        return titan, part
    end

    return nil, nil
end

function V4RaidDirector.FindBossTitan()
    local titansFolder = Workspace:FindFirstChild(Config.TitansFolderName)
    if not titansFolder then return nil, nil end

    if V4RaidDirector.RaidName == "Female Raid" then
        return V4RaidDirector.FindFemaleBossTitan()
    end

    if V4RaidDirector.LockedBossTitan
        and V4RaidDirector.LockedBossTitan.Parent == titansFolder
        and isTitanAlive(V4RaidDirector.LockedBossTitan) then
        local lockedPart = getTitanTargetPart(V4RaidDirector.LockedBossTitan)
        if lockedPart then
            V4RaidDirector.LockedBossPart = lockedPart
            return V4RaidDirector.LockedBossTitan, lockedPart
        end
    end

    local refTitan, refPart = V4RaidDirector.ResolveObjectiveBossReference()
    if refTitan and refPart then return refTitan, refPart end

    local alive = {}
    for _, titan in ipairs(titansFolder:GetChildren()) do
        if isTitanAlive(titan) then
            local part = getTitanTargetPart(titan)
            if part and part.Parent then
                if V4RaidDirector.IsBossTitan(titan) then
                    return titan, part
                end
                alive[#alive + 1] = {Titan = titan, Part = part}
            end
        end
    end

    local objectiveActive =
        Workspace:FindFirstChild("Armored_Boss", true)
        or Workspace:FindFirstChild("Female_Boss", true)
        or Workspace:FindFirstChild("Colossal_Boss", true)
        or Workspace:FindFirstChild("Attack_Boss", true)
    if not objectiveActive then return nil, nil end

    local best, second = nil, nil
    for _, entry in ipairs(alive) do
        entry.Score = V4RaidDirector.RaidIdentityScore(entry.Titan)
        if not best or entry.Score > best.Score then
            second = best
            best = entry
        elseif not second or entry.Score > second.Score then
            second = entry
        end
    end

    if not best then return nil, nil end

    -- Identity/attributes are authoritative. Scale/health is only accepted when one
    -- candidate is clearly separated from the rest; otherwise fail closed and wait.
    if best.Score >= 50000 then
        return best.Titan, best.Part
    end

    local gap = best.Score - (second and second.Score or 0)
    local bestScale, secondScale = 1, 1
    pcall(function() bestScale = tonumber(best.Titan:GetScale()) or 1 end)
    if second then pcall(function() secondScale = tonumber(second.Titan:GetScale()) or 1 end) end

    if V4RaidDirector.Phase2Latched
        and bestScale >= 3.25
        and (not second or bestScale - secondScale >= 0.85 or gap >= 900) then
        return best.Titan, best.Part
    end

    return nil, nil
end

function V4RaidDirector.FindArmoredShield()
    local armoredObjective = Workspace:FindFirstChild("Armored_Boss", true)

    if not armoredObjective then
        return false, nil
    end

    local health = armoredObjective:FindFirstChild("Health")

    if not health then
        return false, nil
    end

    local shield = nil

    pcall(function()
        shield = health:GetAttribute("Shield")
    end)

    return shield ~= nil, shield
end

function V4RaidDirector.VisibleObjectiveText(force)
    local now = os.clock()
    if not force
        and V4RaidDirector.VisibleObjectiveCache
        and now - (V4RaidDirector.VisibleObjectiveCacheAt or 0) < 0.20 then
        return V4RaidDirector.VisibleObjectiveCache
    end

    local parts = {}

    pcall(function()
        parts[#parts + 1] = tostring(Workspace:GetAttribute("Objective") or "")
        parts[#parts + 1] = tostring(Workspace:GetAttribute("Phase") or "")
        parts[#parts + 1] = tostring(Workspace:GetAttribute("RaidPhase") or "")
    end)

    pcall(function()
        for _, object in ipairs(playerGui:GetDescendants()) do
            if screenGui and object:IsDescendantOf(screenGui) then
                continue
            end

            if object:IsA("TextLabel")
                or object:IsA("TextButton")
                or object:IsA("TextBox") then

                local visible = object.Visible
                    and object.AbsoluteSize.X > 0
                    and object.AbsoluteSize.Y > 0

                if visible then
                    local raw = V4RaidDirector.Lower(object.Text)
                    if string.find(raw, "boat", 1, true)
                        or string.find(raw, "ship", 1, true)
                        or string.find(raw, "eren", 1, true)
                        or string.find(raw, "annie", 1, true)
                        or string.find(raw, "female titan", 1, true)
                        or string.find(raw, "execute skills", 1, true)
                        or string.find(raw, "boulder", 1, true)
                        or string.find(raw, "armored", 1, true)
                        or string.find(raw, "attack titan", 1, true)
                        or string.find(raw, "colossal", 1, true)
                        or string.find(raw, "cannon", 1, true)
                        or string.find(raw, "stall", 1, true)
                        or string.find(raw, "defend", 1, true)
                        or string.find(raw, "protect", 1, true)
                        or string.find(raw, "kill", 1, true)
                        or string.find(raw, "defeat", 1, true)
                        or string.find(raw, "slay", 1, true)
                        or string.find(raw, "wake", 1, true)
                        or string.find(raw, "vulnerable", 1, true) then
                        parts[#parts + 1] = raw
                    end
                end
            end
        end
    end)

    local result = V4RaidDirector.Lower(table.concat(parts, " | "))
    V4RaidDirector.VisibleObjectiveCache = result
    V4RaidDirector.VisibleObjectiveCacheAt = now
    return result
end

function V4RaidDirector.ObjectiveText()
    local parts = {}

    local visible = V4RaidDirector.VisibleObjectiveText()
    if visible ~= "" then
        parts[#parts + 1] = visible
    end

    pcall(function()
        if V3MissionIdentity and V3MissionIdentity.CombinedTasksLower then
            parts[#parts + 1] = tostring(V3MissionIdentity.CombinedTasksLower() or "")
        end
    end)

    pcall(function()
        parts[#parts + 1] = tostring(Workspace:GetAttribute("Raid") or "")
        parts[#parts + 1] = tostring(Workspace:GetAttribute("RaidName") or "")
    end)

    return V4RaidDirector.Lower(table.concat(parts, " | "))
end


function V4RaidDirector.DetectRaidName()
    -- V5.7.7: Loading Docks Stall is a mission even though it spawns Colossal Titans.
    -- Stale launcher metadata from a previous raid must not turn it into Colossal Raid.
    local liveMap = nil
    local liveSpecial = nil
    pcall(function()
        liveMap = V3MissionIdentity and V3MissionIdentity.ExactWorkspaceMap and V3MissionIdentity.ExactWorkspaceMap() or nil
        liveSpecial = V3MissionIdentity and V3MissionIdentity.InferSpecialMissionTypeFromTasks and V3MissionIdentity.InferSpecialMissionTypeFromTasks() or nil
    end)
    if liveMap == "Loading Docks" and liveSpecial == "Stall"
        and not Workspace:FindFirstChild("Colossal_Boss", true) then
        return "Unknown"
    end

    local mapAttribute = Workspace:GetAttribute("Map")
    local raidAttribute =
        Workspace:GetAttribute("Raid")
        or Workspace:GetAttribute("RaidName")
        or Workspace:GetAttribute("Objective")

    local selectedObjective = ""
    pcall(function()
        selectedObjective = tostring(MissionObjectiveHistory.SelectedObjective or "")
    end)

    local combined =
        V4RaidDirector.Lower(mapAttribute)
        .. " "
        .. V4RaidDirector.Lower(raidAttribute)
        .. " "
        .. V4RaidDirector.Lower(selectedObjective)

    if string.find(combined, "armored", 1, true) then
        return "Armored Raid"
    end
    if string.find(combined, "female", 1, true) then
        return "Female Raid"
    end
    if string.find(combined, "colossal", 1, true) then
        return "Colossal Raid"
    end
    if string.find(combined, "attack titan", 1, true)
        or string.find(combined, "attack raid", 1, true) then
        return "Attack Raid"
    end

    -- Structural fallbacks.
    if Workspace:FindFirstChild("Armored_Boss", true) then
        return "Armored Raid"
    end
    if Workspace:FindFirstChild("Female_Boss", true) then
        return "Female Raid"
    end
    if Workspace:FindFirstChild("Colossal_Boss", true) then
        return "Colossal Raid"
    end
    if Workspace:FindFirstChild("Attack_Boss", true) then
        return "Attack Raid"
    end

    return "Unknown"
end

---------------------------------------------------------------------
-- V5.5 COLOSSAL RAID DIRECTOR
-- Grounded cannon transport:
--   GET:InvokeServer("Cannon", "State", cannon, true)
--   GET:InvokeServer("Cannon", "Shoot", {Base=..., BarrelWood=...})
-- Server cannon projectile speed: 475 studs/s; cannon limits: Base ±90°, Barrel ±40°.
---------------------------------------------------------------------

