local function V576ModifierActive(name)
    local wanted = string.lower(tostring(name or ""))
    if wanted == "" then return false end

    for _, modifier in ipairs((State and State.Modifiers) or {}) do
        if string.lower(tostring(modifier or "")) == wanted then
            return true
        end
    end

    return false
end

function V55ColossalDirector.RefreshModifierProfile()
    local glass = V576ModifierActive("Glass Cannon")
    local oddball = V576ModifierActive("Oddball")

    if glass and oddball then
        V55ColossalDirector.ModifierProfile = "GLASS+ODDBALL"
    elseif glass then
        V55ColossalDirector.ModifierProfile = "GLASS CANNON"
    elseif oddball then
        V55ColossalDirector.ModifierProfile = "ODDBALL"
    else
        V55ColossalDirector.ModifierProfile = "STANDARD"
    end

    return V55ColossalDirector.ModifierProfile
end

function V55ColossalDirector.IsGlassCannonProfile()
    local profile = V55ColossalDirector.RefreshModifierProfile()
    return string.find(profile, "GLASS", 1, true) ~= nil
end

function V55ColossalDirector.IsOddballProfile()
    local profile = V55ColossalDirector.RefreshModifierProfile()
    return string.find(profile, "ODDBALL", 1, true) ~= nil
end

V55ColossalDirector.CalibrationPattern = {
    {Pitch = 0, Yaw = 0},
    {Pitch = 1.25, Yaw = 0},
    {Pitch = -1.25, Yaw = 0},
}

V55ColossalDirector.AimRegions = {
    -- V5.7.4: exact Nape is tested first. Live no-mod runs showed P1 was
    -- already close enough that finding the highest-value critical region early
    -- matters more than surveying six body regions before reaching the nape.
    "Nape",
    "Head",
    "UpperTorso",
    "Torso",
    "LowerTorso",
    "HumanoidRootPart",
}

function V55ColossalDirector.GetRemote()
    local assets = ReplicatedStorage:FindFirstChild("Assets")
    local remotes = assets and assets:FindFirstChild("Remotes")
    local remote = remotes and remotes:FindFirstChild("GET")
    if remote and remote:IsA("RemoteFunction") then return remote end
    return nil
end

function V55ColossalDirector.Invoke(action, ...)
    local remote = V55ColossalDirector.GetRemote()
    if not remote then return false, nil, "GET RemoteFunction missing" end

    local args = table.pack(...)
    local ok, result = pcall(function()
        return remote:InvokeServer("Cannon", action, table.unpack(args, 1, args.n))
    end)

    if not ok then
        V55ColossalDirector.LastError = tostring(result)
        return false, nil, tostring(result)
    end

    return true, result, nil
end

function V55ColossalDirector.ObjectiveText(force)
    local visible = V4RaidDirector.VisibleObjectiveText
        and V4RaidDirector.VisibleObjectiveText(force)
        or ""
    if visible ~= "" then return V4RaidDirector.Lower(visible) end
    return V4RaidDirector.ObjectiveText and V4RaidDirector.ObjectiveText() or ""
end

function V55ColossalDirector.ComputeStage(force)
    if V4RaidDirector.RaidName ~= "Colossal Raid" then
        return "IDLE"
    end

    local textValue = V4RaidDirector.Lower(V55ColossalDirector.ObjectiveText(force))
    textValue = string.gsub(textValue, "%s+", " ")

    -- P1 is authoritative while the live objective explicitly says Stall Bertholdt.
    -- Do not inherit the generic raid Phase2Latched flag here: on Colossal it can
    -- become true simply because the boss model exists at raid start.
    local stallObjective =
        string.find(textValue, "stall bertholdt", 1, true)
        or string.find(textValue, "stall bertolt", 1, true)
        or string.find(textValue, "stall colossal", 1, true)

    local stallDone =
        string.match(textValue, "stall bertholdt%s*%[1%s*/%s*1%]") ~= nil
        or string.match(textValue, "stall bertolt%s*%[1%s*/%s*1%]") ~= nil
        or string.match(textValue, "stall colossal[^%[]*%[1%s*/%s*1%]") ~= nil

    local p2Verb =
        string.find(textValue, "defeat bertholdt", 1, true)
        or string.find(textValue, "kill bertholdt", 1, true)
        or string.find(textValue, "slay bertholdt", 1, true)
        or string.find(textValue, "defeat bertolt", 1, true)
        or string.find(textValue, "kill bertolt", 1, true)
        or string.find(textValue, "slay bertolt", 1, true)
        or string.find(textValue, "defeat colossal", 1, true)
        or string.find(textValue, "kill colossal", 1, true)
        or string.find(textValue, "slay colossal", 1, true)

    local explicitP2 =
        p2Verb
        or string.find(textValue, "phase 2", 1, true)
        or string.find(textValue, "p2", 1, true)

    if explicitP2 then
        V55ColossalDirector.P2Confirmed = true
    end

    if V55ColossalDirector.P2Confirmed == true then
        return "P2 BOSS"
    end

    if stallObjective and not stallDone then
        V4RaidDirector.Phase2Latched = false
        return "P1 CANNON STALL"
    end

    -- If the stall objective disappears briefly during replication/transition,
    -- remain in P1 until exact P2 evidence appears. This is fail-closed on purpose:
    -- cannon logic may wait, but normal weapons never tunnel the invulnerable P1 boss.
    V4RaidDirector.Phase2Latched = false
    return "P1 CANNON STALL"
end

function V55ColossalDirector.FindBoss()
    return V4RaidDirector.FindTitanByIdentityTokens({"bertholdt", "bertolt", "colossal"})
end

function V55ColossalDirector.ResolveAimPart(titan)
    if not titan then return nil end

    local region = V55ColossalDirector.RegionMappingComplete
        and V55ColossalDirector.BestAimRegion
        or V55ColossalDirector.CurrentAimRegion

    if region then
        local part = titan:FindFirstChild(region, true)
        if part and part:IsA("BasePart") then
            return part
        end
    end

    -- Fall back through stable central geometry. The mapper records which actual
    -- body region produced real boss HP loss rather than chasing animated limbs.
    for _, name in ipairs({"UpperTorso", "Torso", "LowerTorso", "HumanoidRootPart", "Head", "Nape"}) do
        local part = titan:FindFirstChild(name, true)
        if part and part:IsA("BasePart") then return part end
    end

    if titan.PrimaryPart and titan.PrimaryPart:IsA("BasePart") then
        return titan.PrimaryPart
    end

    return getTitanTargetPart(titan)
end

V6CannonImpactCore = V6CannonImpactCore or {
    LastTriggerAt = 0,
    LastBurstAt = 0,
    LastTargetPosition = nil,
    Bursts = 0,
    Registers = 0,
    LastBurstShotId = 0,
    Connection = nil,
    Status = "Idle",
}

function V6CannonImpactCore.GetPOST()
    local assets = ReplicatedStorage:FindFirstChild("Assets")
    local remotes = assets and assets:FindFirstChild("Remotes")
    local post = remotes and remotes:FindFirstChild("POST")
    if post and post:IsA("RemoteEvent") then return post end
    return nil
end

function V6CannonImpactCore.TargetPosition()
    local boss = select(1, V55ColossalDirector.FindBoss())
    if not boss then return nil end

    local hitboxes = boss:FindFirstChild("Hitboxes")
    local hit = hitboxes and hitboxes:FindFirstChild("Hit")
    local nape = hit and hit:FindFirstChild("Nape")
    if nape and nape:IsA("BasePart") and nape.Parent then
        return nape.Position
    end

    local directNape = boss:FindFirstChild("Nape", true)
    if directNape and directNape:IsA("BasePart") and directNape.Parent then
        return directNape.Position
    end

    local fallback = V55ColossalDirector.ResolveAimPart(boss)
    return fallback and fallback.Position or nil
end

function V6CannonImpactCore.FireBurst(projectile, shotId)
    if Config.V6ColossalImpactBurstEnabled ~= true then return false end
    if V4RaidDirector.RaidName ~= "Colossal Raid" then return false end
    if V55ColossalDirector.Stage ~= "P1 CANNON STALL" then return false end
    if not V55ColossalDirector.Entered then return false end

    local age = os.clock() - (tonumber(V55ColossalDirector.LastShotAt) or 0)
    if age < 0 or age > math.max(1.0, tonumber(Config.V6ColossalImpactRecentShotWindow) or 6.0) then
        return false
    end

    shotId = tonumber(shotId)
        or (type(V55ColossalDirector.PendingShot) == "table" and tonumber(V55ColossalDirector.PendingShot.ShotId))
        or tonumber(V55ColossalDirector.Shots)
        or 0

    if shotId > 0 and tonumber(V6CannonImpactCore.LastBurstShotId) == shotId then
        return false
    end

    local post = V6CannonImpactCore.GetPOST()
    local targetPosition = V6CannonImpactCore.TargetPosition()
    if not post or typeof(targetPosition) ~= "Vector3" then return false end

    projectile = projectile or Workspace:FindFirstChild("Cannon")
    if not projectile or not projectile.Parent then return false end

    local repeats = math.max(1, math.floor(tonumber(Config.V6ColossalImpactRepeats) or 10))
    local sent = 0
    for _ = 1, repeats do
        local ok = pcall(function()
            post:FireServer("S_Skills", "Impact", projectile, targetPosition)
        end)
        if ok then sent += 1 end
    end

    V6CannonImpactCore.LastBurstAt = os.clock()
    V6CannonImpactCore.LastBurstShotId = shotId
    V6CannonImpactCore.LastTargetPosition = targetPosition
    V6CannonImpactCore.Bursts += 1
    V6CannonImpactCore.Registers += sent
    V6CannonImpactCore.Status = string.format("IMPACT x%d @ Nape", sent)
    V55ColossalDirector.Status = "V6 " .. V6CannonImpactCore.Status
    print(
        "[SliceHub V6][CANNON-IMPACT]",
        "burst=" .. tostring(V6CannonImpactCore.Bursts),
        "sent=" .. tostring(sent),
        "target=" .. tostring(targetPosition)
    )
    return sent > 0
end

function V6CannonImpactCore.Bind()
    if V6CannonImpactCore.Connection then
        pcall(function() V6CannonImpactCore.Connection:Disconnect() end)
        V6CannonImpactCore.Connection = nil
    end

    local post = V6CannonImpactCore.GetPOST()
    if not post then
        V6CannonImpactCore.Status = "POST missing"
        return false
    end

    V6CannonImpactCore.Connection = post.OnClientEvent:Connect(function(category, action, projectile, hitbox, power)
        if Config.V6ColossalImpactBurstEnabled ~= true then return end
        if tostring(category) ~= "Skills" or tostring(action) ~= "Impact" then return end
        if tonumber(power) ~= 5 then return end
        if not projectile or not projectile.Parent then return end
        local lowerName = string.lower(tostring(projectile.Name or ""))
        local looksLikeCannon = string.find(lowerName, "cannon", 1, true) ~= nil
            or projectile:FindFirstChild("Hitbox") ~= nil
        if not looksLikeCannon then return end

        local now = os.clock()
        if now - (tonumber(V6CannonImpactCore.LastTriggerAt) or 0)
            < math.max(0.05, tonumber(Config.V6ColossalImpactDedupe) or 0.35) then
            return
        end

        V6CannonImpactCore.LastTriggerAt = now
        local pendingShotId = type(V55ColossalDirector.PendingShot) == "table"
            and tonumber(V55ColossalDirector.PendingShot.ShotId)
            or tonumber(V55ColossalDirector.Shots)
        task.delay(math.max(0, tonumber(Config.V6ColossalImpactDelay) or 0.12), function()
            pcall(V6CannonImpactCore.FireBurst, projectile, pendingShotId)
        end)
    end)

    V6CannonImpactCore.Status = "Bound"
    return true
end

pcall(V6CannonImpactCore.Bind)

function V55ColossalDirector.AdvanceAimRegion()
    local regions = V55ColossalDirector.AimRegions or {}
    if #regions == 0 then return end

    V55ColossalDirector.AimRegionIndex = (tonumber(V55ColossalDirector.AimRegionIndex) or 1) + 1
    if V55ColossalDirector.AimRegionIndex > #regions then
        V55ColossalDirector.RegionMappingComplete = true
        V55ColossalDirector.AimRegionIndex = 1

        if not V55ColossalDirector.BestAimRegion then
            V55ColossalDirector.BestAimRegion = regions[1]
        end
        V55ColossalDirector.CurrentAimRegion = V55ColossalDirector.BestAimRegion
        return
    end

    V55ColossalDirector.CurrentAimRegion = regions[V55ColossalDirector.AimRegionIndex]
end

function V55ColossalDirector.RecordRegionDamage(region, damage)
    region = tostring(region or V55ColossalDirector.CurrentAimRegion or "Unknown")
    damage = math.max(0, tonumber(damage) or 0)
    local previous = tonumber(V55ColossalDirector.RegionResults[region]) or 0
    if damage > previous then V55ColossalDirector.RegionResults[region] = damage end

    if damage > (tonumber(V55ColossalDirector.BestAimRegionDamage) or 0) then
        V55ColossalDirector.BestAimRegionDamage = damage
        V55ColossalDirector.BestAimRegion = region
    end
end

function V55ColossalDirector.CannonPosition(cannon)
    if not cannon then return nil end
    local base = cannon:FindFirstChild("Base", true)
    if base and base:IsA("BasePart") then return base.Position end
    if cannon:IsA("Model") then
        local ok, cf = pcall(function() return cannon:GetPivot() end)
        if ok then return cf.Position end
    elseif cannon:IsA("BasePart") then
        return cannon.Position
    end
    return nil
end

function V55ColossalDirector.CannonValid(cannon)
    if not cannon or not cannon.Parent then return false end
    local cs = game:GetService("CollectionService")
    if not cs:HasTag(cannon, "Cannon") then return false end
    if cannon:GetAttribute("Setup") ~= true then return false end
    local owner = cannon:GetAttribute("Player")
    return owner == nil or owner == player.Name
end

function V55ColossalDirector.AcquireSingleCannon()
    if V55ColossalDirector.CannonValid(V55ColossalDirector.Cannon) then
        return V55ColossalDirector.Cannon
    end

    V55ColossalDirector.Cannon = nil
    V55ColossalDirector.Entered = false

    local cs = game:GetService("CollectionService")
    local best, bestDistance = nil, math.huge
    local origin = rootPart and rootPart.Position or Vector3.zero

    for _, cannon in ipairs(cs:GetTagged("Cannon")) do
        if V55ColossalDirector.CannonValid(cannon) then
            local pos = V55ColossalDirector.CannonPosition(cannon)
            local distance = pos and (pos - origin).Magnitude or math.huge
            if distance < bestDistance then
                best, bestDistance = cannon, distance
            end
        end
    end

    V55ColossalDirector.Cannon = best
    if best then
        V55ColossalDirector.Status = "Selected one cannon: " .. tostring(best.Name)
    else
        V55ColossalDirector.Status = "Waiting for a Setup Cannon"
    end
    return best
end

function V55ColossalDirector.ReadAngles(cannon)
    cannon = cannon or V55ColossalDirector.Cannon
    local previous = V55ColossalDirector.Angles or {Base = 0, BarrelWood = 0}
    if not cannon then return {Base = previous.Base or 0, BarrelWood = previous.BarrelWood or 0} end

    return {
        Base = tonumber(cannon:GetAttribute("Base")) or tonumber(previous.Base) or 0,
        BarrelWood = tonumber(cannon:GetAttribute("BarrelWood")) or tonumber(previous.BarrelWood) or 0,
    }
end

function V55ColossalDirector.EnterCannon()
    local cannon = V55ColossalDirector.AcquireSingleCannon()
    if not cannon then return false end

    if cannon:GetAttribute("Player") == player.Name then
        V55ColossalDirector.Entered = true
        V55ColossalDirector.Angles = V55ColossalDirector.ReadAngles(cannon)
        return true
    end

    local ok, result, err = V55ColossalDirector.Invoke("State", cannon, true)
    if ok and type(result) == "table" then
        V55ColossalDirector.Angles = {
            Base = tonumber(result.Base) or 0,
            BarrelWood = tonumber(result.BarrelWood) or 0,
        }
        V55ColossalDirector.Entered = true
        V55ColossalDirector.Status = "Mounted single cannon"
        return true
    end

    V55ColossalDirector.Entered = false
    V55ColossalDirector.Status = "Cannon enter failed: " .. tostring(err or result)
    return false
end

function V55ColossalDirector.ExitCannon(reason)
    local cannon = V55ColossalDirector.Cannon
    if cannon and cannon.Parent and cannon:GetAttribute("Player") == player.Name then
        local payload = {Angles = V55ColossalDirector.Angles or V55ColossalDirector.ReadAngles(cannon)}
        V55ColossalDirector.Invoke("State", cannon, false, payload)
    end

    V55ColossalDirector.Entered = false
    if reason then V55ColossalDirector.Status = tostring(reason) end
end

-- V9.4.4: generic ExitCannon() is still used for raid transitions. Blade Guardian
-- uses the handshake helpers below instead: movement remains cannon-owned until
-- the server owner attribute, seat state, and any live cross-assembly joints agree
-- that the character is detached.
function V55ColossalDirector.CannonAttachmentEvidence(cannon)
    cannon = cannon or V55ColossalDirector.Cannon
    if not cannon or not cannon.Parent then return false, "cannon missing" end

    if cannon:GetAttribute("Player") == player.Name then
        return true, "owner attribute"
    end

    local liveCharacter = player.Character
    local liveHumanoid = liveCharacter and liveCharacter:FindFirstChildOfClass("Humanoid")
    local seatPart = liveHumanoid and liveHumanoid.SeatPart
    if seatPart and seatPart:IsDescendantOf(cannon) then
        return true, "humanoid seat"
    end

    local function crossAssemblyJoint(object)
        if not object then return false end
        local ok, part0, part1 = pcall(function()
            return object.Part0, object.Part1
        end)
        if not ok then return false end
        if not part0 and not part1 then return false end

        local p0Character = part0 and liveCharacter and part0:IsDescendantOf(liveCharacter)
        local p1Character = part1 and liveCharacter and part1:IsDescendantOf(liveCharacter)
        local p0Cannon = part0 and part0:IsDescendantOf(cannon)
        local p1Cannon = part1 and part1:IsDescendantOf(cannon)
        return (p0Character and p1Cannon) or (p1Character and p0Cannon)
    end

    if liveCharacter then
        for _, object in ipairs(liveCharacter:GetDescendants()) do
            if (object:IsA("Weld") or object:IsA("WeldConstraint") or object:IsA("Motor6D"))
                and crossAssemblyJoint(object) then
                return true, "character joint"
            end
        end
    end

    for _, object in ipairs(cannon:GetDescendants()) do
        if (object:IsA("Weld") or object:IsA("WeldConstraint") or object:IsA("Motor6D"))
            and crossAssemblyJoint(object) then
            return true, "cannon joint"
        end
    end

    return false, "detached"
end

function V55ColossalDirector.BladeGuardianDangerBudget()
    local now = os.clock()
    local critical = tonumber(V55ColossalDirector.CriticalThreatCount) or 0
    local hp = tonumber(V55ColossalDirector.ErenHealthPercent) or 100
    local hpDropping = now < (tonumber(V55ColossalDirector.ErenDamagedPulseUntil) or 0)
    local heavy = hpDropping or critical >= 1 or hp <= 95

    local banks = heavy
        and math.max(1, math.floor(tonumber(Config.V944BladeGuardianHeavyBanks) or 2))
        or math.max(1, math.floor(tonumber(Config.V944BladeGuardianNormalBanks) or 1))
    local seconds = heavy
        and math.max(0.45, tonumber(Config.V944BladeGuardianHeavySeconds) or 1.90)
        or math.max(0.35, tonumber(Config.V944BladeGuardianNormalSeconds) or 1.10)
    local emergency = math.max(seconds, tonumber(Config.V944BladeGuardianEmergencySeconds) or 2.35)
    return banks, seconds, emergency, heavy
end

function V55ColossalDirector.StartBladeGuardianAirborne()
    local banks, seconds, emergency, heavy = V55ColossalDirector.BladeGuardianDangerBudget()
    local now = os.clock()
    V55ColossalDirector.BladeGuardianAirborne = true
    V55ColossalDirector.BladeGuardianStartedAt = now
    V55ColossalDirector.BladeGuardianStartSlashCount = V6ExactBlade and tonumber(V6ExactBlade.TotalSlashes) or 0
    V55ColossalDirector.BladeGuardianBankBudget = banks
    V55ColossalDirector.BladeGuardianTimeBudget = seconds
    V55ColossalDirector.BladeGuardianEmergencyDeadline = now + emergency
    V55ColossalDirector.BladeGuardNeedsRemount = false
    V55ColossalDirector.CannonHandshakeStatus = heavy and "airborne heavy guard" or "airborne normal guard"

    -- Do not reuse the cannon-seat CFrame as the zero-target hold point. The next
    -- keeper pass must resolve a fresh aerial combat anchor.
    if V942AirLock then
        V942AirLock.LastSafeCFrame = nil
        V942AirLock.Status = "BLADE GUARDIAN REANCHOR"
    end
    if V6ExactBlade then V6ExactBlade.Targets = {} end
    cachedTitanCandidatesAt = 0
end

function V55ColossalDirector.BeginBladeGuardianDismount(reason)
    local cannon = V55ColossalDirector.Cannon
    if not cannon or not cannon.Parent then
        V55ColossalDirector.Entered = false
        V55ColossalDirector.DismountPending = false
        V55ColossalDirector.StartBladeGuardianAirborne()
        return true
    end

    local now = os.clock()
    V55ColossalDirector.DismountPending = true
    V55ColossalDirector.DismountRequestedAt = V55ColossalDirector.DismountRequestedAt > 0
        and V55ColossalDirector.DismountRequestedAt or now
    V55ColossalDirector.LastDismountRequestAt = now
    V55ColossalDirector.DismountReason = tostring(reason or "Blade Guardian")
    V55ColossalDirector.CannonHandshakeStatus = "dismount requested"

    local payload = {Angles = V55ColossalDirector.Angles or V55ColossalDirector.ReadAngles(cannon)}
    V55ColossalDirector.Invoke("State", cannon, false, payload)
    -- Entered deliberately remains true until verified detached.
    return true
end

function V55ColossalDirector.UpdateBladeGuardianDismount()
    if V55ColossalDirector.DismountPending ~= true then
        return V55ColossalDirector.BladeGuardianAirborne == true
    end

    local cannon = V55ColossalDirector.Cannon
    local attached, evidence = V55ColossalDirector.CannonAttachmentEvidence(cannon)
    if not attached then
        V55ColossalDirector.DismountPending = false
        V55ColossalDirector.DismountRequestedAt = 0
        V55ColossalDirector.LastDismountRequestAt = 0
        V55ColossalDirector.Entered = false
        V55ColossalDirector.CannonHandshakeStatus = "dismount verified"
        V55ColossalDirector.StartBladeGuardianAirborne()
        return true
    end

    local now = os.clock()
    local retry = math.max(0.15, tonumber(Config.V944CannonHandshakeRetrySeconds) or 0.35)
    local age = now - (tonumber(V55ColossalDirector.DismountRequestedAt) or now)
    if now - (tonumber(V55ColossalDirector.LastDismountRequestAt) or 0) >= retry then
        V55ColossalDirector.LastDismountRequestAt = now
        if cannon and cannon.Parent then
            local payload = {Angles = V55ColossalDirector.Angles or V55ColossalDirector.ReadAngles(cannon)}
            V55ColossalDirector.Invoke("State", cannon, false, payload)
        end
    end

    local warnAfter = math.max(1.0, tonumber(Config.V944CannonHandshakeWarnSeconds) or 3.0)
    V55ColossalDirector.CannonHandshakeStatus = age >= warnAfter
        and ("DISMOUNT BLOCKED SAFE • " .. tostring(evidence))
        or ("waiting detach • " .. tostring(evidence))
    -- Safety over progress: never release movement ownership while attachment evidence survives.
    return false
end

function V55ColossalDirector.BeginBladeGuardianRemount()
    local cannon = V55ColossalDirector.Cannon
    if not cannon or not cannon.Parent then
        V55ColossalDirector.CannonHandshakeStatus = "same cannon missing"
        return false
    end

    local now = os.clock()
    V55ColossalDirector.RemountPending = true
    V55ColossalDirector.RemountRequestedAt = V55ColossalDirector.RemountRequestedAt > 0
        and V55ColossalDirector.RemountRequestedAt or now
    V55ColossalDirector.LastRemountRequestAt = now
    V55ColossalDirector.Entered = false
    V55ColossalDirector.CannonHandshakeStatus = "remount requested"
    V55ColossalDirector.Invoke("State", cannon, true)
    return true
end

function V55ColossalDirector.UpdateBladeGuardianRemount()
    if V55ColossalDirector.RemountPending ~= true then return false end

    local cannon = V55ColossalDirector.Cannon
    if not cannon or not cannon.Parent then
        V55ColossalDirector.CannonHandshakeStatus = "same cannon missing during remount"
        return false
    end

    local attached, evidence = V55ColossalDirector.CannonAttachmentEvidence(cannon)
    if attached then
        V55ColossalDirector.RemountPending = false
        V55ColossalDirector.RemountRequestedAt = 0
        V55ColossalDirector.LastRemountRequestAt = 0
        V55ColossalDirector.BladeGuardNeedsRemount = false
        V55ColossalDirector.Entered = true
        V55ColossalDirector.Angles = V55ColossalDirector.ReadAngles(cannon)
        V55ColossalDirector.CannonHandshakeStatus = "remount verified • " .. tostring(evidence)
        V55ColossalDirector.Status = "Blade Guardian complete — same cannon remounted"
        return true
    end

    local now = os.clock()
    local retry = math.max(0.15, tonumber(Config.V944CannonHandshakeRetrySeconds) or 0.35)
    if now - (tonumber(V55ColossalDirector.LastRemountRequestAt) or 0) >= retry then
        V55ColossalDirector.LastRemountRequestAt = now
        V55ColossalDirector.Invoke("State", cannon, true)
    end

    local age = now - (tonumber(V55ColossalDirector.RemountRequestedAt) or now)
    local warnAfter = math.max(1.0, tonumber(Config.V944CannonHandshakeWarnSeconds) or 3.0)
    V55ColossalDirector.CannonHandshakeStatus = age >= warnAfter
        and "REMOUNT RETRY SAFE • movement locked"
        or "waiting remount verification"
    return false
end

function V55ColossalDirector.WrapDegrees(value)
    value = (tonumber(value) or 0) % 360
    if value > 180 then value -= 360 end
    return value
end

function V55ColossalDirector.SampleBossMotion(targetPart)
    if not targetPart or not targetPart.Parent then
        V55ColossalDirector.SmoothedBossVelocity = Vector3.zero
        return Vector3.zero
    end

    local model = targetPart:FindFirstAncestorOfClass("Model")
    local stablePart = model and (
        model:FindFirstChild("HumanoidRootPart", true)
        or model:FindFirstChild("UpperTorso", true)
        or model:FindFirstChild("Torso", true)
        or model:FindFirstChild("LowerTorso", true)
    ) or targetPart

    if not stablePart or not stablePart:IsA("BasePart") then
        stablePart = targetPart
    end

    local now = os.clock()
    local position = stablePart.Position
    local previousPosition = V55ColossalDirector.LastMotionPosition
    local previousAt = tonumber(V55ColossalDirector.LastMotionAt) or 0
    local velocity = V55ColossalDirector.SmoothedBossVelocity or Vector3.zero

    if typeof(previousPosition) == "Vector3" and previousAt > 0 then
        local dt = now - previousAt
        if dt >= 0.08 and dt <= 2.5 then
            local raw = (position - previousPosition) / dt
            -- Colossal walks slowly relative to projectile speed. Clamp animation
            -- spikes, then smooth the real world-space approach velocity.
            local horizontal = Vector3.new(raw.X, 0, raw.Z)
            if horizontal.Magnitude > 90 then
                horizontal = horizontal.Unit * 90
            end
            local vertical = math.clamp(raw.Y, -25, 25)
            local sample = Vector3.new(horizontal.X, vertical, horizontal.Z)
            velocity = velocity:Lerp(sample, 0.38)
        end
    end

    V55ColossalDirector.LastMotionPosition = position
    V55ColossalDirector.LastMotionAt = now
    V55ColossalDirector.SmoothedBossVelocity = velocity
    return velocity
end

function V55ColossalDirector.RangeArcLift(range)
    -- Empirical Colossal P1 arc profile. Live tests showed ~34 degrees connecting
    -- at the far wall, then sailing high once Bertholdt walked closer. Interpolate
    -- a lower arc continuously as range closes instead of keeping a 34-degree floor.
    local anchors = {
        {600, 1.0},
        {750, 4.0},
        {900, 8.0},
        {1050, 13.0},
        {1200, 19.0},
        {1325, 25.0},
        {1425, 29.0},
        {1550, 31.5},
    }
    range = math.max(0, tonumber(range) or 0)
    if range <= anchors[1][1] then return anchors[1][2] end
    for index = 1, #anchors - 1 do
        local a, b = anchors[index], anchors[index + 1]
        if range <= b[1] then
            local alpha = math.clamp((range - a[1]) / math.max(1, b[1] - a[1]), 0, 1)
            return a[2] + (b[2] - a[2]) * alpha
        end
    end
    return anchors[#anchors][2]
end

function V55ColossalDirector.BallisticDirection(muzzlePosition, targetPart)
    local speed = tonumber(V55ColossalDirector.ShotSpeed) or 475
    local velocity = V55ColossalDirector.SampleBossMotion(targetPart)
    velocity = Vector3.new(velocity.X, 0, velocity.Z)
    if velocity.Magnitude > 55 then velocity = velocity.Unit * 55 end

    local spawnDelay = 0.7666666666666667 -- grounded cannon module delay before projectile spawn
    local predicted = targetPart.Position
    local theta = 0
    local tof = 0.1
    local range = 0

    for _ = 1, 3 do
        local delta = predicted - muzzlePosition
        local horizontal = Vector3.new(delta.X, 0, delta.Z)
        range = horizontal.Magnitude
        if range <= 0.01 then
            return Vector3.new(0, 1, 0), 40, 0.1, "LIVE-RANGE"
        end

        local linePitch = math.deg(math.atan2(delta.Y, range))
        local desiredPitch = math.clamp(
            linePitch + V55ColossalDirector.RangeArcLift(range) + (tonumber(V55ColossalDirector.MissPitchBias) or 0),
            -12,
            40
        )
        theta = math.rad(desiredPitch)
        tof = math.clamp(range / (speed * math.max(0.18, math.cos(theta))), 0.05, 5.0)

        -- The server waits 0.7667s after Shoot before spawning the cannonball.
        -- Lead through BOTH windup and flight time so an approaching Colossal is
        -- not targeted at the place where he stood several seconds earlier.
        predicted = targetPart.Position + velocity * math.clamp(spawnDelay + tof, 0, 5.5)
    end

    local delta = predicted - muzzlePosition
    local horizontal = Vector3.new(delta.X, 0, delta.Z)
    if horizontal.Magnitude <= 0.01 then
        return Vector3.new(0, 1, 0), math.deg(theta), tof, "LIVE-RANGE"
    end

    local flat = horizontal.Unit
    local direction = flat * math.cos(theta) + Vector3.new(0, math.sin(theta), 0)
    return direction.Unit, math.deg(theta), tof, "LIVE-RANGE"
end

function V55ColossalDirector.SolveAngles(cannon, targetPart)
    local muzzle = cannon and cannon:FindFirstChild("EndBarrel3", true)
    if not muzzle or not muzzle:IsA("BasePart") then return nil, "muzzle missing" end
    if not targetPart or not targetPart.Parent then return nil, "target missing" end

    local desiredDirection, ballisticPitch, tof, arcName =
        V55ColossalDirector.BallisticDirection(muzzle.Position, targetPart)

    local liveDistance = (targetPart.Position - muzzle.Position).Magnitude
    local previousDistance = tonumber(V55ColossalDirector.LastSolvedDistance)
    if previousDistance and math.abs(liveDistance - previousDistance) >= 220 then
        -- The boss has materially changed range. Rebase angle correction around the
        -- freshly solved trajectory while keeping the best proven body region.
        V55ColossalDirector.CalibrationPitch = tonumber(V55ColossalDirector.MissPitchBias) or 0
        V55ColossalDirector.CalibrationYaw = tonumber(V55ColossalDirector.MissYawBias) or 0
        V55ColossalDirector.CalibrationLocked = false
        V55ColossalDirector.Status = string.format(
            "Range changed %.0f→%.0f — live ballistic rebase",
            previousDistance,
            liveDistance
        )
    end
    V55ColossalDirector.LastSolvedDistance = liveDistance
    V55ColossalDirector.LastAimDistance = liveDistance
    V55ColossalDirector.LastAimTOF = tonumber(tof) or 0

    local currentDirection = -muzzle.CFrame.LookVector

    local function yawOf(direction)
        return math.deg(math.atan2(direction.X, -direction.Z))
    end

    local currentYaw = yawOf(currentDirection)
    local desiredYaw = yawOf(desiredDirection)
    local deltaYaw = V55ColossalDirector.WrapDegrees(desiredYaw - currentYaw)
    local currentPitch = math.deg(math.asin(math.clamp(currentDirection.Y, -1, 1)))
    local desiredPitch = math.deg(math.asin(math.clamp(desiredDirection.Y, -1, 1)))
    local currentAngles = V55ColossalDirector.ReadAngles(cannon)

    local angles = {
        Base = math.clamp(
            (tonumber(currentAngles.Base) or 0)
            + deltaYaw
            + (tonumber(V55ColossalDirector.CalibrationYaw) or 0),
            -90,
            90
        ),
        BarrelWood = math.clamp(
            (tonumber(currentAngles.BarrelWood) or 0)
            + (desiredPitch - currentPitch)
            + (tonumber(V55ColossalDirector.CalibrationPitch) or 0),
            -40,
            40
        ),
    }

    V55ColossalDirector.LastAimYaw = angles.Base
    V55ColossalDirector.LastAimPitch = angles.BarrelWood
    V55ColossalDirector.LastArc = arcName .. " " .. string.format("%.1f° ballistic", ballisticPitch)
    return angles
end

function V55ColossalDirector.ReadBossHealthPercent(boss)
    boss = boss or select(1, V55ColossalDirector.FindBoss())
    if not boss then return nil end

    local humanoid = boss:FindFirstChildOfClass("Humanoid")
    if humanoid and tonumber(humanoid.MaxHealth) and humanoid.MaxHealth > 0 then
        local percent = math.clamp((humanoid.Health / humanoid.MaxHealth) * 100, 0, 100)
        V55ColossalDirector.LastBossHealthPercent = percent
        return percent
    end

    local health = tonumber(boss:GetAttribute("Health"))
        or tonumber(boss:GetAttribute("HP"))
    local maxHealth = tonumber(boss:GetAttribute("MaxHealth"))
        or tonumber(boss:GetAttribute("MaxHP"))
    if health and maxHealth and maxHealth > 0 then
        local percent = math.clamp((health / maxHealth) * 100, 0, 100)
        V55ColossalDirector.LastBossHealthPercent = percent
        return percent
    end

    return V55ColossalDirector.LastBossHealthPercent
end

function V55ColossalDirector.ApplyCalibrationPattern(index)
    local pattern = V55ColossalDirector.CalibrationPattern or {}
    if #pattern == 0 then return end

    index = ((tonumber(index) or 1) - 1) % #pattern + 1
    V55ColossalDirector.CalibrationIndex = index
    local entry = pattern[index]
    V55ColossalDirector.CalibrationPitch =
        (tonumber(V55ColossalDirector.BestCalibrationPitch) or 0)
        + (tonumber(entry.Pitch) or 0)
    V55ColossalDirector.CalibrationYaw =
        (tonumber(V55ColossalDirector.BestCalibrationYaw) or 0)
        + (tonumber(entry.Yaw) or 0)
end

function V55ColossalDirector.ExistingCannonProjectiles()
    local found = {}
    for _, object in ipairs(Workspace:GetChildren()) do
        if object:IsA("Model") then
            local playerTag = object:GetAttribute("Player")
            local skillTag = object:GetAttribute("Skill")
            if playerTag == player.Name and skillTag == "Cannon" then
                found[object] = true
            end
        end
    end
    return found
end

function V55ColossalDirector.UpdateProjectileFeedback()
    local pending = V55ColossalDirector.PendingShot
    if type(pending) ~= "table" then return end

    if not pending.Projectile or not pending.Projectile.Parent then
        for _, object in ipairs(Workspace:GetChildren()) do
            if object:IsA("Model")
                and object:GetAttribute("Player") == player.Name
                and object:GetAttribute("Skill") == "Cannon"
                and not (pending.ExistingProjectiles and pending.ExistingProjectiles[object]) then
                pending.Projectile = object
                break
            end
        end
    end

    local projectile = pending.Projectile
    if not projectile or not projectile.Parent then return end
    local projectilePart = projectile.PrimaryPart or projectile:FindFirstChildWhichIsA("BasePart", true)
    local boss = pending.Boss
    local targetPart = boss and boss.Parent and V55ColossalDirector.ResolveAimPart(boss) or nil
    if not projectilePart or not targetPart then return end

    local offset = projectilePart.Position - targetPart.Position
    local distance = offset.Magnitude
    if distance < (tonumber(pending.ClosestDistance) or math.huge) then
        pending.ClosestDistance = distance
        pending.ClosestOffset = offset
        pending.ClosestTargetPosition = targetPart.Position
        pending.ClosestProjectilePosition = projectilePart.Position
    end
end

function V55ColossalDirector.ApplyMissVectorCorrection(pending)
    local offset = pending and pending.ClosestOffset
    if typeof(offset) ~= "Vector3" then return false end
    local range = math.max(200, tonumber(pending.Distance) or 1000)

    -- Positive Y means the ball passed above the live body target: lower pitch.
    local verticalDegrees = math.deg(math.atan2(math.abs(offset.Y), range))
    verticalDegrees = math.clamp(verticalDegrees, 0.35, 6.0)
    local pitchStep = offset.Y > 0 and -verticalDegrees or verticalDegrees
    V55ColossalDirector.MissPitchBias = math.clamp(
        (tonumber(V55ColossalDirector.MissPitchBias) or 0) + pitchStep * 0.85,
        -12,
        12
    )

    local cannonPos = V55ColossalDirector.CannonPosition(V55ColossalDirector.Cannon)
    local targetPos = pending.ClosestTargetPosition
    if cannonPos and typeof(targetPos) == "Vector3" then
        local forward = Vector3.new(targetPos.X - cannonPos.X, 0, targetPos.Z - cannonPos.Z)
        if forward.Magnitude > 1 then
            forward = forward.Unit
            local right = Vector3.new(-forward.Z, 0, forward.X)
            local lateral = offset:Dot(right)
            local yawDegrees = math.deg(math.atan2(math.abs(lateral), range))
            yawDegrees = math.clamp(yawDegrees, 0, 4.0)
            local yawStep = lateral > 0 and -yawDegrees or yawDegrees
            V55ColossalDirector.MissYawBias = math.clamp(
                (tonumber(V55ColossalDirector.MissYawBias) or 0) + yawStep * 0.70,
                -8,
                8
            )
        end
    end

    V55ColossalDirector.CalibrationPitch = V55ColossalDirector.MissPitchBias
    V55ColossalDirector.CalibrationYaw = V55ColossalDirector.MissYawBias
    V55ColossalDirector.ProjectileFeedback = string.format(
        "miss vector Y %.0f | closest %.0f | bias P%.1f Y%.1f",
        offset.Y,
        tonumber(pending.ClosestDistance) or -1,
        tonumber(V55ColossalDirector.MissPitchBias) or 0,
        tonumber(V55ColossalDirector.MissYawBias) or 0
    )
    return true
end

function V55ColossalDirector.EvaluatePendingShot(force)
    V55ColossalDirector.UpdateProjectileFeedback()
    local pending = V55ColossalDirector.PendingShot
    if type(pending) ~= "table" then return true end

    local age = os.clock() - (tonumber(pending.At) or os.clock())
    local impactWait = math.clamp(tonumber(pending.ImpactWait) or 4.2, 1.0, 5.5)
    if not force and age < impactWait then return false end

    local after = V55ColossalDirector.ReadBossHealthPercent(pending.Boss)
    local before = tonumber(pending.Before)
    V55ColossalDirector.PendingShot = nil

    if after == nil or before == nil then
        V55ColossalDirector.Status = "Damage Mapper feedback unavailable — holding current aim"
        return true
    end

    local damage = math.max(0, before - after)
    local region = tostring(pending.AimRegion or V55ColossalDirector.CurrentAimRegion or "Unknown")
    local shotId = tonumber(pending.ShotId) or tonumber(V55ColossalDirector.Shots) or 0
    V55ColossalDirector.LastShotDamage = damage
    V55ColossalDirector.RecordRegionDamage(region, damage)

    -- V9.1: once the fixed-shot impact burst was actually delivered for this shot,
    -- do not feed a delayed/zero HUD sample into the legacy ballistic miss mapper.
    if Config.V6ColossalFixedShotEnabled == true
        and V6CannonImpactCore
        and tonumber(V6CannonImpactCore.LastBurstShotId) == shotId then
        V55ColossalDirector.MissStreak = 0
        V55ColossalDirector.ProvenRegionMisses = 0
        if damage >= 0.05 then
            print(string.format(
                "[SliceHub V9.1][CANNON-DAMAGE] Shot %d | FIXED IMPACT HIT | dealt %.2f%% | boss %.2f%% -> %.2f%%",
                shotId, damage, before, after
            ))
        else
            print(string.format(
                "[SliceHub V9.1][CANNON-IMPACT] Shot %d burst delivered; holding fixed 0/40 route despite delayed HP telemetry",
                shotId
            ))
        end
        V55ColossalDirector.Status = string.format(
            "V9.1 FIXED SHOT %d • impact delivered • %.2f%% observed",
            shotId,
            damage
        )
        return true
    end

    if damage >= 0.05 then
        -- V5.7.4 Nape-first experiment: once a real cannon shot aimed at the
        -- exact Nape produces measurable boss HP loss, keep that region instead
        -- of immediately rotating to torso geometry. Miss-vector correction still
        -- adjusts the trajectory if range changes and the nape shot later misses.
        if tostring(region) == "Nape" then
            V55ColossalDirector.BestAimRegion = "Nape"
            V55ColossalDirector.BestAimRegionDamage = math.max(
                tonumber(V55ColossalDirector.BestAimRegionDamage) or 0,
                damage
            )
            V55ColossalDirector.RegionMappingComplete = true
            V55ColossalDirector.CurrentAimRegion = "Nape"
        end

        V55ColossalDirector.HitStreak = (V55ColossalDirector.HitStreak or 0) + 1
        V55ColossalDirector.MissPitchBias = (tonumber(V55ColossalDirector.MissPitchBias) or 0) * 0.92
        V55ColossalDirector.MissYawBias = (tonumber(V55ColossalDirector.MissYawBias) or 0) * 0.92
        V55ColossalDirector.HitAngleSamples = V55ColossalDirector.HitAngleSamples or {}
        table.insert(V55ColossalDirector.HitAngleSamples, {
            Distance = tonumber(pending.Distance) or 0,
            Pitch = pending.Angles and tonumber(pending.Angles.BarrelWood) or nil,
            Base = pending.Angles and tonumber(pending.Angles.Base) or nil,
            Damage = damage,
        })
        while #V55ColossalDirector.HitAngleSamples > 12 do table.remove(V55ColossalDirector.HitAngleSamples, 1) end
        V55ColossalDirector.MissStreak = 0
        V55ColossalDirector.ProvenRegionMisses = 0

        if damage > (tonumber(V55ColossalDirector.BestShotDamage) or 0) then
            V55ColossalDirector.BestShotDamage = damage
            V55ColossalDirector.BestCalibrationPitch = tonumber(pending.CalibrationPitch) or 0
            V55ColossalDirector.BestCalibrationYaw = tonumber(pending.CalibrationYaw) or 0
        end

        if not V55ColossalDirector.RegionMappingComplete then
            V55ColossalDirector.AdvanceAimRegion()
        else
            -- Once mapping is done, stay on the best proven body region. A hit is
            -- valuable even if it is not 8%; do not sabotage working aim anymore.
            V55ColossalDirector.CurrentAimRegion = V55ColossalDirector.BestAimRegion or region
            V55ColossalDirector.CalibrationPitch = V55ColossalDirector.BestCalibrationPitch or 0
            V55ColossalDirector.CalibrationYaw = V55ColossalDirector.BestCalibrationYaw or 0
            V55ColossalDirector.CalibrationLocked = true
        end

        V55ColossalDirector.Status = string.format(
            "MAPPER HIT %.2f%% | %s | best %s %.2f%%",
            damage,
            region,
            tostring(V55ColossalDirector.BestAimRegion or region),
            tonumber(V55ColossalDirector.BestAimRegionDamage) or 0
        )
        print("[SliceHub V5.7.6][CANNON-TRACK]", V55ColossalDirector.Status)
        print(string.format(
            "[SliceHub V5.7.8][CANNON-DAMAGE] Shot %d | HIT | %s | dealt %.2f%% | boss %.2f%% -> %.2f%%",
            shotId,
            region,
            damage,
            before,
            after
        ))
        return true
    end

    V55ColossalDirector.HitStreak = 0
    V55ColossalDirector.MissStreak = (V55ColossalDirector.MissStreak or 0) + 1
    V55ColossalDirector.ApplyMissVectorCorrection(pending)

    if not V55ColossalDirector.RegionMappingComplete then
        -- A miss during the survey advances to the next stable region immediately.
        V55ColossalDirector.AdvanceAimRegion()
    else
        V55ColossalDirector.ProvenRegionMisses = (V55ColossalDirector.ProvenRegionMisses or 0) + 1
        if V55ColossalDirector.ProvenRegionMisses >= 2 then
            -- Only after two actual consecutive misses do we reopen the mapper.
            V55ColossalDirector.RegionMappingComplete = false
            V55ColossalDirector.AimRegionIndex = 1
            V55ColossalDirector.CurrentAimRegion = (V55ColossalDirector.AimRegions or {})[1] or "UpperTorso"
            V55ColossalDirector.ProvenRegionMisses = 0
            V55ColossalDirector.Status = "Best region missed twice — remapping impact regions"
        else
            V55ColossalDirector.Status = "Single miss on proven region — holding aim for confirmation"
        end
    end

    print("[SliceHub V5.7.6][CANNON-TRACK]", V55ColossalDirector.Status)
    print(string.format(
        "[SliceHub V5.7.8][CANNON-MISS] Shot %d | MISS | %s | dealt %.2f%% | closest %.0f | boss %.2f%% -> %.2f%%",
        shotId,
        region,
        damage,
        tonumber(pending.ClosestDistance) or -1,
        before,
        after
    ))
    return true
end

function V55ColossalDirector.EnsureMapReady()
    if V55ColossalDirector.MapReady then
        return os.clock() - (V55ColossalDirector.MapRestoreRequestedAt or 0) >= 0.35
    end

    local env = _G
    pcall(function()
        if type(getgenv) == "function" then env = getgenv() end
    end)

    local restore = env and env.SliceHubRestoreColossalMapProps
    if type(restore) ~= "function" then
        -- If map prop hiding is off, there is nothing to restore and cannon setup
        -- can continue. When hiding is on, wait for the performance bridge.
        return State.MapPropsHiddenEnabled ~= true
    end

    local ok = pcall(restore)
    if not ok then return false end

    V55ColossalDirector.MapReady = true
    V55ColossalDirector.MapRestoreRequestedAt = os.clock()
    V55ColossalDirector.Status = "Restored Colossal walls + cannon geometry"
    return false
end

function V55ColossalDirector.ReadErenHealthPercent(force)
    local textValue = V4RaidDirector.Lower(V55ColossalDirector.ObjectiveText(force))
    textValue = string.gsub(textValue, "%s+", " ")

    local percent = string.match(textValue, "defend eren%s*%[([%d%.]+)%%%]")
        or string.match(textValue, "protect eren%s*%[([%d%.]+)%%%]")

    percent = tonumber(percent)

    local previous = tonumber(V55ColossalDirector.LastErenHealthPercent)
    if percent ~= nil and previous ~= nil and percent < previous - 0.05 then
        V55ColossalDirector.ErenDamagedPulseUntil = os.clock() + 3.0
    end

    if percent ~= nil then
        V55ColossalDirector.LastErenHealthPercent = percent
    end

    V55ColossalDirector.ErenHealthPercent = percent
    return percent
end

function V55ColossalDirector.ResolveErenAnchor(force)
    local now = os.clock()
    if not force
        and typeof(V55ColossalDirector.ErenAnchor) == "Vector3"
        and now - (V55ColossalDirector.ErenAnchorAt or 0) < 6.0 then
        return V55ColossalDirector.ErenAnchor
    end

    V55ColossalDirector.ErenAnchorAt = now
    local titansFolder = Workspace:FindFirstChild(Config.TitansFolderName)
    local bestPosition = nil
    local bestScore = -math.huge
    local checked = 0

    for _, object in ipairs(Workspace:GetDescendants()) do
        checked += 1
        if checked > 18000 then break end

        if (object:IsA("Model") or object:IsA("BasePart"))
            and object ~= player.Character
            and not (player.Character and object:IsDescendantOf(player.Character))
            and not (titansFolder and object:IsDescendantOf(titansFolder)) then

            local lowerName = V4RaidDirector.Lower(object.Name)
            local score = 0

            if lowerName == "eren" then
                score += 10000
            elseif string.find(lowerName, "eren", 1, true) then
                score += 7000
            end

            if lowerName == "boulder" then
                score += 8500
            elseif string.find(lowerName, "boulder", 1, true) then
                score += 5000
            end

            pcall(function()
                local objectiveType = V4RaidDirector.Lower(
                    object:GetAttribute("Objective")
                    or object:GetAttribute("Type")
                    or object:GetAttribute("Role")
                    or ""
                )
                if string.find(objectiveType, "eren", 1, true)
                    or string.find(objectiveType, "defend", 1, true)
                    or string.find(objectiveType, "protect", 1, true) then
                    score += 2500
                end
            end)

            if score > 0 then
                local position = V4RaidDirector.GetObjectPosition(object)
                if position and score > bestScore then
                    bestScore = score
                    bestPosition = position
                end
            end
        end
    end

    if not bestPosition then
        local anchors = V4RaidDirector.RefreshObjectiveAnchors(force == true)
        if type(anchors) == "table" and #anchors > 0 then
            local cannonPos = V55ColossalDirector.CannonPosition(V55ColossalDirector.Cannon)
            local bestDistance = math.huge

            for _, position in ipairs(anchors) do
                if typeof(position) == "Vector3" then
                    local distance = cannonPos and (position - cannonPos).Magnitude or 0
                    if distance < bestDistance then
                        bestDistance = distance
                        bestPosition = position
                    end
                end
            end
        end
    end

    V55ColossalDirector.ErenAnchor = bestPosition
    return bestPosition
end

function V55ColossalDirector.CountObjectiveThreats(force)
    local now = os.clock()
    if not force and now - (V55ColossalDirector.LastThreatScanAt or 0) < 0.22 then
        return V55ColossalDirector.ThreatCount or 0
    end

    V55ColossalDirector.LastThreatScanAt = now
    local anchor = V55ColossalDirector.ResolveErenAnchor(force == true)
    local count = 0
    local critical = 0
    local titansFolder = Workspace:FindFirstChild(Config.TitansFolderName)
    local colossal = select(1, V55ColossalDirector.FindBoss())

    -- V5.7.6: P2 no longer treats every Titan in a huge 430-stud circle as an
    -- equal emergency. 360 studs is the watch zone; 175 studs is the critical
    -- zone that may interrupt boss DPS immediately.
    local isP2 = V55ColossalDirector.Stage == "P2 BOSS"
    local oddballProfile = V55ColossalDirector.IsOddballProfile()
    local glassProfile = V55ColossalDirector.IsGlassCannonProfile()

    local radius = 340
    local criticalRadius = 150
    if isP2 then
        if oddballProfile then
            radius = 300
            criticalRadius = 150
        elseif glassProfile then
            radius = 325
            criticalRadius = 165
        else
            radius = 360
            criticalRadius = 175
        end
    elseif oddballProfile then
        radius = 310
        criticalRadius = 140
    end
    local radiusSquared = radius * radius
    local criticalSquared = criticalRadius * criticalRadius

    if titansFolder and typeof(anchor) == "Vector3" then
        for _, titan in ipairs(titansFolder:GetChildren()) do
            if titan ~= colossal
                and isTitanAlive(titan)
                and not V4RaidDirector.IsBossTitan(titan) then

                local part = getTitanTargetPart(titan)
                if part then
                    local delta = part.Position - anchor
                    local distanceSquared = delta:Dot(delta)
                    if distanceSquared <= radiusSquared then
                        count += 1
                        if distanceSquared <= criticalSquared then
                            critical += 1
                        end
                    end
                end
            end
        end
    elseif titansFolder then
        -- Fail safe: if the protected Eren anchor has not replicated yet, use the
        -- raid director's objective-near check rather than pretending there are no threats.
        for _, titan in ipairs(titansFolder:GetChildren()) do
            if titan ~= colossal
                and isTitanAlive(titan)
                and not V4RaidDirector.IsBossTitan(titan)
                and V4RaidDirector.IsTitanNearObjective(titan) then
                count += 1
            end
        end
        critical = math.min(count, 1)
    end

    V55ColossalDirector.ReadErenHealthPercent(force == true)
    V55ColossalDirector.ThreatCount = count
    V55ColossalDirector.CriticalThreatCount = critical
    return count
end

function V55ColossalDirector.UpdateDefenseMode()
    local now = os.clock()
    local threats = V55ColossalDirector.CountObjectiveThreats(false)
    local critical = tonumber(V55ColossalDirector.CriticalThreatCount) or 0
    local erenHealth = tonumber(V55ColossalDirector.ErenHealthPercent)
    local erenDamaged = now < (tonumber(V55ColossalDirector.ErenDamagedPulseUntil) or 0)
    local isP2 = V55ColossalDirector.Stage == "P2 BOSS"
    local oddballProfile = V55ColossalDirector.IsOddballProfile()
    local glassProfile = V55ColossalDirector.IsGlassCannonProfile()

    local function leaveDefense(status, focusWindow)
        V55ColossalDirector.DefenseMode = false
        V55ColossalDirector.DefenseLastEndedAt = now
        V55ColossalDirector.P2BossFocusUntil = isP2
            and (now + math.max(0, tonumber(focusWindow) or 0))
            or 0

        if not isP2 and V55ColossalDirector.BladeGuardianAirborne == true then
            V55ColossalDirector.BladeGuardianAirborne = false
            V55ColossalDirector.BladeGuardNeedsRemount = true
            V55ColossalDirector.CannonHandshakeStatus = "guard budget complete • remount due"
        end

        V55ColossalDirector.Status = status
        if clearCurrentTarget then clearCurrentTarget(false) end
        cachedTitanCandidatesAt = 0
    end

    if V55ColossalDirector.DefenseMode then
        local elapsed = now - (V55ColossalDirector.DefenseStartedAt or now)

        if isP2 then
            local hardDanger = erenDamaged
                or ((erenHealth or 100) <= (glassProfile and 93 or 90))
                or critical >= (glassProfile and 1 or 2)

            local safeAgain = critical <= 0 and not erenDamaged
            local burstLimit
            local focusWindow

            if oddballProfile then
                burstLimit = hardDanger and 1.85 or 0.90
                focusWindow = hardDanger and 0.75 or 1.55
            elseif glassProfile then
                -- Glass Cannon never blade-dives; Guardian is Spear-only, so a slightly
                -- longer remote burst is still safe while keeping Bertholdt pressure high.
                burstLimit = hardDanger and 2.35 or 1.15
                focusWindow = hardDanger and 0.70 or 1.35
            else
                burstLimit = hardDanger and 2.80 or 1.35
                focusWindow = ((erenHealth or 100) <= 90) and 0.45 or 1.10
            end

            if elapsed >= 0.40 and safeAgain then
                leaveDefense("P2 GUARDIAN clear — boss focus", focusWindow)
            elseif elapsed >= burstLimit and not erenDamaged then
                leaveDefense("P2 GUARDIAN burst complete — boss focus", focusWindow)
            else
                V55ColossalDirector.Status = "P2 GUARDIAN [" .. tostring(V55ColossalDirector.ModifierProfile or "STANDARD") .. "] | threats "
                    .. tostring(threats)
                    .. " | critical " .. tostring(critical)
                    .. (erenHealth and (" | HP " .. string.format("%.1f%%", erenHealth)) or "")
            end
            return
        end

        -- V9.4.4 Blade-only P1 defense is bank/time-budgeted. Respawning waves are
        -- allowed to remain after the burst; cannon progression resumes instead of
        -- waiting forever for the whole Eren radius to become empty. Spear behavior
        -- is intentionally left on the proven V9.4.3 path.
        if V55ColossalDirector.DismountPending == true then
            V55ColossalDirector.Status = "P1 BLADE GUARDIAN • "
                .. tostring(V55ColossalDirector.CannonHandshakeStatus or "waiting detach")
            return
        end

        if V55ColossalDirector.BladeGuardianAirborne == true then
            local guardElapsed = now - (tonumber(V55ColossalDirector.BladeGuardianStartedAt) or now)
            local slashStart = tonumber(V55ColossalDirector.BladeGuardianStartSlashCount) or 0
            local slashNow = V6ExactBlade and tonumber(V6ExactBlade.TotalSlashes) or slashStart
            local banksUsed = math.max(0, slashNow - slashStart)
            local bankBudget = math.max(1, tonumber(V55ColossalDirector.BladeGuardianBankBudget) or 1)
            local timeBudget = math.max(0.35, tonumber(V55ColossalDirector.BladeGuardianTimeBudget) or 1.10)
            local emergencyDeadline = tonumber(V55ColossalDirector.BladeGuardianEmergencyDeadline)
                or (now + math.max(timeBudget, tonumber(Config.V944BladeGuardianEmergencySeconds) or 2.35))

            local banksDone = banksUsed >= bankBudget
            local normalTimeDone = guardElapsed >= timeBudget
            local emergencyExpired = now >= emergencyDeadline

            if emergencyExpired then
                leaveDefense("Blade Guardian emergency cap reached — remounting same cannon", 0)
            elseif (banksDone or normalTimeDone) and not erenDamaged then
                leaveDefense("Blade Guardian burst complete — remounting same cannon", 0)
            else
                V55ColossalDirector.Status = string.format(
                    "P1 BLADE GUARDIAN AIRBORNE | banks %d/%d | %.1f/%.1fs | threats %d | critical %d%s",
                    banksUsed,
                    bankBudget,
                    guardElapsed,
                    timeBudget,
                    tonumber(threats) or 0,
                    tonumber(critical) or 0,
                    erenHealth and (" | HP " .. string.format("%.1f%%", erenHealth)) or ""
                )
            end
            return
        end

        local safeAgain = threats <= V55ColossalDirector.DefenseExitThreats and not erenDamaged
        if elapsed >= V55ColossalDirector.DefenseMinSeconds and safeAgain then
            leaveDefense("Eren clear — returning to same cannon", 0)
        elseif elapsed >= V55ColossalDirector.DefenseMaxSeconds and safeAgain then
            leaveDefense("Defense burst complete — returning to same cannon", 0)
        else
            V55ColossalDirector.Status = "DEFEND EREN [" .. tostring(V55ColossalDirector.ModifierProfile or "STANDARD") .. "] | threats "
                .. tostring(threats)
                .. (erenHealth and (" | HP " .. string.format("%.1f%%", erenHealth)) or "")
        end
        return
    end

    local shouldEnter = false
    if isP2 then
        local bossFocusLocked = now < (tonumber(V55ColossalDirector.P2BossFocusUntil) or 0)
        local lowHealthThreshold = glassProfile and 97 or (oddballProfile and 92 or 95)
        local normalWaveThreshold = oddballProfile and 5 or (glassProfile and 4 or 3)
        local lowHealthPressure = (erenHealth or 100) <= lowHealthThreshold and threats >= 1
        local normalWavePressure = threats >= normalWaveThreshold
        local immediatePressure = critical >= 1

        shouldEnter = erenDamaged
            or lowHealthPressure
            or normalWavePressure
            or immediatePressure

        if bossFocusLocked
            and not erenDamaged
            and (erenHealth or 100) > (glassProfile and 94 or 90)
            and critical < (glassProfile and 1 or 2) then
            shouldEnter = false
        end
    else
        if oddballProfile then
            -- Oddball P1 cannot afford long cannon downtime. Only real danger breaks
            -- cannon ownership; distant packs are handled while the cannon keeps working.
            shouldEnter = erenDamaged or critical >= 1 or threats >= 3
        else
            shouldEnter = threats >= V55ColossalDirector.DefenseEnterThreats or erenDamaged
        end
    end

    if shouldEnter then
        V55ColossalDirector.DefenseMode = true
        V55ColossalDirector.DefenseStartedAt = now
        V55ColossalDirector.Status = erenDamaged
            and (isP2
                and "P2 GUARDIAN — Eren HP dropped; emergency burst"
                or "Eren HP dropped — mounted Infinite Spear defense")
            or (isP2
                and ("P2 GUARDIAN — intercept burst | critical " .. tostring(critical))
                or "Threat near Eren — mounted Infinite Spear defense")

        if clearCurrentTarget then clearCurrentTarget(false) end
        cachedTitanCandidatesAt = 0
    end
end

function V55ColossalDirector.RestoreControl()
    pcall(function()
        local liveCharacter = player.Character
        local liveRoot = liveCharacter and liveCharacter:FindFirstChild("HumanoidRootPart")
        local liveHumanoid = liveCharacter and liveCharacter:FindFirstChildOfClass("Humanoid")
        if liveRoot then
            liveRoot.Anchored = false
            liveRoot.AssemblyLinearVelocity = Vector3.zero
            liveRoot.AssemblyAngularVelocity = Vector3.zero
        end
        if liveHumanoid then
            liveHumanoid.PlatformStand = false
            liveHumanoid.AutoRotate = true
            liveHumanoid:ChangeState(Enum.HumanoidStateType.Running)
        end
        local camera = Workspace.CurrentCamera
        if camera and liveHumanoid then
            camera.CameraType = Enum.CameraType.Custom
            camera.CameraSubject = liveHumanoid
        end
    end)
end

function V55ColossalDirector.HazardBelongsToBoss(object)
    if not object or not object.Parent then return false end
    local boss, bossPart = V55ColossalDirector.FindBoss()
    if not boss or not bossPart then return false end
    if object == boss or object:IsDescendantOf(boss) then return true end

    local node = object
    local part = nil
    for _ = 1, 7 do
        if not node then break end
        if node:IsA("BasePart") then
            part = node
            break
        end
        node = node.Parent
    end
    if part and (part.Position - bossPart.Position).Magnitude <= 380 then
        return true
    end

    local lowerPath = string.lower(tostring(object:GetFullName()))
    if string.find(lowerPath, "workspace.debris", 1, true) then
        local pivotPosition = nil
        local owner = object:FindFirstAncestorOfClass("Model")
        if owner then
            local ok, pivot = pcall(function() return owner:GetPivot() end)
            if ok and pivot then pivotPosition = pivot.Position end
        end
        if typeof(pivotPosition) == "Vector3" and (pivotPosition - bossPart.Position).Magnitude <= 500 then
            return true
        end
    end
    return false
end

function V55ColossalDirector.MarkHazard(signal, duration)
    if V4RaidDirector.RaidName ~= "Colossal Raid" or V55ColossalDirector.Stage ~= "P2 BOSS" then return end
    local now = os.clock()
    signal = tostring(signal or "Colossal hazard")
    V55ColossalDirector.HazardDebounce = V55ColossalDirector.HazardDebounce or {}
    local last = tonumber(V55ColossalDirector.HazardDebounce[signal]) or 0
    if now - last < 0.45 then
        return
    end
    V55ColossalDirector.HazardDebounce[signal] = now
    V55ColossalDirector.LastHazardSignal = signal
    V55ColossalDirector.LastHazardSignalAt = now
    V55ColossalDirector.EvadeUntil = math.max(V55ColossalDirector.EvadeUntil or 0, now + math.max(0.8, tonumber(duration) or 1.8))
end

function V55ColossalDirector.ScanBossHazard()
    if V55ColossalDirector.Stage ~= "P2 BOSS" then return false end
    local now = os.clock()
    if now - (V55ColossalDirector.LastHazardScanAt or 0) < 0.10 then
        return now < (V55ColossalDirector.EvadeUntil or 0)
    end
    V55ColossalDirector.LastHazardScanAt = now

    local boss = select(1, V55ColossalDirector.FindBoss())
    local humanoid = boss and boss:FindFirstChildOfClass("Humanoid") or nil
    if humanoid then
        for _, track in ipairs(humanoid:GetPlayingAnimationTracks()) do
            local text = string.lower(tostring(track.Name or "") .. " " .. tostring(track.Animation and track.Animation.AnimationId or ""))
            local signal = nil
            local duration = 1.8
            if string.find(text, "heat", 1, true) or string.find(text, "wave", 1, true) then
                signal, duration = "HEATWAVE animation", 2.4
            elseif string.find(text, "stomp", 1, true) or string.find(text, "slam", 1, true) or string.find(text, "ground", 1, true) then
                signal, duration = "STOMP animation", 1.8
            elseif string.find(text, "roar", 1, true) then
                signal, duration = "ROAR animation", 1.5
            end
            if signal then
                local animationKey = text
                if animationKey ~= V55ColossalDirector.LastHazardAnimation or now - (V55ColossalDirector.LastHazardSignalAt or 0) > 1.2 then
                    V55ColossalDirector.LastHazardAnimation = animationKey
                    V55ColossalDirector.MarkHazard(signal, duration)
                    print("[SliceHub V5.7.7][EVADE]", signal, animationKey)
                end
            end
        end
    end
    return now < (V55ColossalDirector.EvadeUntil or 0)
end

function V55ColossalDirector.PerformEvade()
    if not character or not character.Parent or not rootPart or not humanoid or humanoid.Health <= 0 then return false end
    local now = os.clock()
    if now - (V55ColossalDirector.LastEvadeAt or 0) < 0.75 then return false end

    local boss, bossPart = V55ColossalDirector.FindBoss()
    if not boss or not bossPart then return false end
    local away = rootPart.Position - bossPart.Position
    away = Vector3.new(away.X, 0, away.Z)
    if away.Magnitude < 20 then away = Vector3.new(1, 0, 0) end

    local glass = V55ColossalDirector.IsGlassCannonProfile and V55ColossalDirector.IsGlassCannonProfile()
    local lateral = glass and 850 or 680
    local altitude = glass and 1180 or 980
    local safe = bossPart.Position + away.Unit * lateral + Vector3.new(0, altitude, 0)

    character:PivotTo(CFrame.lookAt(safe, bossPart.Position))
    rootPart.AssemblyLinearVelocity = Vector3.zero
    rootPart.AssemblyAngularVelocity = Vector3.zero
    CombatAnchorRuntime.Position = safe
    CombatAnchorRuntime.GroundCenter = bossPart.Position
    CombatAnchorRuntime.AimPosition = bossPart.Position
    CombatAnchorRuntime.LastRefresh = now
    CombatAnchorRuntime.LastCommit = now
    V55ColossalDirector.LastEvadeAt = now
    return true
end

function V55ColossalDirector.UpdateEvadeMode()
    if V55ColossalDirector.Stage ~= "P2 BOSS" then
        V55ColossalDirector.EvadeMode = false
        return false
    end
    V55ColossalDirector.ScanBossHazard()
    local active = os.clock() < (V55ColossalDirector.EvadeUntil or 0)
    V55ColossalDirector.EvadeMode = active
    if active then
        V55ColossalDirector.PerformEvade()
        V55ColossalDirector.Status = "EVADE • " .. tostring(V55ColossalDirector.LastHazardSignal or "Colossal hazard")
    end
    return active
end

-- Effect/sound names are useful even when animation tracks are obfuscated.
-- V5.7.8 scopes signals to the actual Colossal or nearby boss debris.
Workspace.DescendantAdded:Connect(function(object)
    if not V4RaidDirector or V4RaidDirector.RaidName ~= "Colossal Raid"
        or not V55ColossalDirector or V55ColossalDirector.Stage ~= "P2 BOSS" then return end
    local lower = string.lower(tostring(object.Name or ""))
    local signal, duration = nil, nil
    if string.find(lower, "heatwave", 1, true) or (string.find(lower, "heat", 1, true) and string.find(lower, "wave", 1, true)) then
        signal, duration = "HEATWAVE effect", 2.8
    elseif string.find(lower, "stomp", 1, true) or string.find(lower, "groundslam", 1, true) or string.find(lower, "shockwave", 1, true) then
        signal, duration = "STOMP effect", 2.2
    end
    if signal and V55ColossalDirector.HazardBelongsToBoss(object) then
        local before = tonumber(V55ColossalDirector.LastHazardSignalAt) or 0
        V55ColossalDirector.MarkHazard(signal, duration)
        if (tonumber(V55ColossalDirector.LastHazardSignalAt) or 0) > before then
            print("[SliceHub V5.7.8][EVADE-SIGNAL]", signal, object:GetFullName())
        end
    end
end)

function V55ColossalDirector.MoveToP2SafetyLane(reason)
    if not character or not character.Parent or not rootPart or not humanoid or humanoid.Health <= 0 then return false end
    local boss, bossPart = V55ColossalDirector.FindBoss()
    if not boss or not bossPart then return false end

    local glass = V55ColossalDirector.IsGlassCannonProfile and V55ColossalDirector.IsGlassCannonProfile()
    local oddball = V55ColossalDirector.IsOddballProfile and V55ColossalDirector.IsOddballProfile()
    local serial = tonumber(V55ColossalDirector.P2SafetySerial) or 0
    local angle = math.rad((serial * 71) % 360)
    local radius = glass and 1080 or (oddball and 760 or 900)
    local altitude = glass and 1320 or (oddball and 980 or 1120)
    local orbit = Vector3.new(math.cos(angle) * radius, altitude, math.sin(angle) * radius)
    local safe = bossPart.Position + orbit

    character:PivotTo(CFrame.lookAt(safe, bossPart.Position))
    rootPart.AssemblyLinearVelocity = Vector3.zero
    rootPart.AssemblyAngularVelocity = Vector3.zero
    CombatAnchorRuntime.Position = safe
    CombatAnchorRuntime.GroundCenter = bossPart.Position
    CombatAnchorRuntime.AimPosition = bossPart.Position
    CombatAnchorRuntime.LastRefresh = os.clock()
    CombatAnchorRuntime.LastCommit = os.clock()
    V55ColossalDirector.P2SafetySerial = serial + 1
    V55ColossalDirector.LastP2SafetyAt = os.clock()
    V55ColossalDirector.Status = "P2 TRANSITION SHIELD • " .. tostring(reason or "safe orbit")
    return true
end

function V55ColossalDirector.UpdateStage()
    local stage = V55ColossalDirector.ComputeStage(false)
    local previous = V55ColossalDirector.Stage

    if stage ~= previous then
        V55ColossalDirector.PreviousStage = previous
        V55ColossalDirector.Stage = stage

        if previous == "P1 CANNON STALL" and stage == "P2 BOSS" then
            V55ColossalDirector.TransitionActive = true
            V55ColossalDirector.TransitionStartedAt = os.clock()
            local glass = V55ColossalDirector.IsGlassCannonProfile and V55ColossalDirector.IsGlassCannonProfile()
            V55ColossalDirector.P2SafetyUntil = os.clock() + (glass and 6.0 or 3.8)
            V55ColossalDirector.ExitCannon("P1 complete — exiting cannon")
            task.defer(function()
                task.wait(0.05)
                pcall(V55ColossalDirector.MoveToP2SafetyLane, "phase handoff")
            end)
            pcall(function() if clearCurrentTarget then clearCurrentTarget(false) end end)
            pcall(function() if V35Spears and V35Spears.ClearDrainPack then V35Spears.ClearDrainPack("Colossal P2 transition") end end)
            pcall(function() if V4BlasterNapeLock and V4BlasterNapeLock.Stop then V4BlasterNapeLock.Stop() end end)
            cachedTitanCandidatesAt = 0
        end
    end

    if V55ColossalDirector.TransitionActive then
        local boss = select(1, V55ColossalDirector.FindBoss())
        local camera = Workspace.CurrentCamera
        local cameraReady = not camera or camera.CameraType ~= Enum.CameraType.Scriptable
        local elapsed = os.clock() - (V55ColossalDirector.TransitionStartedAt or os.clock())

        if boss and isTitanAlive(boss) and cameraReady and elapsed >= 0.5 then
            V55ColossalDirector.TransitionActive = false
            V55ColossalDirector.P2SafetyUntil = math.max(V55ColossalDirector.P2SafetyUntil or 0, os.clock() + 2.8)
            V55ColossalDirector.Status = "P2 ready — transition shield active"
            V55ColossalDirector.RestoreControl()
            pcall(V55ColossalDirector.MoveToP2SafetyLane, "camera released")
        elseif boss and isTitanAlive(boss) and elapsed >= 8 then
            V55ColossalDirector.TransitionActive = false
            V55ColossalDirector.Status = "P2 watchdog recovery"
            V55ColossalDirector.RestoreControl()
        else
            V55ColossalDirector.Status = "Colossal phase transition"
        end
    end

    return V55ColossalDirector.Stage
end

function V55ColossalDirector.ShouldOwnCombat()
    if V4RaidDirector.RaidName ~= "Colossal Raid" then return false end
    if V55ColossalDirector.TransitionActive then return true end
    local bladeGuardianOpen = V941ObjectiveGuardian
        and V941ObjectiveGuardian.ColossalMountedActive
        and V941ObjectiveGuardian.ColossalMountedActive() == true
    return V55ColossalDirector.Stage == "P1 CANNON STALL"
        and not V55ColossalDirector.DefenseMode
        and not bladeGuardianOpen
end

function V55ColossalDirector.TryOddballRapidShot()
    if not V55ColossalDirector.IsOddballProfile() then return false end
    if V55ColossalDirector.Stage ~= "P1 CANNON STALL" then return false end
    if not V55ColossalDirector.Entered then return false end

    local cannon = V55ColossalDirector.Cannon
    if not V55ColossalDirector.CannonValid(cannon) then return false end
    if cannon:GetAttribute("Firing") == true then return false end
    if tonumber(cannon:GetAttribute("Cooldown")) == nil then return false end

    local angles = V55ColossalDirector.Angles
    if type(angles) ~= "table" then return false end
    if tonumber(angles.Base) == nil or tonumber(angles.BarrelWood) == nil then return false end

    local now = os.clock()
    local pending = V55ColossalDirector.PendingShot

    if not V55ColossalDirector.RapidProbeDone then
        local age = type(pending) == "table" and (now - (tonumber(pending.At) or now)) or 0
        if age < 0.18 then return false end

        V55ColossalDirector.RapidProbeDone = true
        V55ColossalDirector.RapidProbeStatus = "probing"
        local ok, result, err = V55ColossalDirector.Invoke("Shoot", angles)
        if ok and result == true then
            V55ColossalDirector.RapidCannonAccepted = true
            V55ColossalDirector.RapidLastShotAt = now
            V55ColossalDirector.LastShotAt = now
            V55ColossalDirector.RapidShots = (V55ColossalDirector.RapidShots or 0) + 1
            V55ColossalDirector.Shots = (V55ColossalDirector.Shots or 0) + 1
            V55ColossalDirector.RapidProbeStatus = "ACCEPTED"
            V55ColossalDirector.Status = "ODDBALL RAPID CANNON ACCEPTED — cadence unlocked"
        else
            V55ColossalDirector.RapidCannonAccepted = false
            V55ColossalDirector.RapidProbeStatus = "rejected: " .. tostring(err or result)
            V55ColossalDirector.Status = "Oddball rapid cannon probe rejected — normal cooldown retained"
        end
        print("[SliceHub V5.7.6][ODDBALL-CANNON]", V55ColossalDirector.RapidProbeStatus)
        return true
    end

    if not V55ColossalDirector.RapidCannonAccepted then return false end
    if now - (tonumber(V55ColossalDirector.RapidLastShotAt) or 0) < 0.22 then return false end

    local ok, result, err = V55ColossalDirector.Invoke("Shoot", angles)
    V55ColossalDirector.RapidLastShotAt = now

    if ok and result == true then
        V55ColossalDirector.RapidRejects = 0
        V55ColossalDirector.LastShotAt = now
        V55ColossalDirector.RapidShots = (V55ColossalDirector.RapidShots or 0) + 1
        V55ColossalDirector.Shots = (V55ColossalDirector.Shots or 0) + 1
        V55ColossalDirector.Status = "ODDBALL RAPID CANNON | extra shots " .. tostring(V55ColossalDirector.RapidShots)
    else
        V55ColossalDirector.RapidRejects = (V55ColossalDirector.RapidRejects or 0) + 1
        if V55ColossalDirector.RapidRejects >= 3 then
            V55ColossalDirector.RapidCannonAccepted = false
            V55ColossalDirector.Status = "Oddball rapid cadence disabled after repeated rejection"
        else
            V55ColossalDirector.Status = "Oddball rapid shot rejected " .. tostring(V55ColossalDirector.RapidRejects) .. "/3"
        end
    end

    return true
end

function V55ColossalDirector.FireOneShot()
    local cannon = V55ColossalDirector.Cannon
    if not V55ColossalDirector.CannonValid(cannon) then return false end

    -- V5.7.6 Oddball experiment: one controlled cooldown-window probe. Rapid
    -- cadence is only enabled after the server explicitly accepts that probe.
    if V55ColossalDirector.TryOddballRapidShot() then
        return true
    end

    -- Feedback from the previous shot is evaluated before the next shot is planned.
    -- The cannon cooldown naturally gives the projectile enough time to reach P1 Colossal.
    if not V55ColossalDirector.EvaluatePendingShot(false) then
        V55ColossalDirector.Status = "Waiting for cannon impact feedback"
        return false
    end
    if cannon:GetAttribute("Firing") == true then
        V55ColossalDirector.Status = "Same cannon firing"
        return false
    end

    local cooldown = tonumber(cannon:GetAttribute("Cooldown"))
    local readyEpsilon = math.max(0, tonumber(Config.V943CannonReadyEpsilon) or 0.05)
    if cooldown ~= nil and cooldown > readyEpsilon then
        V55ColossalDirector.Status = string.format("Same cannon cooldown %.1fs", cooldown)
        return false
    end
    -- Lua treats 0 as truthy. The old `if cooldown then` path therefore parked
    -- forever at Cooldown=0 after the first accepted shot on servers that retain
    -- the numeric attribute instead of clearing it to nil. Zero/negative is ready.

    local boss = select(1, V55ColossalDirector.FindBoss())
    local targetPart = V55ColossalDirector.ResolveAimPart(boss)
    if not boss or not targetPart then
        V55ColossalDirector.Status = "Waiting for Colossal target"
        return false
    end

    local angles, reason
    if Config.V6ColossalFixedShotEnabled == true then
        angles = {
            Base = tonumber(Config.V6ColossalFixedBase) or 0,
            BarrelWood = tonumber(Config.V6ColossalFixedBarrelWood) or 40,
        }
        V55ColossalDirector.LastAimYaw = angles.Base
        V55ColossalDirector.LastAimPitch = angles.BarrelWood
        V55ColossalDirector.LastArc = "V6 fixed 0/40"
        V55ColossalDirector.LastAimDistance = (targetPart.Position - (V55ColossalDirector.CannonPosition(cannon) or targetPart.Position)).Magnitude
        V55ColossalDirector.LastAimTOF = 0.80
    else
        angles, reason = V55ColossalDirector.SolveAngles(cannon, targetPart)
        if not angles then
            V55ColossalDirector.Status = "Aim failed: " .. tostring(reason)
            return false
        end
    end

    local beforeHealth = V55ColossalDirector.ReadBossHealthPercent(boss)
    local ok, result, err = V55ColossalDirector.Invoke("Shoot", angles)
    if ok and result == true then
        V55ColossalDirector.Angles = angles
        V55ColossalDirector.Shots += 1
        V55ColossalDirector.LastShotAt = os.clock()
        V55ColossalDirector.LastTargetName = tostring(boss.Name)
        V55ColossalDirector.PendingShot = {
            At = os.clock(),
            Before = beforeHealth,
            ExistingProjectiles = V55ColossalDirector.ExistingCannonProjectiles(),
            Boss = boss,
            CalibrationPitch = tonumber(V55ColossalDirector.CalibrationPitch) or 0,
            CalibrationYaw = tonumber(V55ColossalDirector.CalibrationYaw) or 0,
            AimRegion = tostring(V55ColossalDirector.RegionMappingComplete and V55ColossalDirector.BestAimRegion or V55ColossalDirector.CurrentAimRegion or targetPart.Name),
            Angles = {Base = angles.Base, BarrelWood = angles.BarrelWood},
            Distance = tonumber(V55ColossalDirector.LastAimDistance) or 0,
            ImpactWait = math.clamp(0.7666666666666667 + (tonumber(V55ColossalDirector.LastAimTOF) or 0) + 0.55, 1.2, 5.5),
            ShotId = V55ColossalDirector.Shots,
        }
        V55ColossalDirector.Status = string.format(
            "Shot %d | %s | %s | pitch %.1f° | range %.0f | lead %.1fs",
            V55ColossalDirector.Shots,
            V55ColossalDirector.LastArc,
            Config.V6ColossalFixedShotEnabled == true and "Impact Burst Nape" or tostring(V55ColossalDirector.RegionMappingComplete and V55ColossalDirector.BestAimRegion or V55ColossalDirector.CurrentAimRegion or targetPart.Name),
            V55ColossalDirector.LastAimPitch,
            tonumber(V55ColossalDirector.LastAimDistance) or 0,
            tonumber(V55ColossalDirector.LastAimTOF) or 0
        )
        print("[SliceHub V6][COLOSSAL]", V55ColossalDirector.Status)

        local acceptedShotId = V55ColossalDirector.Shots
        if Config.V91CannonShotFallbackEnabled == true
            and Config.V6ColossalImpactBurstEnabled == true then
            task.delay(math.max(0.35, tonumber(Config.V91CannonShotFallbackDelay) or 1.12), function()
                pcall(function()
                    if V4RaidDirector.RaidName ~= "Colossal Raid"
                        or V55ColossalDirector.Stage ~= "P1 CANNON STALL"
                        or not V55ColossalDirector.Entered then
                        return
                    end
                    if tonumber(V6CannonImpactCore.LastBurstShotId) == acceptedShotId then
                        return
                    end
                    local projectile = Workspace:FindFirstChild("Cannon")
                    if projectile and projectile.Parent then
                        print("[SliceHub V9.1][CANNON-FALLBACK] impact event missed; forcing burst for shot", acceptedShotId)
                        V6CannonImpactCore.FireBurst(projectile, acceptedShotId)
                    end
                end)
            end)
        end
        return true
    end

    V55ColossalDirector.Status = "Cannon Shoot rejected: " .. tostring(err or result)
    return false
end

function V55ColossalDirector.Step()
    if V4RaidDirector.RaidName ~= "Colossal Raid" then
        if V55ColossalDirector.Entered then V55ColossalDirector.ExitCannon("Raid changed") end
        V55ColossalDirector.Stage = "IDLE"
        V55ColossalDirector.PreviousStage = "IDLE"
        V55ColossalDirector.TransitionActive = false
        V55ColossalDirector.DefenseMode = false
        V55ColossalDirector.DismountPending = false
        V55ColossalDirector.DismountRequestedAt = 0
        V55ColossalDirector.LastDismountRequestAt = 0
        V55ColossalDirector.BladeGuardianAirborne = false
        V55ColossalDirector.BladeGuardianStartedAt = 0
        V55ColossalDirector.BladeGuardNeedsRemount = false
        V55ColossalDirector.RemountPending = false
        V55ColossalDirector.RemountRequestedAt = 0
        V55ColossalDirector.LastRemountRequestAt = 0
        V55ColossalDirector.CannonHandshakeStatus = "idle"
        V55ColossalDirector.P2Confirmed = false
        V55ColossalDirector.ErenAnchor = nil
        V55ColossalDirector.ErenHealthPercent = nil
        V55ColossalDirector.LastErenHealthPercent = nil
        V55ColossalDirector.ErenDamagedPulseUntil = 0
        V55ColossalDirector.MapReady = false
        V55ColossalDirector.PendingShot = nil
        V55ColossalDirector.CalibrationPitch = 0
        V55ColossalDirector.CalibrationYaw = 0
        V55ColossalDirector.BestCalibrationPitch = 0
        V55ColossalDirector.BestCalibrationYaw = 0
        V55ColossalDirector.BestShotDamage = 0
        V55ColossalDirector.CalibrationIndex = 1
        V55ColossalDirector.CalibrationLocked = false
        V55ColossalDirector.MissStreak = 0
        V55ColossalDirector.HitStreak = 0
        V55ColossalDirector.AimRegionIndex = 1
        V55ColossalDirector.CurrentAimRegion = (V55ColossalDirector.AimRegions or {})[1] or "UpperTorso"
        V55ColossalDirector.BestAimRegion = nil
        V55ColossalDirector.BestAimRegionDamage = 0
        V55ColossalDirector.RegionResults = {}
        V55ColossalDirector.RegionMappingComplete = false
        V55ColossalDirector.ProvenRegionMisses = 0
        V55ColossalDirector.LastMotionPosition = nil
        V55ColossalDirector.LastMotionAt = 0
        V55ColossalDirector.SmoothedBossVelocity = Vector3.zero
        V55ColossalDirector.LastSolvedDistance = nil
        V55ColossalDirector.LastAimTOF = 0
        V55ColossalDirector.LastAimDistance = 0
        V55ColossalDirector.LastMountedBuffAt = 0
        V55ColossalDirector.PreMountBuffDone = false
        V55ColossalDirector.PreMountBuffFinishedAt = 0
        V55ColossalDirector.PreMountBuffSummary = "Not applied"
        V55ColossalDirector.ProjectileFeedback = "none"
        V55ColossalDirector.MissPitchBias = 0
        V55ColossalDirector.MissYawBias = 0
        V55ColossalDirector.HitAngleSamples = {}
        V55ColossalDirector.ModifierProfile = "STANDARD"
        V55ColossalDirector.RapidProbeDone = false
        V55ColossalDirector.RapidCannonAccepted = false
        V55ColossalDirector.RapidLastShotAt = 0
        V55ColossalDirector.RapidRejects = 0
        V55ColossalDirector.RapidShots = 0
        V55ColossalDirector.RapidProbeStatus = "idle"
        V55ColossalDirector.EvadeMode = false
        V55ColossalDirector.EvadeUntil = 0
        V55ColossalDirector.LastEvadeAt = 0
        V55ColossalDirector.LastHazardSignalAt = 0
        V55ColossalDirector.LastHazardSignal = "none"
        V55ColossalDirector.LastHazardAnimation = ""
        V55ColossalDirector.HazardDebounce = {}
        V55ColossalDirector.P2SafetyUntil = 0
        V55ColossalDirector.P2SafetySerial = 0
        V55ColossalDirector.LastP2SafetyAt = 0
        if V6CannonImpactCore then
            V6CannonImpactCore.LastTriggerAt = 0
            V6CannonImpactCore.LastBurstAt = 0
            V6CannonImpactCore.LastTargetPosition = nil
            V6CannonImpactCore.Status = "Idle"
        end
        V55ColossalDirector.Status = "Idle"
        return
    end

    -- V9.5: Colossal is officially Spears-only. Preserve the proven 1:48 Spear
    -- route and prevent any Blade Guardian/P2 Blade branch from running here.
    if Config.V95ColossalSpearsOnly == true and State and State.BladesEnabled == true then
        State.BladesEnabled = false
        V5FarmRouter.Sync("V9.5 Colossal Spears-only policy")
        V55ColossalDirector.Status = "COLOSSAL • SPEARS ONLY • Blades suppressed"
        if V95ColossalWeaponPolicyNotified ~= true then
            V95ColossalWeaponPolicyNotified = true
            pcall(showNotification,
                "Colossal: Spears only",
                "Blade combat is disabled for Colossal in V9.5. The proven Spear route remains unchanged.",
                "info")
        end
    end

    local stage = V55ColossalDirector.UpdateStage()

    if V55ColossalDirector.TransitionActive then
        return
    end

    if stage == "P2 BOSS" then
        V55ColossalDirector.P1OwnershipInitialized = false
        V55ColossalDirector.DismountPending = false
        V55ColossalDirector.BladeGuardianAirborne = false
        V55ColossalDirector.BladeGuardNeedsRemount = false
        V55ColossalDirector.RemountPending = false
        V55ColossalDirector.CannonHandshakeStatus = "P2 transition"
        if V55ColossalDirector.Entered then V55ColossalDirector.ExitCannon("P2 boss phase") end

        local now = os.clock()
        if now < (tonumber(V55ColossalDirector.P2SafetyUntil) or 0) then
            if now - (tonumber(V55ColossalDirector.LastP2SafetyAt) or 0) >= 0.70 then
                V55ColossalDirector.MoveToP2SafetyLane("post-cutscene shield")
            end
            return
        end

        if V55ColossalDirector.IsGlassCannonProfile
            and V55ColossalDirector.IsGlassCannonProfile()
            and now - (tonumber(V55ColossalDirector.LastP2SafetyAt) or 0) >= 2.25 then
            V55ColossalDirector.MoveToP2SafetyLane("glass cannon remote lane")
        end

        -- V5.7.8 hazard guard owns movement briefly for HeatWave / Stomp / Roar.
        -- Spears and Blaster remain remote-capable while blade movement is paused.
        if V55ColossalDirector.UpdateEvadeMode() then
            return
        end

        -- P2 Guardian: keep boss DPS as the default, but briefly hand
        -- Blades + Infinite Spears to Eren-zone adds when a real threat or HP drop is detected.
        V55ColossalDirector.UpdateDefenseMode()
        if V55ColossalDirector.DefenseMode then
            V55ColossalDirector.Status = "P2 SPLIT BOSS LOCK | threats "
                .. tostring(V55ColossalDirector.ThreatCount or 0)
                .. " | critical " .. tostring(V55ColossalDirector.CriticalThreatCount or 0)
                .. " | fill " .. tostring(V9RaidCombat and V9RaidCombat.LastColossalThreatFill or 0)
                .. (V55ColossalDirector.ErenHealthPercent and (" | HP " .. string.format("%.1f%%", V55ColossalDirector.ErenHealthPercent)) or "")
        else
            local focusRemaining = math.max(0, (tonumber(V55ColossalDirector.P2BossFocusUntil) or 0) - os.clock())
            V55ColossalDirector.Status = focusRemaining > 0
                and string.format("P2 split Colossal lock | focus %.1fs", focusRemaining)
                or "P2 split Colossal lock | Eren fill standby"
        end
        return
    end

    if not V55ColossalDirector.P1OwnershipInitialized then
        V55ColossalDirector.P1OwnershipInitialized = true
        pcall(function() if clearCurrentTarget then clearCurrentTarget(false) end end)
        pcall(function()
            if V35Spears and V35Spears.ClearDrainPack then
                V35Spears.ClearDrainPack("Colossal P1 cannon ownership")
            end
        end)
        pcall(function()
            if V4BlasterNapeLock and V4BlasterNapeLock.Stop then
                V4BlasterNapeLock.Stop()
            end
        end)
        cachedTitanCandidatesAt = 0
        V55ColossalDirector.Status = "P1 cannon owns Colossal; weapons reserved for Eren defense"
    end

    V55ColossalDirector.UpdateDefenseMode()
    if V55ColossalDirector.DefenseMode then
        local spearGuardianAvailable = State
            and State.SpearSupportEnabled == true
            and State.SpearAutoFireEnabled ~= false
            and V35Spears
            and V35Spears.IsEquipped
            and V35Spears.IsEquipped() == true

        if State and State.BladesEnabled == true and not spearGuardianAvailable then
            -- V9.4.4: no movement and no exact Blade bank until real detach evidence.
            if V55ColossalDirector.DismountPending == true then
                V55ColossalDirector.UpdateBladeGuardianDismount()
                V55ColossalDirector.Status = "P1 BLADE GUARDIAN • "
                    .. tostring(V55ColossalDirector.CannonHandshakeStatus or "waiting detach")
                return
            end

            if V55ColossalDirector.BladeGuardianAirborne == true then
                -- Normal Farm/Objective Guardian loop owns the bounded Blade banks.
                return
            end

            local attached = V55ColossalDirector.CannonAttachmentEvidence(V55ColossalDirector.Cannon)
            if V55ColossalDirector.Entered == true or attached == true then
                V55ColossalDirector.BeginBladeGuardianDismount("Blade Guardian dismount")
                V55ColossalDirector.Status = "P1 BLADE GUARDIAN • dismount handshake"
                return
            end

            -- Already physically detached (for example after a replicated server release).
            V55ColossalDirector.Entered = false
            V55ColossalDirector.StartBladeGuardianAirborne()
            return
        else
            V55ColossalDirector.Status = "Mounted Spear Eren defense | threats "
                .. tostring(V55ColossalDirector.ThreatCount or 0)
        end
        return
    end

    -- Blade Guardian ended by bank/time budget. Remount the retained same cannon
    -- before generic movement or map restoration can touch the character.
    if V55ColossalDirector.BladeGuardNeedsRemount == true
        or V55ColossalDirector.RemountPending == true then
        if V55ColossalDirector.RemountPending ~= true then
            V55ColossalDirector.BeginBladeGuardianRemount()
        end
        if not V55ColossalDirector.UpdateBladeGuardianRemount() then
            V55ColossalDirector.Status = "P1 BLADE GUARDIAN • "
                .. tostring(V55ColossalDirector.CannonHandshakeStatus or "remounting")
            return
        end
        -- Verified same-cannon attachment: fall through and immediately resume shot logic.
    end

    if not V55ColossalDirector.EnsureMapReady() then
        V55ColossalDirector.Status = "Restoring Colossal walls/cannon geometry before mount"
        return
    end

    local cannon = V55ColossalDirector.AcquireSingleCannon()
    if not cannon then return end

    -- V5.6.4: cast enabled ready buffs BEFORE Cannon State(true). Mounted hotbar
    -- keypresses were ignored in live tests, so cannon entry waits for the burst.
    if not V55ColossalDirector.Entered and not V55ColossalDirector.PreMountBuffDone then
        V55ColossalDirector.Status = "Applying enabled buffs before cannon mount"
        if V5BuffEngine and V5BuffEngine.CastPreCannonBurst then
            local ok, summary = pcall(V5BuffEngine.CastPreCannonBurst)
            V55ColossalDirector.PreMountBuffSummary = ok and tostring(summary or "Buff burst complete") or ("Buff burst error: " .. tostring(summary))
        else
            V55ColossalDirector.PreMountBuffSummary = "Buff engine unavailable; continuing"
        end
        V55ColossalDirector.PreMountBuffDone = true
        V55ColossalDirector.PreMountBuffFinishedAt = os.clock()
        V55ColossalDirector.Status = V55ColossalDirector.PreMountBuffSummary
        return
    end

    if not V55ColossalDirector.Entered then
        if os.clock() - (tonumber(V55ColossalDirector.PreMountBuffFinishedAt) or 0) < 0.80 then
            V55ColossalDirector.Status = "Buffs applied — waiting before cannon mount"
            return
        end
        if not V55ColossalDirector.EnterCannon() then return end
    end

    V55ColossalDirector.FireOneShot()
end

task.spawn(function()
    while true do
        task.wait(0.10)
        local ok, err = pcall(V55ColossalDirector.Step)
        if not ok then
            V55ColossalDirector.LastError = tostring(err)
            V55ColossalDirector.Status = "Director error: " .. tostring(err)
        end
    end
end)

V521FemaleDirector = V521FemaleDirector or {
    Stage = nil,
    PreviousStage = nil,
    TransitionActive = false,
    TransitionStartedAt = 0,
    TransitionReason = "Idle",
    TargetStableSince = nil,
    LastAnnieSeenAt = 0,
    LastErenSeenAt = 0,
    LastRestoreAt = 0,
    LastLiveScanAt = 0,
    LastObjectiveScanAt = 0,
    LastStageComputeAt = 0,
    CachedLiveTargets = nil,
    CachedObjective = nil,
    CachedStage = nil,
    SeenErenPhase = false,
    SeenAnnieP3 = false,
}

function V521FemaleDirector.LiveTargets(force)
    local now = os.clock()
    local cache = V521FemaleDirector.CachedLiveTargets
    if not force and cache and now - (V521FemaleDirector.LastLiveScanAt or 0) < 0.14 then
        return cache[1], cache[2], cache[3], cache[4]
    end

    local annieTitan, anniePart = V4RaidDirector.FindTitanByIdentityTokens
        and V4RaidDirector.FindTitanByIdentityTokens({"annie", "female"}) or nil, nil
    if annieTitan and getTitanTargetPart then anniePart = getTitanTargetPart(annieTitan) end

    local erenTitan, erenPart = V4RaidDirector.FindTitanByIdentityTokens
        and V4RaidDirector.FindTitanByIdentityTokens({"eren", "attack"}) or nil, nil
    if erenTitan and getTitanTargetPart then erenPart = getTitanTargetPart(erenTitan) end

    if annieTitan then V521FemaleDirector.LastAnnieSeenAt = now end
    if erenTitan then
        V521FemaleDirector.LastErenSeenAt = now
        V521FemaleDirector.SeenErenPhase = true
    end

    cache = {[1] = annieTitan, [2] = anniePart, [3] = erenTitan, [4] = erenPart}
    V521FemaleDirector.CachedLiveTargets = cache
    V521FemaleDirector.LastLiveScanAt = now
    return annieTitan, anniePart, erenTitan, erenPart
end

function V521FemaleDirector.ObjectiveFlags(force)
    local now = os.clock()
    local cache = V521FemaleDirector.CachedObjective
    if not force and cache and now - (V521FemaleDirector.LastObjectiveScanAt or 0) < 0.20 then
        return cache[1], cache[2], cache[3], cache[4]
    end

    local textValue = V4RaidDirector.VisibleObjectiveText and V4RaidDirector.VisibleObjectiveText(force) or ""
    textValue = string.gsub(V4RaidDirector.Lower(textValue), "%s+", " ")

    local annieDone = string.match(textValue, "defeat annie%s*%[1%s*/%s*1%]") ~= nil
        or string.match(textValue, "kill annie%s*%[1%s*/%s*1%]") ~= nil
    local erenDone = string.match(textValue, "defeat eren%s*%[1%s*/%s*1%]") ~= nil
        or string.match(textValue, "kill eren%s*%[1%s*/%s*1%]") ~= nil
    local p3Marker = string.find(textValue, "execute skills", 1, true) ~= nil

    cache = {[1] = annieDone, [2] = erenDone, [3] = textValue, [4] = p3Marker}
    V521FemaleDirector.CachedObjective = cache
    V521FemaleDirector.LastObjectiveScanAt = now
    return annieDone, erenDone, textValue, p3Marker
end

function V521FemaleDirector.ExpectedTokens(stage)
    if stage == "EREN P2" then return {"eren", "attack"} end
    if stage == "ANNIE P1" or stage == "ANNIE P3" then return {"annie", "female"} end
    return nil
end

function V521FemaleDirector.ComputeStage(force)
    local now = os.clock()
    if not force
        and V521FemaleDirector.CachedStage
        and now - (V521FemaleDirector.LastStageComputeAt or 0) < 0.10 then
        return V521FemaleDirector.CachedStage
    end

    local annieDone, erenDone, _, p3Marker = V521FemaleDirector.ObjectiveFlags(force)
    local annieTitan, _, erenTitan = V521FemaleDirector.LiveTargets(force)
    local remembered = V521FemaleDirector.Stage
    local stage

    if p3Marker then
        V521FemaleDirector.SeenErenPhase = true
        V521FemaleDirector.SeenAnnieP3 = true
        stage = "ANNIE P3"
    elseif annieDone and erenDone then
        stage = "DONE"
    elseif erenDone and not annieDone then
        V521FemaleDirector.SeenErenPhase = true
        V521FemaleDirector.SeenAnnieP3 = true
        stage = "ANNIE P3"
    elseif annieDone and not erenDone then
        V521FemaleDirector.SeenErenPhase = true
        stage = "EREN P2"
    elseif erenTitan and not annieTitan then
        V521FemaleDirector.SeenErenPhase = true
        stage = "EREN P2"
    elseif V521FemaleDirector.SeenErenPhase and annieTitan then
        V521FemaleDirector.SeenAnnieP3 = true
        stage = "ANNIE P3"
    elseif remembered == "ANNIE P3" or V521FemaleDirector.SeenAnnieP3 then
        stage = "ANNIE P3"
    elseif remembered == "EREN P2" then
        stage = "EREN P2"
    else
        stage = "ANNIE P1"
    end

    V521FemaleDirector.CachedStage = stage
    V521FemaleDirector.LastStageComputeAt = now
    return stage
end

function V521FemaleDirector.BeginTransition(reason, nextStage)
    V521FemaleDirector.TransitionActive = true
    V521FemaleDirector.TransitionStartedAt = os.clock()
    V521FemaleDirector.TransitionReason = tostring(reason or "Female transition")
    V521FemaleDirector.TargetStableSince = nil

    if nextStage then
        V521FemaleDirector.PreviousStage = V521FemaleDirector.Stage
        V521FemaleDirector.Stage = nextStage
    end

    V4RaidDirector.LockedBossTitan = nil
    V4RaidDirector.LockedBossPart = nil
    V4RaidDirector.BossTitan = nil
    V4RaidDirector.BossPart = nil

    pcall(function() if clearCurrentTarget then clearCurrentTarget(false) end end)
    pcall(function() if V35Spears and V35Spears.ClearDrainPack then V35Spears.ClearDrainPack("female transition") end end)
    pcall(function() if V4BlasterNapeLock and V4BlasterNapeLock.Stop then V4BlasterNapeLock.Stop() end end)
    cachedTitanCandidatesAt = 0
end

function V521FemaleDirector.RestoreControl()
    if os.clock() - (V521FemaleDirector.LastRestoreAt or 0) < 0.75 then return end
    V521FemaleDirector.LastRestoreAt = os.clock()

    pcall(function()
        local liveCharacter = player and player.Character or character
        local liveHumanoid = liveCharacter and liveCharacter:FindFirstChildOfClass("Humanoid") or humanoid
        local liveRoot = liveCharacter and liveCharacter:FindFirstChild("HumanoidRootPart") or rootPart

        if liveRoot and not (StationRefill and StationRefill.Running) then
            liveRoot.Anchored = false
            liveRoot.AssemblyLinearVelocity = Vector3.zero
            liveRoot.AssemblyAngularVelocity = Vector3.zero
        end

        if liveHumanoid then
            liveHumanoid.PlatformStand = false
            liveHumanoid.Sit = false
            liveHumanoid.AutoRotate = true
            liveHumanoid:ChangeState(Enum.HumanoidStateType.Freefall)
        end

        local camera = Workspace.CurrentCamera
        if camera and liveHumanoid then
            camera.CameraSubject = liveHumanoid
            if camera.CameraType == Enum.CameraType.Scriptable then
                camera.CameraType = Enum.CameraType.Custom
            end
        end
    end)

    pcall(function() if clearCurrentTarget then clearCurrentTarget(false) end end)
    pcall(function() if V35Spears and V35Spears.ClearDrainPack then V35Spears.ClearDrainPack("female transition complete") end end)
    cachedTitanCandidates = {}
    cachedTitanCandidatesAt = 0
end

function V521FemaleDirector.UpdateTransition()
    local stage = V521FemaleDirector.ComputeStage()
    local oldStage = V521FemaleDirector.Stage

    if oldStage == nil then
        V521FemaleDirector.Stage = stage
    elseif stage ~= oldStage then
        V521FemaleDirector.BeginTransition(oldStage .. " -> " .. stage, stage)
    end

    local camera = Workspace.CurrentCamera
    local cameraScriptable = camera and camera.CameraType == Enum.CameraType.Scriptable

    -- Camera ownership is authoritative. The old UI-only detector could see stale
    -- cutscene/skip elements and repeatedly freeze a live Female boss fight.
    if cameraScriptable and not V521FemaleDirector.TransitionActive then
        V521FemaleDirector.BeginTransition("Female camera cutscene", stage)
    end

    if not V521FemaleDirector.TransitionActive then
        return false
    end

    local currentStage = V521FemaleDirector.Stage or stage
    if currentStage == "DONE" then
        V521FemaleDirector.TransitionActive = false
        V521FemaleDirector.TransitionReason = "Female raid objectives complete"
        V521FemaleDirector.RestoreControl()
        return false
    end

    local tokens = V521FemaleDirector.ExpectedTokens(currentStage)
    local target = tokens and select(1, V4RaidDirector.FindTitanByIdentityTokens(tokens)) or nil
    local elapsed = os.clock() - (V521FemaleDirector.TransitionStartedAt or os.clock())

    -- Once the correct next-stage boss is alive and the camera is back, resume fast.
    -- Do not wait 12 seconds because a stale skip UI still exists.
    if target and isTitanAlive(target) and not cameraScriptable then
        V521FemaleDirector.TargetStableSince = V521FemaleDirector.TargetStableSince or os.clock()
        if os.clock() - V521FemaleDirector.TargetStableSince >= 0.35 then
            V521FemaleDirector.TransitionActive = false
            V521FemaleDirector.TransitionReason = "Ready: " .. tostring(currentStage)
            V521FemaleDirector.RestoreControl()
            return false
        end
    else
        V521FemaleDirector.TargetStableSince = nil
    end

    -- A faulted camera can still be recovered once the expected target exists.
    if target and isTitanAlive(target) and elapsed >= 8.0 then
        V521FemaleDirector.TransitionActive = false
        V521FemaleDirector.TransitionReason = "Watchdog recovery: " .. tostring(currentStage)
        V521FemaleDirector.RestoreControl()
        return false
    end

    return true
end

function V4RaidDirector.CutsceneActive()
    -- Keep the old global transition lock disabled for other raids. Female has multiple
    -- cutscene-owned combat handoffs and gets its own strict staged lock.
    if V4RaidDirector.RaidName ~= "Female Raid" then return false end
    return V521FemaleDirector.UpdateTransition()
end

function V4RaidDirector.GetObjectPosition(object)
    if not object then return nil end

    if object:IsA("BasePart") then
        return object.Position
    end

    if object:IsA("Model") then
        local ok, pivot = pcall(function() return object:GetPivot() end)
        return ok and pivot and pivot.Position or nil
    end

    return nil
end

function V4RaidDirector.RefreshObjectiveAnchors(force)
    local now = os.clock()
    if not force and now - (V4RaidDirector.ObjectiveAnchorsAt or 0) < 1.25 then
        return V4RaidDirector.ObjectiveAnchors
    end

    V4RaidDirector.ObjectiveAnchorsAt = now
    V4RaidDirector.ObjectiveAnchors = {}

    local raidName = V4RaidDirector.RaidName
    local keywords = nil

    if raidName == "Armored Raid" then
        keywords = {"boat", "ship", "vessel"}
    elseif raidName == "Attack Raid" then
        keywords = {"eren", "boulder"}
    elseif raidName == "Colossal Raid" then
        keywords = {"eren", "boulder"}
    else
        return V4RaidDirector.ObjectiveAnchors
    end

    local titansFolder = Workspace:FindFirstChild(Config.TitansFolderName)
    local seenModels = {}
    local checked = 0

    for _, object in ipairs(Workspace:GetDescendants()) do
        checked += 1
        if checked > 16000 then break end

        if (object:IsA("BasePart") or object:IsA("Model"))
            and not (titansFolder and object:IsDescendantOf(titansFolder)) then

            local lowerName = V4RaidDirector.Lower(object.Name)
            local matched = false

            for _, keyword in ipairs(keywords) do
                if string.find(lowerName, keyword, 1, true) then
                    matched = true
                    break
                end
            end

            if matched then
                local owner = object:IsA("Model") and object or object:FindFirstAncestorOfClass("Model")
                local key = owner or object

                if not seenModels[key] then
                    local position = V4RaidDirector.GetObjectPosition(key)
                        or V4RaidDirector.GetObjectPosition(object)

                    if position then
                        seenModels[key] = true
                        V4RaidDirector.ObjectiveAnchors[#V4RaidDirector.ObjectiveAnchors + 1] = position
                    end
                end
            end
        end
    end

    -- Some raid objectives expose their protected target through an ObjectValue
    -- named Reference/Target instead of a descriptive Workspace model name.
    if #V4RaidDirector.ObjectiveAnchors == 0 then
        for _, object in ipairs(Workspace:GetDescendants()) do
            if object:IsA("ObjectValue")
                and (
                    V4RaidDirector.Lower(object.Name) == "reference"
                    or V4RaidDirector.Lower(object.Name) == "target"
                ) then

                local value = object.Value
                if value
                    and value:IsDescendantOf(Workspace)
                    and not (titansFolder and value:IsDescendantOf(titansFolder)) then

                    local position = V4RaidDirector.GetObjectPosition(value)
                    if position then
                        V4RaidDirector.ObjectiveAnchors[#V4RaidDirector.ObjectiveAnchors + 1] = position
                    end
                end
            end
        end
    end

    return V4RaidDirector.ObjectiveAnchors
end

function V4RaidDirector.BossAttributeValue(titan, names)
    if not titan then return nil end

    local candidates = {titan}
    local humanoid = titan:FindFirstChildOfClass("Humanoid")
    local nape = titan:FindFirstChild("Nape", true)
    if humanoid then candidates[#candidates + 1] = humanoid end
    if nape then candidates[#candidates + 1] = nape end

    for _, object in ipairs(candidates) do
        for _, name in ipairs(names) do
            local value = nil
            pcall(function() value = object:GetAttribute(name) end)
            if value ~= nil then return value end
        end
    end

    return nil
end

function V4RaidDirector.AttackBossVulnerable(titan, objectiveText)
    objectiveText = V4RaidDirector.Lower(objectiveText)

    if (string.find(objectiveText, "kill", 1, true)
        or string.find(objectiveText, "defeat", 1, true)
        or string.find(objectiveText, "slay", 1, true))
        and (string.find(objectiveText, "eren", 1, true)
            or string.find(objectiveText, "attack titan", 1, true)) then
        return true
    end

    if (string.find(objectiveText, "defend", 1, true)
        or string.find(objectiveText, "protect", 1, true))
        and (string.find(objectiveText, "eren", 1, true)
            or string.find(objectiveText, "boulder", 1, true)) then
        return false
    end

    local invulnerable = V4RaidDirector.BossAttributeValue(
        titan,
        {"Invulnerable", "Invincible", "Immune", "Sleeping", "Asleep"}
    )
    if invulnerable == true then return false end

    local vulnerable = V4RaidDirector.BossAttributeValue(
        titan,
        {"Vulnerable", "Awake", "Awakened", "Active"}
    )
    if vulnerable ~= nil then return vulnerable == true end

    return V4RaidDirector.Phase2Latched == true
end

function V4RaidDirector.DetermineBossPhase(rawBoss)
    local raidName = V4RaidDirector.RaidName
    local visibleText = V4RaidDirector.VisibleObjectiveText()
    local text = visibleText ~= ""
        and visibleText
        or V4RaidDirector.ObjectiveText()
    local anchors = V4RaidDirector.RefreshObjectiveAnchors(false)

    if V4RaidDirector.LastRaidName ~= raidName then
        V4RaidDirector.LastRaidName = raidName
        V4RaidDirector.Phase2Latched = false
        V4RaidDirector.LockedBossTitan = nil
        V4RaidDirector.LockedBossPart = nil
        V4RaidDirector.FemaleStage = nil
        if V521FemaleDirector then
            V521FemaleDirector.Stage = nil
            V521FemaleDirector.PreviousStage = nil
            V521FemaleDirector.TransitionActive = false
            V521FemaleDirector.TargetStableSince = nil
            V521FemaleDirector.CachedStage = nil
            V521FemaleDirector.CachedLiveTargets = nil
            V521FemaleDirector.CachedObjective = nil
            V521FemaleDirector.SeenErenPhase = false
            V521FemaleDirector.SeenAnnieP3 = false
        end
    end

    if raidName == "Armored Raid" then
        local p1Text = string.find(text, "boat", 1, true)
            or string.find(text, "ship", 1, true)
            or (
                (string.find(text, "defend", 1, true) or string.find(text, "protect", 1, true))
                and not string.find(text, "kill armored", 1, true)
            )

        local p2Text = string.find(text, "kill armored", 1, true)
            or string.find(text, "defeat armored", 1, true)
            or string.find(text, "slay armored", 1, true)
            or string.find(text, "kill reiner", 1, true)
            or string.find(text, "defeat reiner", 1, true)
            or string.find(text, "slay reiner", 1, true)

        local hasShield, shieldValue = V4RaidDirector.FindArmoredShield()
        local shieldBroken = hasShield
            and (
                shieldValue == false
                or (tonumber(shieldValue) ~= nil and tonumber(shieldValue) <= 0)
            )
        local bossVulnerable = V4RaidDirector.BossAttributeValue(
            rawBoss,
            {"Vulnerable", "Awake", "Awakened", "Active"}
        ) == true

        -- V9.4.1: shield existence is normal P1 state, not proof of P2. A missed
        -- boat-text frame must never permanently hard-lock Reiner while boats die.
        if p2Text then
            V4RaidDirector.Phase2Latched = true
        elseif p1Text or #anchors > 0 then
            V4RaidDirector.Phase2Latched = false
        elseif #anchors == 0 and (shieldBroken or bossVulnerable) then
            V4RaidDirector.Phase2Latched = true
        end

        if V4RaidDirector.Phase2Latched then return rawBoss ~= nil end
        if p1Text then return false end
        if #anchors > 0 then return false end
        -- Unknown/missing objective evidence is a safe P1 hold. Reiner existing in
        -- Workspace is not permission to abandon protected boats.
        return false
    end

    if raidName == "Female Raid" then
        local stage = V4RaidDirector.FemaleObjectiveStage()
        V4RaidDirector.FemaleStage = stage
        if stage == "DONE" then return false end
        return rawBoss ~= nil
    end

    if raidName == "Colossal Raid" then
        local stage = V55ColossalDirector and V55ColossalDirector.ComputeStage
            and V55ColossalDirector.ComputeStage(false)
            or "P1 CANNON STALL"

        if stage == "P2 BOSS" then
            V4RaidDirector.Phase2Latched = true
            return rawBoss ~= nil
        end

        return false
    end

    if raidName == "Attack Raid" then
        local vulnerable = V4RaidDirector.AttackBossVulnerable(rawBoss, text)
        if vulnerable then V4RaidDirector.Phase2Latched = true end

        local p1Text = (string.find(text, "defend", 1, true)
            or string.find(text, "protect", 1, true))
            and (string.find(text, "eren", 1, true)
                or string.find(text, "boulder", 1, true))

        if p1Text and not V4RaidDirector.Phase2Latched then
            return false
        end

        if V4RaidDirector.Phase2Latched then
            return rawBoss ~= nil
        end

        if #anchors > 0 then return false end
        return vulnerable and rawBoss ~= nil
    end

    return rawBoss ~= nil
end

function V4RaidDirector.IsTitanNearObjective(titan)
    if not titan then return false end
    local part = getTitanTargetPart(titan)
    if not part then return false end

    local anchors = V4RaidDirector.RefreshObjectiveAnchors(false)
    if #anchors == 0 then return true end

    local radius = tonumber(V4RaidDirector.ObjectiveRadius) or 260
    local radiusSquared = radius * radius

    for _, position in ipairs(anchors) do
        local delta = part.Position - position
        if delta:Dot(delta) <= radiusSquared then
            return true
        end
    end

    return false
end

function V4RaidDirector.AllowTitanTarget(titan)
    if not V4RaidDirector.Enabled or not titan then
        return true
    end

    if V4RaidDirector.Phase == "P1 Objective" then
        if titan == V4RaidDirector.RawBossTitan
            or V4RaidDirector.IsBossTitan(titan) then
            return false
        end

        if V4RaidDirector.RaidName == "Colossal Raid"
            and V55ColossalDirector
            and V55ColossalDirector.ResolveErenAnchor then

            local anchor = V55ColossalDirector.ResolveErenAnchor(false)
            local part = getTitanTargetPart(titan)
            if typeof(anchor) == "Vector3" and part then
                local delta = part.Position - anchor
                return delta:Dot(delta) <= (340 * 340)
            end
        end

        return V4RaidDirector.IsTitanNearObjective(titan)
    end

    if V4RaidDirector.Phase == "Boss"
        or V4RaidDirector.Phase == "Boss Shield" then
        -- V5.7.4: Colossal P2 Guardian temporarily releases boss-only routing
        -- and admits only ordinary Titans inside the Eren defense zone.
        if V4RaidDirector.RaidName == "Colossal Raid"
            and V55ColossalDirector
            and V55ColossalDirector.Stage == "P2 BOSS"
            and V55ColossalDirector.DefenseMode == true then

            if titan == V4RaidDirector.BossTitan or V4RaidDirector.IsBossTitan(titan) then
                return false
            end

            local anchor = V55ColossalDirector.ResolveErenAnchor(false)
            local part = getTitanTargetPart(titan)
            if typeof(anchor) == "Vector3" and part then
                local delta = part.Position - anchor
                -- V5.7.6: Guardian attacks the actual Eren-danger lane, not every
                -- Titan in the old 430-stud watch circle.
                return delta:Dot(delta) <= (300 * 300)
            end
            return V4RaidDirector.IsTitanNearObjective(titan)
        end

        local boss = V4RaidDirector.BossTitan
        return boss ~= nil and titan == boss
    end

    if V4RaidDirector.RaidName == "Female Raid"
        and V4RaidDirector.FemaleStage
        and V4RaidDirector.FemaleStage ~= "DONE" then
        -- A staged Female target is expected. Do not rotate into ordinary Titans
        -- while Annie/Eren resolution is temporarily between replicated models.
        return false
    end

    return true
end

function V4RaidDirector.ResolveWeakPointText()
    if not V4RaidDirector.Enabled then
        return nil
    end

    if V4RaidDirector.Phase == "P1 Objective" then
        if V4RaidDirector.RaidName == "Armored Raid" then
            return "Locked during boat defense"
        elseif V4RaidDirector.RaidName == "Attack Raid" then
            return "Locked until Eren wakes"
        elseif V4RaidDirector.RaidName == "Colossal Raid" then
            return "Cannon stall target: Colossal body"
        end
        return "Locked until boss phase"
    end

    local titan = V4RaidDirector.BossTitan
    if not titan then
        return "Waiting for boss"
    end

    local priorityNames = {
        "Nape",
        "WeakPoint",
        "Weak_Point",
        "Neck",
        "Eye",
        "Eyes",
        "Ankle",
        "Achilles",
    }

    for _, name in ipairs(priorityNames) do
        local part = titan:FindFirstChild(name, true)
        if part and part:IsA("BasePart") then
            if V4RaidDirector.ShieldActive and name == "Nape" then
                return "Nape (shield active)"
            end
            return name
        end
    end

    return V4RaidDirector.BossPart and V4RaidDirector.BossPart.Name or "Boss body"
end

function V4RaidDirector.Refresh()
    V4RaidDirector.LastRefreshAt = os.clock()
    V4RaidDirector.RaidName = V4RaidDirector.DetectRaidName()
    V4RaidDirector.Enabled = V4RaidDirector.RaidName ~= "Unknown"

    if not V4RaidDirector.Enabled then
        V4RaidDirector.CombatPaused = false
        V4RaidDirector.Phase = "Idle"
        V4RaidDirector.BossTitan = nil
        V4RaidDirector.BossPart = nil
        V4RaidDirector.RawBossTitan = nil
        V4RaidDirector.RawBossPart = nil
        V4RaidDirector.WeakPointText = nil
        V4RaidDirector.Status = "Waiting for raid runtime"
        return
    end

    if type(SliceHubRaidRuntimeAllowed) == "function"
        and not SliceHubRaidRuntimeAllowed(V4RaidDirector.RaidName) then
        V4RaidDirector.CombatPaused = true
        V4RaidDirector.Phase = "Premium Locked"
        V4RaidDirector.BossTitan = nil
        V4RaidDirector.BossPart = nil
        V4RaidDirector.RawBossTitan = nil
        V4RaidDirector.RawBossPart = nil
        V4RaidDirector.WeakPointText = "Premium only"
        V4RaidDirector.Status = tostring(V4RaidDirector.RaidName) .. " | Premium only in Free build"
        if State then
            State.FarmEnabled = false
            State.BladesEnabled = false
            State.SpearSupportEnabled = false
            State.SpearAutoFireEnabled = false
            State.AutoSkipCutsceneEnabled = false
            State.RaidAutoSkipEnabled = false
        end
        warn("[SliceHub Free] " .. tostring(V4RaidDirector.RaidName) .. " automation is unsupported in the Free version.")
        return
    end

    if V4RaidDirector.CutsceneActive() then
        V4RaidDirector.CombatPaused = true
        V4RaidDirector.Phase = "Transition"
        V4RaidDirector.Status =
            V4RaidDirector.RaidName .. " | cutscene/transition lock"
        V4RaidDirector.LastTransitionAt = os.clock()
        V4RaidDirector.WeakPointText = "Transition"
        return
    end

    local rawBoss, rawBossPart = V4RaidDirector.FindBossTitan()
    V4RaidDirector.RawBossTitan = rawBoss
    V4RaidDirector.RawBossPart = rawBossPart

    local bossPhase = V4RaidDirector.DetermineBossPhase(rawBoss)

    local hasShield, shieldValue = V4RaidDirector.FindArmoredShield()
    if type(shieldValue) == "number" then
        V4RaidDirector.ShieldActive = hasShield and shieldValue > 0
    else
        V4RaidDirector.ShieldActive = hasShield and shieldValue == true
    end
    V4RaidDirector.BossVulnerable = bossPhase == true

    if not bossPhase
        and (V4RaidDirector.RaidName == "Armored Raid"
            or V4RaidDirector.RaidName == "Attack Raid"
            or V4RaidDirector.RaidName == "Colossal Raid") then

        V4RaidDirector.BossTitan = nil
        V4RaidDirector.BossPart = nil
        V4RaidDirector.BossName = nil
        V4RaidDirector.LockedBossTitan = nil
        V4RaidDirector.LockedBossPart = nil
        V4RaidDirector.CombatPaused = false
        V4RaidDirector.Phase = "P1 Objective"
        V4RaidDirector.RefreshObjectiveAnchors(false)

        V4RaidDirector.Status = V4RaidDirector.RaidName
            .. (
                V4RaidDirector.RaidName == "Armored Raid"
                and " | P1 boat defense | boss excluded"
                or V4RaidDirector.RaidName == "Colossal Raid"
                    and " | P1 single-cannon stall + Eren defense"
                    or " | P1 defend Eren | boss excluded"
            )

        V4RaidDirector.WeakPointText = V4RaidDirector.ResolveWeakPointText()
        return
    end

    if bossPhase and rawBoss and rawBossPart then
        if not V4RaidDirector.LockedBossTitan
            or not isTitanAlive(V4RaidDirector.LockedBossTitan) then
            V4RaidDirector.LockedBossTitan = rawBoss
        end
        V4RaidDirector.LockedBossPart = getTitanTargetPart(V4RaidDirector.LockedBossTitan) or rawBossPart
        rawBoss = V4RaidDirector.LockedBossTitan
        rawBossPart = V4RaidDirector.LockedBossPart
    end

    V4RaidDirector.BossTitan = rawBoss
    V4RaidDirector.BossPart = rawBossPart
    V4RaidDirector.BossName = rawBoss and rawBoss.Name or nil

    if rawBoss and rawBossPart then
        V4RaidDirector.LastBossSeenAt = os.clock()
        V4RaidDirector.CombatPaused = false
        V4RaidDirector.Phase =
            V4RaidDirector.ShieldActive
            and "Boss Shield"
            or "Boss"

        V4RaidDirector.Status = V4RaidDirector.RaidName
            .. (V4RaidDirector.RaidName == "Female Raid" and (" | " .. tostring(V4RaidDirector.FemaleStage or "WAITING")) or "")
            .. " | "
            .. V4RaidDirector.Phase
            .. " | "
            .. tostring(V4RaidDirector.BossName)

        V4RaidDirector.WeakPointText = V4RaidDirector.ResolveWeakPointText()
        return
    end

    local titanCount = 0
    local titansFolder = Workspace:FindFirstChild(Config.TitansFolderName)

    if titansFolder then
        for _, titan in ipairs(titansFolder:GetChildren()) do
            if isTitanAlive(titan)
                and V4RaidDirector.AllowTitanTarget(titan) then
                titanCount += 1
            end
        end
    end

    V4RaidDirector.CombatPaused = false

    if titanCount > 0 then
        V4RaidDirector.Phase = "Adds"
        V4RaidDirector.Status = V4RaidDirector.RaidName
            .. " | clearing adds "
            .. tostring(titanCount)
    else
        V4RaidDirector.Phase = "Waiting Phase"
        V4RaidDirector.Status = V4RaidDirector.RaidName
            .. " | waiting for next phase"
    end

    V4RaidDirector.WeakPointText = V4RaidDirector.ResolveWeakPointText()
end

function V4RaidDirector.ShouldPauseCombat()
    if V55ColossalDirector
        and V55ColossalDirector.ShouldOwnCombat
        and V55ColossalDirector.ShouldOwnCombat() then
        return true
    end

    return V4RaidDirector.Enabled == true
        and V4RaidDirector.CombatPaused == true
end

function V4RaidDirector.BossPriorityScore(titan)
    if not V4RaidDirector.Enabled
        or not State.RaidBossPriorityEnabled
        or not titan then
        return 0
    end

    if V4RaidDirector.Phase == "P1 Objective" then
        return V4RaidDirector.AllowTitanTarget(titan)
            and 0
            or 1000000000
    end

    return V4RaidDirector.IsBossTitan(titan)
        and -1000000000
        or 0
end

function V4RaidDirector.PreferredBossPart()
    if not V4RaidDirector.Enabled
        or not State.RaidBossPriorityEnabled
        or not V4RaidDirector.BossVulnerable then
        return nil, nil
    end

    if V4RaidDirector.RaidName == "Colossal Raid"
        and V55ColossalDirector
        and V55ColossalDirector.Stage == "P2 BOSS"
        and V55ColossalDirector.DefenseMode == true then
        return nil, nil
    end

    local titan = V4RaidDirector.BossTitan
    local part = V4RaidDirector.BossPart

    if titan
        and part
        and part.Parent
        and isTitanAlive(titan) then
        return titan, part
    end

    return nil, nil
end

function V4RaidDirector.HardBossLock()
    if not V4RaidDirector.Enabled
        or not State.RaidBossPriorityEnabled then
        return nil, nil
    end

    -- The Raid Director already refreshes at 10 Hz. Only refresh here if its state
    -- is genuinely stale; the old unconditional call multiplied full Female GUI/Titan
    -- scans across Blades, Spears, Pack Drain, and Blaster decision paths.
    local now = os.clock()
    if now - (V4RaidDirector.LastRefreshAt or 0) >= 0.14 then
        pcall(V4RaidDirector.Refresh)
    end

    return V4RaidDirector.PreferredBossPart()
end

