        task.wait(0.10)

        local ok, err = pcall(V4RaidDirector.Refresh)

        if not ok then
            V4RaidDirector.Status = "Raid Director error: " .. tostring(err)
        end
    end
end)

-- V9.1 transient Attack boss invulnerability guard. The uploaded trace shows the
-- boss Buff_Scream signal during the rage/roar window; combat resumes after the
-- short lock instead of spending Blade durability or Spear shots on an immune boss.
V91RaidBossGuard = V91RaidBossGuard or {
    AttackRoarUntil = 0,
    LastSignal = "None",
    Connection = nil,
}

function V91RaidBossGuard.IsAttackBoss(titan)
    if not titan or not titan.Parent then return false end
    if V4RaidDirector.RaidName ~= "Attack Raid" then return false end
    if titan == V4RaidDirector.BossTitan or titan == V4RaidDirector.RawBossTitan then return true end
    local lower = string.lower(tostring(titan.Name or ""))
    return string.find(lower, "attack", 1, true) ~= nil
        or lower == "eren"
        or string.find(lower, "eren", 1, true) ~= nil
end

function V91RaidBossGuard.Blocked()
    return V4RaidDirector
        and V4RaidDirector.RaidName == "Attack Raid"
        and os.clock() < (tonumber(V91RaidBossGuard.AttackRoarUntil) or 0)
end

do
    local post = resolvePath(ReplicatedStorage, {"Assets", "Remotes", "POST"})
    if post and post:IsA("RemoteEvent") then
        V91RaidBossGuard.Connection = post.OnClientEvent:Connect(function(category, action, titan)
            if tostring(category) ~= "Effects" then return end
            local signal = tostring(action or "")
            if signal ~= "Buff_Scream" and signal ~= "Scream" then return end
            if not V91RaidBossGuard.IsAttackBoss(titan) then return end

            local duration = math.max(0.8, tonumber(Config.V91AttackRoarPauseSeconds) or 2.45)
            V91RaidBossGuard.AttackRoarUntil = math.max(
                tonumber(V91RaidBossGuard.AttackRoarUntil) or 0,
                os.clock() + duration
            )
            V91RaidBossGuard.LastSignal = signal
            print("[SliceHub V9.1][ATTACK-ROAR-GUARD]", signal, "pause", string.format("%.2fs", duration))
        end)
    end
end

V43RaidChestAuto = V43RaidChestAuto or {
    ScreenActive = false,
    Attempted = false,
    LastAttemptAt = 0,
    Status = "Idle",
}

function V43RaidChestAuto.ScreenVisible()
    local found = false

    pcall(function()
        for _, object in ipairs(playerGui:GetDescendants()) do
            if object:IsA("GuiObject") and object.Visible then
                local node = object
                local actuallyVisible = true

                while node and node ~= playerGui do
                    if node:IsA("GuiObject") and not node.Visible then
                        actuallyVisible = false
                        break
                    end
                    if node:IsA("LayerCollector") and not node.Enabled then
                        actuallyVisible = false
                        break
                    end
                    node = node.Parent
                end

                if actuallyVisible then
                    local name = string.lower(tostring(object.Name or ""))
                    local textValue = ""
                    if object:IsA("TextLabel")
                        or object:IsA("TextButton")
                        or object:IsA("TextBox") then
                        textValue = string.lower(tostring(object.Text or ""))
                    end

                    if name == "chests"
                        or textValue == "chests"
                        or string.find(textValue, "open (", 1, true) then
                        found = true
                        break
                    end
                end
            end
        end
    end)

    return found
end

function V43RaidChestAuto.FindFinishButton()
    local best = nil
    local bestY = -math.huge

    for _, object in ipairs(playerGui:GetDescendants()) do
        if object:IsA("TextLabel") or object:IsA("TextButton") or object:IsA("TextBox") then
            local textValue = string.upper(string.gsub(tostring(object.Text or ""), "%s+", " "))
            if textValue == "FINISH" and guiObjectIsActuallyVisible(object) then
                local candidate = object
                local node = object
                for _ = 1, 7 do
                    if not node or node == playerGui then break end
                    if node:IsA("GuiButton") then candidate = node break end
                    node = node.Parent
                end

                if candidate:IsA("GuiObject") then
                    local y = candidate.AbsolutePosition.Y
                    if y > bestY then
                        bestY = y
                        best = candidate
                    end
                end
            end
        end
    end

    return best
end

function V43RaidChestAuto.ClickFinish()
    local button = V43RaidChestAuto.FindFinishButton()
    if not button then return false, "FINISH not found" end

    if button:IsA("GuiButton") then
        pcall(function() button:Activate() end)
        if type(firesignal) == "function" then
            pcall(function() firesignal(button.MouseButton1Down) end)
            pcall(function() firesignal(button.MouseButton1Click) end)
            pcall(function() firesignal(button.Activated) end)
        end
    end

    local pos = button.AbsolutePosition
    local size = button.AbsoluteSize
    local x = math.floor(pos.X + size.X * 0.5 + 0.5)
    local y = math.floor(pos.Y + size.Y * 0.5 + 0.5)
    local inset = Vector2.new(0, 0)
    pcall(function() inset = GuiService:GetGuiInset() end)

    pcall(function()
        VirtualInputManager:SendMouseMoveEvent(x + inset.X, y + inset.Y, game)
        task.wait(0.03)
        VirtualInputManager:SendMouseButtonEvent(x + inset.X, y + inset.Y, 0, true, game, 0)
        task.wait(0.06)
        VirtualInputManager:SendMouseButtonEvent(x + inset.X, y + inset.Y, 0, false, game, 0)
    end)

    return true, "FINISH clicked"
end

function V43RaidChestAuto.Open(kind)
    local assets = ReplicatedStorage:FindFirstChild("Assets")
    local remotes = assets and assets:FindFirstChild("Remotes")
    local getRemote = remotes and remotes:FindFirstChild("GET")

    if not getRemote or not getRemote:IsA("RemoteFunction") then
        return false, "GET RemoteFunction missing"
    end

    local ok, rewards, updatedData = pcall(function()
        return getRemote:InvokeServer("S_Rewards", "Chest", kind)
    end)

    if not ok then
        return false, tostring(rewards)
    end

    local rewardCount = type(rewards) == "table" and #rewards or 0
    return rewardCount > 0, rewardCount
end

