V52KillingEngine = V52KillingEngine or {
    ClusterRadius = 95,
    LastSeed = nil,
    LastSeedDensity = 0,
    LastWaveSize = 0,
    LastHandoffAt = 0,
    Status = "Learning targets",
}

function V52KillingEngine.ComputeDensity(entries, entry)
    if not entry or not entry.Part then return 0 end
    local radius = tonumber(V52KillingEngine.ClusterRadius) or 95
    local radiusSquared = radius * radius
    local count = 0
    for _, other in ipairs(entries or {}) do
        if other.Part and other.Part.Parent then
            local delta = other.Part.Position - entry.Part.Position
            if delta:Dot(delta) <= radiusSquared then count += 1 end
        end
    end
    return count
end

function V52KillingEngine.ScoreEntry(entry, entries)
    if not entry or not entry.Titan or not entry.Part then return math.huge end

    local hardBoss = V4RaidDirector
        and V4RaidDirector.BossVulnerable == true
        and V4RaidDirector.BossTitan
        or nil
    if hardBoss then
        return entry.Titan == hardBoss and -1e15 or 1e15
    end

    local score = getObjectiveTargetScore and getObjectiveTargetScore(entry)
        or tonumber(entry.DistanceSquared)
        or math.huge

    local density = V52KillingEngine.ComputeDensity(entries, entry)
    entry.ClusterDensity = density

    -- Lower score wins. Dense local groups are preferred because one blade wave can\n    -- physically cover them instead of averaging aim across scattered Titans.\n    score -= math.max(0, density - 1) * 2300
    score += math.sqrt(math.max(0, tonumber(entry.DistanceSquared) or 0)) * 4

    if V4RaidDirector and V4RaidDirector.BossPriorityScore then
        score += V4RaidDirector.BossPriorityScore(entry.Titan)
    end

    local failed = BladeBurstFailureCounts and BladeBurstFailureCounts[entry.Titan] or 0
    score += tonumber(failed or 0) * 9000

    entry.KillScore = score
    return score
end

function V52KillingEngine.BuildBladeWave(limit, current)
    limit = math.max(1, math.floor(tonumber(limit) or 1))
    local candidates = findClosestTitans(math.min(40, math.max(limit * 3, limit + 4)))
    if #candidates == 0 then return {} end

    local seed = nil
    if current and isTitanAlive(current) then
        for _, entry in ipairs(candidates) do
            if entry.Titan == current then seed = entry break end
        end
    end
    seed = seed or candidates[1]
    if not seed or not seed.Part then return {} end

    local radius = tonumber(V52KillingEngine.ClusterRadius) or 95
    local radiusSquared = radius * radius
    local near, far = {}, {}

    for _, entry in ipairs(candidates) do
        local delta = entry.Part.Position - seed.Part.Position
        if delta:Dot(delta) <= radiusSquared then
            near[#near + 1] = entry
        else
            far[#far + 1] = entry
        end
    end

    table.sort(near, function(a, b)
        local da = (a.Part.Position - seed.Part.Position).Magnitude
        local db = (b.Part.Position - seed.Part.Position).Magnitude
        if da == db then return (a.KillScore or 0) < (b.KillScore or 0) end
        return da < db
    end)

    local result, seen = {}, {}
    for _, bucket in ipairs({near, far}) do
        for _, entry in ipairs(bucket) do
            if #result >= limit then break end
            if entry.Titan and not seen[entry.Titan] and isTitanAlive(entry.Titan) then
                seen[entry.Titan] = true
                result[#result + 1] = entry.Titan
            end
        end
        if #result >= limit then break end
    end

    V52KillingEngine.LastSeed = seed.Titan
    V52KillingEngine.LastSeedDensity = tonumber(seed.ClusterDensity) or #near
    V52KillingEngine.LastWaveSize = #result
    V52KillingEngine.Status = "Seed density " .. tostring(V52KillingEngine.LastSeedDensity)
        .. " | wave " .. tostring(#result)

    return result
end

local function rebuildTitanCandidateCache()
	cachedTitanCandidates = {}
	cachedTitanCandidatesAt = os.clock()

	if not rootPart then return end
	local titansFolder = Workspace:FindFirstChild(Config.TitansFolderName)
	if not titansFolder then return end

	local origin = rootPart.Position
	local maximumDistanceSquared = Config.AttackRange * Config.AttackRange
	local hardBoss = nil

	if V4RaidDirector and V4RaidDirector.HardBossLock then
		hardBoss = select(1, V4RaidDirector.HardBossLock())
	end

	for _, instance in ipairs(titansFolder:GetChildren()) do
		if hardBoss and instance ~= hardBoss then continue end
        if V4RaidDirector
            and V4RaidDirector.AllowTitanTarget
            and not V4RaidDirector.AllowTitanTarget(instance) then
            continue
        end
		if not isTitanAlive(instance) then continue end
		local targetPart = getTitanTargetPart(instance)
		if not targetPart then continue end

		local difference = targetPart.Position - origin
		local distanceSquared = difference:Dot(difference)
		if distanceSquared <= maximumDistanceSquared then
			table.insert(cachedTitanCandidates, {
				Titan = instance,
				Part = targetPart,
				DistanceSquared = distanceSquared,
			})
		end
	end

    for _, entry in ipairs(cachedTitanCandidates) do
        V52KillingEngine.ScoreEntry(entry, cachedTitanCandidates)
    end

	table.sort(cachedTitanCandidates, function(a, b)
        local scoreA = tonumber(a.KillScore) or math.huge
        local scoreB = tonumber(b.KillScore) or math.huge
        if scoreA == scoreB then
            return (tonumber(a.DistanceSquared) or math.huge) < (tonumber(b.DistanceSquared) or math.huge)
        end
		return scoreA < scoreB
	end)
end

findClosestTitans = function(limit)
	if not rootPart then return {} end
	limit = math.clamp(math.floor(tonumber(limit) or 1), 1, 40)

	if os.clock() - cachedTitanCandidatesAt >= Config.TargetCacheLifetime then
		rebuildTitanCandidateCache()
	end

	local selected = {}
	for _, entry in ipairs(cachedTitanCandidates) do
		if #selected >= limit then break end
		if entry.Part and entry.Part.Parent and not isTitanBlacklisted(entry.Titan) and isTitanAlive(entry.Titan) then
			table.insert(selected, entry)
		end
	end
	return selected
end

local function findClosestTitan()
	local selected = findClosestTitans(1)
	local entry = selected[1]
	if not entry then return nil, nil end
	return entry.Titan, entry.Part
end

local function getCachedAliveTitanCount()
    if os.clock() - cachedTitanCandidatesAt >= Config.TargetCacheLifetime then
        rebuildTitanCandidateCache()
    end

    local count = 0
    for _, entry in ipairs(cachedTitanCandidates) do
        if entry
            and entry.Titan
            and entry.Part
            and entry.Part.Parent
            and isTitanAlive(entry.Titan) then

            count += 1
        end
    end

    return count
end

local function findClosestAliveTitanIgnoringBlacklist()
    local titansFolder = Workspace:FindFirstChild(Config.TitansFolderName)
    if not titansFolder or not rootPart then return nil, nil end

    local bestTitan, bestPart = nil, nil
    local bestDistanceSquared = math.huge

    for _, titan in ipairs(titansFolder:GetChildren()) do
        if isTitanAlive(titan)
            and (
                not V4RaidDirector
                or not V4RaidDirector.AllowTitanTarget
                or V4RaidDirector.AllowTitanTarget(titan)
            ) then
            local part = getTitanTargetPart(titan)
            if part and part.Parent then
                local delta = part.Position - rootPart.Position
                local distanceSquared = delta:Dot(delta)
                if distanceSquared < bestDistanceSquared then
                    bestDistanceSquared = distanceSquared
                    bestTitan = titan
                    bestPart = part
                end
            end
        end
    end

    return bestTitan, bestPart
end

function getBestTitanCluster(radius, scanLimit)
	local entries = findClosestTitans(math.clamp(math.floor(tonumber(scanLimit) or 20), 1, 40))
	if #entries == 0 then return nil, nil, 0 end

	radius = math.max(1, tonumber(radius) or 280)
	local radiusSquared = radius * radius
	local bestCenter, bestPart, bestCount, bestDistance = nil, nil, 0, math.huge

	for _, a in ipairs(entries) do
		local part = a and a.Part
		if part and part.Parent then
			local sum = Vector3.zero
			local members = {}
			for _, b in ipairs(entries) do
				local other = b and b.Part
				if other and other.Parent then
					local delta = other.Position - part.Position
					if delta:Dot(delta) <= radiusSquared then
						sum += other.Position
						table.insert(members, other)
					end
				end
			end

			local count = #members
			if count > 0 then
				local center = sum / count
				local centerPart, centerDistance = nil, math.huge
				for _, member in ipairs(members) do
					local d = member.Position - center
					local ds = d:Dot(d)
					if ds < centerDistance then
						centerPart, centerDistance = member, ds
					end
				end

				local distance = tonumber(a.DistanceSquared) or math.huge
				if count > bestCount or (count == bestCount and distance < bestDistance) then
					bestCenter, bestPart, bestCount, bestDistance = center, centerPart or part, count, distance
				end
			end
		end
	end

	return bestCenter, bestPart, bestCount
end

local function chooseRipperAimPart()
    if player and player:GetAttribute("Weapon") == "Spears"
        and V35Spears
        and V35Spears.GetBestCluster then

        local center, bestPart, bestCount = V35Spears.GetBestCluster()

        if center then
            return bestPart, tonumber(bestCount) or 0, center
        end
    end

	if not Config.RipperClusterEnabled then
		return currentTargetPart, 1, currentTargetPart and currentTargetPart.Position or nil
	end

	local center, bestPart, bestCount = getBestTitanCluster(Config.RipperClusterRadius, Config.RipperClusterScanLimit)
	if center and bestPart and bestCount >= math.max(1, tonumber(Config.RipperClusterMinTargets) or 5) then
		return bestPart, bestCount, center
	end

	local fallbackPart = currentTargetPart or bestPart
	return fallbackPart, bestCount, fallbackPart and fallbackPart.Position or center
end

local function getRipperOpportunity()
    if V4RaidDirector
        and V4RaidDirector.ShouldPauseCombat
        and V4RaidDirector.ShouldPauseCombat() then
        return false, 0, getCachedAliveTitanCount()
    end

    local aliveCount = getCachedAliveTitanCount()

    if player
        and player:GetAttribute("Weapon") == "Spears"
        and V35Spears
        and V35Spears.GetBestCluster then

        if aliveCount <= 1 then
            return false, 0, aliveCount
        end

        local _, _, spearPackCount = V35Spears.GetBestCluster()
        spearPackCount = tonumber(spearPackCount) or 0

        return
            spearPackCount >= math.max(1, tonumber(Config.TitanBlasterMinPack) or 2),
            spearPackCount,
            aliveCount
    end

    if aliveCount <= math.max(1, tonumber(Config.RipperNeverCastAtOrBelowAlive) or 5) then
        return false, 0, aliveCount
    end

    local _, _, packCount = getBestTitanCluster(
        Config.RipperClusterRadius,
        Config.RipperClusterScanLimit
    )

    packCount = tonumber(packCount) or 0
    local now = os.clock()
    local immediateMin = math.max(1, tonumber(Config.RipperImmediateClusterMin) or 12)
    local delayedMin = math.max(1, tonumber(Config.RipperDelayedClusterMin) or 8)

    if packCount >= immediateMin then
        RipperOpportunityReadySince = nil
        return true, packCount, aliveCount
    end

    if packCount >= delayedMin then
        RipperOpportunityReadySince = RipperOpportunityReadySince or now
        if now - RipperOpportunityReadySince >= (tonumber(Config.RipperOpportunityWait) or 1.0) then
            RipperOpportunityReadySince = nil
            return true, packCount, aliveCount
        end
        return false, packCount, aliveCount
    end

    RipperOpportunityReadySince = nil
    return false, packCount, aliveCount
end

local function getEffectiveTitansPerHit()
	return SliceHubMissionClampTPS(Config.TitansPerHit, SliceHubMissionTPSMax())
end


---------------------------------------------------------------------
-- V3.5 THUNDER SPEAR ENGINE
-- Validated protocol:
--   GET : InvokeServer("Spears", "S_Fire", spearName)
--   POST: FireServer("Spears", "S_Explode", Vector3 position)
-- Server S_Fire spends ammo and sets Current_Spear.
-- Server S_Explode applies blast damage and clears Current_Spear.
---------------------------------------------------------------------


---------------------------------------------------------------------
-- V9 RAID COMBAT MATRIX
-- Observable-behavior reconstruction from clean raid traces:
--   NORMAL PACKS  : unique exact weak points, max 10 per visible attack bank
--   RAID BOSSES   : same live weak point repeated x5 per visible attack
--   SPEAR PACKS   : one accepted S_Fire fans into up to 10 exact positions
--   SPEAR BOSSES  : same live weak point repeated x5, optional leftover-add fill
--
-- This is an independently implemented behavior profile. It keeps the existing
-- raid phase detector authoritative and only changes per-phase combat delivery.
---------------------------------------------------------------------

V941ObjectiveGuardian = {
    ActiveRoute = false,
    LastRouteKey = "",
    Anchors = {},
    AnchorsAt = 0,
    AnchorRaid = "",
    ThreatCount = 0,
    CriticalThreatCount = 0,
    LastThreatScanAt = 0,
    Status = "STANDBY",
}

function V941ObjectiveGuardian.ColossalMountedActive()
    if Config.V941ObjectiveGuardianEnabled ~= true then return false end
    if not V4RaidDirector
        or V4RaidDirector.RaidName ~= "Colossal Raid"
        or not V55ColossalDirector
        or V55ColossalDirector.Stage ~= "P1 CANNON STALL" then
        return false
    end

    -- V9.4.3: Blade-only P1 defense intentionally dismounts the cannon. Keep the
    -- Guardian route authoritative during that defense window so exact Blade banks
    -- continue targeting Eren-zone threats until the wave is actually clear.
    if V55ColossalDirector.DefenseMode == true then return true end
    if V55ColossalDirector.Entered ~= true then return false end

    local threats = tonumber(V55ColossalDirector.ThreatCount) or 0
    pcall(function()
        threats = tonumber(V55ColossalDirector.CountObjectiveThreats(false)) or threats
    end)
    local damaged = os.clock() < (tonumber(V55ColossalDirector.ErenDamagedPulseUntil) or 0)
    return threats > 0 or damaged
end

function V941ObjectiveGuardian.RouteActive()
    if Config.V941ObjectiveGuardianEnabled ~= true
        or not V4RaidDirector
        or V4RaidDirector.Enabled ~= true then
        if V941ObjectiveGuardian.ActiveRoute == true then
            V941ObjectiveGuardian.ActiveRoute = false
            V941ObjectiveGuardian.LastRouteKey = "DISABLED"
            V941ObjectiveGuardian.Status = "STANDBY"
            V941ObjectiveGuardian.Anchors = {}
            V941ObjectiveGuardian.AnchorsAt = 0
            if V6ExactBlade then V6ExactBlade.Targets = {} end
            if clearCurrentTarget then clearCurrentTarget(false) end
            cachedTitanCandidatesAt = 0
        end
        return false
    end

    local raid = tostring(V4RaidDirector.RaidName or "Unknown")
    local phase = tostring(V4RaidDirector.Phase or "Idle")
    local active = false

    if raid == "Colossal Raid" then
        active = V941ObjectiveGuardian.ColossalMountedActive()
    elseif phase == "P1 Objective"
        and (raid == "Armored Raid" or raid == "Attack Raid") then
        active = true
    end

    local routeKey = raid .. "|" .. phase .. "|" .. tostring(active)
    if routeKey ~= V941ObjectiveGuardian.LastRouteKey then
        V941ObjectiveGuardian.LastRouteKey = routeKey
        V941ObjectiveGuardian.ActiveRoute = active
        V941ObjectiveGuardian.AnchorsAt = 0
        V941ObjectiveGuardian.Anchors = {}
        if V4RaidDirector then V4RaidDirector.ObjectiveAnchorsAt = 0 end
        if V6ExactBlade then V6ExactBlade.Targets = {} end
        if clearCurrentTarget then clearCurrentTarget(false) end
        cachedTitanCandidatesAt = 0
        V94RunRecorder.Record("OBJECTIVE_GUARD_ROUTE", routeKey)
    end

    return active
end

function V941ObjectiveGuardian.DefenseRadius()
    local raid = V4RaidDirector and tostring(V4RaidDirector.RaidName or "") or ""
    if raid == "Armored Raid" then
        return math.max(180, tonumber(Config.V941ArmoredDefenseRadius) or 360)
    end
    if raid == "Attack Raid" then
        return math.max(180, tonumber(Config.V941AttackDefenseRadius) or 340)
    end
    return math.max(180, tonumber(Config.V941ColossalP1DefenseRadius) or 360)
end

function V941ObjectiveGuardian.ResolveAnchors(force)
    local now = os.clock()
    local raid = V4RaidDirector and tostring(V4RaidDirector.RaidName or "Unknown") or "Unknown"
    if not force
        and raid == V941ObjectiveGuardian.AnchorRaid
        and now - (tonumber(V941ObjectiveGuardian.AnchorsAt) or 0)
            < math.max(0.35, tonumber(Config.V941AnchorRefreshSeconds) or 0.65) then
        return V941ObjectiveGuardian.Anchors
    end

    local anchors = {}
    local function addPosition(position)
        if typeof(position) ~= "Vector3" then return end
        for _, existing in ipairs(anchors) do
            if (existing - position).Magnitude <= 8 then return end
        end
        anchors[#anchors + 1] = position
    end

    if raid == "Colossal Raid"
        and V55ColossalDirector
        and V55ColossalDirector.ResolveErenAnchor then
        local ok, position = pcall(V55ColossalDirector.ResolveErenAnchor, force == true)
        if ok then addPosition(position) end
    end

    if V4RaidDirector and V4RaidDirector.RefreshObjectiveAnchors then
        local ok, values = pcall(V4RaidDirector.RefreshObjectiveAnchors, force == true)
        if ok and type(values) == "table" then
            for _, position in ipairs(values) do addPosition(position) end
        end
    end

    -- Exact reference fallback: only used when name-based boat/Eren anchors failed.
    if #anchors == 0 then
        local titansFolder = Workspace:FindFirstChild(Config.TitansFolderName)
        local keywords = raid == "Armored Raid"
            and {"boat", "ship", "vessel", "defend", "protect"}
            or {"eren", "boulder", "defend", "protect"}
        local checked = 0

        for _, object in ipairs(Workspace:GetDescendants()) do
            checked += 1
            if checked > 20000 then break end

            if object:IsA("ObjectValue") and object.Value
                and object.Value:IsDescendantOf(Workspace)
                and not (titansFolder and object.Value:IsDescendantOf(titansFolder)) then

                local context = string.lower(
                    tostring(object.Name or "") .. " "
                    .. tostring(object.Parent and object.Parent.Name or "") .. " "
                    .. tostring(object.Value.Name or "")
                )
                local matched = false
                for _, keyword in ipairs(keywords) do
                    if string.find(context, keyword, 1, true) then
                        matched = true
                        break
                    end
                end

                if matched then
                    addPosition(V4RaidDirector.GetObjectPosition(object.Value))
                end
            end
        end
    end

    V941ObjectiveGuardian.Anchors = anchors
    V941ObjectiveGuardian.AnchorsAt = now
    V941ObjectiveGuardian.AnchorRaid = raid
    return anchors
end

function V941ObjectiveGuardian.ThreatEntries(limit)
    limit = math.max(1, math.floor(tonumber(limit) or 20))
    local folder = Workspace:FindFirstChild(Config.TitansFolderName)
    if not folder then return {} end

    local anchors = V941ObjectiveGuardian.ResolveAnchors(false)
    local radius = V941ObjectiveGuardian.DefenseRadius()
    local radiusSquared = radius * radius
    local criticalRadius = math.max(80, tonumber(Config.V941ObjectiveCriticalRadius) or 175)
    local criticalSquared = criticalRadius * criticalRadius
    local candidates = {}
    local critical = 0

    for _, titan in ipairs(folder:GetChildren()) do
        if isTitanAlive(titan)
            and not (V4RaidDirector.IsBossTitan and V4RaidDirector.IsBossTitan(titan)) then
            local part = V9RaidCombat and V9RaidCombat.ExactNape
                and (V9RaidCombat.ExactNape(titan) or getTitanTargetPart(titan))
                or getTitanTargetPart(titan)
            if part and part.Parent then
                local bestDistanceSquared = math.huge
                for _, anchor in ipairs(anchors) do
                    local delta = part.Position - anchor
                    bestDistanceSquared = math.min(bestDistanceSquared, delta:Dot(delta))
                end

                local allowed = #anchors > 0 and bestDistanceSquared <= radiusSquared
                    or (#anchors == 0 and (
                        not V4RaidDirector.AllowTitanTarget
                        or V4RaidDirector.AllowTitanTarget(titan)
                    ))

                if allowed then
                    if #anchors == 0 and rootPart then
                        local delta = part.Position - rootPart.Position
                        bestDistanceSquared = delta:Dot(delta)
                    end
                    local isCritical = bestDistanceSquared <= criticalSquared
                    if isCritical then critical += 1 end
                    candidates[#candidates + 1] = {
                        Titan = titan,
                        Part = part,
                        DistanceSquared = bestDistanceSquared,
                        Critical = isCritical,
                    }
                end
            end
        end
    end

    table.sort(candidates, function(a, b)
        if a.Critical ~= b.Critical then return a.Critical == true end
        return (tonumber(a.DistanceSquared) or math.huge)
            < (tonumber(b.DistanceSquared) or math.huge)
    end)

    local output = {}
    for index = 1, math.min(limit, #candidates) do output[index] = candidates[index] end

    V941ObjectiveGuardian.ThreatCount = #candidates
    V941ObjectiveGuardian.CriticalThreatCount = critical
    V941ObjectiveGuardian.LastThreatScanAt = os.clock()
    V941ObjectiveGuardian.Status = string.format(
        "%s • anchors %d • threats %d • critical %d",
        tostring(V4RaidDirector.RaidName or "OBJECTIVE GUARD"),
        #anchors,
        #candidates,
        critical
    )
    return output
end

V9RaidCombat = V9RaidCombat or {
    Version = "9.4.4",
    BladeMode = "BOOT",
    SpearMode = "BOOT",
    LastBladeRegisters = 0,
    LastBladeSlashes = 0,
    LastSpearExplodes = 0,
    LastColossalThreatFill = 0,
    LastColossalCriticalFill = 0,
    BossBladeCycles = 0,
    BossSpearShots = 0,
    PackBladeCycles = 0,
    PackSpearShots = 0,
}

function V9RaidCombat.Context()
    local raid = V4RaidDirector and tostring(V4RaidDirector.RaidName or "Unknown") or "Unknown"
    local phase = V4RaidDirector and tostring(V4RaidDirector.Phase or "Idle") or "Idle"
    local stage = V4RaidDirector and tostring(
        V4RaidDirector.FemaleStage
        or (V521FemaleDirector and V521FemaleDirector.Stage)
        or "WAITING"
    ) or "WAITING"
    return raid, phase, stage
end

function V9RaidCombat.ExactNape(titan)
    if not titan or not titan.Parent then return nil end
    local hitboxes = titan:FindFirstChild("Hitboxes")
    local hit = hitboxes and hitboxes:FindFirstChild("Hit")
    local nape = hit and hit:FindFirstChild("Nape")
    if nape and nape:IsA("BasePart") and nape.Parent then return nape end
    return nil
end

function V9RaidCombat.LiveBoss()
    if not V4RaidDirector or V4RaidDirector.Enabled ~= true then return nil, nil end
    if V4RaidDirector.HardBossLock then
        local ok, titan, part = pcall(V4RaidDirector.HardBossLock)
        if ok and titan and part and part.Parent and isTitanAlive(titan) then
            return titan, V9RaidCombat.ExactNape(titan) or part
        end
    end
    local titan = V4RaidDirector.BossTitan
    local part = titan and (V9RaidCombat.ExactNape(titan) or V4RaidDirector.BossPart)
    if titan and part and part.Parent and isTitanAlive(titan) then return titan, part end
    return nil, nil
end

function V9RaidCombat.RawP1Boss()
    if not V4RaidDirector then return nil, nil end
    local titan = V4RaidDirector.RawBossTitan
    local part = titan and (V9RaidCombat.ExactNape(titan) or V4RaidDirector.RawBossPart)
    if titan and part and part.Parent and isTitanAlive(titan) then return titan, part end
    return nil, nil
end

function V9RaidCombat.ColossalGuardianActive()
    return V4RaidDirector
        and V4RaidDirector.RaidName == "Colossal Raid"
        and V55ColossalDirector
        and V55ColossalDirector.Stage == "P2 BOSS"
        and V55ColossalDirector.DefenseMode == true
end

function V9RaidCombat.BossAddFillAllowed()
    local raid = V9RaidCombat.Context()
    if raid == "Female Raid" then return false end

    -- V9.4.2: Colossal P2 must never mix boss pressure with add cleanup.
    -- Outside Guardian the route is boss-only; inside Guardian the dedicated
    -- ColossalGuardianActive branch already builds an add-only defense plan.
    if raid == "Colossal Raid" then return false end

    if V9RaidCombat.ColossalGuardianActive() then return false end
    if V941ObjectiveGuardian and V941ObjectiveGuardian.RouteActive
        and V941ObjectiveGuardian.RouteActive() then return false end
    return raid == "Attack Raid" or raid == "Armored Raid"
end

function V9RaidCombat.OrdinaryTitans(limit, allowBossPhaseAdds)
    local output = {}
    local folder = Workspace:FindFirstChild(Config.TitansFolderName)
    if not folder then return output end

    for _, titan in ipairs(folder:GetChildren()) do
        if #output >= math.max(1, tonumber(limit) or 10) then break end
        if isTitanAlive(titan) and not (V4RaidDirector and V4RaidDirector.IsBossTitan and V4RaidDirector.IsBossTitan(titan)) then
            local allowed = true
            if V4RaidDirector and V4RaidDirector.Enabled == true and not allowBossPhaseAdds then
                allowed = not V4RaidDirector.AllowTitanTarget
                    or V4RaidDirector.AllowTitanTarget(titan)
            end
            local part = allowed and (V9RaidCombat.ExactNape(titan) or getTitanTargetPart(titan)) or nil
            if part and part.Parent then
                output[#output + 1] = {Titan = titan, Part = part}
            end
        end
    end

    return output
end

function V9RaidCombat.ColossalP2ThreatEntries(limit)
    local output = {}
    limit = math.max(0, math.floor(tonumber(limit) or 0))
    if limit <= 0
        or Config.V943ColossalSplitRouteEnabled ~= true
        or not V4RaidDirector
        or V4RaidDirector.RaidName ~= "Colossal Raid"
        or not V55ColossalDirector
        or V55ColossalDirector.Stage ~= "P2 BOSS" then
        V9RaidCombat.LastColossalThreatFill = 0
        V9RaidCombat.LastColossalCriticalFill = 0
        return output
    end

    local anchor = V55ColossalDirector.ResolveErenAnchor
        and V55ColossalDirector.ResolveErenAnchor(false)
        or nil
    local folder = Workspace:FindFirstChild(Config.TitansFolderName)
    if typeof(anchor) ~= "Vector3" or not folder then
        V9RaidCombat.LastColossalThreatFill = 0
        V9RaidCombat.LastColossalCriticalFill = 0
        return output
    end

    local radius = math.max(120, tonumber(Config.V943ColossalThreatRadius) or 300)
    local criticalRadius = math.max(60, tonumber(Config.V943ColossalCriticalRadius) or 175)
    local radiusSquared = radius * radius
    local criticalSquared = criticalRadius * criticalRadius
    local candidates = {}

    for _, titan in ipairs(folder:GetChildren()) do
        if isTitanAlive(titan)
            and not (V4RaidDirector.IsBossTitan and V4RaidDirector.IsBossTitan(titan)) then
            local part = V9RaidCombat.ExactNape(titan) or getTitanTargetPart(titan)
            if part and part.Parent then
                local delta = part.Position - anchor
                local distanceSquared = delta:Dot(delta)
                if distanceSquared <= radiusSquared then
                    candidates[#candidates + 1] = {
                        Titan = titan,
                        Part = part,
                        DistanceSquared = distanceSquared,
                        Critical = distanceSquared <= criticalSquared,
                    }
                end
            end
        end
    end

    table.sort(candidates, function(a, b)
        if a.Critical ~= b.Critical then return a.Critical == true end
        return (tonumber(a.DistanceSquared) or math.huge)
            < (tonumber(b.DistanceSquared) or math.huge)
    end)

    local critical = 0
    for index = 1, math.min(limit, #candidates) do
        local entry = candidates[index]
        output[#output + 1] = entry
        if entry.Critical == true then critical += 1 end
    end

    V9RaidCombat.LastColossalThreatFill = #output
    V9RaidCombat.LastColossalCriticalFill = critical
    return output
end

function V9RaidCombat.ColossalP2ThreatFillLimit()
    if not V55ColossalDirector or V55ColossalDirector.Stage ~= "P2 BOSS" then return 0 end
    if V55ColossalDirector.DefenseMode == true then
        return math.max(0, math.floor(tonumber(Config.V943ColossalGuardianThreatFill) or 5))
    end
    return math.max(0, math.floor(tonumber(Config.V943ColossalNormalThreatFill) or 2))
end

function V9RaidCombat.BuildBladePlan(queueTargets)
    local raid, phase, stage = V9RaidCombat.Context()
    local plan = {}
    local seen = {}

    local function add(titan, repeats)
        if not titan or seen[titan] or not isTitanAlive(titan) then return end
        if not V9RaidCombat.ExactNape(titan) then return end
        seen[titan] = true
        plan[#plan + 1] = {
            Titan = titan,
            Repeats = math.max(1, math.floor(tonumber(repeats) or 1)),
        }
    end

    if Config.V9RaidCombatEnabled ~= true
        or not V4RaidDirector
        or V4RaidDirector.Enabled ~= true then
        local maximum = math.min(
            getEffectiveTitansPerHit(),
            math.max(1, math.floor(tonumber(Config.V9BladeQueueMaxTargets) or SliceHubMissionTPSMax()))
        )
        for _, titan in ipairs(queueTargets or {}) do
            add(titan, 1)
            if #plan >= maximum then break end
        end
        return plan, "DUAL PACK BANK"
    end

    -- V9.4.1: protected objectives own Blades before every P1 boss/cannon route.
    -- Targets come from a fresh anchor-distance scan, not a stale combat queue.
    if V941ObjectiveGuardian
        and V941ObjectiveGuardian.RouteActive
        and V941ObjectiveGuardian.RouteActive() then
        local maximum = math.min(
            getEffectiveTitansPerHit(),
            math.max(
                1,
                math.floor(tonumber(Config.V941ObjectiveGuardianMaxTargets) or SliceHubMissionTPSMax())
            )
        )

        -- V9.4.4 Colossal P1 Blade Guardian consumes an explicit bank budget.
        -- One normal bank means at most 10 targets; heavy danger permits two.
        if raid == "Colossal Raid"
            and V55ColossalDirector
            and V55ColossalDirector.BladeGuardianAirborne == true then
            local bankSize = math.max(1, math.floor(tonumber(Config.V9BladeBankSize) or 10))
            local bankBudget = math.max(1, math.floor(tonumber(V55ColossalDirector.BladeGuardianBankBudget) or 1))
            maximum = math.min(maximum, bankSize * bankBudget)
        end

        for _, entry in ipairs(V941ObjectiveGuardian.ThreatEntries(maximum)) do
            add(entry.Titan, 1)
        end

        -- V9.4.2: live objective threats remain first, but Armored/Attack P1
        -- no longer devolves into one-Titan-at-a-time cleanup when only one add
        -- has crossed the defense radius. Fill the remaining exact Blade bank
        -- with ordinary non-boss Titans so the proven 10 + 10 bank throughput
        -- stays active while boats/Eren remain protected.
        if #plan < maximum
            and (raid == "Armored Raid" or raid == "Attack Raid") then
            for _, entry in ipairs(V9RaidCombat.OrdinaryTitans(maximum, true)) do
                add(entry.Titan, 1)
                if #plan >= maximum then break end
            end
        end

        return plan, raid .. " • OBJECTIVE GUARDIAN"
    end

    -- Female raid traces are pure staged boss pressure: ANNIE -> EREN -> ANNIE.
    if raid == "Female Raid" then
        local boss = V9RaidCombat.LiveBoss()
        if boss then add(boss, tonumber(Config.V9BossBladeRegistersPerSlash) or 5) end
        return plan, "FEMALE " .. stage .. " • BOSS x5"
    end

    if phase == "Boss" or phase == "Boss Shield" then
        -- V9.4.3: Colossal P2 never abandons boss pressure. One Blade cycle keeps
        -- boss x5 and appends only the nearest Eren-zone threats in the same Slash.
        if raid == "Colossal Raid" and Config.V943ColossalSplitRouteEnabled == true then
            local boss = V9RaidCombat.LiveBoss()
            if boss then add(boss, tonumber(Config.V9BossBladeRegistersPerSlash) or 5) end

            local fillLimit = V9RaidCombat.ColossalP2ThreatFillLimit()
            for _, entry in ipairs(V9RaidCombat.ColossalP2ThreatEntries(fillLimit)) do
                add(entry.Titan, 1)
            end

            return plan, string.format(
                "COLOSSAL SPLIT • BOSS x5 + EREN x%d",
                tonumber(V9RaidCombat.LastColossalThreatFill) or 0
            )
        end

        local boss = V9RaidCombat.LiveBoss()
        if boss then add(boss, tonumber(Config.V9BossBladeRegistersPerSlash) or 5) end

        if V9RaidCombat.BossAddFillAllowed() then
            local fill = raid == "Colossal Raid"
                and math.max(0, math.floor(tonumber(Config.V9ColossalBossAddFill) or 9))
                or math.max(0, math.floor(tonumber(Config.V9BossAddFill) or 6))
            for _, entry in ipairs(V9RaidCombat.OrdinaryTitans(fill, true)) do
                add(entry.Titan, 1)
            end
        end
        return plan, raid .. " • BOSS x5"
    end

    if phase == "P1 Objective" then
        local normalLimit = getEffectiveTitansPerHit()
        if raid == "Armored Raid" then
            normalLimit = math.max(1, normalLimit - 1)
        end
        for _, titan in ipairs(queueTargets or {}) do
            add(titan, 1)
            if #plan >= normalLimit then break end
        end

        -- Armored P1 traces mix objective adds with one light boss register.
        if raid == "Armored Raid" then
            local rawBoss = V9RaidCombat.RawP1Boss()
            if rawBoss then
                seen[rawBoss] = nil
                add(rawBoss, tonumber(Config.V9ArmoredP1BossRegisters) or 1)
            end
        end

        return plan, raid .. " • P1 OBJECTIVE"
    end

    local packLimit = getEffectiveTitansPerHit()
    for _, titan in ipairs(queueTargets or {}) do
        add(titan, 1)
        if #plan >= packLimit then break end
    end
    return plan, raid .. " • " .. phase
end


function V9RaidCombat.FreeSpearBurstTargets(entries, fallbackPosition)
    entries = type(entries) == "table" and entries or {}

    local spearProfile = PROFILE and PROFILE.Spears or {}
    local minimum = math.max(1, math.floor(tonumber(spearProfile.PackMinTargets) or 2))
    local maximum = math.max(minimum, math.floor(tonumber(spearProfile.PackMaxTargets) or 4))
    local valid = {}

    for _, entry in ipairs(entries) do
        local titan = entry and entry.Titan
        local part = titan and (V9RaidCombat.ExactNape(titan) or entry.Part) or (entry and entry.Part)

        if part and part.Parent then
            valid[#valid + 1] = {
                Part = part,
                Distance = typeof(fallbackPosition) == "Vector3"
                    and (part.Position - fallbackPosition).Magnitude
                    or 0,
            }
        end
    end

    table.sort(valid, function(a, b)
        return a.Distance < b.Distance
    end)

    local available = #valid
    if available <= 0 then
        return {}, 0
    end

    local targetCount = math.min(maximum, available)
    if available >= minimum then
        targetCount = math.max(minimum, targetCount)
    end

    local targets = {}
    for index = 1, targetCount do
        targets[index] = valid[index].Part
    end

    return targets, targetCount
end

function V9RaidCombat.BuildSpearBurstTargets(mode, exactTitan, fallbackPosition)
    local raid = V9RaidCombat.Context()
    local targets = {}

    local function addPart(part, repeats)
        if not part or not part.Parent then return end
        for _ = 1, math.max(1, math.floor(tonumber(repeats) or 1)) do
            targets[#targets + 1] = part
        end
    end

    if mode == "BOSS BURST" then
        local boss, part = V9RaidCombat.LiveBoss()
        if not boss and exactTitan and isTitanAlive(exactTitan) then
            boss = exactTitan
            part = V9RaidCombat.ExactNape(exactTitan) or getTitanTargetPart(exactTitan)
        end

        local splitFill = 0
        if part then
            addPart(part, tonumber(Config.V9SpearBossRepeats) or 5)

            if raid == "Colossal Raid"
                and V55ColossalDirector
                and V55ColossalDirector.Stage == "P2 BOSS"
                and Config.V943ColossalSplitRouteEnabled == true then
                local fillLimit = V9RaidCombat.ColossalP2ThreatFillLimit()
                for _, entry in ipairs(V9RaidCombat.ColossalP2ThreatEntries(fillLimit)) do
                    if entry.Part and entry.Part.Parent then
                        targets[#targets + 1] = entry.Part
                        splitFill += 1
                    end
                end
            elseif V9RaidCombat.BossAddFillAllowed() then
                local fill = math.max(0, math.floor(tonumber(Config.V9SpearBossAddFill) or 6))
                for _, entry in ipairs(V9RaidCombat.OrdinaryTitans(fill, true)) do
                    if entry.Part and entry.Part.Parent then targets[#targets + 1] = entry.Part end
                end
            end
        end

        if raid == "Colossal Raid"
            and V55ColossalDirector
            and V55ColossalDirector.Stage == "P2 BOSS" then
            return targets, string.format("COLOSSAL SPLIT BOSS x5 + EREN x%d", splitFill)
        end
        return targets, raid .. " BOSS x5"
    end

    if mode == "SURVIVOR HUNT" and exactTitan then
        local part = V9RaidCombat.ExactNape(exactTitan) or getTitanTargetPart(exactTitan)
        if part then targets[1] = part end
        return targets, "SURVIVOR"
    end

    local entries = V35Spears and V35Spears.GetGlobalEntries and V35Spears.GetGlobalEntries() or {}
    if typeof(fallbackPosition) == "Vector3" then
        table.sort(entries, function(a, b)
            local ap = a.Part and a.Part.Position
            local bp = b.Part and b.Part.Position
            if not ap then return false end
            if not bp then return true end
            return (ap - fallbackPosition).Magnitude < (bp - fallbackPosition).Magnitude
        end)
    end

    if not SliceHubIsPremium() then
        local freeTargets, projectedCount =
            V9RaidCombat.FreeSpearBurstTargets(entries, fallbackPosition)
        return freeTargets, "BASIC PACK STRIKE", projectedCount
    end

    local spearProfile = PROFILE and PROFILE.Spears or {}
    local minimum = math.max(1, math.floor(tonumber(spearProfile.PackMinTargets) or 6))
    local maximum = math.max(minimum, math.floor(tonumber(spearProfile.PackMaxTargets) or 16))

    for _, entry in ipairs(entries) do
        local part = entry.Titan and (V9RaidCombat.ExactNape(entry.Titan) or entry.Part) or entry.Part
        if part and part.Parent then
            targets[#targets + 1] = part
            if #targets >= maximum then break end
        end
    end

    -- When six or more Titans remain, Premium always commits at least six exact
    -- weak-point registers. With fewer than six alive, it cleans the survivors.
    local plannedCount = #targets
    if #entries >= minimum then
        plannedCount = math.max(minimum, plannedCount)
    end

    return targets, "ADVANCED PACK STRIKE", math.min(maximum, plannedCount)
end

function V9RaidCombat.ResolveBurstPosition(target, fallbackPosition)
    if typeof(target) == "Instance" and target:IsA("BasePart") and target.Parent then
        return target.Position
    end
    if typeof(target) == "Vector3" then return target end
    return fallbackPosition
end

V35Spears = V35Spears or {
    Busy = false,
    NextFireAt = 0,
    Shots = 0,
    Serial = 0,
    LastRipperSerial = 0,
    LastPack = 0,
    LastTarget = nil,
    LastSpearName = nil,
    LastStatus = "Idle",
    LastError = nil,
    LastShotAt = 0,
}

function V35Spears.GetRemotes()
    local replicatedStorage = game:GetService("ReplicatedStorage")
    local assets = replicatedStorage:FindFirstChild("Assets")
    local remotes = assets and assets:FindFirstChild("Remotes")

    return
        remotes and remotes:FindFirstChild("GET"),
        remotes and remotes:FindFirstChild("POST")
end


function V35Spears.DirectReload(station)
    local _, postRemote = V35Spears.GetRemotes()

    if not postRemote or not postRemote:IsA("RemoteEvent") then
        V35Spears.LastStatus = "Reload POST missing"
        return false
    end

    local ok, err = pcall(function()
        postRemote:FireServer(
            "Attacks",
            "Reload",
            station
        )
    end)

    if not ok then
        V35Spears.LastError = tostring(err)
        V35Spears.LastStatus = "Direct reload failed"
        return false
    end

    V35Spears.LastStatus = "Station reload sent"
    return true
end

function V35Spears.IsEquipped()
    return player and player:GetAttribute("Weapon") == "Spears"
end

function V35Spears.LiveCharacter()
    local live = player and player.Character or nil
    if live and live.Parent then return live end
    if character and character.Parent then return character end
    return nil
end

function V35Spears.CountAvailableSpearObjects(liveCharacter)
    liveCharacter = liveCharacter or V35Spears.LiveCharacter()
    if not liveCharacter then return nil end

    local sawNumbered = false
    local available = 0

    for _, object in ipairs(liveCharacter:GetDescendants()) do
        if object.Name == "Spears" then
            for _, spear in ipairs(object:GetChildren()) do
                if tonumber(spear.Name) then
                    sawNumbered = true
                    local used = spear:GetAttribute("Used") == true
                    local visible = true
                    pcall(function()
                        if spear:IsA("BasePart") then visible = spear.Transparency < 1 end
                    end)
                    if not used and visible then available += 1 end
                end
            end
        end
    end

    return sawNumbered and available or nil
end

function V35Spears.ReadAmmo()
    local liveCharacter = V35Spears.LiveCharacter()
    if not liveCharacter then return nil end

    local attributeAmmo = tonumber(liveCharacter:GetAttribute("Spears"))
    local objectAmmo = V35Spears.CountAvailableSpearObjects(liveCharacter)

    if attributeAmmo == nil then return objectAmmo end
    if objectAmmo == nil then return attributeAmmo end

    -- The HUD and refill engine now share one conservative source. During Female
    -- transitions the old Character reference could survive briefly with stale ammo;
    -- numbered live spear objects provide a lower bound that catches that state.
    return math.max(0, math.min(attributeAmmo, objectAmmo))
end


function V35Spears.ReadCapacity()
    local liveCharacter = V35Spears.LiveCharacter()
    if not liveCharacter then return nil end

    local value = tonumber(liveCharacter:GetAttribute("Max_Spears"))
    if value and value > 0 then
        return math.floor(value + 0.5)
    end

    return nil
end

function V35Spears.FindAvailableSpearName()
    local liveCharacter = V35Spears.LiveCharacter()
    if not liveCharacter then return nil end

    local candidates = {}

    for _, object in ipairs(liveCharacter:GetDescendants()) do
        if object.Name == "Spears" then
            for _, spear in ipairs(object:GetChildren()) do
                local numericName = tonumber(spear.Name)

                if numericName then
                    local used = spear:GetAttribute("Used") == true
                    local visible = true

                    pcall(function()
                        if spear:IsA("BasePart") then
                            visible = spear.Transparency < 1
                        end
                    end)

                    if State.SpearInfiniteEnabled == true or (not used and visible) then
                        table.insert(candidates, {
                            Number = numericName,
                            Name = spear.Name,
                        })
                    end
                end
            end
        end
    end

    table.sort(candidates, function(a, b)
        return a.Number < b.Number
    end)

    return candidates[1] and candidates[1].Name or nil
end

V36PackDrain = V36PackDrain or {
    Center = nil,
    AnchorPart = nil,
    PackCount = 0,
    ShotsOnPack = 0,
    Misses = 0,
    ObservedKillCap = 3,
    LastKills = 0,
    LastGlobalAlive = 0,
    Serial = 0,
}

function V35Spears.GetGlobalEntries()
    local entries = {}
    local titansFolder = Workspace:FindFirstChild(Config.TitansFolderName)

    if not titansFolder then
        return entries
    end

    for _, titan in ipairs(titansFolder:GetChildren()) do
        if isTitanAlive(titan)
            and (
                not V4RaidDirector
                or not V4RaidDirector.AllowTitanTarget
                or V4RaidDirector.AllowTitanTarget(titan)
            ) then

            local part = getTitanTargetPart(titan)

            if part and part.Parent then
                entries[#entries + 1] = {
                    Titan = titan,
                    Part = part,
                }
            end
        end
    end

    return entries
end

function V35Spears.GlobalAliveCount()
    return #V35Spears.GetGlobalEntries()
end

function V35Spears.PackMembersNear(center, radius)
    if typeof(center) ~= "Vector3" then
        return {}
    end

    local entries = V35Spears.GetGlobalEntries()
    local members = {}
    local radiusSquared = math.max(10, tonumber(radius) or 95) ^ 2

    for _, entry in ipairs(entries) do
        local part = entry.Part

        if part and part.Parent then
            local delta = part.Position - center

            if delta:Dot(delta) <= radiusSquared then
                members[#members + 1] = entry
            end
        end
    end

    return members
end

function V35Spears.CenterForMembers(members)
    if type(members) ~= "table" or #members == 0 then
        return nil, nil
    end

    if #members <= 2 then
        local part = members[1] and members[1].Part
        return part and part.Position or nil, part
    end

    local sum = Vector3.zero

    for _, entry in ipairs(members) do
        sum += entry.Part.Position
    end

    local center = sum / #members
    local nearestPart = nil
    local nearestDistance = math.huge

    for _, entry in ipairs(members) do
        local delta = entry.Part.Position - center
        local distanceSquared = delta:Dot(delta)

        if distanceSquared < nearestDistance then
            nearestDistance = distanceSquared
            nearestPart = entry.Part
        end
    end

    return center, nearestPart
end

function V35Spears.SelectBestGlobalPack()
    if V4RaidDirector and V4RaidDirector.PreferredBossPart then
        local bossTitan, bossPart =
            V4RaidDirector.PreferredBossPart()

        if bossTitan and bossPart then
            return bossPart.Position, bossPart, 1
        end
    end

    local entries = V35Spears.GetGlobalEntries()

    if #entries == 0 then
        return nil, nil, 0
    end

    local radius = math.max(10, tonumber(Config.SpearClusterRadius) or 95)
    local radiusSquared = radius * radius
    local bestMembers = nil
    local bestCount = 0
    local bestCompactness = math.huge

    for _, anchor in ipairs(entries) do
        local anchorPart = anchor.Part

        if anchorPart and anchorPart.Parent then
            local members = {}
            local compactness = 0

            for _, candidate in ipairs(entries) do
                local part = candidate.Part

                if part and part.Parent then
                    local delta = part.Position - anchorPart.Position
                    local distanceSquared = delta:Dot(delta)

                    if distanceSquared <= radiusSquared then
                        members[#members + 1] = candidate
                        compactness += distanceSquared
                    end
                end
            end

            local count = #members
            local averageCompactness =
                count > 0 and (compactness / count) or math.huge

            if count > bestCount
                or (count == bestCount and averageCompactness < bestCompactness) then

                bestMembers = members
                bestCount = count
                bestCompactness = averageCompactness
            end
        end
    end

    local center, part = V35Spears.CenterForMembers(bestMembers)

    return center, part, bestCount
end

function V35Spears.ClearDrainPack(reason)
    V36PackDrain.Center = nil
    V36PackDrain.AnchorPart = nil
    V36PackDrain.PackCount = 0
    V36PackDrain.ShotsOnPack = 0
    V36PackDrain.Misses = 0
    V36PackDrain.Serial += 1

    if reason then
        V35Spears.LastStatus = "Rescan: " .. tostring(reason)
    end
end

function V35Spears.ResolveDrainPack()
    local radius = math.max(10, tonumber(Config.SpearClusterRadius) or 95)

    if V4RaidDirector and V4RaidDirector.HardBossLock then
        local bossTitan, bossPart = V4RaidDirector.HardBossLock()
        if bossTitan and bossPart then
            V36PackDrain.Center = bossPart.Position
            V36PackDrain.AnchorPart = bossPart
            V36PackDrain.PackCount = 1
            V36PackDrain.Misses = 0
            V35Spears.LastStatus = "Boss Drain Lock: " .. tostring(bossTitan.Name)
            return bossPart.Position, bossPart, 1
        end
    end

    if typeof(V36PackDrain.Center) == "Vector3" then
        local members = V35Spears.PackMembersNear(V36PackDrain.Center, radius)

        if #members > 0 and V36PackDrain.Misses < 2 then
            local center, part = V35Spears.CenterForMembers(members)

            V36PackDrain.Center = center or V36PackDrain.Center
            V36PackDrain.AnchorPart = part or V36PackDrain.AnchorPart
            V36PackDrain.PackCount = #members

            return
                V36PackDrain.Center,
                V36PackDrain.AnchorPart,
                V36PackDrain.PackCount
        end

        V35Spears.ClearDrainPack(
            #members == 0 and "pack drained" or "pack not responding"
        )
    end

    local center, part, count = V35Spears.SelectBestGlobalPack()

    V36PackDrain.Center = center
    V36PackDrain.AnchorPart = part
    V36PackDrain.PackCount = tonumber(count) or 0
    V36PackDrain.ShotsOnPack = 0
    V36PackDrain.Misses = 0
    V36PackDrain.Serial += 1

    return center, part, tonumber(count) or 0
end

function V35Spears.AfterDrainShot(targetPosition, previousPackCount, aliveBefore)
    task.wait(math.max(0.01, tonumber(PROFILE.Spears.PostShotSettle) or 0.08))

    local aliveAfter = V35Spears.GlobalAliveCount()
    local kills = math.max(
        0,
        (tonumber(aliveBefore) or aliveAfter) - aliveAfter
    )

    V36PackDrain.LastKills = kills
    V36PackDrain.LastGlobalAlive = aliveAfter
    V36PackDrain.ShotsOnPack += 1

    if kills > 0 then
        V36PackDrain.ObservedKillCap = math.max(
            tonumber(V36PackDrain.ObservedKillCap) or 3,
            kills
        )
        V36PackDrain.Misses = 0
    else
        V36PackDrain.Misses += 1
    end

    if V4RaidDirector and V4RaidDirector.HardBossLock then
        local bossTitan, bossPart = V4RaidDirector.HardBossLock()
        if bossTitan and bossPart then
            V36PackDrain.Center = bossPart.Position
            V36PackDrain.AnchorPart = bossPart
            V36PackDrain.PackCount = 1
            V36PackDrain.Misses = 0
            V35Spears.LastStatus =
                "Boss Drain Lock | last global kills " .. tostring(kills)
            return
        end
    end

    local radius = math.max(10, tonumber(Config.SpearClusterRadius) or 95)
    local remaining = V35Spears.PackMembersNear(
        V36PackDrain.Center or targetPosition,
        radius
    )

    V36PackDrain.PackCount = #remaining

    if #remaining <= 0 then
        V35Spears.ClearDrainPack("pack drained")
    elseif V36PackDrain.Misses >= 2 then
        V35Spears.ClearDrainPack("two no-kill blasts")
    else
        local center, part = V35Spears.CenterForMembers(remaining)

        V36PackDrain.Center = center or V36PackDrain.Center
        V36PackDrain.AnchorPart = part or V36PackDrain.AnchorPart

        V35Spears.LastStatus = string.format(
            "Drain pack %d | last kills %d | cap≥%d",
            #remaining,
            kills,
            tonumber(V36PackDrain.ObservedKillCap) or 3
        )
    end
end

function V35Spears.GetBestCluster()
    local center, part, count = V35Spears.ResolveDrainPack()

    V35Spears.LastPack = tonumber(count) or 0
    V35Spears.LastTarget = center

    return center, part, tonumber(count) or 0
end

function V35Spears.ShouldRun()
    if V577StallEngine and V577StallEngine.OwnsCombat and V577StallEngine.OwnsCombat() then
        return false
    end
    if V4RaidDirector
        and V4RaidDirector.ShouldPauseCombat
        and V4RaidDirector.ShouldPauseCombat() then
        return false
    end

    return State
        and State.FarmEnabled == true
        and State.SpearSupportEnabled == true
        and State.SpearAutoFireEnabled ~= false
        and V35Spears.IsEquipped()
end

function V35Spears.FireDirect(targetPosition, packCount, burstTargets, burstLabel)
    local isBossBurst = string.find(tostring(burstLabel or ""), "BOSS", 1, true) ~= nil

    if not isBossBurst then
        local spearProfile = PROFILE and PROFILE.Spears or {}
        local maximum = math.max(
            1,
            math.floor(tonumber(spearProfile.PackMaxTargets)
                or (SliceHubIsPremium() and 16 or 4))
        )

        if type(burstTargets) ~= "table" or #burstTargets == 0 then
            V35Spears.LastStatus = SliceHubIsPremium()
                and "ADVANCED PACK • waiting for targets"
                or "BASIC PACK • waiting for exact targets"
            return false, "no planned pack targets"
        end

        while #burstTargets > maximum do
            table.remove(burstTargets)
        end

        packCount = math.min(math.max(1, tonumber(packCount) or #burstTargets), maximum)
    end

    if V4RaidDirector
        and V4RaidDirector.ShouldPauseCombat
        and V4RaidDirector.ShouldPauseCombat() then
        V35Spears.LastStatus = "Paused for raid transition"
        return false, "raid transition"
    end

    if V35Spears.Busy then
        return false, "busy"
    end

    local now = os.clock()
    if now < (V35Spears.NextFireAt or 0) then
        return false, "cooldown"
    end

    if typeof(targetPosition) ~= "Vector3" then
        return false, "invalid target"
    end

    local ammo = V35Spears.ReadAmmo()

    if State.SpearInfiniteEnabled ~= true
        and ammo ~= nil
        and State.SpearAutoRefillEnabled
        and ammo <= 1 then
        V35Spears.LastStatus = "Holding last spear — safety refill"
        return false, "refill safety"
    end

    if State.SpearInfiniteEnabled ~= true and ammo ~= nil and ammo <= 0 then
        V35Spears.LastStatus = "Empty — refill pending"
        return false, "empty"
    end

    local spearName = V35Spears.FindAvailableSpearName()
    if not spearName then
        V35Spears.LastStatus = "No available spear object"
        return false, "no spear"
    end

    local getRemote, postRemote = V35Spears.GetRemotes()
    if not getRemote or not getRemote:IsA("RemoteFunction") then
        V35Spears.LastStatus = "GET remote missing"
        return false, "GET missing"
    end
    if not postRemote or not postRemote:IsA("RemoteEvent") then
        V35Spears.LastStatus = "POST remote missing"
        return false, "POST missing"
    end

    local aliveBeforeShot = V35Spears.GlobalAliveCount()

    V35Spears.Busy = true
    V35Spears.LastStatus = "Arming spear " .. tostring(spearName)
    V35Spears.LastError = nil
    V35Spears.LastSpearName = spearName

    task.spawn(function()
        local okFire, fired = pcall(function()
            return getRemote:InvokeServer("Spears", "S_Fire", tostring(spearName))
        end)

        if not okFire or fired ~= true then
            V35Spears.LastError = okFire and "S_Fire rejected" or tostring(fired)
            V35Spears.LastStatus = "S_Fire failed"
            V35Spears.NextFireAt = os.clock() + 0.35
            V35Spears.Busy = false
            return
        end

        local armedStart = os.clock()
        while character
            and character.Parent
            and character:GetAttribute("Current_Spear") == nil
            and os.clock() - armedStart < (tonumber(Config.SpearArmTimeout) or 0.60) do
            task.wait(0.01)
        end

        -- Raid traces consistently place the first explosion roughly 0.10-0.12s
        -- after accepted S_Fire, then fan the whole burst with no scheduler wait.
        task.wait(math.max(
            0.03,
            tonumber(Config.V9SpearArmDelay)
            or tonumber(Config.SpearExplodeDelay)
            or 0.105
        ))

        local targets = type(burstTargets) == "table" and burstTargets or {}
        if #targets == 0 then targets = {targetPosition} end

        local sent = 0
        local firstPosition = nil
        local okExplode, explodeErr = pcall(function()
            for _, burstTarget in ipairs(targets) do
                local explodePosition = V9RaidCombat
                    and V9RaidCombat.ResolveBurstPosition
                    and V9RaidCombat.ResolveBurstPosition(burstTarget, targetPosition)
                    or targetPosition

                if typeof(explodePosition) == "Vector3" then
                    firstPosition = firstPosition or explodePosition
                    postRemote:FireServer("Spears", "S_Explode", explodePosition)
                    sent += 1
                end
            end
        end)

        if not okExplode or sent <= 0 then
            V35Spears.LastError = tostring(explodeErr or "no valid burst target")
            V35Spears.LastStatus = "S_Explode burst failed"
            V35Spears.NextFireAt = os.clock() + 0.35
            V35Spears.Busy = false
            return
        end

        V35Spears.Shots += 1
        V35Spears.Serial += 1
        V35Spears.LastShotAt = os.clock()
        V35Spears.LastPack = tonumber(packCount) or V35Spears.LastPack
        V35Spears.LastBurstCount = sent
        V35Spears.LastStatus = string.format(
            "%s • EXPLODE x%d",
            tostring(burstLabel or "V9 BURST"),
            sent
        )

        if V9RaidCombat then
            V9RaidCombat.LastSpearExplodes = sent
            V9RaidCombat.SpearMode = tostring(burstLabel or "V9 BURST")
            if string.find(V9RaidCombat.SpearMode, "BOSS", 1, true) then
                V9RaidCombat.BossSpearShots += 1
            else
                V9RaidCombat.PackSpearShots += 1
            end
        end

        local confirmStart = os.clock()
        while character
            and character.Parent
            and character:GetAttribute("Current_Spear") ~= nil
            and os.clock() - confirmStart
                < (tonumber(Config.SpearPostExplodeConfirmTimeout) or 0.45) do
            task.wait(0.015)
        end

        V35Spears.AfterDrainShot(
            firstPosition or targetPosition,
            tonumber(packCount) or 0,
            aliveBeforeShot
        )

        local directorMode = V56SpearDirector and V56SpearDirector.Mode or "PACK SWEEP"
        local directorCooldown = V56SpearDirector and V56SpearDirector.CooldownForMode
            and V56SpearDirector.CooldownForMode(directorMode)
            or math.max(0.12, tonumber(Config.SpearFireCooldown) or 0.24)
        V35Spears.NextFireAt = os.clock() + directorCooldown
        V35Spears.Busy = false
    end)

    return true, spearName
end


---------------------------------------------------------------------
-- V5.6 SPEAR ENGINE V2 DIRECTOR
-- Modes:
--   PACK SWEEP       : build multiple packs and rotate by angle around player.
--   OBJECTIVE DEFENSE: barrage packs threatening boats / Eren objective anchors.
--   BOSS BURST       : exact live raid boss weak point, refreshed every shot.
--   CANNON HOLD      : Colossal P1 remains cannon-owned unless defense mode opens.
---------------------------------------------------------------------

V56SpearDirector = V56SpearDirector or {
    Mode = "PACK SWEEP",
    Queue = {},
    QueueIndex = 1,
    QueueBuiltAt = 0,
    QueueLifetime = tonumber(PROFILE.Spears.QueueLifetime) or 0.45,
    QueueMode = nil,
    MaxPacks = tonumber(PROFILE.Spears.MaxPacks) or 10,
    PackRadius = tonumber(PROFILE.Spears.ClusterRadius) or 95,
    LastTargetLabel = "none",
    LastQueueSize = 0,
    SweepSerial = 0,
    BossShots = 0,
    DefenseShots = 0,
    PackShots = 0,
    SurvivorThreshold = 5,
    SurvivorTarget = nil,
    SurvivorPart = nil,
    SurvivorShots = 0,
    SurvivorLastShotAt = 0,
    SurvivorLastHealth = nil,
    SurvivorLastAlive = nil,
    SurvivorBlacklist = setmetatable({}, {__mode = "k"}),
    SurvivorRotations = 0,
    SurvivorPartIndex = 1,
    TravelHeight = 520,
    TravelMinDistance = 70,
    TravelCooldown = tonumber(PROFILE.Spears.TravelCooldown) or 0.075,
    LastTravelAt = 0,
    LastTravelPosition = nil,
}

function V56SpearDirector.RootPosition()
    local live = V35Spears.LiveCharacter()
    local root = live and live:FindFirstChild("HumanoidRootPart")
    return root and root.Position or nil
end

function V56SpearDirector.ObjectiveAnchors()
    local anchors = {}

    if V4RaidDirector
        and V4RaidDirector.RaidName == "Colossal Raid"
        and V55ColossalDirector
        and V55ColossalDirector.ResolveErenAnchor then
        local ok, anchor = pcall(V55ColossalDirector.ResolveErenAnchor, false)
        if ok and typeof(anchor) == "Vector3" then
            anchors[#anchors + 1] = anchor
        end
    end

    if #anchors == 0
        and V4RaidDirector
        and V4RaidDirector.RefreshObjectiveAnchors then
        local ok, values = pcall(V4RaidDirector.RefreshObjectiveAnchors, false)
        if ok and type(values) == "table" then
            for _, value in ipairs(values) do
                if typeof(value) == "Vector3" then
                    anchors[#anchors + 1] = value
                end
            end
        end
    end

    return anchors
end

function V56SpearDirector.DistanceToAnchors(position, anchors)
    if typeof(position) ~= "Vector3" then return math.huge end
    if type(anchors) ~= "table" or #anchors == 0 then return 0 end

    local best = math.huge
    for _, anchor in ipairs(anchors) do
        if typeof(anchor) == "Vector3" then
            best = math.min(best, (position - anchor).Magnitude)
        end
    end
    return best
end

function V56SpearDirector.ResolveMode()
    -- V9.4.3: Colossal P2 is always boss-lane movement. Eren defense is appended
    -- inside the same BOSS BURST payload, so Guardian state never pulls the
    -- character away from Bertholdt or turns the whole shot into add-only damage.
    if V4RaidDirector
        and V4RaidDirector.RaidName == "Colossal Raid"
        and V55ColossalDirector
        and V55ColossalDirector.Stage == "P2 BOSS" then
        local bossTitan, bossPart = nil, nil
        if V9RaidCombat and V9RaidCombat.LiveBoss then
            bossTitan, bossPart = V9RaidCombat.LiveBoss()
        end
        if bossTitan and bossPart and bossPart.Parent then
            return "BOSS BURST", bossTitan, bossPart
        end
        return "BOSS BURST", nil, nil
    end

    if V4RaidDirector and V4RaidDirector.HardBossLock then
        local bossTitan, bossPart = V4RaidDirector.HardBossLock()
        if bossTitan and bossPart and bossPart.Parent then
            return "BOSS BURST", bossTitan, bossPart
        end
    end

    if V4RaidDirector and V4RaidDirector.Enabled then
        if V4RaidDirector.RaidName == "Colossal Raid"
            and V4RaidDirector.Phase == "P1 Objective" then
            local defense = V55ColossalDirector
                and V55ColossalDirector.DefenseMode == true
            return defense and "OBJECTIVE DEFENSE" or "CANNON HOLD"
        end

        if V4RaidDirector.Phase == "P1 Objective"
            and (V4RaidDirector.RaidName == "Armored Raid"
                or V4RaidDirector.RaidName == "Attack Raid") then
            return "OBJECTIVE DEFENSE"
        end
    end

    return "PACK SWEEP"
end

function V56SpearDirector.BuildPacks(entries, mode)
    if type(entries) ~= "table" or #entries == 0 then return {} end

    local radius = math.max(30, tonumber(Config.SpearClusterRadius) or V56SpearDirector.PackRadius)
    local radiusSquared = radius * radius
    local anchors = mode == "OBJECTIVE DEFENSE" and V56SpearDirector.ObjectiveAnchors() or {}
    local source = {}

    for _, entry in ipairs(entries) do
        local part = entry.Part
        if part and part.Parent then
            local allowed = true
            if mode == "OBJECTIVE DEFENSE" and #anchors > 0 then
                local defenseRadius = 340
                if V4RaidDirector
                    and V4RaidDirector.RaidName == "Colossal Raid"
                    and V55ColossalDirector
                    and V55ColossalDirector.Stage == "P2 BOSS" then
                    defenseRadius = 300
                end
                allowed = V56SpearDirector.DistanceToAnchors(part.Position, anchors) <= defenseRadius
            end
            if allowed then source[#source + 1] = entry end
        end
    end

    if #source == 0 then return {} end

    local candidatePacks = {}
    for _, seed in ipairs(source) do
        local members = {}
        local compactness = 0
        local seedPos = seed.Part.Position

        for _, candidate in ipairs(source) do
            local part = candidate.Part
            if part and part.Parent then
                local delta = part.Position - seedPos
                local d2 = delta:Dot(delta)
                if d2 <= radiusSquared then
                    members[#members + 1] = candidate
                    compactness += d2
                end
            end
        end

        local center, anchorPart = V35Spears.CenterForMembers(members)
        if center and anchorPart then
            candidatePacks[#candidatePacks + 1] = {
                Center = center,
                Part = anchorPart,
                Members = members,
                Count = #members,
                Compactness = #members > 0 and compactness / #members or math.huge,
                ObjectiveDistance = V56SpearDirector.DistanceToAnchors(center, anchors),
            }
        end
    end

    table.sort(candidatePacks, function(a, b)
        if mode == "OBJECTIVE DEFENSE" and a.ObjectiveDistance ~= b.ObjectiveDistance then
            return a.ObjectiveDistance < b.ObjectiveDistance
        end
        if a.Count ~= b.Count then return a.Count > b.Count end
        return a.Compactness < b.Compactness
    end)

    local selected = {}
    local assigned = {}
    local maxPacks = math.max(1, tonumber(V56SpearDirector.MaxPacks) or 10)

    for _, pack in ipairs(candidatePacks) do
        local freshMembers = {}
        for _, member in ipairs(pack.Members) do
            if member.Titan and not assigned[member.Titan] then
                freshMembers[#freshMembers + 1] = member
            end
        end

        if #freshMembers > 0 then
            local center, part = V35Spears.CenterForMembers(freshMembers)
            if center and part then
                selected[#selected + 1] = {
                    Center = center,
                    Part = part,
                    Members = freshMembers,
                    Count = #freshMembers,
                    ObjectiveDistance = V56SpearDirector.DistanceToAnchors(center, anchors),
                }
                for _, member in ipairs(freshMembers) do
                    assigned[member.Titan] = true
                end
                if #selected >= maxPacks then break end
            end
        end
    end

    -- Spiral sweep ordering: once packs are chosen by value, walk around the
    -- battlefield in angular order instead of bouncing randomly left/right.
    local rootPosition = V56SpearDirector.RootPosition()
    if mode == "PACK SWEEP" and typeof(rootPosition) == "Vector3" then
        table.sort(selected, function(a, b)
            local da = a.Center - rootPosition
            local db = b.Center - rootPosition
            local aa = math.atan2(da.Z, da.X)
            local ab = math.atan2(db.Z, db.X)
            return aa < ab
        end)
    end

    return selected
end

function V56SpearDirector.RebuildQueue(mode)
    local entries = V35Spears.GetGlobalEntries()
    local queue = V56SpearDirector.BuildPacks(entries, mode)

    V56SpearDirector.Queue = queue
    V56SpearDirector.QueueIndex = 1
    V56SpearDirector.QueueBuiltAt = os.clock()
    V56SpearDirector.QueueMode = mode
    V56SpearDirector.LastQueueSize = #queue
    V56SpearDirector.SweepSerial += 1

    return queue
end

function V56SpearDirector.ResolvePackTarget(pack)
    if type(pack) ~= "table" then return nil, 0 end

    local liveMembers = {}
    for _, member in ipairs(pack.Members or {}) do
        local titan = member.Titan
        if titan and titan.Parent and isTitanAlive(titan)
            and (not V4RaidDirector
                or not V4RaidDirector.AllowTitanTarget
                or V4RaidDirector.AllowTitanTarget(titan)) then
            local part = getTitanTargetPart(titan)
            if part and part.Parent then
                liveMembers[#liveMembers + 1] = {Titan = titan, Part = part}
            end
        end
    end

    if #liveMembers == 0 then return nil, 0 end
    local center, part = V35Spears.CenterForMembers(liveMembers)
    pack.Center = center or pack.Center
    pack.Part = part or pack.Part
    pack.Members = liveMembers
    pack.Count = #liveMembers
    return pack.Center, pack.Count
end

function V56SpearDirector.NextPack(mode)
    local now = os.clock()
    local queue = V56SpearDirector.Queue

    if V56SpearDirector.QueueMode ~= mode
        or type(queue) ~= "table"
        or #queue == 0
        or now - (V56SpearDirector.QueueBuiltAt or 0) >= V56SpearDirector.QueueLifetime then
        queue = V56SpearDirector.RebuildQueue(mode)
    end

    if #queue == 0 then return nil, 0 end

    local attempts = #queue
    while attempts > 0 do
        if V56SpearDirector.QueueIndex > #queue then
            V56SpearDirector.QueueIndex = 1
        end

        local pack = queue[V56SpearDirector.QueueIndex]
        V56SpearDirector.QueueIndex += 1
        local center, count = V56SpearDirector.ResolvePackTarget(pack)
        if center and count > 0 then
            return center, count
        end
        attempts -= 1
    end

    V56SpearDirector.RebuildQueue(mode)
    return nil, 0
end

function V56SpearDirector.TitanHealth(titan)
    if not titan or not titan.Parent then return nil end
    local humanoid = titan:FindFirstChildOfClass("Humanoid")
    return humanoid and tonumber(humanoid.Health) or nil
end

function V56SpearDirector.SurvivorBlacklisted(titan)
    local expiry = V56SpearDirector.SurvivorBlacklist[titan]
    if not expiry then return false end
    if os.clock() >= expiry then
        V56SpearDirector.SurvivorBlacklist[titan] = nil
        return false
    end
    return true
end

function V56SpearDirector.ResetSurvivorTarget(reason)
    V56SpearDirector.SurvivorTarget = nil
    V56SpearDirector.SurvivorPart = nil
    V56SpearDirector.SurvivorShots = 0
    V56SpearDirector.SurvivorLastShotAt = 0
    V56SpearDirector.SurvivorLastHealth = nil
    V56SpearDirector.SurvivorLastAlive = nil
    V56SpearDirector.SurvivorPartIndex = 1
    if reason then V56SpearDirector.LastTargetLabel = tostring(reason) end
end

function V56SpearDirector.ResolveSurvivorPart(titan)
    if not titan or not titan.Parent then return nil end
    local order = {"Nape", "UpperTorso", "HumanoidRootPart", "Torso", "Head", "LowerTorso"}
    local startIndex = math.clamp(math.floor(tonumber(V56SpearDirector.SurvivorPartIndex) or 1), 1, #order)

    for offset = 0, #order - 1 do
        local index = ((startIndex + offset - 1) % #order) + 1
        local part = titan:FindFirstChild(order[index], true)
        if part and part:IsA("BasePart") and part.Parent then
            V56SpearDirector.SurvivorPartIndex = index
            return part
        end
    end

    return getTitanTargetPart(titan)
end

function V56SpearDirector.AdvanceSurvivorPart()
    local count = 6
    V56SpearDirector.SurvivorPartIndex = ((math.floor(tonumber(V56SpearDirector.SurvivorPartIndex) or 1)) % count) + 1
end

function V56SpearDirector.FastTravel(targetPosition, mode)
    if typeof(targetPosition) ~= "Vector3" then return false end
    if not character or not character.Parent or not rootPart or not humanoid or humanoid.Health <= 0 then return false end
    if V577MovementAuthority and not V577MovementAuthority.CanMove("NORMAL") then
        return false
    end

    local colossalMountedDefense = V55ColossalDirector
        and V4RaidDirector
        and V4RaidDirector.RaidName == "Colossal Raid"
        and V55ColossalDirector.Stage == "P1 CANNON STALL"
        and V55ColossalDirector.DefenseMode == true
        and V55ColossalDirector.Entered == true

    if mode == "CANNON HOLD" or colossalMountedDefense then
        return false
    end

    local now = os.clock()
    if now - (tonumber(V56SpearDirector.LastTravelAt) or 0)
        < math.max(0.03, tonumber(V56SpearDirector.TravelCooldown) or 0.075) then
        return false
    end

    local height = math.max(
        tonumber(Config.SpearSkyHeight) or 430,
        tonumber(V56SpearDirector.TravelHeight) or 520
    )
    local desired = targetPosition + Vector3.new(0, height, 0)
    if V4RaidDirector
        and V4RaidDirector.RaidName == "Colossal Raid"
        and V55ColossalDirector
        and V55ColossalDirector.Stage == "P2 BOSS"
        and mode == "BOSS BURST" then
        local glass = V55ColossalDirector.IsGlassCannonProfile and V55ColossalDirector.IsGlassCannonProfile()
        height = math.max(height, glass and 940 or 780)
        local radial = rootPart.Position - targetPosition
        radial = Vector3.new(radial.X, 0, radial.Z)
        if radial.Magnitude < 20 then radial = Vector3.new(1, 0, 0) end
        local lateral = glass and 560 or 420
        desired = targetPosition + radial.Unit * lateral + Vector3.new(0, height, 0)
    elseif V4RaidDirector
        and V4RaidDirector.RaidName == "Colossal Raid"
        and V55ColossalDirector
        and V55ColossalDirector.IsGlassCannonProfile
        and V55ColossalDirector.IsGlassCannonProfile() then
        height = math.max(height, 760)
        desired = targetPosition + Vector3.new(0, height, 0)
    end
    local distance = (rootPart.Position - desired).Magnitude
    if distance < math.max(20, tonumber(V56SpearDirector.TravelMinDistance) or 70) then
        return false
    end

    CombatAnchorRuntime.Position = desired
    CombatAnchorRuntime.GroundCenter = targetPosition
    CombatAnchorRuntime.AimPosition = targetPosition
    CombatAnchorRuntime.TargetCount = 1
    CombatAnchorRuntime.InitialResidents = 1
    CombatAnchorRuntime.LastRefresh = now
    CombatAnchorRuntime.LastCommit = now

    character:PivotTo(CFrame.lookAt(desired, targetPosition))
    rootPart.AssemblyAngularVelocity = Vector3.zero
    rootPart.AssemblyLinearVelocity = Vector3.zero

    V56SpearDirector.LastTravelAt = now
    V56SpearDirector.LastTravelPosition = targetPosition
    return true
end

function V56SpearDirector.PickSurvivor(entries)
    entries = type(entries) == "table" and entries or V35Spears.GetGlobalEntries()
    local now = os.clock()
    local aliveCount = #entries
    local current = V56SpearDirector.SurvivorTarget

    if current and current.Parent and isTitanAlive(current)
        and not V56SpearDirector.SurvivorBlacklisted(current) then
        local part = V56SpearDirector.ResolveSurvivorPart(current)
        local health = V56SpearDirector.TitanHealth(current)
        local lastHealth = tonumber(V56SpearDirector.SurvivorLastHealth)
        local lastAlive = tonumber(V56SpearDirector.SurvivorLastAlive)
        local shotAge = now - (tonumber(V56SpearDirector.SurvivorLastShotAt) or 0)

        if health and lastHealth and health < lastHealth then
            V56SpearDirector.SurvivorShots = 0
        elseif lastAlive and aliveCount < lastAlive then
            V56SpearDirector.SurvivorShots = 0
        elseif V56SpearDirector.SurvivorShots >= 3 and shotAge >= 0.45 then
            -- The final 1-5 Titans are often awkward ragdolls or expose a different
            -- damage part. Cycle exact body regions first; only blacklist the model
            -- after several rotations instead of tunneling one stale nape forever.
            V56SpearDirector.AdvanceSurvivorPart()
            V56SpearDirector.SurvivorShots = 0
            V56SpearDirector.SurvivorRotations += 1

            if V56SpearDirector.SurvivorRotations % 6 == 0 then
                V56SpearDirector.SurvivorBlacklist[current] = now + 1.2
                V56SpearDirector.SurvivorTarget = nil
                V56SpearDirector.SurvivorPart = nil
                current = nil
            else
                part = V56SpearDirector.ResolveSurvivorPart(current)
            end
        end

        if current and part and part.Parent then
            V56SpearDirector.SurvivorPart = part
            V56SpearDirector.SurvivorLastHealth = health
            V56SpearDirector.SurvivorLastAlive = aliveCount
            return part.Position, 1, current
        end
    end

    local rootPosition = V56SpearDirector.RootPosition()
    local candidates = {}
    for _, entry in ipairs(entries) do
        local titan = entry.Titan
        local part = titan and V56SpearDirector.ResolveSurvivorPart(titan) or nil
        if titan and part and part.Parent and isTitanAlive(titan)
            and not V56SpearDirector.SurvivorBlacklisted(titan) then
            local health = V56SpearDirector.TitanHealth(titan) or math.huge
            local distance = typeof(rootPosition) == "Vector3"
                and (part.Position - rootPosition).Magnitude or math.huge
            candidates[#candidates + 1] = {
                Titan = titan,
                Part = part,
                Health = health,
                Distance = distance,
            }
        end
    end

    if #candidates == 0 and aliveCount > 0 then
        -- All remaining survivors were briefly blacklisted. Clear the temporary
        -- rotation list and try again rather than idling forever.
        V56SpearDirector.SurvivorBlacklist = setmetatable({}, {__mode = "k"})
        for _, entry in ipairs(entries) do
            local titan = entry.Titan
            local part = titan and V56SpearDirector.ResolveSurvivorPart(titan) or nil
            if titan and part and part.Parent and isTitanAlive(titan) then
                candidates[#candidates + 1] = {
                    Titan = titan,
                    Part = part,
                    Health = V56SpearDirector.TitanHealth(titan) or math.huge,
                    Distance = typeof(rootPosition) == "Vector3"
                        and (part.Position - rootPosition).Magnitude or math.huge,
                }
            end
        end
    end

    table.sort(candidates, function(a, b)
        if a.Health ~= b.Health then return a.Health < b.Health end
        return a.Distance < b.Distance
    end)

    local chosen = candidates[1]
    if not chosen then
        V56SpearDirector.ResetSurvivorTarget("no live survivor")
        return nil, 0, nil
    end

    V56SpearDirector.SurvivorTarget = chosen.Titan
    V56SpearDirector.SurvivorPart = chosen.Part
    V56SpearDirector.SurvivorShots = 0
    V56SpearDirector.SurvivorLastShotAt = 0
    V56SpearDirector.SurvivorLastHealth = chosen.Health
    V56SpearDirector.SurvivorLastAlive = aliveCount
    return chosen.Part.Position, 1, chosen.Titan
end

function V56SpearDirector.Target()
    local mode, bossTitan, bossPart = V56SpearDirector.ResolveMode()
    V56SpearDirector.Mode = mode

    if mode == "CANNON HOLD" then
        V56SpearDirector.LastTargetLabel = "Colossal P1 cannon ownership"
        V56SpearDirector.ResetSurvivorTarget()
        return nil, 0, mode, nil
    end

    if mode == "BOSS BURST" then
        V56SpearDirector.ResetSurvivorTarget()
        if bossTitan and bossPart and bossPart.Parent then
            V56SpearDirector.LastTargetLabel = tostring(bossTitan.Name) .. " / " .. tostring(bossPart.Name)
            return bossPart.Position, 1, mode, bossTitan
        end
        V56SpearDirector.LastTargetLabel = "boss unresolved"
        return nil, 0, mode, nil
    end

    local entries = V35Spears.GetGlobalEntries()
    if #entries > 0 and #entries <= math.max(1, tonumber(V56SpearDirector.SurvivorThreshold) or 5) then
        local position, count, titan = V56SpearDirector.PickSurvivor(entries)
        V56SpearDirector.Mode = "SURVIVOR HUNT"
        V56SpearDirector.LastTargetLabel = titan
            and ("SURVIVOR HUNT • " .. tostring(titan.Name) .. " • " .. tostring(#entries) .. " left")
            or "SURVIVOR HUNT • rescanning"
        return position, count, "SURVIVOR HUNT", titan
    end

    V56SpearDirector.ResetSurvivorTarget()
    local center, count = V56SpearDirector.NextPack(mode)
    V56SpearDirector.LastTargetLabel = center and (mode .. " pack " .. tostring(count)) or "none"
    return center, count, mode, nil
end

function V56SpearDirector.CooldownForMode(mode)
    if mode == "STALL DESTROYER" then return 0.025 end

    -- V9 traces: productive boss spear bursts settle into ~1.0s cadence even
    -- with Infinite Spears enabled, while the accepted shot itself fans x5.
    if mode == "BOSS BURST" then
        return math.max(0.35, tonumber(Config.V9SpearBossCadence) or 1.0)
    end

    if State.SpearInfiniteEnabled == true then
        local base = math.max(0.05, tonumber(PROFILE.Spears.InfiniteCooldown) or 0.10)
        if mode == "SURVIVOR HUNT" then return math.max(0.05, base * 0.85) end
        if mode == "OBJECTIVE DEFENSE" then return math.max(0.05, base * 0.95) end
        return base
    end
    local minimum = SliceHubIsPremium() and 0.06 or 0.45
    return math.max(minimum, tonumber(Config.SpearFireCooldown) or 0.24)
end

function V35Spears.Step()
    if not V35Spears.ShouldRun() then
        return false, 0
    end

    if V91RaidBossGuard and V91RaidBossGuard.Blocked and V91RaidBossGuard.Blocked() then
        V35Spears.LastStatus = "Attack boss roar invulnerability"
        return false, 0
    end

    if V35Spears.Busy then
        return false, V35Spears.LastPack or 0
    end

    local center, packCount, mode, exactTitan = V56SpearDirector.Target()

    if not SliceHubIsPremium() then
        local freeCap = math.max(1, math.floor(tonumber(PROFILE.Spears.KillCap) or 6))
        packCount = math.min(math.max(0, tonumber(packCount) or 0), freeCap)
    end

    if not center or packCount <= 0 then
        V35Spears.LastStatus = mode == "CANNON HOLD"
            and "Colossal P1 cannon ownership"
            or ("Director " .. tostring(mode) .. " waiting for target")
        return false, 0
    end

    if mode == "PACK SWEEP"
        and State.BladesEnabled == true
        and packCount <= 1
        and State.SpearInfiniteEnabled ~= true then
        V35Spears.LastStatus = "Single survivor yielded to blades"
        return false, packCount
    end

    if mode == "BOSS BURST" then
        V56SpearDirector.BossShots += 1
        V35Spears.LastStatus = "BOSS BURST • live weak point • shot " .. tostring(V56SpearDirector.BossShots)
    elseif mode == "SURVIVOR HUNT" then
        V35Spears.LastStatus = "SURVIVOR HUNT • exact nape • " .. tostring(exactTitan and exactTitan.Name or "rescan")
    elseif mode == "OBJECTIVE DEFENSE" then
        V56SpearDirector.DefenseShots += 1
        V35Spears.LastStatus = "DEFENSE BARRAGE • active pack"
    else
        V56SpearDirector.PackShots += 1
        if SliceHubIsPremium() then
            V35Spears.LastStatus = "ADVANCED PACK SWEEP"
        else
            V35Spears.LastStatus = "BASIC PACK TARGET"
        end
    end

    V56SpearDirector.FastTravel(center, mode)

    local burstTargets, burstLabel, plannedCount = V9RaidCombat.BuildSpearBurstTargets(
        mode,
        exactTitan,
        center
    )

    if tonumber(plannedCount) and tonumber(plannedCount) > 0 then
        packCount = tonumber(plannedCount)
    end

    local fired = V35Spears.FireDirect(
        center,
        packCount,
        burstTargets,
        burstLabel
    )
    if fired == true and mode == "SURVIVOR HUNT" then
        V56SpearDirector.SurvivorTarget = exactTitan or V56SpearDirector.SurvivorTarget
        V56SpearDirector.SurvivorShots += 1
        V56SpearDirector.SurvivorLastShotAt = os.clock()
        V56SpearDirector.SurvivorLastHealth = V56SpearDirector.TitanHealth(V56SpearDirector.SurvivorTarget)
        V56SpearDirector.SurvivorLastAlive = V35Spears.GlobalAliveCount()
    end
    return fired == true, packCount
end

function V35Spears.Telemetry()
    local ammo = V35Spears.ReadAmmo()
    local weapon = player and tostring(player:GetAttribute("Weapon") or "Unknown") or "Unknown"
    local pack = V35Spears.LastPack or 0

    return {
        Weapon = weapon,
        Ammo = ammo,
        Pack = pack,
        Busy = V35Spears.Busy,
        Shots = V35Spears.Shots,
        LastKills = V36PackDrain.LastKills or 0,
        ObservedCap = V36PackDrain.ObservedKillCap or 3,
        Status = V35Spears.LastStatus,
    }
end


V35Spears.Refill = V35Spears.Refill or {
    LowSince = nil,
    Armed = true,
    LastAmmo = nil,
    LastAttemptAt = 0,
    MaxObserved = 0,
}

---------------------------------------------------------------------
-- V5.7.8 STALL DESTROYER
-- Exact-member microburst + objective guardian ordering for Loading Docks Stall.
---------------------------------------------------------------------
V577StallEngine = V577StallEngine or {
    Status = "Disabled",
    Shots = 0,
    Waves = 0,
    EstimatedKills = 0,
    ObservedDrops = 0,
    LastAlive = 0,
    Queue = {},
    QueueIndex = 1,
    QueueBuiltAt = 0,
    LastTravelAt = 0,
    LastPackCount = 0,
    LastError = nil,
    BurstIndex = 0,
    BurstCount = 0,
    CurrentPackKey = "",
    ObjectiveAnchors = {},
    ObjectiveAnchorsAt = 0,
    EmergencyThreats = 0,
}

function V577StallEngine.Context()
    local mapName = nil
    local objectiveText = ""
    pcall(function()
        mapName = V3MissionIdentity and V3MissionIdentity.ExactWorkspaceMap and V3MissionIdentity.ExactWorkspaceMap()
            or (V3MissionIdentity and V3MissionIdentity.GetTrackedMissionMap and V3MissionIdentity.GetTrackedMissionMap())
        objectiveText = V4RaidDirector and V4RaidDirector.ObjectiveText and V4RaidDirector.ObjectiveText()
            or (V3MissionIdentity and V3MissionIdentity.CombinedTasksLower and V3MissionIdentity.CombinedTasksLower())
            or ""
    end)
    local stall = string.find(string.lower(tostring(objectiveText or "")), "stall", 1, true) ~= nil
    local raid = V4RaidDirector and V4RaidDirector.Enabled == true
    return mapName, stall, raid
end

function V577StallEngine.ValidMission()
    local mapName, stall, raid = V577StallEngine.Context()
    return mapName == "Loading Docks" and stall == true and raid ~= true
end

function V577StallEngine.OwnsCombat()
    return State
        and State.StallDestroyerEnabled == true
        and V577StallEngine.ValidMission()
        and V35Spears.IsEquipped()
end

function V577StallEngine.IsColossalTitan(titan)
    if not titan or not titan.Parent or not isTitanAlive(titan) then return false end
    local identity = tostring(titan.Name or "")
    pcall(function()
        identity ..= " " .. tostring(titan:GetAttribute("Type") or "")
        identity ..= " " .. tostring(titan:GetAttribute("TitanType") or "")
        identity ..= " " .. tostring(titan:GetAttribute("Variant") or "")
        identity ..= " " .. tostring(titan:GetAttribute("BossName") or "")
    end)
    identity = string.lower(identity)
    if string.find(identity, "colossal", 1, true)
        or string.find(identity, "bertholdt", 1, true)
        or string.find(identity, "bertolt", 1, true) then
        return true
    end

    local scale = 1
    pcall(function() scale = tonumber(titan:GetScale()) or 1 end)
    if scale >= 4.5 then return true end

    local okBox, _, size = pcall(function() return titan:GetBoundingBox() end)
    if okBox and typeof(size) == "Vector3" and size.Y >= 70 then return true end
    return false
end

function V577StallEngine.Entries()
    local entries = {}
    local folder = Workspace:FindFirstChild(Config.TitansFolderName)
    if not folder then return entries end
    for _, titan in ipairs(folder:GetChildren()) do
        if V577StallEngine.IsColossalTitan(titan) then
            local part = titan:FindFirstChild("Nape", true)
                or titan:FindFirstChild("UpperTorso", true)
                or titan:FindFirstChild("HumanoidRootPart", true)
                or getTitanTargetPart(titan)
            if part and part:IsA("BasePart") and part.Parent then
                entries[#entries + 1] = {Titan = titan, Part = part}
            end
        end
    end
    return entries
end

function V577StallEngine.GetObjectiveAnchors(force)
    local now = os.clock()
    if not force and now - (V577StallEngine.ObjectiveAnchorsAt or 0) < 2.0 then
        return V577StallEngine.ObjectiveAnchors or {}
    end
    V577StallEngine.ObjectiveAnchorsAt = now

    local anchors = {}
    local seen = {}
    local titanFolder = Workspace:FindFirstChild(Config.TitansFolderName)
    local checked = 0
    local keywords = {"boat", "ship", "vessel", "dock target", "mission target"}

    for _, object in ipairs(Workspace:GetDescendants()) do
        checked += 1
        if checked > 18000 then break end
        if (object:IsA("Model") or object:IsA("BasePart"))
            and not (titanFolder and object:IsDescendantOf(titanFolder)) then
            local lower = string.lower(tostring(object.Name or ""))
            local matched = false
            for _, keyword in ipairs(keywords) do
                if string.find(lower, keyword, 1, true) then
                    matched = true
                    break
                end
            end
            if matched then
                local owner = object:IsA("Model") and object or object:FindFirstAncestorOfClass("Model") or object
                if not seen[owner] then
                    local position = nil
                    if V4RaidDirector and V4RaidDirector.GetObjectPosition then
                        position = V4RaidDirector.GetObjectPosition(owner)
                    else
                        if owner:IsA("BasePart") then position = owner.Position end
                        if owner:IsA("Model") then
                            local ok, pivot = pcall(function() return owner:GetPivot() end)
                            if ok and pivot then position = pivot.Position end
                        end
                    end
                    if typeof(position) == "Vector3" then
                        seen[owner] = true
                        anchors[#anchors + 1] = position
                    end
                end
            end
        end
    end

    V577StallEngine.ObjectiveAnchors = anchors
    return anchors
end

function V577StallEngine.DistanceToObjective(position, anchors)
    if typeof(position) ~= "Vector3" then return math.huge end
    anchors = type(anchors) == "table" and anchors or V577StallEngine.GetObjectiveAnchors(false)
    if #anchors == 0 then return math.huge end
    local best = math.huge
    for _, anchor in ipairs(anchors) do
        if typeof(anchor) == "Vector3" then
            best = math.min(best, (position - anchor).Magnitude)
        end
    end
    return best
end

function V577StallEngine.BuildQueue(entries)
    entries = type(entries) == "table" and entries or {}
    local packs = {}
    local assigned = {}
    local radius = 330
    local radiusSquared = radius * radius
    local anchors = V577StallEngine.GetObjectiveAnchors(false)

    while true do
        local bestMembers = nil
        for _, seed in ipairs(entries) do
            if seed.Titan and not assigned[seed.Titan] and seed.Part and seed.Part.Parent then
                local members = {}
                for _, candidate in ipairs(entries) do
                    if candidate.Titan and not assigned[candidate.Titan] and candidate.Part and candidate.Part.Parent then
                        local d = candidate.Part.Position - seed.Part.Position
                        if d:Dot(d) <= radiusSquared then members[#members + 1] = candidate end
                    end
                end
                if not bestMembers or #members > #bestMembers then bestMembers = members end
            end
        end
        if not bestMembers or #bestMembers == 0 then break end

        local sum = Vector3.zero
        for _, member in ipairs(bestMembers) do
            sum += member.Part.Position
            assigned[member.Titan] = true
        end
        local center = sum / #bestMembers
        packs[#packs + 1] = {
            Center = center,
            Members = bestMembers,
            Count = #bestMembers,
            ObjectiveDistance = V577StallEngine.DistanceToObjective(center, anchors),
        }
    end

    table.sort(packs, function(a, b)
        local ad = tonumber(a.ObjectiveDistance) or math.huge
        local bd = tonumber(b.ObjectiveDistance) or math.huge
        if math.abs(ad - bd) > 25 then return ad < bd end
        if a.Count ~= b.Count then return a.Count > b.Count end
        return ad < bd
    end)

    V577StallEngine.Queue = packs
    V577StallEngine.QueueIndex = 1
    V577StallEngine.QueueBuiltAt = os.clock()
    return packs
end

function V577StallEngine.RefreshPack(pack)
    if type(pack) ~= "table" then return nil end
    local live = {}
    local sum = Vector3.zero
    for _, member in ipairs(pack.Members or {}) do
        if member.Titan and V577StallEngine.IsColossalTitan(member.Titan) then
            local part = member.Titan:FindFirstChild("Nape", true)
                or member.Titan:FindFirstChild("UpperTorso", true)
                or member.Titan:FindFirstChild("HumanoidRootPart", true)
                or getTitanTargetPart(member.Titan)
            if part and part:IsA("BasePart") and part.Parent then
                live[#live + 1] = {Titan = member.Titan, Part = part}
                sum += part.Position
            end
        end
    end
    if #live == 0 then return nil end
    pack.Members = live
    pack.Count = #live
    pack.Center = sum / #live
    pack.ObjectiveDistance = V577StallEngine.DistanceToObjective(pack.Center, V577StallEngine.GetObjectiveAnchors(false))
    return pack
end

function V577StallEngine.NextPack(entries)
    local now = os.clock()
    if now - (V577StallEngine.QueueBuiltAt or 0) > 0.18 or #V577StallEngine.Queue == 0 then
        V577StallEngine.BuildQueue(entries)
    end

    local queue = V577StallEngine.Queue
    for _ = 1, math.max(1, #queue) do
        if V577StallEngine.QueueIndex > #queue then V577StallEngine.QueueIndex = 1 end
        local pack = V577StallEngine.RefreshPack(queue[V577StallEngine.QueueIndex])
        V577StallEngine.QueueIndex += 1
        if pack then return pack end
    end

    local rebuilt = V577StallEngine.BuildQueue(entries)
    return V577StallEngine.RefreshPack(rebuilt[1])
end

function V577StallEngine.BurstTargets(pack)
    if type(pack) ~= "table" then return {} end
    local anchors = V577StallEngine.GetObjectiveAnchors(false)
    local targets = {}
    for _, member in ipairs(pack.Members or {}) do
        local titan = member.Titan
        local part = titan and (
            titan:FindFirstChild("Nape", true)
            or titan:FindFirstChild("UpperTorso", true)
            or titan:FindFirstChild("HumanoidRootPart", true)
            or getTitanTargetPart(titan)
        ) or nil
        if titan and part and part:IsA("BasePart") and part.Parent and V577StallEngine.IsColossalTitan(titan) then
            targets[#targets + 1] = {
                Titan = titan,
                Part = part,
                Position = part.Position,
                ObjectiveDistance = V577StallEngine.DistanceToObjective(part.Position, anchors),
            }
        end
    end
    table.sort(targets, function(a, b)
        local ad = tonumber(a.ObjectiveDistance) or math.huge
        local bd = tonumber(b.ObjectiveDistance) or math.huge
        if ad ~= bd then return ad < bd end
        return tostring(a.Titan) < tostring(b.Titan)
    end)
    return targets
end

function V577StallEngine.FastTravel(center)
    if typeof(center) ~= "Vector3" or not character or not rootPart then return false end
    local now = os.clock()
    if now - (V577StallEngine.LastTravelAt or 0) < 0.075 then return false end
    local desired = center + Vector3.new(0, 760, 0)
    if (rootPart.Position - desired).Magnitude < 110 then return false end
    character:PivotTo(CFrame.lookAt(desired, center))
    rootPart.AssemblyLinearVelocity = Vector3.zero
    rootPart.AssemblyAngularVelocity = Vector3.zero
    V577StallEngine.LastTravelAt = now
    return true
end

function V577StallEngine.Step()
    if State.StallDestroyerEnabled ~= true then
        V577StallEngine.Status = "Disabled"
        return false
    end

    local mapName, stall, raid = V577StallEngine.Context()
    if mapName ~= "Loading Docks" or not stall or raid then
        V577StallEngine.Status = "WAITING • requires Loading Docks / Stall mission"
        return false
    end
    if not V35Spears.IsEquipped() then
        V577StallEngine.Status = "BLOCKED • equip Thunder Spears"
        return false
    end
    if not character or not character.Parent or not humanoid or humanoid.Health <= 0 or not rootPart then
        V577StallEngine.Status = "Waiting for character"
        return false
    end

    local entries = V577StallEngine.Entries()
    local alive = #entries
    if V577StallEngine.LastAlive > alive then
        local drops = V577StallEngine.LastAlive - alive
        V577StallEngine.EstimatedKills += drops
        V577StallEngine.ObservedDrops += drops
    elseif V577StallEngine.LastAlive == 0 and alive > 0 then
        V577StallEngine.Waves += 1
        V577StallEngine.QueueBuiltAt = 0
    end
    V577StallEngine.LastAlive = alive

    if alive <= 0 then
        V577StallEngine.Status = string.format("WAITING NEXT WAVE • waves %d • observed drops %d", V577StallEngine.Waves, V577StallEngine.ObservedDrops)
        return false
    end

    local pack = V577StallEngine.NextPack(entries)
    if not pack then
        V577StallEngine.Status = "Rescanning Colossal wave"
        return false
    end

    local targets = V577StallEngine.BurstTargets(pack)
    if #targets == 0 then
        V577StallEngine.Status = "Pack changed • rebuilding burst"
        V577StallEngine.QueueBuiltAt = 0
        return false
    end

    V577StallEngine.BurstCount = #targets
    V577StallEngine.BurstIndex = (V577StallEngine.BurstIndex % #targets) + 1
    local target = targets[V577StallEngine.BurstIndex]
    local packCount = #targets
    local targetPosition = target.Position
    local objectiveDistance = tonumber(target.ObjectiveDistance) or math.huge
    V577StallEngine.EmergencyThreats = 0
    for _, candidate in ipairs(targets) do
        if (tonumber(candidate.ObjectiveDistance) or math.huge) <= 260 then
            V577StallEngine.EmergencyThreats += 1
        end
    end

    V577StallEngine.LastPackCount = packCount
    V577StallEngine.FastTravel(pack.Center)

    local previousInfinite = State.SpearInfiniteEnabled
    State.SpearInfiniteEnabled = true
    V56SpearDirector.Mode = "STALL DESTROYER"
    local fired, reason = V35Spears.FireDirect(targetPosition, packCount)
    State.SpearInfiniteEnabled = previousInfinite

    if fired then
        V577StallEngine.Shots += 1
        if objectiveDistance <= 260 then
            V577StallEngine.Status = string.format(
                "BOAT GUARD BRATATTA • threat %.0f • member %d/%d • alive %d • shots %d",
                objectiveDistance,
                V577StallEngine.BurstIndex,
                packCount,
                alive,
                V577StallEngine.Shots
            )
        else
            V577StallEngine.Status = string.format(
                "PACK BURST • member %d/%d • alive %d • shots %d • drops %d",
                V577StallEngine.BurstIndex,
                packCount,
                alive,
                V577StallEngine.Shots,
                V577StallEngine.ObservedDrops
            )
        end
    elseif reason ~= "busy" and reason ~= "cooldown" then
        V577StallEngine.Status = "Fire wait • " .. tostring(reason or "unknown")
    end
    return fired == true
end

function V577StallEngine.Telemetry()
    return {
        Status = V577StallEngine.Status,
        Shots = V577StallEngine.Shots,
        Waves = V577StallEngine.Waves,
        EstimatedKills = V577StallEngine.EstimatedKills,
        ObservedDrops = V577StallEngine.ObservedDrops,
        Alive = V577StallEngine.LastAlive,
        Pack = V577StallEngine.LastPackCount,
        BurstIndex = V577StallEngine.BurstIndex,
        BurstCount = V577StallEngine.BurstCount,
        EmergencyThreats = V577StallEngine.EmergencyThreats,
    }
end

task.spawn(function()
    while true do
        task.wait(0.025)
        pcall(V577StallEngine.Step)
    end
end)

function V35Spears.RefillStep()
    -- V5.6 hybrid policy: Infinite Spears is a zero-ammo firing fallback, not a
    -- replacement for refill. Refill stays active so real ammo can restore
    -- Titan Blaster availability; if refill fails, basic infinite fire resumes.
    if not State.SpearAutoRefillEnabled then
        V35Spears.Refill.LowSince = nil
        return
    end

    if not V35Spears.IsEquipped() then
        V35Spears.Refill.LowSince = nil
        return
    end

    if StationRefill.Running or V35Spears.Busy then
        return
    end

    local ammo = V35Spears.ReadAmmo()
    V35Spears.Refill.LastAmmo = ammo

    if ammo == nil then
        V35Spears.Refill.LowSince = nil
        return
    end

    local exactCapacity = V35Spears.ReadCapacity()

    if ammo > 1 then
        V35Spears.Refill.MaxObserved = math.max(
            tonumber(V35Spears.Refill.MaxObserved) or 0,
            tonumber(exactCapacity) or 0,
            ammo
        )

        V35Spears.Refill.LowSince = nil
        V35Spears.Refill.Armed = true
        return
    end

    -- V3.6.1 safety trigger:
    -- preserve the final spear and start refill before the 0-ammo state can drop the character.
    if ammo > 1 or not V35Spears.Refill.Armed then
        return
    end

    V35Spears.Refill.LowSince =
        V35Spears.Refill.LowSince or os.clock()

    if os.clock() - V35Spears.Refill.LowSince < 0.10 then
        return
    end

    local verifyAmmo = V35Spears.ReadAmmo()

    if verifyAmmo == nil or verifyAmmo > 1 then
        V35Spears.Refill.LowSince = nil
        return
    end

    V35Spears.Refill.Armed = false
    V35Spears.Refill.LowSince = nil
    V35Spears.Refill.LastAttemptAt = os.clock()

    local target = math.clamp(
        math.floor(
            (
                tonumber(V35Spears.ReadCapacity())
                or tonumber(V35Spears.Refill.MaxObserved)
                or 8
            )
            + 0.5
        ),
        1,
        30
    )

    V35Spears.LastStatus =
        "Safety refill " .. tostring(verifyAmmo) .. " → " .. tostring(target)

    print(
        "[SliceHub V3.6.1][TS-REFILL]",
        "safety trigger ammo=" .. tostring(verifyAmmo),
        "target=" .. tostring(target)
    )

    beginStationRefill(
        "spears safety " .. tostring(verifyAmmo) .. " -> " .. tostring(target),
        false,
        "Spears",
        target
    )
end

task.spawn(function()
    while true do
        task.wait(0.05)
        pcall(V35Spears.RefillStep)
    end
end)

V58BladeEngine = V58BladeEngine or {
    Version = "6.0.0",
    Mode = "PACK SWEEP",
    Status = "Booting V6 Exact Blade Queue",
    LastModeAt = 0,
    LastWaveSize = 0,
    LastCleanupDamaged = 0,
    SurvivorTarget = nil,
    SurvivorPart = nil,
    SurvivorPartIndex = 1,
    SurvivorNoProgress = 0,
    SurvivorRotations = 0,
    SurvivorLastHealth = nil,
    SurvivorLastAlive = nil,
    SurvivorBlacklist = setmetatable({}, {__mode = "k"}),
    HybridBurstRequested = false,
    HybridBurstActive = false,
    HybridStatus = "Idle",

    Phase = "READY",
    PhaseDetail = "boot",
    NextActionAt = 0,
    BurstSerial = 0,
    LastBurst = {
        Requested = 0,
        Registered = 0,
        Kills = 0,
        Damaged = 0,
        Duration = 0,
        Mode = "PACK SWEEP",
        Source = "BLADE",
    },
    LastBurstAt = 0,
    LastTelemetryPrintAt = 0,
    LastBlasterName = "None",
    LastBlasterKills = 0,
    LastBlasterPack = 0,
    LastBlasterAt = 0,
}

function V58BladeEngine.AllowedTitan(titan)
    return titan
        and titan.Parent
        and isTitanAlive(titan)
        and (
            not V4RaidDirector
            or not V4RaidDirector.AllowTitanTarget
            or V4RaidDirector.AllowTitanTarget(titan)
        )
end

function V58BladeEngine.HealthInfo(titan)
    if not titan or not titan.Parent then return nil, nil, nil end
    local humanoid = titan:FindFirstChildOfClass("Humanoid")
    if not humanoid then return nil, nil, nil end
    local health = tonumber(humanoid.Health)
    local maximum = tonumber(humanoid.MaxHealth)
    local ratio = health and maximum and maximum > 0 and (health / maximum) or 1
    return health, maximum, ratio
end

function V58BladeEngine.SetPhase(phase, detail, nextActionAt)
    V58BladeEngine.Phase = tostring(phase or "READY")
    V58BladeEngine.PhaseDetail = tostring(detail or "")
    V58BladeEngine.NextActionAt = tonumber(nextActionAt) or 0
end

function V58BladeEngine.BeginBurstSnapshot(targets, mode, source)
    local snapshot = {
        StartedAt = os.clock(),
        Requested = #(targets or {}),
        Mode = tostring(mode or V58BladeEngine.Mode or "PACK SWEEP"),
        Source = tostring(source or "BLADE"),
        Before = {},
    }

    for _, titan in ipairs(targets or {}) do
        if titan then
            local health = select(1, V58BladeEngine.HealthInfo(titan))
            snapshot.Before[titan] = health
        end
    end

    V58BladeEngine.BurstSerial += 1
    V58BladeEngine.SetPhase(
        "BURST_ACTIVE",
        string.format("%s %d targets", snapshot.Source, snapshot.Requested),
        0
    )

    return snapshot
end

function V58BladeEngine.FinishBurstSnapshot(snapshot)
    snapshot = type(snapshot) == "table" and snapshot or {}
    local kills, damaged, registered = 0, 0, 0

    for titan, healthBefore in pairs(snapshot.Before or {}) do
        local dead = not titan or not titan.Parent or not isTitanAlive(titan)
        local healthAfter = titan and select(1, V58BladeEngine.HealthInfo(titan)) or nil
        local healthDrop =
            healthBefore ~= nil
            and healthAfter ~= nil
            and healthAfter < healthBefore - (tonumber(Config.HealthProgressEpsilon) or 0.01)

        if dead then
            kills += 1
            registered += 1
        elseif healthDrop then
            damaged += 1
            registered += 1
        end
    end

    local result = {
        Requested = tonumber(snapshot.Requested) or 0,
        Registered = registered,
        Kills = kills,
        Damaged = damaged,
        Duration = math.max(0, os.clock() - (tonumber(snapshot.StartedAt) or os.clock())),
        Mode = tostring(snapshot.Mode or V58BladeEngine.Mode or "PACK SWEEP"),
        Source = tostring(snapshot.Source or "BLADE"),
    }

    V58BladeEngine.LastBurst = result
    V58BladeEngine.LastBurstAt = os.clock()

    local now = os.clock()
    local printDelay = math.max(0.10, tonumber(Config.BladeV31TelemetryPrintDelay) or 0.35)
    if result.Registered > 0 or now - (tonumber(V58BladeEngine.LastTelemetryPrintAt) or 0) >= printDelay then
        V58BladeEngine.LastTelemetryPrintAt = now
        print(
            "[SliceHub V6.0.0][BLADE-BURST]",
            "source=" .. result.Source,
            "mode=" .. result.Mode,
            "requested=" .. tostring(result.Requested),
            "registered=" .. tostring(result.Registered),
            "kills=" .. tostring(result.Kills),
            "damaged=" .. tostring(result.Damaged),
            "duration=" .. string.format("%.2fs", result.Duration)
        )
    end

    return result
end

function V58BladeEngine.BurstSummary()
    local burst = V58BladeEngine.LastBurst or {}
    return string.format(
        "%s %d→%d reg • K%d D%d • %.2fs",
        tostring(burst.Source or "BLADE"),
        tonumber(burst.Requested) or 0,
        tonumber(burst.Registered) or 0,
        tonumber(burst.Kills) or 0,
        tonumber(burst.Damaged) or 0,
        tonumber(burst.Duration) or 0
    )
end

function V58BladeEngine.ReturnToSafeLane(reason)
    if Config.BladeV31SafeReturnEnabled ~= true then return false end
    if V577MovementAuthority and not V577MovementAuthority.CanMove("NORMAL") then return false end
    if not State or State.FarmEnabled ~= true then return false end
    if not character or not character.Parent or not rootPart or not rootPart.Parent then return false end

    local base = CombatAnchorRuntime and CombatAnchorRuntime.Position or nil
    local aim = CombatAnchorRuntime and CombatAnchorRuntime.AimPosition or nil
    if typeof(base) ~= "Vector3" then return false end

    local extra = math.max(0, tonumber(Config.BladeV31SafeReturnHeight) or 42)
    local safe = base + Vector3.new(0, extra, 0)
    aim = typeof(aim) == "Vector3" and aim or safe + Vector3.new(0, -1, 0)

    pcall(function()
        character:PivotTo(CFrame.lookAt(safe, aim))
        rootPart.AssemblyLinearVelocity = Vector3.zero
        rootPart.AssemblyAngularVelocity = Vector3.zero
    end)

    local now = os.clock()
    CombatSafetyBoostUntil = math.max(
        tonumber(CombatSafetyBoostUntil) or 0,
        now + math.max(0.05, tonumber(Config.BladeV31SafeReturnHold) or 0.24)
    )
    CombatSafetyBoostHeight = math.max(
        tonumber(CombatSafetyBoostHeight) or 0,
        extra
    )

    if reason then
        V58BladeEngine.PhaseDetail = tostring(reason)
    end

    return true
end

function V58BladeEngine.ResolveMode(aliveCount)
    aliveCount = tonumber(aliveCount) or getCachedAliveTitanCount()
    local mode = "PACK SWEEP"

    if V4RaidDirector and V4RaidDirector.HardBossLock then
        local bossTitan, bossPart = V4RaidDirector.HardBossLock()
        if bossTitan and bossPart then mode = "BOSS PRESSURE" end
    end

    if mode ~= "BOSS PRESSURE"
        and aliveCount <= math.max(1, tonumber(Config.FinisherTitanCount) or 5) then
        mode = "SURVIVOR HUNT"
    elseif mode ~= "BOSS PRESSURE"
        and V35Spears
        and V35Spears.ShouldRun
        and V35Spears.ShouldRun() then
        mode = "PACK CLEANUP"
    end

    if V58BladeEngine.Mode ~= mode then
        V58BladeEngine.Mode = mode
        V58BladeEngine.LastModeAt = os.clock()
    end

    return mode
end

function V58BladeEngine.SurvivorBlacklisted(titan)
    local expiry = V58BladeEngine.SurvivorBlacklist[titan]
    if not expiry then return false end
    if os.clock() >= expiry then
        V58BladeEngine.SurvivorBlacklist[titan] = nil
        return false
    end
    return true
end

function V58BladeEngine.ResetSurvivor(reason, keepBlacklist)
    V58BladeEngine.SurvivorTarget = nil
    V58BladeEngine.SurvivorPart = nil
    V58BladeEngine.SurvivorPartIndex = 1
    V58BladeEngine.SurvivorNoProgress = 0
    V58BladeEngine.SurvivorRotations = 0
    V58BladeEngine.SurvivorLastHealth = nil
    V58BladeEngine.SurvivorLastAlive = nil
    if keepBlacklist ~= true then
        V58BladeEngine.SurvivorBlacklist = setmetatable({}, {__mode = "k"})
    end
    if reason then V58BladeEngine.Status = tostring(reason) end
end

function V58BladeEngine.ResolveStrikePart(titan)
    if not titan or not titan.Parent then return nil end
    local order = {"Nape", "UpperTorso", "HumanoidRootPart", "Torso", "Head", "LowerTorso"}
    local startIndex = math.clamp(
        math.floor(tonumber(V58BladeEngine.SurvivorPartIndex) or 1),
        1,
        #order
    )

    for offset = 0, #order - 1 do
        local index = ((startIndex + offset - 1) % #order) + 1
        local part = titan:FindFirstChild(order[index], true)
        if part and part:IsA("BasePart") and part.Parent then
            V58BladeEngine.SurvivorPartIndex = index
            return part
        end
    end

    return getTitanTargetPart(titan)
end

function V58BladeEngine.AdvanceStrikePart()
    local partCount = 6
    V58BladeEngine.SurvivorPartIndex =
        ((math.floor(tonumber(V58BladeEngine.SurvivorPartIndex) or 1)) % partCount) + 1
end

function V58BladeEngine.PickSurvivor()
    local current = V58BladeEngine.SurvivorTarget
    if V58BladeEngine.AllowedTitan(current)
        and not V58BladeEngine.SurvivorBlacklisted(current) then
        local part = V58BladeEngine.ResolveStrikePart(current)
        if part and part.Parent then
            V58BladeEngine.SurvivorPart = part
            return current, part
        end
    end

    local titansFolder = Workspace:FindFirstChild(Config.TitansFolderName)
    if not titansFolder then return nil, nil end

    local origin = rootPart and rootPart.Position or Vector3.zero
    local candidates = {}

    local function collect(ignoreBlacklist)
        table.clear(candidates)
        for _, titan in ipairs(titansFolder:GetChildren()) do
            if V58BladeEngine.AllowedTitan(titan)
                and (ignoreBlacklist or not V58BladeEngine.SurvivorBlacklisted(titan)) then
                local part = V58BladeEngine.ResolveStrikePart(titan)
                if part and part.Parent then
                    local health = select(1, V58BladeEngine.HealthInfo(titan)) or math.huge
                    candidates[#candidates + 1] = {
                        Titan = titan,
                        Part = part,
                        Health = health,
                        Distance = (part.Position - origin).Magnitude,
                    }
                end
            end
        end
    end

    collect(false)
    if #candidates == 0 then
        V58BladeEngine.SurvivorBlacklist = setmetatable({}, {__mode = "k"})
        collect(true)
    end

    table.sort(candidates, function(a, b)
        if a.Health ~= b.Health then return a.Health < b.Health end
        return a.Distance < b.Distance
    end)

    local chosen = candidates[1]
    if not chosen then
        V58BladeEngine.ResetSurvivor("SURVIVOR HUNT • no live target", true)
        return nil, nil
    end

    V58BladeEngine.SurvivorTarget = chosen.Titan
    V58BladeEngine.SurvivorPart = chosen.Part
    V58BladeEngine.SurvivorPartIndex = 1
    V58BladeEngine.SurvivorNoProgress = 0
    V58BladeEngine.SurvivorRotations = 0
    V58BladeEngine.SurvivorLastHealth = chosen.Health
    V58BladeEngine.SurvivorLastAlive = getCachedAliveTitanCount()
    V58BladeEngine.Status = "SURVIVOR HUNT • " .. tostring(chosen.Titan.Name)
    return chosen.Titan, chosen.Part
end

function V58BladeEngine.BuildCleanupWave(limit, current)
    limit = math.max(1, math.floor(tonumber(limit) or 1))
    local scanLimit = math.max(limit, math.floor(tonumber(Config.BladeV3CleanupScanLimit) or 40))
    local candidates = findClosestTitans(scanLimit)
    local damaged = {}
    local threshold = math.clamp(tonumber(Config.BladeV3CleanupHealthRatio) or 0.985, 0.05, 1)

    for _, entry in ipairs(candidates or {}) do
        local titan = entry.Titan
        if V58BladeEngine.AllowedTitan(titan) then
            local health, _, ratio = V58BladeEngine.HealthInfo(titan)
            if health and ratio and ratio < threshold then
                damaged[#damaged + 1] = {
                    Titan = titan,
                    Ratio = ratio,
                    Health = health,
                    DistanceSquared = tonumber(entry.DistanceSquared) or math.huge,
                    Score = tonumber(entry.KillScore) or math.huge,
                }
            end
        end
    end

    table.sort(damaged, function(a, b)
        if a.Ratio ~= b.Ratio then return a.Ratio < b.Ratio end
        if a.Health ~= b.Health then return a.Health < b.Health end
        if a.Score ~= b.Score then return a.Score < b.Score end
        return a.DistanceSquared < b.DistanceSquared
    end)

    local result, seen = {}, {}
    local cleanupCap = math.min(
        limit,
        math.max(1, math.floor(tonumber(Config.BladeV3CleanupMaxTargets) or 8))
    )

    for _, entry in ipairs(damaged) do
        if #result >= cleanupCap then break end
        if entry.Titan and not seen[entry.Titan] and isTitanAlive(entry.Titan) then
            seen[entry.Titan] = true
            result[#result + 1] = entry.Titan
        end
    end

    if #result < limit then
        local fallback = V52KillingEngine.BuildBladeWave(limit, current)
        for _, titan in ipairs(fallback) do
            if #result >= limit then break end
            if titan and not seen[titan] and isTitanAlive(titan) then
                seen[titan] = true
                result[#result + 1] = titan
            end
        end
    end

    V58BladeEngine.LastCleanupDamaged = #damaged
    V58BladeEngine.LastWaveSize = #result
    V58BladeEngine.Status = string.format(
        "PACK CLEANUP • damaged %d • wave %d",
        #damaged,
        #result
    )
    return result
end

function V58BladeEngine.BuildWave(limit, current)
    local aliveCount = getCachedAliveTitanCount()
    local mode = V58BladeEngine.ResolveMode(aliveCount)

    if mode == "BOSS PRESSURE" and V4RaidDirector and V4RaidDirector.HardBossLock then
        local bossTitan, bossPart = V4RaidDirector.HardBossLock()
        if bossTitan and bossPart then
            V58BladeEngine.Status = "BOSS PRESSURE • " .. tostring(bossTitan.Name)
            V58BladeEngine.LastWaveSize = 1
            return {bossTitan}
        end
    end

    if mode == "SURVIVOR HUNT" then
        local titan, part = V58BladeEngine.PickSurvivor()
        if titan and part then
            currentTarget = titan
            currentTargetPart = part
            currentTargetHealth = select(1, V58BladeEngine.HealthInfo(titan))
            targetLastProgressTime = os.clock()
            V58BladeEngine.LastWaveSize = 1
            return {titan}
        end
        return {}
    end

    if mode == "PACK CLEANUP" then
        return V58BladeEngine.BuildCleanupWave(limit, current)
    end

    local wave = V52KillingEngine.BuildBladeWave(limit, current)
    V58BladeEngine.LastWaveSize = #wave
    V58BladeEngine.Status = "PACK SWEEP • wave " .. tostring(#wave)
    return wave
end

function V58BladeEngine.AimPartForTitan(titan)
    if V58BladeEngine.Mode == "SURVIVOR HUNT"
        and titan == V58BladeEngine.SurvivorTarget then
        local part = V58BladeEngine.ResolveStrikePart(titan)
        if part and part.Parent then
            V58BladeEngine.SurvivorPart = part
            return part
        end
    end
    return getTitanTargetPart(titan)
end

function V58BladeEngine.RecordSurvivorBurst(titan, healthBefore, aliveBefore, madeProgress)
    if V58BladeEngine.Mode ~= "SURVIVOR HUNT" or not titan then return end

    local healthAfter = select(1, V58BladeEngine.HealthInfo(titan))
    local aliveAfter = getCachedAliveTitanCount()
    local dead = not V58BladeEngine.AllowedTitan(titan)
    local healthProgress = healthBefore and healthAfter and healthAfter < healthBefore - Config.HealthProgressEpsilon
    local aliveProgress = tonumber(aliveBefore) and aliveAfter < tonumber(aliveBefore)

    if dead or healthProgress or aliveProgress or madeProgress == true then
        V58BladeEngine.SurvivorNoProgress = 0
        V58BladeEngine.SurvivorLastHealth = healthAfter
        V58BladeEngine.SurvivorLastAlive = aliveAfter
        if dead then
            V58BladeEngine.ResetSurvivor("SURVIVOR HUNT • kill confirmed", true)
        else
            V58BladeEngine.Status = "SURVIVOR HUNT • progress confirmed"
        end
        return
    end

    V58BladeEngine.SurvivorNoProgress += 1
    local attempts = math.max(1, math.floor(tonumber(Config.BladeV3SurvivorPartAttempts) or 1))
    if V58BladeEngine.SurvivorNoProgress < attempts then return end

    V58BladeEngine.SurvivorNoProgress = 0
    V58BladeEngine.AdvanceStrikePart()
    V58BladeEngine.SurvivorRotations += 1
    V58BladeEngine.SurvivorPart = V58BladeEngine.ResolveStrikePart(titan)
    V58BladeEngine.Status = string.format(
        "SURVIVOR HUNT • no progress • part %d/6",
        tonumber(V58BladeEngine.SurvivorPartIndex) or 1
    )

    local rotationLimit = math.max(2, math.floor(tonumber(Config.BladeV3SurvivorMaxRotations) or 6))
    if V58BladeEngine.SurvivorRotations >= rotationLimit then
        V58BladeEngine.SurvivorBlacklist[titan] =
            os.clock() + math.max(0.2, tonumber(Config.BladeV3SurvivorBlacklistTime) or 0.8)
        V58BladeEngine.ResetSurvivor("SURVIVOR HUNT • rotating stale Titan", true)
    end
end

function V58BladeEngine.CanFillSpearGap(spearTriggered)
    if Config.BladeV3Enabled ~= true or Config.BladeV3HybridEnabled ~= true then return false end
    if spearTriggered == true then
        V58BladeEngine.HybridStatus = "Spear shot owns frame"
        return false
    end
    if not State or State.BladesEnabled ~= true then return false end
    if not V35Spears or not V35Spears.ShouldRun or not V35Spears.ShouldRun() then return false end
    if V35Spears.Busy or bladeBurstRunning or refillSequenceRunning or ripperSequenceRunning then return false end
    if V577MovementAuthority and not V577MovementAuthority.CanMove("NORMAL") then return false end

    local now = os.clock()
    local readyAt = tonumber(V35Spears.NextFireAt) or 0
    local gap = readyAt - now
    if gap <= 0 then
        V58BladeEngine.HybridStatus = "Spear ready now"
        return false
    end
    if gap < math.max(0.08, tonumber(Config.BladeV3HybridMinWindow) or 0.145) then
        V58BladeEngine.HybridStatus = "Gap too short"
        return false
    end

    local shotAge = now - (tonumber(V35Spears.LastShotAt) or 0)
    if V35Spears.LastShotAt and V35Spears.LastShotAt > 0
        and shotAge < math.max(0.02, tonumber(Config.BladeV3HybridPostSpearSettle) or 0.055) then
        V58BladeEngine.HybridStatus = "Post-spear settle"
        return false
    end

    V58BladeEngine.HybridStatus = string.format("Blade gap %.3fs", gap)
    return true
end

local function getBladeAttackTargets()
    -- V5.7.6 Glass Cannon profile remains authoritative: Colossal P2 is remote-pressure
    -- only, so V5.8 never allows a blade dive to break the safe lane.
    if V4RaidDirector
        and V4RaidDirector.RaidName == "Colossal Raid"
        and V55ColossalDirector
        and V55ColossalDirector.Stage == "P2 BOSS"
        and V55ColossalDirector.IsGlassCannonProfile
        and V55ColossalDirector.IsGlassCannonProfile() then
        return {}
    end

    if Config.BladeV3Enabled == true then
        return V58BladeEngine.BuildWave(getEffectiveTitansPerHit(), currentTarget)
    end

    return V52KillingEngine.BuildBladeWave(getEffectiveTitansPerHit(), currentTarget)
end

function clearCurrentTarget(blacklist)
	if blacklist and currentTarget then
		targetBlacklistedUntil[currentTarget] = os.clock() + Config.TargetBlacklistTime
	end
	currentTarget = nil
	currentTargetPart = nil
	currentTargetHealth = nil
	targetLastProgressTime = 0
end

local function acquireCurrentTarget()
    if V4RaidDirector and V4RaidDirector.HardBossLock then
        local bossTitan, bossPart = V4RaidDirector.HardBossLock()
        if bossTitan and bossPart then
            targetBlacklistedUntil[bossTitan] = nil
            local bossHumanoid = bossTitan:FindFirstChildOfClass("Humanoid")
            currentTarget = bossTitan
            currentTargetPart = bossPart
            currentTargetHealth = bossHumanoid and bossHumanoid.Health or nil
            targetLastProgressTime = os.clock()
            return true
        end
    end

    local aliveCount = getCachedAliveTitanCount()
    local finisherThreshold = math.max(1, tonumber(Config.FinisherTitanCount) or 5)

    local titan, targetPart
    if aliveCount <= finisherThreshold then
        titan, targetPart = findClosestAliveTitanIgnoringBlacklist()
    else
        titan, targetPart = findClosestTitan()
    end

    if not titan or not targetPart then
        return false
    end

    -- Last-Titan cleanup owns the target directly.
    if aliveCount <= finisherThreshold then
        targetBlacklistedUntil[titan] = nil
    end

    local titanHumanoid = titan:FindFirstChildOfClass("Humanoid")
    currentTarget = titan
    currentTargetPart = targetPart
    currentTargetHealth = titanHumanoid and titanHumanoid.Health or nil
    targetLastProgressTime = os.clock()
    return true
end

local function updateAndValidateCurrentTarget()
    if currentTarget
        and V4RaidDirector
        and V4RaidDirector.AllowTitanTarget
        and not V4RaidDirector.AllowTitanTarget(currentTarget) then
        clearCurrentTarget(false)
        return false, "raid-phase-filter"
    end

	if V4RaidDirector and V4RaidDirector.HardBossLock then
		local bossTitan = select(1, V4RaidDirector.HardBossLock())
		if bossTitan and currentTarget ~= bossTitan then
			clearCurrentTarget(false)
			return false, "boss-switch"
		end
	end

	if not currentTarget or not currentTargetPart then return false, "missing" end
	if isTitanBlacklisted(currentTarget) or not isTitanAlive(currentTarget) then
		clearCurrentTarget(false)
		return false, "dead"
	end
	if not currentTargetPart.Parent then
		clearCurrentTarget(false)
		return false, "missing"
	end

	local titanHumanoid = currentTarget:FindFirstChildOfClass("Humanoid")
	if not titanHumanoid then
		clearCurrentTarget(true)
		return false, "invalid"
	end

	local now = os.clock()
	local health = titanHumanoid.Health
	if currentTargetHealth == nil or health < currentTargetHealth - Config.HealthProgressEpsilon then
		currentTargetHealth = health
		targetLastProgressTime = now
	elseif health > currentTargetHealth + Config.HealthProgressEpsilon then
		-- Some Titans regenerate. Track the new value without counting it as attack progress.
		currentTargetHealth = health
	end

	if now - targetLastProgressTime >= Config.TargetStallTimeout then
		local hardBoss = V4RaidDirector
			and V4RaidDirector.HardBossLock
			and select(1, V4RaidDirector.HardBossLock())

		if hardBoss and currentTarget == hardBoss then
			-- Boss health can remain flat while a raid shield/objective value is draining.
			-- Never blacklist or rotate away from the live P2 boss.
			targetLastProgressTime = now
			return true, nil
		end

		local stalledName = currentTarget.Name
		clearCurrentTarget(true)
		return false, stalledName
	end

	return true, nil
end

V577MovementAuthority = V577MovementAuthority or {
    LastMode = "NORMAL",
}

function V577MovementAuthority.Mode()
    if WavesRuntimeDirector and WavesRuntimeDirector.Busy == true then
        V577MovementAuthority.LastMode = "WAVE_CRATE"
        return "WAVE_CRATE"
    end
    if V55ColossalDirector and V55ColossalDirector.EvadeMode == true then
        V577MovementAuthority.LastMode = "EVADE"
        return "EVADE"
    end
    if V55ColossalDirector and V4RaidDirector
        and V4RaidDirector.RaidName == "Colossal Raid"
        and V55ColossalDirector.Stage == "P1 CANNON STALL"
        and (
            V55ColossalDirector.Entered == true
            or V55ColossalDirector.DismountPending == true
            or V55ColossalDirector.RemountPending == true
        ) then
        V577MovementAuthority.LastMode = "CANNON"
        return "CANNON"
    end
    if V577StallEngine and V577StallEngine.OwnsCombat and V577StallEngine.OwnsCombat() then
        V577MovementAuthority.LastMode = "STALL"
        return "STALL"
    end
    if StationRefill and StationRefill.Running then
        V577MovementAuthority.LastMode = "REFILL"
        return "REFILL"
    end
    V577MovementAuthority.LastMode = "NORMAL"
    return "NORMAL"
end

function V577MovementAuthority.CanMove(requester)
    local mode = V577MovementAuthority.Mode()
    requester = tostring(requester or "NORMAL")
    return mode == "NORMAL" or mode == requester
end

function releaseCombatLock()
	clearCurrentTarget(false)
	speedPulseForward = false
	CombatAnchorRuntime.Position = nil
	CombatAnchorRuntime.GroundCenter = nil
	CombatAnchorRuntime.AimPosition = nil
	CombatAnchorRuntime.TargetCount = 0
	CombatAnchorRuntime.PulseUntil = 0
	CombatAnchorRuntime.PulseSerial += 1
	State.IsGrabbed = false

	local function pushDown()
		if State.FarmEnabled then return end
		if rootPart and rootPart.Parent then
			rootPart.Anchored = false
			rootPart.AssemblyAngularVelocity = Vector3.zero
			rootPart.AssemblyLinearVelocity = Vector3.new(0, -Config.DropSpeed, 0)
		end
	end

	if humanoid and humanoid.Health > 0 then
		humanoid.PlatformStand = false
		humanoid.Sit = false
		humanoid:ChangeState(Enum.HumanoidStateType.Freefall)
	end

	-- Apply the drop immediately, then once more after other game scripts have had a frame to react.
	pushDown()
	task.delay(0.12, pushDown)
end

-- DEV14 anchor hysteresis: keep the player over one useful cluster until that cluster is actually depleted.
local function countAliveTitansNearPosition(center, radius)
	if typeof(center) ~= "Vector3" then return 0 end
	local titansFolder = Workspace:FindFirstChild(Config.TitansFolderName)
	if not titansFolder then return 0 end
	radius = math.max(1, tonumber(radius) or 360)
	local radiusSquared = radius * radius
	local count = 0

	for _, titan in ipairs(titansFolder:GetChildren()) do
		if isTitanAlive(titan) and not isTitanBlacklisted(titan) then
			local part = getTitanTargetPart(titan)
			if part and part.Parent then
				local delta = part.Position - center
				if delta:Dot(delta) <= radiusSquared then
					count += 1
				end
			end
		end
	end

	return count
end

local function currentCombatSkyHeight()
    if State
        and State.SpearSupportEnabled == true
        and V35Spears
        and V35Spears.IsEquipped
        and V35Spears.IsEquipped() then
        return tonumber(Config.SpearSkyHeight) or 430
    end

    return tonumber(Config.SkyHeight) or 300
end

-- DEV14 stable cluster anchor: movement anchor is separated from the tracked damage target.
function refreshCombatAnchor(force)
    if not Config.CombatAnchorEnabled then return nil, nil, 0 end
    local now = os.clock()

    if V4RaidDirector and V4RaidDirector.HardBossLock then
        local bossTitan, bossPart = V4RaidDirector.HardBossLock()
        if bossTitan and bossPart then
            local center = bossPart.Position
            CombatAnchorRuntime.Position =
                center + Vector3.new(0, currentCombatSkyHeight(), 0)
            CombatAnchorRuntime.GroundCenter = center
            CombatAnchorRuntime.AimPosition = center
            CombatAnchorRuntime.TargetCount = 1
            CombatAnchorRuntime.InitialResidents = 1
            CombatAnchorRuntime.LastRefresh = now
            CombatAnchorRuntime.LastCommit = now
            return CombatAnchorRuntime.Position, center, 1
        end
    end

    local aliveCount = getCachedAliveTitanCount()
    local finisherThreshold = math.max(1, tonumber(Config.FinisherTitanCount) or 5)
    if aliveCount <= finisherThreshold and currentTargetPart and currentTargetPart.Parent then
        local center = currentTargetPart.Position
        local finisherHeight = currentCombatSkyHeight()
        if not (State.SpearSupportEnabled and V35Spears and V35Spears.IsEquipped and V35Spears.IsEquipped()) then
            finisherHeight = tonumber(Config.FinisherSkyHeight) or 175
        end
        CombatAnchorRuntime.Position = center + Vector3.new(0, finisherHeight, 0)
        CombatAnchorRuntime.GroundCenter = center
        CombatAnchorRuntime.AimPosition = center
        CombatAnchorRuntime.TargetCount = aliveCount
        CombatAnchorRuntime.InitialResidents = aliveCount
        CombatAnchorRuntime.LastRefresh = now
        CombatAnchorRuntime.LastCommit = now
        return CombatAnchorRuntime.Position, CombatAnchorRuntime.AimPosition, aliveCount
    end
	local refreshDelay = math.max(0.05, tonumber(Config.CombatAnchorRefreshDelay) or 0.20)
	if not force and CombatAnchorRuntime.Position and now - CombatAnchorRuntime.LastRefresh < refreshDelay then
		return CombatAnchorRuntime.Position, CombatAnchorRuntime.AimPosition, CombatAnchorRuntime.TargetCount
	end

	CombatAnchorRuntime.LastRefresh = now
	local center, aimPart, count = getBestTitanCluster(Config.CombatAnchorClusterRadius, Config.CombatAnchorScanLimit)
	if not center then
		return CombatAnchorRuntime.Position, CombatAnchorRuntime.AimPosition, CombatAnchorRuntime.TargetCount
	end

	local candidatePosition = center + Vector3.new(0, currentCombatSkyHeight(), 0)
	local commit = force == true or CombatAnchorRuntime.Position == nil
	if not commit then
		local moved = (candidatePosition - CombatAnchorRuntime.Position).Magnitude
		local residents = countAliveTitansNearPosition(
			CombatAnchorRuntime.GroundCenter,
			Config.CombatAnchorReleaseRadius
		)
        local minimumResidents = math.max(1, math.floor(tonumber(Config.CombatAnchorMinResidents) or 3))
        local initialResidents = math.max(
            minimumResidents,
            tonumber(CombatAnchorRuntime.InitialResidents) or residents
        )
        local retentionThreshold = math.max(
            minimumResidents,
            math.ceil(initialResidents * (tonumber(Config.CombatAnchorRetentionRatio) or 0.35))
        )
        local betterClusterGain = math.max(1, math.floor(tonumber(Config.CombatAnchorBetterClusterGain) or 5))
        local emergencyDistance = math.max(
            math.max(8, tonumber(Config.CombatAnchorMoveThreshold) or 140),
            tonumber(Config.CombatAnchorEmergencyMoveDistance) or 520
        )

        local depleted = residents < retentionThreshold
        local clearlyBetter = count >= residents + betterClusterGain
            and moved >= math.max(8, tonumber(Config.CombatAnchorMoveThreshold) or 140)

        commit = depleted or clearlyBetter or moved >= emergencyDistance
    end

    if commit then
        CombatAnchorRuntime.Position = candidatePosition
        CombatAnchorRuntime.GroundCenter = center
        CombatAnchorRuntime.InitialResidents = count
        CombatAnchorRuntime.LastCommit = now
    end

	-- Aim may update while position stays fixed; this rotates toward action without lateral teleport jitter.
	CombatAnchorRuntime.AimPosition = center
	CombatAnchorRuntime.TargetCount = count
	return CombatAnchorRuntime.Position, CombatAnchorRuntime.AimPosition, count
end

function triggerCombatForcePulse(aimPosition, duration)
    if V577MovementAuthority and not V577MovementAuthority.CanMove("NORMAL") then return end
	if not State.FarmEnabled or not character or not character.Parent or not rootPart then return end
	local anchorPosition = select(1, refreshCombatAnchor(false))
	if anchorPosition and os.clock() < CombatSafetyBoostUntil then
		anchorPosition = anchorPosition + Vector3.new(0, CombatSafetyBoostHeight, 0)
	elseif os.clock() >= CombatSafetyBoostUntil then
		CombatSafetyBoostHeight = 0
	end
	if not anchorPosition then return end
	aimPosition = typeof(aimPosition) == "Vector3" and aimPosition or CombatAnchorRuntime.AimPosition
	if not aimPosition then return end

    local aliveCount = getCachedAliveTitanCount()
    local finisherMode = aliveCount <= math.max(1, tonumber(Config.FinisherTitanCount) or 5)

    local attackDirection = Vector3.new(0, -1, 0)
    if finisherMode and aimPosition then
        local delta = aimPosition - anchorPosition
        if delta.Magnitude > 0.1 then
            attackDirection = delta.Unit
        end
    end

	CombatAnchorRuntime.PulseSerial += 1
	local serial = CombatAnchorRuntime.PulseSerial
	local pulseDuration = math.max(0.025, tonumber(duration) or tonumber(Config.BladeForcePulseDuration) or 0.065)
	CombatAnchorRuntime.PulseUntil = os.clock() + pulseDuration

    local pulseDistance = finisherMode
        and (tonumber(Config.FinisherPulseDistance) or 34)
        or (tonumber(Config.SpeedPulseDistance) or 20)

    local killSpeed = finisherMode
        and (tonumber(Config.FinisherKillSpeed) or 1450)
        or (tonumber(Config.KillSpeed) or 1180)

    local pulsePosition = anchorPosition + attackDirection * pulseDistance
    character:PivotTo(CFrame.lookAt(pulsePosition, aimPosition))
    rootPart.AssemblyAngularVelocity = Vector3.zero
    rootPart.AssemblyLinearVelocity = attackDirection * killSpeed

	task.delay(pulseDuration, function()
		if serial ~= CombatAnchorRuntime.PulseSerial then return end
		CombatAnchorRuntime.PulseUntil = 0
		if not State.FarmEnabled or not character or not character.Parent or not rootPart then return end
		local stablePosition = CombatAnchorRuntime.Position or anchorPosition
		local stableAim = CombatAnchorRuntime.AimPosition or aimPosition
		character:PivotTo(CFrame.lookAt(stablePosition, stableAim))
		rootPart.AssemblyAngularVelocity = Vector3.zero
		rootPart.AssemblyLinearVelocity = Vector3.zero
	end)
end

-- V9.4.2 hard air-lock invariant. Target detection is not allowed to release
-- gravity ownership. The last safe aerial CFrame survives temporary 0-target scans.
V942AirLock = V942AirLock or {
    RootPart = nil,
    LastSafeCFrame = nil,
    LastHoldAt = 0,
    Status = "BOOT",
}

-- Stable anchor keeper. Force generation happens only when a blade burst is actually launched.
local function lockCharacterInSky(targetPart)
    if V577MovementAuthority and not V577MovementAuthority.CanMove("NORMAL") then return end
	if not character or not character.Parent or not humanoid or humanoid.Health <= 0 or not rootPart then return end
	if os.clock() < (CombatAnchorRuntime.PulseUntil or 0) then return end

    if V942AirLock.RootPart ~= rootPart then
        V942AirLock.RootPart = rootPart
        V942AirLock.LastSafeCFrame = nil
        V942AirLock.Status = "NEW CHARACTER"
    end

	local anchorPosition, aimPosition = refreshCombatAnchor(false)
	if anchorPosition and os.clock() < CombatSafetyBoostUntil then
		anchorPosition = anchorPosition + Vector3.new(0, CombatSafetyBoostHeight, 0)
	elseif os.clock() >= CombatSafetyBoostUntil then
		CombatSafetyBoostHeight = 0
	end

	if not anchorPosition then
        if targetPart and targetPart.Parent then
            aimPosition = targetPart.Position
            anchorPosition = aimPosition + Vector3.new(0, currentCombatSkyHeight(), 0)
        else
            -- Zero targets: hold the last proven combat CFrame instead of only
            -- zeroing velocity and letting gravity win between scan frames.
            local hold = V942AirLock.LastSafeCFrame
            if not hold then
                hold = rootPart.CFrame
                V942AirLock.LastSafeCFrame = hold
            end

            character:PivotTo(hold)
            rootPart.AssemblyAngularVelocity = Vector3.zero
            rootPart.AssemblyLinearVelocity = Vector3.zero
            V942AirLock.LastHoldAt = os.clock()
            V942AirLock.Status = "HOLD • 0 TARGETS"
            return
        end
	end

	aimPosition = aimPosition or (targetPart and targetPart.Position) or anchorPosition + Vector3.new(0, -1, 0)
    local desiredCFrame
	if (rootPart.Position - anchorPosition).Magnitude >= math.max(2, tonumber(Config.CombatAnchorSnapDistance) or 8) then
        desiredCFrame = CFrame.lookAt(anchorPosition, aimPosition)
	else
        desiredCFrame = CFrame.lookAt(rootPart.Position, aimPosition)
	end

    character:PivotTo(desiredCFrame)
	rootPart.AssemblyAngularVelocity = Vector3.zero
	rootPart.AssemblyLinearVelocity = Vector3.zero

    V942AirLock.LastSafeCFrame = desiredCFrame
    V942AirLock.LastHoldAt = os.clock()
    V942AirLock.Status = targetPart and "LOCKED • TARGET" or "LOCKED • ANCHOR"
end

-- Independent keeper: active Farm owns a safe aerial hold even when the main
-- targeting loop has no current target. Explicit movement owners remain authoritative.
task.spawn(function()
    while true do
        task.wait(0.06)

        if not State.FarmEnabled
            or State.IsGrabbed
            or ripperSequenceRunning
            or not character
            or not character.Parent
            or not humanoid
            or humanoid.Health <= 0
            or not rootPart then
            continue
        end

        local cutsceneBusy = V94CutsceneDirector
            and tostring(V94CutsceneDirector.State or "IDLE") ~= "IDLE"
        local colossalTransition = V55ColossalDirector
            and V55ColossalDirector.TransitionActive == true
        local femaleTransition = V521FemaleDirector
            and V521FemaleDirector.TransitionActive == true
        local movementMode = V577MovementAuthority
            and V577MovementAuthority.Mode
            and V577MovementAuthority.Mode()
            or "NORMAL"
        local raidPause = false
        if V4RaidDirector and V4RaidDirector.ShouldPauseCombat then
            pcall(function()
                raidPause = V4RaidDirector.ShouldPauseCombat() == true
            end)
        end

        if movementMode == "NORMAL"
            and not raidPause
            and not cutsceneBusy
            and not colossalTransition
            and not femaleTransition then
            pcall(lockCharacterInSky, nil)
        end
    end
end)

