-- BLADE FARM ENGINE
---------------------------------------------------------------------

local function fireBladeRemote(titan)
	if not CachedBladeRemote then
		CachedBladeRemote = resolvePath(ReplicatedStorage, Config.BladeRemotePath) or scanNetworkForRemote({"swing", "blade", "slash", "hit", "attack", "m1"})
	end
    if not CachedBladeRemote then
        BladeDiag.LastRemote = "optional:none"
        return false
    end
    BladeDiag.LastRemote = CachedBladeRemote:GetFullName()

	if CachedBladeRemote:IsA("RemoteEvent") then
		if Config.SendTitanToBladeRemote then CachedBladeRemote:FireServer(titan) else CachedBladeRemote:FireServer() end
		return true
	elseif CachedBladeRemote:IsA("RemoteFunction") then
		task.spawn(function() if Config.SendTitanToBladeRemote then CachedBladeRemote:InvokeServer(titan) else CachedBladeRemote:InvokeServer() end end)
		return true
	end
	return false
end

V6ExactBlade = V6ExactBlade or {
    Version = "9.0.0",
    Targets = {},
    NextCycleAt = 0,
    LastSlashAt = 0,
    LastCycleTargets = 0,
    LastCycleSlashes = 0,
    TotalSlashes = 0,
    TotalRegisters = 0,
    Status = "Booting V9 raid combat matrix",
}

function V6ExactBlade.GetPOST()
    local post = resolvePath(ReplicatedStorage, {"Assets", "Remotes", "POST"})
    if post and post:IsA("RemoteEvent") then return post end
    return nil
end

function V6ExactBlade.GetExactNape(titan)
    if V9RaidCombat and V9RaidCombat.ExactNape then
        return V9RaidCombat.ExactNape(titan)
    end
    if not titan or not titan.Parent then return nil end
    local hitboxes = titan:FindFirstChild("Hitboxes")
    local hit = hitboxes and hitboxes:FindFirstChild("Hit")
    local nape = hit and hit:FindFirstChild("Nape")
    if nape and nape:IsA("BasePart") and nape.Parent then return nape end
    return nil
end

function V6ExactBlade.TargetAllowed(titan)
    if not titan or not titan.Parent or not isTitanAlive(titan) then return false end
    if V58BladeEngine and V58BladeEngine.AllowedTitan and not V58BladeEngine.AllowedTitan(titan) then
        return false
    end
    return V6ExactBlade.GetExactNape(titan) ~= nil
end

function V6ExactBlade.PruneTargets()
    local kept = {}
    local seen = {}
    for _, titan in ipairs(V6ExactBlade.Targets or {}) do
        if V6ExactBlade.TargetAllowed(titan) and not seen[titan] then
            kept[#kept + 1] = titan
            seen[titan] = true
        end
    end
    V6ExactBlade.Targets = kept
    return seen
end

function V6ExactBlade.FillTargets()
    local maximum = math.min(
        getEffectiveTitansPerHit(),
        math.max(
            1,
            math.floor(
                tonumber(Config.V9BladeQueueMaxTargets)
                or tonumber(Config.V6ExactBladeMaxTargets)
                or SliceHubMissionTPSMax()
            )
        )
    )
    local seen = V6ExactBlade.PruneTargets()

    local function add(titan)
        if #V6ExactBlade.Targets >= maximum then return end
        if not seen[titan] and V6ExactBlade.TargetAllowed(titan) then
            seen[titan] = true
            V6ExactBlade.Targets[#V6ExactBlade.Targets + 1] = titan
        end
    end

    local requested = getBladeAttackTargets()
    for _, titan in ipairs(requested or {}) do
        add(titan)
        if #V6ExactBlade.Targets >= maximum then break end
    end

    if #V6ExactBlade.Targets < maximum then
        local folder = Workspace:FindFirstChild(Config.TitansFolderName)
        if folder then
            for _, titan in ipairs(folder:GetChildren()) do
                add(titan)
                if #V6ExactBlade.Targets >= maximum then break end
            end
        end
    end

    return V6ExactBlade.Targets
end

function V6ExactBlade.SendPlanBank(post, bank)
    if type(bank) ~= "table" or #bank == 0 then return 0, 0 end

    local low = math.floor(tonumber(Config.V6ExactBladeRegisterMin) or 625)
    local high = math.floor(tonumber(Config.V6ExactBladeRegisterMax) or 850)
    if high < low then low, high = high, low end

    post:FireServer("Attacks", "Slash", true)

    local registers = 0
    for _, item in ipairs(bank) do
        local titan = item and item.Titan
        local repeats = math.max(1, math.floor(tonumber(item and item.Repeats) or 1))
        for _ = 1, repeats do
            local nape = V6ExactBlade.GetExactNape(titan)
            if nape then
                post:FireServer(
                    "Hitboxes",
                    "Register",
                    nape,
                    math.random(low, high)
                )
                registers += 1
            end
        end
    end

    return 1, registers
end

function V6ExactBlade.PlanUniqueTitans(plan)
    local output = {}
    local seen = {}
    for _, item in ipairs(plan or {}) do
        local titan = item and item.Titan
        if titan and not seen[titan] then
            seen[titan] = true
            output[#output + 1] = titan
        end
    end
    return output
end

function V6ExactBlade.Cycle()
    if Config.V6ExactBladeEnabled ~= true then return false, 0 end
    if not State or State.BladesEnabled ~= true or State.FarmEnabled ~= true then return false, 0 end

    if Config.V93BladeAmmoDirectorEnabled == true
        and V93BladeAmmoDirector
        and V93BladeAmmoDirector.BladelessHold == true then
        V6ExactBlade.Status = "BLADELESS_HOLD"
        if V58BladeEngine then
            V58BladeEngine.SetPhase("WAIT_AMMO", tostring(V93BladeAmmoDirector.Status or "bladeless hold"), 0)
        end
        return false, 0
    end

    if refillSequenceRunning or (StationRefill and StationRefill.Running) then
        V6ExactBlade.Status = "REFILL_LOCK"
        if V58BladeEngine then V58BladeEngine.SetPhase("REFILL_LOCK", "V9.1 exact queue paused", 0) end
        return false, 0
    end

    if V91BladeRefillGuard
        and os.clock() < (tonumber(V91BladeRefillGuard.HoldUntil) or 0) then
        V6ExactBlade.Status = "BLADE_BREAK_RELOAD"
        if V58BladeEngine then V58BladeEngine.SetPhase("REFILL_LOCK", "V9.1 Break reload ownership", 0) end
        return false, 0
    end

    if V91RaidBossGuard and V91RaidBossGuard.Blocked and V91RaidBossGuard.Blocked() then
        V6ExactBlade.Status = "BOSS_INVULN_ROAR"
        V6ExactBlade.NextCycleAt = os.clock() + 0.08
        if V58BladeEngine then V58BladeEngine.SetPhase("WAIT_COOLDOWN", "Attack boss roar invulnerability", V6ExactBlade.NextCycleAt) end
        return false, 0
    end

    if V577MovementAuthority and V577MovementAuthority.Mode() == "CANNON" then
        if V55ColossalDirector
            and (V55ColossalDirector.DismountPending == true or V55ColossalDirector.RemountPending == true) then
            V6ExactBlade.Status = "CANNON_HANDSHAKE_LOCK"
            return false, 0
        end

        local mountedGuardian = V941ObjectiveGuardian
            and V941ObjectiveGuardian.ColossalMountedActive
            and V941ObjectiveGuardian.ColossalMountedActive() == true
        if not mountedGuardian then
            V6ExactBlade.Status = "CANNON_LOCK"
            return false, 0
        end
        V6ExactBlade.Status = "CANNON_GUARDIAN_REMOTE"
    end

    local now = os.clock()
    if now < (tonumber(V6ExactBlade.NextCycleAt) or 0) then
        if V58BladeEngine then
            V58BladeEngine.SetPhase(
                "WAIT_COOLDOWN",
                string.format("V9 matrix %.2fs", math.max(0, V6ExactBlade.NextCycleAt - now)),
                V6ExactBlade.NextCycleAt
            )
        end
        return false, 0
    end

    local post = V6ExactBlade.GetPOST()
    if not post then
        V6ExactBlade.Status = "POST missing"
        V6ExactBlade.NextCycleAt = now + 0.25
        return false, 0
    end

    local targets = V6ExactBlade.FillTargets()
    local plan, matrixMode = V9RaidCombat.BuildBladePlan(targets)

    if type(plan) ~= "table" or #plan == 0 then
        V6ExactBlade.Status = "NO_VALID_NAPES"
        V6ExactBlade.NextCycleAt = now + math.max(0.02, tonumber(Config.V6ExactBladeNoTargetDelay) or 0.05)
        if V58BladeEngine then
            V58BladeEngine.SetPhase("NO_VALID_WAVE", "V9 matrix empty", V6ExactBlade.NextCycleAt)
        end
        return false, 0
    end

    local uniqueTargets = V6ExactBlade.PlanUniqueTitans(plan)
    local snapshot = V58BladeEngine and V58BladeEngine.BeginBurstSnapshot(
        uniqueTargets,
        V58BladeEngine.Mode or "PACK SWEEP",
        "V9 RAID MATRIX"
    ) or nil

    bladeBurstRunning = true
    BladeDiag.BurstStartedAt = now

    local slashCount = 0
    local registerCount = 0
    local ok, err = pcall(function()
        local raidEnabled = V4RaidDirector and V4RaidDirector.Enabled == true
        local bankSize = math.min(
            getEffectiveTitansPerHit(),
            math.max(1, math.floor(tonumber(Config.V9BladeBankSize) or 10))
        )

        local objectiveGuardianPlan = string.find(
            tostring(matrixMode or ""),
            "OBJECTIVE GUARDIAN",
            1,
            true
        ) ~= nil

        if (not raidEnabled or objectiveGuardianPlan) and #plan > bankSize then
            local bankA = {}
            local bankB = {}
            for index, item in ipairs(plan) do
                if index <= bankSize then
                    bankA[#bankA + 1] = item
                else
                    bankB[#bankB + 1] = item
                end
            end

            local s1, r1 = V6ExactBlade.SendPlanBank(post, bankA)
            slashCount += s1
            registerCount += r1

            if #bankB > 0 then
                task.wait(math.max(0.05, tonumber(Config.V9BladeSecondBankDelay) or 0.12))
                local s2, r2 = V6ExactBlade.SendPlanBank(post, bankB)
                slashCount += s2
                registerCount += r2
            end
        else
            local s, r = V6ExactBlade.SendPlanBank(post, plan)
            slashCount += s
            registerCount += r
        end
    end)

    bladeBurstRunning = false
    BladeDiag.BurstStartedAt = 0

    if not ok then
        V6ExactBlade.Status = "REMOTE_ERROR: " .. tostring(err)
        V6ExactBlade.NextCycleAt = os.clock() + 0.20
        return false, 0
    end

    BladeBurstSerial += 1
    lastBladeBurstCount = math.max(1, registerCount)
    lastBladeBurstFinishedAt = os.clock()
    V6ExactBlade.LastSlashAt = now
    V6ExactBlade.LastCycleTargets = registerCount
    V6ExactBlade.LastCycleSlashes = slashCount
    V6ExactBlade.TotalSlashes += slashCount
    V6ExactBlade.TotalRegisters += registerCount

    V9RaidCombat.BladeMode = tostring(matrixMode or "UNKNOWN")
    V9RaidCombat.LastBladeRegisters = registerCount
    V9RaidCombat.LastBladeSlashes = slashCount
    if string.find(V9RaidCombat.BladeMode, "BOSS", 1, true) then
        V9RaidCombat.BossBladeCycles += 1
    else
        V9RaidCombat.PackBladeCycles += 1
    end

    V6ExactBlade.Status = string.format(
        "%s • Slash x%d • Reg %d",
        tostring(matrixMode or "V9"),
        slashCount,
        registerCount
    )

    local bossMode = string.find(tostring(matrixMode or ""), "BOSS", 1, true) ~= nil
    local cadence = bossMode
        and math.max(0.12, tonumber(Config.V9BossBladeCadence) or 0.21)
        or math.max(0.12, tonumber(Config.V9BladeCycleCadence) or tonumber(Config.V6ExactBladeCadence) or 0.24)

    V6ExactBlade.NextCycleAt = now + cadence
    nextBladeAttack = V6ExactBlade.NextCycleAt

    if V58BladeEngine then
        V58BladeEngine.SetPhase("READY", V6ExactBlade.Status, V6ExactBlade.NextCycleAt)
        V58BladeEngine.Status = "V9 RAID MATRIX • " .. V6ExactBlade.Status
    end

    if snapshot and V58BladeEngine then
        task.delay(0.42, function()
            pcall(function()
                V58BladeEngine.FinishBurstSnapshot(snapshot)
            end)
        end)
    end

    return true, registerCount
end

local function swingBlades()
    if Config.V6ExactBladeEnabled == true then
        return V6ExactBlade.Cycle()
    end

    if ripperSequenceRunning then
        BladeDiag.Reason = "BLOCK:RIPPER"
        if V58BladeEngine then V58BladeEngine.SetPhase("BLASTER_LOCK", "ability window", 0) end
        return false, 0
    end
    if refillSequenceRunning then
        BladeDiag.Reason = "BLOCK:REFILL"
        if V58BladeEngine then V58BladeEngine.SetPhase("REFILL_LOCK", "blade refill", 0) end
        return false, 0
    end
    if bladeBurstRunning then
        BladeDiag.Reason = "BLOCK:BURST_RUNNING"
        if V58BladeEngine then V58BladeEngine.SetPhase("BURST_ACTIVE", "physical wave running", 0) end
        return false, 0
    end

    local currentTime = os.clock()
    if currentTime < nextBladeAttack then
        BladeDiag.Reason = "BLOCK:COOLDOWN"
        if V58BladeEngine then
            V58BladeEngine.SetPhase(
                "WAIT_COOLDOWN",
                string.format("%.2fs", math.max(0, nextBladeAttack - currentTime)),
                nextBladeAttack
            )
        end
        return false, 0
    end

	local requestedTargets = getBladeAttackTargets()
	local validTargets = {}
	local seen = {}
	local maximumTargets = getEffectiveTitansPerHit()
    local bladeV3Mode = V58BladeEngine and V58BladeEngine.Mode or "PACK SWEEP"
    local hybridBurst = V58BladeEngine and V58BladeEngine.HybridBurstRequested == true
    if hybridBurst then
        maximumTargets = math.min(
            maximumTargets,
            math.max(1, math.floor(tonumber(Config.BladeV3HybridMaxTargets) or 2))
        )
    end

	if State.AutoRefillEnabled and lastBladeSegments ~= nil then
		local segments = tonumber(lastBladeSegments) or 0
        if segments <= 0 then
            BladeDiag.Reason = "BLOCK:SEGMENTS_0"
            nextBladeAttack = currentTime + math.max(0.12, tonumber(Config.AutoRefillPostPressDelay) or 0.18)
            if V58BladeEngine then V58BladeEngine.SetPhase("WAIT_AMMO", "segments 0", nextBladeAttack) end
            return false, 0
		elseif segments <= (tonumber(Config.BladeBurstMinimumSegments) or 2) then
			maximumTargets = math.min(maximumTargets, math.max(1, tonumber(Config.BladeBurstLowSegmentCap) or 2))
		end
	end

	for _, titan in ipairs(requestedTargets) do
		if #validTargets >= maximumTargets then break end
		if titan and not seen[titan] and isTitanAlive(titan) and not isTitanBlacklisted(titan) then
			seen[titan] = true
			table.insert(validTargets, titan)
		end
	end

	if #validTargets == 0 then
        BladeDiag.Reason = "BLOCK:NO_TARGETS"
        cachedTitanCandidatesAt = 0
        nextBladeAttack = currentTime + math.max(0.015, tonumber(Config.BladeV31NoTargetRescanDelay) or 0.040)
        if V58BladeEngine then
            V58BladeEngine.SetPhase("NO_VALID_WAVE", "refreshing Titan cache", nextBladeAttack)
        end
        return false, 0
    end

	local targetCount = #validTargets
	local bladeOnlySaw = AdaptiveCombatMode ~= "Ripper"
	local burstRounds = bladeOnlySaw
		and math.clamp(math.floor((tonumber(Config.BladeOnlyBurstRounds) or 2) + 0.5), 1, 3)
		or math.clamp(math.floor((tonumber(Config.RipperBladeBurstRounds) or 2) + 0.5), 1, 3)
	local clickRepeats = bladeOnlySaw
		and math.clamp(math.floor((tonumber(Config.BladeOnlyClickRepeats) or 2) + 0.5), 1, 3)
		or math.clamp(math.floor((tonumber(Config.RipperBladeClickRepeats) or 1) + 0.5), 1, 3)

	local aliveCount = getCachedAliveTitanCount()
	local finisherMode = targetCount <= 3 or aliveCount <= math.max(1, tonumber(Config.FinisherTitanCount) or 5)
	if finisherMode then
		burstRounds = math.max(burstRounds, math.clamp(math.floor((tonumber(Config.FinisherBladeRounds) or 4) + 0.5), 3, 5))
		clickRepeats = math.max(clickRepeats, math.clamp(math.floor((tonumber(Config.FinisherClickRepeats) or 3) + 0.5), 2, 6))
		Config.TargetStallTimeout = math.min(tonumber(Config.TargetStallTimeout) or 0.75, tonumber(Config.FinisherTargetStallTimeout) or 0.45)
	end

    local waveSize = math.clamp(math.floor((tonumber(Config.BladeBurstWaveSize) or 4) + 0.5), 1, 20)
    local dynamicPhysicalClicks = math.max(1, math.floor(tonumber(Config.MainPhysicalClicksPerWave) or 2))

    if finisherMode then
        waveSize = 1
        dynamicPhysicalClicks = math.max(1, math.floor(tonumber(Config.FinisherPhysicalClicksPerWave) or 3))
        burstRounds = math.max(burstRounds, 5)
    elseif Config.DynamicSweepEnabled == true then
        if targetCount >= math.max(1, tonumber(Config.DenseSweepMinTargets) or 12) then
            waveSize = math.max(1, math.floor(tonumber(Config.DenseSweepWaveSize) or 6))
            dynamicPhysicalClicks = math.max(1, math.floor(tonumber(Config.DenseSweepClicks) or 3))
        elseif targetCount >= math.max(1, tonumber(Config.MediumSweepMinTargets) or 6) then
            waveSize = math.max(1, math.floor(tonumber(Config.MediumSweepWaveSize) or 4))
            dynamicPhysicalClicks = math.max(1, math.floor(tonumber(Config.MediumSweepClicks) or 2))
        else
            waveSize = math.max(1, math.floor(tonumber(Config.SparseSweepWaveSize) or 2))
            dynamicPhysicalClicks = math.max(1, math.floor(tonumber(Config.SparseSweepClicks) or 1))
        end
    end

    if bladeOnlySaw and not finisherMode then
        dynamicPhysicalClicks = math.min(
            math.max(dynamicPhysicalClicks + math.floor(tonumber(Config.BladeOnlyExtraClicksPerWave) or 1), 1),
            math.max(1, math.floor(tonumber(Config.BladeOnlyMaxPhysicalClicks) or 4))
        )
    end

    local bladePulseDuration = tonumber(Config.BladeForcePulseDuration) or 0.16
    local waveDelay = math.max(0.025, tonumber(Config.BladeBurstWaveDelay) or 0.034)
    if hybridBurst then
        waveSize = math.min(
            targetCount,
            math.max(1, math.floor(tonumber(Config.BladeV3HybridMaxTargets) or 2))
        )
        burstRounds = math.max(1, math.floor(tonumber(Config.BladeV3HybridRounds) or 1))
        clickRepeats = 1
        dynamicPhysicalClicks = math.max(1, math.floor(tonumber(Config.BladeV3HybridClicks) or 1))
        bladePulseDuration = math.max(0.025, tonumber(Config.BladeV3HybridPulseDuration) or 0.045)
        waveDelay = math.max(0.010, tonumber(Config.BladeV3HybridWaveDelay) or 0.018)
    end

	local waveCount = math.max(1, math.ceil(targetCount / waveSize))
	local burstDuration = math.max(
		Config.BladeCooldown,
		(targetCount * burstRounds) * Config.MultiTargetRemoteSpacing
			+ (waveCount * burstRounds) * (
                bladePulseDuration
				+ (tonumber(Config.BladeWaveReturnPadding) or 0.02)
			)
			+ Config.MultiTargetBurstPadding
	)

    -- V5.8.1 continuity: bladeBurstRunning already owns the real execution window.
    -- Keep only a tiny anti-double-fire guard here; completion/verification decides
    -- the next real action time from observed progress.
    nextBladeAttack = currentTime + math.max(
        tonumber(Config.BladeCooldown) or 0.105,
        tonumber(Config.BladeV31CooldownGuard) or 0.060
    )
	lastBladeBurstCount = targetCount
	BladeBurstSerial += 1

    local burstSnapshot = V58BladeEngine and V58BladeEngine.BeginBurstSnapshot(
        validTargets,
        bladeV3Mode,
        hybridBurst and "HYBRID" or "BLADE"
    ) or nil

	local verificationTitan =
        (bladeV3Mode == "SURVIVOR HUNT" and V58BladeEngine and V58BladeEngine.SurvivorTarget)
        or currentTarget
        or validTargets[1]
	local verificationHealth = nil
	local aliveBeforeBurst = getCachedAliveTitanCount()
	if verificationTitan then
		local verificationHumanoid = verificationTitan:FindFirstChildOfClass("Humanoid")
		verificationHealth = verificationHumanoid and verificationHumanoid.Health or nil
	end

	local function getWaveAim(startIndex, endIndex)
		local sum = Vector3.zero
		local count = 0
		local firstPart = nil

		for index = startIndex, endIndex do
			local titan = validTargets[index]
			if titan and isTitanAlive(titan) then
				local part = V58BladeEngine and V58BladeEngine.AimPartForTitan(titan) or getTitanTargetPart(titan)
				if part and part.Parent then
					firstPart = firstPart or part
					sum += part.Position
					count += 1
				end
			end
		end

		if count > 0 then
			return sum / count, firstPart
		end

		return CombatAnchorRuntime.AimPosition
			or (currentTargetPart and currentTargetPart.Position),
			currentTargetPart
	end

	-- V5.8: hybrid ownership is only asserted after a real target wave survives all gates.
    if V58BladeEngine then V58BladeEngine.HybridBurstActive = hybridBurst end
	bladeBurstRunning = true
    BladeDiag.BurstStartedAt = currentTime
	task.spawn(function()
		pcall(function()
			for round = 1, burstRounds do
				local waveStart = 1
				while waveStart <= targetCount and State.FarmEnabled do
					local waveEnd = math.min(targetCount, waveStart + waveSize - 1)
					local waveAimPosition, waveAimPart = getWaveAim(waveStart, waveEnd)

					-- DEV14 sustained blade route: reacquire/equip the actual blade Tool, then create
					-- force, then click while force is live, then fan out only this micro-wave.
                    local waveBladeTool = prepareBladeWaveTool()
                    if waveAimPosition then
                        triggerCombatForcePulse(
                            waveAimPosition,
                            bladePulseDuration
                        )
                        task.wait(math.max(
                            0.005,
                            tonumber(Config.BladeWavePulseLead) or 0.030
                        ))
                    end

                    local physicalClicks = dynamicPhysicalClicks

                    for clickIndex = 1, physicalClicks do
                        if not State.FarmEnabled then break end

                        if clickIndex > 1 then
                            task.wait(math.max(
                                0.015,
                                tonumber(Config.BladeWaveClickSpacing) or 0.026
                            ))
                        end

                        local chosenIndex
                        if physicalClicks <= 1 or waveEnd <= waveStart then
                            chosenIndex = waveStart
                        else
                            local alpha = (clickIndex - 1) / (physicalClicks - 1)
                            chosenIndex = math.floor(
                                waveStart + ((waveEnd - waveStart) * alpha) + 0.5
                            )
                        end

                        local clickTitan = validTargets[chosenIndex]
                        local clickPart = clickTitan and (V58BladeEngine and V58BladeEngine.AimPartForTitan(clickTitan) or getTitanTargetPart(clickTitan)) or nil

                        if waveBladeTool and waveBladeTool.Parent == character then
                            pcall(function()
                                waveBladeTool:Activate()
                            end)
                        end

                        simulateCenterMouseClick(
                            clickPart
                            or waveAimPart
                            or waveAimPosition
                            or currentTargetPart
                        )
                    end

					for index = waveStart, waveEnd do
						if not State.FarmEnabled then break end
						local titan = validTargets[index]
						if titan and isTitanAlive(titan) then
							fireBladeRemote(titan)
						end
						if index < waveEnd then
							task.wait(Config.MultiTargetRemoteSpacing)
						end
					end

					-- Give the pulse return a moment to settle before the next micro-wave.
					task.wait(math.max(0.005, tonumber(Config.BladeWaveReturnPadding) or 0.020))
					waveStart = waveEnd + 1
					if waveStart <= targetCount then
						task.wait(waveDelay)
					end
				end
			end
		end)

        if V58BladeEngine then
            V58BladeEngine.ReturnToSafeLane("post-burst safe lane")
            V58BladeEngine.SetPhase("VERIFY", "checking real HP / kills", 0)
        end

		bladeBurstRunning = false
        BladeDiag.BurstStartedAt = 0
        if V58BladeEngine then V58BladeEngine.HybridBurstActive = false end
		lastBladeBurstFinishedAt = os.clock()

		-- DEV14: verify both the primary target and total alive count. A burst that kills other Titans
		-- is still real progress. Repeated zero-progress bursts rebuild blade Tool/remote caches and back off briefly.
		task.wait(math.max(0.02, tonumber(Config.BladeProgressVerifyDelay) or 0.10))
		local burstMadeProgress = false
		local aliveAfterBurst = getCachedAliveTitanCount()
        local burstStats = V58BladeEngine and V58BladeEngine.FinishBurstSnapshot(burstSnapshot) or nil

        if burstStats and (
            (tonumber(burstStats.Registered) or 0) > 0
            or (tonumber(burstStats.Kills) or 0) > 0
        ) then
            burstMadeProgress = true
        end

		if aliveAfterBurst < aliveBeforeBurst then
			burstMadeProgress = true
		end

		if verificationTitan then
			local verificationHumanoid = verificationTitan:FindFirstChildOfClass("Humanoid")
			if not verificationHumanoid or verificationHumanoid.Health <= 0 or not verificationTitan.Parent then
				burstMadeProgress = true
				BladeBurstFailureCounts[verificationTitan] = nil
				if currentTarget == verificationTitan then clearCurrentTarget(false) end
			elseif verificationHealth ~= nil and verificationHumanoid.Health < verificationHealth - Config.HealthProgressEpsilon then
				burstMadeProgress = true
				BladeBurstFailureCounts[verificationTitan] = nil
				targetLastProgressTime = os.clock()
			elseif bladeV3Mode == "SURVIVOR HUNT" then
                -- Survivor Hunter owns no-progress recovery: switch exact body reference first,
                -- then rotate the stale Titan only after a complete part cycle.
                BladeBurstFailureCounts[verificationTitan] = nil
			else
				local failures = (BladeBurstFailureCounts[verificationTitan] or 0) + 1
				BladeBurstFailureCounts[verificationTitan] = failures
                if failures >= math.max(1, tonumber(Config.BladeFailedBurstLimit) or 2) then
                    BladeBurstFailureCounts[verificationTitan] = nil
                    if currentTarget == verificationTitan then
                        clearCurrentTarget(not finisherMode)
                    end
                    cachedTitanCandidatesAt = 0
                end
			end
		end

        if bladeV3Mode == "SURVIVOR HUNT" and V58BladeEngine then
            V58BladeEngine.RecordSurvivorBurst(
                verificationTitan,
                verificationHealth,
                aliveBeforeBurst,
                burstMadeProgress
            )
        end

        if burstMadeProgress then
            BladeEngineNoProgressBursts = 0
            cachedTitanCandidatesAt = 0
            V52KillingEngine.LastHandoffAt = os.clock()
            V52KillingEngine.Status = "Progress confirmed • immediate rescan"
            nextBladeAttack = os.clock() + math.max(
                0.005,
                tonumber(Config.BladeV31ImmediateRescanDelay) or 0.012
            )
            if V58BladeEngine then
                local kills = burstStats and tonumber(burstStats.Kills) or math.max(0, aliveBeforeBurst - aliveAfterBurst)
                local registered = burstStats and tonumber(burstStats.Registered) or kills
                V58BladeEngine.SetPhase(
                    "READY",
                    string.format("progress K%d / R%d", kills or 0, registered or 0),
                    nextBladeAttack
                )
            end
        else
			BladeEngineNoProgressBursts += 1
            CachedBladeTool = nil
            CachedBladeRemote = nil
            cachedTitanCandidatesAt = 0

            local recoveryLimit = math.max(1, tonumber(Config.BladeEngineRecoveryLimit) or 2)
            local hardRecovery = BladeEngineNoProgressBursts >= recoveryLimit
            if hardRecovery then
                BladeEngineNoProgressBursts = 0
            end

            local retryDelay = hardRecovery
                and math.max(0.08, tonumber(Config.BladeV31NoProgressHardBackoff) or 0.180)
                or math.max(0.02, tonumber(Config.BladeV31NoProgressRetryDelay) or 0.060)

            nextBladeAttack = os.clock() + retryDelay
            if V58BladeEngine then
                V58BladeEngine.SetPhase(
                    "RECOVERY_RETRY",
                    hardRecovery and "hard cache rebuild" or "quick tool/target rebuild",
                    nextBladeAttack
                )
            end
		end
	end)

	-- Extra real clicks are spaced independently from the remote fan-out. They support pure-blade alts
	-- without making Titan Ripper the main damage source.
	if clickRepeats > 1 then
		task.spawn(function()
			for i = 2, clickRepeats do
				task.wait(0.035)
				if not State.FarmEnabled then break end
				simulateCenterMouseClick(currentTargetPart)
			end
		end)
	end

	return true, targetCount
end


-- V2 quiet watchdog: only reports a genuinely stuck burst.
task.spawn(function()
    while true do
        task.wait(0.25)

        if State and State.FarmEnabled then
            local now = os.clock()
            if bladeBurstRunning
                and BladeDiag.BurstStartedAt > 0
                and now - BladeDiag.BurstStartedAt > 3.0 then

                BladeDiag.WatchdogResets += 1
                warn(
                    "[SliceHub V2][BLADE-WATCHDOG] clearing stale burst",
                    "age=" .. string.format("%.2f", now - BladeDiag.BurstStartedAt)
                )

                bladeBurstRunning = false
                BladeDiag.BurstStartedAt = 0
                BladeDiag.Reason = "WATCHDOG:BURST_RESET"
                nextBladeAttack = 0
            end
        end
    end
end)

---------------------------------------------------------------------
-- TITAN RIPPER HOTBAR ENGINE (AUTO SLOTS 1-5)
---------------------------------------------------------------------


---------------------------------------------------------------------
-- V4 TITAN BLASTER NAPE LOCK
---------------------------------------------------------------------

V4BlasterNapeLock = V4BlasterNapeLock or {
    Active = false,
    Token = 0,
    Queue = {},
    SkillId = nil,
    Status = "Idle",
    Center = nil,
    Dynamic = false,
    TargetCount = 0,
    LastRefreshAt = 0,
}

function V4BlasterNapeLock.BuildQueue(limit, center)
    local entries =
        V35Spears
        and V35Spears.GetGlobalEntries
        and V35Spears.GetGlobalEntries()
        or {}

    local candidates = {}

    for _, entry in ipairs(entries) do
        local titan = entry.Titan
        local part =
            titan
            and (
                titan:FindFirstChild("Nape", true)
                or entry.Part
            )
            or nil

        if part and part:IsA("BasePart") and part.Parent then
            local distanceSquared = 0

            if typeof(center) == "Vector3" then
                local delta = part.Position - center
                distanceSquared = delta:Dot(delta)
            end

            candidates[#candidates + 1] = {
                Titan = titan,
                Part = part,
                DistanceSquared = distanceSquared,
            }
        end
    end

    table.sort(candidates, function(a, b)
        return a.DistanceSquared < b.DistanceSquared
    end)

    local queue = {}
    local seen = {}

    for _, candidate in ipairs(candidates) do
        if #queue >= limit then
            break
        end

        if candidate.Titan
            and not seen[candidate.Titan] then

            seen[candidate.Titan] = true
            queue[#queue + 1] = candidate.Part
        end
    end

    return queue
end

function V4BlasterNapeLock.AimAt(part)
    if not part or not part.Parent then
        return false
    end

    local position = part.Position

    pcall(function()
        local camera = Workspace.CurrentCamera

        if camera then
            camera.CFrame = CFrame.lookAt(camera.CFrame.Position, position)

            -- Hellfire Barrage calls Spears.Get_Location() for every shot.
            -- That function reads UIS:GetMouseLocation(), so camera steering alone
            -- is not enough when the player's cursor is off-center. Move the real
            -- virtual cursor onto the projected live nape every lock tick.
            local screenPoint, onScreen = camera:WorldToScreenPoint(position)
            if onScreen then
                VirtualInputManager:SendMouseMoveEvent(
                    math.floor(screenPoint.X + 0.5),
                    math.floor(screenPoint.Y + 0.5),
                    game
                )
            end
        end

        if rootPart and rootPart.Parent then
            local flatTarget = Vector3.new(
                position.X,
                rootPart.Position.Y,
                position.Z
            )

            if (flatTarget - rootPart.Position).Magnitude > 0.1 then
                rootPart.CFrame = CFrame.lookAt(rootPart.Position, flatTarget)
            end
        end
    end)

    return true
end

function V4BlasterNapeLock.Start(skillId, duration, center)
    local id = tostring(skillId)
    local dynamicBladeSweep =
        Config.BladeBlasterDynamicSweepEnabled == true
        and (id == "14" or id == "23")

    local targetCount
    if id == "135" then
        targetCount = 4
    elseif id == "126" then
        targetCount = 3
    elseif id == "23" then
        targetCount = math.max(4, math.floor(tonumber(Config.BladeBlasterTorrentialTargets) or 18))
    elseif id == "14" then
        targetCount = math.max(3, math.floor(tonumber(Config.BladeBlasterDrillTargets) or 8))
    else
        targetCount = 3
    end

    local queue = V4BlasterNapeLock.BuildQueue(targetCount, center)

    if #queue == 0 then
        V4BlasterNapeLock.Status = "No live napes"
        return false
    end

    V4BlasterNapeLock.Token += 1
    local token = V4BlasterNapeLock.Token

    V4BlasterNapeLock.Active = true
    V4BlasterNapeLock.Queue = queue
    V4BlasterNapeLock.SkillId = id
    V4BlasterNapeLock.Center = center
    V4BlasterNapeLock.Dynamic = dynamicBladeSweep
    V4BlasterNapeLock.TargetCount = targetCount
    V4BlasterNapeLock.LastRefreshAt = os.clock()

    task.spawn(function()
        local started = os.clock()
        local totalDuration = math.max(0.6, tonumber(duration) or 1.8)
        local refreshDelay = math.max(0.04, tonumber(Config.BladeBlasterSweepRefresh) or 0.080)
        local minimumDwell = math.max(0.025, tonumber(Config.BladeBlasterTargetDwellMin) or 0.055)
        local activeQueue = queue
        local lastRefresh = 0

        local label =
            id == "135" and "Meteoric"
            or id == "126" and "Hellfire"
            or id == "23" and "Torrential"
            or id == "14" and "Drill"
            or ("Skill " .. id)

        while V4BlasterNapeLock.Active
            and V4BlasterNapeLock.Token == token
            and os.clock() - started < totalDuration do

            local now = os.clock()
            local elapsed = now - started

            if dynamicBladeSweep and now - lastRefresh >= refreshDelay then
                lastRefresh = now
                local rebuilt = V4BlasterNapeLock.BuildQueue(targetCount, center)
                if #rebuilt > 0 then
                    activeQueue = rebuilt
                    V4BlasterNapeLock.Queue = rebuilt
                    V4BlasterNapeLock.LastRefreshAt = now
                end
            end

            local shotCount = #activeQueue
            if shotCount <= 0 then
                V4BlasterNapeLock.Status = label .. " • no live napes"
                task.wait(0.016)
                continue
            end

            local index
            if dynamicBladeSweep then
                local idealDwell = totalDuration / math.max(1, targetCount)
                local dwell = math.max(minimumDwell, idealDwell)
                index = (math.floor(elapsed / dwell) % shotCount) + 1
            else
                local shotWindow = totalDuration / math.max(1, shotCount)
                index = math.clamp(math.floor(elapsed / shotWindow) + 1, 1, shotCount)
            end

            local part = activeQueue[index]
            if not part or not part.Parent then
                for _, fallback in ipairs(activeQueue) do
                    if fallback and fallback.Parent then
                        part = fallback
                        break
                    end
                end
            end

            if part then
                V4BlasterNapeLock.AimAt(part)
                V4BlasterNapeLock.Status = string.format(
                    "%s nape %d/%d%s",
                    label,
                    index,
                    shotCount,
                    dynamicBladeSweep and " LIVE" or ""
                )
            end

            task.wait(0.016)
        end

        if V4BlasterNapeLock.Token == token then
            V4BlasterNapeLock.Active = false
            V4BlasterNapeLock.Dynamic = false
            V4BlasterNapeLock.Status = "Idle"
        end
    end)

    print(
        "[SliceHub V6.0.0][BLASTER-SWEEP]",
        "skill=" .. id,
        "targets=" .. tostring(#queue),
        "dynamic=" .. tostring(dynamicBladeSweep)
    )

    return true
end

function V4BlasterNapeLock.Stop()
    V4BlasterNapeLock.Token += 1
    V4BlasterNapeLock.Active = false
    V4BlasterNapeLock.Queue = {}
    V4BlasterNapeLock.Dynamic = false
    V4BlasterNapeLock.TargetCount = 0
    V4BlasterNapeLock.Center = nil
    V4BlasterNapeLock.Status = "Idle"
end

;(function() -- scoped so Titan Blaster does not blow Luau's 200 local-register limit
    local TitanBlasterSkillInfo = {
        ["126"] = {
            Name = "Hellfire Barrage",
            Short = "HELLFIRE",
            Cooldown = 50,
