		[2] = {RootFound = false, HasAbility = false, Ready = false, Remaining = nil, Source = "fallback"},
		[3] = {RootFound = false, HasAbility = false, Ready = false, Remaining = nil, Source = "fallback"},
		[4] = {RootFound = false, HasAbility = false, Ready = false, Remaining = nil, Source = "fallback"},
		[5] = {RootFound = false, HasAbility = false, Ready = false, Remaining = nil, Source = "fallback"},
	}
	local RipperLearnedCooldown = {
		[1] = Config.TitanRipperDefaultCooldown,
		[2] = Config.TitanRipperDefaultCooldown,
		[3] = Config.TitanRipperSlot3Cooldown or Config.TitanRipperDefaultCooldown,
		[4] = Config.TitanRipperSlot4Cooldown or Config.TitanRipperDefaultCooldown,
		[5] = Config.TitanRipperDefaultCooldown,
	}
	local RipperLastCastAt = {}
	local RipperPendingLearn = {}
	local RipperSawCooldownAfterCast = {}
	local RipperEmptyUntil = {} -- v116: empty/failed slots get ignored so alt accounts enter BladeOnly fast.
	local LastRipperUiScanAt = 0
	local RipperUiScanDelay = 0.16

	local function getRipperSlotByNumber(slotNumber)
		for _, slot in ipairs(RipperSlots) do
			if slot.Number == slotNumber then
				return slot
			end
		end
		return nil
	end

	local function getRipperFallbackCooldown(slotNumber)
        local state = RipperUiState[slotNumber]
        local exactInfo =
            state
            and state.SkillId
            and TitanBlasterSkillInfo[state.SkillId]
            or nil

        if exactInfo and tonumber(exactInfo.Cooldown) then
            return tonumber(exactInfo.Cooldown)
        end

		local learned = tonumber(RipperLearnedCooldown[slotNumber])
		if learned and learned >= 8 and learned <= 90 then
			return learned
		end

		local slot = getRipperSlotByNumber(slotNumber)
		return (slot and tonumber(slot.Cooldown))
            or (tonumber(Config.TitanBlasterFallbackCooldown) or 50)
	end

	local function ripperSlotAllowed(slotNumber)
		local key = "AbilitySlot" .. tostring(slotNumber) .. "Enabled"
		local blockedUntil = tonumber(RipperEmptyUntil[slotNumber]) or 0
		if os.clock() < blockedUntil then return false end
		return not State or State[key] ~= false
	end

	local function ripperCleanText(value)
		local text = tostring(value or "")
		text = string.gsub(text, "<.->", "")
		text = string.gsub(text, "^%s+", "")
		text = string.gsub(text, "%s+$", "")
