	end

	local function ripperLower(value)
		return string.lower(ripperCleanText(value))
	end

    local function titanBlasterSkillIdFromRoot(root)
        if not root then return nil end

        local node = root

        while node and node ~= playerGui do
            local skillId = nil

            pcall(function()
                skillId = node:GetAttribute("Skill")
            end)

