            return true
        end

        local ammo = V35Spears and V35Spears.ReadAmmo and V35Spears.ReadAmmo() or nil

        if ammo == nil then
            return false
        end

        -- Preserve one spear so V3.6.1 safety refill never falls into the 0-ammo drop state.
        return ammo >= (tonumber(info.Cost) or 0) + 1
    end

	local function objectInsideTitanControlGui(object)
		local node = object
		while node do
			if node.Name == "TitanControlMenu" then
				return true
			end
			node = node.Parent
		end
