	end

	local function hotbarRootLooksVisible(root)
		return root and root:IsA("GuiObject") and root.Parent and not objectInsideTitanControlGui(root) and guiObjectIsActuallyVisible(root)
	end

	local function rootHasSlotText(root, slotNumber)
		local targetText = tostring(slotNumber)
		for _, child in ipairs(root:GetDescendants()) do
			if (child:IsA("TextLabel") or child:IsA("TextButton") or child:IsA("TextBox")) and guiObjectIsActuallyVisible(child) then
				if ripperCleanText(child.Text) == targetText then
					return true
				end
			end
		end
		return false
	end

	local function candidateHotbarScore(object, slotNumber)
		if not object:IsA("GuiObject") or not guiObjectIsActuallyVisible(object) or objectInsideTitanControlGui(object) then
			return -math.huge
		end

		local size = object.AbsoluteSize
		if size.X < 24 or size.Y < 24 or size.X > 190 or size.Y > 190 then
			return -math.huge
		end

		local slotText = tostring(slotNumber)
		local score = 0
		local node = object
		for depth = 0, 5 do
			if not node or node == playerGui then break end
			local name = ripperLower(node.Name)
			if string.find(name, "hotbar", 1, true) or string.find(name, "ability", 1, true) or string.find(name, "skill", 1, true) or string.find(name, "slot", 1, true) or string.find(name, "toolbar", 1, true) then
				score += 7 - math.min(depth, 5)
			end
			if string.find(name, "slot" .. slotText, 1, true) or string.find(name, "slot_" .. slotText, 1, true) or name == slotText then
				score += 8
			end
			node = node.Parent
		end

		if object.Name == slotText then
			score += 8
		end
		if rootHasSlotText(object, slotNumber) then
			score += 10
		end

		return score
	end

	local function findHotbarSlotRoot(slotNumber)
		local cached = RipperUiRoots[slotNumber]
		if hotbarRootLooksVisible(cached) then
			return cached
		end

		local bestObject = nil
		local bestScore = -math.huge
		for _, object in ipairs(playerGui:GetDescendants()) do
			local score = candidateHotbarScore(object, slotNumber)
			if score > bestScore then
				bestObject = object
				bestScore = score
			end
		end

		if bestObject and bestScore >= 9 then
			RipperUiRoots[slotNumber] = bestObject
			return bestObject
		end
		return nil
	end

	local function parseCooldownNumber(text)
		text = ripperCleanText(text)
		text = string.gsub(text, "s$", "")
		local numberText = string.match(text, "^(%d+%.?%d*)$")
		local value = tonumber(numberText)
		if value and value > 0 and value <= 120 then
			return value
		end
		return nil
	end

	local function textLooksLikeReady(text)
		local lower = ripperLower(text)
		return lower == "ready" or lower == "rdy" or lower == "go" or lower == "0" or lower == "0.0"
	end

	local function slotRootHasAbilityVisual(root, slotNumber)
		if not root then return false end
		for _, object in ipairs(root:GetDescendants()) do
			if (object:IsA("ImageLabel") or object:IsA("ImageButton")) and guiObjectIsActuallyVisible(object) then
				local image = tostring(object.Image or "")
				local name = ripperLower(object.Name)
				local size = object.AbsoluteSize
				if image ~= "" and size.X >= 14 and size.Y >= 14 then
					if string.find(name, "icon", 1, true) or string.find(name, "skill", 1, true) or string.find(name, "ability", 1, true) or string.find(name, "image", 1, true) then
						return true
					end
					if size.X <= root.AbsoluteSize.X * 0.85 and size.Y <= root.AbsoluteSize.Y * 0.85 and (object.ImageTransparency or 0) < 0.95 then
						return true
					end
				end
			elseif (object:IsA("TextLabel") or object:IsA("TextButton") or object:IsA("TextBox")) and guiObjectIsActuallyVisible(object) then
				local clean = ripperLower(object.Text)
				if clean ~= "" and clean ~= tostring(slotNumber) and not parseCooldownNumber(clean) and not textLooksLikeReady(clean) then
					if string.find(clean, "ripper", 1, true) or string.find(clean, "titan", 1, true) or string.find(clean, "skill", 1, true) then
						return true
