	local function getSlotCooldownRemainingFromRoot(root, slotNumber)
		if not root then return nil, false end
		local bestValue = nil
		local bestScore = -math.huge
		local slotText = tostring(slotNumber)
		local sawReadyText = false

		for _, object in ipairs(root:GetDescendants()) do
			if (object:IsA("TextLabel") or object:IsA("TextButton") or object:IsA("TextBox")) and guiObjectIsActuallyVisible(object) then
				local text = ripperCleanText(object.Text)
				if textLooksLikeReady(text) then
					sawReadyText = true
				end

				local value = parseCooldownNumber(text)
				if value then
					local name = ripperLower(object.Name)
					local score = 0
					if string.find(name, "cool", 1, true) or string.find(name, "cd", 1, true) or string.find(name, "timer", 1, true) or string.find(name, "count", 1, true) then
						score += 10
					end
					if math.abs(value - slotNumber) < 0.01 and text == slotText then
						score -= 9
					end
					if object.TextSize and object.TextSize >= 13 then
						score += 2
					end
					local rootPos = root.AbsolutePosition
					local rootSize = root.AbsoluteSize
					local objectPos = object.AbsolutePosition
					local objectCenterX = objectPos.X + object.AbsoluteSize.X / 2
					local objectCenterY = objectPos.Y + object.AbsoluteSize.Y / 2
					local rootCenterX = rootPos.X + rootSize.X / 2
					local rootCenterY = rootPos.Y + rootSize.Y / 2
					if math.abs(objectCenterX - rootCenterX) <= rootSize.X * 0.35 and math.abs(objectCenterY - rootCenterY) <= rootSize.Y * 0.35 then
						score += 4
					end
					if score > bestScore then
						bestScore = score
						bestValue = value
					end
				end
			end
		end

		if bestValue and bestScore >= -1 then
			return bestValue, true
		end
		return nil, sawReadyText
	end

	local function hotbarSlotLooksSelected(slotNumber)
		local root = findHotbarSlotRoot(slotNumber)
		if not root then return false end

		for _, object in ipairs(root:GetDescendants()) do
			if object:IsA("UIStroke") then
				local thickness = tonumber(object.Thickness) or 0
				local transparency = tonumber(object.Transparency) or 1
				if thickness >= 1.5 and transparency <= 0.55 then
					return true
				end
			end
		end

		if character then
			local tool = character:FindFirstChildOfClass("Tool")
			if tool then
				local name = ripperLower(tool.Name)
				if string.find(name, "ripper", 1, true) or string.find(name, "titan", 1, true) or string.find(name, "skill", 1, true) then
					return true
				end
			end
		end

		return false
	end

	local function scanRipperSlotState(slotNumber, now)
		now = now or os.clock()
		local state = RipperUiState[slotNumber]
		local root = findHotbarSlotRoot(slotNumber)

		if root then
			local remaining, reliable = getSlotCooldownRemainingFromRoot(root, slotNumber)
			local hasVisual = slotRootHasAbilityVisual(root, slotNumber)
            local skillId = titanBlasterSkillIdFromRoot(root)
            local skillInfo = skillId and TitanBlasterSkillInfo[skillId] or nil
            local weapon = player and tostring(player:GetAttribute("Weapon") or "") or ""
            local exactWeaponMatch =
                skillInfo ~= nil
                and (
                    (weapon == "Spears" and skillInfo.Weapon == "Spears")
                    or (weapon ~= "Spears" and skillInfo.Weapon == "Blades")
                )

			state.RootFound = true
            state.SkillId = skillId
            state.AbilityName = skillInfo and skillInfo.Name or nil
			state.HasAbility = exactWeaponMatch
			state.Source = state.HasAbility
                and (reliable and "exact-ui" or "exact-ready")
                or (hasVisual and "other-skill" or "empty")
			state.Remaining = remaining
			state.Selected = hotbarSlotLooksSelected(slotNumber)
			if not state.HasAbility then
				state.Ready = false
				state.Remaining = nil
				nextRipperReadyAt[slotNumber] = now + 1.5
				return state
			end
			if remaining and remaining > 0.18 then
				state.Ready = false
				nextRipperReadyAt[slotNumber] = now + remaining
				if RipperPendingLearn[slotNumber] and RipperLastCastAt[slotNumber] then
					RipperSawCooldownAfterCast[slotNumber] = true
					local estimatedCooldown = (now - RipperLastCastAt[slotNumber]) + remaining
					if estimatedCooldown >= 8 and estimatedCooldown <= 90 then
						RipperLearnedCooldown[slotNumber] = estimatedCooldown
						local slot = getRipperSlotByNumber(slotNumber)
						if slot then slot.Cooldown = estimatedCooldown end
					end
				end
			else
				state.Ready = true
				state.Remaining = nil
				nextRipperReadyAt[slotNumber] = 0
				if RipperPendingLearn[slotNumber] and RipperSawCooldownAfterCast[slotNumber] and RipperLastCastAt[slotNumber] then
					local measuredCooldown = now - RipperLastCastAt[slotNumber]
					if measuredCooldown >= 8 and measuredCooldown <= 90 then
						RipperLearnedCooldown[slotNumber] = measuredCooldown
						local slot = getRipperSlotByNumber(slotNumber)
						if slot then slot.Cooldown = measuredCooldown end
					end
					RipperPendingLearn[slotNumber] = false
					RipperSawCooldownAfterCast[slotNumber] = false
				end
			end
		else
			local remaining = math.max(0, (nextRipperReadyAt[slotNumber] or 0) - now)
			state.RootFound = false
			state.HasAbility = false
            state.SkillId = nil
            state.AbilityName = nil
			state.Source = "missing"
			state.Remaining = remaining > 0 and remaining or nil
			state.Ready = false
			state.Selected = false
		end

		return state
	end

	local function refreshRipperUiState(force)
		local now = os.clock()
		if not force and now - LastRipperUiScanAt < RipperUiScanDelay then
			return
		end
		LastRipperUiScanAt = now
		for _, slot in ipairs(RipperSlots) do
			scanRipperSlotState(slot.Number, now)
		end
	end

	local function getReadyRipperSlot(now)
		refreshRipperUiState(false)
		now = now or os.clock()

        local weapon = player and tostring(player:GetAttribute("Weapon") or "") or ""
        local packCount = tonumber(V36PackDrain and V36PackDrain.PackCount) or 0

        local desiredSkillOrder

        if weapon == "Spears" then
            desiredSkillOrder =
                packCount >= 6
                and {"135", "126"}
                or {"126", "135"}
        else
            desiredSkillOrder =
                packCount >= 6
                and {"23", "14"}
                or {"14", "23"}
        end

        for _, desiredSkillId in ipairs(desiredSkillOrder) do
            for index, slot in ipairs(RipperSlots) do
                local state = RipperUiState[slot.Number]
                local fallbackReady = now >= (nextRipperReadyAt[slot.Number] or 0)
                local info = state and state.SkillId and TitanBlasterSkillInfo[state.SkillId] or nil

                if state
                    and state.SkillId == desiredSkillId
                    and state.HasAbility
                    and ripperSlotAllowed(slot.Number)
                    and (state.Ready or fallbackReady)
                    and titanBlasterAmmoAllows(info) then

                    ripperSlotCursor = (index % #RipperSlots) + 1
                    return slot
                end
            end
        end

		return nil
	end

	getRipperCooldownText = function()
		refreshRipperUiState(false)
		local now = os.clock()
		local parts = {}
		for _, slot in ipairs(RipperSlots) do
			local slotNumber = slot.Number
            local state = RipperUiState[slotNumber]
            local info = state and state.SkillId and TitanBlasterSkillInfo[state.SkillId] or nil

            if info then
                local label = tostring(info.Short or info.Name or ("S" .. tostring(slotNumber)))

                if not ripperSlotAllowed(slotNumber) then
                    table.insert(parts, label .. " OFF")
                else
                    local remaining =
                        state.Remaining
                        or math.max(0, (nextRipperReadyAt[slotNumber] or 0) - now)

                    if remaining and remaining > 0 then
                        table.insert(parts, string.format("%s %ds", label, math.ceil(remaining)))
                    else
                        table.insert(parts, label .. " READY")
                    end
                end
            end
		end
		return table.concat(parts, " | ")
	end

	TitanControlRipperAvailable = function()
		refreshRipperUiState(false)
		for _, slot in ipairs(RipperSlots) do
			local state = RipperUiState[slot.Number]
			if ripperSlotAllowed(slot.Number) and state and state.HasAbility then
				return true
			end
		end
		return false
	end

	local function waitForRipperSlotEquip(slotNumber, timeout)
		local started = os.clock()
		while os.clock() - started <= (timeout or 0.18) do
			if hotbarSlotLooksSelected(slotNumber) then
				return true
			end
			task.wait(0.025)
		end
		return false
	end

	useTitanRipper = function()
        -- V5.7.4: during a short Colossal P2 Eren-defense burst, preserve Titan
        -- Blaster cooldown/ammo for Bertholdt. Blades + Infinite Spears clear adds.
        if V4RaidDirector
            and V4RaidDirector.RaidName == "Colossal Raid"
            and V55ColossalDirector
            and V55ColossalDirector.Stage == "P2 BOSS"
            and V55ColossalDirector.DefenseMode == true then
            return nil
        end

		if not State.TitanRipperEnabled
            or ripperSequenceRunning
            or refillSequenceRunning
            or StationRefill.Running then
            return nil
        end

        if V35Spears and V35Spears.Busy then
            return nil
        end

		local now = os.clock()
		local slot = getReadyRipperSlot(now)
		if not slot then return nil end

		local slotNumber = slot.Number
        local state = RipperUiState[slotNumber]
        local skillId = state and state.SkillId or nil
        local skillInfo = skillId and TitanBlasterSkillInfo[skillId] or nil

        if not skillInfo then
            return nil
        end

        if not titanBlasterAmmoAllows(skillInfo) then
            return nil
        end

		local fallbackCooldown = getRipperFallbackCooldown(slotNumber)

		nextRipperReadyAt[slotNumber] = now + fallbackCooldown
		RipperUiState[slotNumber].Ready = false
		RipperUiState[slotNumber].Remaining = fallbackCooldown
		ripperSequenceRunning = true

		task.spawn(function()
            local weapon = player and tostring(player:GetAttribute("Weapon") or "") or ""
            local aimPart, packCount, aimPosition = chooseRipperAimPart()

            aimPosition =
                aimPosition
                or (aimPart and aimPart.Position)
                or (V36PackDrain and V36PackDrain.Center)
                or CombatAnchorRuntime.AimPosition

            if weapon == "Spears" and typeof(aimPosition) == "Vector3" then
                pcall(function()
                    local stageCFrame

                    if skillId == tostring(Config.TitanBlasterMeteoricSkillId or "135") then
                        local stagePosition =
                            aimPosition
                            + Vector3.new(
                                0,
                                tonumber(Config.TitanBlasterMeteoricStageHeight) or 58,
                                0
                            )

                        stageCFrame = CFrame.lookAt(stagePosition, aimPosition)
                    else
                        local stagePosition =
                            aimPosition
                            + Vector3.new(
                                0,
                                tonumber(Config.TitanBlasterHellfireStageHeight) or 82,
                                tonumber(Config.TitanBlasterHellfireBackOffset) or 120
                            )

                        stageCFrame = CFrame.lookAt(stagePosition, aimPosition)
                    end

                    if character and character.Parent then
                        character:PivotTo(stageCFrame)
                    end

                    if rootPart and rootPart.Parent then
                        rootPart.AssemblyLinearVelocity = Vector3.zero
                        rootPart.AssemblyAngularVelocity = Vector3.zero
                    end

                    local camera = Workspace.CurrentCamera

                    if camera then
                        camera.CFrame = CFrame.lookAt(camera.CFrame.Position, aimPosition)
                    end
                end)

                task.wait(0.04)
            elseif aimPosition then
                local camera = Workspace.CurrentCamera

                if camera then
                    pcall(function()
                        camera.CFrame = CFrame.lookAt(camera.CFrame.Position, aimPosition)
                    end)
                end

                task.wait(0.01)
            end

			if not State.FarmEnabled or not State.TitanRipperEnabled then
				nextRipperReadyAt[slotNumber] = 0
				ripperSequenceRunning = false
				return
			end

			local castTime = os.clock()
			RipperLastCastAt[slotNumber] = castTime
			RipperPendingLearn[slotNumber] = true
			RipperSawCooldownAfterCast[slotNumber] = false

            V35Spears.LastStatus =
                "Titan Blaster: "
                .. tostring(skillInfo.Name)
                .. " | Pack "
                .. tostring(packCount or 0)

            print(
                "[SliceHub V4][TITAN-BLASTER]",
                tostring(skillInfo.Name),
                "skill=" .. tostring(skillId),
                "slot=" .. tostring(slotNumber),
                "pack=" .. tostring(packCount or 0)
            )

            local blasterAliveBefore = getCachedAliveTitanCount()
            local shouldSweep =
                (skillId == "126" or skillId == "135")
                or (
                    Config.BladeBlasterDynamicSweepEnabled == true
                    and (skillId == "14" or skillId == "23")
                )

            if shouldSweep then
                V4BlasterNapeLock.Start(
                    skillId,
                    tonumber(skillInfo.Lock) or 1.8,
                    aimPosition
                )
            end

            if V58BladeEngine then
                V58BladeEngine.SetPhase(
                    "BLASTER_LOCK",
                    tostring(skillInfo.Short or skillInfo.Name),
                    os.clock() + math.max(0.25, tonumber(skillInfo.Lock) or 1.75)
                )
            end

            -- Hotbar keys invoke Core.Skills.Use directly. Nape Lock steers the viewport ray during the firing window.
			simulateHumanKeyPress(slot.KeyCode)

            local cooldownAttribute =
                "Skill_" .. tostring(slotNumber)

            local accepted = false
            local acceptedStarted = os.clock()

            while os.clock() - acceptedStarted < 0.36 do
                local value = nil

                pcall(function()
                    value = player:GetAttribute(cooldownAttribute)
                end)

                if value ~= nil then
                    accepted = true
                    break
                end

                task.wait(0.025)
            end

            if not accepted and State.FarmEnabled then
                simulateHumanKeyPress(slot.KeyCode)

                local retryStarted = os.clock()

                while os.clock() - retryStarted < 0.30 do
                    local value = nil

                    pcall(function()
                        value = player:GetAttribute(cooldownAttribute)
                    end)

                    if value ~= nil then
                        accepted = true
                        break
                    end

                    task.wait(0.025)
                end
            end

            if not accepted then
                V35Spears.LastStatus =
                    "Titan Blaster cast not confirmed: "
                    .. tostring(skillInfo.Name)

                RipperEmptyUntil[slotNumber] = os.clock() + 2.0
                nextRipperReadyAt[slotNumber] = os.clock() + 2.0
                RipperPendingLearn[slotNumber] = false

                if V4BlasterNapeLock then
                    V4BlasterNapeLock.Stop()
                end

                ripperSequenceRunning = false
                return
            end

			nextRipperReadyAt[slotNumber] =
                castTime
                + fallbackCooldown
                + Config.TitanRipperSafetyMargin

            local lockDuration =
                math.max(0.25, tonumber(skillInfo.Lock) or 1.75)

            task.wait(lockDuration)

            local blasterAliveAfter = getCachedAliveTitanCount()
            local blasterKills = math.max(0, blasterAliveBefore - blasterAliveAfter)
            if V58BladeEngine then
                V58BladeEngine.LastBlasterName = tostring(skillInfo.Short or skillInfo.Name)
                V58BladeEngine.LastBlasterKills = blasterKills
                V58BladeEngine.LastBlasterPack = tonumber(packCount) or 0
                V58BladeEngine.LastBlasterAt = os.clock()
                V58BladeEngine.SetPhase(
                    "READY",
                    string.format("%s K%d / P%d", tostring(skillInfo.Short or skillInfo.Name), blasterKills, tonumber(packCount) or 0),
                    os.clock()
                )
            end

            print(
                "[SliceHub V6.0.0][BLASTER-RESULT]",
                tostring(skillInfo.Name),
                "pack=" .. tostring(packCount or 0),
                "kills=" .. tostring(blasterKills),
                "alive=" .. tostring(blasterAliveBefore) .. "->" .. tostring(blasterAliveAfter)
            )

            if weapon == "Spears"
                and V35Spears
                and V35Spears.ClearDrainPack then

                V35Spears.ClearDrainPack(
                    "Titan Blaster " .. tostring(skillInfo.Short or skillInfo.Name)
                )
            end

			refreshRipperUiState(true)

            if V4BlasterNapeLock then
                V4BlasterNapeLock.Stop()
            end

            CachedBladeTool = nil
			ripperSequenceRunning = false
		end)

		return slotNumber
	end
end)()

---------------------------------------------------------------------
-- V5 EQUIPPED BUFF SKILL ENGINE
---------------------------------------------------------------------

V5BuffEngine = V5BuffEngine or {
    Skills = {
        ["93"] = {Name = "Order: Advance", StateKey = "BuffOrderAdvanceEnabled", Cooldown = 55},
        ["95"] = {Name = "Black Flare", StateKey = "BuffBlackFlareEnabled", Cooldown = 35},
        ["97"] = {Name = "Order: Rage", StateKey = "BuffOrderRageEnabled", Cooldown = 85},
        ["158"] = {Name = "Founder's Order", StateKey = "BuffFoundersOrderEnabled", Cooldown = 90},
        ["163"] = {Name = "Order: Revolution", StateKey = "BuffOrderRevolutionEnabled", Cooldown = 135},
    },
    Detected = {},
    LastCast = {},
    LastScanAt = 0,
    Status = "No equipped buff skills detected",
}

function V5BuffEngine.SlotFromObject(object)
    local node = object

    for _ = 1, 6 do
        if not node or node == playerGui then break end

        local lowerName = string.lower(tostring(node.Name or ""))
        local byName = string.match(lowerName, "slot[_%- ]*([1-5])")
            or string.match(lowerName, "^([1-5])$")

        if byName then
            return tonumber(byName)
        end

        if node:IsA("GuiObject") then
            local size = node.AbsoluteSize
            if size.X >= 24 and size.Y >= 24 and size.X <= 190 and size.Y <= 190 then
                for _, child in ipairs(node:GetDescendants()) do
                    if child:IsA("TextLabel") or child:IsA("TextButton") or child:IsA("TextBox") then
                        local clean = string.gsub(tostring(child.Text or ""), "%s+", "")
                        local slot = tonumber(clean)
                        if slot and slot >= 1 and slot <= 5 then
                            return slot
                        end
                    end
                end
            end
        end

        node = node.Parent
    end

    return nil
end

function V5BuffEngine.Scan(force)
    local now = os.clock()
    if not force and now - (V5BuffEngine.LastScanAt or 0) < 0.55 then
        return V5BuffEngine.Detected
    end

    V5BuffEngine.LastScanAt = now
    local detected = {}

    for _, object in ipairs(playerGui:GetDescendants()) do
        local skillId = nil
        pcall(function() skillId = object:GetAttribute("Skill") end)
        skillId = skillId ~= nil and tostring(skillId) or nil

        if skillId and V5BuffEngine.Skills[skillId] then
            local slot = V5BuffEngine.SlotFromObject(object)
            if slot then
                detected[skillId] = slot
            end
        end
    end

    V5BuffEngine.Detected = detected

    local parts = {}
    for skillId, slot in pairs(detected) do
        local info = V5BuffEngine.Skills[skillId]
        parts[#parts + 1] = tostring(info.Name) .. " [" .. tostring(slot) .. "]"
    end
    table.sort(parts)

    V5BuffEngine.Status = #parts > 0
        and ("Detected: " .. table.concat(parts, " • "))
        or "No equipped active buff skills detected"

    return detected
end

function V5BuffEngine.KeyForSlot(slot)
    local map = {
        [1] = Enum.KeyCode.One,
        [2] = Enum.KeyCode.Two,
        [3] = Enum.KeyCode.Three,
        [4] = Enum.KeyCode.Four,
        [5] = Enum.KeyCode.Five,
    }
    return map[tonumber(slot)]
end

function V5BuffEngine.CooldownValue(slot)
    if not slot then return nil end
    local value = nil
    pcall(function() value = player:GetAttribute("Skill_" .. tostring(slot)) end)
    return value
end

function V5BuffEngine.Ready(slot)
    local value = V5BuffEngine.CooldownValue(slot)
    if value == nil or value == false then return true end
    if type(value) == "number" then return value <= 0 end
    if type(value) == "string" then
        local clean = string.lower(string.gsub(value, "%s+", ""))
        if clean == "" or clean == "ready" or clean == "false" then return true end
        local numeric = tonumber(string.match(clean, "[-%d%.]+"))
        if numeric then return numeric <= 0 end
    end
    return false
end

function V5BuffEngine.CastPreCannonBurst()
    if not State.AutoUseBuffsEnabled then
        V5BuffEngine.Status = "Pre-cannon buffs disabled"
        return "Pre-cannon buffs disabled"
    end

    -- V5.7.6: Fritz / Founder's Order is prioritized first because live multi-run
    -- tests showed Black Flare + Rage were reliable while Founder's Order was
    -- the one being lost before cannon mount.
    -- V5.7.6 empirical sequence from live runs: Black Flare reliably primes the
    -- hotbar state, then Founder's Order, then remaining support, with Rage last.
    local order = {"95", "158", "93", "163", "97"}
    local castNames = {}
    V5BuffEngine.LastAttempt = V5BuffEngine.LastAttempt or {}

    local function waitForCooldownStart(slot, timeout)
        local started = os.clock()
        while os.clock() - started < timeout do
            if not V5BuffEngine.Ready(slot) then
                return true
            end
            task.wait(0.05)
        end
        return not V5BuffEngine.Ready(slot)
    end

    local function pressFor(key, holdSeconds)
        task.wait(0.02)
        VirtualInputManager:SendKeyEvent(true, key, false, game)
        task.wait(math.max(0.04, tonumber(holdSeconds) or 0.04))
        VirtualInputManager:SendKeyEvent(false, key, false, game)
    end

    for _, skillId in ipairs(order) do
        -- Re-scan before every cast. Some hotbar trees rebuild after a support
        -- skill fires, and keeping a stale slot map was enough to skip Fritz.
        local detected = V5BuffEngine.Scan(true)
        local slot = detected[skillId]
        local info = V5BuffEngine.Skills[skillId]

        if slot and info and State[info.StateKey] ~= false and V5BuffEngine.Ready(slot) then
            local key = V5BuffEngine.KeyForSlot(slot)
            if key then
                local isRage = skillId == "97"
                local isFounder = skillId == "158"
                local maxAttempts = isFounder and 4 or (isRage and 3 or 2)
                V5BuffEngine._Confirmed = false

                if isFounder then
                    task.wait(0.35)
                elseif isRage then
                    task.wait(0.55)
                end

                for attempt = 1, maxAttempts do
                    V5BuffEngine.Status = string.format(
                        "Pre-cannon cast: %s (%d/%d)",
                        tostring(info.Name), attempt, maxAttempts
                    )
                    V5BuffEngine.LastAttempt[skillId] = os.clock()

                    if isFounder then
                        -- Slightly longer held input for Fritz/Founder's Order.
                        -- Alternate the hold length on retries instead of spamming
                        -- identical 40ms taps that live tests showed could be ignored.
                        pressFor(key, attempt == 1 and 0.12 or 0.18)
                    else
                        simulateHumanKeyPress(key)
                    end

                    V5BuffEngine._Confirmed = waitForCooldownStart(slot, isFounder and 1.35 or (isRage and 1.05 or 0.75))
                    if V5BuffEngine._Confirmed then break end

                    -- Refresh slot mapping before retrying the same skill.
                    task.wait(isFounder and 0.60 or (isRage and 0.50 or 0.30))
                    detected = V5BuffEngine.Scan(true)
                    slot = detected[skillId] or slot
                    key = V5BuffEngine.KeyForSlot(slot) or key
                end

                if V5BuffEngine._Confirmed then
                    V5BuffEngine.LastCast[skillId] = os.clock()
                    castNames[#castNames + 1] = tostring(info.Name)
                else
                    castNames[#castNames + 1] = tostring(info.Name) .. "?"
                end

                if isFounder then
                    task.wait(0.75)
                elseif isRage then
                    task.wait(0.45)
                else
                    task.wait(0.30)
                end
            end
        end
    end

    if #castNames > 0 then task.wait(1.00) end

    local summary = #castNames > 0
        and ("Pre-cannon buffs: " .. table.concat(castNames, ", "))
        or "No enabled ready buffs before cannon"
    V5BuffEngine.Status = summary
    return summary
end

function V5BuffEngine.Step()
    local mountedColossalCannon = V55ColossalDirector
        and V4RaidDirector
        and V4RaidDirector.RaidName == "Colossal Raid"
        and V55ColossalDirector.Stage == "P1 CANNON STALL"
        and V55ColossalDirector.Entered == true

    if mountedColossalCannon then
        V5BuffEngine.Status = "Mounted: buffs were applied before cannon entry"
        return false
    end

    if not State.AutoUseBuffsEnabled or not State.FarmEnabled then
        return false
    end
    if V4RaidDirector
        and V4RaidDirector.ShouldPauseCombat
        and V4RaidDirector.ShouldPauseCombat() then
        V5BuffEngine.Status = "Paused for raid transition"
        return false
    end
    if ripperSequenceRunning
        or refillSequenceRunning
        or StationRefill.Running
        or ((V35Spears and V35Spears.Busy) and not mountedColossalCannon) then
        return false
    end

    local detected = V5BuffEngine.Scan(false)
    local now = os.clock()
    V5BuffEngine.LastAttempt = V5BuffEngine.LastAttempt or {}

    -- Deterministic order prevents table iteration from starving a later enabled buff.
    local order = {"93", "95", "97", "158", "163"}
    for _, skillId in ipairs(order) do
        local slot = detected[skillId]
        local info = V5BuffEngine.Skills[skillId]
        if slot and info then
            local allowed = State[info.StateKey] ~= false
            local lastCast = tonumber(V5BuffEngine.LastCast[skillId]) or 0
            local lastAttempt = tonumber(V5BuffEngine.LastAttempt[skillId]) or 0
            local localGap = math.max(2.0, math.min(8.0, (tonumber(info.Cooldown) or 35) * 0.08))

            if allowed
                and now - lastCast >= localGap
                and now - lastAttempt >= 1.25
                and V5BuffEngine.Ready(slot) then

                local key = V5BuffEngine.KeyForSlot(slot)
                if key then
                    V5BuffEngine.LastAttempt[skillId] = now
                    V5BuffEngine.Status = "Casting " .. tostring(info.Name) .. " [" .. tostring(slot) .. "]"
                    task.spawn(function()
                        simulateHumanKeyPress(key)
                        task.wait(0.28)

                        if not V5BuffEngine.Ready(slot) then
                            V5BuffEngine.LastCast[skillId] = os.clock()
                            V5BuffEngine.Status = "Cast confirmed: " .. tostring(info.Name)
                        else
                            -- Input was ignored or the skill was not actually ready; retry soon.
                            V5BuffEngine.Status = "Retry pending: " .. tostring(info.Name)
                        end
                    end)
                    return true
                end
            end
        end
    end

    return false
end

task.spawn(function()
    while true do
        task.wait(0.35)
        local ok, err = pcall(V5BuffEngine.Step)
        if not ok then
            V5BuffEngine.Status = "Buff engine error: " .. tostring(err)
        end
    end
end)

---------------------------------------------------------------------
-- EMERGENCY GRAB ESCAPE ENGINE
---------------------------------------------------------------------

local lastEmergencyGrabSnapAt = 0
local GrabSnapDebounce = 0.85

local function titanFolderNow()
    return Workspace:FindFirstChild(Config.TitansFolderName)
end

local function partBelongsToTitan(part)
    local folder = titanFolderNow()
    return folder ~= nil and part ~= nil and part:IsDescendantOf(folder)
end

local function partBelongsToCharacter(part)
    return character ~= nil and part ~= nil and part:IsDescendantOf(character)
end

local function isGrabJoint(instance)
    return instance
        and (
            instance:IsA("Weld")
            or instance:IsA("WeldConstraint")
            or instance:IsA("ManualWeld")
            or instance:IsA("Motor6D")
            or instance:IsA("Constraint")
        )
end

local function grabLinkParts(instance)
    if not instance then return nil, nil end

    local p0, p1 = nil, nil

    pcall(function()
        p0 = instance.Part0
        p1 = instance.Part1
    end)

    if p0 or p1 then
        return p0, p1
    end

    pcall(function()
        local a0 = instance.Attachment0
        local a1 = instance.Attachment1
        p0 = a0 and a0.Parent or nil
        p1 = a1 and a1.Parent or nil
    end)

    return p0, p1
end

local function breakGrabJoint(instance)
    if not isGrabJoint(instance) then return false end

    local p0, p1 = grabLinkParts(instance)
    local crossLinked =
        (partBelongsToCharacter(p0) and partBelongsToTitan(p1))
        or (partBelongsToCharacter(p1) and partBelongsToTitan(p0))

    if crossLinked then
        pcall(function()
            instance:Destroy()
        end)
        return true
    end

    return false
end

local function grabFlagActive(container)
    if not container then return false end

    local attributes = {}
    pcall(function()
        attributes = container:GetAttributes()
    end)

    for name, value in pairs(attributes) do
        local lowerName = string.lower(tostring(name or ""))
        local relevant =
            string.find(lowerName, "grab", 1, true)
            or string.find(lowerName, "held", 1, true)
            or string.find(lowerName, "captur", 1, true)
            or string.find(lowerName, "caught", 1, true)

        if relevant then
            if value == true then
                return true
            end

            if type(value) == "string" then
                local lowerValue = string.lower(value)
                if lowerValue == "true"
                    or string.find(lowerValue, "grab", 1, true)
                    or string.find(lowerValue, "held", 1, true)
                    or string.find(lowerValue, "captur", 1, true)
                    or string.find(lowerValue, "caught", 1, true) then
                    return true
                end
            end
        end
    end

    return false
end

local function grabValueStateActive(container)
    if not container then return false end

    for _, item in ipairs(container:GetDescendants()) do
        if item:IsA("BoolValue") and item.Value == true then
            local lowerName = string.lower(item.Name)
            if string.find(lowerName, "grab", 1, true)
                or string.find(lowerName, "held", 1, true)
                or string.find(lowerName, "captur", 1, true)
                or string.find(lowerName, "caught", 1, true) then
                return true
            end
        end
    end

    return false
end

local function emergencyGrabSnap(reason)
    if not rootPart or not rootPart.Parent or not character or not character.Parent then
        return
    end
    if V577MovementAuthority and V577MovementAuthority.Mode() == "CANNON" then
        statusText = "Grab joint cleared • cannon mount position preserved"
        return
    end

    local now = os.clock()
    if now - (tonumber(lastEmergencyGrabSnapAt) or 0) < GrabSnapDebounce then
        return
    end
    lastEmergencyGrabSnapAt = now

    CombatSafetyBoostUntil = now + (tonumber(Config.GrabSafetyBoostDuration) or 0.65)
    CombatSafetyBoostHeight = math.max(
        CombatSafetyBoostHeight,
        tonumber(Config.GrabSafetyBoostHeight) or 48
    )

    local anchorPosition, aimPosition = refreshCombatAnchor(false)
    if anchorPosition then
        local snapPosition = anchorPosition
            + Vector3.new(0, tonumber(Config.GrabEmergencySnapHeight) or 85, 0)

        character:PivotTo(
            aimPosition and CFrame.lookAt(snapPosition, aimPosition)
            or CFrame.new(snapPosition)
        )
    else
        rootPart.CFrame = rootPart.CFrame
            + Vector3.new(0, tonumber(Config.GrabEmergencySnapHeight) or 85, 0)
    end

    rootPart.AssemblyAngularVelocity = Vector3.zero
    rootPart.AssemblyLinearVelocity =
        Vector3.new(0, tonumber(Config.GrabEmergencyUpVelocity) or 70, 0)

    if humanoid then
        humanoid.Sit = false
        humanoid.PlatformStand = false
        pcall(function()
            humanoid:ChangeState(Enum.HumanoidStateType.GettingUp)
        end)
    end

    statusText = "Grab broken: " .. tostring(reason or "detected")
end

local function evaluateGrabState()
	-- Anti-grab is only needed while farming. Keeping it active after Farm is off
	-- can falsely detect ordinary W/A/S/D UI labels and cancel the downward drop.
	if not State.FarmEnabled or not State.AutoEscapeEnabled or not character or not rootPart then
		State.IsGrabbed = false
		return
	end

    local flagEvidence = grabFlagActive(character)
        or grabFlagActive(player)
        or grabValueStateActive(character)
        or false

    local postureEvidence = humanoid ~= nil
        and (humanoid.Sit == true or humanoid.PlatformStand == true)

    local camera = Workspace.CurrentCamera
    local cutsceneOwned = camera and camera.CameraType == Enum.CameraType.Scriptable

    -- Posture alone is noisy during raid transitions and Female choreography. A true
    -- grab flag/value or a Titan↔character joint remains authoritative.
    local currentGrabDetected = flagEvidence
        or (postureEvidence and not cutsceneOwned and State.IsGrabbed == true)
        or false

    -- Joint check: only destroy true Titan↔character cross-links.
    for _, item in ipairs(character:GetDescendants()) do
        if breakGrabJoint(item) then
            currentGrabDetected = true
        end
    end

	-- V5.7.6: visible W/A/S/D labels are QTE helpers only, never proof of a grab.

	-- Solver Loop
    if currentGrabDetected then
        State.IsGrabbed = true
        emergencyGrabSnap("state")

		if humanoid then
			for _, track in ipairs(humanoid:GetPlayingAnimationTracks()) do
				if string.find(string.lower(track.Name), "grab") or (track.Animation and string.find(string.lower(track.Animation.AnimationId), "grab")) then
					track:Stop()
				end
			end
			humanoid:ChangeState(Enum.HumanoidStateType.GettingUp)
		end

		local now = os.clock()
		if now - lastQTEPressTime >= QTEDebounceDelay then
			local targetKeyFound = nil

			for _, uiElement in ipairs(playerGui:GetDescendants()) do
				if uiElement:IsA("TextLabel") and uiElement.Visible and uiElement.AbsoluteSize.X > 0 then
					local cleanText = string.gsub(string.upper(uiElement.Text), "%s+", "")
					if cleanText == "W" or cleanText == "A" or cleanText == "S" or cleanText == "D" then
						targetKeyFound = Enum.KeyCode[cleanText]
						break
					end
				elseif uiElement:IsA("ImageLabel") and uiElement.Visible and uiElement.AbsoluteSize.X > 0 then
					local normalizedName = string.lower(uiElement.Name)
					if string.find(normalizedName, "w") then targetKeyFound = Enum.KeyCode.W; break
					elseif string.find(normalizedName, "a") then targetKeyFound = Enum.KeyCode.A; break
					elseif string.find(normalizedName, "s") then targetKeyFound = Enum.KeyCode.S; break
					elseif string.find(normalizedName, "d") then targetKeyFound = Enum.KeyCode.D; break
					end
				end
			end

			if targetKeyFound then
				lastQTEPressTime = now
				task.spawn(simulateHumanKeyPress, targetKeyFound)
			end
		end
		-- emergencyGrabSnap applies one escape pulse. Do not reapply +Y velocity every
		-- 25ms; that old loop could turn a false grab state into an infinite sky boost.
	else
		State.IsGrabbed = false
	end
end

task.spawn(function()
	while true do
		task.wait(Config.GrabCheckDelay)
		pcall(evaluateGrabState)
	end
end)

-- V2.1.1 immediate grab connection guard.
Workspace.DescendantAdded:Connect(function(instance)
    if not State.FarmEnabled or not State.AutoEscapeEnabled or not character then
        return
    end

    if not isGrabJoint(instance) then
        return
    end

    task.defer(function()
        if breakGrabJoint(instance) then
            State.IsGrabbed = true
            emergencyGrabSnap("joint")
        end
    end)
end)

-- Some grab joints can be created directly under Character descendants before the
-- Workspace-wide event path becomes useful, so watch Character additions too.
local CharacterGrabConnection = nil

local function bindCharacterGrabGuard()
    if CharacterGrabConnection then
        CharacterGrabConnection:Disconnect()
        CharacterGrabConnection = nil
    end

    if character then
        CharacterGrabConnection = character.DescendantAdded:Connect(function(instance)
            if not State.FarmEnabled or not State.AutoEscapeEnabled then
                return
            end

            if isGrabJoint(instance) then
                task.defer(function()
                    if breakGrabJoint(instance) then
                        State.IsGrabbed = true
                        emergencyGrabSnap("character joint")
                    end
                end)
                return
            end

            if instance:IsA("BoolValue") then
                local lowerName = string.lower(instance.Name)
                local relevant =
                    string.find(lowerName, "grab", 1, true)
                    or string.find(lowerName, "held", 1, true)
                    or string.find(lowerName, "captur", 1, true)
                    or string.find(lowerName, "caught", 1, true)

                if relevant then
                    instance:GetPropertyChangedSignal("Value"):Connect(function()
                        if State.FarmEnabled
                            and State.AutoEscapeEnabled
                            and instance.Value == true then
                            State.IsGrabbed = true
                            emergencyGrabSnap("grab state value")
                        end
                    end)
                end
            end
        end)
    end
end

bindCharacterGrabGuard()
player.CharacterAdded:Connect(function()
    task.defer(bindCharacterGrabGuard)
end)

local SpearSupport = nil

---------------------------------------------------------------------
-- MAIN PROCESSING LOOP
---------------------------------------------------------------------

task.spawn(function()
	while true do
		task.wait(Config.LoopDelay)

		if statusLabel and statusLabel.Text ~= "Status: " .. statusText then
			statusLabel.Text = "Status: " .. statusText
		end

		if statusDetailLabel then
			local bladeText = lastBladeSegments ~= nil
				and string.format("Segments %d/%d", lastBladeSegments, Config.BladeSegmentMaximum)
				or string.format("Segments ?/%d", Config.BladeSegmentMaximum)
			if lastBladeSets ~= nil then bladeText = bladeText .. string.format(" | Sets %d/%d", lastBladeSets, Config.BladeSetMaximum) end
			local targetText = string.format("Targets %d/%d", math.clamp(tonumber(lastBladeBurstCount) or 0, 0, getEffectiveTitansPerHit()), getEffectiveTitansPerHit())
			local farmText = string.format(
                "Blades %s • TS %s",
                State.BladesEnabled and "ON" or "OFF",
                (State.SpearSupportEnabled and State.SpearAutoFireEnabled ~= false) and "ON" or "OFF"
            )
			local detailText = string.format("%s  •  %s  •  %s  •  Kit %d blades + %d refill", farmText, targetText, bladeText, Config.BladeStockMaximum, Config.BladeRefillMaximum)
			if statusDetailLabel.Text ~= detailText then
				statusDetailLabel.Text = detailText
			end
		end

		if MiniHUD and MiniHUD.Update then
            pcall(MiniHUD.Update)
        end


		if updateObjectiveBrain then
			pcall(updateObjectiveBrain, false)
		end
		if updateAdaptiveCombatMode then
			pcall(updateAdaptiveCombatMode)
		end

		if State.IsGrabbed then
			continue
		end

        if V577StallEngine and V577StallEngine.OwnsCombat and V577StallEngine.OwnsCombat() then
            statusText = "STALL DESTROYER • " .. tostring(V577StallEngine.Status or "routing wave")
            continue
        end

		if not State.FarmEnabled then
			-- Farm controls the sky lock. Titan Ripper is an optional add-on while Farm is active.
			-- Do not zero velocity here: doing that every frame cancels gravity.
			if StationRefill.Running then
				statusText = "Gas station refill: " .. tostring(StationRefill.LastReason or "running")
			elseif refillSequenceRunning then
				statusText = "Auto Refill: pulling new blades"
			elseif State.AutoRefillEnabled and lastBladeSegments ~= nil then
				statusText = string.format("Farm disabled | Blade segments %d/%d", lastBladeSegments, Config.BladeSegmentMaximum)
			else
				statusText = "Disabled"
			end
			continue
		end

		if not character or not character.Parent or not humanoid or humanoid.Health <= 0 or not rootPart then
			statusText = "Waiting for character"
			continue
		end

        if V4RaidDirector
            and V4RaidDirector.ShouldPauseCombat
            and V4RaidDirector.ShouldPauseCombat() then

            statusText =
                V4RaidDirector.Status
                or "Raid transition lock"

            rootPart.AssemblyLinearVelocity = Vector3.zero
            rootPart.AssemblyAngularVelocity = Vector3.zero

            continue
        end

        local colossalEvadeActive = V55ColossalDirector
            and V4RaidDirector
            and V4RaidDirector.RaidName == "Colossal Raid"
            and V55ColossalDirector.Stage == "P2 BOSS"
            and V55ColossalDirector.EvadeMode == true

        if colossalEvadeActive then
            statusText = "Colossal EVADE • " .. tostring(V55ColossalDirector.LastHazardSignal or "hazard")
            if V35Spears and V35Spears.ShouldRun and V35Spears.ShouldRun() then
                pcall(V35Spears.Step)
            end
            continue
        end

        local colossalMountedDefense = V941ObjectiveGuardian
            and V941ObjectiveGuardian.ColossalMountedActive
            and V941ObjectiveGuardian.ColossalMountedActive() == true
        local objectiveGuardianActive = V941ObjectiveGuardian
            and V941ObjectiveGuardian.RouteActive
            and V941ObjectiveGuardian.RouteActive() == true

        if not objectiveGuardianActive then
		    local targetValid, targetProblem = updateAndValidateCurrentTarget()
		    if not targetValid then
			    if targetProblem and targetProblem ~= "missing" and targetProblem ~= "dead" and targetProblem ~= "invalid" then
				    statusText = "Skipping stalled Titan: " .. targetProblem
			    end

			    if not acquireCurrentTarget() then
				    statusText = "Scanning map for Titans... • AIR-LOCK HOLD"
                    lockCharacterInSky(nil)
				    continue
			    end
		    end

		    -- Active combat modes share targeting, sky locking, speed generation, and stalled-target skipping.
		    lockCharacterInSky(currentTargetPart)
        else
            -- Objective Guardian is remote-first, but Armored/Attack P1 still need
            -- the same hard aerial hold as normal farming. Actual Colossal cannon
            -- ownership is protected by MovementAuthority.CANNON, so this call no-ops
            -- while physically mounted instead of dragging cannon geometry.
            lockCharacterInSky(nil)
            statusText = "Objective Guardian: "
                .. tostring(V941ObjectiveGuardian.Status or "scanning protected target")
        end

		if StationRefill.Running then
			statusText = "Gas station refill: " .. tostring(StationRefill.LastReason or "running")
			continue
		end

		if refillSequenceRunning then
			statusText = "Auto Refill: pulling new blades"
			continue
		end

		-- V3.5 weapon router:
        -- blades remain the default engine; equipped Spears use the TS cluster engine.
		local bladeSwingTriggered, bladeHitCount = false, 0
        local spearTriggered, spearPackCount = false, 0
        local spearModeActive = V35Spears and V35Spears.ShouldRun()
		local ripperSlotUsed = nil
		local ripperAvailableNow = titanControlRipperAvailableNow and titanControlRipperAvailableNow()
        if objectiveGuardianActive then ripperAvailableNow = false end

		if State.FarmEnabled
            and (not ripperSequenceRunning or Config.V6ExactBladeOverlapBlaster == true) then
            if spearModeActive then
                if not bladeBurstRunning then
                    spearTriggered, spearPackCount = V35Spears.Step()
                end

                if State.BladesEnabled and Config.V6ExactBladeEnabled == true then
                    -- V6 exact queue is remote-first and can continue independently of Spear
                    -- cooldowns and Titan Blaster animation ownership.
                    bladeSwingTriggered, bladeHitCount = swingBlades()
                elseif State.BladesEnabled
                    and V58BladeEngine
                    and V58BladeEngine.CanFillSpearGap(spearTriggered) then
                    V58BladeEngine.HybridBurstRequested = true
                    bladeSwingTriggered, bladeHitCount = swingBlades()
                    V58BladeEngine.HybridBurstRequested = false
                end
            elseif State.BladesEnabled then
			    bladeSwingTriggered, bladeHitCount = swingBlades()
            end
		end

        local ripperGapReady = os.clock() - (lastRipperAssistAt or 0) >= (tonumber(Config.RipperAssistMinGap) or 0.10)
        local bladeBurstEarnedAssist =
            spearModeActive
            and (V35Spears.Serial > (V35Spears.LastRipperSerial or 0))
            or (BladeBurstSerial > LastRipperBladeSerial)

        local ripperOpportunity = false
        if State.TitanRipperEnabled and ripperAvailableNow then
            ripperOpportunity = getRipperOpportunity()
        else
            RipperOpportunityReadySince = nil
        end

        if not bladeSwingTriggered
            and not bladeBurstRunning
            and State.TitanRipperEnabled
            and ripperAvailableNow
            and ripperGapReady
            and bladeBurstEarnedAssist
            and ripperOpportunity then

            ripperSlotUsed = useTitanRipper()
            if ripperSlotUsed then
                lastRipperAssistAt = os.clock()

                if spearModeActive then
                    V35Spears.LastRipperSerial = V35Spears.Serial
                else
                    LastRipperBladeSerial = BladeBurstSerial
                end
            end
        end

		local displayedTargetCount =
            spearModeActive
            and math.max(1, tonumber(spearPackCount) or tonumber(V35Spears.LastPack) or 1)
            or (bladeSwingTriggered and bladeHitCount or lastBladeBurstCount)

        if not spearModeActive then
		    displayedTargetCount = math.clamp(displayedTargetCount, 1, getEffectiveTitansPerHit())
        end

		local bladeCounterText = ""
		if State.AutoRefillEnabled and lastBladeSegments ~= nil then
			bladeCounterText = string.format(" | Segments %d/%d", lastBladeSegments, Config.BladeSegmentMaximum)
		end

        if spearModeActive then
            local ammo = V35Spears.ReadAmmo()
            local ammoText = ammo ~= nil and tostring(ammo) or "?"
            local ripperText = ""

            if State.TitanRipperEnabled and ripperAvailableNow then
                ripperText = " | Blaster " .. (
                    ripperSlotUsed
                    and ("slot " .. tostring(ripperSlotUsed))
                    or getRipperCooldownText()
                )
            end

            local bladeRouteText = State.BladesEnabled
                and (" | Blade " .. tostring(V58BladeEngine and V58BladeEngine.Mode or "PACK CLEANUP"))
                or ""
            statusText = string.format(
                "TS Engine | Pack %d | Ammo %s | %s%s",
                displayedTargetCount,
                ammoText,
                tostring(V35Spears.LastStatus or "Idle"),
                ripperText .. bladeRouteText
            )
		elseif State.TitanRipperEnabled and ripperAvailableNow then
			local ripperState
			if ripperSlotUsed then
				ripperState = string.format("activated slot %d", ripperSlotUsed)
			else
				ripperState = getRipperCooldownText()
			end
			statusText = string.format("Blade Main + Titan Blaster | Wave %d/%d | %s%s", displayedTargetCount, getEffectiveTitansPerHit(), ripperState, bladeCounterText)
		else
			local noun = displayedTargetCount == 1 and "Titan" or "Titans"
			local modeText = State.TitanRipperEnabled and "BladeOnly: Blaster skill missing" or "BladeOnly"
			statusText = string.format("%s | Burst %d/%d %s | Speed %d%s", modeText, displayedTargetCount, getEffectiveTitansPerHit(), noun, Config.KillSpeed, bladeCounterText)
		end
	end
end)


---------------------------------------------------------------------
-- V5.1 10-SECOND RECOVERY BRAIN
---------------------------------------------------------------------

V51RecoveryBrain = V51RecoveryBrain or {
    Threshold = 10,
    LastProgressAt = os.clock(),
    LastAlive = nil,
    LastTarget = nil,
    LastPosition = nil,
    Recoveries = 0,
    Consecutive = 0,
    Status = "Monitoring",
}

function V51RecoveryBrain.MarkProgress(reason)
    V51RecoveryBrain.LastProgressAt = os.clock()
    V51RecoveryBrain.Consecutive = 0
    V51RecoveryBrain.Status = tostring(reason or "Progress")
end

function V51RecoveryBrain.Recover(reason)
    V51RecoveryBrain.Recoveries += 1
    V51RecoveryBrain.Consecutive += 1
    V51RecoveryBrain.LastProgressAt = os.clock()
    V51RecoveryBrain.Status = "RECOVERY #" .. tostring(V51RecoveryBrain.Recoveries) .. ": " .. tostring(reason)

    pcall(function() if V4RaidDirector and V4RaidDirector.Refresh then V4RaidDirector.Refresh() end end)
    pcall(function() clearCurrentTarget(false) end)
    pcall(function() if V35Spears and V35Spears.ClearDrainPack then V35Spears.ClearDrainPack("10s recovery") end end)
    pcall(function() if V4BlasterNapeLock and V4BlasterNapeLock.Stop then V4BlasterNapeLock.Stop() end end)
    pcall(function()
        CombatAnchorRuntime.Position = nil
        CombatAnchorRuntime.GroundCenter = nil
        CombatAnchorRuntime.AimPosition = nil
        CombatAnchorRuntime.TargetCount = 0
        CombatAnchorRuntime.LastRefresh = 0
        CombatAnchorRuntime.PulseUntil = 0
        CombatAnchorRuntime.PulseSerial += 1
    end)
    cachedTitanCandidates = {}
    cachedTitanCandidatesAt = 0
    print("[SliceHub V5.1][RECOVERY]", reason)
end

task.spawn(function()
    while true do
        task.wait(1.0)
        pcall(function()
            if not State.FarmEnabled or (V3ResultGuard and V3ResultGuard.Processing) or StationRefill.Running or refillSequenceRunning or ripperSequenceRunning then
                V51RecoveryBrain.MarkProgress("Paused/non-combat")
                return
            end

            if V4RaidDirector
                and V4RaidDirector.ShouldPauseCombat
                and V4RaidDirector.ShouldPauseCombat() then
                V51RecoveryBrain.MarkProgress(
                    V4RaidDirector.RaidName == "Colossal Raid"
                    and "Colossal cannon/transition ownership"
                    or "Raid transition"
                )
                return
            end

            local alive = getCachedAliveTitanCount()
            local pos = rootPart and rootPart.Position or nil
            local target = currentTarget
            local progress = false

            if V51RecoveryBrain.LastAlive == nil or alive < V51RecoveryBrain.LastAlive then progress = true end
            if target ~= nil and target ~= V51RecoveryBrain.LastTarget then progress = true end
            if typeof(pos) == "Vector3" and typeof(V51RecoveryBrain.LastPosition) == "Vector3" then
                if (pos - V51RecoveryBrain.LastPosition).Magnitude >= 18 then progress = true end
            elseif typeof(pos) == "Vector3" then
                progress = true
            end

            V51RecoveryBrain.LastAlive = alive
            V51RecoveryBrain.LastTarget = target
            V51RecoveryBrain.LastPosition = pos

            if progress then
                V51RecoveryBrain.MarkProgress("Combat progress")
                return
            end

            local stalledFor = os.clock() - (V51RecoveryBrain.LastProgressAt or os.clock())
            if stalledFor >= V51RecoveryBrain.Threshold then
                local bossLocked = V4RaidDirector and V4RaidDirector.HardBossLock and select(1, V4RaidDirector.HardBossLock())
                V51RecoveryBrain.Recover(bossLocked and "boss-lock rescan" or "10s no-progress rescan")
            else
                V51RecoveryBrain.Status = string.format("Watching %.1fs / %ss", stalledFor, V51RecoveryBrain.Threshold)
            end
        end)
    end
end)

---------------------------------------------------------------------
-- NAMED CONFIG PROFILE STORAGE
---------------------------------------------------------------------

local ProfileStore = {}
local ProfileStorageMode = "Session"
local ProfileStorageDetail = "Profiles reset when this script stops."

local function getOptionalGlobalFunction(name)
	local environment = nil
	local ok = pcall(function()
		if type(getgenv) == "function" then
			environment = getgenv()
		end
	end)

	if ok and type(environment) == "table" and type(environment[name]) == "function" then
		return environment[name]
	end
	if type(_G) == "table" and type(_G[name]) == "function" then
		return _G[name]
	end
	return nil
end

local executorReadFile = getOptionalGlobalFunction("readfile")
local executorWriteFile = getOptionalGlobalFunction("writefile")

if executorReadFile and executorWriteFile then
	ProfileStorageMode = "File"
	ProfileStorageDetail = "Profiles persist between sessions."
end

local function sanitizeProfileName(value)
	local raw = tostring(value or "")
	local kept = {}
	for index = 1, #raw do
		local byte = string.byte(raw, index)
		if byte and byte >= 32 and byte ~= 127 then
			kept[#kept + 1] = string.sub(raw, index, index)
		end
	end

	local name = table.concat(kept)
	while #name > 0 and string.sub(name, 1, 1) == " " do
		name = string.sub(name, 2)
	end
	while #name > 0 and string.sub(name, -1) == " " do
		name = string.sub(name, 1, #name - 1)
	end

	name = string.sub(name, 1, Config.ProfileNameMaxLength)
	return name
end

local function resolveProfileKey(name)
	local wanted = string.lower(sanitizeProfileName(name))
	if wanted == "" then return nil end

	for existingName in pairs(ProfileStore) do
		if string.lower(existingName) == wanted then
			return existingName
		end
	end
	return nil
end

local function normalizeProfile(data)
	if type(data) ~= "table" then return nil end

	local function booleanOr(value, fallback)
		if typeof(value) == "boolean" then return value end
		return fallback
	end

	return {
		Version = 2,
        BladesEnabled = booleanOr(data.BladesEnabled, booleanOr(data.FarmEnabled, false)),
		FarmEnabled = booleanOr(data.FarmEnabled, booleanOr(data.BladesEnabled, false)),
        SpearSupportEnabled = booleanOr(data.SpearSupportEnabled, false),
        SpearAutoFireEnabled = booleanOr(data.SpearAutoFireEnabled, true),
        SpearAutoRefillEnabled = booleanOr(data.SpearAutoRefillEnabled, true),
        SpearInfiniteEnabled = booleanOr(data.SpearInfiniteEnabled, false),
        AutoUseBuffsEnabled = booleanOr(data.AutoUseBuffsEnabled, false),
        BuffOrderAdvanceEnabled = booleanOr(data.BuffOrderAdvanceEnabled, true),
        BuffBlackFlareEnabled = booleanOr(data.BuffBlackFlareEnabled, true),
        BuffOrderRageEnabled = booleanOr(data.BuffOrderRageEnabled, true),
        BuffFoundersOrderEnabled = booleanOr(data.BuffFoundersOrderEnabled, true),
        BuffOrderRevolutionEnabled = booleanOr(data.BuffOrderRevolutionEnabled, true),
        RaidAutoOpenChestsEnabled = booleanOr(data.RaidAutoOpenChestsEnabled, false),
		TitanRipperEnabled = booleanOr(data.TitanRipperEnabled, false),
		AbilitySlot1Enabled = booleanOr(data.AbilitySlot1Enabled, true),
		AbilitySlot2Enabled = booleanOr(data.AbilitySlot2Enabled, true),
		AbilitySlot3Enabled = booleanOr(data.AbilitySlot3Enabled, true),
		AbilitySlot4Enabled = booleanOr(data.AbilitySlot4Enabled, true),
		AbilitySlot5Enabled = booleanOr(data.AbilitySlot5Enabled, true),
		AutoRefillEnabled = booleanOr(data.AutoRefillEnabled, true),
		AutoSkipCutsceneEnabled = SliceHubClampAutoSkipCutscene(booleanOr(data.AutoSkipCutsceneEnabled, false)),
		AutoEscapeEnabled = booleanOr(data.AutoEscapeEnabled, true),
		ExpandHitboxesEnabled = booleanOr(data.ExpandHitboxesEnabled, true),
		PerformanceModeEnabled = booleanOr(data.PerformanceModeEnabled, false),
		DisableEffectsEnabled = booleanOr(data.DisableEffectsEnabled, false),
		EcoLoopModeEnabled = booleanOr(data.EcoLoopModeEnabled, false),
		MapPropsHiddenEnabled = booleanOr(data.MapPropsHiddenEnabled, false),
		RemoveInjuryKillFlashEnabled = booleanOr(data.RemoveInjuryKillFlashEnabled, false),
		RemoveDamageTextEnabled = booleanOr(data.RemoveDamageTextEnabled, false),
		AutoRetryEnabled = booleanOr(data.AutoRetryEnabled, false),
		AutoMissionLimit = math.clamp(math.floor((tonumber(data.AutoMissionLimit) or 0) + 0.5), 0, 10),
		TitansPerHit = SliceHubMissionClampTPS(data.TitansPerHit, SliceHubMissionTPSMax()),
	}
end

local function loadProfileStore()
	if not executorReadFile then return end

	local readOk, encoded = pcall(executorReadFile, Config.ProfileFileName)
	if not readOk or type(encoded) ~= "string" or encoded == "" then return end

	local decodeOk, document = pcall(function()
		return HttpService:JSONDecode(encoded)
	end)
	if not decodeOk or type(document) ~= "table" then return end

	local profiles = type(document.Profiles) == "table" and document.Profiles or document
	for name, data in pairs(profiles) do
		local cleanName = sanitizeProfileName(name)
		local normalized = normalizeProfile(data)
		if cleanName ~= "" and normalized then
			ProfileStore[cleanName] = normalized
		end
	end
end

local function persistProfileStore()
	if not executorWriteFile then
		return true, "Saved for this session"
	end

	local encodeOk, encoded = pcall(function()
		return HttpService:JSONEncode({
			Version = 2,
			Profiles = ProfileStore,
		})
	end)
	if not encodeOk then
		return false, "JSON encode failed"
	end

	local writeOk = pcall(executorWriteFile, Config.ProfileFileName, encoded)
	if not writeOk then
		return false, "File write failed; kept in session"
	end
	return true, "Saved to file"
end

local function captureCurrentProfile()
	return {
		Version = 2,
        BladesEnabled = State.BladesEnabled == true,
		FarmEnabled = State.BladesEnabled == true,
        SpearSupportEnabled = State.SpearSupportEnabled == true,
        SpearAutoFireEnabled = State.SpearAutoFireEnabled ~= false,
        SpearAutoRefillEnabled = State.SpearAutoRefillEnabled == true,
        SpearInfiniteEnabled = State.SpearInfiniteEnabled == true,
        AutoUseBuffsEnabled = State.AutoUseBuffsEnabled == true,
        BuffOrderAdvanceEnabled = State.BuffOrderAdvanceEnabled ~= false,
        BuffBlackFlareEnabled = State.BuffBlackFlareEnabled ~= false,
        BuffOrderRageEnabled = State.BuffOrderRageEnabled ~= false,
        BuffFoundersOrderEnabled = State.BuffFoundersOrderEnabled ~= false,
        BuffOrderRevolutionEnabled = State.BuffOrderRevolutionEnabled ~= false,
        RaidAutoOpenChestsEnabled = State.RaidAutoOpenChestsEnabled == true,
		TitanRipperEnabled = State.TitanRipperEnabled == true,
		AbilitySlot1Enabled = State.AbilitySlot1Enabled ~= false,
		AbilitySlot2Enabled = State.AbilitySlot2Enabled ~= false,
		AbilitySlot3Enabled = State.AbilitySlot3Enabled ~= false,
		AbilitySlot4Enabled = State.AbilitySlot4Enabled ~= false,
		AbilitySlot5Enabled = State.AbilitySlot5Enabled ~= false,
		AutoRefillEnabled = State.AutoRefillEnabled == true,
		AutoSkipCutsceneEnabled = SliceHubClampAutoSkipCutscene(State.AutoSkipCutsceneEnabled),
		AutoEscapeEnabled = State.AutoEscapeEnabled == true,
		ExpandHitboxesEnabled = State.ExpandHitboxesEnabled == true,
		MapPropsHiddenEnabled = State.MapPropsHiddenEnabled == true,
		AutoRetryEnabled = State.AutoRetryEnabled == true,
		AutoMissionLimit = math.clamp(math.floor((tonumber(State.AutoMissionLimit) or 0) + 0.5), 0, 10),
		TitansPerHit = SliceHubMissionClampTPS(Config.TitansPerHit, SliceHubMissionTPSMax()),
	}
end

local function saveNamedProfile(name)
	local cleanName = sanitizeProfileName(name)
	if cleanName == "" then
		return false, "Enter a profile name"
	end

	local existingKey = resolveProfileKey(cleanName)
	if existingKey and existingKey ~= cleanName then
		ProfileStore[existingKey] = nil
	end

	ProfileStore[cleanName] = captureCurrentProfile()
	local persisted, message = persistProfileStore()
	return persisted, message, cleanName
end

local function getNamedProfile(name)
	local key = resolveProfileKey(name)
	if not key then return nil, nil end
	return normalizeProfile(ProfileStore[key]), key
end

local function deleteNamedProfile(name)
	local key = resolveProfileKey(name)
	if not key then
		return false, "Profile not found"
	end

	ProfileStore[key] = nil
	local persisted, message = persistProfileStore()
	if persisted then
		return true, "Deleted " .. key
	end
	return false, message
end

local function getSortedProfileNames()
	local names = {}
	for name in pairs(ProfileStore) do
		table.insert(names, name)
	end
	table.sort(names, function(a, b)
		return string.lower(a) < string.lower(b)
	end)
	return names
end

loadProfileStore()

---------------------------------------------------------------------
-- BASIC PERFORMANCE OPTIMIZER
---------------------------------------------------------------------

local Performance = {}

do
	Performance.OriginalLighting = {}
	Performance.OriginalTerrain = {}
	Performance.OriginalEffects = setmetatable({}, {__mode = "k"})
	Performance.HiddenMapProps = {}
    Performance.ColossalCullSuspended = false
	Performance.LightingSaved = false
	Performance.TerrainSaved = false
	Performance.DefaultConfig = {
		LoopDelay = Config.LoopDelay,
		TargetCacheLifetime = Config.TargetCacheLifetime,
		HitboxRefreshDelay = Config.HitboxRefreshDelay,
		GrabCheckDelay = Config.GrabCheckDelay,
		CutsceneCheckDelay = Config.CutsceneCheckDelay,
		AutoRefillCheckDelay = Config.AutoRefillCheckDelay,
	}

	function Performance.SafeGet(object, property)
		local ok, value = pcall(function()
			return object[property]
		end)
		if ok then return value end
		return nil
	end

	function Performance.SafeSet(object, property, value)
		pcall(function()
			object[property] = value
		end)
	end

	function Performance.RememberProperty(bucket, object, property)
		if bucket[property] ~= nil then return end
		local value = Performance.SafeGet(object, property)
		if value ~= nil then
			bucket[property] = value
		end
	end

	function Performance.GetTerrain()
		return Workspace:FindFirstChildOfClass("Terrain") or Workspace:FindFirstChild("Terrain")
	end

	function Performance.IsVisualEffect(object)
		return object:IsA("ParticleEmitter")
			or object:IsA("Trail")
			or object:IsA("Beam")
			or object:IsA("Smoke")
			or object:IsA("Fire")
			or object:IsA("Sparkles")
	end

	Performance.MapPropKeywords = {
		"house", "building", "wall", "roof", "door", "window", "fence", "tree", "bush", "rock",
		"prop", "props", "decor", "decoration", "foliage", "grass", "lamp", "barrel",
		"crate", "cart", "wood", "plank", "chimney", "bench", "sign", "tower", "pillar"
	}

	Performance.MapPropProtectedKeywords = {
		"titan", "enemy", "npc", "player", "spawn", "checkpoint", "objective", "quest", "mission",
		"hitbox", "nape", "humanoid", "root", "camera", "terrain", "baseplate", "ground", "floor",
		"road", "path", "water", "safe", "zone", "barrier", "invisible", "kill", "damage", "remote",
        "debris", "characters", "effects", "particles", "projectiles", "attacks", "runtime", "interactions", "cannon"
	}

	function Performance.NameHasKeyword(name, keywords)
		local lowerName = string.lower(tostring(name or ""))
		for _, keyword in ipairs(keywords) do
			if string.find(lowerName, keyword, 1, true) then
				return true
			end
		end
		return false
	end

	function Performance.HasHumanoidAncestor(object)
		local node = object
		while node and node ~= Workspace do
			if node:IsA("Model") and node:FindFirstChildOfClass("Humanoid") then
				return true
			end
			node = node.Parent
		end
		return false
	end

	function Performance.IsProtectedMapObject(object)
		if not object or object == Workspace or object == Workspace.CurrentCamera then return true end
		if object:IsA("Terrain") then return true end
		if character and object:IsDescendantOf(character) then return true end
		if Performance.HasHumanoidAncestor(object) then return true end

        -- V5.5: preserve the selected/available cannon and any ancestor container.
        -- Otherwise a generic "building/prop" cull can remove the cannon with its parent.
        local okCannons, cannons = pcall(function()
            return game:GetService("CollectionService"):GetTagged("Cannon")
        end)
        if okCannons and type(cannons) == "table" then
            for _, cannon in ipairs(cannons) do
                if cannon == object
                    or cannon:IsDescendantOf(object)
                    or object:IsDescendantOf(cannon) then
                    return true
                end
            end
        end

        -- V3.5.1: never cull live runtime containers used by game systems.
        local top = object
        while top and top.Parent and top.Parent ~= Workspace do
            top = top.Parent
        end

        if top and top.Parent == Workspace then
            local topName = string.lower(tostring(top.Name or ""))
            if topName == "debris"
                or topName == "characters"
                or topName == "titans"
                or topName == "effects"
                or topName == "particles"
                or topName == "projectiles"
                or topName == "attacks"
                or topName == "runtime"
                or topName == "interactions" then
                return true
            end

            if topName == "climbable" or topName == "unclimbable" then
                local objectName = string.lower(tostring(object.Name or ""))
                if objectName == "buildings"
                    or objectName == "cutscene_buildings"
                    or objectName == "gastanks"
                    or objectName == "refill" then
                    return true
                end

                local criticalNode = object.Parent
                while criticalNode and criticalNode ~= top do
                    local criticalName = string.lower(tostring(criticalNode.Name or ""))
                    if criticalName == "cutscene_buildings"
                        or criticalName == "gastanks" then
                        return true
                    end
                    criticalNode = criticalNode.Parent
                end
            end
        end

		local node = object
		while node and node ~= Workspace do
			if node.Name == Config.TitansFolderName then return true end
			if Performance.NameHasKeyword(node.Name, Performance.MapPropProtectedKeywords) then return true end
			node = node.Parent
		end
		return false
	end

	function Performance.IsMapPropCandidate(object)
		if Performance.IsProtectedMapObject(object) then return false end
		if object:IsA("Model") or object:IsA("Folder") then
			return Performance.NameHasKeyword(object.Name, Performance.MapPropKeywords)
		end
		if object:IsA("BasePart") then
			if object:IsA("SpawnLocation") then return false end
			return Performance.NameHasKeyword(object.Name, Performance.MapPropKeywords)
		end
		return false
	end

    function Performance.IsColossalRaidActive()
        local active = false
        pcall(function()
            active = V4RaidDirector
                and V4RaidDirector.RaidName == "Colossal Raid"
        end)
        if active then return true end

        return Workspace:FindFirstChild("Colossal_Boss", true) ~= nil
            or Workspace:FindFirstChild("Colossal Titan", true) ~= nil
    end

	function Performance:ApplyMapPropCull()
        Performance.RestoreCriticalRuntimeFolders()

        -- Colossal P1 cannons are physically mounted on wall geometry. Never cull
        -- map props during this raid: deleting/restoring the wall after mounting can
        -- remove the cannon or drag the restored wall assembly with the player.
        if Performance.IsColossalRaidActive() then
            self:RestoreMapProps()
            Performance.ColossalCullSuspended = true
            return 0
        end

		local moved = 0
		local limit = math.max(1, tonumber(Config.MapPropCullMaxPerPass) or 900)

		for _, object in ipairs(Workspace:GetDescendants()) do
			if moved >= limit then break end
			if object and object.Parent and object:IsDescendantOf(Workspace) and Performance.IsMapPropCandidate(object) then
				if self.HiddenMapProps[object] == nil then
					self.HiddenMapProps[object] = {Parent = object.Parent}
				end
				pcall(function()
					object.Parent = nil
				end)
				moved += 1
			end
		end

		return moved
	end

	function Performance:RestoreMapProps()
		for object, data in pairs(self.HiddenMapProps) do
			if object and data and data.Parent then
				pcall(function()
					if object.Parent == nil then
						object.Parent = data.Parent
					end
				end)
			end
			self.HiddenMapProps[object] = nil
		end
	end

    function Performance.RestoreCriticalRuntimeFolders()
        for object, data in pairs(Performance.HiddenMapProps or {}) do
            if object and data and data.Parent and object.Parent == nil then
                local objectName = string.lower(tostring(object.Name or ""))
                local mustRestore = objectName == "debris"
                    or objectName == "buildings"
                    or objectName == "cutscene_buildings"
                    or objectName == "gastanks"
                    or objectName == "refill"

                local node = data.Parent
                while node and node ~= Workspace do
                    local lowerName = string.lower(tostring(node.Name or ""))
                    if lowerName == "cutscene_buildings" or lowerName == "gastanks" then
                        mustRestore = true
                        break
                    end
                    node = node.Parent
                end

                if mustRestore then
                    pcall(function() object.Parent = data.Parent end)
                    Performance.HiddenMapProps[object] = nil
                end
            end
        end
    end

	function Performance:SetMapPropCull(enabled)
        Performance.RestoreCriticalRuntimeFolders()
		State.MapPropsHiddenEnabled = enabled == true
        if Performance.IsColossalRaidActive() then
            self:RestoreMapProps()
            Performance.ColossalCullSuspended = true
            return 0
        end
		if State.MapPropsHiddenEnabled then
			return self:ApplyMapPropCull()
		else
			self:RestoreMapProps()
			return 0
		end
	end

    do
        local env = _G
        pcall(function()
            if type(getgenv) == "function" then env = getgenv() end
        end)

        if type(env) == "table" then
            env.SliceHubRestoreColossalMapProps = function()
                Performance:RestoreMapProps()
                Performance.RestoreCriticalRuntimeFolders()
                Performance.ColossalCullSuspended = true
                return true
            end
        end

        task.spawn(function()
            local wasColossal = false
            while true do
                task.wait(0.35)
                local active = Performance.IsColossalRaidActive()

                if active then
                    if not wasColossal or next(Performance.HiddenMapProps) ~= nil then
                        Performance:RestoreMapProps()
                        Performance.RestoreCriticalRuntimeFolders()
                    end
                    Performance.ColossalCullSuspended = true
                elseif wasColossal then
                    Performance.ColossalCullSuspended = false
                    if State.MapPropsHiddenEnabled then
                        Performance:ApplyMapPropCull()
                    end
                end

                wasColossal = active
            end
        end)
    end

	function Performance:ApplyLowGraphics()
		local lighting = game:GetService("Lighting")
		if lighting then
			if not self.LightingSaved then
				Performance.RememberProperty(self.OriginalLighting, lighting, "GlobalShadows")
				Performance.RememberProperty(self.OriginalLighting, lighting, "ShadowSoftness")
				Performance.RememberProperty(self.OriginalLighting, lighting, "EnvironmentDiffuseScale")
				Performance.RememberProperty(self.OriginalLighting, lighting, "EnvironmentSpecularScale")
				self.LightingSaved = true
			end

			Performance.SafeSet(lighting, "GlobalShadows", false)
			Performance.SafeSet(lighting, "ShadowSoftness", 0)
			Performance.SafeSet(lighting, "EnvironmentDiffuseScale", 0)
			Performance.SafeSet(lighting, "EnvironmentSpecularScale", 0)
		end

		local terrain = Performance.GetTerrain()
		if terrain then
			if not self.TerrainSaved then
				Performance.RememberProperty(self.OriginalTerrain, terrain, "Decoration")
				Performance.RememberProperty(self.OriginalTerrain, terrain, "WaterWaveSize")
				Performance.RememberProperty(self.OriginalTerrain, terrain, "WaterWaveSpeed")
				Performance.RememberProperty(self.OriginalTerrain, terrain, "WaterReflectance")
				Performance.RememberProperty(self.OriginalTerrain, terrain, "WaterTransparency")
				self.TerrainSaved = true
			end

			Performance.SafeSet(terrain, "Decoration", false)
			Performance.SafeSet(terrain, "WaterWaveSize", 0)
			Performance.SafeSet(terrain, "WaterWaveSpeed", 0)
			Performance.SafeSet(terrain, "WaterReflectance", 0)
			Performance.SafeSet(terrain, "WaterTransparency", 1)
		end
	end

	function Performance:RestoreLowGraphics()
		local lighting = game:GetService("Lighting")
		if lighting then
			for property, value in pairs(self.OriginalLighting) do
				Performance.SafeSet(lighting, property, value)
			end
		end

		local terrain = Performance.GetTerrain()
		if terrain then
			for property, value in pairs(self.OriginalTerrain) do
				Performance.SafeSet(terrain, property, value)
			end
		end
	end

	function Performance:SetLowGraphics(enabled)
		State.PerformanceModeEnabled = enabled == true
		if State.PerformanceModeEnabled then
			self:ApplyLowGraphics()
		else
			self:RestoreLowGraphics()
		end
	end

	function Performance:ApplyNoEffects()
		for _, object in ipairs(Workspace:GetDescendants()) do
			if Performance.IsVisualEffect(object) then
				if self.OriginalEffects[object] == nil then
					self.OriginalEffects[object] = Performance.SafeGet(object, "Enabled")
				end
				Performance.SafeSet(object, "Enabled", false)
			end
		end
	end

	function Performance:RestoreNoEffects()
		for object, wasEnabled in pairs(self.OriginalEffects) do
			if object and object.Parent then
				Performance.SafeSet(object, "Enabled", wasEnabled)
			end
			self.OriginalEffects[object] = nil
		end
	end

	function Performance:SetNoEffects(enabled)
		State.DisableEffectsEnabled = enabled == true
		if State.DisableEffectsEnabled then
			self:ApplyNoEffects()
		else
			self:RestoreNoEffects()
		end
	end


    Performance.VisualConnections = Performance.VisualConnections or {}
    Performance.VisualWatched = Performance.VisualWatched or setmetatable({}, {__mode = "k"})

    function Performance.HasAncestorNamed(object, tokens)
        local node = object
        while node do
            local lower = string.lower(tostring(node.Name or ""))
            for _, token in ipairs(tokens) do
                if string.find(lower, token, 1, true) then return true end
            end
            node = node.Parent
        end
        return false
    end

    function Performance.IsDamageNumberLabel(object)
        if not object or not object:IsA("TextLabel") then return false end
        local text = tostring(object.Text or "")
        local compact = string.gsub(text, "[,%s]", "")
        if not string.match(compact, "^%-?%d+%.?%d*$") then return false end
        if tonumber(object.TextSize) and object.TextSize < 16 then return false end

        -- Damage popups are normally large world-space BillboardGui labels. The
        -- TextSize guard preserves small distance/objective markers such as 706m.
        -- explicit Damage/Hit/Critical containers, but never blanket-hide HUD stats.
        local node = object.Parent
        while node do
            if node:IsA("BillboardGui") then return true end
            local lower = string.lower(tostring(node.Name or ""))
            if string.find(lower, "damage", 1, true)
                or string.find(lower, "critical", 1, true)
                or string.find(lower, "hitnumber", 1, true)
                or string.find(lower, "hit_number", 1, true) then
                return true
            end
            node = node.Parent
        end
        return false
    end

    function Performance.IsInjuryKillFlashObject(object)
        if not object then return false end
        if not (object:IsA("GuiObject")
            or object:IsA("ColorCorrectionEffect")
            or object:IsA("BloomEffect")) then
            return false
        end

        local lower = string.lower(tostring(object.Name or ""))
        if string.find(lower, "injuryflash", 1, true)
            or string.find(lower, "injury_flash", 1, true)
            or string.find(lower, "killflash", 1, true)
            or string.find(lower, "kill_flash", 1, true)
            or string.find(lower, "damageflash", 1, true)
            or string.find(lower, "damage_flash", 1, true) then
            return true
        end

        -- The game's injury screen is exposed as Interface.Injury. Suppress only
        -- descendants of that branch, not generic Flash effects such as Black Flash.
        return Performance.HasAncestorNamed(object, {"injury"})
    end

    function Performance.ApplyVisualSuppressorTo(object)
        local damageMatch = State.RemoveDamageTextEnabled and Performance.IsDamageNumberLabel(object)
        local flashMatch = State.RemoveInjuryKillFlashEnabled and Performance.IsInjuryKillFlashObject(object)

        if damageMatch then
            Performance.SafeSet(object, "Visible", false)
            Performance.SafeSet(object, "TextTransparency", 1)
            Performance.SafeSet(object, "TextStrokeTransparency", 1)
        end

        if flashMatch then
            if object:IsA("GuiObject") then
                Performance.SafeSet(object, "Visible", false)
                Performance.SafeSet(object, "BackgroundTransparency", 1)
                if object:IsA("ImageLabel") or object:IsA("ImageButton") then
                    Performance.SafeSet(object, "ImageTransparency", 1)
                end
            else
                Performance.SafeSet(object, "Enabled", false)
            end
        end

        if (damageMatch or flashMatch) and not Performance.VisualWatched[object] then
            Performance.VisualWatched[object] = true
            if object:IsA("GuiObject") then
                object:GetPropertyChangedSignal("Visible"):Connect(function()
                    if object.Parent then task.defer(Performance.ApplyVisualSuppressorTo, object) end
                end)
            elseif object:IsA("ColorCorrectionEffect") or object:IsA("BloomEffect") then
                object:GetPropertyChangedSignal("Enabled"):Connect(function()
                    if object.Parent then task.defer(Performance.ApplyVisualSuppressorTo, object) end
                end)
            end
        end
    end

    function Performance:ApplyVisualSuppressors()
        local containers = {playerGui, Workspace, game:GetService("Lighting")}
        for _, container in ipairs(containers) do
            if container then
                for _, object in ipairs(container:GetDescendants()) do
                    Performance.ApplyVisualSuppressorTo(object)
                end
            end
        end
    end

    function Performance:SetRemoveInjuryKillFlash(enabled)
        State.RemoveInjuryKillFlashEnabled = enabled == true
        if State.RemoveInjuryKillFlashEnabled then self:ApplyVisualSuppressors() end
    end

    function Performance:SetRemoveDamageText(enabled)
        State.RemoveDamageTextEnabled = enabled == true
        if State.RemoveDamageTextEnabled then self:ApplyVisualSuppressors() end
    end

    do
        local function connect(container)
            if not container or Performance.VisualConnections[container] then return end
            Performance.VisualConnections[container] = container.DescendantAdded:Connect(function(object)
                task.defer(function()
                    if object and object.Parent then Performance.ApplyVisualSuppressorTo(object) end
                end)
            end)
        end
        connect(playerGui)
        connect(Workspace)
        connect(game:GetService("Lighting"))
    end

	function Performance:SetEcoLoops(enabled)
		State.EcoLoopModeEnabled = enabled == true
		if State.EcoLoopModeEnabled then
			Config.LoopDelay = 0.05
			Config.TargetCacheLifetime = 0.35
			Config.HitboxRefreshDelay = 1.25
			Config.GrabCheckDelay = 0.14
			Config.CutsceneCheckDelay = 0.14
			Config.AutoRefillCheckDelay = 0.10
		else
			for key, value in pairs(self.DefaultConfig) do
				Config[key] = value
			end
		end
	end

	task.spawn(function()
		local lastPropCullAt = 0
		while true do
			task.wait(Config.PerformanceRefreshDelay)
			if State.PerformanceModeEnabled then
				Performance:ApplyLowGraphics()
			end
			if State.DisableEffectsEnabled then
				Performance:ApplyNoEffects()
			end
			if State.MapPropsHiddenEnabled and os.clock() - lastPropCullAt >= Config.MapPropCullRefreshDelay then
				lastPropCullAt = os.clock()
				Performance:ApplyMapPropCull()
			end
		end
	end)
end


pcall(function()
    if State.RemoveInjuryKillFlashEnabled then Performance:SetRemoveInjuryKillFlash(true) end
    if State.RemoveDamageTextEnabled then Performance:SetRemoveDamageText(true) end
end)

