;(function() -- V9.8.2.0: scope the entire UI section to stay below Luau's 200-local register limit

local function getTitanControlGuiParent()
	-- v98 fix: gethui() can return weird containers on some executors.
	-- A ScreenGui only renders reliably under PlayerGui/CoreGui, so never parent to Player.
	local coreGui = nil
	pcall(function()
		coreGui = game:GetService("CoreGui")
	end)

	local function validGuiParent(obj)
		if typeof(obj) ~= "Instance" then return false end
		if obj:IsA("PlayerGui") then return true end
		if coreGui and obj == coreGui then return true end
		if coreGui and obj:IsDescendantOf(coreGui) then return true end
		return false
	end

	pcall(function()
		if type(gethui) == "function" then
			local hiddenUi = gethui()
			if validGuiParent(hiddenUi) then
				return hiddenUi
			end
		end
	end)

	if coreGui then
		return coreGui
	end
	return playerGui
end

local titanControlGuiParent = getTitanControlGuiParent()

local function destroyOldTitanControlGui()
print("[SliceHub V1 V2/PERFORMANCE] old gui destroyed")
	local seen = {}
	for _, container in ipairs({playerGui, titanControlGuiParent}) do
		if container and not seen[container] then
			seen[container] = true
			local oldGui = container:FindFirstChild("TitanControlMenu")
			if oldGui then oldGui:Destroy() end
		end
	end
end

