	notificationOrder += 1
	local isError = kind == "error"
	local isSuccess = kind == "success"
	local accent = isError and Color3.fromRGB(238, 105, 125)
		or (isSuccess and Color3.fromRGB(87, 206, 154) or Theme.AccentLight)

	local toast = Instance.new("CanvasGroup")
	toast.Name = "Toast"
	toast.LayoutOrder = notificationOrder
	toast.Size = UDim2.fromOffset(286, 58)
	toast.Position = UDim2.fromOffset(28, 0)
	toast.BackgroundColor3 = Color3.fromRGB(20, 18, 26)
	toast.BackgroundTransparency = 0.02
	toast.GroupTransparency = 1
	toast.BorderSizePixel = 0
	toast.ZIndex = 51
	toast.Parent = notificationHolder

	local corner = Instance.new("UICorner")
	corner.CornerRadius = UDim.new(0, 5)
	corner.Parent = toast

	local stroke = Instance.new("UIStroke")
	stroke.Color = accent
	stroke.Transparency = 0.28
	stroke.Thickness = 1
	stroke.Parent = toast

	local strip = Instance.new("Frame")
	strip.Size = UDim2.fromOffset(4, 42)
	strip.Position = UDim2.fromOffset(0, 10)
	strip.BackgroundColor3 = accent
	strip.BorderSizePixel = 0
	strip.ZIndex = 52
	strip.Parent = toast
	local stripCorner = Instance.new("UICorner")
	stripCorner.CornerRadius = UDim.new(1, 0)
	stripCorner.Parent = strip

	local titleText = Instance.new("TextLabel")
	titleText.Position = UDim2.fromOffset(15, 8)
	titleText.Size = UDim2.new(1, -28, 0, 20)
	titleText.BackgroundTransparency = 1
	titleText.Font = Enum.Font.GothamBold
	titleText.Text = tostring(title or "Notification")
	titleText.TextColor3 = Theme.Text
	titleText.TextSize = 12
	titleText.TextXAlignment = Enum.TextXAlignment.Left
	titleText.ZIndex = 52
	titleText.Parent = toast

	local messageText = Instance.new("TextLabel")
	messageText.Position = UDim2.fromOffset(15, 29)
	messageText.Size = UDim2.new(1, -28, 0, 24)
	messageText.BackgroundTransparency = 1
	messageText.Font = Enum.Font.Gotham
