	messageText.TextColor3 = Theme.TextMuted
	messageText.TextSize = 10
	messageText.TextWrapped = true
	messageText.TextXAlignment = Enum.TextXAlignment.Left
	messageText.TextYAlignment = Enum.TextYAlignment.Top
	messageText.ZIndex = 52
	messageText.Parent = toast

	TweenService:Create(toast, TweenInfo.new(0.28, Enum.EasingStyle.Quint, Enum.EasingDirection.Out), {
		GroupTransparency = 0,
		Position = UDim2.fromOffset(0, 0),
	}):Play()

	task.delay(2.8, function()
		if not toast.Parent then return end
		TweenService:Create(toast, TweenInfo.new(0.22, Enum.EasingStyle.Quad, Enum.EasingDirection.In), {
			GroupTransparency = 1,
			Position = UDim2.fromOffset(24, 0),
		}):Play()
		task.delay(0.24, function()
			if toast.Parent then toast:Destroy() end
		end)
	end)
end


V51PhaseStats = V51PhaseStats or {
    SessionStartedAt = os.clock(),
    CurrentRaid = "Unknown",
    CurrentPhase = "Idle",
    PhaseStartedAt = os.clock(),
    Completed = 0,
    Failed = 0,
    TotalSeconds = 0,
    FastestSeconds = nil,
}

function V51PhaseStats.CurrentPhaseSeconds()
    return math.max(0, os.clock() - (V51PhaseStats.PhaseStartedAt or os.clock()))
end

function V51PhaseStats.Observe()
    if not V4RaidDirector or not V4RaidDirector.Enabled then return end
    local raid = tostring(V4RaidDirector.RaidName or "Unknown")
    local phase = tostring(V4RaidDirector.Phase or "Idle")
    if raid ~= V51PhaseStats.CurrentRaid or phase ~= V51PhaseStats.CurrentPhase then
        V51PhaseStats.CurrentRaid = raid
        V51PhaseStats.CurrentPhase = phase
        V51PhaseStats.PhaseStartedAt = os.clock()
    end
end

task.spawn(function()
    while true do
        task.wait(0.5)
        pcall(V51PhaseStats.Observe)
    end
end)

