---------------------------------------------------------------------
-- V9.8.1.4 WAVES RUNTIME DIRECTOR
-- Premium-only orchestration around the existing blade engine.
-- Auto Farm Waves reuses Auto Blades; no second killing system is created.
---------------------------------------------------------------------

;(function()
    WavesRuntimeDirector = WavesRuntimeDirector or {
        Busy = false,
        Status = "Idle",
        CurrentCrate = nil,
        BoundFolder = nil,
        FolderConnection = nil,
        LastReadyAttempt = 0,
        LastCrateAttempt = 0,
        OwnedBlades = false,
        ResumeFarmAfterMove = false,
        MovementOriginCFrame = nil,
        RoundActiveSince = nil,
        RoundGateReason = "Waiting for wave start",
        SetupMissingSince = nil,
        SetupFailureNotified = false,
        UIStatusLabel = nil,
    }

    local VirtualInputManager = game:GetService("VirtualInputManager")

    local function premiumAllowed()
        return type(SliceHubWaveAutomationAllowed) == "function"
            and SliceHubWaveAutomationAllowed() == true
    end

    local function liveCharacter()
        local characterModel = player.Character
        local humanoidObject = characterModel and characterModel:FindFirstChildOfClass("Humanoid")
        local root = characterModel
            and (
                characterModel:FindFirstChild("HumanoidRootPart")
                or characterModel.PrimaryPart
            )
        if not characterModel or not humanoidObject or humanoidObject.Health <= 0 or not root then
            return nil, nil, nil
        end
        return characterModel, humanoidObject, root
    end

    local function waitUntil(predicate, timeout, interval)
        local started = os.clock()
        repeat
            local ok, result = pcall(predicate)
            if ok and result then return true end
            task.wait(interval or 0.04)
        until os.clock() - started >= (timeout or 2)
        return false
    end

    local function setStatus(value)
        WavesRuntimeDirector.Status = tostring(value or "Idle")
        local label = WavesRuntimeDirector.UIStatusLabel
        if label and label.Parent then
            label.Text = "Status: " .. WavesRuntimeDirector.Status
        end
    end

    function WavesRuntimeDirector.IsRuntime()
        local waves = Workspace:FindFirstChild("Waves")
        local unclimbable = Workspace:FindFirstChild("Unclimbable")
        local objective = unclimbable and unclimbable:FindFirstChild("Objective")
        local waveObjective = objective and objective:FindFirstChild("Waves")
        return waves ~= nil and waveObjective ~= nil
    end

    function WavesRuntimeDirector.GetObjective()
        local unclimbable = Workspace:FindFirstChild("Unclimbable")
        local objective = unclimbable and unclimbable:FindFirstChild("Objective")
        return objective and objective:FindFirstChild("Waves")
    end

    function WavesRuntimeDirector.GetCratesFolder()
        local waves = Workspace:FindFirstChild("Waves")
        return waves and waves:FindFirstChild("Crates")
    end

    -- Combat readiness and crate readiness are separate.
    -- A late-loaded script can enter after READY was already pressed, while
    -- Workspace.Waves.Crates is absent or between crate cycles. That must not
    -- disable the proven blade engine or incorrectly demand a rejoin.
    function WavesRuntimeDirector.IsServerSetupReady()
        local waves = Workspace:FindFirstChild("Waves")
        if not waves then
            return false, "Waiting for Workspace.Waves"
        end

        local objective = WavesRuntimeDirector.GetObjective()
        if not objective then
            return false, "Waiting for Waves objective"
        end

        return true, "Waves runtime ready"
    end

    function WavesRuntimeDirector.IsCrateSetupReady(requireDropoff)
        local waves = Workspace:FindFirstChild("Waves")
        if not waves then
            return false, "Waiting for Workspace.Waves"
        end

        local crates = waves:FindFirstChild("Crates")
        if not crates or not crates:IsA("Folder") then
            return false, "Waiting for live crate system"
        end

        if requireDropoff == true then
            local props = waves:FindFirstChild("Props")
            local dropoff = props and props:FindFirstChild("Dropoff")
            if not dropoff then
                return false, "Waiting for crate delivery station"
            end
        end

        return true, "Crate system ready"
    end

    -- The Waves map creates a temporary/pre-wave crate while the READY
    -- countdown and cutscene are still active. Moving to that crate can leave
    -- the character on a roof or at an unloaded spawn when the server deletes
    -- it at round start. Combat and crate movement are therefore armed only
    -- after the READY/countdown state has fully cleared and remained stable.
    function WavesRuntimeDirector.IsRoundActive()
        if not WavesRuntimeDirector.IsRuntime() then
            WavesRuntimeDirector.RoundActiveSince = nil
            WavesRuntimeDirector.RoundGateReason = "Waiting for Waves runtime"
            return false, WavesRuntimeDirector.RoundGateReason
        end

        local setupReady, setupReason = WavesRuntimeDirector.IsServerSetupReady()
        if not setupReady then
            WavesRuntimeDirector.RoundActiveSince = nil
            WavesRuntimeDirector.RoundGateReason = setupReason or "Waiting for Waves server setup"
            return false, WavesRuntimeDirector.RoundGateReason
        end

        local objective = WavesRuntimeDirector.GetObjective()
        if not objective then
            WavesRuntimeDirector.RoundActiveSince = nil
            WavesRuntimeDirector.RoundGateReason = "Waiting for Waves objective"
            return false, WavesRuntimeDirector.RoundGateReason
        end

        local countdown = tonumber(objective:GetAttribute("Countdown"))
        local ready = tonumber(objective:GetAttribute("Ready")) or 0
        local show = objective:GetAttribute("Show")
        local phase = tostring(objective:GetAttribute("Phase") or "")

        if countdown and countdown > 0 then
            WavesRuntimeDirector.RoundActiveSince = nil
            WavesRuntimeDirector.RoundGateReason = "Waiting for READY countdown"
            return false, WavesRuntimeDirector.RoundGateReason
        end

        if ready == 1 then
            WavesRuntimeDirector.RoundActiveSince = nil
            WavesRuntimeDirector.RoundGateReason = "Waiting for READY countdown"
            return false, WavesRuntimeDirector.RoundGateReason
        end

        -- During the pre-round transition the game can briefly remove the
        -- Countdown attribute before re-showing the READY/Skip panel. Keep the
        -- gate closed through that transient state.
        if show == true and (phase == "Start" or phase == "Skip") then
            WavesRuntimeDirector.RoundActiveSince = nil
            WavesRuntimeDirector.RoundGateReason = "Waiting for cutscene release"
            return false, WavesRuntimeDirector.RoundGateReason
        end

        local now = os.clock()
        if not WavesRuntimeDirector.RoundActiveSince then
            WavesRuntimeDirector.RoundActiveSince = now
            WavesRuntimeDirector.RoundGateReason = "Round starting; stabilizing"
            return false, WavesRuntimeDirector.RoundGateReason
        end

        if now - WavesRuntimeDirector.RoundActiveSince < 0.85 then
            WavesRuntimeDirector.RoundGateReason = "Round starting; stabilizing"
            return false, WavesRuntimeDirector.RoundGateReason
        end

        WavesRuntimeDirector.RoundGateReason = "Wave round active"
        return true, WavesRuntimeDirector.RoundGateReason
    end

    function WavesRuntimeDirector.GetDropoff()
        local waves = Workspace:FindFirstChild("Waves")
        local props = waves and waves:FindFirstChild("Props")
        return props and props:FindFirstChild("Dropoff")
    end

    function WavesRuntimeDirector.GetPlayerCrate()
        local folder = WavesRuntimeDirector.GetCratesFolder()
        if not folder then return nil end

        -- Waves creates one server-owned crate per player. Never fall back to
        -- another player's crate in multiplayer servers.
        local exact = folder:FindFirstChild("Crate_" .. tostring(player.Name))
        return exact and exact:IsA("Model") and exact or nil
    end

    function WavesRuntimeDirector.GetCrateHitbox(crate)
        if not crate then return nil end
        local hitbox = crate:FindFirstChild("Hitbox")
        if hitbox and hitbox:IsA("BasePart") then return hitbox end
        return crate:FindFirstChildWhichIsA("BasePart", true)
    end

    function WavesRuntimeDirector.MoveCharacter(targetPosition, lookPosition)
        if typeof(targetPosition) ~= "Vector3" then return false end
        local characterModel, humanoidObject, root = liveCharacter()
        if not characterModel then return false end

        local look = typeof(lookPosition) == "Vector3"
            and lookPosition
            or targetPosition + Vector3.new(0, 0, -1)
        if (look - targetPosition).Magnitude < 0.05 then
            look = targetPosition + Vector3.new(0, 0, -1)
        end

        characterModel:PivotTo(CFrame.lookAt(targetPosition, look))
        root.AssemblyAngularVelocity = Vector3.zero
        root.AssemblyLinearVelocity = Vector3.zero
        humanoidObject.Sit = false
        humanoidObject.PlatformStand = false
        return true
    end

    function WavesRuntimeDirector.BeginMovement(reason)
        if WavesRuntimeDirector.Busy then return false end

        local _, _, root = liveCharacter()
        WavesRuntimeDirector.MovementOriginCFrame = root and root.CFrame or nil
        WavesRuntimeDirector.Busy = true
        WavesRuntimeDirector.ResumeFarmAfterMove = State.FarmEnabled == true
        State.FarmEnabled = false
        pcall(function() clearCurrentTarget(false) end)
        setStatus(reason or "Crate movement")
        return true
    end

    function WavesRuntimeDirector.EndMovement(reason, restoreOrigin)
        local resume = WavesRuntimeDirector.ResumeFarmAfterMove == true
        local origin = WavesRuntimeDirector.MovementOriginCFrame

        WavesRuntimeDirector.ResumeFarmAfterMove = false
        WavesRuntimeDirector.MovementOriginCFrame = nil
        WavesRuntimeDirector.Busy = false
        WavesRuntimeDirector.CurrentCrate = nil

        -- Failed/pre-wave crate attempts must not strand the character at the
        -- temporary crate spawn. Successful pickup/delivery keeps its live
        -- position so the blade engine can naturally reacquire a target.
        if restoreOrigin == true and typeof(origin) == "CFrame" then
            local characterModel, humanoidObject, root = liveCharacter()
            if characterModel and root then
                pcall(function()
                    characterModel:PivotTo(origin)
                    root.AssemblyAngularVelocity = Vector3.zero
                    root.AssemblyLinearVelocity = Vector3.zero
                    humanoidObject.Sit = false
                    humanoidObject.PlatformStand = false
                end)
            end
        end

        if State.WavesAutoFarmEnabled == true
            and premiumAllowed()
            and WavesRuntimeDirector.IsRuntime() then
            local active = WavesRuntimeDirector.IsRoundActive()
            State.FarmEnabled = active == true
        elseif resume then
            State.FarmEnabled = true
        end

        setStatus(reason or "Idle")
    end

    function WavesRuntimeDirector.EnsureBladeFarm()
        if not premiumAllowed()
            or State.WavesAutoFarmEnabled ~= true
            or not WavesRuntimeDirector.IsRuntime()
            or WavesRuntimeDirector.Busy then
            return false
        end

        local roundActive, gateReason = WavesRuntimeDirector.IsRoundActive()
        if not roundActive then
            -- Auto Farm Waves owns movement while enabled. Never let the blade
            -- engine target anything during the cutscene/READY transition.
            if State.FarmEnabled == true then
                State.FarmEnabled = false
                pcall(function() clearCurrentTarget(false) end)
            end
            setStatus(gateReason or "Waiting for wave start")
            return false
        end

        if State.BladesEnabled ~= true then
            WavesRuntimeDirector.OwnedBlades = true
            State.BladesEnabled = true
            if Controls and Controls.Farm and Controls.Farm.Set then
                pcall(function() Controls.Farm:Set(true, true) end)
            elseif V5FarmRouter and V5FarmRouter.Sync then
                V5FarmRouter.Sync("waves auto farm")
            else
                State.FarmEnabled = true
            end
        elseif State.FarmEnabled ~= true then
            if V5FarmRouter and V5FarmRouter.Sync then
                V5FarmRouter.Sync("waves auto farm resume")
            else
                State.FarmEnabled = true
            end
        end

        setStatus("Auto farming Waves with blade engine")
        return true
    end

    function WavesRuntimeDirector.DisableOwnedBladeFarm()
        if not WavesRuntimeDirector.OwnedBlades then return end
        WavesRuntimeDirector.OwnedBlades = false

        if Controls and Controls.Farm and Controls.Farm.Set then
            pcall(function() Controls.Farm:Set(false, true) end)
        else
            State.BladesEnabled = false
            if V5FarmRouter and V5FarmRouter.Sync then
                V5FarmRouter.Sync("waves auto farm disabled")
            else
                State.FarmEnabled = false
            end
        end
    end

    function WavesRuntimeDirector.FindReadyGui()
        local interface = playerGui:FindFirstChild("Interface")
        local wavesGui = interface and interface:FindFirstChild("Waves")
        local inner = wavesGui and wavesGui:FindFirstChild("Inner")
        local main = inner and inner:FindFirstChild("Main")
        local vote = main and main:FindFirstChild("Vote")
        if vote and vote:IsA("GuiObject") then return vote end

        for _, object in ipairs(playerGui:GetDescendants()) do
            if (object:IsA("TextLabel") or object:IsA("TextButton"))
                and string.upper(tostring(object.Text or "")) == "READY" then
                local node = object
                while node and node ~= playerGui do
                    if node:IsA("GuiButton") then return node end
                    node = node.Parent
                end
                if object:IsA("GuiObject") then return object end
            end
        end
        return nil
    end

    function WavesRuntimeDirector.TryReady()
        if not premiumAllowed()
            or State.WavesAutoFarmEnabled ~= true
            or not WavesRuntimeDirector.IsRuntime() then
            return false
        end

        local setupReady, setupReason = WavesRuntimeDirector.IsServerSetupReady()
        if not setupReady then
            setStatus(setupReason or "Waiting for Waves server setup")
            return false
        end

        local objective = WavesRuntimeDirector.GetObjective()
        if not objective or tonumber(objective:GetAttribute("Ready")) == 1 then
            return false
        end

        local now = os.clock()
        if now - (WavesRuntimeDirector.LastReadyAttempt or 0) < 0.85 then
            return false
        end
        WavesRuntimeDirector.LastReadyAttempt = now

        local target = WavesRuntimeDirector.FindReadyGui()
        if not target or not target.Visible then return false end

        local fired = false
        local env = type(getgenv) == "function" and getgenv() or _G
        local fireSignal = env and env.firesignal or nil
        if type(fireSignal) == "function" and target:IsA("GuiButton") then
            fired = pcall(function()
                fireSignal(target.Activated)
                if target:IsA("TextButton") or target:IsA("ImageButton") then
                    fireSignal(target.MouseButton1Click)
                end
            end)
        end

        if not fired then
            local position = target.AbsolutePosition + target.AbsoluteSize / 2
            pcall(function()
                VirtualInputManager:SendMouseMoveEvent(position.X, position.Y, game)
                VirtualInputManager:SendMouseButtonEvent(position.X, position.Y, 0, true, game, 0)
                task.wait(0.04)
                VirtualInputManager:SendMouseButtonEvent(position.X, position.Y, 0, false, game, 0)
            end)
        end

        setStatus("READY vote sent")
        return true
    end

    function WavesRuntimeDirector.Pickup(crate)
        if not crate or not crate.Parent then return false, "crate missing" end
        if crate:GetAttribute("Occupied") == true then return true, "already occupied" end
        if State.WavesAutoPickupEnabled ~= true then return false, "pickup disabled" end

        local hitbox = WavesRuntimeDirector.GetCrateHitbox(crate)
        if not hitbox then return false, "crate hitbox missing" end

        for attempt = 1, 6 do
            if not crate.Parent then return false, "crate removed" end
            if crate:GetAttribute("Occupied") == true then return true, "picked up" end

            local target = hitbox.Position + Vector3.new(0, 0.45, 0)
            WavesRuntimeDirector.MoveCharacter(target, hitbox.Position)

            local _, _, root = liveCharacter()
            local env = type(getgenv) == "function" and getgenv() or _G
            local touch = env and env.firetouchinterest or nil
            if root and type(touch) == "function" then
                pcall(function()
                    touch(root, hitbox, 0)
                    task.wait(0.03)
                    touch(root, hitbox, 1)
                end)
            end

            if waitUntil(function()
                return crate.Parent == nil
                    or crate:GetAttribute("Occupied") == true
            end, 0.48, 0.025) then
                return crate.Parent ~= nil, crate.Parent and "picked up" or "crate removed"
            end
        end

        return crate:GetAttribute("Occupied") == true, "pickup timeout"
    end

    function WavesRuntimeDirector.DropoffTargets(dropoff)
        local output = {}
        local pivot = dropoff:GetPivot()
        local center = pivot.Position

        -- Two confirmed deliveries landed roughly 8-13 studs from this live model.
        output[#output + 1] = center + Vector3.new(-10, 4, 2)
        output[#output + 1] = center + Vector3.new(-14, 4, 0)
        output[#output + 1] = center + Vector3.new(-7, 4, 6)
        output[#output + 1] = center + Vector3.new(0, 4, 0)
        output[#output + 1] = (pivot * CFrame.new(-10, 4, 2)).Position
        output[#output + 1] = (pivot * CFrame.new(-14, 4, 0)).Position

        local added = 0
        for _, object in ipairs(dropoff:GetDescendants()) do
            if object:IsA("BasePart") and object.Name == "Crate" then
                output[#output + 1] = object.Position + Vector3.new(0, 3.5, 0)
                added += 1
                if added >= 5 then break end
            end
        end

        return output, center
    end

    function WavesRuntimeDirector.Deliver(crate)
        if not crate or not crate.Parent then return true, "already removed" end
        if State.WavesAutoDeliverEnabled ~= true then return false, "delivery disabled" end
        if crate:GetAttribute("Occupied") ~= true then return false, "crate is not occupied" end

        local dropoff = WavesRuntimeDirector.GetDropoff()
        if not dropoff then return false, "Workspace.Waves.Props.Dropoff missing" end

        local targets, center = WavesRuntimeDirector.DropoffTargets(dropoff)
        for _, target in ipairs(targets) do
            if not crate.Parent then return true, "delivered" end
            WavesRuntimeDirector.MoveCharacter(target, center)

            if waitUntil(function()
                local folder = WavesRuntimeDirector.GetCratesFolder()
                return crate.Parent == nil
                    or not crate:IsDescendantOf(Workspace)
                    or (folder and not crate:IsDescendantOf(folder))
            end, 0.55, 0.025) then
                return true, "delivered"
            end
        end

        return not crate.Parent, crate.Parent and "dropoff timeout" or "delivered"
    end

    function WavesRuntimeDirector.ProcessCrate(crate)
        if not premiumAllowed()
            or WavesRuntimeDirector.Busy
            or not WavesRuntimeDirector.IsRuntime()
            or not crate
            or not crate.Parent then
            return false
        end

        local roundActive, gateReason = WavesRuntimeDirector.IsRoundActive()
        if not roundActive then
            setStatus((gateReason or "Waiting for wave start") .. " • crates paused")
            return false
        end

        local wantsPickup = State.WavesAutoPickupEnabled == true
        local wantsDeliver = State.WavesAutoDeliverEnabled == true
        local occupied = crate:GetAttribute("Occupied") == true

        if not occupied and not wantsPickup then return false end
        if occupied and not wantsDeliver then return false end
        if not WavesRuntimeDirector.BeginMovement("Claiming supply crate") then return false end

        WavesRuntimeDirector.CurrentCrate = crate

        task.spawn(function()
            local ok, success, reason = pcall(function()
                if crate:GetAttribute("Occupied") ~= true and wantsPickup then
                    setStatus("Picking up supply crate")
                    local picked, pickupReason = WavesRuntimeDirector.Pickup(crate)
                    if not picked then
                        return false, pickupReason
                    end
                end

                if crate.Parent
                    and crate:GetAttribute("Occupied") == true
                    and State.WavesAutoDeliverEnabled == true then
                    setStatus("Delivering supply crate")
                    return WavesRuntimeDirector.Deliver(crate)
                end

                return true, "crate picked up"
            end)

            if not ok then
                local restore = not crate.Parent
                    or crate:GetAttribute("Occupied") ~= true
                WavesRuntimeDirector.EndMovement(
                    "Crate error: " .. tostring(success),
                    restore
                )
            elseif success then
                if not crate.Parent then
                    WavesRuntimeDirector.EndMovement("Crate delivered")
                elseif crate:GetAttribute("Occupied") == true then
                    WavesRuntimeDirector.EndMovement(
                        State.WavesAutoDeliverEnabled == true
                            and "Crate delivery finished"
                            or "Crate picked up; delivery disabled"
                    )
                else
                    WavesRuntimeDirector.EndMovement(tostring(reason or "Crate action finished"))
                end
            else
                local restore = not crate.Parent
                    or crate:GetAttribute("Occupied") ~= true
                WavesRuntimeDirector.EndMovement(
                    "Crate failed: " .. tostring(reason or "unknown"),
                    restore
                )
            end
        end)

        return true
    end

    function WavesRuntimeDirector.BindCratesFolder(folder)
        if WavesRuntimeDirector.BoundFolder == folder then return end
        if WavesRuntimeDirector.FolderConnection then
            pcall(function() WavesRuntimeDirector.FolderConnection:Disconnect() end)
        end

        WavesRuntimeDirector.BoundFolder = folder
        WavesRuntimeDirector.FolderConnection = folder.ChildAdded:Connect(function(child)
            if not child:IsA("Model")
                or child.Name ~= ("Crate_" .. tostring(player.Name)) then
                return
            end

            task.defer(function()
                task.wait(0.03)
                if State.WavesAutoPickupEnabled == true then
                    WavesRuntimeDirector.ProcessCrate(child)
                end
            end)
        end)
    end

    task.spawn(function()
        while true do
            task.wait(0.08)

            if not premiumAllowed() then
                State.WavesAutoFarmEnabled = false
                State.WavesAutoPickupEnabled = false
                State.WavesAutoDeliverEnabled = false
                continue
            end

            if not WavesRuntimeDirector.IsRuntime() then
                if not WavesRuntimeDirector.Busy then setStatus("Waiting for Waves runtime") end
                continue
            end

            local setupReady, setupReason = WavesRuntimeDirector.IsServerSetupReady()
            local folder = WavesRuntimeDirector.GetCratesFolder()
            if folder then WavesRuntimeDirector.BindCratesFolder(folder) end

            if not setupReady then
                if not WavesRuntimeDirector.Busy then
                    setStatus(setupReason or "Waiting for Waves runtime")
                end
                State.FarmEnabled = false
                pcall(function() clearCurrentTarget(false) end)
                continue
            end

            -- Late execution is supported. If READY was already pressed or the
            -- wave is already active, TryReady simply does nothing and the
            -- round gate arms the existing blade engine from current state.
            if State.WavesAutoFarmEnabled == true then
                WavesRuntimeDirector.TryReady()
                WavesRuntimeDirector.EnsureBladeFarm()
            end

            if not WavesRuntimeDirector.Busy then
                local roundActive, gateReason = WavesRuntimeDirector.IsRoundActive()
                local crateAutomation = State.WavesAutoPickupEnabled == true
                    or State.WavesAutoDeliverEnabled == true

                if crateAutomation and not roundActive then
                    setStatus((gateReason or "Waiting for wave start") .. " • crates paused")
                elseif crateAutomation then
                    local crateReady, crateReason =
                        WavesRuntimeDirector.IsCrateSetupReady(
                            State.WavesAutoDeliverEnabled == true
                        )

                    if not crateReady then
                        if State.WavesAutoFarmEnabled == true and roundActive then
                            setStatus(
                                "Auto farming Waves • "
                                .. tostring(crateReason or "waiting for crates")
                            )
                        else
                            setStatus(crateReason or "Waiting for live crate system")
                        end
                    else
                        local crate = WavesRuntimeDirector.GetPlayerCrate()
                        if crate then
                            local occupied = crate:GetAttribute("Occupied") == true
                            if (not occupied and State.WavesAutoPickupEnabled == true)
                                or (occupied and State.WavesAutoDeliverEnabled == true) then
                                WavesRuntimeDirector.ProcessCrate(crate)
                            end
                        elseif State.WavesAutoFarmEnabled ~= true then
                            setStatus("Waiting for supply crate")
                        end
                    end
                elseif State.WavesAutoFarmEnabled ~= true then
                    setStatus("Waves runtime ready")
                end
            end
        end
    end)
end)()

