    function updateV1Scale()
        local camera = Workspace.CurrentCamera
        if not camera then return end
        local viewport = camera.ViewportSize
        if viewport.X < 300 or viewport.Y < 250 then return end
        local fit = math.min((viewport.X * 0.82) / 920, (viewport.Y * 0.80) / 600, 1)
        if UserInputService.TouchEnabled or viewport.Y < 560 or viewport.X < 760 then
            fit = math.min(fit, 0.50)
            windowScale.Scale = fit
            shadowScale.Scale = fit
            return
        end
        local userScale = math.clamp((tonumber(PersistentSettings.MenuScale) or 100) / 100, 0.8, 1.2)
        windowScale.Scale = fit * userScale
        shadowScale.Scale = fit * userScale
    end
    updateV1Scale()
    if Workspace.CurrentCamera then
        Workspace.CurrentCamera:GetPropertyChangedSignal("ViewportSize"):Connect(updateV1Scale)
    end
