    function setV1Page(name)
        if name == "Waves" and not SliceHubWaveAutomationAllowed() then
            showNotification("Premium only", "This tab unlocks only when you have Premium.", "info")
            return
        end
        local target = V1Pages[name]
        if not target then return end
        activeV1Page = name
        for pageName, page in pairs(V1Pages) do
            page.Visible = pageName == name
            if pageName == name then page.CanvasPosition = Vector2.zero end
        end
        for buttonName, button in pairs(V1NavButtons) do
            local selected = buttonName == name
            button.BackgroundTransparency = 1
            button.BackgroundColor3 = Theme.CardSoft
            button.TextColor3 = selected and Theme.Text or Theme.TextDim
            local indicator = button:FindFirstChild("Indicator")
            if indicator then indicator.BackgroundTransparency = selected and 0 or 1 end
        end
        activePageTitle.Text = name == "Welcome" and "OVERVIEW" or string.upper(({Farm="MISSIONS", Config="PROFILES"})[name] or name)
        print("[SliceHub V3] page ->", name)
    end

