            group.TextXAlignment = Enum.TextXAlignment.Left
            group.Parent = navHolder
        end
        local button = createNavButton(name, index)
        local function activatePage()
            setV1Page(name)
        end
        button.Activated:Connect(activatePage)
        button.MouseButton1Click:Connect(activatePage)
        button.InputBegan:Connect(function(input)
            if input.UserInputType == Enum.UserInputType.MouseButton1
                or input.UserInputType == Enum.UserInputType.Touch then
                activatePage()
            end
        end)
        button.MouseEnter:Connect(function()
