    local function owningPageFor(object)
        for pageName, page in pairs(V1Pages) do
            if object and object:IsDescendantOf(page) then
                return pageName, page
            end
        end
        return nil, nil
    end

    local function searchTargetFor(label, page)
        local node = label
        local candidate = label
        while node and node.Parent and node.Parent ~= page do
            if node:IsA("GuiButton") then candidate = node end
            if node:IsA("Frame") and tonumber(node.LayoutOrder) and node.LayoutOrder > 0 then candidate = node end
            node = node.Parent
        end
        return candidate
    end

    local function clearSearchResults()
        for _, child in ipairs(resultsScroll:GetChildren()) do
            if child:IsA("GuiButton") then child:Destroy() end
        end
    end

    local function refreshFeatureSearch()
        clearSearchResults()
        local query = string.lower(string.gsub(tostring(searchBox.Text or ""), "^%s*(.-)%s*$", "%1"))
        if #query < 2 then
            searchPanel.Visible = false
            return
        end

        local seen = {}
        local matches = {}
        for _, page in pairs(V1Pages) do
            for _, label in ipairs(page:GetDescendants()) do
                if label:IsA("TextLabel") then
                    local textValue = tostring(label.Text or "")
                    local lower = string.lower(textValue)
                    if textValue ~= "" and string.find(lower, query, 1, true) then
                        local pageName, ownerPage = owningPageFor(label)
                        local key = tostring(pageName) .. "|" .. lower
                        if pageName and ownerPage and not seen[key] then
                            seen[key] = true
                            matches[#matches + 1] = {
                                PageName = pageName,
                                Page = ownerPage,
                                Label = label,
                                Target = searchTargetFor(label, ownerPage),
                                Text = textValue,
                            }
                        end
                    end
                end
            end
        end

        table.sort(matches, function(a, b)
            if a.PageName ~= b.PageName then return a.PageName < b.PageName end
            return a.Text < b.Text
        end)

        for index = 1, math.min(#matches, 18) do
            local info = matches[index]
            local result = Instance.new("TextButton")
            result.LayoutOrder = index
            result.Size = UDim2.new(1, -4, 0, 38)
            result.BackgroundColor3 = Theme.CardSoft
            result.BorderSizePixel = 0
            result.AutoButtonColor = false
            result.Font = Enum.Font.GothamMedium
            result.Text = "  " .. tostring(info.PageName) .. "  ›  " .. string.sub(string.gsub(info.Text, "\n", " "), 1, 82)
            result.TextColor3 = Theme.Text
            result.TextSize = 10
            result.TextXAlignment = Enum.TextXAlignment.Left
            result.ZIndex = 32
            result.Parent = resultsScroll
            uiCorner(result, 8)
            result.MouseEnter:Connect(function() result.BackgroundColor3 = Theme.CardActive end)
            result.MouseLeave:Connect(function() result.BackgroundColor3 = Theme.CardSoft end)
            result.Activated:Connect(function()
                setV1Page(info.PageName)
                searchBox.Text = ""
                searchPanel.Visible = false
                task.defer(function()
                    if info.Target and info.Target.Parent and info.Page and info.Page.Parent then
                        local offset = info.Target.AbsolutePosition.Y - info.Page.AbsolutePosition.Y + info.Page.CanvasPosition.Y - 14
                        info.Page.CanvasPosition = Vector2.new(0, math.max(0, offset))
                    end
                end)
            end)
        end

        if #matches == 0 then
            local empty = Instance.new("TextButton")
            empty.Size = UDim2.new(1, -4, 0, 42)
            empty.BackgroundColor3 = Theme.CardSoft
            empty.BorderSizePixel = 0
            empty.AutoButtonColor = false
            empty.Font = Enum.Font.GothamMedium
            empty.Text = "No feature matched  ‘" .. query .. "’"
            empty.TextColor3 = Theme.TextDim
            empty.TextSize = 10
            empty.ZIndex = 32
            empty.Parent = resultsScroll
            uiCorner(empty, 8)
        end

        searchPanel.Visible = true
    end

    searchBox:GetPropertyChangedSignal("Text"):Connect(refreshFeatureSearch)
    searchBox.FocusLost:Connect(function()
        if searchBox.Text == "" then searchPanel.Visible = false end
    end)

    -- V4.2 GUI repair: screen-position fallback for clients/executors that swallow GuiButton events.
    UserInputService.InputBegan:Connect(function(input)
        if not State.MenuOpen or not window or not window.Visible then return end
        local kind = input.UserInputType
        if kind ~= Enum.UserInputType.MouseButton1 and kind ~= Enum.UserInputType.Touch then return end

        local p = input.Position
        local x = tonumber(p.X) or 0
        local y = tonumber(p.Y) or 0

        for _, pageName in ipairs(tabNames) do
            local button = V1NavButtons[pageName]
            if button and button.Visible then
                local pos = button.AbsolutePosition
                local size = button.AbsoluteSize
                if x >= pos.X and x <= pos.X + size.X
                    and y >= pos.Y and y <= pos.Y + size.Y then
                    if pageName == "Waves" and not SliceHubWaveAutomationAllowed() then
                        showNotification("Premium only", "This tab unlocks only when you have Premium.", "info")
                    else
                        setV1Page(pageName)
                    end
                    return
                end
            end
        end
    end)

    -- Keep the top-level page visibility invariant repaired even if later feature code touches Visible.
    task.spawn(function()
        while screenGui and screenGui.Parent do
            task.wait(0.5)
            if State.MenuOpen then
                for pageName, page in pairs(V1Pages) do
                    local shouldShow = pageName == activeV1Page
                    if page.Visible ~= shouldShow then
