local function createToggle(parent, order, displayName, description, default, callback)
    local enabled = default == true

    local row = Instance.new("TextButton")
    row.Name = displayName:gsub("%s+", "") .. "Toggle"
    row.LayoutOrder = order
    row.Size = UDim2.new(1, 0, 0, 52)
    row.BackgroundColor3 = Theme.ElementBg
    row.BackgroundTransparency = 0.18
    row.BorderSizePixel = 0
    row.Text = ""
    row.AutoButtonColor = false
    row.Parent = parent

    local corner = Instance.new("UICorner")
    corner.CornerRadius = UDim.new(0, 3)
    corner.Parent = row

    local stroke = Instance.new("UIStroke")
    stroke.Color = Theme.Stroke
    stroke.Transparency = 0.30
    stroke.Thickness = 1
    stroke.Parent = row

    local nameLabel = Instance.new("TextLabel")
    nameLabel.Position = UDim2.fromOffset(6, 5)
    nameLabel.Size = UDim2.new(1, -54, 0, 20)
    nameLabel.BackgroundTransparency = 1
    nameLabel.Font = Enum.Font.GothamMedium
    nameLabel.Text = displayName
    nameLabel.TextColor3 = Theme.Text
    nameLabel.TextSize = 13
    nameLabel.TextXAlignment = Enum.TextXAlignment.Left
    nameLabel.Parent = row

    local descriptionLabel = Instance.new("TextLabel")
    descriptionLabel.Position = UDim2.fromOffset(6, 26)
    descriptionLabel.Size = UDim2.new(1, -54, 0, 16)
    descriptionLabel.BackgroundTransparency = 1
    descriptionLabel.Font = Enum.Font.Gotham
    descriptionLabel.Text = description
    descriptionLabel.TextColor3 = Theme.TextDim
    descriptionLabel.TextSize = 10
    descriptionLabel.TextTruncate = Enum.TextTruncate.AtEnd
    descriptionLabel.TextXAlignment = Enum.TextXAlignment.Left
    descriptionLabel.Parent = row

    local check = Instance.new("TextLabel")
    check.Name = "Checkbox"
    check.AnchorPoint = Vector2.new(1, 0.5)
    check.Position = UDim2.new(1, -6, 0.5, 0)
    check.Size = UDim2.fromOffset(28, 28)
    check.BackgroundColor3 = Theme.ElementBg
    check.BorderSizePixel = 0
    check.Font = Enum.Font.GothamBold
    check.Text = ""
    check.TextColor3 = Color3.fromRGB(255, 255, 255)
    check.TextSize = 18
    check.Parent = row

    local checkCorner = Instance.new("UICorner")
    checkCorner.CornerRadius = UDim.new(0, 4)
    checkCorner.Parent = check

    local checkStroke = Instance.new("UIStroke")
    checkStroke.Color = Theme.StrokeSoft
    checkStroke.Transparency = 0.12
    checkStroke.Thickness = 1
    checkStroke.Parent = check

    local function renderState(animated)
        local duration = animated and 0.14 or 0
        tween(row, duration, Enum.EasingStyle.Quad, Enum.EasingDirection.Out, {
            BackgroundColor3 = enabled and Theme.CardActive or Theme.ElementBg,
            BackgroundTransparency = enabled and 0.02 or 0.18,
        })
        tween(check, duration, Enum.EasingStyle.Quad, Enum.EasingDirection.Out, {
            BackgroundColor3 = enabled and Theme.Accent or Theme.ElementBg,
        })
        tween(checkStroke, duration, Enum.EasingStyle.Quad, Enum.EasingDirection.Out, {
            Color = enabled and Theme.AccentLight or Theme.StrokeSoft,
            Transparency = enabled and 0 or 0.12,
        })
        check.Text = enabled and "✓" or ""
    end

    local controller = {}
    function controller:Set(value, animated)
        value = value == true
        if value == enabled then return false end
        enabled = value
        renderState(animated ~= false)
        callback(enabled)
        return true
    end
    function controller:Get()
        return enabled
    end

    row.MouseEnter:Connect(function()
        tween(stroke, 0.12, Enum.EasingStyle.Quad, Enum.EasingDirection.Out, {Transparency = 0.04})
    end)
    row.MouseLeave:Connect(function()
        tween(stroke, 0.12, Enum.EasingStyle.Quad, Enum.EasingDirection.Out, {Transparency = 0.30})
    end)
    row.Activated:Connect(function()
        controller:Set(not enabled, true)
    end)

    renderState(false)
    callback(enabled)
    return controller
end

