function createIntegerSlider(parent, order, displayName, description, minimum, maximum, default, callback)
    local currentValue = math.clamp(math.floor((tonumber(default) or minimum) + 0.5), minimum, maximum)
    local draggingSlider = false

    local row = Instance.new("Frame")
    row.Name = displayName:gsub("%s+", "") .. "Slider"
    row.LayoutOrder = order
    row.Size = UDim2.new(1, 0, 0, 64)
    row.BackgroundColor3 = Theme.ElementBg
    row.BackgroundTransparency = 0.18
    row.BorderSizePixel = 0
    row.Parent = parent

    local corner = Instance.new("UICorner")
    corner.CornerRadius = UDim.new(0, 3)
    corner.Parent = row
    local stroke = Instance.new("UIStroke")
    stroke.Color = Theme.Stroke
    stroke.Transparency = 0.30
    stroke.Thickness = 1
    stroke.Parent = row

    local nameLabel = Instance.new("TextLabel")
    nameLabel.Position = UDim2.fromOffset(6, 5)
    nameLabel.Size = UDim2.new(1, -80, 0, 20)
    nameLabel.BackgroundTransparency = 1
    nameLabel.Font = Enum.Font.GothamMedium
    nameLabel.Text = displayName
    nameLabel.TextColor3 = Theme.Text
    nameLabel.TextSize = 13
    nameLabel.TextXAlignment = Enum.TextXAlignment.Left
    nameLabel.Parent = row

    local descriptionLabel = Instance.new("TextLabel")
    descriptionLabel.Position = UDim2.fromOffset(6, 24)
    descriptionLabel.Size = UDim2.new(1, -18, 0, 16)
    descriptionLabel.BackgroundTransparency = 1
    descriptionLabel.Font = Enum.Font.Gotham
    descriptionLabel.Text = description
    descriptionLabel.TextColor3 = Theme.TextDim
    descriptionLabel.TextSize = 10
    descriptionLabel.TextTruncate = Enum.TextTruncate.AtEnd
    descriptionLabel.TextXAlignment = Enum.TextXAlignment.Left
    descriptionLabel.Parent = row

    local valueText = Instance.new("TextLabel")
    valueText.AnchorPoint = Vector2.new(1, 0)
    valueText.Position = UDim2.new(1, -6, 0, 5)
    valueText.Size = UDim2.fromOffset(68, 20)
    valueText.BackgroundTransparency = 1
    valueText.Font = Enum.Font.GothamMedium
    valueText.TextColor3 = Theme.TextMuted
    valueText.TextSize = 12
    valueText.TextXAlignment = Enum.TextXAlignment.Right
    valueText.Parent = row

    local track = Instance.new("TextButton")
    track.Name = "Track"
    track.Position = UDim2.fromOffset(6, 49)
    track.Size = UDim2.new(1, -12, 0, 4)
    track.BackgroundColor3 = Color3.fromRGB(43, 42, 50)
    track.Text = ""
    track.AutoButtonColor = false
    track.BorderSizePixel = 0
    track.Parent = row
    local trackCorner = Instance.new("UICorner")
    trackCorner.CornerRadius = UDim.new(1, 0)
    trackCorner.Parent = track

    local fill = Instance.new("Frame")
    fill.Name = "Fill"
    fill.Size = UDim2.fromScale(0, 1)
    fill.BackgroundColor3 = Theme.Accent
    fill.BorderSizePixel = 0
    fill.Parent = track
    local fillCorner = Instance.new("UICorner")
    fillCorner.CornerRadius = UDim.new(1, 0)
    fillCorner.Parent = fill

    local knob = Instance.new("Frame")
    knob.Name = "Knob"
    knob.AnchorPoint = Vector2.new(0.5, 0.5)
    knob.Position = UDim2.new(0, 0, 0.5, 0)
    knob.Size = UDim2.fromOffset(10, 10)
    knob.BackgroundColor3 = Color3.fromRGB(244, 244, 247)
    knob.BorderSizePixel = 0
    knob.Parent = track
    local knobCorner = Instance.new("UICorner")
    knobCorner.CornerRadius = UDim.new(1, 0)
    knobCorner.Parent = knob

    local controller = {}
    local function setValue(value, animated, invokeCallback)
        value = math.clamp(math.floor((tonumber(value) or minimum) + 0.5), minimum, maximum)
        local changed = value ~= currentValue
        currentValue = value
        local alpha = maximum == minimum and 0 or (currentValue - minimum) / (maximum - minimum)
        valueText.Text = tostring(currentValue)
        if animated then
            tween(fill, 0.10, Enum.EasingStyle.Quad, Enum.EasingDirection.Out, {Size = UDim2.fromScale(alpha, 1)})
            tween(knob, 0.10, Enum.EasingStyle.Quad, Enum.EasingDirection.Out, {Position = UDim2.new(alpha, 0, 0.5, 0)})
        else
            fill.Size = UDim2.fromScale(alpha, 1)
            knob.Position = UDim2.new(alpha, 0, 0.5, 0)
        end
        if changed and invokeCallback ~= false then callback(currentValue) end
        return changed
    end

    function controller:Set(value, animated)
        return setValue(value, animated ~= false, true)
    end
    function controller:Get() return currentValue end

    local function setFromScreenX(screenX)
        local width = track.AbsoluteSize.X
        if width <= 0 then return end
        local alpha = math.clamp((screenX - track.AbsolutePosition.X) / width, 0, 1)
        setValue(minimum + (maximum - minimum) * alpha, true, true)
    end

    track.InputBegan:Connect(function(input)
        if input.UserInputType == Enum.UserInputType.MouseButton1 or input.UserInputType == Enum.UserInputType.Touch then
            draggingSlider = true
            setFromScreenX(input.Position.X)
            knob.Size = UDim2.fromOffset(13, 13)
        end
    end)
    track.InputEnded:Connect(function(input)
        if input.UserInputType == Enum.UserInputType.MouseButton1 or input.UserInputType == Enum.UserInputType.Touch then
            draggingSlider = false
            knob.Size = UDim2.fromOffset(10, 10)
        end
    end)
    UserInputService.InputChanged:Connect(function(input)
        if not draggingSlider then return end
        if input.UserInputType == Enum.UserInputType.MouseMovement or input.UserInputType == Enum.UserInputType.Touch then
            setFromScreenX(input.Position.X)
        end
    end)
    UserInputService.InputEnded:Connect(function(input)
        if draggingSlider and (input.UserInputType == Enum.UserInputType.MouseButton1 or input.UserInputType == Enum.UserInputType.Touch) then
            draggingSlider = false
            knob.Size = UDim2.fromOffset(10, 10)
        end
    end)

    setValue(currentValue, false, false)
    callback(currentValue)
    return controller
end

