StatsTracker = {
	Labels = {},
	LastSignature = "",
	LastAt = 0,
}

function StatsTracker:Fmt(value)
	local number = tonumber(value) or 0
	local text = tostring(math.floor(number))
	local sign = ""
	if string.sub(text, 1, 1) == "-" then
		sign = "-"
		text = string.sub(text, 2)
	end
	local result = text
	while true do
		local nextText, replaced = string.gsub(result, "^(%d+)(%d%d%d)", "%1,%2")
		result = nextText
		if replaced == 0 then break end
	end
	return sign .. result
end

function StatsTracker:ResultKind(data)
	local joined = ""
	if type(data) == "table" and type(data.lines) == "table" then
		joined = string.lower(table.concat(data.lines, " "))
	end
	if string.find(joined, "raid", 1, true) then
		return "raid"
	end
	return "mission"
end

function StatsTracker:AddResult(data)
	if type(data) ~= "table" then return end
	local sig = table.concat({
		tostring(data.resultType or "result"),
		tostring(data.timeTaken or ""),
		tostring(data.titanKills or 0),
		tostring(data.exp or 0),
		tostring(data.gold or 0),
		tostring(data.gems or 0),
	}, "|")
	local now = tick()
	if sig == self.LastSignature and now - (self.LastAt or 0) < 25 then
		return
	end
	self.LastSignature = sig
	self.LastAt = now

	local kind = self:ResultKind(data)
	local failed = tostring(data.resultType or "") == "failed"
	if kind == "raid" then
		if failed then
			State.StatsRaidFailed = (tonumber(State.StatsRaidFailed) or 0) + 1
		else
			State.StatsRaidCompleted = (tonumber(State.StatsRaidCompleted) or 0) + 1
		end
	else
		if failed then
			State.StatsMissionFailed = (tonumber(State.StatsMissionFailed) or 0) + 1
		else
			State.StatsMissionCompleted = (tonumber(State.StatsMissionCompleted) or 0) + 1
		end
	end

	State.StatsTotalXP = (tonumber(State.StatsTotalXP) or 0) + (tonumber(data.exp) or 0)
	State.StatsTotalGold = (tonumber(State.StatsTotalGold) or 0) + (tonumber(data.gold) or 0)
	State.StatsTotalGems = (tonumber(State.StatsTotalGems) or 0) + (tonumber(data.gems) or 0)
	self:Refresh()
	saveSettingsIfReady()
end

function StatsTracker:Reset()
	State.StatsMissionCompleted = 0
	State.StatsRaidCompleted = 0
	State.StatsMissionFailed = 0
	State.StatsRaidFailed = 0
	State.StatsTotalXP = 0
	State.StatsTotalGold = 0
	State.StatsTotalGems = 0
	self:Refresh()
	saveSettingsIfReady()
end

function StatsTracker:Refresh()
	local labels = self.Labels or {}
	if labels.MissionCompleted then labels.MissionCompleted.Text = "Missions completed: " .. self:Fmt(State.StatsMissionCompleted) end
	if labels.RaidCompleted then labels.RaidCompleted.Text = "Raids completed: " .. self:Fmt(State.StatsRaidCompleted) end
	if labels.MissionFailed then labels.MissionFailed.Text = "Failed missions: " .. self:Fmt(State.StatsMissionFailed) end
	if labels.RaidFailed then labels.RaidFailed.Text = "Failed raids: " .. self:Fmt(State.StatsRaidFailed) end
	if labels.TotalXP then labels.TotalXP.Text = "Total XP: " .. self:Fmt(State.StatsTotalXP) end
	if labels.TotalGold then labels.TotalGold.Text = "Total Gold: " .. self:Fmt(State.StatsTotalGold) end
	if labels.TotalGems then labels.TotalGems.Text = "Total Gems: " .. self:Fmt(State.StatsTotalGems) end
end

