WeaponUI = {}


ReturnToLobby = {
	Running = false,
	LastMessage = "Idle",
	LobbyPlaceId = LOBBY_PLACE_ID,
}

;(function() -- direct return-to-lobby teleport scoped to avoid Luau's 200 local-register limit
	local function stopFarmBeforeReturning()
		State.FarmEnabled = false
		State.IsGrabbed = false
		statusText = "Returning to lobby..."

		if Controls and Controls.Farm and Controls.Farm.Set then
			pcall(function()
				Controls.Farm:Set(false, true)
			end)
		end

		if humanoid and humanoid.Health > 0 then
			pcall(function()
				humanoid.PlatformStand = false
				humanoid.Sit = false
				humanoid:ChangeState(Enum.HumanoidStateType.Freefall)
			end)
		end

		if rootPart and rootPart.Parent then
			pcall(function()
				rootPart.Anchored = false
				rootPart.AssemblyAngularVelocity = Vector3.zero
				rootPart.AssemblyLinearVelocity = Vector3.zero
			end)
		end
	end

	local function buildTeleportOptions()
		local options = nil
		pcall(function()
			options = Instance.new("TeleportOptions")
			options:SetTeleportData({
				Source = "TitanControl",
				Action = "ReturnToLobby",
				CreatedAt = os.time(),
			})
		end)
		return options
	end

	local function tryTeleportToLobby()
		local placeId = tonumber(ReturnToLobby.LobbyPlaceId) or 14916516914
		local errors = {}

		local options = buildTeleportOptions()
		if options then
			local ok, err = pcall(function()
				TeleportService:TeleportAsync(placeId, {player}, options)
			end)
			if ok then
				return true
			end
			table.insert(errors, "TeleportAsync: " .. tostring(err))
		end

		local okWithPlayer, errWithPlayer = pcall(function()
			TeleportService:Teleport(placeId, player)
		end)
		if okWithPlayer then
			return true
		end
		table.insert(errors, "Teleport(placeId, player): " .. tostring(errWithPlayer))

		local okSelf, errSelf = pcall(function()
			TeleportService:Teleport(placeId)
		end)
		if okSelf then
			return true
		end
		table.insert(errors, "Teleport(placeId): " .. tostring(errSelf))

		return false, table.concat(errors, " | ")
	end

	function ReturnToLobby.Run()
		if ReturnToLobby.Running then
			showNotification("Already returning", "Lobby teleport is already running.", "info")
			return
		end

		ReturnToLobby.Running = true
		task.spawn(function()
			local ok, err = pcall(function()
				stopFarmBeforeReturning()
				ReturnToLobby.LastMessage = "Teleporting to lobby place " .. tostring(ReturnToLobby.LobbyPlaceId)
				showNotification("Returning to lobby", "Teleporting to PlaceId " .. tostring(ReturnToLobby.LobbyPlaceId) .. ".", "info")

				local success, message = tryTeleportToLobby()
				if not success then
					error("Lobby teleport failed: " .. tostring(message))
				end

				-- If teleport starts successfully, this script will usually stop here because the place changes.
				showNotification("Teleport started", "Leaving this mission and loading the lobby.", "success")
			end)

			-- Keep the guard up briefly after a successful teleport call so spam-clicks do not queue duplicates.
			task.wait(ok and 4 or 0.2)
			ReturnToLobby.Running = false

			if not ok then
				ReturnToLobby.LastMessage = tostring(err)
				warn("[TitanControl] Return to lobby failed:", err)
				showNotification("Return failed", tostring(err), "error")
			end
		end)
	end
end)()


;(function() -- fast mission actions scoped to avoid Luau local-register pressure
	local function makeSmallActionButton(parent, text, xOffset, width, color, callback)
		local actionButton = Instance.new("TextButton")
		actionButton.Position = UDim2.fromOffset(xOffset, 50)
		actionButton.Size = UDim2.new(0, width, 0, 30)
		actionButton.BackgroundColor3 = color or Theme.Button
