	lastRunStatusLabel = Instance.new("TextLabel")
	lastRunStatusLabel.Position = UDim2.fromOffset(16, 51)
	lastRunStatusLabel.Size = UDim2.new(1, -32, 0, 18)
	lastRunStatusLabel.BackgroundTransparency = 1
	lastRunStatusLabel.Font = Enum.Font.GothamMedium
	lastRunStatusLabel.TextColor3 = Theme.TextDim
	lastRunStatusLabel.TextSize = 9
	lastRunStatusLabel.TextXAlignment = Enum.TextXAlignment.Left
	lastRunStatusLabel.TextTruncate = Enum.TextTruncate.AtEnd
	lastRunStatusLabel.Text = "Last run: " .. tostring(State.LastRunSummary or "No result tracked yet")
	lastRunStatusLabel.Parent = autoCard

	local resetButton = Instance.new("TextButton")
	resetButton.Position = UDim2.fromOffset(16, 77)
	resetButton.Size = UDim2.new(1, -32, 0, 28)
	resetButton.BackgroundColor3 = Theme.Button
	resetButton.BorderSizePixel = 0
	resetButton.AutoButtonColor = false
	resetButton.Font = Enum.Font.GothamBold
	resetButton.Text = "RESET MISSION COUNT"
	resetButton.TextColor3 = Theme.Text
	resetButton.TextSize = 10
	resetButton.Parent = autoCard

	local resetCorner = Instance.new("UICorner")
	resetCorner.CornerRadius = UDim.new(0, 8)
	resetCorner.Parent = resetButton

	refreshAutoMissionStatus = function()
		if not autoMissionStatusLabel then return end
		local count = math.clamp(math.floor((tonumber(State.AutoMissionCount) or 0) + 0.5), 0, 99)
		local limit = math.clamp(math.floor((tonumber(State.AutoMissionLimit) or 0) + 0.5), 0, 10)
		local retryText = State.AutoRetryEnabled and "Retry ON" or "Retry OFF"
		if limit <= 0 then
			autoMissionStatusLabel.Text = string.format("%s  •  Runs counted: %d  •  Limit: unlimited", retryText, count)
		else
			autoMissionStatusLabel.Text = string.format("%s  •  Runs counted: %d/%d  •  Then lobby", retryText, count, limit)
		end
		if lastRunStatusLabel then
			lastRunStatusLabel.Text = "Last run: " .. tostring(State.LastRunSummary or "No result tracked yet")
		end
	end

	resetButton.Activated:Connect(function()
		State.AutoMissionCount = 0
		refreshAutoMissionStatus()
		saveSettingsIfReady()
		showNotification("Auto cycle", "Mission count reset to 0.", "info")
	end)

	refreshAutoMissionStatus()
end)()


