;(function() -- V3 Blade Core telemetry dashboard
    local card = Instance.new("Frame")
    card.Name = "BladeCoreDashboard"
    card.LayoutOrder = 0
    card.Size = UDim2.new(1, 0, 0, 143)
    card.BackgroundColor3 = Theme.CardSoft
    card.BorderSizePixel = 0
    card.Parent = mainPage

    local cardCorner = Instance.new("UICorner")
    cardCorner.CornerRadius = UDim.new(0, 11)
    cardCorner.Parent = card

    local cardStroke = Instance.new("UIStroke")
    cardStroke.Color = Theme.AccentLight
    cardStroke.Transparency = 0.30
    cardStroke.Parent = card

    local title = Instance.new("TextLabel")
    title.Position = UDim2.fromOffset(16, 9)
    title.Size = UDim2.new(1, -32, 0, 20)
    title.BackgroundTransparency = 1
    title.Font = Enum.Font.GothamBold
    title.Text = "BLADE CORE • LIVE ENGINE"
    title.TextColor3 = Theme.Text
    title.TextSize = 12
    title.TextXAlignment = Enum.TextXAlignment.Left
    title.Parent = card

    local function metric(name, xScale, yOffset)
        local box = Instance.new("Frame")
        box.Position = UDim2.new(xScale, 0, 0, yOffset)
        box.Size = UDim2.new(0.5, -20, 0, 30)
        box.BackgroundColor3 = Theme.Card
        box.BorderSizePixel = 0
        box.Parent = card

        local boxCorner = Instance.new("UICorner")
        boxCorner.CornerRadius = UDim.new(0, 8)
        boxCorner.Parent = box

        local label = Instance.new("TextLabel")
        label.Position = UDim2.fromOffset(10, 0)
        label.Size = UDim2.new(1, -20, 1, 0)
        label.BackgroundTransparency = 1
        label.Font = Enum.Font.GothamMedium
        label.Text = name .. ": ..."
        label.TextColor3 = Theme.TextMuted
        label.TextSize = 10
        label.TextXAlignment = Enum.TextXAlignment.Left
        label.TextTruncate = Enum.TextTruncate.AtEnd
        label.Parent = box
        return label
    end

    BladeCoreUI.Mode = metric("Mode", 0, 35)
    BladeCoreUI.Ammo = metric("Ammo", 0.5, 35)
    BladeCoreUI.Alive = metric("Titans", 0, 70)
    BladeCoreUI.Anchor = metric("Anchor", 0.5, 70)
    BladeCoreUI.State = metric("State", 0, 105)
    BladeCoreUI.Burst = metric("Last burst", 0.5, 105)

    task.spawn(function()
        while card.Parent do
            task.wait(0.24)

            local mode = tostring(AdaptiveCombatMode or "BladeOnly") .. " / " .. tostring(V58BladeEngine and V58BladeEngine.Mode or "PACK SWEEP")
            local segments = lastBladeSegments ~= nil and tostring(lastBladeSegments) or "?"
            local sets = lastBladeSets ~= nil and tostring(lastBladeSets) or "?"
            local alive = 0

            pcall(function()
                alive = getCachedAliveTitanCount()
            end)

            local anchorCount = 0
            pcall(function()
                anchorCount = tonumber(CombatAnchorRuntime.TargetCount) or 0
            end)

            if BladeCoreUI.Mode then
                BladeCoreUI.Mode.Text = "Mode: " .. mode
            end
            if BladeCoreUI.Ammo then
                BladeCoreUI.Ammo.Text = "Ammo: " .. segments .. "/6 • " .. sets .. "/3"
            end
            if BladeCoreUI.Alive then
                BladeCoreUI.Alive.Text = "Titans alive: " .. tostring(alive)
            end
            if BladeCoreUI.Anchor then
                if Config.V6ExactBladeEnabled == true and V6ExactBlade then
                    BladeCoreUI.Anchor.Text = "V9: " .. tostring(V9RaidCombat and V9RaidCombat.BladeMode or "QUEUE")
                        .. " • Reg " .. tostring(V6ExactBlade.LastCycleTargets or 0)
                        .. " • Slash x" .. tostring(V6ExactBlade.LastCycleSlashes or 0)
                else
                    BladeCoreUI.Anchor.Text = "Anchor pack: " .. tostring(anchorCount)
                end
            end
            if BladeCoreUI.State then
                local phase = V58BladeEngine and tostring(V58BladeEngine.Phase or "READY") or "READY"
                local detail = V58BladeEngine and tostring(V58BladeEngine.PhaseDetail or "") or ""
                local ammoDirector = Config.V93BladeAmmoDirectorEnabled == true
                    and V93BladeAmmoDirector
                    and tostring(V93BladeAmmoDirector.Status or "READY")
                    or "LEGACY"
                BladeCoreUI.State.Text = "State: " .. phase
                    .. (detail ~= "" and (" • " .. detail) or "")
                    .. " • Ammo: " .. ammoDirector
            end
            if BladeCoreUI.Burst then
                BladeCoreUI.Burst.Text = "Last burst: " .. tostring(
                    V58BladeEngine and V58BladeEngine.BurstSummary() or "no sample"
                )
            end
        end
    end)
end)()

