Controls.Farm = createToggle(WeaponUI.BladesPage or mainPage, 1, "Auto Blades", "Independent blade farm. Thunder Spears stay controlled from the Spears tab.", State.BladesEnabled, function(value)
    local wasRuntimeActive = State.FarmEnabled == true
    State.BladesEnabled = value == true
