    if wasRuntimeActive and not State.FarmEnabled then
        releaseCombatLock()
    elseif State.FarmEnabled and not wasRuntimeActive then
        clearCurrentTarget(false)

        task.delay(0.12, function()
            if State.FarmEnabled
                and type(setMenuOpen) == "function"
                and screenGui
