function createProfileActionButton(text, position, size, color)
	local button = Instance.new("TextButton")
	button.Position = position
	button.Size = size
	button.BackgroundColor3 = color
	button.AutoButtonColor = false
	button.Font = Enum.Font.GothamBold
	button.Text = text
	button.TextColor3 = Theme.Text
	button.TextSize = 11
	button.Parent = profileCard

	local corner = Instance.new("UICorner")
	corner.CornerRadius = UDim.new(0, 8)
	corner.Parent = button

	local stroke = Instance.new("UIStroke")
	stroke.Color = Color3.fromRGB(194, 204, 238)
	stroke.Transparency = 0.42
	stroke.Parent = button

	button.MouseEnter:Connect(function()
		tween(button, 0.18, Enum.EasingStyle.Quad, Enum.EasingDirection.Out, {
			BackgroundColor3 = color:Lerp(Color3.fromRGB(255, 255, 255), 0.12)
		})
	end)
	button.MouseLeave:Connect(function()
		tween(button, 0.18, Enum.EasingStyle.Quad, Enum.EasingDirection.Out, {
			BackgroundColor3 = color
		})
	end)

	return button
end

