profileNames = {}
selectedProfileIndex = 0

function setProfileMessage(message, success)
	profileMessage.Text = tostring(message or "")
	profileMessage.TextColor3 = success == false and Color3.fromRGB(255, 188, 198) or Color3.fromRGB(210, 238, 225)
end

function getProfileNameFromUi()
	local requestedName = sanitizeProfileName(profileNameBox.Text)
	if requestedName == "" and selectedProfileIndex >= 1 and profileNames[selectedProfileIndex] then
		requestedName = profileNames[selectedProfileIndex]
	end
	return requestedName
end

function refreshAutoLoadProfileButton()
	if not autoLoadProfileButton then return end
	local autoName = tostring(PersistentSettings.AutoLoadProfileName or "")
	if PersistentSettings.AutoLoadProfile == true and autoName ~= "" then
		autoLoadProfileButton.Text = "AUTO LOAD: " .. autoName
		autoLoadProfileButton.BackgroundColor3 = Theme.Button
	else
		autoLoadProfileButton.Text = "AUTO LOAD: OFF"
		autoLoadProfileButton.BackgroundColor3 = Theme.CardActive
	end
end

function refreshProfileSelector(preferredName)
	profileNames = getSortedProfileNames()

	if #profileNames == 0 then
		selectedProfileIndex = 0
		selectedProfileLabel.Text = "No saved profiles"
		selectedProfileLabel.TextColor3 = Theme.TextMuted
		refreshAutoLoadProfileButton()
		return
	end

	local preferredKey = resolveProfileKey(preferredName)
	if preferredKey then
		for index, name in ipairs(profileNames) do
			if name == preferredKey then
				selectedProfileIndex = index
				break
			end
		end
	end

	if selectedProfileIndex < 1 or selectedProfileIndex > #profileNames then
		selectedProfileIndex = 1
	end

	selectedProfileLabel.Text = profileNames[selectedProfileIndex]
	selectedProfileLabel.TextColor3 = Theme.Text
	refreshAutoLoadProfileButton()
end

function moveProfileSelection(direction)
	if #profileNames == 0 then return end
	selectedProfileIndex = ((selectedProfileIndex - 1 + direction) % #profileNames) + 1
	local selectedName = profileNames[selectedProfileIndex]
	selectedProfileLabel.Text = selectedName
	profileNameBox.Text = selectedName
	refreshAutoLoadProfileButton()
end

previousProfile.Activated:Connect(function()
	moveProfileSelection(-1)
end)

nextProfile.Activated:Connect(function()
	moveProfileSelection(1)
end)

selectedProfileLabel.Activated:Connect(function()
	if selectedProfileIndex >= 1 and profileNames[selectedProfileIndex] then
		profileNameBox.Text = profileNames[selectedProfileIndex]
	end
end)

function applyProfile(profile, autoLoadMode)
	if not profile then return false end

	Controls.TitansPerHit:Set(SliceHubMissionClampTPS(profile.TitansPerHit, Config.TitansPerHit), true)
	Controls.TitanRipper:Set(profile.TitanRipperEnabled, true)
    if Controls.SpearSupport then Controls.SpearSupport:Set(profile.SpearSupportEnabled == true, true) end
    if Controls.SpearAutoFire then Controls.SpearAutoFire:Set(profile.SpearAutoFireEnabled ~= false, true) end
    if Controls.SpearAutoRefill then Controls.SpearAutoRefill:Set(profile.SpearAutoRefillEnabled == true, true) end
    if Controls.SpearInfinite then Controls.SpearInfinite:Set(profile.SpearInfiniteEnabled == true, true) end
    if Controls.AutoUseBuffs then Controls.AutoUseBuffs:Set(profile.AutoUseBuffsEnabled == true, true) end
    if Controls.BuffOrderAdvance then Controls.BuffOrderAdvance:Set(profile.BuffOrderAdvanceEnabled ~= false, true) end
    if Controls.BuffBlackFlare then Controls.BuffBlackFlare:Set(profile.BuffBlackFlareEnabled ~= false, true) end
    if Controls.BuffOrderRage then Controls.BuffOrderRage:Set(profile.BuffOrderRageEnabled ~= false, true) end
    if Controls.BuffFoundersOrder then Controls.BuffFoundersOrder:Set(profile.BuffFoundersOrderEnabled ~= false, true) end
    if Controls.BuffOrderRevolution then Controls.BuffOrderRevolution:Set(profile.BuffOrderRevolutionEnabled ~= false, true) end
    if Controls.RaidAutoOpenChests then Controls.RaidAutoOpenChests:Set(profile.RaidAutoOpenChestsEnabled == true, true) end
	State.AbilitySlot1Enabled = profile.AbilitySlot1Enabled ~= false
	State.AbilitySlot2Enabled = profile.AbilitySlot2Enabled ~= false
	State.AbilitySlot3Enabled = profile.AbilitySlot3Enabled ~= false
	State.AbilitySlot4Enabled = profile.AbilitySlot4Enabled ~= false
	State.AbilitySlot5Enabled = profile.AbilitySlot5Enabled ~= false
	Controls.AutoRefill:Set(profile.AutoRefillEnabled, true)
	if Controls.AutoSkipCutscene then
		Controls.AutoSkipCutscene:Set(SliceHubClampAutoSkipCutscene(profile.AutoSkipCutsceneEnabled), true)
	end
	Controls.AutoEscape:Set(profile.AutoEscapeEnabled, true)
	Controls.ExpandHitboxes:Set(profile.ExpandHitboxesEnabled, true)
	if Controls.LowGraphics then
		Controls.LowGraphics:Set(profile.PerformanceModeEnabled, true)
	end
	if Controls.NoEffects then
		Controls.NoEffects:Set(profile.DisableEffectsEnabled, true)
	end
	if Controls.EcoLoops then
		Controls.EcoLoops:Set(profile.EcoLoopModeEnabled, true)
	end
	if Controls.MapProps then
		Controls.MapProps:Set(profile.MapPropsHiddenEnabled, true)
	end
	if Controls.RemoveInjuryKillFlash then
		Controls.RemoveInjuryKillFlash:Set(profile.RemoveInjuryKillFlashEnabled == true, true)
	end
	if Controls.RemoveDamageText then
		Controls.RemoveDamageText:Set(profile.RemoveDamageTextEnabled == true, true)
	end
	if Controls.AutoMissionLimit then
		Controls.AutoMissionLimit:Set(profile.AutoMissionLimit or 0, true)
	end
	if Controls.AutoRetry then
		Controls.AutoRetry:Set(profile.AutoRetryEnabled == true, true)
	end
	-- Apply Farm last so all support settings are ready before movement begins.
	if autoLoadMode and PersistentSettings.RestoreFarmOnStart ~= true then
		Controls.Farm:Set(false, true)
	else
		Controls.Farm:Set(profile.BladesEnabled == true or profile.FarmEnabled == true, true)
	end
	return true
end

autoLoadProfileButton.Activated:Connect(function()
	local requestedName = getProfileNameFromUi()
	local profile, resolvedName = getNamedProfile(requestedName)
	if PersistentSettings.AutoLoadProfile == true and resolvedName and resolvedName == PersistentSettings.AutoLoadProfileName then
		PersistentSettings.AutoLoadProfile = false
		PersistentSettings.AutoLoadProfileName = ""
		refreshAutoLoadProfileButton()
		local ok, message = saveAllSettings(true)
		setProfileMessage(ok and "Auto-load disabled" or tostring(message), ok)
		showNotification(ok and "Auto-load off" or "Save failed", ok and "No profile will auto-load on next run." or tostring(message), ok and "info" or "error")
		return
	end
	if not profile then
		setProfileMessage("Select or save a profile first", false)
		showNotification("Auto-load failed", "Select or save a config profile first.", "error")
		return
	end
	PersistentSettings.AutoLoadProfile = true
	PersistentSettings.AutoLoadProfileName = resolvedName
	profileNameBox.Text = resolvedName
	refreshProfileSelector(resolvedName)
	local ok, message = saveAllSettings(true)
	setProfileMessage(ok and ("Auto-load set: " .. resolvedName) or tostring(message), ok)
	showNotification(ok and "Auto-load set" or "Save failed", ok and (resolvedName .. " loads on startup.") or tostring(message), ok and "success" or "error")
end)

saveProfileButton.Activated:Connect(function()
	local success, message, savedName = saveNamedProfile(profileNameBox.Text)
	if savedName then
		profileNameBox.Text = savedName
		refreshProfileSelector(savedName)
	end
	setProfileMessage(message, success)
	if success then
		showNotification("Config saved", savedName or "Profile", "success")
	else
		showNotification("Save failed", message, "error")
	end
end)

loadProfileButton.Activated:Connect(function()
	local requestedName = sanitizeProfileName(profileNameBox.Text)
	if requestedName == "" and selectedProfileIndex >= 1 then
		requestedName = profileNames[selectedProfileIndex]
	end

	local profile, resolvedName = getNamedProfile(requestedName)
	if not profile then
		setProfileMessage("Profile not found", false)
		showNotification("Load failed", "Profile not found", "error")
		return
	end

	applyProfile(profile)
	profileNameBox.Text = resolvedName
	refreshProfileSelector(resolvedName)
	setProfileMessage("Loaded " .. resolvedName, true)
	showNotification("Config loaded", resolvedName, "success")
end)

deleteProfileButton.Activated:Connect(function()
	local requestedName = sanitizeProfileName(profileNameBox.Text)
	if requestedName == "" and selectedProfileIndex >= 1 then
		requestedName = profileNames[selectedProfileIndex]
	end

	local success, message = deleteNamedProfile(requestedName)
	if success then
		if PersistentSettings.AutoLoadProfileName == requestedName then
			PersistentSettings.AutoLoadProfile = false
			PersistentSettings.AutoLoadProfileName = ""
			saveAllSettings(true)
		end
		profileNameBox.Text = ""
		refreshProfileSelector()
	end
	setProfileMessage(message, success)
	if success then
		showNotification("Config deleted", requestedName, "success")
	else
		showNotification("Delete failed", message, "error")
	end
end)

profileNameBox.FocusLost:Connect(function()
	profileNameBox.Text = sanitizeProfileName(profileNameBox.Text)
end)

refreshProfileSelector()
refreshAutoLoadProfileButton()
task.defer(function()
	if PersistentSettings.AutoLoadProfile ~= true then return end
	local autoName = tostring(PersistentSettings.AutoLoadProfileName or "")
	if autoName == "" then return end
	local profile, resolvedName = getNamedProfile(autoName)
	if not profile then
		setProfileMessage("Auto-load profile missing: " .. autoName, false)
		showNotification("Auto-load missing", autoName .. " was not found.", "error")
		return
	end
	applyProfile(profile, true)
	profileNameBox.Text = resolvedName
	refreshProfileSelector(resolvedName)
	setProfileMessage("Auto-loaded " .. resolvedName, true)
	showNotification("Config auto-loaded", resolvedName, "success")
end)
end)()

