applyThemeToUi = function()
	applyThemePresetValues(PersistentSettings.ThemeName)

	pcall(function()
		window.BackgroundColor3 = Theme.WindowBottom
		titleBar.BackgroundColor3 = Theme.Title
		tabBar.BackgroundColor3 = Theme.TabBar
		tabSelection.BackgroundColor3 = Theme.TabSelectedA
		windowStroke.Color = Theme.AccentLight
		tabBarStroke.Color = Theme.StrokeSoft
		statusCard.BackgroundColor3 = Theme.CardSoft
		statusDot.BackgroundColor3 = Theme.Accent
		statusLabel.TextColor3 = Theme.TextMuted
		if statusDetailLabel then statusDetailLabel.TextColor3 = Theme.TextDim end
		accentLine.BackgroundColor3 = Theme.Accent
		if settingsPage:IsA("ScrollingFrame") then settingsPage.ScrollBarImageColor3 = Theme.AccentLight end

		windowGradient.Color = ColorSequence.new({
			ColorSequenceKeypoint.new(0, Theme.WindowTop),
			ColorSequenceKeypoint.new(1, Theme.WindowBottom),
		})
		titleGradient.Color = ColorSequence.new({
			ColorSequenceKeypoint.new(0, Theme.WindowTop),
			ColorSequenceKeypoint.new(1, Theme.Title),
		})
		tabSelectionGradient.Color = ColorSequence.new({
			ColorSequenceKeypoint.new(0, Theme.TabSelectedA),
			ColorSequenceKeypoint.new(1, Theme.TabSelectedB),
		})
		accentGradient.Color = ColorSequence.new({
			ColorSequenceKeypoint.new(0, Theme.AccentLight),
			ColorSequenceKeypoint.new(0.5, Theme.Accent),
			ColorSequenceKeypoint.new(1, Theme.TabSelectedA),
		})
	end)
end

