---------------------------------------------------------------------
-- MISSION COMPLETION & WEBHOOK DETECTION
---------------------------------------------------------------------

;(function() -- webhook mission monitor scoped to avoid Luau's 200 local-register limit
	local function startMissionWebhookMonitor()
	local resultScreenActive = false
	local lastWebhookSignature = ""
	local lastWebhookSentAt = 0
	local lastAutoRetryAt = 0

    V3ResultGuard = {
        Armed = false,
        Processing = false,
        ResultSeenSince = nil,
        ActiveEvidenceSince = nil,
        LastAcceptedAt = 0,
    }

	local function getPlayerStats()
		-- v114: safe account-stat scan. No result GUI guessing; only exact ValueBase/Attribute names
		-- under player/player-data containers are accepted. Unknown fields are omitted in the embed.
		local stats = {
			level = nil,
			prestige = nil,
			gold = nil,
			gems = nil,
			trusted = false,
		}

		local function fmt(value)
			local number = tonumber(value)
			if not number then return nil end
			local text = tostring(math.floor(number))
			local sign = ""
			if string.sub(text, 1, 1) == "-" then
				sign = "-"
				text = string.sub(text, 2)
			end
			local result = text
			while true do
				local nextText, replaced = string.gsub(result, "^(%d+)(%d%d%d)", "%1,%2")
				result = nextText
				if replaced == 0 then break end
			end
			return sign .. result
		end

		local function canonicalName(name)
			local lower = string.lower(tostring(name or ""))
			lower = string.gsub(lower, "[^%w]", "")
			if lower == "level" or lower == "lvl" or lower == "playerlevel" or lower == "currentlevel" then return "level" end
			if lower == "prestige" or lower == "prestiges" or lower == "prestigelevel" or lower == "prestigelvl" or lower == "p" then return "prestige" end
			if lower == "gold" or lower == "coins" or lower == "coin" or lower == "money" or lower == "cash" or lower == "currency" then return "gold" end
			if lower == "gems" or lower == "gem" or lower == "crystals" or lower == "crystal" or lower == "shards" then return "gems" end
			return nil
		end

		local function betterNumber(currentText, newValue)
			local current = tonumber(string.gsub(tostring(currentText or ""), ",", ""))
			local newNumber = tonumber(newValue)
			if not newNumber then return false end
			if current == nil then return true end
			-- Prefer non-zero if a previous weak scan found zero.
			if current == 0 and newNumber > 0 then return true end
			return false
		end

		local function applyStat(name, value)
			local key = canonicalName(name)
			if not key then return end
			local text = fmt(value)
			if not text then return end
			if key == "level" then
				if betterNumber(stats.level, value) then stats.level = text; stats.trusted = true end
			elseif key == "prestige" then
				if betterNumber(stats.prestige, value) then stats.prestige = text; stats.trusted = true end
			elseif key == "gold" then
				if betterNumber(stats.gold, value) then stats.gold = text; stats.trusted = true end
			elseif key == "gems" then
				if betterNumber(stats.gems, value) then stats.gems = text; stats.trusted = true end
			end
		end

		local function scanAttributes(object)
			if not object or type(object.GetAttributes) ~= "function" then return end
			local ok, attributes = pcall(function() return object:GetAttributes() end)
			if ok and type(attributes) == "table" then
				for name, value in pairs(attributes) do applyStat(name, value) end
			end
		end

		local function scanValues(root, depthLimit)
			if not root then return end
			scanAttributes(root)
			local rootDepth = 0
			local rootPath = root:GetFullName()
			for _, object in ipairs(root:GetDescendants()) do
				local full = object:GetFullName()
				if not string.find(full, "PlayerGui", 1, true) and not string.find(full, "TitanControlMenu", 1, true) then
					if object:IsA("IntValue") or object:IsA("NumberValue") or object:IsA("StringValue") then
						applyStat(object.Name, object.Value)
					end
					scanAttributes(object)
				end
			end
		end

		scanValues(player)

		-- Some games replicate account stats in ReplicatedStorage.PlayerData/<UserId or Name>.
		local dataRoots = {"PlayerData", "Players", "Profiles", "Data", "Stats", "PlayerStats"}
		for _, rootName in ipairs(dataRoots) do
			local root = ReplicatedStorage:FindFirstChild(rootName)
			if root then
				local userFolder = root:FindFirstChild(tostring(player.UserId)) or root:FindFirstChild(player.Name)
				if userFolder then scanValues(userFolder) end
			end
		end

		return stats
	end

	local ResultKeywords = {
		"mission failed",
		"mission fail",
		"mission complete",
		"mission completed",
        "raid failed",
        "raid fail",
        "raid complete",
        "raid completed",
		"victory",
		"defeat",
	}

	local function cleanGuiText(value)
		local raw = tostring(value or "")
		local out = {}
		local inTag = false
		local lastWasSpace = false

		for index = 1, #raw do
			local ch = string.sub(raw, index, index)
			local byte = string.byte(ch)

			if ch == "<" then
				inTag = true
			elseif ch == ">" then
				inTag = false
			elseif not inTag then
				local isSpace = byte == 9 or byte == 10 or byte == 13 or byte == 32
				if isSpace then
					if not lastWasSpace and #out > 0 then
						out[#out + 1] = " "
						lastWasSpace = true
					end
				else
					out[#out + 1] = ch
					lastWasSpace = false
				end
			end
		end

		local text = table.concat(out)
		while #text > 0 and string.sub(text, -1) == " " do
			text = string.sub(text, 1, #text - 1)
		end
		return text
	end

	local function hasAnyKeyword(lowerText, keywords)
		for _, keyword in ipairs(keywords) do
			if string.find(lowerText, keyword, 1, true) then
				return true
			end
		end
		return false
	end

	local function getTextFromObject(object)
		if object:IsA("TextLabel") or object:IsA("TextButton") or object:IsA("TextBox") then
			return cleanGuiText(object.Text)
		end
		return nil
	end

	local function isVisibleTextObject(object)
		if not object:IsA("GuiObject") then return false end
		local ok, visible = pcall(guiObjectIsActuallyVisible, object)
		return ok and visible == true
	end

	local function guiTextDescendantHas(root, keywords)
		if not root then return false end

		for _, descendant in ipairs(root:GetDescendants()) do
			local text = getTextFromObject(descendant)
			if text and text ~= "" and isVisibleTextObject(descendant) then
				if hasAnyKeyword(string.lower(text), keywords) then
					return true
				end
			end
		end

		return false
	end

	local function findMissionResultRoot()
		for _, object in ipairs(playerGui:GetDescendants()) do
			local text = getTextFromObject(object)
			if text and text ~= "" and isVisibleTextObject(object) then
				local lower = string.lower(text)
				if hasAnyKeyword(lower, ResultKeywords) then
					local node = object
					for _ = 1, 10 do
						if not node or node == playerGui then break end

						if node:IsA("GuiObject") then
							local hasStats = guiTextDescendantHas(node, {"stats"})
							local hasObtained = guiTextDescendantHas(node, {"obtained"})
							local hasButtons = guiTextDescendantHas(node, {"leave", "modifiers", "retry"})
							if hasStats and (hasObtained or hasButtons) then
								return node, lower
							end
						end

						node = node.Parent
					end

					return object.Parent, lower
				end
			end
		end
		return nil, nil
	end


	local function findGuiButtonAncestor(object)
		local node = object
		for _ = 1, 8 do
			if not node or node == playerGui then break end
			if node:IsA("GuiButton") then
				return node
			end
			node = node.Parent
		end
		return nil
	end

	local function clickVisibleGuiObject(object)
		if not object or not object:IsA("GuiObject") then return false end
		local target = findGuiButtonAncestor(object) or object
		if not target:IsA("GuiObject") then return false end

		-- v111: first try the signal route. Some result buttons accept Activate even when mouse click is blocked.
		if target:IsA("GuiButton") then
			pcall(function() target:Activate() end)
			if type(firesignal) == "function" then
				pcall(function() firesignal(target.MouseButton1Down) end)
				pcall(function() firesignal(target.MouseButton1Click) end)
				pcall(function() firesignal(target.Activated) end)
			end
		end

		local oldWindowVisible = window and window.Visible
		local oldShadowVisible = shadow and shadow.Visible
		local oldCursorVisible = guiCursor and guiCursor.Visible
		local hideOwnGui = screenGui and not target:IsDescendantOf(screenGui)

		if hideOwnGui then
			-- The control window sits above Roblox UI. Hide it for the click so RETRY is not covered.
			if window then window.Visible = false end
			if shadow then shadow.Visible = false end
			if guiCursor then guiCursor.Visible = false end
			task.wait(0.08)
		end

		local pos = target.AbsolutePosition
		local size = target.AbsoluteSize
		local x = math.floor(pos.X + size.X / 2 + 0.5)
		local y = math.floor(pos.Y + size.Y / 2 + 0.5)
		local inset = Vector2.new(0, 0)
		pcall(function()
			inset = GuiService:GetGuiInset()
		end)
		pcall(function()
			VirtualInputManager:SendMouseMoveEvent(x + inset.X, y + inset.Y, game)
		end)
		task.wait(0.035)
		pcall(function()
			VirtualInputManager:SendMouseButtonEvent(x + inset.X, y + inset.Y, 0, true, game, 0)
			task.wait(0.07)
			VirtualInputManager:SendMouseButtonEvent(x + inset.X, y + inset.Y, 0, false, game, 0)
		end)

		if hideOwnGui then
			task.wait(0.18)
			if window then window.Visible = oldWindowVisible end
			if shadow then shadow.Visible = oldShadowVisible end
			if guiCursor then guiCursor.Visible = oldCursorVisible end
		end

		return true
	end

	local function findRetryButton(root)
		local bestObject = nil
		local bestY = -math.huge

		local function scanRetryText(scanRoot)
			if not scanRoot then return end
			for _, object in ipairs(scanRoot:GetDescendants()) do
				if screenGui and object:IsDescendantOf(screenGui) then
					continue
				end
				local text = getTextFromObject(object)
				if text and text ~= "" and isVisibleTextObject(object) then
					local lower = string.lower(text)
					if string.find(lower, "retry", 1, true) then
						local candidate = findGuiButtonAncestor(object) or object
						if candidate:IsA("GuiObject") and candidate.AbsolutePosition.Y > bestY then
							bestY = candidate.AbsolutePosition.Y
							bestObject = candidate
						end
					end
				end
			end
		end

		scanRetryText(root)
		if not bestObject then
			scanRetryText(playerGui)
		end
		return bestObject
	end

	local function autoRetryFromResultGui(root)
		if not State.AutoRetryEnabled then return end
		local now = tick()
		if now - lastAutoRetryAt < 6 then return end
		lastAutoRetryAt = now
		task.wait(1.05)
		local refreshedRoot = findMissionResultRoot()
		root = refreshedRoot or root
		local retryButton = findRetryButton(root)
		if retryButton then
			showNotification("Auto retry", "Result screen detected; clicking RETRY.", "info")
			clickVisibleGuiObject(retryButton)
		else
			showNotification("Auto retry", "Result screen detected, but RETRY was not visible.", "error")
		end
	end

	local function handleAutoCycleFromResultGui(root)
		if not State.AutoRetryEnabled then return end
		local now = tick()
		if now - lastAutoRetryAt < 6 then return end
		lastAutoRetryAt = now

		State.AutoMissionCount = math.clamp(math.floor((tonumber(State.AutoMissionCount) or 0) + 1.5), 0, 99)
		refreshAutoMissionStatus()
		saveSettingsIfReady()

		task.wait(1.05)

		local limit = math.clamp(math.floor((tonumber(State.AutoMissionLimit) or 0) + 0.5), 0, 10)
		if limit > 0 and State.AutoMissionCount >= limit then
			showNotification("Auto cycle complete", "Mission limit reached; returning to lobby.", "success")
			State.AutoMissionCount = 0
			refreshAutoMissionStatus()
			saveSettingsIfReady()
			ReturnToLobby.Run()
			return
		end

		local refreshedRoot = findMissionResultRoot()
		root = refreshedRoot or root
		local retryButton = findRetryButton(root)
		if retryButton then
			showNotification("Auto retry", string.format("Mission %d/%s done; clicking RETRY.", tonumber(State.AutoMissionCount) or 0, limit > 0 and tostring(limit) or "∞"), "info")
			clickVisibleGuiObject(retryButton)
		else
			showNotification("Auto retry", "Result screen detected, but RETRY was not visible.", "error")
		end
	end

	triggerAutoRetryNow = function()
		if not State.AutoRetryEnabled then return end
		local root = findMissionResultRoot()
		if root then
			handleAutoCycleFromResultGui(root)
		end
	end

	local function parseNumber(text)
		local compact = string.gsub(tostring(text or ""), ",", "")
		local numberText = string.match(compact, "%d+")
		return numberText and tonumber(numberText) or nil
	end

	local function parseClock(text)
		return string.match(tostring(text or ""), "%d+:%d+")
	end

	local function getVisibleTextItems(root)
		local items = {}
		if not root then return items end

		for _, object in ipairs(root:GetDescendants()) do
			local text = getTextFromObject(object)
			if text and text ~= "" and isVisibleTextObject(object) then
				local position = object.AbsolutePosition
				table.insert(items, {
					text = text,
					lower = string.lower(text),
					number = parseNumber(text),
					clock = parseClock(text),
					x = position.X,
					y = position.Y,
					object = object,
				})
			end
		end

		table.sort(items, function(a, b)
			if math.abs(a.y - b.y) > 8 then
				return a.y < b.y
			end
			return a.x < b.x
		end)

		return items
	end

	local function findClockValue(items)
		for _, item in ipairs(items) do
			if item.clock and item.clock ~= "" then
				return item.clock
			end
		end
		return "Unknown"
	end

	local function findMetricValue(items, keywords)
		for index, item in ipairs(items) do
			if hasAnyKeyword(item.lower, keywords) then
				if item.number then
					return item.number
				end

				for lookAhead = index + 1, math.min(#items, index + 12) do
					local candidate = items[lookAhead]
					if candidate.number then
						local sameRow = math.abs(candidate.y - item.y) <= 34 and candidate.x >= item.x
						local nearbyBelow = candidate.y >= item.y and candidate.y - item.y <= 90
						if sameRow or nearbyBelow then
							return candidate.number
						end
					end
				end
			end
		end
		return 0
	end

	local function formatNumber(value)
		local number = tonumber(value)
		if not number then return "Unknown" end

		local text = tostring(math.floor(number))
		local sign = ""
		if string.sub(text, 1, 1) == "-" then
			sign = "-"
			text = string.sub(text, 2)
		end

		local result = text
		while true do
			local replaced
			result, replaced = string.gsub(result, "^(%d+)(%d%d%d)", "%1,%2")
			if replaced == 0 then break end
		end

		return sign .. result
	end

	local function isOnlyNumberText(text)
		local compact = string.gsub(tostring(text or ""), ",", "")
		compact = string.gsub(compact, "%s+", "")
		return string.match(compact, "^%d+$") ~= nil
	end

	local function isStandardResultText(lowerText)
		local textValue = tostring(lowerText or "")
		if textValue == "" then return true end
		if isOnlyNumberText(textValue) then return true end

		local exactIgnored = {
			["mission completed"] = true,
			["mission complete"] = true,
			["mission failed"] = true,
			["mission fail"] = true,
			["stats"] = true,
			["time taken"] = true,
			["damage dealt"] = true,
			["titans killed"] = true,
			["critical hits"] = true,
			["obtained"] = true,
			["leave"] = true,
			["modifiers"] = true,
			["retry"] = true,
			[">"] = true,
			["<"] = true,
			["exp"] = true,
			["xp"] = true,
			["gold"] = true,
			["gems"] = true,
			["gem"] = true,
			["achievement"] = true,
		}

		if exactIgnored[textValue] then return true end
		if string.find(textValue, "retry", 1, true) then return true end
		if string.find(textValue, "your streak", 1, true) then return true end
		return false
	end

	local function findFirstItemWithKeyword(items, keywords)
		for _, item in ipairs(items) do
			if hasAnyKeyword(item.lower, keywords) then
				return item
			end
		end
		return nil
	end

	local function findButtonStartY(items)
		local lowest = math.huge
		for _, item in ipairs(items) do
			if item.lower == "leave" or item.lower == "modifiers" or string.find(item.lower, "retry", 1, true) then
				if item.y < lowest then
					lowest = item.y
				end
			end
		end
		return lowest ~= math.huge and lowest or nil
	end

	local function collectRewardNumberItems(items)
		local obtainedItem = findFirstItemWithKeyword(items, {"obtained"})
		if not obtainedItem then return {} end

		local buttonY = findButtonStartY(items) or math.huge
		local rewardItems = {}

		for _, item in ipairs(items) do
			if item.number and item.y > obtainedItem.y + 6 and item.y < buttonY - 3 then
				if item.lower ~= ">" and item.lower ~= "<" and not string.find(item.lower, "retry", 1, true) then
					table.insert(rewardItems, item)
				end
			end
		end

		table.sort(rewardItems, function(a, b)
			if math.abs(a.y - b.y) > 10 then
				return a.y < b.y
			end
			return a.x < b.x
		end)

		-- Some result screens expose a tiny hidden/count label right after "OBTAINED".
		-- If it appears before the real reward row, drop it so EXP/Gold/Gems line up correctly.
		while #rewardItems >= 4
			and (rewardItems[1].number or 0) < 1000
			and (rewardItems[2].number or 0) >= 1000
			and (rewardItems[3].number or 0) >= 1000 do
			table.remove(rewardItems, 1)
		end

		return rewardItems
	end

	local function cleanCandidateName(value)
		local name = cleanGuiText(value)
		if name == "" then return nil end

		local lower = string.lower(name)
		local genericNames = {
			["frame"] = true,
			["imagelabel"] = true,
			["imagebutton"] = true,
			["textlabel"] = true,
			["textbutton"] = true,
			["textbox"] = true,
			["uicorner"] = true,
			["uistroke"] = true,
			["reward"] = true,
			["rewards"] = true,
			["item"] = true,
			["icon"] = true,
			["amount"] = true,
			["quantity"] = true,
			["count"] = true,
			["label"] = true,
			["background"] = true,
			["container"] = true,
			["slot"] = true,
			["inner"] = true,
			["outer"] = true,
			["border"] = true,
			["outline"] = true,
			["shadow"] = true,
			["glow"] = true,
			["stroke"] = true,
			["gradient"] = true,
			["star"] = true,
			["rarity"] = true,
			["check"] = true,
			["checkmark"] = true,
			["tick"] = true,
			["mark"] = true,
			["selected"] = true,
			["enabled"] = true,
			["disabled"] = true,
			["button"] = true,
			["hover"] = true,
            ["main"] = true,
            ["root"] = true,
            ["content"] = true,
            ["holder"] = true,
            ["perk"] = true,
            ["drop"] = true,
            ["common perk"] = true,
            ["rare perk"] = true,
            ["epic perk"] = true,
            ["legendary perk"] = true,
            ["mythic perk"] = true,
            ["inventory"] = true,
            ["equipment"] = true,
            ["market"] = true,
            ["rankings"] = true,
            ["regiment"] = true,
            ["battlepass"] = true,
            ["missions"] = true,
            ["quests"] = true,
			["shine"] = true,
			["sparkle"] = true,
		}

		if genericNames[lower] or isStandardResultText(lower) then
			return nil
		end

        -- Reject structural GUI/object ids such as "2_1", "3-2", "1_4".
        if string.match(lower, "^%d+[_%-]%d+$")
            or string.match(lower, "^%d+[_%-]%d+[_%-]%d+$")
            or string.match(lower, "^slot[_%-]?%d+$")
            or string.match(lower, "^item[_%-]?%d+$") then
            return nil
        end

        -- Names made mostly from digits/underscores are never useful reward names.
        local strippedStructure = string.gsub(lower, "[%d_%-%s]", "")
        if strippedStructure == "" then
            return nil
        end
		if string.len(name) <= 1 then
			return nil
		end
		if string.find(lower, "roblox", 1, true) or string.find(lower, "rbxasset", 1, true) then
			return nil
		end

		return name
	end

	local function rarityNameFromText(value)
		local lower = string.lower(tostring(value or ""))
		if string.find(lower, "mythic", 1, true) then return "Mythic" end
		if string.find(lower, "legendary", 1, true) then return "Legendary" end
		if string.find(lower, "epic", 1, true) then return "Epic" end
		if string.find(lower, "rare", 1, true) then return "Rare" end
		if string.find(lower, "common", 1, true) then return "Common" end
		return nil
	end

	local function rarityNameFromColor(color)
		if typeof(color) ~= "Color3" then return nil end

		local h, s, v = Color3.toHSV(color)
		if v < 0.18 then return nil end

		-- Low-saturation white/gray icons are usually common/basic rewards.
		if s < 0.18 then
			return "Common"
		end

		-- Roblox Color3.toHSV hue is 0-1. These ranges are intentionally broad
		-- because different result screens use slightly different border/icon colors.
		if h <= 0.04 or h >= 0.93 then
			return "Mythic"
		elseif h >= 0.05 and h <= 0.15 then
			return "Legendary"
		elseif h >= 0.70 and h <= 0.88 then
			return "Epic"
		elseif h >= 0.48 and h <= 0.65 then
			return "Rare"
		end

		return nil
	end

	local function inspectRewardRarity(numberItem)
		local object = numberItem.object
		if not object then return nil end

		local container = object.Parent
		for _ = 1, 5 do
			if not container then break end

			local fromName = rarityNameFromText(container.Name)
			if fromName then return fromName end

			for _, descendant in ipairs(container:GetDescendants()) do
				local nameRarity = rarityNameFromText(descendant.Name)
				if nameRarity then return nameRarity end
			end

			-- Prefer the item icon/text color. Borders are often just the result-card gold trim,
			-- so border/background color is only used as a fallback.
			local fallbackRarity = nil
			for _, descendant in ipairs(container:GetDescendants()) do
				if descendant:IsA("ImageLabel") or descendant:IsA("ImageButton") then
					local rarity = rarityNameFromColor(descendant.ImageColor3)
					if rarity then return rarity end
				elseif descendant:IsA("TextLabel") or descendant:IsA("TextButton") then
					local rarity = rarityNameFromColor(descendant.TextColor3)
					if rarity then return rarity end
				elseif descendant:IsA("UIStroke") and not fallbackRarity then
					fallbackRarity = rarityNameFromColor(descendant.Color)
				elseif descendant:IsA("GuiObject") and not fallbackRarity then
					fallbackRarity = rarityNameFromColor(descendant.BackgroundColor3)
				end
			end

			if fallbackRarity then return fallbackRarity end
			container = container.Parent
		end

		return nil
	end

	local function findNearbyRewardText(numberItem, items)
		if type(items) ~= "table" then return nil end

		local bestText = nil
		local bestScore = math.huge

		for _, item in ipairs(items) do
			if item ~= numberItem and not item.number then
				local candidate = cleanCandidateName(item.text)
				if candidate then
					local dx = math.abs((item.x or 0) - (numberItem.x or 0))
					local dy = math.abs((item.y or 0) - (numberItem.y or 0))
					if dx <= 110 and dy <= 85 then
						local score = dx + dy * 1.4
						if score < bestScore then
							bestScore = score
							bestText = candidate
						end
					end
				end
			end
		end

		return bestText
	end


    local RewardHoverCache = setmetatable({}, {__mode = "k"})

    local RewardAttributePriority = {
        "PerkName",
        "RewardName",
        "ItemName",
        "DisplayName",
        "TraitName",
        "DropName",
        "Perk",
        "Item",
        "Title",
    }

    local function findRewardTileContainer(numberItem)
        local object = numberItem and numberItem.object
        if not object then return nil end

        local best = nil
        local bestArea = math.huge
        local node = object.Parent

        for _ = 1, 6 do
            if not node then break end

            if node:IsA("GuiObject") then
                local size = node.AbsoluteSize
                local area = size.X * size.Y

                if size.X >= 24 and size.X <= 220
                    and size.Y >= 24 and size.Y <= 220
                    and area < bestArea then

                    local hasImage = false
                    for _, descendant in ipairs(node:GetDescendants()) do
                        if descendant:IsA("ImageLabel") or descendant:IsA("ImageButton") then
                            hasImage = true
                            break
                        end
                    end

                    if hasImage then
                        best = node
                        bestArea = area
                    end
                end
            end

            node = node.Parent
        end

        return best or object.Parent
    end

    local function rewardNameFromMetadata(container)
        if not container then return nil end

        local objects = {container}
        for _, descendant in ipairs(container:GetDescendants()) do
            objects[#objects + 1] = descendant
        end

        for _, object in ipairs(objects) do
            local attributes = {}
            pcall(function()
                attributes = object:GetAttributes()
            end)

            for _, key in ipairs(RewardAttributePriority) do
                local candidate = cleanCandidateName(attributes[key])
                if candidate then return candidate end
            end

            for _, value in pairs(attributes) do
                local candidate = cleanCandidateName(value)
                if candidate then return candidate end
            end

            if object:IsA("StringValue") then
                local candidate = cleanCandidateName(object.Value)
                if candidate then return candidate end
            elseif object:IsA("ObjectValue") and object.Value then
                local candidate = cleanCandidateName(object.Value.Name)
                if candidate then return candidate end
            end
        end

        return nil
    end

    local function visibleTextSnapshot()
        local snapshot = {}
        for _, object in ipairs(playerGui:GetDescendants()) do
            if screenGui and object:IsDescendantOf(screenGui) then
                continue
            end

            local value = getTextFromObject(object)
            if value and value ~= "" and isVisibleTextObject(object) then
                snapshot[value] = true
            end
        end
        return snapshot
    end

    local function scoreTooltipCandidate(textValue, object, cursorX, cursorY)
        local candidate = cleanCandidateName(textValue)
        if not candidate then return nil, -math.huge end

        local lower = string.lower(candidate)
        local length = string.len(candidate)
        local score = 0

        if length <= 32 then score += 20 else score -= math.min(40, length - 32) end
        if length >= 3 and length <= 18 then score += 12 end
        if string.find(lower, "chance", 1, true) then score -= 30 end
        if string.find(lower, "rarity", 1, true) then score -= 25 end
        if string.find(lower, "%", 1, true) then score -= 25 end

        -- Result tooltips are normally close to the hovered reward tile.
        if object and object:IsA("GuiObject") then
            local pos = object.AbsolutePosition
            local size = object.AbsoluteSize
            local centerX = pos.X + size.X * 0.5
            local centerY = pos.Y + size.Y * 0.5
            local distance = math.sqrt(
                (centerX - (cursorX or centerX)) ^ 2
                + (centerY - (cursorY or centerY)) ^ 2
            )

            if distance <= 220 then
                score += 45
            elseif distance <= 420 then
                score += 18
            else
                score -= math.min(35, distance / 50)
            end

            local node = object
            for _ = 1, 5 do
                if not node then break end
                local nodeName = string.lower(tostring(node.Name or ""))
                if string.find(nodeName, "tooltip", 1, true)
                    or string.find(nodeName, "hover", 1, true)
                    or string.find(nodeName, "perk", 1, true)
                    or string.find(nodeName, "reward", 1, true)
                    or string.find(nodeName, "info", 1, true) then
                    score += 18
                    break
                end
                node = node.Parent
            end
        end

        -- Names like CRIPPLE / GEAR BEGINNER are commonly rendered uppercase.
        local letters = string.gsub(candidate, "[^%a]", "")
        if letters ~= "" and letters == string.upper(letters) then
            score += 10
        end

        return candidate, score
    end

    local function rewardNameFromHover(container)
        if not container or not container:IsA("GuiObject") then return nil end

        if RewardHoverCache[container] ~= nil then
            return RewardHoverCache[container] or nil
        end

        pcall(function()
            VirtualInputManager:SendMouseMoveEvent(8, 8, game)
        end)
        task.wait(0.04)

        local before = visibleTextSnapshot()

        local position = container.AbsolutePosition
        local size = container.AbsoluteSize
        local x = math.floor(position.X + size.X * 0.5)
        local y = math.floor(position.Y + size.Y * 0.5)

        local inset = Vector2.new(0, 0)
        pcall(function()
            inset = GuiService:GetGuiInset()
        end)

        pcall(function()
            VirtualInputManager:SendMouseMoveEvent(x + inset.X, y + inset.Y, game)
        end)

        task.wait(0.20)

        local bestName = nil
        local bestScore = -math.huge

        for _, object in ipairs(playerGui:GetDescendants()) do
            if screenGui and object:IsDescendantOf(screenGui) then
                continue
            end

            local value = getTextFromObject(object)
            if value and value ~= "" and isVisibleTextObject(object) and not before[value] then
                local candidate, score = scoreTooltipCandidate(value, object, x, y)
                if candidate and score > bestScore then
                    bestScore = score
                    bestName = candidate
                end
            end
        end

        RewardHoverCache[container] = bestName or false
        return bestName
    end


    local function findObtainedY(items)
        for _, item in ipairs(items or {}) do
            local lower = string.lower(tostring(item.text or ""))
            if lower == "obtained" or string.find(lower, "obtained", 1, true) then
                return tonumber(item.y) or 0
            end
        end
        return nil
    end

    local function tileQuantity(tile)
        if not tile then return 1 end

        local best = nil
        for _, object in ipairs(tile:GetDescendants()) do
            local value = getTextFromObject(object)
            if value and value ~= "" and isVisibleTextObject(object) then
                local cleaned = cleanGuiText(value)
                local number = parseNumber(cleaned)

                if number and number > 0 and number <= 999 then
                    -- Reward tile count labels are normally tiny values.
                    if not best or number < best then
                        best = number
                    end
                end
            end
        end

        return best or 1
    end

    local function collectRewardTiles(root, items)
        if not root then return {} end

        local obtainedY = findObtainedY(items) or 0
        local candidates = {}

        for _, object in ipairs(root:GetDescendants()) do
            if object:IsA("GuiObject")
                and object.Visible
                and object.AbsoluteSize.X >= 35
                and object.AbsoluteSize.X <= 180
                and object.AbsoluteSize.Y >= 35
                and object.AbsoluteSize.Y <= 180 then

                local hasIcon = false
                for _, descendant in ipairs(object:GetDescendants()) do
                    if descendant:IsA("ImageLabel")
                        or descendant:IsA("ImageButton") then
                        hasIcon = true
                        break
                    end
                end

                if hasIcon then
                    local centerY = object.AbsolutePosition.Y + object.AbsoluteSize.Y * 0.5
                    if centerY > obtainedY + 12 then
                        candidates[#candidates + 1] = object
                    end
                end
            end
        end

        -- Keep smallest leaf-like tile candidates.
        table.sort(candidates, function(a, b)
            local areaA = a.AbsoluteSize.X * a.AbsoluteSize.Y
            local areaB = b.AbsoluteSize.X * b.AbsoluteSize.Y
            return areaA < areaB
        end)

        local deduped = {}
        for _, candidate in ipairs(candidates) do
            local overlapsExisting = false

            for _, existing in ipairs(deduped) do
                if candidate:IsDescendantOf(existing)
                    or existing:IsDescendantOf(candidate) then
                    overlapsExisting = true
                    break
                end

                local a = candidate.AbsolutePosition
                local as = candidate.AbsoluteSize
                local b = existing.AbsolutePosition
                local bs = existing.AbsoluteSize

                local centerAX = a.X + as.X * 0.5
                local centerAY = a.Y + as.Y * 0.5
                local centerBX = b.X + bs.X * 0.5
                local centerBY = b.Y + bs.Y * 0.5

                if math.abs(centerAX - centerBX) < 12
                    and math.abs(centerAY - centerBY) < 12 then
                    overlapsExisting = true
                    break
                end
            end

            if not overlapsExisting then
                deduped[#deduped + 1] = candidate
            end
        end

        -- Group every reward row below OBTAINED. V5.2 only returned the widest
        -- row, which dropped lower-row rewards from the webhook scan.
        local rows = {}
        for _, tile in ipairs(deduped) do
            local centerY = tile.AbsolutePosition.Y + tile.AbsoluteSize.Y * 0.5
            local placed = false

            for _, row in ipairs(rows) do
                if math.abs(row.CenterY - centerY) <= 28 then
                    row.Tiles[#row.Tiles + 1] = tile
                    row.CenterY = (row.CenterY * (row.Count or 1) + centerY) / ((row.Count or 1) + 1)
                    row.Count = (row.Count or 1) + 1
                    placed = true
                    break
                end
            end

            if not placed then
                rows[#rows + 1] = {CenterY = centerY, Count = 1, Tiles = {tile}}
            end
        end

        table.sort(rows, function(a, b) return a.CenterY < b.CenterY end)

        local allTiles = {}
        for _, row in ipairs(rows) do
            table.sort(row.Tiles, function(a, b)
                return a.AbsolutePosition.X < b.AbsolutePosition.X
            end)
            for _, tile in ipairs(row.Tiles) do
                allTiles[#allTiles + 1] = tile
            end
        end

        return allTiles
    end

    local function findRewardNameForTile(tile)
        if not tile then return nil end

        local metadataName = rewardNameFromMetadata(tile)
        if metadataName then
            return metadataName
        end

        local hoverName = rewardNameFromHover(tile)
        if hoverName then
            return hoverName
        end

        for _, descendant in ipairs(tile:GetDescendants()) do
            local textValue = getTextFromObject(descendant)
            if textValue and textValue ~= "" then
                local candidate = cleanCandidateName(textValue)
                if candidate then
                    return candidate
                end
            end
        end

        local rarity = nil
        local fakeNumberItem = {
            object = tile,
            x = tile.AbsolutePosition.X,
            y = tile.AbsolutePosition.Y,
        }

        rarity = inspectRewardRarity(fakeNumberItem)
        if rarity then
            return "Unknown " .. rarity .. " reward"
        end

        return "Unknown reward"
    end

    local function tileLooksLikeResource(tile)
        if not tile then return false end
        local keywords = {"exp", "experience", "gold", "money", "cash", "gem"}
        local function matches(value)
            local lower = string.lower(tostring(value or ""))
            for _, keyword in ipairs(keywords) do
                if string.find(lower, keyword, 1, true) then return true end
            end
            return false
        end

        if matches(tile.Name) then return true end
        for _, object in ipairs(tile:GetDescendants()) do
            if matches(object.Name) then return true end
            local value = getTextFromObject(object)
            if value and matches(value) then return true end
        end
        return false
    end

    local function extractRewardsFromTiles(root, items)
        local tiles = collectRewardTiles(root, items)
        if #tiles <= 2 then return {} end

        local drops = {}

        for index, tile in ipairs(tiles) do
            -- Result layouts always begin with EXP and Gold. Gems are optional;
            -- only skip later resource tiles when their metadata/text actually says so.
            local resourceTile = index <= 2 or tileLooksLikeResource(tile)
            if not resourceTile then
                local name = findRewardNameForTile(tile) or "Unknown reward"
                local quantity = tileQuantity(tile)

                drops[#drops + 1] = {
                    name = name,
                    quantity = quantity,
                }
            end
        end

        return drops
    end

    local function findRewardNameNearNumber(numberItem, items)
        local object = numberItem.object
        if not object then return nil end

        local tile = findRewardTileContainer(numberItem)

        local metadataName = rewardNameFromMetadata(tile)
        if metadataName then return metadataName end

        local hoverName = rewardNameFromHover(tile)
        if hoverName then return hoverName end

        local nearbyText = findNearbyRewardText(numberItem, items)
        if nearbyText then return nearbyText end

        local container = tile or object.Parent
        for _ = 1, 4 do
            if not container then break end

            for _, descendant in ipairs(container:GetDescendants()) do
                if descendant ~= object then
                    local textValue = getTextFromObject(descendant)
                    if textValue and textValue ~= "" then
                        local candidate = cleanCandidateName(textValue)
                        if candidate then return candidate end
                    end
                end
            end

            for _, descendant in ipairs(container:GetDescendants()) do
                if descendant:IsA("ImageLabel") or descendant:IsA("ImageButton") then
                    local candidate = cleanCandidateName(descendant.Name)
                    if candidate then return candidate end
                end
            end

            local containerName = cleanCandidateName(container.Name)
            if containerName then return containerName end
            container = container.Parent
        end

        local rarity = inspectRewardRarity(numberItem)
        if rarity then
            return "Unknown " .. rarity .. " reward"
        end

        return "Unknown reward"
    end

	local function extractRewards(root, items)
		local rewardNumberItems = collectRewardNumberItems(items)
		local rewards = {
			exp = 0,
			gold = 0,
			gems = 0,
			drops = {},
		}

		if #rewardNumberItems >= 3 then
			rewards.exp = rewardNumberItems[1].number or 0
			rewards.gold = rewardNumberItems[2].number or 0
			rewards.gems = rewardNumberItems[3].number or 0

            local tileDrops = extractRewardsFromTiles(root, items)
            if #tileDrops > 0 then
                rewards.drops = tileDrops
                return rewards
            end

			for index = 4, #rewardNumberItems do
				local item = rewardNumberItems[index]
				local quantity = tonumber(item.number) or 0
				if quantity > 0 then
					local dropName = findRewardNameNearNumber(item, items) or "Unknown drop"
					table.insert(rewards.drops, {
						name = dropName,
						quantity = quantity,
					})
				end
			end
		else
			-- Fallback for alternate result UIs that label EXP/Gold/Gems directly.
			rewards.exp = findMetricValue(items, {"exp", "xp", "experience"})
			rewards.gold = findMetricValue(items, {"gold", "money", "cash"})
			rewards.gems = findMetricValue(items, {"gems", "gem"})
		end

		return rewards
	end

	local function formatDrops(drops)
		if type(drops) ~= "table" or #drops == 0 then
			return "None detected"
		end

		local totals = {}
		local order = {}
		for _, drop in ipairs(drops) do
			local name = tostring(drop.name or "Unknown drop")
			if name == "" then name = "Unknown drop" end
			local quantity = tonumber(drop.quantity) or 0
			if quantity > 0 then
				if not totals[name] then
					table.insert(order, name)
					totals[name] = 0
				end
				totals[name] += quantity
			end
		end

		if #order == 0 then
			return "None detected"
		end

		local lines = {}
		for _, name in ipairs(order) do
			table.insert(lines, "• **" .. name .. "** x" .. tostring(totals[name]))
		end

		return table.concat(lines, "\n")
	end

	local function sanitizeDrops(drops)
		local clean = {}
		local seen = {}
		for _, drop in ipairs(type(drops) == "table" and drops or {}) do
			local name = cleanCandidateName(drop.name)
			local lower = string.lower(tostring(name or ""))
			local quantity = math.max(0, math.floor((tonumber(drop.quantity) or 0) + 0.5))
			local untrusted = name == nil
				or lower == "unknown drop"
				or lower == "unknown reward"
				or string.find(lower, "unknown ", 1, true) == 1

			if not untrusted and quantity > 0 then
				local key = string.lower(name)
				if not seen[key] then
					seen[key] = {name = name, quantity = 0}
					clean[#clean + 1] = seen[key]
				end
				seen[key].quantity += quantity
			end
		end
		return clean
	end

	local function rewardSnapshotSignature(data)
		local parts = {
			tostring(math.max(0, tonumber(data and data.exp) or 0)),
			tostring(math.max(0, tonumber(data and data.gold) or 0)),
			tostring(math.max(0, tonumber(data and data.gems) or 0)),
		}
		for _, drop in ipairs(data and data.drops or {}) do
			parts[#parts + 1] = string.lower(tostring(drop.name or ""))
				.. "=" .. tostring(tonumber(drop.quantity) or 0)
		end
		return table.concat(parts, "|")
	end

	local function containsRareNamedDrop(drops)
		for _, drop in ipairs(type(drops) == "table" and drops or {}) do
			local lower = string.lower(tostring(drop.name or ""))
			if string.find(lower, "mythic", 1, true)
				or string.find(lower, "serum", 1, true) then
				return true
			end
		end
		return false
	end

	local function collectUniqueLines(items)
		local lines = {}
		local seen = {}

		for _, item in ipairs(items) do
			local text = item.text
			if text ~= "" and not seen[text] then
				seen[text] = true
				table.insert(lines, text)
			end
		end

		return lines
	end

	local function makeSignature(resultType, lines)
		local signature = resultType
		for index = 1, math.min(#lines, 12) do
			signature = signature .. "|" .. lines[index]
		end
		return signature
	end

	local function trimForDiscord(text, limit)
		text = tostring(text or "")
		limit = limit or 1000
		if string.len(text) <= limit then return text end
		return string.sub(text, 1, limit - 3) .. "..."
	end

	local function detectResultType(statusLower, lines)
		local joined = string.lower(table.concat(lines, " "))
		local source = tostring(statusLower or "") .. " " .. joined

		if string.find(source, "failed", 1, true) or string.find(source, "defeat", 1, true) then
			return "failed"
		end
		if string.find(source, "complete", 1, true) or string.find(source, "victory", 1, true) then
			return "completed"
		end
		return "result"
	end

    function V3ResultGuard.PanelStarting(root)
        if not root then return false end

        for _, object in ipairs(root:GetDescendants()) do
            local value = getTextFromObject(object)
            if value and value ~= "" and isVisibleTextObject(object) then
                local lower = string.lower(value)
                if string.find(lower, "starting", 1, true)
                    or string.find(lower, "loading mission", 1, true)
                    or string.find(lower, "teleporting", 1, true) then
                    return true
                end
            end
        end

        return false
    end

    function V3ResultGuard.ActiveMissionEvidence()
        if V4RaidDirector and V4RaidDirector.Enabled == true then
            return true
        end

        local alive = 0
        pcall(function()
            alive = getCachedAliveTitanCount()
        end)

        if alive > 0 then
            return true
        end

        -- Objective history alone is weak evidence; require a live progress row.
        for _, key in ipairs(MissionObjectiveHistory.Order) do
            local value = tostring(MissionObjectiveHistory.LatestByKey[key] or "")
            if string.match(value, "%[%s*%d+%s*/%s*[1-9]%d*%s*%]") then
                return true
            end
        end

        return false
    end

    function V3ResultGuard.ValidData(data)
        if type(data) ~= "table" then return false end
        if tostring(data.timeTaken or "Unknown") == "Unknown" then return false end

        -- A real result panel can be a 0-kill failure, but it must at least have
        -- a populated result clock and a recognized result type.
        return data.resultType == "completed"
            or data.resultType == "failed"
            or data.resultType == "result"
    end

    function V3ResultGuard.ResetTaskHistoryForRun()
        MissionObjectiveHistory.Order = {}
        MissionObjectiveHistory.LatestByKey = {}
        MissionObjectiveHistory.LastUpdatedAt = 0
    end

	local function createMissionResultEmbed(data)
		local isFailed = data.resultType == "failed"
        local isRaid = tostring(data.runType or "Mission") == "Raid"
		local title = isFailed
            and (isRaid and "❌ Raid Failed" or "❌ Mission Failed")
            or (isRaid and "✅ Raid Completed" or "✅ Mission Completed")
		local color = isFailed and 15158332 or 3066993

		local rewardLine = "EXP **" .. formatNumber(data.exp or 0)
			.. "**  •  Gold **" .. formatNumber(data.gold or 0)
			.. "**  •  Gems **" .. formatNumber(data.gems or 0) .. "**"
		local description = "Verified from a stable result-panel snapshot."

		local embed = {
			title = title,
			description = trimForDiscord(description, 3800),
			color = color,
			timestamp = os.date("!%Y-%m-%dT%H:%M:%SZ"),
			fields = {},
			footer = {text = "SliceHub V9.4 • Webhook V2"},
			pingRare = containsRareNamedDrop(data.drops),
		}

        table.insert(embed.fields, {
            name = isRaid and "⚔️ Raid" or "🧭 Mission",
            value = trimForDiscord(isRaid and ((data.raidName or "Unknown raid") .. "\n" .. tostring(data.missionDisplay or "Unknown map")) or (data.missionDisplay or "Unknown mission"), 1000),
            inline = false,
        })

		table.insert(embed.fields, {
			name = "⏱️ Performance",
			value = "Time **" .. tostring(data.timeTaken or "Unknown")
				.. "**  •  Kills **" .. formatNumber(data.titanKills or 0)
				.. "**  •  Damage **" .. formatNumber(data.damageDealt or 0)
				.. "**  •  Crits **" .. formatNumber(data.criticalHits or 0) .. "**",
			inline = false,
		})

		table.insert(embed.fields, {
			name = "💰 Verified Rewards",
			value = rewardLine,
			inline = false,
		})

        local queueActive, queueState = V51QueueRuntime.IsActive()
        if isRaid and queueActive and type(queueState) == "table" then
            table.insert(embed.fields, {
                name = "🔁 Raid Queue",
                value = "Entry " .. tostring(queueState.Index or 1) .. "/" .. tostring(type(queueState.Entries) == "table" and #queueState.Entries or 0)
                    .. " • Entry progress " .. tostring(queueState.EntryDone or 0)
                    .. " • Total clears " .. tostring(queueState.TotalCompleted or 0)
                    .. " • Failures " .. tostring(queueState.TotalFailed or 0),
                inline = false,
            })
        end

        table.insert(embed.fields, {
            name = isRaid and "📋 Raid Objectives" or "📋 Mission Tasks",
            value = trimForDiscord(data.objectives or "No tasks detected", 1000),
            inline = false,
        })

		table.insert(embed.fields, {
			name = "🎁 Named Drops",
			value = trimForDiscord(formatDrops(data.drops), 1000),
			inline = false,
		})

		if WebhookConfig.includeRawDebug then
			local rawText = table.concat(data.lines or {}, "\n")
				.. "\n\nRun recorder:\n" .. V94RunRecorder.Summary(10)
			if rawText ~= "" then
				table.insert(embed.fields, {
					name = "Raw GUI Debug",
					value = trimForDiscord(rawText, 1000),
					inline = false,
				})
			end
		end

		if WebhookConfig.enableStats then
			local statsOk, stats = pcall(getPlayerStats)
			if statsOk and type(stats) == "table" and stats.trusted == true then
				local statParts = {}
				if stats.level then table.insert(statParts, "**Level:** " .. tostring(stats.level)) end
				if stats.prestige then table.insert(statParts, "**Prestige:** " .. tostring(stats.prestige)) end
				if stats.gold then table.insert(statParts, "**Gold:** " .. tostring(stats.gold)) end
				if stats.gems then table.insert(statParts, "**Gems:** " .. tostring(stats.gems)) end
				if #statParts > 0 then
					table.insert(embed.fields, {
						name = "Player Stats",
						value = table.concat(statParts, " | "),
						inline = false,
					})
				end
			end
		end

		return embed
	end

	local function extractMissionResultData(root, statusLower)
		local items = getVisibleTextItems(root)
		local lines = collectUniqueLines(items)
		local resultType = detectResultType(statusLower, lines)
		local rewards = extractRewards(root, items)
		local trustedDrops = sanitizeDrops(rewards.drops)
        local runMeta = V3MissionIdentity.GetRunMetadataForWebhook()

		return {
            runType = runMeta.RunType,
            raidName = runMeta.RaidName,
            difficulty = runMeta.Difficulty,
            raidChoice = runMeta.RaidChoice,
			resultType = resultType,
			timeTaken = findClockValue(items),
			damageDealt = findMetricValue(items, {"damage dealt", "damage"}),
			titanKills = findMetricValue(items, {"titans killed", "titan killed", "titans", "titan"}),
			criticalHits = findMetricValue(items, {"critical hits", "critical", "crit"}),
			exp = rewards.exp,
			gold = rewards.gold,
			gems = rewards.gems,
			drops = trustedDrops,
			rewardSignature = table.concat({
				tostring(rewards.exp or 0),
				tostring(rewards.gold or 0),
				tostring(rewards.gems or 0),
				tostring(#trustedDrops),
			}, "|"),
            missionDisplay = V3MissionIdentity.GetMissionDisplayForWebhook(),
            objectives = V3MissionIdentity.GetMissionObjectiveSummary(),
			lines = lines,
		}
	end

	local function updateLastRunTracker(data)
		if type(data) ~= "table" then return end
		local outcome = tostring(data.resultType or "result")
		local kills = tonumber(data.titanKills) or 0
		local timeTaken = tostring(data.timeTaken or "Unknown")
		local damage = tonumber(data.damageDealt) or 0
		State.LastRunOutcome = outcome
		State.LastRunKills = kills
		State.LastRunTime = timeTaken
		State.LastRunSummary = string.format("%s | %d kills | %s | %s dmg", string.upper(outcome), kills, timeTaken, formatNumber(damage))
		if lastRunStatusLabel then
			lastRunStatusLabel.Text = "Last run: " .. State.LastRunSummary
		end
		refreshAutoMissionStatus()
		saveSettingsIfReady()
	end

	local function clearFinishedRunContext()
		MissionObjectiveHistory.Order = {}
		MissionObjectiveHistory.LatestByKey = {}
		MissionObjectiveHistory.LastUpdatedAt = 0
		MissionObjectiveHistory.SelectedObjective = nil
		MissionObjectiveHistory.SelectedMap = nil
		MissionObjectiveHistory.MetadataUpdatedAt = 0
		V3MissionIdentity.MapTracker.ObservedMap = nil
		V3MissionIdentity.MapTracker.ObservedAt = 0
	end

	local function sendMissionResultFromGui(root, statusLower)
        -- V9.4: poll until both the result identity and reward snapshot are stable.
        -- Never send the first half-populated animation frame.
        local data = nil
        local startedAt = os.clock()
        local lastRewardSnapshot = nil
        local stableRewardReads = 0

        repeat
            local refreshedRoot, refreshedStatus = findMissionResultRoot()
            root = refreshedRoot or root
            statusLower = refreshedStatus or statusLower

            if not root or V3ResultGuard.PanelStarting(root) then
                return false
            end

            data = extractMissionResultData(root, statusLower)
            if V3ResultGuard.ValidData(data) then
				local snapshot = rewardSnapshotSignature(data)
				if snapshot == lastRewardSnapshot then
					stableRewardReads += 1
				else
					lastRewardSnapshot = snapshot
					stableRewardReads = 1
				end

				V94Webhook.LastRewardSignature = snapshot
				V94Webhook.LastStableReads = stableRewardReads
				V94Webhook.Status = "VERIFYING RESULT • stable " .. tostring(stableRewardReads) .. "/2"

				if os.clock() - startedAt >= 0.80 and stableRewardReads >= 2 then
					data.rewardVerified = true
					break
				end
            end

			task.wait(0.22)
		until os.clock() - startedAt >= 4.2

        if not V3ResultGuard.ValidData(data) then
			V94Webhook.Status = "RESULT REJECTED • incomplete panel"
			V94RunRecorder.Record("RESULT_REJECTED", V94Webhook.Status)
            return false
        end

		data.rewardVerified = data.rewardVerified == true
		V94Webhook.Status = data.rewardVerified
			and "RESULT VERIFIED • stable reward snapshot"
			or "RESULT VERIFIED • reward stability timeout"
		V94RunRecorder.Finish(data)
		V94RunRecorder.Record("WEBHOOK_PARSE", V94Webhook.Status, {
			stableReads = stableRewardReads,
			drops = type(data.drops) == "table" and #data.drops or 0,
		})
        V51LastParsedResultData = data
        if tostring(data.runType or "Mission") == "Raid" and V51PhaseStats then
            local seconds = 0
            local m, s = string.match(tostring(data.timeTaken or ""), "(%d+):(%d+)")
            if m and s then seconds = tonumber(m) * 60 + tonumber(s) end
            if tostring(data.resultType) == "failed" then
                V51PhaseStats.Failed += 1
            else
                V51PhaseStats.Completed += 1
            end
            if seconds > 0 then
                V51PhaseStats.TotalSeconds += seconds
                if not V51PhaseStats.FastestSeconds or seconds < V51PhaseStats.FastestSeconds then V51PhaseStats.FastestSeconds = seconds end
            end
        end
		updateLastRunTracker(data)
		if StatsTracker and StatsTracker.AddResult then
			StatsTracker:AddResult(data)
		end
		if data.resultType == "failed" and WebhookConfig.sendFailed == false then
			V94Webhook.Status = "SKIPPED • failed-result webhooks disabled"
			V94RunRecorder.Record("WEBHOOK_SKIPPED", V94Webhook.Status)
			clearFinishedRunContext()
			return true
		end
		if data.resultType ~= "failed" and WebhookConfig.sendCompleted == false then
			V94Webhook.Status = "SKIPPED • completed-result webhooks disabled"
			V94RunRecorder.Record("WEBHOOK_SKIPPED", V94Webhook.Status)
			clearFinishedRunContext()
			return true
		end

        local signature = table.concat({
			tostring(data.runType or "Mission"),
			tostring(data.missionDisplay or "Unknown"),
            tostring(data.resultType or "result"),
            tostring(data.timeTaken or "Unknown"),
            tostring(data.titanKills or 0),
            tostring(data.damageDealt or 0),
            tostring(data.exp or 0),
            tostring(data.gold or 0),
			rewardSnapshotSignature(data),
        }, "|")

		if signature == lastWebhookSignature and tick() - lastWebhookSentAt < 90 then
			V94Webhook.Status = "SKIPPED • duplicate result snapshot"
			V94RunRecorder.Record("WEBHOOK_SKIPPED", V94Webhook.Status)
			clearFinishedRunContext()
			return false
		end

		lastWebhookSignature = signature
		lastWebhookSentAt = tick()
		V94Webhook.LastSentSignature = signature

		local embedOk, embedOrError = pcall(createMissionResultEmbed, data)
		if not embedOk then
			showNotification("Webhook failed", "Embed build error: " .. tostring(embedOrError), "error")
			V94Webhook.Status = "FAILED • embed build"
			V94RunRecorder.Record("WEBHOOK_FAILED", V94Webhook.Status)
			clearFinishedRunContext()
			return
		end

		local ok, result = sendWebhook(embedOrError)
		if ok then
			V94Webhook.Status = "SENT • verified " .. tostring(data.runType or "Mission") .. " result"
			V94RunRecorder.Record("WEBHOOK_SENT", V94Webhook.Status)
			showNotification("Webhook V2 sent", tostring(data.runType or "Mission") .. " stable result snapshot sent.", "success")
		else
			V94Webhook.Status = "FAILED • " .. tostring(result or "request error")
			V94RunRecorder.Record("WEBHOOK_FAILED", V94Webhook.Status)
			showNotification("Webhook failed", tostring(result or "Unknown request error"), "error")
		end

        -- Preserve the finished run's objectives through report creation, then clear for retry.
		clearFinishedRunContext()

        return ok == true
	end

    function V3ResultGuard.ProcessResult(root, statusLower)
        if V3ResultGuard.Processing then return end

        V3ResultGuard.Processing = true
        V3ResultGuard.Armed = false
        V3ResultGuard.ResultSeenSince = nil
        V3ResultGuard.LastAcceptedAt = os.clock()

        V51LastParsedResultData = nil
        local parsed = sendMissionResultFromGui(root, statusLower)

        local queueHandled = false
        if V51LastParsedResultData then
            queueHandled = V51QueueRuntime.HandleResult(V51LastParsedResultData) == true
        end

        -- Queue owns post-result travel. Give remote chest automation enough time to open both chests first.
        if queueHandled then
            task.spawn(function()
                task.wait(2.1)
                ReturnToLobby.Run()
            end)
        elseif parsed and State.AutoRetryEnabled then
            handleAutoCycleFromResultGui(root)
        end

        V3ResultGuard.Processing = false
    end

	local function monitorMissionCompletion()
		while true do
			task.wait(0.20)

            local now = os.clock()
			local root, statusLower = findMissionResultRoot()

			if root then
                V3ResultGuard.ActiveEvidenceSince = nil

                if V3ResultGuard.PanelStarting(root) then
                    -- Old result GUI is still visible while the next run is counting down.
                    resultScreenActive = false
                    V3ResultGuard.Armed = false
                    V3ResultGuard.ResultSeenSince = nil
                    continue
                end

                resultScreenActive = true

                if V3ResultGuard.Armed and not V3ResultGuard.Processing then
                    V3ResultGuard.ResultSeenSince =
                        V3ResultGuard.ResultSeenSince or now

                    if now - V3ResultGuard.ResultSeenSince >= 0.45 then
                        task.spawn(V3ResultGuard.ProcessResult, root, statusLower)
                    end
                end
			else
				resultScreenActive = false
                V3ResultGuard.ResultSeenSince = nil

                if not V3ResultGuard.Armed and not V3ResultGuard.Processing then
                    if V3ResultGuard.ActiveMissionEvidence() then
                        V3ResultGuard.ActiveEvidenceSince =
                            V3ResultGuard.ActiveEvidenceSince or now

                        if now - V3ResultGuard.ActiveEvidenceSince >= 0.80 then
                            V3ResultGuard.ResetTaskHistoryForRun()
                            V3ResultGuard.Armed = true
                            V3ResultGuard.ActiveEvidenceSince = nil
							local runMeta = V3MissionIdentity.GetRunMetadataForWebhook()
							V94RunRecorder.Begin({
								runType = runMeta.RunType,
								raid = runMeta.RaidName,
								difficulty = runMeta.Difficulty,
								mission = V3MissionIdentity.GetMissionDisplayForWebhook(),
							})
                            print("[SliceHub V9.4][RESULT] armed for current mission")
                        end
                    else
                        V3ResultGuard.ActiveEvidenceSince = nil
                    end
                end
			end
		end
	end

	task.spawn(monitorMissionCompletion)
	end

	startMissionWebhookMonitor()
end)()

