    if shadow then shadow.Visible = true end
    if inputShield then inputShield.Visible = true end
    updateGuiCursor()
end

function beginDrag(input)
    dragging = true
    dragStart = input.Position
    originalPosition = window.Position
end

titleBar.InputBegan:Connect(function(input)
    if input.UserInputType == Enum.UserInputType.MouseButton1 or input.UserInputType == Enum.UserInputType.Touch then
        beginDrag(input)
    end
end)

UserInputService.InputChanged:Connect(function(input)
    if dragging and (input.UserInputType == Enum.UserInputType.MouseMovement or input.UserInputType == Enum.UserInputType.Touch) then
        local movement = input.Position - dragStart
        window.Position = UDim2.new(
            originalPosition.X.Scale,
            originalPosition.X.Offset + movement.X,
            originalPosition.Y.Scale,
            originalPosition.Y.Offset + movement.Y
        )
        syncShadow()
    end
end)

UserInputService.InputEnded:Connect(function(input)
    if input.UserInputType == Enum.UserInputType.MouseButton1 or input.UserInputType == Enum.UserInputType.Touch then
        dragging = false
        dragStart = nil
        originalPosition = nil
    end
end)

function setMenuOpen(open)
    State.MenuOpen = open == true
    saveSettingsIfReady()
    dragging = false
    if screenGui then screenGui.Enabled = true end
    if window then window.Visible = State.MenuOpen end
    if shadow then shadow.Visible = State.MenuOpen end
    if inputShield then
        inputShield.Visible = State.MenuOpen
        inputShield.Modal = State.MenuOpen
    end
    updateGuiCursor()
    print("[SliceHub V4.2] menu", State.MenuOpen and "OPEN" or "CLOSED")
end

-- Mobile SH floating button. The real logo can be swapped in later with a Roblox asset id;
-- this text fallback is reliable on every executor and device.
if UserInputService.TouchEnabled and screenGui and not screenGui:FindFirstChild("SliceHubMobileToggle") then
    State.SliceHubMobileToggle = Instance.new("TextButton")
    State.SliceHubMobileToggle.Name = "SliceHubMobileToggle"
    State.SliceHubMobileToggle.AnchorPoint = Vector2.new(1, 0)
    State.SliceHubMobileToggle.Position = UDim2.new(1, -14, 0, 92)
    State.SliceHubMobileToggle.Size = UDim2.fromOffset(54, 54)
    State.SliceHubMobileToggle.BackgroundColor3 = Theme.Accent or Color3.fromRGB(89, 169, 255)
    State.SliceHubMobileToggle.BorderSizePixel = 0
    State.SliceHubMobileToggle.AutoButtonColor = true
    State.SliceHubMobileToggle.Text = "SH"
    State.SliceHubMobileToggle.TextColor3 = Color3.fromRGB(255, 255, 255)
    State.SliceHubMobileToggle.TextSize = 18
    State.SliceHubMobileToggle.Font = Enum.Font.GothamBlack
    State.SliceHubMobileToggle.ZIndex = 10000
    State.SliceHubMobileToggle.Parent = screenGui
    Instance.new("UICorner", State.SliceHubMobileToggle).CornerRadius = UDim.new(1, 0)
    State.SliceHubMobileToggle.Activated:Connect(function()
        setMenuOpen(not State.MenuOpen)
    end)
end

UserInputService.InputBegan:Connect(function(input, processed)
    if MenuKeyBindingActive and input.UserInputType == Enum.UserInputType.Keyboard then
        if input.KeyCode == Enum.KeyCode.Escape then
            MenuKeyBindingActive = false
            refreshMenuKeyCard()
            showNotification("Keybind cancelled", "Menu toggle key was not changed.", "info")
            return
        elseif input.KeyCode ~= Enum.KeyCode.Unknown then
            PersistentSettings.MenuToggleKeyName = input.KeyCode.Name
            MenuKeyBindingActive = false
            refreshMenuKeyCard()
            local ok, message = saveAllSettings(true)
            showNotification(ok and "Keybind saved" or "Save failed", ok and ("Menu toggle is now " .. tostring(PersistentSettings.MenuToggleKeyName)) or tostring(message), ok and "success" or "error")
            return
        end
    end

    if input.UserInputType == Enum.UserInputType.Keyboard
        and input.KeyCode == getMenuToggleKeyCode() then
        setMenuOpen(not State.MenuOpen)
    end
end)

setMenuOpen(PersistentSettings.AutoHideGuiOnLaunch ~= true)
