local SH_CACHE_FOLDER = "SH"
local SH_CACHE_FILE = "SH/bootstrap.shc"
local SH_LEGACY_BOOTSTRAP = "SliceHub_AOTR_V9_1_BOOTSTRAP.lua"
local SH_CACHE_MAGIC = "SHC1"

local SH_B64_ALPHABET =
    "ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789+/"

local function SHBase64Encode(data)
    local output = {}
    local outputIndex = 0

    for index = 1, #data, 3 do
        local a = string.byte(data, index) or 0
        local b = string.byte(data, index + 1) or 0
        local c = string.byte(data, index + 2) or 0
        local remaining = #data - index + 1
        local packed = a * 65536 + b * 256 + c

        local i1 = math.floor(packed / 262144) % 64 + 1
        local i2 = math.floor(packed / 4096) % 64 + 1
        local i3 = math.floor(packed / 64) % 64 + 1
        local i4 = packed % 64 + 1

        outputIndex += 1
        output[outputIndex] = string.sub(SH_B64_ALPHABET, i1, i1)

        outputIndex += 1
        output[outputIndex] = string.sub(SH_B64_ALPHABET, i2, i2)

        outputIndex += 1
        output[outputIndex] =
            remaining >= 2
            and string.sub(SH_B64_ALPHABET, i3, i3)
            or "="

        outputIndex += 1
        output[outputIndex] =
            remaining >= 3
            and string.sub(SH_B64_ALPHABET, i4, i4)
            or "="
    end

    return table.concat(output)
end

local function SHAdler32(data)
    local a = 1
    local b = 0

    for index = 1, #data do
        a = (a + string.byte(data, index)) % 65521
        b = (b + a) % 65521
    end

    return string.format("%08x", b * 65536 + a)
end

local function SHRC4(data, key)
    assert(type(key) == "string" and #key > 0, "invalid cache key")

    local state = {}

    for index = 0, 255 do
        state[index] = index
    end

    local swapIndex = 0

    for index = 0, 255 do
        local keyByte =
            string.byte(key, (index % #key) + 1)

        swapIndex =
            (swapIndex + state[index] + keyByte) % 256

        state[index], state[swapIndex] =
            state[swapIndex], state[index]
    end

    local output = {}
    local outputIndex = 0
    local chunk = {}
    local chunkIndex = 0
    local i = 0
    local j = 0

    for position = 1, #data do
        i = (i + 1) % 256
        j = (j + state[i]) % 256

        state[i], state[j] = state[j], state[i]

        local streamByte =
            state[(state[i] + state[j]) % 256]

        chunkIndex += 1
        chunk[chunkIndex] = string.char(
            bit32.bxor(
                string.byte(data, position),
                streamByte
            )
        )

        if chunkIndex >= 4096 then
            outputIndex += 1
            output[outputIndex] = table.concat(chunk)
            chunk = {}
            chunkIndex = 0
        end
    end

    if chunkIndex > 0 then
        outputIndex += 1
        output[outputIndex] = table.concat(chunk)
    end

    return table.concat(output)
end

local function SHDeviceMaterial()
    local clientId = "unknown-client"
    local userId = "0"

    pcall(function()
        clientId =
            tostring(
                game:GetService(
                    "RbxAnalyticsService"
                ):GetClientId()
            )
    end)

    pcall(function()
        local players = game:GetService("Players")
        local localPlayer = players.LocalPlayer
        if localPlayer then
            userId = tostring(localPlayer.UserId)
        end
    end)

    return table.concat({
        "SliceHub",
        SH_CACHE_MAGIC,
        clientId,
        userId,
    }, "|")
end

local function SHBuildEncryptedWrapper(plainSource)
    local httpService = game:GetService("HttpService")
    local salt = httpService:GenerateGUID(false)
    local checksum = SHAdler32(plainSource)
    local key = SHDeviceMaterial() .. "|" .. salt
    local encrypted = SHRC4(plainSource, key)
    local payload = SHBase64Encode(encrypted)

    return table.concat({
        "-- SliceHub encrypted auto-teleport cache.\n",
        "-- This file intentionally contains no plaintext SliceHub source.\n",
        "local MAGIC = ", string.format("%q", SH_CACHE_MAGIC), "\n",
        "local SALT = ", string.format("%q", salt), "\n",
        "local CHECKSUM = ", string.format("%q", checksum), "\n",
        "local PAYLOAD = ", string.format("%q", payload), "\n",
        [=[

local ALPHABET =
    "ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789+/"

local function base64Decode(data)
    local lookup = {}

    for index = 1, #ALPHABET do
        lookup[string.byte(ALPHABET, index)] = index - 1
    end

    local output = {}
    local outputIndex = 0

    for index = 1, #data, 4 do
        local b1 = string.byte(data, index)
        local b2 = string.byte(data, index + 1)
        local b3 = string.byte(data, index + 2)
        local b4 = string.byte(data, index + 3)

        local c1 = lookup[b1] or 0
        local c2 = lookup[b2] or 0
        local c3 = b3 == 61 and 0 or (lookup[b3] or 0)
        local c4 = b4 == 61 and 0 or (lookup[b4] or 0)

        local packed =
            c1 * 262144
            + c2 * 4096
            + c3 * 64
            + c4

        outputIndex += 1
        output[outputIndex] = string.char(
            math.floor(packed / 65536) % 256
        )

        if b3 ~= 61 then
            outputIndex += 1
            output[outputIndex] = string.char(
                math.floor(packed / 256) % 256
            )
        end

        if b4 ~= 61 then
            outputIndex += 1
            output[outputIndex] = string.char(
                packed % 256
            )
        end
    end

    return table.concat(output)
end

local function adler32(data)
    local a = 1
    local b = 0

    for index = 1, #data do
        a = (a + string.byte(data, index)) % 65521
        b = (b + a) % 65521
    end

    return string.format("%08x", b * 65536 + a)
end

