    end

    local swapIndex = 0

    for index = 0, 255 do
        local keyByte =
            string.byte(key, (index % #key) + 1)

        swapIndex =
            (swapIndex + state[index] + keyByte) % 256

        state[index], state[swapIndex] =
            state[swapIndex], state[index]
    end

    local output = {}
    local outputIndex = 0
    local chunk = {}
    local chunkIndex = 0
    local i = 0
    local j = 0

    for position = 1, #data do
        i = (i + 1) % 256
        j = (j + state[i]) % 256

        state[i], state[j] = state[j], state[i]

        local streamByte =
            state[(state[i] + state[j]) % 256]

        chunkIndex += 1
        chunk[chunkIndex] = string.char(
            bit32.bxor(
                string.byte(data, position),
                streamByte
            )
        )

        if chunkIndex >= 4096 then
            outputIndex += 1
            output[outputIndex] = table.concat(chunk)
            chunk = {}
            chunkIndex = 0
        end
    end

    if chunkIndex > 0 then
        outputIndex += 1
        output[outputIndex] = table.concat(chunk)
    end

    return table.concat(output)
end

local function deviceMaterial()
